// ============================================================================
// Context persistence: keeps "viewing <X> ID" across page refresh (F5).
// Before: viewingFlpId etc. were module-level vars that evaporated on reload,
// so refreshing a View page left blank fields. Now we mirror these into
// sessionStorage keyed by page so `navigateTo()` can rehydrate them.
// Call _ctxSet('viewFlp', id) when entering a view, _ctxGet('viewFlp') to
// restore on reload, and _ctxClear('viewFlp') when leaving.
// ============================================================================
function _ctxSet(key, val) {
  try {
    if (val == null || val === '') sessionStorage.removeItem('azadCtx.' + key);
    else sessionStorage.setItem('azadCtx.' + key, String(val));
  } catch (e) {}
}
function _ctxGet(key) {
  try { return sessionStorage.getItem('azadCtx.' + key); } catch (e) { return null; }
}
function _ctxGetInt(key) { var v = _ctxGet(key); var n = parseInt(v); return isNaN(n) ? null : n; }
function _ctxClear(key) { try { sessionStorage.removeItem('azadCtx.' + key); } catch (e) {} }

