// Capture current filter panel values (and current pagination position)
// into sessionStorage. Snapshot keys are the element IDs themselves, plus a
// reserved `__page` key for the pagination state (when LIST_PAGE_VAR maps
// this list to a global page variable).
function _captureListFilters(listPageId) {
  var ids = LIST_FILTER_MAP[listPageId];
  if (!ids) return;
  var snapshot = {};
  ids.forEach(function(id) {
    var el = document.getElementById(id);
    if (el) snapshot[id] = el.value;
  });
  // Also snapshot the current page number so returning to this list lands
  // the user back on the same page they were viewing — not page 1.
  var pageVarName = LIST_PAGE_VAR && LIST_PAGE_VAR[listPageId];
  if (pageVarName) {
    try {
      var cur = window[pageVarName];
      if (typeof cur === 'number' && cur > 0) snapshot.__page = cur;
    } catch (e) {}
  }
  try { sessionStorage.setItem('azadFilters.' + listPageId, JSON.stringify(snapshot)); } catch (e) {}
}

// Restore saved values into the filter panel AND the pagination position.
// Returns true if any value was restored. The page variable (per
// LIST_PAGE_VAR) is written directly to the global namespace so the page's
// loader function picks it up on next render.
function _restoreListFilters(listPageId) {
  var ids = LIST_FILTER_MAP[listPageId];
  if (!ids) return false;
  var raw;
  try { raw = sessionStorage.getItem('azadFilters.' + listPageId); } catch (e) { raw = null; }
  if (!raw) return false;
  var snapshot;
  try { snapshot = JSON.parse(raw); } catch (e) { return false; }
  if (!snapshot || typeof snapshot !== 'object') return false;
  var restored = false;
  ids.forEach(function(id) {
    var el = document.getElementById(id);
    if (!el) return;
    var v = snapshot[id];
    if (v != null && v !== '') {
      el.value = v;
      restored = true;
    }
  });
  // Restore pagination position. We do this even if no filter values were
  // restored — the user may have only paginated, not filtered.
  var pageVarName = LIST_PAGE_VAR && LIST_PAGE_VAR[listPageId];
  if (pageVarName && snapshot.__page && typeof snapshot.__page === 'number') {
    try { window[pageVarName] = snapshot.__page; restored = true; } catch (e) {}
  }
  return restored;
}

// Read the saved page number for a list (without restoring DOM filter values).
// Used by navigateTo when invoking the loader function with an explicit page
// argument. Returns null if no page is saved.
function _savedListPage(listPageId) {
  var raw;
  try { raw = sessionStorage.getItem('azadFilters.' + listPageId); } catch (e) { return null; }
  if (!raw) return null;
  try {
    var snap = JSON.parse(raw);
    if (snap && typeof snap.__page === 'number' && snap.__page > 0) return snap.__page;
  } catch (e) {}
  return null;
}

// Clear the saved state so the next visit starts fresh — both filter values
// AND pagination get wiped, so clicking Reset truly resets everything.
function _clearListFilters(listPageId) {
  try { sessionStorage.removeItem('azadFilters.' + listPageId); } catch (e) {}
  var pageVarName = LIST_PAGE_VAR && LIST_PAGE_VAR[listPageId];
  if (pageVarName) {
    try { window[pageVarName] = 1; } catch (e) {}
  }
}

// Track the previous page so navigateTo can detect "returning from a detail view"
var _prevPageId = null;

// Centralized role check for "can hard-delete a record from a list".
// Mirrors FLP's gating (admin + super_admin only) and the backend's
// require_admin_role guard. Used by every Delete trash icon across FLP,
// AK and MGJ list rows so a single edit changes who can delete.
function _canDeleteRecord() {
  // 2026-06-05: State Lead added per AK module spec — SL manages their
  // state's data including delete on Assessment List + Adda List. The
  // backend role-scope enforcement (routes/_role_scope.py, Phase 2)
  // already pins their state_code on delete-adjacent reads, so SL can
  // only see/delete records inside their own state.
  return !!(currentUser && (
    currentUser.role === 'admin' ||
    currentUser.role === 'super_admin' ||
    currentUser.role === 'state_lead'
  ));
}

