/**
 * Format a date string or Date object to "15 Jun 2023" style.
 */
// Format a date for UI display as DD-MM-YYYY. Accepts a Date, ISO string,
// or yyyy-mm-dd. Uses LOCAL date components to avoid timezone shifts.
function formatDateDMY(dateVal) {
  if (!dateVal) return '';
  // If it's a Date, read local components directly (no timezone conversion)
  if (dateVal instanceof Date) {
    if (isNaN(dateVal.getTime())) return '';
    var dd0 = String(dateVal.getDate()).padStart(2, '0');
    var mm0 = String(dateVal.getMonth() + 1).padStart(2, '0');
    return dd0 + '-' + mm0 + '-' + dateVal.getFullYear();
  }
  var s = String(dateVal);
  // Fast-path: "yyyy-mm-dd" (ignore any time portion — avoids timezone pitfalls)
  var m = s.match(/^(\d{4})-(\d{2})-(\d{2})/);
  if (m) return m[3] + '-' + m[2] + '-' + m[1];
  var d = new Date(dateVal);
  if (isNaN(d.getTime())) return s;
  var dd = String(d.getDate()).padStart(2, '0');
  var mm = String(d.getMonth() + 1).padStart(2, '0');
  return dd + '-' + mm + '-' + d.getFullYear();
}

// Historical alias — keep name `formatDateNice` since many callers use it,
// but route through the new DMY formatter so UI displays match the
// "dd-mm-yyyy" standard across the system.
function formatDateNice(dateVal) {
  return formatDateDMY(dateVal);
}

// 2026-05-28: Current age in completed years derived from a DOB. Used
// on the AK + MGJ profile VIEW pages to render a "Present Age" cell
// beside "Age at Enrollment" — the latter is the auto-filled value
// captured at enrolment time, this is the live runtime age. View-only;
// never written back to the DB.
function _computePresentAge(dob) {
  if (!dob) return null;
  var birth = new Date(dob);
  if (isNaN(birth.getTime())) return null;
  var now = new Date();
  var age = now.getFullYear() - birth.getFullYear();
  var m = now.getMonth() - birth.getMonth();
  if (m < 0 || (m === 0 && now.getDate() < birth.getDate())) age--;
  return age >= 0 ? age : null;
}

// "2026-05" -> "May-2026".  Accepts the YYYY-MM shape produced by
// <input type="month">, plus YYYY-MM-DD ISO dates as a tolerance.
function _formatMonthMmmYy(s) {
  if (!s) return '';
  var m = String(s).match(/^(\d{4})-(\d{2})/);
  if (!m) return String(s);
  var y = parseInt(m[1], 10), mo = parseInt(m[2], 10);
  if (!y || !mo || mo < 1 || mo > 12) return String(s);
  var NAMES = ['Jan','Feb','Mar','Apr','May','Jun','Jul','Aug','Sep','Oct','Nov','Dec'];
  return NAMES[mo - 1] + '-' + y;
}

/**
 * Return the previous calendar month in `YYYY-MM` format (the value
 * shape expected by `<input type="month">`). Used by Centre Performance
 * to default the month filter to "last month" on page open — Centres
 * always look at the just-completed month's data, never the current
 * (still-in-progress) month.
 *
 * IST is forced via toLocaleDateString so a user whose browser has
 * drifted to a non-IST timezone still sees the Indian wall-clock
 * "previous month" — important right at midnight on the 1st of a month.
 */
function _previousMonthYM() {
  // Build today in IST, then step back one calendar month. Using
  // setMonth(getMonth()-1) handles year rollover (Jan -> prev Dec)
  // automatically.
  var nowIst = new Date(new Date().toLocaleString('en-US', { timeZone: 'Asia/Kolkata' }));
  nowIst.setDate(1);            // avoid 31 Mar -> 31 Feb (=> Mar) anomaly
  nowIst.setMonth(nowIst.getMonth() - 1);
  var y = nowIst.getFullYear();
  var m = String(nowIst.getMonth() + 1).padStart(2, '0');
  return y + '-' + m;
}

/**
 * Format a number with commas (e.g. 33145 -> "33,145").
 */
function formatNumber(n) {
  if (n === null || n === undefined) return '0';
  return Number(n).toLocaleString('en-IN');
}

/**
 * Return a status badge HTML snippet.
 */
function showUserError(context, err) {
  var raw = err && err.message ? err.message : (typeof err === 'string' ? err : JSON.stringify(err));
  console.error(context + ':', raw);
  // If backend returned a user-facing detail message (via apiRequest -> new Error(err.detail)),
  // surface it directly. Only fall back to the generic message for raw server/network errors.
  var isGeneric = !raw || /^(Server Error|API Error|Failed to fetch|NetworkError|Upload Error)/i.test(raw);
  if (!isGeneric) {
    alert(raw);
    return;
  }
  // 2026-06-03: Server Errors carry the response body inline (apiRequest does
  // `'Server Error (500): ' + text.substring(0, 200)`). Stripping that body
  // hid root causes from non-admin users — they only saw the generic message.
  // Now we show both the friendly framing AND the technical detail beneath,
  // so when a Leader Log save (or anything else) fails the actual message
  // from the backend is visible without opening DevTools.
  var detail = raw ? (' Details: ' + raw) : '';
  alert('Something went wrong while ' + context + '. Please try again. If the issue persists, contact support.' + detail);
}
function statusBadge(status) {
  var cls = 'badge-active';
  var text = status || 'Active';
  // Display "Walkout" as "Dropout" in UI
  if (text === 'Walkout') text = 'Dropout';
  var lower = (text + '').toLowerCase();
  if (lower === 'walkout' || lower === 'rejected' || lower === 'inactive' || lower === 'absent' || lower === 'dropout') {
    cls = 'badge-walkout';
  } else if (lower === 'approved' || lower === 'both completed' || lower === 'completed') {
    cls = 'badge-approved';
  } else if (lower === 'submitted' || lower === 'active' || lower === 'pending post-assessment' || lower === 'present') {
    cls = 'badge-active';
  } else if (lower === 'draft') {
    // Distinct orange/amber badge for drafts so PIs can spot half-filled
    // FLP records at a glance in the list. Inline-styled because the
    // existing CSS doesn't ship a `.badge-draft` class — keeps the change
    // self-contained in app.js without touching index.html / CSS files.
    return '<span class="badge" style="background:#f39c12;color:#fff;font-weight:600;">' +
           '<i class="fas fa-clipboard" style="margin-right:4px;"></i>Draft</span>';
  }
  return '<span class="badge ' + cls + '">' + text + '</span>';
}

/**
 * Escape HTML entities to prevent XSS in table data.
 */
function escHtml(str) {
  if (str === null || str === undefined) return '';
  var div = document.createElement('div');
  div.appendChild(document.createTextNode(str));
  return div.innerHTML;
}

/**
 * Reset a numeric input to 0 if the user has typed (or pasted, or
 * spinner-decremented) a negative value. Used on count / quantity / income
 * fields where negative values make no sense. Handles both keyboard typing
 * and the native `<input type="number">` down-arrow spinner — pair this
 * with `min="0"` on the element so the spinner control also stops at 0.
 */
function clampNonNegative(input) {
  if (!input) return;
  // Allow an empty string (user erased the value mid-edit) to pass
  // through — re-validating on every keystroke would be jarring.
  if (input.value === '' || input.value === '-') { input.value = ''; return; }
  var v = parseFloat(input.value);
  if (!isNaN(v) && v < 0) input.value = 0;
}

/**
 * Atomically render the options of a <select>, deduped by value, with a
 * placeholder option preserved at the top. Use this in place of the common
 * pattern:
 *
 *     sel.innerHTML = '<option value="">All</option>';
 *     fetch().then(items => items.forEach(it => sel.appendChild(...)));
 *
 * which doubles up when the populator runs twice concurrently (e.g. once
 * at app startup and once on navigation, or once via a default loader and
 * once via an edit-mode pre-fill). Because this helper builds the entire
 * inner HTML in one shot AND dedupes by `value` first, two overlapping
 * calls produce the same output as one — no duplicates regardless of
 * response ordering.
 *
 * @param {HTMLSelectElement} sel       target select element
 * @param {Array}             items     raw row objects from the API
 * @param {Function}          getValue  (row) => option.value
 * @param {Function}          getLabel  (row) => option.textContent
 * @param {Object}            opts      { placeholder, selectedValue }
 */
function setDropdownOptions(sel, items, getValue, getLabel, opts) {
  if (!sel) return;
  opts = opts || {};
  var seen = Object.create(null);
  var html = (opts.placeholder != null) ? opts.placeholder : '';
  var selectedValue = opts.selectedValue != null ? String(opts.selectedValue) : null;
  for (var i = 0; i < (items || []).length; i++) {
    var v = getValue(items[i]);
    if (v == null || v === '') continue;
    var key = String(v);
    if (seen[key]) continue;
    seen[key] = true;
    var sel_attr = (selectedValue != null && key === selectedValue) ? ' selected' : '';
    html += '<option value="' + escHtml(key) + '"' + sel_attr + '>' +
            escHtml(getLabel(items[i]) || '') + '</option>';
  }
  sel.innerHTML = html;
}


