// Dispatch table: page id → (state-select-id, district-select-id).
// Pages without a District filter pass null. Pages without a State filter
// either don't appear here, or pass null for the first slot.
var _AK_MGJ_LIST_SCOPE_MAP = {
  // AK pages
  'akHome':              ['akDashFilterState',    'akDashFilterDistrict'],
  'akList':              ['akFilterState',        null],
  'akAlapList':          [null,                   null],  // no state/district filter row
  'akAlapTraining':      ['alapTrFilterState',    null],
  'akAlapCrc':           [null,                   null],
  'akAlapActivityMapping': [null,                 null],
  'akAlapPerformance':   ['alapPerfFilterState',  null],
  'akAlapCohorts':       [null,                   null],
  'akMentorLog':         [null,                   null],
  'akTrainingList':      ['akTrFilterState',      null],
  'akAssessmentList':    ['akAsFilterState',      null],
  'akAdda':              ['akAddaFilterState',    null],
  'akAlumni':            ['akAlumniFilterState',  null],
  'akAlumniAgm':         [null,                   null],
  'akBatchManagement':   [null,                   null],
  // MGJ pages
  'mgjHome':             ['mgjDashFilterState',   'mgjDashFilterDistrict'],
  'mgjList':             ['mgjFilterState',       null],
  'mgjActivitiesList':   [null,                   null],
  'mgjActivitiesReport': [null,                   null],
  'mgjAssessmentList':   ['mgjAsFilterState',     'mgjAsFilterDistrict'],
  // 2026-05-27: pakhwada split — keep legacy key for forward compat, add the two new pages.
  'mgjPakhwadaList':     [null,                   null],
  'mgjPakhwadaInput':    [null,                   null],
  'mgjPakhwadaSports':   [null,                   null],
  'mgjLeaderList':       ['mgjLdrFilterState',    null],
  'mgjLeaderTraining':   ['mgjLtFilterState',     null],
  'mgjAlumniList':       ['mgjAlFilterState',     null],
};
function _applyAkMgjListRoleScope(pageId) {
  var pair = _AK_MGJ_LIST_SCOPE_MAP[pageId];
  if (!pair) return;
  _applyListRoleScope(pair[0], pair[1]);
}


// =============================================================================
// 5. DATA LOADING FUNCTIONS (one per page)
// =============================================================================

// ---- DASHBOARD ----

// Dynamic cascading state → centre filter for dashboard
function updateDashDistrictOptions() {
  var stateCode = document.getElementById('dashFilterState').value;
  var distSelect = document.getElementById('dashFilterDistrict');
  if (!distSelect) return;
  distSelect.innerHTML = '<option value="">All Districts</option>';
  if (!stateCode || typeof apiGeoDropdownDistricts !== 'function') return;
  // stateCode is already a state_code (e.g. "S07") from loadStateDropdown
  apiGeoDropdownDistricts(stateCode).then(function(result) {
    var districts = result.data || result || [];
    districts.forEach(function(d) {
      var opt = document.createElement('option');
      opt.value = d.district_code;
      opt.textContent = d.district_name;
      distSelect.appendChild(opt);
    });
  }).catch(function() {});
}
// Keep old name as alias for HTML onchange
function updateDashCentreOptions() { updateDashDistrictOptions(); }

function getDashFilterParams() {
  var state = document.getElementById('dashFilterState') ? document.getElementById('dashFilterState').value : '';
  var status = document.getElementById('dashFilterStatus') ? document.getElementById('dashFilterStatus').value : '';
  var districtCode = document.getElementById('dashFilterDistrict') ? document.getElementById('dashFilterDistrict').value : '';
  var dateFrom = document.getElementById('dashFilterDateFrom') ? document.getElementById('dashFilterDateFrom').value : '';
  var dateTo = document.getElementById('dashFilterDateTo') ? document.getElementById('dashFilterDateTo').value : '';
  var params = {};
  if (state) params.state_code = state;
  if (status) params.status = status;
  if (districtCode) params.district_code = districtCode;
  if (dateFrom) params.date_from = dateFrom;
  if (dateTo) params.date_to = dateTo;
  // Role-floor: SL can only see their state, DL only their district, PI only
  // their centre. This guarantees the Dashboard KPIs / charts cannot show
  // out-of-scope data even if the filter dropdowns are unset.
  return _applyRoleScopeFloor(params);
}

// On the Home / Dashboard page, hide the State filter dropdown for any role
// that is scoped to a single state (SL, DL, PI) and hide the District filter
// for DL/PI. The Export button uses _applyRoleScopeFloor so even if these
// dropdowns are bypassed, the role floor still applies.
function _applyDashboardRoleScope() {
  if (!currentUser) return;
  var role = currentUser.role || '';
  var stateGroup = document.getElementById('dashFilterStateGroup');
  var distGroup  = document.getElementById('dashFilterDistrictGroup');
  var isScopedToState = (role === 'state_lead' || role === 'district_lead' || role === 'pi');
  var isScopedToDistrict = (role === 'district_lead' || role === 'pi');
  if (stateGroup) stateGroup.style.display = isScopedToState ? 'none' : '';
  if (distGroup)  distGroup.style.display  = isScopedToDistrict ? 'none' : '';
}

// Generic helper for AK / MGJ list filter rows — hides the State filter for
// any scoped role (SL/DL/PI) and District filter for DL/PI. Pass the **select**
// element ids directly; the helper walks up to find the nearest .filter-group
// wrapper (or its parent + preceding sibling label) and hides that container.
// Avoids per-page index.html edits — works against the existing markup.
function _hideFilterByEl(el) {
  if (!el) return;
  // 1) Prefer the closest .filter-group wrapper if one exists.
  var box = el.closest && el.closest('.filter-group');
  if (box) { box.style.display = 'none'; return; }
  // 2) Otherwise hide both the select and any immediately-preceding label.
  el.style.display = 'none';
  var prev = el.previousElementSibling;
  if (prev && prev.tagName && prev.tagName.toLowerCase() === 'label') prev.style.display = 'none';
}
// Pre-fill a select with the user's scoped code and fire its change event
// so downstream cascading dropdowns (Centre depends on State, Area depends on
// Centre, etc.) populate correctly even though the parent select is hidden.
// Polls for up to ~2s waiting for the parent's options to load (state dropdowns
// are filled async), then sets value + dispatches change.
function _setHiddenSelectAndCascade(el, code, retries) {
  if (!el || !code) return;
  retries = (retries == null) ? 12 : retries;
  var has = false;
  for (var i = 0; i < el.options.length; i++) {
    if (el.options[i].value === code) { has = true; break; }
  }
  if (!has) {
    if (retries > 0) setTimeout(function() { _setHiddenSelectAndCascade(el, code, retries - 1); }, 200);
    return;
  }
  if (el.value !== code) {
    el.value = code;
    try { el.dispatchEvent(new Event('change', { bubbles: true })); } catch (e) {}
  }
}
function _applyListRoleScope(stateSelId, districtSelId) {
  if (!currentUser) return;
  var role = currentUser.role || '';
  var hideState = (role === 'state_lead' || role === 'district_lead' || role === 'pi');
  var hideDist  = (role === 'district_lead' || role === 'pi');
  var stateEl = stateSelId && document.getElementById(stateSelId);
  var distEl  = districtSelId && document.getElementById(districtSelId);
  // Set scoped State / District BEFORE hiding so the page's onchange cascade
  // (which populates Centre dropdowns) actually fires once.
  if (hideState && stateEl && currentUser.state_code) {
    _setHiddenSelectAndCascade(stateEl, currentUser.state_code);
  }
  if (hideDist && distEl && currentUser.district_code) {
    _setHiddenSelectAndCascade(distEl, currentUser.district_code);
  }
  if (hideState && stateEl) _hideFilterByEl(stateEl);
  if (hideDist  && distEl)  _hideFilterByEl(distEl);
}

// Centralized role-scope pin used everywhere a list / dashboard payload is
// built. Forces state_code / district_code / centre_code to the user's
// assigned geography for restricted roles. Admin / Super Admin / Power User
// pass through unchanged.
function _applyRoleScopeFloor(params, ctx) {
  // 2026-06-08: ctx may be 'mgj' to opt into MGJ-master geography codes
  // (currentUser.mgj_state_code / mgj_centre_code) instead of FLP codes.
  // MGJ has its own master tables so centre_code namespaces differ. Pass
  // 'mgj' from every MGJ list / dashboard / report loader to make their
  // role-scoped filters actually match the saved MGJ records. Anything
  // else keeps the legacy FLP/AK behaviour for backward compatibility.
  params = params || {};
  if (!currentUser) return params;
  var role = currentUser.role || '';
  var isMgj = ctx === 'mgj';
  if (role === 'state_lead' && currentUser.state_code) {
    params.state_code = currentUser.state_code;
    // SL can narrow to a district WITHIN their state, but never widen to
    // another state. We don't strip district_code here so they can still
    // pick a district inside their state from the dropdown.
  } else if (role === 'district_lead') {
    if (isMgj) {
      if (currentUser.mgj_state_code)  params.state_code = currentUser.mgj_state_code;
      else if (currentUser.state_code) params.state_code = currentUser.state_code;
    } else {
      if (currentUser.state_code) params.state_code = currentUser.state_code;
      if (currentUser.district_code) params.district_code = currentUser.district_code;
    }
  } else if (role === 'pi') {
    if (isMgj) {
      if (currentUser.mgj_state_code)  params.state_code  = currentUser.mgj_state_code;
      else if (currentUser.state_code) params.state_code  = currentUser.state_code;
      if (currentUser.mgj_centre_code) params.centre_code = currentUser.mgj_centre_code;
      // Deliberately NO fallback to FLP centre_code in MGJ context —
      // it would mismatch MGJ records and return 0 rows.
    } else {
      if (currentUser.state_code) params.state_code = currentUser.state_code;
      if (currentUser.district_code) params.district_code = currentUser.district_code;
      if (currentUser.centre_code) params.centre_code = currentUser.centre_code;
    }
  } else if (role === 'mobiliser' || role === 'sangini') {
    // 2026-06-05: Strictly centre-scoped. The user cannot widen even if
    // the URL or filters were tampered with — we always force these
    // three codes onto outgoing params. Phase 2 will additionally
    // enforce these on the backend from the JWT.
    if (isMgj) {
      if (currentUser.mgj_state_code)  params.state_code  = currentUser.mgj_state_code;
      else if (currentUser.state_code) params.state_code  = currentUser.state_code;
      if (currentUser.mgj_centre_code) params.centre_code = currentUser.mgj_centre_code;
    } else {
      if (currentUser.state_code)    params.state_code    = currentUser.state_code;
      if (currentUser.district_code) params.district_code = currentUser.district_code;
      if (currentUser.centre_code)   params.centre_code   = currentUser.centre_code;
    }
  }
  return params;
}

// 2026-06-05: For Mobiliser / Sangini, the Baseline Report's Batch
// dropdown depends on a cascade triggered by an onchange event on
// State (MGJ) or Centre (AK). Because our lock helper writes the
// value programmatically (no change event), that cascade never
// runs and Batch stays empty. This helper bypasses the cascade and
// loads batches directly from the right endpoint:
//   • AK Baseline:  /ak-batches?centre_code=<user's centre>
//   • MGJ Baseline: /mgj-master/dropdown/batches?state_code=<user's state>
// Called once after the lock on page-init, and again after Reset.
function _loadBatchesForRestrictedRole(pageId) {
  if (!currentUser) return;
  var role = currentUser.role || '';
  if (role !== 'mobiliser' && role !== 'sangini') return;
  if (pageId === 'akBaselineReport' && currentUser.centre_code) {
    apiGet('/ak-batches?centre_code=' + encodeURIComponent(currentUser.centre_code)).then(function(resp) {
      var bSel = document.getElementById('akBrFilterBatch');
      if (!bSel) return;
      var rows = (resp && resp.data) || resp || [];
      bSel.innerHTML = '<option value="">All Batches</option>';
      rows.forEach(function(r) {
        var o = document.createElement('option');
        o.value = r.id;
        o.textContent = r.name + (r.year ? ' (' + r.year + ')' : '');
        bSel.appendChild(o);
      });
    }).catch(function(err) {
      console.error('[' + role + '] AK batch load failed:', err);
    });
  }
  if (pageId === 'mgjBaselineReport' && currentUser.state_code) {
    apiGet('/mgj-master/dropdown/batches?state_code=' + encodeURIComponent(currentUser.state_code)).then(function(rows) {
      var bSel = document.getElementById('mgjBrFilterBatch');
      if (!bSel) return;
      bSel.innerHTML = '<option value="">All Batches</option>';
      (rows || []).forEach(function(r) {
        var o = document.createElement('option');
        o.value = r.id;
        o.textContent = r.name + (r.year ? ' (' + r.year + ')' : '');
        bSel.appendChild(o);
      });
    }).catch(function(err) {
      console.error('[' + role + '] MGJ batch load failed:', err);
    });
  }
}

// 2026-06-05: State-only lock for State Lead role. Pin the State select
// to SL's state + disable it, but leave Centre + Batch fully selectable
// so SL can pick any centre/batch within their state. Triggers the
// page's onchange cascade so Centre + Batch populate correctly.
function _lockStateOnlyForSL(stateSelId, centreSelId) {
  if (!currentUser || !currentUser.state_code) return;

  function apply() {
    var sel = stateSelId && document.getElementById(stateSelId);
    if (!sel) return;
    sel.innerHTML = '<option value="' + escHtml(currentUser.state_code) + '" selected>' +
                    escHtml(currentUser.state_name || currentUser.state_code) + '</option>';
    sel.value = currentUser.state_code;
    sel.disabled = true;
    sel.style.backgroundColor = '#f5f5f5';
    sel.style.cursor = 'not-allowed';
    sel.title = 'Locked to your assigned State';
    // Fire change so the page's cascade (Centre + Batch) populates for
    // SL's state without manual user action.
    try { sel.dispatchEvent(new Event('change', { bubbles: true })); } catch (e) {}
  }

  // 2026-06-09: try BOTH MGJ + AK masters when state_name isn't cached.
  // Previously this only tried AK master, so MGJ pages would render "S07"
  // when AK master returned nothing (or returned a code-only row).  Try
  // MGJ first since this helper is most often called from MGJ pages; if
  // MGJ doesn't have a row, fall back to AK.  Either lookup that
  // succeeds stamps the resolved name on currentUser.state_name.
  function _tryMaster(url, next) {
    apiGet(url).then(function(rows) {
      var rows2 = (rows && rows.data) ? rows.data : (rows || []);
      var match = rows2.filter(function(r) {
        return r.state_code === currentUser.state_code;
      })[0];
      if (match && match.state_name) {
        currentUser.state_name = match.state_name;
        try { localStorage.setItem('azadUserData', JSON.stringify(currentUser)); } catch (e) {}
        apply();
      } else if (next) {
        next();
      } else {
        apply();   // best-effort with code-as-label
      }
    }).catch(function() { (next || apply)(); });
  }

  setTimeout(function() {
    if (currentUser.state_name && currentUser.state_name !== currentUser.state_code) {
      apply(); return;
    }
    _tryMaster('/mgj-master/dropdown/states', function() {
      _tryMaster('/ak-master/dropdown/states', null);
    });
  }, 60);
}

// 2026-06-05: Lock geo filter <select>s to the user's assigned values
// for Mobiliser / Sangini. The dropdowns are pre-filled with a single
// option (code as value, friendly name as label) and marked disabled
// so the field is visibly locked. Centre + District names come from
// the parsed `currentUser.scope`; State name is fetched once via the
// dropdown/states endpoint and cached on currentUser.state_name so
// subsequent locks don't re-hit the network.
//
// Pass null for any select id that doesn't exist on the page (e.g.
// the MGJ Assessment List has no District filter).
function _lockGeoFiltersForRestrictedRole(stateSelId, districtSelId, centreSelId) {
  if (!currentUser) return;
  var role = currentUser.role || '';
  // 2026-06-05: State Lead added. SL gets the State select pinned + disabled
  // (single option, their state), but Centre stays selectable so they can
  // narrow within their state. We branch on role: SL = state lock only;
  // Mobiliser/Sangini = lock all three. District Lead and PI are handled by
  // _applyListRoleScope (list pages) and the per-form patterns; their
  // dropdowns are already hidden on list pages and auto-injected on forms.
  if (role === 'state_lead') {
    if (!currentUser.state_code) return;
    _lockStateOnlyForSL(stateSelId, centreSelId);
    return;
  }
  if (role !== 'mobiliser' && role !== 'sangini') return;
  if (!currentUser.centre_code) return;
  // Parse "<Centre>, <District> [...|...|...]" → names.
  var scope = currentUser.scope || '';
  var nameMatch = scope.match(/^(.+?), (.+?) \[/);
  var centreName   = nameMatch ? nameMatch[1].trim() : currentUser.centre_code;
  var districtName = nameMatch ? nameMatch[2].trim() : currentUser.district_code;
  var stateName    = currentUser.state_name || currentUser.state_code;

  function setLocked(id, code, label) {
    if (!id || !code) return;
    var sel = document.getElementById(id);
    if (!sel) return;
    sel.innerHTML = '<option value="' + escHtml(code) + '" selected>' + escHtml(label || code) + '</option>';
    sel.value = code;
    sel.disabled = true;
    sel.style.backgroundColor = '#f5f5f5';
    sel.style.cursor = 'not-allowed';
    sel.title = 'Locked to your assigned ' + (id.toLowerCase().indexOf('state') >= 0 ? 'State' :
                                              id.toLowerCase().indexOf('district') >= 0 ? 'District' : 'Centre');
  }

  function applyAll() {
    var resolvedStateName = currentUser.state_name || currentUser.state_code;
    setLocked(stateSelId,    currentUser.state_code,    resolvedStateName);
    setLocked(districtSelId, currentUser.district_code, districtName);
    setLocked(centreSelId,   currentUser.centre_code,   centreName);
  }

  // Defer one tick so any page-init that populates the dropdowns has
  // finished before we override + disable. (Most page-inits load the
  // state dropdown synchronously then cascade async; we lock after.)
  setTimeout(function() {
    if (currentUser.state_name) {
      applyAll();
      return;
    }
    // One-time async lookup for state name. Cached on currentUser so
    // subsequent page navs don't refetch.
    var base = (role === 'mobiliser') ? '/mgj-master/dropdown/states'
                                       : '/ak-master/dropdown/states';
    apiGet(base).then(function(rows) {
      (rows || []).some(function(r) {
        if (r.state_code === currentUser.state_code) {
          currentUser.state_name = r.state_name;
          return true;
        }
        return false;
      });
      try { localStorage.setItem('azadUserData', JSON.stringify(currentUser)); } catch (e) {}
      applyAll();
    }).catch(function() {
      applyAll();   // best-effort with code-as-label
    });
  }, 50);
}

function applyDashboardFilters() {
  loadDashboardData(getDashFilterParams());
}

// 2026-06-08: AK-side analogue of _lockMgjFiltersForDlPi. Soft- or
// hard-locks State / Centre filters or form fields to the SL/DL/PI
// user's FLP-geo scope.
//   opts.stateMode  = 'hard' (default) | 'soft'
//   opts.centreMode = 'hard' (default) | 'soft'
// For SL: state locked; centre full state-scoped selectable list.
// For DL/PI (with currentUser.centre_code resolved): both locked to
// the single value. The _resolveDlPiScope helper that runs on login
// fills centre_code from the user's "<Centre>, <District>" scope.
// Multi-attempt retry (60/400/1200 ms) defeats races with page-init
// XHR loaders that might re-populate the dropdown after the lock.
function _lockAkFiltersForDlPi(stateSelId, centreSelId, opts) {
  if (!currentUser) return;
  var role = currentUser.role || '';
  if (role !== 'pi' && role !== 'district_lead' && role !== 'state_lead') return;
  opts = opts || {};
  var stateMode  = opts.stateMode  || 'hard';
  var centreMode = opts.centreMode || 'hard';

  function _whenScopeReady(cb) {
    if (window._dlPiScopeReady) { window._dlPiScopeReady.then(cb).catch(cb); }
    else cb();
  }
  _whenScopeReady(function() {
    if (!currentUser.state_code) return;
    // 2026-06-08: Resolve state_name + centre_name once and cache on
    // currentUser, so the lock helper renders "Delhi" / "South Delhi"
    // instead of state_code / centre_code (which previously surfaced
    // as "S07" / cryptic ids when the user object was missing the
    // friendly names). _resolveDlPiScope fills the codes from
    // /geo/centres at login but doesn't always stamp the names; this
    // backfills both via AK-master lookups, then runs the lock.
    _ensureAkScopeNames().then(function() {
      [60, 400, 1200, 2500, 4000].forEach(function(delay) {
        setTimeout(function() { _doLockAkFiltersInner(stateSelId, centreSelId, stateMode, centreMode); }, delay);
      });
    });
  });
}

// 2026-06-08: Lazy resolver that fills currentUser.state_name and
// currentUser.centre_name from the AK masters when missing. Cached on
// currentUser + localStorage so it only fetches once per session.
function _ensureAkScopeNames() {
  if (!currentUser) return Promise.resolve();
  var needState    = currentUser.state_code    && !currentUser.state_name;
  var needCentre   = currentUser.centre_code   && !currentUser.centre_name;
  var needDistrict = currentUser.district_code && !currentUser.district_name;
  if (!needState && !needCentre && !needDistrict) return Promise.resolve();
  var work = [];
  if (needState) {
    work.push(apiGet('/ak-master/dropdown/states').then(function(rows) {
      (rows || []).some(function(r) {
        if (r.state_code === currentUser.state_code) {
          currentUser.state_name = r.state_name;
          return true;
        }
        return false;
      });
    }).catch(function() {}));
  }
  if (needCentre) {
    // Centre name might already be derivable from currentUser.scope
    // (format: "<Centre>, <District> [...]") — try that first before
    // hitting the network.
    if (currentUser.scope) {
      var m = String(currentUser.scope).match(/^(.+?), /);
      if (m) currentUser.centre_name = m[1].trim();
    }
    if (!currentUser.centre_name && currentUser.state_code) {
      work.push(apiGet('/ak/geo/centres?state_code=' + encodeURIComponent(currentUser.state_code)).then(function(rows) {
        (rows || []).some(function(r) {
          if (r.centre_code === currentUser.centre_code) {
            currentUser.centre_name = r.centre_name;
            return true;
          }
          return false;
        });
      }).catch(function() {}));
    }
  }
  if (needDistrict && currentUser.state_code) {
    work.push(apiGet('/ak-master/dropdown/districts?state_code=' + encodeURIComponent(currentUser.state_code)).then(function(rows) {
      (rows || []).some(function(r) {
        if (r.district_code === currentUser.district_code) {
          currentUser.district_name = r.district_name;
          return true;
        }
        return false;
      });
    }).catch(function() {}));
  }
  return Promise.all(work).then(function() {
    try { localStorage.setItem('azadUserData', JSON.stringify(currentUser)); } catch (e) {}
  });
}

// 2026-06-08: Soft 2-option lock for the Baseline Report District
// dropdown. Lives separately from _lockAkFiltersForDlPi because that
// helper only handles State + Centre. BR has a 3-level cascade
// (State → District → Centre) and the user wants the same "All X +
// <your value>" pattern at every level for DL/PI.
function _lockAkBrDistrictForDlPi() {
  if (!currentUser) return;
  var role = currentUser.role || '';
  if (role !== 'district_lead' && role !== 'pi') return;
  if (!currentUser.district_code) return;
  function _apply() {
    var sel = document.getElementById('akBrFilterDistrict');
    if (!sel) return;
    var esc = (typeof escHtml === 'function') ? escHtml : function(x) { return x; };
    var label = currentUser.district_name || currentUser.district_code;
    sel.innerHTML = '<option value="">All Districts</option>' +
                    '<option value="' + esc(currentUser.district_code) + '">' + esc(label) + '</option>';
    sel.disabled = false;
    sel.style.backgroundColor = '';
    sel.style.cursor = '';
  }
  _ensureAkScopeNames().then(function() {
    [60, 400, 1200].forEach(function(d) { setTimeout(_apply, d); });
  });
}

function _doLockAkFiltersInner(stateSelId, centreSelId, stateMode, centreMode) {
  if (!currentUser || !currentUser.state_code) return;
  var role = currentUser.role || '';
  var esc = (typeof escHtml === 'function') ? escHtml : function(x) { return x; };

  // STATE
  var stateSel = stateSelId && document.getElementById(stateSelId);
  if (stateSel) {
    if (stateMode === 'soft') {
      var stateDefaultLabel = (stateSel.options[0] && stateSel.options[0].text) || 'All States';
      stateSel.innerHTML = '<option value="">' + esc(stateDefaultLabel) + '</option>' +
                           '<option value="' + esc(currentUser.state_code) + '">' +
                           esc(currentUser.state_name || currentUser.state_code) + '</option>';
      stateSel.disabled = false;
      stateSel.style.backgroundColor = '';
      stateSel.style.cursor = '';
      stateSel.title = '';
    } else {
      stateSel.innerHTML = '<option value="' + esc(currentUser.state_code) + '" selected>' +
                           esc(currentUser.state_name || currentUser.state_code) + '</option>';
      stateSel.value = currentUser.state_code;
      stateSel.disabled = true;
      stateSel.style.backgroundColor = '#f5f5f5';
      stateSel.style.cursor = 'not-allowed';
      stateSel.title = 'Locked to your assigned State';
    }
  }

  // CENTRE
  var centreSel = centreSelId && document.getElementById(centreSelId);
  if (!centreSel) {
    if (stateSel) try { stateSel.dispatchEvent(new Event('change', { bubbles: true })); } catch (e) {}
    return;
  }

  if ((role === 'pi' || role === 'district_lead') && currentUser.centre_code) {
    var centreName = currentUser.centre_name;
    // Best-effort label resolution from currentUser.scope ("<Centre>, <District> [...]")
    if (!centreName && currentUser.scope) {
      var m = String(currentUser.scope).match(/^(.+?), /);
      if (m) centreName = m[1].trim();
    }
    centreName = centreName || currentUser.centre_code;
    if (centreMode === 'soft') {
      var defaultLabel = (centreSel.options[0] && centreSel.options[0].text) || 'All Centres';
      centreSel.innerHTML = '<option value="">' + esc(defaultLabel) + '</option>' +
                            '<option value="' + esc(currentUser.centre_code) + '">' +
                            esc(centreName) + '</option>';
      centreSel.disabled = false;
      centreSel.style.backgroundColor = '';
      centreSel.style.cursor = '';
      centreSel.title = '';
    } else {
      centreSel.innerHTML = '<option value="' + esc(currentUser.centre_code) + '" selected>' +
                            esc(centreName) + '</option>';
      centreSel.value = currentUser.centre_code;
      centreSel.disabled = true;
      centreSel.style.backgroundColor = '#f5f5f5';
      centreSel.style.cursor = 'not-allowed';
      centreSel.title = 'Locked to your assigned Centre';
    }
    try { centreSel.dispatchEvent(new Event('change', { bubbles: true })); } catch (e) {}
    return;
  }
  // SL (or DL/PI with no resolved centre): full state-scoped centre list.
  apiGet('/ak-master/centres?state_code=' + encodeURIComponent(currentUser.state_code) + '&limit=500').then(function(resp) {
    var rows = (resp && resp.data) || resp || [];
    var fallbackLabel = (centreSel.options[0] && centreSel.options[0].text) || 'All Centres';
    centreSel.innerHTML = '<option value="">' + esc(fallbackLabel) + '</option>';
    rows.forEach(function(c) {
      var opt = document.createElement('option');
      opt.value = c.centre_code; opt.textContent = c.centre_name;
      centreSel.appendChild(opt);
    });
  }).catch(function() {});
}

function resetDashboardFilters() {
  // 2026-06-30 — re-apply PI/DL/SL lock after reset clears dropdowns
  setTimeout(function() { if (typeof _lockFlpFiltersForDlPi === 'function') _lockFlpFiltersForDlPi('dashFilterState', 'dashFilterDistrict', null); }, 50);
  document.getElementById('dashFilterState').value = '';
  document.getElementById('dashFilterStatus').value = '';
  var distEl = document.getElementById('dashFilterDistrict');
  if (distEl) { distEl.innerHTML = '<option value="">All Districts</option>'; distEl.value = ''; }
  document.getElementById('dashFilterDateFrom').value = '';
  document.getElementById('dashFilterDateTo').value = '';
  // Reset still respects the role floor so SL/DL/PI never see all-states data.
  loadDashboardData(_applyRoleScopeFloor({}));
}

// ---- FLP LIST FILTERS ----
function applyFlpFilters() {
  flpCurrentPage = 1;
  loadFlpListData(1);
}
function resetFlpFilters() {
  // 2026-06-30 — re-apply PI/DL/SL lock after reset clears dropdowns
  setTimeout(function() { if (typeof _lockFlpFiltersForDlPi === 'function') _lockFlpFiltersForDlPi('flpFilterState', 'flpFilterDistrict', null); }, 50);
  _clearListFilters('flpList');  // wipe persisted snapshot so reset truly clears
  var state = document.getElementById('flpFilterState');
  var dist = document.getElementById('flpFilterDistrict');
  var batch = document.getElementById('flpFilterBatch');
  var name = document.getElementById('flpFilterName');
  var dateFrom = document.getElementById('flpFilterDateFrom');
  var dateTo = document.getElementById('flpFilterDateTo');
  if (state) state.value = '';
  if (dist) { dist.innerHTML = '<option value="">All Districts</option>'; dist.value = ''; }
  if (batch) batch.value = '';
  if (name) name.value = '';
  if (dateFrom) dateFrom.value = '';
  if (dateTo) dateTo.value = '';
  var status = document.getElementById('flpFilterStatus');
  if (status) status.value = '';
  // Re-populate district and batch for PI/DL/SL
  _flpDistrictForRestrictedLoaded = false;
  _flpBatchFilterStateCode = null;
  flpCurrentPage = 1;
  loadFlpListData(1);
}

// Populate batch dropdown for FLP list filter — filtered by selected state
var _flpBatchFilterStateCode = null;
function _populateFlpBatchFilter() {
  var sel = document.getElementById('flpFilterBatch');
  if (!sel || typeof apiGet !== 'function') return;

  // Determine state code: from state dropdown or from user profile
  var isRestricted = currentUser && (currentUser.role === 'pi' || currentUser.role === 'district_lead' || currentUser.role === 'state_lead');
  var stateCode = '';
  if (isRestricted && currentUser.state_code) {
    stateCode = currentUser.state_code;
  } else {
    var stateEl = document.getElementById('flpFilterState');
    if (stateEl && stateEl.value) stateCode = stateEl.value;
  }

  // Skip reload if same state
  if (_flpBatchFilterStateCode === stateCode) return;
  _flpBatchFilterStateCode = stateCode;

  sel.innerHTML = '<option value="">All Batches</option>';
  var url = '/batches?status=Active&limit=100';
  if (stateCode) url += '&state_code=' + encodeURIComponent(stateCode);

  apiGet(url).then(function(result) {
    var batches = result.data || result || [];
    batches.forEach(function(b) {
      var opt = document.createElement('option');
      opt.value = b.id;
      var label = b.name + (b.year ? ' (' + b.year + ')' : '');
      if (!stateCode && b.state_name) label += ' - ' + b.state_name;
      opt.textContent = label;
      sel.appendChild(opt);
    });
  }).catch(function() {});
}

// Auto-populate FLP list district dropdown for PI/DL/SL based on their state
var _flpDistrictForRestrictedLoaded = false;
function _populateFlpDistrictForRestricted() {
  if (_flpDistrictForRestrictedLoaded) return;
  var isRestricted = currentUser && (currentUser.role === 'pi' || currentUser.role === 'district_lead' || currentUser.role === 'state_lead');
  if (!isRestricted || !currentUser.state_code) return;
  _flpDistrictForRestrictedLoaded = true;
  var distSel = document.getElementById('flpFilterDistrict');
  if (!distSel || typeof apiGeoDropdownDistricts !== 'function') return;
  distSel.innerHTML = '<option value="">All Districts</option>';
  apiGeoDropdownDistricts(currentUser.state_code).then(function(result) {
    var districts = result.data || result || [];
    districts.forEach(function(d) {
      var opt = document.createElement('option');
      opt.value = d.district_code;
      opt.textContent = d.district_name;
      distSel.appendChild(opt);
    });
  }).catch(function() {});
}

