function loadDashboardData(filterParams) {
  if (!apiAvailable) {
    // Just init charts with hardcoded data
    initDashboard();
    return;
  }

  var params = filterParams || {};

  // Load KPIs — using element IDs
  apiDashboardStats(params)
    .then(function(stats) {
      var el;
      el = document.getElementById('kpiStates');
      if (el && stats.states !== undefined) el.textContent = formatNumber(stats.states);
      el = document.getElementById('kpiDistricts');
      if (el && stats.total_districts !== undefined) el.textContent = formatNumber(stats.total_districts);
      el = document.getElementById('kpiCentres');
      if (el && stats.total_centres !== undefined) el.textContent = formatNumber(stats.total_centres);
      el = document.getElementById('kpiFlps');
      if (el && stats.total_flps !== undefined) el.textContent = formatNumber(stats.total_flps);
      el = document.getElementById('kpiSurveys');
      if (el && stats.total_surveys !== undefined) el.textContent = formatNumber(stats.total_surveys);
    })
    .catch(function() { /* keep hardcoded */ });

  // Load chart data
  apiDashboardCharts(params)
    .then(function(charts) {
      initDashboardWithApiData(charts);
      // Attach click handlers for drill-down (survey charts already created inside initDashboardWithApiData)
      setTimeout(attachChartClickHandlers, 200);
    })
    .catch(function(err) {
      console.error('Dashboard charts error:', err);
      // Fall back to hardcoded chart data (includes survey charts via initDashboard->initSurveyAnalyticsCharts)
      initDashboard();
      setTimeout(attachChartClickHandlers, 200);
    });

  // State Wise FLP Count table must stay consistent regardless of the Status
  // filter — fetch it with status stripped out so Active + Dropout counts
  // always sum to the state's true total.
  var stateTableParams = Object.assign({}, params);
  delete stateTableParams.status;
  apiDashboardCharts(stateTableParams)
    .then(function(charts) {
      var stateData = charts.state_flp_breakdown || charts.flp_by_state || [];
      var tbody = document.getElementById('dashStateTableBody');
      if (!tbody) return;
      if (!stateData.length) {
        tbody.innerHTML = '<tr><td colspan="4" style="text-align:center;color:#999;padding:20px;">No data</td></tr>';
        return;
      }
      var html = '';
      stateData.forEach(function(row) {
        html += '<tr><td>' + escHtml(row.state) + '</td><td>' + (row.total || row.count || 0) +
          '</td><td>' + (row.active || row.total || row.count || 0) +
          '</td><td>' + (row.walkout || 0) + '</td></tr>';
      });
      tbody.innerHTML = html;
    })
    .catch(function() {});
}

// ---- FLP LIST ----
function loadFlpListData(page) {
  if (!apiAvailable) return;
  if (typeof page === 'number') flpCurrentPage = page;

  // Role-based visibility: PI/DL see only their district, SL sees their state
  var stateGroup = document.getElementById('flpFilterStateGroup');
  var distGroup = document.getElementById('flpFilterDistrictGroup');
  var isRestricted = currentUser && (currentUser.role === 'pi' || currentUser.role === 'district_lead' || currentUser.role === 'state_lead');
  var isDlPi = currentUser && (currentUser.role === 'pi' || currentUser.role === 'district_lead');
  if (stateGroup) stateGroup.style.display = isRestricted ? 'none' : '';
  if (distGroup) distGroup.style.display = isDlPi ? 'none' : '';

  // For SL: auto-populate district dropdown
  if (!isDlPi) _populateFlpDistrictForRestricted();
  _populateFlpBatchFilter();

  var filterParams = {};
  var stateEl = document.getElementById('flpFilterState');
  var distEl = document.getElementById('flpFilterDistrict');
  var batchEl = document.getElementById('flpFilterBatch');
  var name = document.getElementById('flpFilterName');
  var dateFrom = document.getElementById('flpFilterDateFrom');
  var dateTo = document.getElementById('flpFilterDateTo');

  // PI/DL: auto-inject state + district
  if (isDlPi && currentUser.state_code) {
    filterParams.state_code = currentUser.state_code;
    if (currentUser.district_code) filterParams.district_code = currentUser.district_code;
  } else if (isRestricted && currentUser.state_code) {
    filterParams.state_code = currentUser.state_code;
  } else if (stateEl && stateEl.value) {
    filterParams.state_code = stateEl.value;
  }
  if (!isDlPi && distEl && distEl.value) filterParams.district_code = distEl.value;
  if (batchEl && batchEl.value) filterParams.batch_id = batchEl.value;
  if (name && name.value.trim()) filterParams.name = name.value.trim();
  if (dateFrom && dateFrom.value) filterParams.date_from = dateFrom.value;
  if (dateTo && dateTo.value) filterParams.date_to = dateTo.value;
  var statusEl = document.getElementById('flpFilterStatus');
  if (statusEl && statusEl.value) filterParams.status = statusEl.value;
  filterParams.page = flpCurrentPage;
  filterParams.limit = flpPageLimit;

  apiFlps(filterParams)
    .then(function(result) {
      var data = result.data || result;
      var tbody = document.getElementById('flpListTableBody');
      if (!tbody) return;
      if (!data || data.length === 0) {
        tbody.innerHTML = '<tr><td colspan="7" style="text-align:center;color:#999;padding:30px;">No FLP records found matching your search criteria.</td></tr>';
        var pagDiv = document.querySelector('#page-flpList .pagination');
        if (pagDiv) pagDiv.textContent = 'Showing 0 of 0';
        return;
      }
      var html = '';
      // FLP edit gating:
      //   - Admin / Super Admin / DL / SL: always allowed.
      //   - PI: allowed ONLY for Draft records, so the PI who parked a
      //     half-filled FLP can come back and complete it. PIs are still
      //     blocked from editing Active records (client requirement).
      // The per-row decision happens inline below since `flp.status` is
      // only known per row. This is purely UI gating; the equivalent
      // server check lives in `openEditFlp()` -> `_proceedEditFlp()` so
      // a clever PI hitting the URL directly still gets blocked.
      var _isPi = currentUser && currentUser.role === 'pi';
      // Admin / Super Admin gating for the row-level Delete button.
      // Backend also enforces this via require_admin_role.
      var _canDeleteFlp = currentUser && (currentUser.role === 'admin' || currentUser.role === 'super_admin');
      data.forEach(function(flp) {
        // Per-row Edit visibility. Non-PIs see Edit on every row; PIs see
        // it only on Draft rows. flp.status comes back from the list API
        // and is one of: 'Active', 'Draft', 'Walkout'.
        var canEditThisRow = !_isPi || (flp.status === 'Draft');
        html += '<tr>' +
          '<td><a href="#" onclick="viewFlpDetail(' + flp.id + '); return false;" style="color:var(--primary);font-weight:600;">' + escHtml(flp.enrollment_number) + '</a></td>' +
          '<td><a href="#" onclick="viewFlpDetail(' + flp.id + '); return false;" style="color:var(--primary);font-weight:600;">' + escHtml(flp.name) + '</a></td>' +
          '<td>' + escHtml(flp.mobile || '') + '</td>' +
          '<td>' + escHtml([flp.district_name, flp.state_name].filter(Boolean).join(', ') || '') + '</td>' +
          '<td>' + escHtml(flp.batch_name || '') + '</td>' +
          '<td>' + statusBadge(flp.status) + '</td>' +
          '<td>' +
            '<button class="btn-icon" title="View" onclick="viewFlpDetail(' + flp.id + ')"><i class="fas fa-eye"></i></button>' +
            (canEditThisRow ? ' <button class="btn-icon" title="Edit" onclick="openEditFlp(' + flp.id + ')"><i class="fas fa-edit"></i></button>' : '') +
            (_canDeleteFlp ? ' <button class="btn-icon text-danger" title="Delete" onclick="deleteFlpFromList(' + flp.id + ',\'' + escHtml(flp.name || '').replace(/\'/g, "\\'") + '\')"><i class="fas fa-trash-alt"></i></button>' : '') +
          '</td>' +
          '</tr>';
      });
      tbody.innerHTML = html;

      // Update pagination
      var total = result.total || data.length;
      renderListPagination('#page-flpList .pagination', total, flpCurrentPage, flpPageLimit, 'loadFlpListData');
      // Sync dropdown to current limit
      var flpSel = document.getElementById('flpItemsPerPage');
      if (flpSel) flpSel.value = String(flpPageLimit);
    })
    .catch(function(err) {
      console.error('Error loading FLP list:', err);
    });
}

// ---- EXPORT FLP LIST TO EXCEL ----
function exportFlpToExcel() {
  // Build query string from current filters
  var qs = [];
  var stateEl = document.getElementById('flpFilterState');
  var distEl = document.getElementById('flpFilterDistrict');
  var name = document.getElementById('flpFilterName');
  var dateFrom = document.getElementById('flpFilterDateFrom');
  var dateTo = document.getElementById('flpFilterDateTo');
  if (stateEl && stateEl.value) qs.push('state_code=' + encodeURIComponent(stateEl.value));
  if (distEl && distEl.value) qs.push('district_code=' + encodeURIComponent(distEl.value));
  if (name && name.value.trim()) qs.push('name=' + encodeURIComponent(name.value.trim()));
  if (dateFrom && dateFrom.value) qs.push('date_from=' + dateFrom.value);
  if (dateTo && dateTo.value) qs.push('date_to=' + dateTo.value);
  var statusEl = document.getElementById('flpFilterStatus');
  if (statusEl && statusEl.value) qs.push('status=' + encodeURIComponent(statusEl.value));

  // Direct navigation triggers download via Content-Disposition: attachment header
  var url = API_BASE + '/flps/export/excel' + (qs.length ? '?' + qs.join('&') : '');
  window.location.href = url;
}

function exportTrainingToExcel() {
  // 2026-06-30 — Training List page has only State + Phase + Batch + Duration
  // filters (no District/Centre dropdowns), so for PI/DL/SL we MUST inject
  // their scope from currentUser, otherwise the export streams every state.
  var qs = [];
  var stateEl = document.getElementById('trainingFilterState');
  var phase = document.getElementById('trainingFilterPhase');
  var dateFrom = document.getElementById('trainingFilterDateFrom');
  var dateTo = document.getElementById('trainingFilterDateTo');
  var isDlPi = currentUser && (currentUser.role === 'pi' || currentUser.role === 'district_lead');
  var isRestricted = isDlPi || (currentUser && currentUser.role === 'state_lead');
  if (isDlPi && currentUser.state_code) {
    // 2026-06-30 v2: backend export endpoint intersects state+centre (strict),
    // but the list endpoint uses ELIF (state OR centre). Send only state_code
    // to match list behavior — backend will include all trainings tied to that
    // state regardless of which specific centre_code they reference.
    qs.push('state_code=' + encodeURIComponent(currentUser.state_code));
  } else if (isRestricted && currentUser.state_code) {
    qs.push('state_code=' + encodeURIComponent(currentUser.state_code));
  } else if (stateEl && stateEl.value) {
    qs.push('state_code=' + encodeURIComponent(stateEl.value));
  }
  if (phase && phase.value)    qs.push('phase=' + encodeURIComponent(phase.value));
  if (dateFrom && dateFrom.value) qs.push('date_from=' + dateFrom.value);
  if (dateTo && dateTo.value)     qs.push('date_to=' + dateTo.value);
  window.location.href = API_BASE + '/trainings/export/excel' + (qs.length ? '?' + qs.join('&') : '');
}

function exportSurveyToExcel() {
  var qs = [];
  // 2026-06-10 fix: PI / District Lead / State Lead have their filter
  // dropdowns hidden by loadSurveyListData() so reading state_code /
  // district_code from the DOM yields blank values, and the backend
  // happily streamed every state's surveys to the Excel.  Mirror the
  // list-page scope logic — forward state_code + district_code +
  // centre_code from currentUser so the export is restricted to the
  // user's assigned scope (e.g. Delhi / North Delhi for North Delhi
  // PI).  See loadSurveyListData() at ~line 5417 for the matching
  // logic.
  var isRestricted = currentUser && (
    currentUser.role === 'pi' ||
    currentUser.role === 'district_lead' ||
    currentUser.role === 'state_lead'
  );
  var isDlPi = currentUser && (
    currentUser.role === 'pi' ||
    currentUser.role === 'district_lead'
  );

  var stateEl = document.getElementById('surveyFilterState');
  var distEl = document.getElementById('surveyFilterDistrict');
  var flpName = document.getElementById('surveyFilterFlpName');
  var dateFrom = document.getElementById('surveyFilterDateFrom');
  var dateTo = document.getElementById('surveyFilterDateTo');

  if (isDlPi && currentUser.state_code) {
    qs.push('state_code=' + encodeURIComponent(currentUser.state_code));
    if (currentUser.district_code) {
      qs.push('district_code=' + encodeURIComponent(currentUser.district_code));
    }
    if (currentUser.centre_code) {
      qs.push('centre_code=' + encodeURIComponent(currentUser.centre_code));
    }
  } else if (isRestricted && currentUser.state_code) {
    // State Lead — scoped to state only.
    qs.push('state_code=' + encodeURIComponent(currentUser.state_code));
    if (distEl && distEl.value) {
      qs.push('district_code=' + encodeURIComponent(distEl.value));
    }
  } else {
    // Admin / Power User / Super Admin — honour whatever they picked.
    if (stateEl && stateEl.value) qs.push('state_code=' + encodeURIComponent(stateEl.value));
    if (distEl && distEl.value) qs.push('district_code=' + encodeURIComponent(distEl.value));
  }

  if (flpName && flpName.value) qs.push('flp_id=' + flpName.value);
  if (dateFrom && dateFrom.value) qs.push('date_from=' + dateFrom.value);
  if (dateTo && dateTo.value) qs.push('date_to=' + dateTo.value);
  window.location.href = API_BASE + '/surveys/export/excel' + (qs.length ? '?' + qs.join('&') : '');
}

