// ---- BATCH MANAGEMENT ----
function loadBatchManagementData(page) {
  if (!apiAvailable) return;
  if (typeof page === 'number') batchCurrentPage = page;

  var filterParams = { page: batchCurrentPage, limit: batchPageLimit };
  // State Lead AND District Lead: scope batch list strictly to their
  // assigned state. DL was added (April 2026) when the Batch tab was
  // opened up to district leads — they should only ever see batches
  // for their own state, never the national list.
  if (currentUser &&
      (currentUser.role === 'state_lead' || currentUser.role === 'district_lead') &&
      currentUser.state_code) {
    filterParams.state_code = currentUser.state_code;
  }
  apiBatches(filterParams)
    .then(function(result) {
      var data = result.data || result;
      if (!data || data.length === 0) {
        var tbody = document.getElementById('batchManagementTableBody');
        if (tbody) tbody.innerHTML = '<tr><td colspan="7" style="text-align:center;color:#999;padding:30px;">No batch records found.</td></tr>';
        return;
      }
      var tbody = document.getElementById('batchManagementTableBody');
      if (!tbody) return;
      var startIdx = (batchCurrentPage - 1) * batchPageLimit;
      var html = '';
      data.forEach(function(b, idx) {
        html += '<tr>' +
          '<td>' + (startIdx + idx + 1) + '</td>' +
          '<td>' + escHtml(b.name) + '</td>' +
          '<td>' + escHtml(b.year) + '</td>' +
          '<td>' + escHtml(b.state_name || '') + '</td>' +
          '<td>' + (b.flp_count || 0) + '</td>' +
          '<td>' + statusBadge(b.status || 'Active') + '</td>' +
          '<td>' +
            '<button class="btn-icon" title="View" onclick="viewMaster(\'batch\',' + b.id + ')"><i class="fas fa-eye"></i></button> ' +
            '<button class="btn-icon" title="Edit" onclick="openMasterForm(\'batch\',\'edit\',' + b.id + ')"><i class="fas fa-edit"></i></button> ' +
            '<button class="btn-icon" title="Allocate FLPs" onclick="openBatchAllocation(' + b.id + ',\'' + escHtml(b.name).replace(/'/g, "\\'") + '\',\'' + escHtml(b.state_name || '').replace(/'/g, "\\'") + '\')"><i class="fas fa-user-plus"></i></button> ' +
            '<button class="btn-icon text-danger" title="Delete" onclick="deleteBatch(' + b.id + ',\'' + escHtml(b.name).replace(/'/g, "\\'") + '\')"><i class="fas fa-trash-alt"></i></button>' +
          '</td>' +
          '</tr>';
      });
      tbody.innerHTML = html;

      var total = result.total || data.length;
      renderListPagination('#page-batchManagement .pagination', total, batchCurrentPage, batchPageLimit, 'loadBatchManagementData');
      var sel = document.getElementById('batchItemsPerPage');
      if (sel) sel.value = String(batchPageLimit);
    })
    .catch(function() { /* keep hardcoded */ });
}

// ---- BATCH ALLOCATION ----
function deleteBatch(batchId, batchName) {
  if (!confirm('Are you sure you want to delete batch "' + batchName + '"? Any FLPs assigned to this batch will be unlinked.')) return;
  apiDelete('/batches/' + batchId)
    .then(function() {
      alert('Batch deleted successfully.');
      loadBatchManagementData(batchCurrentPage);
    })
    .catch(function(err) {
      showUserError('deleting batch', err);
    });
}

// ============================================================================
// ADMIN DELETE HELPERS — FLP / Assessment / Survey list rows
// ============================================================================
// All three follow the same pattern:
//   1. Confirm with the user (show the human-readable label, not the id).
//   2. Call the matching backend DELETE endpoint via apiDelete.
//   3. On success, reload the current page of the relevant list so the
//      row disappears AND pagination/total counts refresh.
//   4. On error, surface the server's `detail` if any (the
//      `require_admin_role` guard returns 403 with a clean message,
//      which is exactly what we want a non-admin user to see if they
//      somehow trigger this — though the buttons are gated client-side
//      so this is defence-in-depth).
//
// FLP delete is soft (sets `deleted_at`); Assessment + Survey deletes
// are hard.

function deleteFlpFromList(flpId, flpName) {
  if (!flpId) return;
  if (!confirm('Delete FLP "' + flpName + '"? This will hide the record from all lists and dashboards.')) return;
  apiDelete('/flps/' + flpId)
    .then(function() {
      alert('FLP deleted successfully.');
      loadFlpListData(flpCurrentPage);
    })
    .catch(function(err) {
      showUserError('deleting FLP', err);
    });
}

