function openBatchAllocation(batchId, batchName, centreName) {
  allocatingBatchId = batchId;
  var titleEl = document.getElementById('batchAllocationTitle');
  if (titleEl) titleEl.innerHTML = '<i class="fas fa-user-plus"></i> Allocate FLPs to ' + escHtml(batchName);
  var infoEl = document.getElementById('batchAllocationInfo');
  if (infoEl) infoEl.innerHTML = 'Showing unallocated Active FLPs from <strong>' + escHtml(centreName) + '</strong>';
  var tbody = document.getElementById('batchAllocationTableBody');
  if (tbody) tbody.innerHTML = '<tr><td colspan="5" style="text-align:center;color:#999;padding:30px;"><i class="fas fa-spinner fa-spin"></i> Loading...</td></tr>';
  var countEl = document.getElementById('allocateSelectedCount');
  if (countEl) countEl.textContent = '0';
  var selectAllCb = document.getElementById('allocateSelectAll');
  if (selectAllCb) selectAllCb.checked = false;
  var btn = document.getElementById('btnConfirmAllocate');
  if (btn) { btn.disabled = false; btn.innerHTML = '<i class="fas fa-check"></i> Allocate Selected'; }
  document.getElementById('batchAllocationModal').style.display = 'flex';

  apiUnallocatedFlps(batchId)
    .then(function(result) {
      var data = result.data || [];
      if (data.length === 0) {
        tbody.innerHTML = '<tr><td colspan="5" style="text-align:center;color:#999;padding:30px;"><i class="fas fa-info-circle"></i> No unallocated FLPs available for this state.</td></tr>';
        if (btn) btn.disabled = true;
        return;
      }
      var html = '';
      data.forEach(function(flp) {
        html += '<tr>' +
          '<td><input type="checkbox" class="allocate-check" value="' + flp.id + '"></td>' +
          '<td>' + escHtml(flp.enrollment_number) + '</td>' +
          '<td>' + escHtml(flp.name) + '</td>' +
          '<td>' + escHtml(flp.mobile || '') + '</td>' +
          '<td>' + statusBadge(flp.status) + '</td>' +
          '</tr>';
      });
      tbody.innerHTML = html;
    })
    .catch(function(err) {
      tbody.innerHTML = '<tr><td colspan="5" style="text-align:center;color:#e74c3c;padding:30px;"><i class="fas fa-exclamation-triangle"></i> Error loading FLPs</td></tr>';
    });
}

function toggleAllocateSelectAll(masterCheckbox) {
  var checkboxes = document.querySelectorAll('.allocate-check');
  checkboxes.forEach(function(cb) { cb.checked = masterCheckbox.checked; });
  updateAllocateSelectedCount();
}

function updateAllocateSelectedCount() {
  var checked = document.querySelectorAll('.allocate-check:checked').length;
  var el = document.getElementById('allocateSelectedCount');
  if (el) el.textContent = checked;
}

function confirmBatchAllocation() {
  var checkboxes = document.querySelectorAll('.allocate-check:checked');
  if (checkboxes.length === 0) {
    alert('Please select at least one FLP to allocate.');
    return;
  }
  var flpIds = [];
  checkboxes.forEach(function(cb) { flpIds.push(parseInt(cb.value)); });
  if (!confirm('Allocate ' + flpIds.length + ' FLP(s) to this batch?')) return;

  var btn = document.getElementById('btnConfirmAllocate');
  if (btn) { btn.disabled = true; btn.innerHTML = '<i class="fas fa-spinner fa-spin"></i> Allocating...'; }

  apiBatchAllocate(allocatingBatchId, flpIds)
    .then(function(result) {
      alert(result.message || (flpIds.length + ' FLP(s) allocated successfully!'));
      closeMasterModal('batchAllocationModal');
      loadBatchManagementData(batchCurrentPage);
    })
    .catch(function(err) {
      alert('Allocation failed: ' + (err.message || 'Unknown error'));
    })
    .finally(function() {
      if (btn) { btn.disabled = false; btn.innerHTML = '<i class="fas fa-check"></i> Allocate Selected'; }
    });
}

// ---- ROLE MANAGEMENT ----
function loadRoleManagementData(page) {
  if (!apiAvailable) return;
  if (typeof page === 'number') roleCurrentPage = page;

  var filterParams = { page: roleCurrentPage, limit: rolePageLimit };
  apiRoles(filterParams)
    .then(function(result) {
      var data = result.data || result;
      // 2026-06-06: Per user request, hide Power User / Mobiliser /
      // Sangini from the Role Management list. The DB rows stay
      // (existing users may still be assigned to them) — we just
      // suppress them in the management surface. Case-insensitive
      // match on role name so "power user" / "Power User" / "POWER
      // USER" all get filtered.
      var _HIDE = { 'power user': 1, 'mobiliser': 1, 'sangini': 1 };
      if (Array.isArray(data)) {
        data = data.filter(function(r) {
          var nm = ((r && r.name) || '').trim().toLowerCase();
          return !_HIDE[nm];
        });
      }
      if (!data || data.length === 0) {
        var tbody = document.getElementById('roleManagementTableBody');
        if (tbody) tbody.innerHTML = '<tr><td colspan="6" style="text-align:center;color:#999;padding:30px;">No role records found.</td></tr>';
        return;
      }
      var tbody = document.getElementById('roleManagementTableBody');
      if (!tbody) return;
      var startIdx = (roleCurrentPage - 1) * rolePageLimit;
      var html = '';
      data.forEach(function(r, idx) {
        // 6 cells, alignment matches the table header.
        html += '<tr>' +
          '<td>' + (startIdx + idx + 1) + '</td>' +
          '<td><strong style="color:#732269;">' + escHtml(r.name) + '</strong></td>' +
          '<td>' + escHtml(r.description || '') + '</td>' +
          '<td style="text-align:center;font-weight:600;">' + (r.user_count || 0) + '</td>' +
          '<td style="text-align:center;">' + statusBadge(r.status || 'Active') + '</td>' +
          '<td style="text-align:center;white-space:nowrap;">' +
            '<button class="btn-icon" title="View" onclick="viewRole(' + r.id + ')"><i class="fas fa-eye"></i></button> ' +
            '<button class="btn-icon" title="Edit" onclick="openRoleFormModal(\'edit\',' + r.id + ')"><i class="fas fa-edit"></i></button>' +
          '</td>' +
          '</tr>';
      });
      tbody.innerHTML = html;

      var total = result.total || data.length;
      renderListPagination('#page-roleManagement .pagination', total, roleCurrentPage, rolePageLimit, 'loadRoleManagementData');
      var sel = document.getElementById('roleItemsPerPage');
      if (sel) sel.value = String(rolePageLimit);
    })
    .catch(function() { /* keep hardcoded */ });
}

