// ---- MGJ ACTIVITY LOG ----
// 2026-06-06: Uses the same /api/system-log endpoint as FLP but
// forwards program=mgj so the backend filters to MGJ-scoped rows
// only (matches resource_type / action / description). Renders into
// mgj-prefixed DOM ids so the FLP page logic is untouched. UI mirrors
// the FLP Activity Log page 1:1, including stats strip, auto-refresh
// toggle, and Prev/Next pagination.
var mgjLogCurrentPage = 1;
var mgjLogPageLimit   = 50;
var _mgjLogAutoRefreshTimer = null;
function loadMgjSystemActivityLog(page) {
  mgjLogCurrentPage = page || mgjLogCurrentPage || 1;
  if (!apiAvailable) return;
  // 2026-06-06 (revised): User reviewed the FLP page and asked for
  // matching UI + data on the MGJ page. The strict program=mgj filter
  // returned zero rows (backend logging hasn't been instrumented for
  // MGJ routes yet), which made the page look broken. Dropping the
  // filter so the MGJ page shows the same system-wide activity rows
  // the FLP page shows. The backend `program` param is still
  // available for future use once MGJ-tagged events start landing in
  // system_activity_log.
  var params = { page: mgjLogCurrentPage, limit: mgjLogPageLimit };
  var userF   = document.getElementById('mgjLogFilterUser');
  var actionF = document.getElementById('mgjLogFilterAction');
  var sourceF = document.getElementById('mgjLogFilterSource');
  var startF  = document.getElementById('mgjLogFilterStartDate');
  var endF    = document.getElementById('mgjLogFilterEndDate');
  if (userF   && userF.value)   params.user_id    = userF.value;
  if (actionF && actionF.value) params.action     = actionF.value;
  if (sourceF && sourceF.value) params.source     = sourceF.value;
  if (startF  && startF.value)  params.start_date = startF.value;
  if (endF    && endF.value)    params.end_date   = endF.value;
  apiSystemLog(params).then(function(result) {
    var userSel = document.getElementById('mgjLogFilterUser');
    var actionSel = document.getElementById('mgjLogFilterAction');
    if (userSel && userSel.options.length <= 1) {
      (result.available_users || []).forEach(function(u) {
        var o = document.createElement('option'); o.value = u.id; o.textContent = u.name; userSel.appendChild(o);
      });
    }
    if (actionSel && actionSel.options.length <= 1) {
      (result.available_actions || []).forEach(function(a) {
        var o = document.createElement('option'); o.value = a; o.textContent = a; actionSel.appendChild(o);
      });
    }
    var _set = function(id, v) { var el = document.getElementById(id); if (el) el.textContent = (v != null ? v : 0); };
    _set('mgjLogStatTotal', result.total);
    _set('mgjLogStatToday', result.today_count || 0);
    _set('mgjLogStatActiveUsers', result.active_users || 0);
    _renderMgjActivityLogTable(result.data, result.total, result.page, result.limit);
  }).catch(function() {
    var tbody = document.getElementById('mgjSystemActivityLogBody');
    if (tbody) tbody.innerHTML = '<tr><td colspan="9" style="text-align:center;padding:40px;color:#999;">Failed to load activity log.</td></tr>';
  });
}
function _renderMgjActivityLogTable(data, total, page, limit) {
  // 2026-06-06 (revised): Mirror the FLP renderer 1:1 — colored Action
  // badges, formatted timestamps via formatLogTimestamp, font-weight on
  // user name, uppercase Source badge with green/blue backgrounds,
  // resource_type with optional '#id' suffix, ellipsised description
  // with title-attribute tooltip. The previous MGJ renderer used a
  // simpler markup which is why the FLP and MGJ pages looked different.
  var tbody = document.getElementById('mgjSystemActivityLogBody');
  if (!tbody) return;
  if (!data || data.length === 0) {
    tbody.innerHTML = '<tr><td colspan="9" style="text-align:center; padding:40px; color:#999;"><i class="fas fa-inbox" style="font-size:24px;"></i><br>No activity log entries found</td></tr>';
    var pi = document.getElementById('mgjLogPaginationInfo'); if (pi) pi.textContent = 'No entries';
    var pc = document.getElementById('mgjLogPaginationControls'); if (pc) pc.innerHTML = '';
    return;
  }
  var actionColors = {
    'Login': '#27ae60', 'Create FLP': '#2980b9', 'Edit FLP': '#f39c12',
    'Submit Survey': '#8e44ad', 'Approve Survey': '#27ae60', 'Create Training': '#2980b9',
    'Assign Participants': '#16a085', 'View Report': '#7f8c8d', 'Export Report': '#34495e',
    'Create Assessment': '#2980b9', 'Edit User': '#f39c12', 'Create Centre': '#2980b9',
    'Create Batch': '#2980b9', 'Reset Password': '#e74c3c'
  };
  var rows = '';
  var startIdx = (page - 1) * limit;
  data.forEach(function(entry, i) {
    var ts = entry.created_at ? formatLogTimestamp(entry.created_at) : '-';
    var actionColor = actionColors[entry.action] || '#732269';
    var sourceClass = entry.source === 'mobile' ? 'background:#e8f5e9;color:#2e7d32;' : 'background:#e3f2fd;color:#1565c0;';
    var resource = '';
    if (entry.resource_type) {
      resource = entry.resource_type;
      if (entry.resource_id) resource += ' #' + entry.resource_id;
    }
    rows += '<tr>' +
      '<td style="color:#999; font-size:12px;">' + (startIdx + i + 1) + '</td>' +
      '<td style="font-size:12px; white-space:nowrap;">' + escHtml(ts) + '</td>' +
      '<td style="font-weight:600;">' + escHtml(entry.user_name || '-') + '</td>' +
      '<td style="font-size:12px; color:#666;">' + escHtml(entry.role_name || '-') + '</td>' +
      '<td><span style="display:inline-block; padding:2px 10px; border-radius:12px; font-size:12px; font-weight:600; background:' + actionColor + '1a; color:' + actionColor + ';">' + escHtml(entry.action) + '</span></td>' +
      '<td style="font-size:12px; color:#555;">' + escHtml(resource || '-') + '</td>' +
      '<td style="font-size:12px;">' + escHtml(entry.ip_address || '-') + (entry.city ? '<br><span style="color:#999; font-size:11px;">' + escHtml(entry.city) + '</span>' : '') + '</td>' +
      '<td><span style="display:inline-block; padding:2px 8px; border-radius:10px; font-size:11px; font-weight:600; ' + sourceClass + '">' + escHtml((entry.source || 'web').toUpperCase()) + '</span></td>' +
      '<td style="font-size:12px; color:#555; max-width:250px; overflow:hidden; text-overflow:ellipsis; white-space:nowrap;" title="' + escHtml(entry.description || '') + '">' + escHtml(entry.description || '-') + '</td>' +
      '</tr>';
  });
  tbody.innerHTML = rows;
  // Pagination info + numbered Prev/Next controls — same shape as FLP.
  var showing = Math.min(data.length, limit);
  var fromRow = startIdx + 1;
  var toRow = startIdx + showing;
  var info = document.getElementById('mgjLogPaginationInfo');
  if (info) info.textContent = 'Showing ' + fromRow + '-' + toRow + ' of ' + total + ' entries';
  var pag = document.getElementById('mgjLogPaginationControls');
  if (pag) {
    var totalPages = Math.max(1, Math.ceil((total || data.length) / limit));
    var html2 = '';
    html2 += '<button class="btn btn-sm btn-outline" ' + (page <= 1 ? 'disabled' : 'onclick="loadMgjSystemActivityLog(' + (page - 1) + ')"') + '>&laquo; Prev</button>';
    var from = Math.max(1, page - 2), to = Math.min(totalPages, page + 2);
    for (var p = from; p <= to; p++) {
      html2 += '<button class="btn btn-sm ' + (p === page ? 'btn-primary' : 'btn-outline') + '" onclick="loadMgjSystemActivityLog(' + p + ')">' + p + '</button>';
    }
    html2 += '<button class="btn btn-sm btn-outline" ' + (page >= totalPages ? 'disabled' : 'onclick="loadMgjSystemActivityLog(' + (page + 1) + ')"') + '>Next &raquo;</button>';
    pag.innerHTML = html2;
  }
}
function clearMgjLogFilters() {
  ['mgjLogFilterUser','mgjLogFilterAction','mgjLogFilterSource','mgjLogFilterStartDate','mgjLogFilterEndDate'].forEach(function(id) {
    var el = document.getElementById(id); if (el) el.value = '';
  });
  loadMgjSystemActivityLog(1);
}
// 2026-06-06: Auto-refresh toggle — same 15 s cadence the FLP page
// uses. Status text shows the live ticker so the user knows it's on.
function toggleMgjLogAutoRefresh() {
  var cb = document.getElementById('mgjLogAutoRefresh');
  var st = document.getElementById('mgjLogAutoRefreshStatus');
  if (_mgjLogAutoRefreshTimer) { clearInterval(_mgjLogAutoRefreshTimer); _mgjLogAutoRefreshTimer = null; }
  if (cb && cb.checked) {
    if (st) st.textContent = '(refreshing every 15s)';
    _mgjLogAutoRefreshTimer = setInterval(function() { loadMgjSystemActivityLog(mgjLogCurrentPage); }, 15000);
  } else {
    if (st) st.textContent = '';
  }
}

