function _renderAkActivityLogTable(data, total, page, limit) {
  var tbody = document.getElementById('akSystemActivityLogBody');
  if (!tbody) return;
  if (!data || data.length === 0) {
    tbody.innerHTML = '<tr><td colspan="9" style="text-align:center; padding:40px; color:#999;"><i class="fas fa-inbox" style="font-size:24px;"></i><br>No activity log entries found</td></tr>';
    var pi = document.getElementById('akLogPaginationInfo'); if (pi) pi.textContent = 'No entries';
    var pc = document.getElementById('akLogPaginationControls'); if (pc) pc.innerHTML = '';
    return;
  }
  var actionColors = {
    'Login': '#27ae60', 'Create FLP': '#2980b9', 'Edit FLP': '#f39c12',
    'Submit Survey': '#8e44ad', 'Approve Survey': '#27ae60', 'Create Training': '#2980b9',
    'Assign Participants': '#16a085', 'View Report': '#7f8c8d', 'Export Report': '#34495e',
    'Create Assessment': '#2980b9', 'Edit User': '#f39c12', 'Create Centre': '#2980b9',
    'Create Batch': '#2980b9', 'Reset Password': '#e74c3c'
  };
  var rows = '';
  var startIdx = (page - 1) * limit;
  data.forEach(function(entry, i) {
    var ts = entry.created_at ? formatLogTimestamp(entry.created_at) : '-';
    var actionColor = actionColors[entry.action] || '#732269';
    var sourceClass = entry.source === 'mobile' ? 'background:#e8f5e9;color:#2e7d32;' : 'background:#e3f2fd;color:#1565c0;';
    var resource = '';
    if (entry.resource_type) {
      resource = entry.resource_type;
      if (entry.resource_id) resource += ' #' + entry.resource_id;
    }
    rows += '<tr>' +
      '<td style="color:#999; font-size:12px;">' + (startIdx + i + 1) + '</td>' +
      '<td style="font-size:12px; white-space:nowrap;">' + escHtml(ts) + '</td>' +
      '<td style="font-weight:600;">' + escHtml(entry.user_name || '-') + '</td>' +
      '<td style="font-size:12px; color:#666;">' + escHtml(entry.role_name || '-') + '</td>' +
      '<td><span style="display:inline-block; padding:2px 10px; border-radius:12px; font-size:12px; font-weight:600; background:' + actionColor + '1a; color:' + actionColor + ';">' + escHtml(entry.action) + '</span></td>' +
      '<td style="font-size:12px; color:#555;">' + escHtml(resource || '-') + '</td>' +
      '<td style="font-size:12px;">' + escHtml(entry.ip_address || '-') + (entry.city ? '<br><span style="color:#999; font-size:11px;">' + escHtml(entry.city) + '</span>' : '') + '</td>' +
      '<td><span style="display:inline-block; padding:2px 8px; border-radius:10px; font-size:11px; font-weight:600; ' + sourceClass + '">' + escHtml((entry.source || 'web').toUpperCase()) + '</span></td>' +
      '<td style="font-size:12px; color:#555; max-width:250px; overflow:hidden; text-overflow:ellipsis; white-space:nowrap;" title="' + escHtml(entry.description || '') + '">' + escHtml(entry.description || '-') + '</td>' +
      '</tr>';
  });
  tbody.innerHTML = rows;
  var showing = Math.min(data.length, limit);
  var fromRow = startIdx + 1;
  var toRow = startIdx + showing;
  var info = document.getElementById('akLogPaginationInfo');
  if (info) info.textContent = 'Showing ' + fromRow + '-' + toRow + ' of ' + total + ' entries';
  var pag = document.getElementById('akLogPaginationControls');
  if (pag) {
    var totalPages = Math.max(1, Math.ceil((total || data.length) / limit));
    var html2 = '';
    html2 += '<button class="btn btn-sm btn-outline" ' + (page <= 1 ? 'disabled' : 'onclick="loadAkSystemActivityLog(' + (page - 1) + ')"') + '>&laquo; Prev</button>';
    var from = Math.max(1, page - 2), to = Math.min(totalPages, page + 2);
    for (var p = from; p <= to; p++) {
      html2 += '<button class="btn btn-sm ' + (p === page ? 'btn-primary' : 'btn-outline') + '" onclick="loadAkSystemActivityLog(' + p + ')">' + p + '</button>';
    }
    html2 += '<button class="btn btn-sm btn-outline" ' + (page >= totalPages ? 'disabled' : 'onclick="loadAkSystemActivityLog(' + (page + 1) + ')"') + '>Next &raquo;</button>';
    pag.innerHTML = html2;
  }
}
function clearAkLogFilters() {
  ['akLogFilterUser','akLogFilterAction','akLogFilterSource','akLogFilterStartDate','akLogFilterEndDate'].forEach(function(id) {
    var el = document.getElementById(id); if (el) el.value = '';
  });
  loadAkSystemActivityLog(1);
}
function toggleAkLogAutoRefresh() {
  var cb = document.getElementById('akLogAutoRefresh');
  var st = document.getElementById('akLogAutoRefreshStatus');
  if (_akLogAutoRefreshTimer) { clearInterval(_akLogAutoRefreshTimer); _akLogAutoRefreshTimer = null; }
  if (cb && cb.checked) {
    if (st) st.textContent = '(refreshing every 15s)';
    _akLogAutoRefreshTimer = setInterval(function() { loadAkSystemActivityLog(akLogCurrentPage); }, 15000);
  } else {
    if (st) st.textContent = '';
  }
}

// ---- USER MANAGEMENT ----
function loadUserManagementData(page) {
  if (!apiAvailable) return;
  if (typeof page === 'number') userCurrentPage = page;

  var filterParams = {};
  var nameEl = document.getElementById('userFilterName');
  var role = document.getElementById('userFilterRole');
  var status = document.getElementById('userFilterStatus');
  var stateEl = document.getElementById('userFilterState');
  var distEl = document.getElementById('userFilterDistrict');
  var centreEl = document.getElementById('userFilterCentre');
  if (nameEl && nameEl.value.trim()) filterParams.name = nameEl.value.trim();
  if (role && role.value) filterParams.role_id = role.value;
  if (status && status.value) filterParams.status = status.value;
  if (stateEl && stateEl.value) filterParams.state_code = stateEl.value;
  if (distEl && distEl.value) filterParams.district_code = distEl.value;
  if (centreEl && centreEl.value) filterParams.centre_code = centreEl.value;
  filterParams.page = userCurrentPage;
  filterParams.limit = userPageLimit;

  apiUsers(filterParams)
    .then(function(result) {
      var data = result.data || result;
      if (!Array.isArray(data)) data = result;
      var tbody = document.getElementById('userManagementTableBody');
      if (!tbody) return;
      if (!data || data.length === 0) {
        tbody.innerHTML = '<tr><td colspan="8" style="text-align:center;color:#999;padding:30px;">No users found.</td></tr>';
        return;
      }
      var startIdx = (userCurrentPage - 1) * userPageLimit;
      var html = '';
      data.forEach(function(u, idx) {
        var uid = u.id;
        html += '<tr>' +
          '<td>' + (startIdx + idx + 1) + '</td>' +
          '<td><strong>' + escHtml(u.name) + '</strong></td>' +
          '<td>' + escHtml(u.email) + '</td>' +
          '<td>' + escHtml(u.role_name || '') + '</td>' +
          '<td>' + escHtml(u.geo_scope || '') + '</td>' +
          '<td>' + statusBadge(u.status) + '</td>' +
          '<td>' + formatDateNice(u.last_login) + '</td>' +
          '<td>' +
            '<button class="btn-icon" title="View" onclick="openViewUser(' + uid + ')"><i class="fas fa-eye"></i></button> ' +
            '<button class="btn-icon" title="Edit" onclick="openEditUser(' + uid + ')"><i class="fas fa-edit"></i></button> ' +
            '<button class="btn-icon" title="Reset Password" onclick="resetUserPassword(' + uid + ')"><i class="fas fa-key"></i></button> ' +
            '<button class="btn-icon text-danger" title="Delete" onclick="deleteUser(' + uid + ',\'' + escHtml(u.name).replace(/'/g, "\\'") + '\')"><i class="fas fa-trash-alt"></i></button>' +
          '</td>' +
          '</tr>';
      });
      tbody.innerHTML = html;

      var total = result.total || data.length;
      renderListPagination('#page-userManagement .pagination', total, userCurrentPage, userPageLimit, 'loadUserManagementData');
      var userSel = document.getElementById('userItemsPerPage');
      if (userSel) userSel.value = String(userPageLimit);
    })
    .catch(function() { /* keep hardcoded */ });
}


// =============================================================================
// 6A. ROLE CRUD FUNCTIONS
// =============================================================================

/**
 * Open the Role Form modal in 'add' or 'edit' mode.
 */
function openRoleFormModal(mode, roleIndex) {
  roleModalMode = mode;
  editingRoleId = (mode === 'edit') ? roleIndex : null;

  var titleEl = document.getElementById('roleFormModalTitle');
  var submitEl = document.getElementById('roleFormSubmitText');

  // Clear all fields
  document.getElementById('roleFormName').value = '';
  document.getElementById('roleFormDescription').value = '';
  document.getElementById('roleFormStatus').value = 'Active';
  document.getElementById('roleModDashboard').checked = false;
  document.getElementById('roleModFLP').checked = false;
  document.getElementById('roleModActivity').checked = false;
  document.getElementById('roleModAssessment').checked = false;
  document.getElementById('roleModMaster').checked = false;
  document.getElementById('roleModSettings').checked = false;
  document.getElementById('roleCapEdit').checked = false;
  document.getElementById('roleCapUsers').checked = false;
  document.getElementById('roleCapMaster').checked = false;
  document.getElementById('roleCapRoles').checked = false;

  if (mode === 'edit' && DEMO_ROLES[roleIndex]) {
    var role = DEMO_ROLES[roleIndex];
    titleEl.innerHTML = '<i class="fas fa-edit"></i> Edit Role';
    submitEl.textContent = 'Update Role';
    document.getElementById('roleFormName').value = role.name;
    document.getElementById('roleFormDescription').value = role.description;
    document.getElementById('roleFormStatus').value = role.status;
    // Check module checkboxes
    if (role.modules.indexOf('Dashboard') >= 0) document.getElementById('roleModDashboard').checked = true;
    if (role.modules.indexOf('FLP') >= 0) document.getElementById('roleModFLP').checked = true;
    if (role.modules.indexOf('Activity') >= 0) document.getElementById('roleModActivity').checked = true;
    if (role.modules.indexOf('Assessment') >= 0) document.getElementById('roleModAssessment').checked = true;
    if (role.modules.indexOf('Master') >= 0) document.getElementById('roleModMaster').checked = true;
    if (role.modules.indexOf('Settings') >= 0) document.getElementById('roleModSettings').checked = true;
    // Check capability checkboxes
    if (role.capabilities.canEdit) document.getElementById('roleCapEdit').checked = true;
    if (role.capabilities.canManageUsers) document.getElementById('roleCapUsers').checked = true;
    if (role.capabilities.canManageMaster) document.getElementById('roleCapMaster').checked = true;
    if (role.capabilities.canManageRoles) document.getElementById('roleCapRoles').checked = true;
  } else {
    titleEl.innerHTML = '<i class="fas fa-plus-circle"></i> Add Role';
    submitEl.textContent = 'Save Role';
  }

  document.getElementById('roleFormModal').style.display = 'flex';
}

function closeRoleFormModal() {
  document.getElementById('roleFormModal').style.display = 'none';
}

/**
 * Save the role (add or edit mode).
 */
function saveRole() {
  var name = document.getElementById('roleFormName').value.trim();
  if (!name) {
    alert('Please enter a role name.');
    return;
  }

  var description = document.getElementById('roleFormDescription').value.trim();
  var status = document.getElementById('roleFormStatus').value;

  // Collect modules
  var modules = [];
  if (document.getElementById('roleModDashboard').checked) modules.push('Dashboard');
  if (document.getElementById('roleModFLP').checked) modules.push('FLP');
  if (document.getElementById('roleModActivity').checked) modules.push('Activity');
  if (document.getElementById('roleModAssessment').checked) modules.push('Assessment');
  if (document.getElementById('roleModMaster').checked) modules.push('Master');
  if (document.getElementById('roleModSettings').checked) modules.push('Settings');

  // Collect capabilities
  var capabilities = {
    canEdit: document.getElementById('roleCapEdit').checked,
    canManageUsers: document.getElementById('roleCapUsers').checked,
    canManageMaster: document.getElementById('roleCapMaster').checked,
    canManageRoles: document.getElementById('roleCapRoles').checked
  };

  if (roleModalMode === 'edit' && editingRoleId !== null && DEMO_ROLES[editingRoleId]) {
    // Update existing role in DEMO_ROLES
    DEMO_ROLES[editingRoleId].name = name;
    DEMO_ROLES[editingRoleId].description = description;
    DEMO_ROLES[editingRoleId].status = status;
    DEMO_ROLES[editingRoleId].modules = modules;
    DEMO_ROLES[editingRoleId].capabilities = capabilities;
    alert('Role "' + name + '" updated successfully!');
  } else {
    // Add new role
    DEMO_ROLES.push({
      id: DEMO_ROLES.length + 1,
      name: name,
      key: name.toLowerCase().replace(/[^a-z0-9]/g, '_'),
      description: description,
      modules: modules,
      capabilities: capabilities,
      userCount: 0,
      status: status
    });
    alert('Role "' + name + '" created successfully!');
  }

  closeRoleFormModal();
}

/**
 * View role details in the read-only modal.
 */
function viewRole(roleIndex) {
  if (!DEMO_ROLES[roleIndex]) return;
  editingRoleId = roleIndex;
  var role = DEMO_ROLES[roleIndex];

  // Build module badges
  var moduleBadges = '';
  role.modules.forEach(function(m) {
    moduleBadges += '<span class="badge" style="background:#f8f0f7;color:#732269;padding:4px 12px;font-size:12px;">' + escHtml(m) + '</span> ';
  });

  // Build capability list
  function capIcon(val, label) {
    if (val) {
      return '<li><i class="fas fa-check-circle" style="color:#27ae60;"></i> ' + label + '</li>';
    }
    return '<li><i class="fas fa-times-circle" style="color:#e74c3c;"></i> ' + label + '</li>';
  }

  var capList = '<ul class="capability-list">' +
    capIcon(role.capabilities.canEdit, 'Can Edit Data') +
    capIcon(role.capabilities.canManageUsers, 'Can Manage Users') +
    capIcon(role.capabilities.canManageMaster, 'Can Manage Master Data') +
    capIcon(role.capabilities.canManageRoles, 'Can Manage Roles') +
    '</ul>';

  var statusBadgeHtml = role.status === 'Active'
    ? '<span class="badge badge-active">Active</span>'
    : '<span class="badge badge-walkout">Inactive</span>';

  var bodyHtml = '' +
    '<div style="margin-bottom:18px;">' +
      '<h2 style="color:#732269;margin:0 0 4px 0;">' + escHtml(role.name) + '</h2>' +
      '<div style="display:flex;gap:8px;align-items:center;">' + statusBadgeHtml + ' <span style="color:var(--text-light);font-size:13px;">' + role.userCount + ' user(s) assigned</span></div>' +
    '</div>' +
    '<div class="view-section" style="margin-bottom:18px;">' +
      '<h3 style="color:#732269;font-size:14px;margin-bottom:8px;padding-bottom:6px;border-bottom:1px solid var(--border);"><i class="fas fa-info-circle"></i> Description</h3>' +
      '<p style="font-size:13px;color:var(--text);line-height:1.5;margin:0;">' + escHtml(role.description) + '</p>' +
    '</div>' +
    '<div class="view-section" style="margin-bottom:18px;">' +
      '<h3 style="color:#732269;font-size:14px;margin-bottom:8px;padding-bottom:6px;border-bottom:1px solid var(--border);"><i class="fas fa-th-large"></i> Module Access</h3>' +
      '<div style="display:flex;flex-wrap:wrap;gap:6px;">' + (moduleBadges || '<span style="color:var(--text-light);font-style:italic;">No modules assigned</span>') + '</div>' +
    '</div>' +
    '<div class="view-section">' +
      '<h3 style="color:#732269;font-size:14px;margin-bottom:8px;padding-bottom:6px;border-bottom:1px solid var(--border);"><i class="fas fa-key"></i> Capabilities</h3>' +
      capList +
    '</div>';

  document.getElementById('roleViewBody').innerHTML = bodyHtml;
  document.getElementById('roleViewModal').style.display = 'flex';
}

function closeRoleViewModal() {
  document.getElementById('roleViewModal').style.display = 'none';
}

function editRoleFromView() {
  closeRoleViewModal();
  openRoleFormModal('edit', editingRoleId);
}


// =============================================================================
// 6B. USER CRUD FUNCTIONS
// =============================================================================

// Color mapping for role avatars
var ROLE_AVATAR_COLORS = {
  'super_admin': '#732269',
  'admin': '#3498db',
  'pi': '#27ae60',
  'flp': '#f39c12',
  'power_user': '#9b59b6'
};

var ROLE_AVATAR_INITIALS = {
  'super_admin': 'SA',
  'admin': 'AD',
  'pi': 'PI',
  'flp': 'FL',
  'power_user': 'PU'
};

/**
 * Navigate to Add User form (blank).
 */
function openAddUser() {
  userFormMode = 'add';
  editingUserId = null;
  navigateTo('addUser');

  // Wait a tick for the page to become visible, then reset form
  setTimeout(function() {
    document.getElementById('addUserTitle').innerHTML = '<i class="fas fa-user-plus"></i> Add New User';
    document.getElementById('addUserBreadcrumb').innerHTML = '<a href="#" onclick="navigateTo(\'dashboard\');return false;"><i class="fas fa-home"></i> Home</a> <span class="bc-sep">\u203A</span> <a href="#" onclick="navigateTo(\'userManagement\');return false;">Settings</a> <span class="bc-sep">\u203A</span> Add User';
    document.getElementById('userFormSubmitText').textContent = 'Save User';
    document.getElementById('userFormName').value = '';
    document.getElementById('userFormEmail').value = '';
    document.getElementById('userFormPhone').value = '';
    document.getElementById('userFormLoginId').value = '';
    document.getElementById('userFormPassword').value = '';
    document.getElementById('userFormRole').value = '';
    document.getElementById('userFormState').value = '';
    document.getElementById('userFormDistrict').innerHTML = '<option value="">Select District</option>';
    document.getElementById('userFormCentre').innerHTML = '<option value="">Select Centre</option>';
    document.getElementById('userFormStatus').value = 'Active';
    document.getElementById('userFormPasswordGroup').style.display = '';
    document.getElementById('userFormStateGroup').style.display = 'none';
    document.getElementById('userFormDistrictGroup').style.display = 'none';
    document.getElementById('userFormCentreGroup').style.display = 'none';
    // Clear program checkboxes — default all checked for admin roles
    document.querySelectorAll('input[name="userProgram"]').forEach(function(cb) { cb.checked = true; });
  }, 50);
}

/**
 * Navigate to Edit User form (pre-populated).
 */
function openEditUser(userId) {
  userFormMode = 'edit';
  editingUserId = userId;
  navigateTo('addUser');

  setTimeout(function() {
    document.getElementById('addUserTitle').innerHTML = '<i class="fas fa-user-edit"></i> Edit User';
    document.getElementById('addUserBreadcrumb').innerHTML = '<a href="#" onclick="navigateTo(\'dashboard\');return false;"><i class="fas fa-home"></i> Home</a> <span class="bc-sep">\u203A</span> <a href="#" onclick="navigateTo(\'userManagement\');return false;">Settings</a> <span class="bc-sep">\u203A</span> Edit User';
    document.getElementById('userFormSubmitText').textContent = 'Update User';
    document.getElementById('userFormPasswordGroup').style.display = 'none';

    // Fetch user from API
    apiUserDetail(userId).then(function(user) {
      // Map role_id back to role key
      var roleKeyMap = { 1: 'super_admin', 2: 'admin', 3: 'pi', 4: 'flp', 5: 'power_user', 6: 'state_lead', 7: 'district_lead' };
      var roleKey = roleKeyMap[user.role_id] || '';

      document.getElementById('addUserTitle').innerHTML = '<i class="fas fa-user-edit"></i> Edit User — ' + escHtml(user.name);
      document.getElementById('userFormName').value = user.name || '';
      document.getElementById('userFormEmail').value = user.email || '';
      document.getElementById('userFormPhone').value = user.phone || '';
      document.getElementById('userFormLoginId').value = user.username || '';
      document.getElementById('userFormPassword').value = '';
      document.getElementById('userFormRole').value = roleKey;
      document.getElementById('userFormStatus').value = user.status || 'Active';
      toggleUserCentreField();
      if (user.geo_scope) {
        // `toggleUserCentreField()` above already kicked off a state-dropdown
        // populator (loadGeoStateDropdown). Doing a SECOND apiGeoDropdownStates
        // call here used to race that one and produce duplicate <option>s
        // ("Delhi, Delhi, Rajasthan, Rajasthan…"). Use setDropdownOptions
        // which writes innerHTML atomically + dedupes by state_code, so
        // even with two concurrent fetches the user only ever sees each
        // state once. The second branch (DL/PI) just adds an info hint
        // about the current centre/district assignment — same dropdown
        // behaviour as state_lead.
        if (roleKey === 'state_lead' || roleKey === 'district_lead' || roleKey === 'pi') {
          var stateSel = document.getElementById('userFormState');
          if (stateSel) {
            apiGeoDropdownStates().then(function(states) {
              var rows = states && states.data ? states.data : (states || []);
              // For state_lead the geo_scope IS the state name, so use it
              // to pre-select. For DL/PI geo_scope is "Centre, District"
              // which doesn't match a state name; we can't auto-pick the
              // state from that alone, so just dedupe-render the list.
              var preselectCode = null;
              if (roleKey === 'state_lead') {
                for (var i = 0; i < rows.length; i++) {
                  if ((rows[i].state_name || '') === user.geo_scope) {
                    preselectCode = rows[i].state_code;
                    break;
                  }
                }
              }
              setDropdownOptions(
                stateSel, rows,
                function(s) { return s.state_code; },
                function(s) { return s.state_name; },
                {
                  placeholder: '<option value="">Select State</option>',
                  selectedValue: preselectCode,
                }
              );
            }).catch(function() {});
          }

          // Show "Current assignment" hint for DL / PI so admins know which
          // centre/district the user is currently mapped to.
          if (roleKey === 'district_lead' || roleKey === 'pi') {
            var infoEl = document.getElementById('userFormCentreGroup');
            if (infoEl) {
              var existing = document.getElementById('userFormScopeHint');
              if (existing) existing.remove();
              var hint = document.createElement('small');
              hint.style.cssText = 'color:#732269;font-size:11px;display:block;margin-top:4px;';
              hint.textContent = 'Current assignment: ' + user.geo_scope;
              hint.id = 'userFormScopeHint';
              infoEl.appendChild(hint);
            }
          }
        }
      }
      // Load and pre-fill program checkboxes
      document.querySelectorAll('input[name="userProgram"]').forEach(function(cb) { cb.checked = false; });
      if (typeof apiGetUserPrograms === 'function') {
        apiGetUserPrograms(userId).then(function(progs) {
          var codes = progs.map(function(p) { return p.code; });
          document.querySelectorAll('input[name="userProgram"]').forEach(function(cb) {
            if (codes.indexOf(cb.value) >= 0) cb.checked = true;
          });
        }).catch(function() {});
      }

    }).catch(function(err) {
      showUserError('loading user', err);
    });
  }, 50);
}

/**
 * Navigate to View User page.
 */
function openViewUser(userId) {
  viewingUserId = userId;
  navigateTo('viewUser');
}

/**
 * Populate the View User page with data from API.
 */
function loadViewUserData() {
  if (!viewingUserId) return;

  apiUserDetail(viewingUserId).then(function(user) {
    // Map role_id to role key for permissions lookup
    var roleKeyMap = { 1: 'super_admin', 2: 'admin', 3: 'pi', 4: 'flp', 5: 'power_user', 6: 'state_lead', 7: 'district_lead' };
    var roleKey = roleKeyMap[user.role_id] || '';
    var roleName = user.role_name || '';

    var roleColor = ROLE_AVATAR_COLORS[roleKey] || '#732269';
    var initials = ROLE_AVATAR_INITIALS[roleKey] || 'U';

    // Breadcrumb
    document.getElementById('viewUserBreadcrumb').innerHTML =
      '<a href="#" onclick="navigateTo(\'dashboard\');return false;"><i class="fas fa-home"></i> Home</a> <span class="bc-sep">\u203A</span> <a href="#" onclick="navigateTo(\'userManagement\');return false;">Settings</a> <span class="bc-sep">\u203A</span> ' + escHtml(user.name);

    // Avatar
    document.getElementById('viewUserAvatar').style.background = roleColor;
    document.getElementById('viewUserAvatar').textContent = initials;

    // Name
    document.getElementById('viewUserName').textContent = user.name;

    // Subtitle (role badge + status badge)
    var roleBadge = '<span class="badge" style="background:' + roleColor + '22;color:' + roleColor + ';padding:4px 12px;font-weight:600;">' + escHtml(roleName) + '</span>';
    var sBadgeClass = user.status === 'Active' ? 'badge-active' : 'badge-inactive';
    var statusBadge2 = '<span class="badge ' + sBadgeClass + '">' + escHtml(user.status || 'Active') + '</span>';
    document.getElementById('viewUserSubtitle').innerHTML = roleBadge + ' ' + statusBadge2;

    // Account Details grid
    document.getElementById('viewUserAccountGrid').innerHTML =
      '<div class="detail-item"><label>Email</label><span>' + escHtml(user.email) + '</span></div>' +
      '<div class="detail-item"><label>User ID / Login</label><span>' + escHtml(user.username || '') + '</span></div>' +
      '<div class="detail-item"><label>Phone</label><span>Not provided</span></div>' +
      '<div class="detail-item"><label>Last Login</label><span>' + formatDateNice(user.last_login) + '</span></div>' +
      '<div class="detail-item"><label>Created</label><span>' + formatDateNice(user.created_at) + '</span></div>' +
      '<div class="detail-item"><label>Status</label><span><span class="badge ' + sBadgeClass + '">' + escHtml(user.status || 'Active') + '</span></span></div>';

    // Role & Access grid
    document.getElementById('viewUserRoleGrid').innerHTML =
      '<div class="detail-item"><label>Role</label><span>' + escHtml(roleName) + '</span></div>' +
      '<div class="detail-item"><label>Centre / Scope</label><span>' + escHtml(user.geo_scope || 'National (All Centres)') + '</span></div>';

    // Capabilities
    var perms = ROLE_PERMISSIONS[roleKey] || {};
    function capRow(val, label) {
      var icon = val
        ? '<i class="fas fa-check-circle" style="color:#27ae60;"></i>'
        : '<i class="fas fa-times-circle" style="color:#e74c3c;"></i>';
      return '<li>' + icon + ' ' + label + '</li>';
    }
    var navModules = (perms.navGroups || []).map(function(g) {
      return '<span class="badge" style="background:#f8f0f7;color:#732269;padding:3px 10px;font-size:11px;">' + g.charAt(0).toUpperCase() + g.slice(1) + '</span>';
    }).join(' ');

    document.getElementById('viewUserCapabilities').innerHTML =
      '<div style="margin-bottom:12px;"><strong style="font-size:12px;color:var(--text-light);text-transform:uppercase;">Accessible Modules</strong><br>' +
      '<div style="display:flex;flex-wrap:wrap;gap:6px;margin-top:6px;">' + (navModules || '<span style="color:var(--text-light);font-style:italic;">No web modules (mobile only)</span>') + '</div></div>' +
      '<ul class="capability-list">' +
      capRow(perms.canEdit, 'Can Edit Data') +
      capRow(perms.canManageUsers, 'Can Manage Users') +
      capRow(perms.canManageMaster, 'Can Manage Master Data') +
      capRow(perms.canManageRoles, 'Can Manage Roles') +
      '</ul>';
  }).catch(function(err) {
    showUserError('loading user details', err);
  });
}

/**
 * Save User (add or edit).
 */
function saveUser() {
  var name = document.getElementById('userFormName').value.trim();
  var email = document.getElementById('userFormEmail').value.trim();
  var loginId = document.getElementById('userFormLoginId').value.trim();
  var role = document.getElementById('userFormRole').value;

  if (!name) { alert('Please enter the full name.'); return; }
  if (!email) { alert('Please enter the email address.'); return; }
  if (!loginId) { alert('Please enter a User ID / Login.'); return; }
  if (!role) { alert('Please select a role.'); return; }

  var password = '';
  if (userFormMode === 'add') {
    password = document.getElementById('userFormPassword').value;
    if (!password) { alert('Please set a password.'); return; }
  }

  // Map role key to role_id
  // 2026-06-05: Mobiliser=8 and Sangini=9 added by sql/059_mobiliser_sangini_roles.sql.
  var roleIdMap = { 'super_admin': 1, 'admin': 2, 'pi': 3, 'flp': 4, 'power_user': 5, 'state_lead': 6, 'district_lead': 7, 'mobiliser': 8, 'sangini': 9 };
  var roleId = roleIdMap[role];
  if (!roleId) { alert('Invalid role selected.'); return; }

  // Get scope based on role
  var scope = 'National (All Centres)';
  if (role === 'state_lead') {
    var stateVal = document.getElementById('userFormState').value;
    if (!stateVal) { alert('Please select a state for State Lead role.'); return; }
    // Get the display name from the select
    var stateSel = document.getElementById('userFormState');
    scope = stateSel.options[stateSel.selectedIndex].textContent;
  } else if (role === 'district_lead' || role === 'pi') {
    var distVal = document.getElementById('userFormDistrict').value;
    var centreVal = document.getElementById('userFormCentre').value;
    if (!distVal) { alert('Please select a district for this role.'); return; }
    if (!centreVal) { alert('Please select a centre for this role.'); return; }
    var centreSel = document.getElementById('userFormCentre');
    var distSel = document.getElementById('userFormDistrict');
    var centreName = centreSel.options[centreSel.selectedIndex].textContent;
    var distName = distSel.options[distSel.selectedIndex].textContent;
    scope = centreName + ', ' + distName;
  } else if (role === 'mobiliser' || role === 'sangini') {
    // 2026-06-05: Mobiliser (MGJ) / Sangini (AK) require all three.
    // We persist the human-readable label as geo_scope AND embed the
    // codes so the login scope-resolver can pick them up without a
    // second roundtrip. Format: "<Centre>, <District> [<Sx|Dx|Cx>]"
    // where the bracketed segment carries the canonical codes.
    var stVal = document.getElementById('userFormState').value;
    var dsVal = document.getElementById('userFormDistrict').value;
    var ctVal = document.getElementById('userFormCentre').value;
    if (!stVal) { alert('Please select a State for this role.'); return; }
    if (!dsVal) { alert('Please select a District for this role.'); return; }
    if (!ctVal) { alert('Please select a Centre for this role.'); return; }
    var _stS = document.getElementById('userFormState');
    var _dsS = document.getElementById('userFormDistrict');
    var _ctS = document.getElementById('userFormCentre');
    var _stN = _stS.options[_stS.selectedIndex].textContent;
    var _dsN = _dsS.options[_dsS.selectedIndex].textContent;
    var _ctN = _ctS.options[_ctS.selectedIndex].textContent;
    scope = _ctN + ', ' + _dsN + ' [' + stVal + '|' + dsVal + '|' + ctVal + ']';
  }

  var status = document.getElementById('userFormStatus').value;
  var phone = document.getElementById('userFormPhone').value.trim();

  // Get selected programs
  var selectedPrograms = [];
  document.querySelectorAll('input[name="userProgram"]:checked').forEach(function(cb) {
    selectedPrograms.push(cb.value);
  });
  if (selectedPrograms.length === 0) { alert('Please select at least one program.'); return; }

  // Disable save button to prevent double-click
  var saveBtn = document.querySelector('#page-addUser .btn-primary');
  if (saveBtn) saveBtn.disabled = true;

  if (userFormMode === 'edit' && editingUserId) {
    var updateData = { name: name, email: email, role_id: roleId, geo_scope: scope, status: status, phone: phone, username: loginId };
    apiUpdateUser(editingUserId, updateData)
      .then(function() {
        // Assign programs
        return apiAssignPrograms(editingUserId, selectedPrograms);
      })
      .then(function() {
        alert('User "' + name + '" updated successfully!');
        navigateTo('userManagement');
      })
      .catch(function(err) {
        showUserError('updating user', err);
      })
      .finally(function() { if (saveBtn) saveBtn.disabled = false; });
  } else {
    // Create new user via API
    var createData = { name: name, email: email, password: password, role_id: roleId, geo_scope: scope, status: status, username: loginId, phone: phone };
    var _userCreated = false; // flip to true once apiCreateUser resolves so we can distinguish errors
    // Resolve the role label from the form's <select> so the credentials
    // modal can show "Project Incharge" instead of the API key "pi".
    var _roleSel = document.getElementById('userFormRole');
    var _roleLabel = (_roleSel && _roleSel.selectedIndex >= 0)
      ? _roleSel.options[_roleSel.selectedIndex].textContent.trim()
      : role;
    apiCreateUser(createData)
      .then(function(resp) {
        _userCreated = true;
        // Assign programs to newly created user
        var newUserId = resp && resp.id ? resp.id : null;
        if (newUserId && typeof apiAssignPrograms === 'function') {
          return apiAssignPrograms(newUserId, selectedPrograms);
        }
      })
      .then(function() {
        // Show credentials modal instead of an alert+navigate. The admin
        // gets one chance to copy / download these before the password
        // is unrecoverable (backend stores bcrypt hash). The modal's
        // Close button is what triggers navigateTo('userManagement').
        _showUserCredentialsModal({
          name:     name,
          username: loginId,
          email:    email,
          password: password,
          role:     _roleLabel,
          scope:    scope
        });
      })
      .catch(function(err) {
        var detail = (err && err.detail) ? (typeof err.detail === 'string' ? err.detail : JSON.stringify(err.detail))
                   : (err && err.message) ? err.message
                   : 'Unknown error';
        if (_userCreated) {
          // User row was created — the failure is in the post-create step (program assignment).
          // Make this very clear so the user doesn't retry the Save and hit "username already exists".
          alert('User "' + name + '" was created, BUT we could not assign the selected programs.\n\n' +
                'Do NOT retry Save (that will fail — the user already exists). Open the user from the list and re-assign programs.\n\n' +
                'Technical detail: ' + detail);
          navigateTo('userManagement');
        } else {
          alert('Error creating user: ' + detail);
        }
      })
      .finally(function() { if (saveBtn) saveBtn.disabled = false; });
  }
}

// ---------------------------------------------------------------------------
// User Credentials modal — appears after a successful POST /users so the
// admin can copy or download the freshly minted credentials before the
// password disappears from memory (the backend only stores a bcrypt hash).
// Driven from `saveUser()`; not exposed via any other entry point.
// ---------------------------------------------------------------------------

// Snapshot of the most recently-created user's credentials. Held in module
// scope so the Copy / Download PDF buttons can read fields without
// re-querying the DOM (and so we don't accidentally copy stale values from
// a prior creation if the user reopens the modal somehow).
var _lastCreatedCredentials = null;

function _showUserCredentialsModal(data) {
  _lastCreatedCredentials = data || {};
  var setText = function(id, val) {
    var el = document.getElementById(id);
    if (el) el.textContent = val || '—';
  };
  setText('credName',     data.name);
  setText('credUsername', data.username);
  setText('credEmail',    data.email);
  setText('credPassword', data.password);
  setText('credRole',     data.role);
  setText('credScope',    data.scope);
  // Show the URL the user should hit to log in. Falls back to the current
  // origin so this works on stage, live, and local previews without an
  // env-specific config knob.
  var loginUrl = (window.location && window.location.origin) ? window.location.origin + '/' : '';
  setText('credLoginUrl', loginUrl);

  var modal = document.getElementById('userCredentialsModal');
  if (modal) modal.style.display = 'flex';
}

function closeUserCredentialsModal() {
  var modal = document.getElementById('userCredentialsModal');
  if (modal) modal.style.display = 'none';
  _lastCreatedCredentials = null;
  // Now that the admin has dismissed the modal, take them to the user
  // list (the navigateTo call we deferred from saveUser's success path).
  navigateTo('userManagement');
}

/**
 * Build a plaintext block of the credentials for clipboard / file output.
 * Single source of truth so Copy and Download PDF stay in sync.
 */
function _formatUserCredentialsText() {
  var d = _lastCreatedCredentials || {};
  var loginUrl = (window.location && window.location.origin) ? window.location.origin + '/' : '';
  var lines = [
    'Azad Foundation MIS — New User Credentials',
    '------------------------------------------',
    'Name:      ' + (d.name     || '—'),
    'Username:  ' + (d.username || '—'),
    'Email:     ' + (d.email    || '—'),
    'Password:  ' + (d.password || '—'),
    'Role:      ' + (d.role     || '—'),
    'Scope:     ' + (d.scope    || '—'),
    'Login URL: ' + loginUrl,
    '',
    'IMPORTANT: Please change your password after first login.',
    'Generated: ' + new Date().toLocaleString('en-IN', { timeZone: 'Asia/Kolkata' })
  ];
  return lines.join('\n');
}

function copyUserCredentials() {
  var text = _formatUserCredentialsText();
  var btn = document.getElementById('credCopyBtn');
  var restore = function() {
    if (!btn) return;
    setTimeout(function() {
      btn.innerHTML = '<i class="fas fa-copy"></i> Copy';
    }, 1500);
  };
  // Prefer the modern async clipboard API; fall back to the legacy
  // execCommand path for older browsers / non-secure contexts.
  if (navigator.clipboard && navigator.clipboard.writeText) {
    navigator.clipboard.writeText(text).then(function() {
      if (btn) btn.innerHTML = '<i class="fas fa-check"></i> Copied!';
      restore();
    }).catch(function() {
      _legacyCopyToClipboard(text, btn, restore);
    });
  } else {
    _legacyCopyToClipboard(text, btn, restore);
  }
}

function _legacyCopyToClipboard(text, btn, restore) {
  var ta = document.createElement('textarea');
  ta.value = text;
  ta.style.position = 'fixed';
  ta.style.opacity = '0';
  document.body.appendChild(ta);
  ta.select();
  try {
    var ok = document.execCommand('copy');
    if (btn) btn.innerHTML = ok ? '<i class="fas fa-check"></i> Copied!' : '<i class="fas fa-times"></i> Failed';
  } catch (e) {
    if (btn) btn.innerHTML = '<i class="fas fa-times"></i> Failed';
  }
  document.body.removeChild(ta);
  restore();
}

/**
 * Generate a one-page PDF of the credentials. Lazy-loads html2pdf.js from
 * the same CDN that the FLP / Survey PDF exports use, so we don't add a
 * new always-on dependency to the bundle. If the network blocks the CDN,
 * falls back to a printable HTML window the user can save as PDF via
 * their browser's print dialog.
 */
function downloadUserCredentialsPdf() {
  var d = _lastCreatedCredentials || {};
  var loginUrl = (window.location && window.location.origin) ? window.location.origin + '/' : '';
  var generatedAt = new Date().toLocaleString('en-IN', { timeZone: 'Asia/Kolkata' });
  var safeName = (d.name || 'user').replace(/[^a-z0-9_-]+/gi, '_').slice(0, 40) || 'user';
  var fileName = 'azad-credentials-' + safeName + '.pdf';

  // Build the printable card off-screen. Inline styles only — html2pdf
  // captures via html2canvas which doesn't pick up the page's external
  // CSS reliably.
  var html = '' +
    '<div id="_credPdfRoot" style="width:560px;padding:30px;font-family:Arial,Helvetica,sans-serif;color:#222;background:#fff;">' +
      '<div style="border-bottom:3px solid #732269;padding-bottom:12px;margin-bottom:18px;">' +
        '<h2 style="margin:0;color:#732269;">Azad Foundation MIS</h2>' +
        '<p style="margin:4px 0 0 0;color:#666;font-size:13px;">New User Credentials</p>' +
      '</div>' +
      '<table style="width:100%;border-collapse:collapse;font-size:13px;">' +
        _credPdfRow('Name',      d.name) +
        _credPdfRow('Username',  d.username, true) +
        _credPdfRow('Email',     d.email,    true) +
        _credPdfRow('Password',  d.password, true, '#732269') +
        _credPdfRow('Role',      d.role) +
        _credPdfRow('Scope',     d.scope) +
        _credPdfRow('Login URL', loginUrl,   true) +
      '</table>' +
      '<div style="margin-top:18px;padding:10px 12px;background:#fff8e6;border:1px solid #f0c674;border-radius:6px;font-size:12px;color:#7a5b00;">' +
        '<b>Important:</b> Save this PDF in a secure location and share it with the user via a secure channel. ' +
        'The user should change their password immediately after first login.' +
      '</div>' +
      '<p style="margin-top:18px;color:#888;font-size:11px;text-align:right;">Generated: ' + escHtml(generatedAt) + ' &middot; Azad Foundation MIS</p>' +
    '</div>';

  // Mount off-screen so html2pdf can render it without a flash.
  var holder = document.createElement('div');
  holder.style.position = 'fixed';
  holder.style.left = '-9999px';
  holder.style.top = '0';
  holder.innerHTML = html;
  document.body.appendChild(holder);

  var node = holder.querySelector('#_credPdfRoot');
  var cleanup = function() {
    if (holder && holder.parentNode) holder.parentNode.removeChild(holder);
  };

  var run = function() {
    if (typeof html2pdf !== 'function') {
      cleanup();
      alert('PDF library failed to load. Falling back to a printable window — use your browser\'s "Save as PDF" from the print dialog.');
      _credPdfPrintFallback(html, fileName);
      return;
    }
    html2pdf().set({
      margin: 10,
      filename: fileName,
      image: { type: 'jpeg', quality: 0.95 },
      html2canvas: { scale: 2, useCORS: true },
      jsPDF: { unit: 'mm', format: 'a4', orientation: 'portrait' }
    }).from(node).save().then(cleanup).catch(function(e) {
      cleanup();
      alert('PDF generation failed: ' + (e && e.message ? e.message : e));
    });
  };

  if (typeof html2pdf === 'function') {
    run();
  } else {
    // Lazy-load html2pdf.js — same CDN/version as the other exports.
    var s = document.createElement('script');
    s.src = 'https://cdnjs.cloudflare.com/ajax/libs/html2pdf.js/0.10.1/html2pdf.bundle.min.js';
    s.onload = run;
    s.onerror = function() {
      cleanup();
      alert('Could not load the PDF library (network blocked the CDN). Falling back to a printable window.');
      _credPdfPrintFallback(html, fileName);
    };
    document.head.appendChild(s);
  }
}

function _credPdfRow(label, value, mono, color) {
  var v = value || '—';
  var style = 'padding:8px 10px;border-bottom:1px solid #eee;';
  if (mono) style += 'font-family:monospace;';
  if (color) style += 'color:' + color + ';font-weight:600;';
  return '<tr>' +
    '<td style="padding:8px 10px;border-bottom:1px solid #eee;font-weight:600;color:#666;width:35%;">' + escHtml(label) + '</td>' +
    '<td style="' + style + '">' + escHtml(v) + '</td>' +
  '</tr>';
}

function _credPdfPrintFallback(innerHtml, fileName) {
  var w = window.open('', '_blank', 'width=720,height=900');
  if (!w) {
    alert('Pop-up blocked. Please allow pop-ups for this site to download the credentials.');
    return;
  }
  w.document.open();
  w.document.write(
    '<!doctype html><html><head><meta charset="utf-8"><title>' + escHtml(fileName) + '</title>' +
    '<style>@media print{button{display:none;}}</style></head><body>' +
    '<div style="text-align:right;padding:8px;"><button onclick="window.print()" style="padding:6px 14px;border-radius:4px;border:1px solid #732269;background:#732269;color:#fff;cursor:pointer;">Print / Save as PDF</button></div>' +
    innerHtml +
    '</body></html>'
  );
  w.document.close();
}

/**
 * Switch from View User page to Edit User form.
 */
function editUserFromView() {
  openEditUser(viewingUserId);
}

/**
 * Show/hide the Centre field based on selected role.
 * Also loads centre options from the API when shown.
 */
function toggleUserCentreField() {
  var role = document.getElementById('userFormRole').value;
  var stateGroup = document.getElementById('userFormStateGroup');
  var districtGroup = document.getElementById('userFormDistrictGroup');
  var centreGroup = document.getElementById('userFormCentreGroup');

  stateGroup.style.display = 'none';
  districtGroup.style.display = 'none';
  centreGroup.style.display = 'none';

  // 2026-06-05: Program-lock for the two new field roles. Auto-tick the
  // role's programme checkbox and disable all others so the admin can't
  // accidentally widen access. Clears any previous auto-lock when role
  // is switched back to a non-locked role.
  _userFormApplyRoleProgramLock(role);

  if (role === 'state_lead') {
    stateGroup.style.display = '';
    var stateSel = document.getElementById('userFormState');
    if (stateSel && stateSel.options.length <= 1) {
      loadGeoStateDropdown('userFormState', 'Select State');
    }
    document.getElementById('userFormDistrict').innerHTML = '<option value="">Select District</option>';
    document.getElementById('userFormCentre').innerHTML = '<option value="">Select Centre</option>';
  } else if (role === 'district_lead' || role === 'pi') {
    stateGroup.style.display = '';
    districtGroup.style.display = '';
    centreGroup.style.display = '';
    var stateSel = document.getElementById('userFormState');
    if (stateSel && stateSel.options.length <= 1) {
      loadGeoStateDropdown('userFormState', 'Select State');
    }
  } else if (role === 'mobiliser' || role === 'sangini') {
    // 2026-06-05: Mobiliser (MGJ) + Sangini (AK) need full State +
    // District + Centre assignment. Geo cascade pulls from the
    // programme-specific master tables so the codes match what the
    // Assessment endpoints filter on at query time (mgj_master for
    // Mobiliser, ak_master for Sangini). Switching role wipes any
    // previously-loaded state options so the cascade starts fresh.
    stateGroup.style.display = '';
    districtGroup.style.display = '';
    centreGroup.style.display = '';
    var ss = document.getElementById('userFormState');
    var ds = document.getElementById('userFormDistrict');
    var cs = document.getElementById('userFormCentre');
    if (ss) ss.innerHTML = '<option value="">Select State</option>';
    if (ds) ds.innerHTML = '<option value="">Select District</option>';
    if (cs) cs.innerHTML = '<option value="">Select Centre</option>';
    _userFormLoadProgramStates(role);
  } else {
    document.getElementById('userFormState').value = '';
    document.getElementById('userFormDistrict').innerHTML = '<option value="">Select District</option>';
    document.getElementById('userFormCentre').innerHTML = '<option value="">Select Centre</option>';
  }
}

// 2026-06-05 (v2): Program auto-tick — when role is Mobiliser → MGJ,
// Sangini → AK. We only ensure the role's primary programme is ticked;
// other Program Access checkboxes are left enabled + their previous
// checked state untouched so the admin can freely add additional
// programmes on top if needed. (User said 2026-06-05: "Don't disable
// other program access when we pick mobiliser and sangini.")
//
// Sidebar lockdown logic in applyRolePermissions() still shows ONLY
// the role's own programme Assessment submenu at runtime, so extra
// programmes ticked here become spare access at most — they don't
// surface in the nav.
function _userFormApplyRoleProgramLock(role) {
  var autoTick = (role === 'mobiliser') ? 'MGJ'
              : (role === 'sangini')   ? 'AK'
              : null;
  var checks = document.querySelectorAll('input[name="userProgram"]');
  checks.forEach(function(cb) {
    // Always leave every checkbox enabled — no disable behaviour.
    cb.disabled = false;
    // Force-tick only the role's primary programme; never untick
    // anything the admin had already chosen.
    if (autoTick && cb.value === autoTick) cb.checked = true;
  });
}

// 2026-06-05: For Mobiliser/Sangini the cascade pulls from the
// programme's own geo tables (mgj_master / ak-master) so the codes
// match what the Assessment endpoints actually filter against.
//
// 2026-06-05 (v2): Removed the previous FLP fallback inside .catch
// — if the programme endpoint fails we leave the State dropdown
// EMPTY and log the error to the console rather than silently
// substituting FLP data. This guarantees a Mobiliser/Sangini admin
// can never accidentally end up with FLP geos in the form.
function _userFormLoadProgramStates(role) {
  var sel = document.getElementById('userFormState');
  if (!sel) return;
  sel.innerHTML = '<option value="">Select State</option>';
  var url = (role === 'mobiliser')
    ? '/mgj-master/dropdown/states'
    : '/ak-master/dropdown/states';
  apiGet(url).then(function(rows) {
    (rows || []).forEach(function(r) {
      var o = document.createElement('option');
      o.value = r.state_code;
      o.textContent = r.state_name;
      sel.appendChild(o);
    });
  }).catch(function(err) {
    console.error('[' + role + '] state cascade failed — NO fallback applied. URL was:', url, err);
    sel.innerHTML = '<option value="">(unable to load states — see console)</option>';
  });
}

function onUserFormStateChange() {
  var stateCode = document.getElementById('userFormState').value;
  var distSel = document.getElementById('userFormDistrict');
  var centreSel = document.getElementById('userFormCentre');
  if (distSel) distSel.innerHTML = '<option value="">Select District</option>';
  if (centreSel) centreSel.innerHTML = '<option value="">Select Centre</option>';
  if (!stateCode) return;

  // 2026-06-05: Program-aware cascade for Mobiliser/Sangini.
  // Uses the lightweight /dropdown/districts endpoint which filters
  // `deleted_at IS NULL AND status = 'Active'` server-side, so the
  // dropdown only shows currently-running districts for that
  // programme. (The full /districts endpoint includes Inactive rows
  // because it's used by Master CRUD screens.)
  var role = (document.getElementById('userFormRole') || {}).value;
  if (role === 'mobiliser' || role === 'sangini') {
    var base = (role === 'mobiliser') ? '/mgj-master' : '/ak-master';
    apiGet(base + '/dropdown/districts?state_code=' + encodeURIComponent(stateCode)).then(function(rows) {
      (rows || []).forEach(function(d) {
        var opt = document.createElement('option');
        opt.value = d.district_code;
        opt.textContent = d.district_name;
        distSel.appendChild(opt);
      });
    }).catch(function(err) {
      console.error('[' + role + '] district cascade failed — NO fallback. URL was:',
                    base + '/dropdown/districts?state_code=' + stateCode, err);
    });
    return;
  }

  if (typeof apiGeoDropdownDistricts !== 'function') return;
  apiGeoDropdownDistricts(stateCode).then(function(result) {
    var districts = result.data || result || [];
    districts.forEach(function(d) {
      var opt = document.createElement('option');
      opt.value = d.district_code;
      opt.textContent = d.district_name;
      distSel.appendChild(opt);
    });
  }).catch(function() {});
}

function onUserFormDistrictChange() {
  var distCode = document.getElementById('userFormDistrict').value;
  var centreSel = document.getElementById('userFormCentre');
  if (centreSel) centreSel.innerHTML = '<option value="">Select Centre</option>';
  if (!distCode) return;

  // 2026-06-05: Program-aware cascade for Mobiliser/Sangini.
  var role = (document.getElementById('userFormRole') || {}).value;
  if (role === 'mobiliser' || role === 'sangini') {
    var base = (role === 'mobiliser') ? '/mgj-master' : '/ak-master';
    apiGet(base + '/dropdown/centres?district_code=' + encodeURIComponent(distCode)).then(function(rows) {
      (rows || []).forEach(function(c) {
        var opt = document.createElement('option');
        opt.value = c.centre_code;
        opt.textContent = c.centre_name;
        centreSel.appendChild(opt);
      });
    }).catch(function() {});
    return;
  }

  if (typeof apiGeoDropdownCentres !== 'function') return;
  apiGeoDropdownCentres(distCode).then(function(result) {
    var centres = result.data || result || [];
    centres.forEach(function(c) {
      var opt = document.createElement('option');
      opt.value = c.centre_code;
      opt.textContent = c.centre_name;
      centreSel.appendChild(opt);
    });
  }).catch(function() {});
}

// Load states from geo API into a select dropdown
function loadGeoStateDropdown(selectId, placeholder) {
  var sel = document.getElementById(selectId);
  if (!sel) return;
  sel.innerHTML = '<option value="">' + (placeholder || 'Select State') + '</option>';
  if (typeof apiGeoDropdownStates === 'function') {
    apiGeoDropdownStates().then(function(result) {
      var states = result.data || result || [];
      states.forEach(function(s) {
        var opt = document.createElement('option');
        opt.value = s.state_code || s.state_name;
        opt.textContent = s.state_name;
        sel.appendChild(opt);
      });
    }).catch(function() {
      // Fallback: hardcoded states
      ['Delhi', 'Rajasthan', 'West Bengal', 'Tamil Nadu'].forEach(function(name) {
        var opt = document.createElement('option');
        opt.value = name;
        opt.textContent = name;
        sel.appendChild(opt);
      });
    });
  }
}

/**
 * Generate a random password for the user form.
 */
function generateUserPassword() {
  var chars = 'ABCDEFGHJKLMNPQRSTUVWXYZabcdefghijkmnopqrstuvwxyz23456789!@#$%';
  var pwd = '';
  for (var i = 0; i < 10; i++) pwd += chars.charAt(Math.floor(Math.random() * chars.length));
  document.getElementById('userFormPassword').value = pwd;
}

/**
 * Reset a user's password with confirmation.
 */
function resetUserPassword(userId) {
  if (confirm('Reset password for this user to the default (zaq@123)?\n\nThe user will need to change it on next login.')) {
    apiResetPassword(userId)
      .then(function() {
        alert('Password has been reset to default successfully!');
      })
      .catch(function(err) {
        showUserError('resetting password', err);
      });
  }
}

function deleteUser(userId, userName) {
  if (!confirm('Are you sure you want to delete user "' + userName + '"?\n\nThis action cannot be undone.')) return;
  apiDeleteUser(userId)
    .then(function() {
      alert('User "' + userName + '" deleted successfully.');
      loadUserManagementData(userCurrentPage);
    })
    .catch(function(err) {
      showUserError('deleting user', err);
    });
}

// ---- User Management filter cascades ----
function onUserFilterStateChange() {
  var stateCode = (document.getElementById('userFilterState') || {}).value;
  var distSel = document.getElementById('userFilterDistrict');
  var centreSel = document.getElementById('userFilterCentre');
  if (distSel) distSel.innerHTML = '<option value="">All Districts</option>';
  if (centreSel) centreSel.innerHTML = '<option value="">All Centres</option>';
  if (!stateCode || typeof apiGeoDropdownDistricts !== 'function') return;
  apiGeoDropdownDistricts(stateCode).then(function(result) {
    var districts = result.data || result || [];
    districts.forEach(function(d) {
      var opt = document.createElement('option');
      opt.value = d.district_code;
      opt.textContent = d.district_name;
      distSel.appendChild(opt);
    });
  }).catch(function() {});
}

function onUserFilterDistrictChange() {
  var distCode = (document.getElementById('userFilterDistrict') || {}).value;
  var centreSel = document.getElementById('userFilterCentre');
  if (centreSel) centreSel.innerHTML = '<option value="">All Centres</option>';
  if (!distCode || typeof apiGeoDropdownCentres !== 'function') return;
  apiGeoDropdownCentres(distCode).then(function(result) {
    var centres = result.data || result || [];
    centres.forEach(function(c) {
      var opt = document.createElement('option');
      opt.value = c.centre_code;
      opt.textContent = c.centre_name;
      centreSel.appendChild(opt);
    });
  }).catch(function() {});
}


// =============================================================================
// 6. DASHBOARD CHARTS (with API data support)
// =============================================================================

/**
 * Initialize dashboard charts with hardcoded fallback data.
 */
function initDashboard() {
  // Destroy existing charts to prevent duplicates
  Object.keys(chartInstances).forEach(function(k) {
    if (chartInstances[k]) { try { chartInstances[k].destroy(); } catch(e) {} }
    delete chartInstances[k];
  });

  // FLP Pie Chart (with %)
  var ctx1 = document.getElementById('flpPieChart');
  if (ctx1) {
    chartInstances.flpPie = new Chart(ctx1.getContext('2d'), {
      type: 'pie',
      data: {
        labels: ['Delhi', 'Kolkata', 'Jaipur', 'Chennai'],
        datasets: [{
          data: [82, 65, 45, 32],
          backgroundColor: CHART_COLORS
        }]
      },
      options: { responsive: true, plugins: { legend: { position: 'bottom', labels: { font: { size: 12 } } }, datalabels: PIE_DATALABEL_OPTS } }
    });
  }

  // FLP Status Pie Chart (ordered by process flow, with %)
  var ctx2 = document.getElementById('flpStatusPieChart');
  if (ctx2) {
    chartInstances.flpStatus = new Chart(ctx2.getContext('2d'), {
      type: 'pie',
      data: {
        labels: FLP_STATUS_ORDER,
        datasets: [{
          data: [10, 9, 15, 5, 6],
          backgroundColor: FLP_STATUS_COLORS
        }]
      },
      options: {
        responsive: true,
        plugins: { legend: { position: 'bottom', labels: { font: { size: 11 } } }, datalabels: PIE_DATALABEL_OPTS }
      }
    });
  }

  // FLP Age Distribution — Stacked Bar
  var ctx3 = document.getElementById('ageDistributionChart');
  if (ctx3) {
    chartInstances.ageDist = new Chart(ctx3.getContext('2d'), {
      type: 'bar',
      data: {
        labels: ['Delhi', 'Kolkata', 'Jaipur', 'Chennai'],
        datasets: [
          { label: 'Less than 20', data: [2, 0, 0, 0], backgroundColor: '#732269' },
          { label: '20 to 25', data: [60, 50, 30, 22], backgroundColor: '#9b3d8e' },
          { label: 'Above 25', data: [20, 15, 15, 10], backgroundColor: '#c06bb3' }
        ]
      },
      options: {
        responsive: true,
        plugins: { legend: { position: 'bottom', labels: { font: { size: 11 } } }, datalabels: { display: false } },
        scales: { x: { stacked: true }, y: { stacked: true, beginAtZero: true } }
      }
    });
  }

  // Also init survey analytics with fallback data
  initSurveyAnalyticsCharts(null);
}

/**
 * Initialize dashboard charts with data from the API.
 */
function initDashboardWithApiData(charts) {
  // Destroy existing charts
  Object.keys(chartInstances).forEach(function(k) {
    if (chartInstances[k]) { try { chartInstances[k].destroy(); } catch(e) {} }
    delete chartInstances[k];
  });

  // FLP Pie Chart from flp_by_state.
  // CRITICAL: an empty array means the API answered honestly that there
  // are zero rows in the database — render an empty chart, NOT the old
  // demo fallback. The previous code ([82,65,45,32]) made cleared
  // databases look like they still had data.
  var flpLabels = [];
  var flpData = [];
  if (Array.isArray(charts.flp_by_state)) {
    charts.flp_by_state.forEach(function(item) {
      flpLabels.push(item.state);
      flpData.push(item.count);
    });
  }

  var ctx1 = document.getElementById('flpPieChart');
  if (ctx1) {
    chartInstances.flpPie = new Chart(ctx1.getContext('2d'), {
      type: 'pie',
      data: {
        labels: flpLabels,
        datasets: [{ data: flpData, backgroundColor: CHART_COLORS.slice(0, flpLabels.length) }]
      },
      options: { responsive: true, plugins: { legend: { position: 'bottom', labels: { font: { size: 12 } } }, datalabels: PIE_DATALABEL_OPTS } }
    });
  }

  // FLP Status Pie Chart (ordered by process flow, with %)
  var ctx2 = document.getElementById('flpStatusPieChart');
  if (ctx2) {
    // Build ordered data from API response. Empty array = legitimately
    // zero across every status; do NOT fall back to demo numbers.
    var orderedData = FLP_STATUS_ORDER.map(function(status) { return 0; });
    if (Array.isArray(charts.flp_status_breakdown)) {
      charts.flp_status_breakdown.forEach(function(item) {
        var idx = FLP_STATUS_ORDER.indexOf(item.flp_status);
        if (idx >= 0) orderedData[idx] = item.count;
      });
    }
    chartInstances.flpStatus = new Chart(ctx2.getContext('2d'), {
      type: 'pie',
      data: {
        labels: FLP_STATUS_ORDER,
        datasets: [{ data: orderedData, backgroundColor: FLP_STATUS_COLORS }]
      },
      options: {
        responsive: true,
        plugins: { legend: { position: 'bottom', labels: { font: { size: 11 } } }, datalabels: PIE_DATALABEL_OPTS }
      }
    });
  }

  // FLP Age Distribution — Stacked Bar from age_distribution API data
  var ctx3 = document.getElementById('ageDistributionChart');
  if (ctx3) {
    var ageGroups = ['Less than 20', '20 to 25', 'Above 25'];
    var ageColors = ['#732269', '#9b3d8e', '#c06bb3'];
    var ageStates = [];
    var ageDatasets = [];

    if (Array.isArray(charts.age_distribution) && charts.age_distribution.length > 0) {
      // Collect unique states
      var stateSet = {};
      charts.age_distribution.forEach(function(item) { stateSet[item.state] = true; });
      ageStates = Object.keys(stateSet);

      ageDatasets = ageGroups.map(function(group, gi) {
        return {
          label: group,
          data: ageStates.map(function(st) {
            var match = charts.age_distribution.find(function(d) { return d.age_group === group && d.state === st; });
            return match ? match.count : 0;
          }),
          backgroundColor: ageColors[gi]
        };
      });
    } else {
      // No data — render empty axes instead of fake demo bars. We keep
      // the dataset shape so the legend still shows the age-group labels
      // (helps the user understand what the chart will show once data
      // exists), but every value is 0.
      ageStates = [];
      ageDatasets = ageGroups.map(function(group, gi) {
        return { label: group, data: [], backgroundColor: ageColors[gi] };
      });
    }

    chartInstances.ageDist = new Chart(ctx3.getContext('2d'), {
      type: 'bar',
      data: { labels: ageStates, datasets: ageDatasets },
      options: {
        responsive: true,
        plugins: { legend: { position: 'bottom', labels: { font: { size: 11 } } }, datalabels: { display: false } },
        scales: { x: { stacked: true }, y: { stacked: true, beginAtZero: true } }
      }
    });
  }

  // Survey analytics charts (inline — created together with main charts)
  _createSurveyCharts(charts);

  // 2026-06-09 — Socio-economic + Trainings panels.
  _createSocioCharts(charts);
  _createTrainingByStateChart(charts);
  // 2026-06-09 v3 — Community Action + Statewise Achievements.
  _createCommunityActionChart(charts);
  _createAchievementsByStateChart(charts);
  // 2026-06-09 v5 — GBV Support by FLP (under Achievements).
  _createGbvByStateTable(charts);
  // 2026-06-09 v6 — WWW Registration + Enrollment by State.
  _createWwwEnrolledTables(charts);
}

/** 2026-06-09 v6 — Renders the two sister tables added below GBV:
 *  "Numbers Registered into WWW by FLP" and "Numbers Enrolled
 *  (Statewise)".  Each consumes the same www_enrollment_by_state
 *  payload but pulls a different column, so the user can read the
 *  funnel left → right without flicking between cards. */
function _createWwwEnrolledTables(charts) {
  var rows = (charts && Array.isArray(charts.www_enrollment_by_state))
    ? charts.www_enrollment_by_state : [];

  function _renderOne(bodyId, footId, valueKey, colspan) {
    var tbody = document.getElementById(bodyId);
    var tfoot = document.getElementById(footId);
    if (!tbody) return;
    if (!rows.length) {
      tbody.innerHTML = '<tr><td colspan="' + colspan + '" style="text-align:center;color:#999;padding:20px;">No data</td></tr>';
      if (tfoot) tfoot.innerHTML = '<tr><td colspan="' + colspan + '"></td></tr>';
      return;
    }
    var byState = {}, stateOrder = [];
    rows.forEach(function(r) {
      var st = r.state || 'Unassigned';
      if (!byState[st]) { byState[st] = []; stateOrder.push(st); }
      byState[st].push(r);
    });
    var html = '';
    var grand = 0;
    var SUM_BG = '#fce4ec';
    stateOrder.forEach(function(st) {
      var children = byState[st];
      var stateTot = 0;
      children.forEach(function(r) {
        var v = Number(r[valueKey] || 0);
        stateTot += v;
        html += '<tr>' +
          '<td>' + escHtml(r.centre || '\u2014') + '</td>' +
          '<td style="text-align:right;">' + formatNumber(v) + '</td>' +
          '</tr>';
      });
      html += '<tr style="background:' + SUM_BG + ';font-weight:700;">' +
        '<td>' + escHtml(String(st).toUpperCase()) + '</td>' +
        '<td style="text-align:right;">' + formatNumber(stateTot) + '</td>' +
        '</tr>';
      grand += stateTot;
    });
    tbody.innerHTML = html;
    if (tfoot) {
      tfoot.innerHTML = '<tr style="background:' + SUM_BG + ';font-weight:700;">' +
        '<td>Total</td>' +
        '<td style="text-align:right;color:#732269;">' + formatNumber(grand) + '</td>' +
        '</tr>';
    }
  }

  _renderOne('wwwRegByStateBody',    'wwwRegByStateFoot',    'www_registered', 2);
  _renderOne('enrolledByStateBody',  'enrolledByStateFoot',  'enrolled',       2);
}


/** 2026-06-09 v5 — GBV Support by FLP, rendered as a data table that
 *  mirrors the Statewise Achievements idiom: state rows with right-
 *  aligned numbers, a per-row Total, and a bolded grand-total tfoot row.
 *  Sits under the Achievements section per user spec ("GBV support by
 *  FLP can be part of achievement"). */
function _createGbvByStateTable(charts) {
  var tbody = document.getElementById('gbvByStateBody');
  var tfoot = document.getElementById('gbvByStateFoot');
  if (!tbody) return;

  var rows = (charts && Array.isArray(charts.gbv_by_state)) ? charts.gbv_by_state : [];
  if (!rows.length) {
    tbody.innerHTML = '<tr><td colspan="4" style="text-align:center;color:#999;padding:20px;">No data</td></tr>';
    if (tfoot) tfoot.innerHTML = '<tr><td colspan="4"></td></tr>';
    return;
  }
  function fmt(n) { return formatNumber(Number(n || 0)); }

  var byState = {}, stateOrder = [];
  rows.forEach(function(r) {
    var st = r.state || 'Unassigned';
    if (!byState[st]) { byState[st] = []; stateOrder.push(st); }
    byState[st].push(r);
  });

  var SUM_BG = '#fce4ec';
  var html = '';
  var gId = 0, gSup = 0;
  stateOrder.forEach(function(st) {
    var children = byState[st];
    var sId = 0, sSup = 0;
    children.forEach(function(r) {
      var id  = Number(r.cases_identified || 0);
      var sup = Number(r.cases_supported  || 0);
      sId += id; sSup += sup;
      html += '<tr>' +
        '<td>' + escHtml(r.centre || '\u2014') + '</td>' +
        '<td style="text-align:right;">' + fmt(id)  + '</td>' +
        '<td style="text-align:right;">' + fmt(sup) + '</td>' +
        '<td style="text-align:right;font-weight:600;">' + fmt(id + sup) + '</td>' +
        '</tr>';
    });
    html += '<tr style="background:' + SUM_BG + ';font-weight:700;">' +
      '<td>' + escHtml(String(st).toUpperCase()) + '</td>' +
      '<td style="text-align:right;">' + fmt(sId)  + '</td>' +
      '<td style="text-align:right;">' + fmt(sSup) + '</td>' +
      '<td style="text-align:right;">' + fmt(sId + sSup) + '</td>' +
      '</tr>';
    gId += sId; gSup += sSup;
  });
  tbody.innerHTML = html;
  if (tfoot) {
    tfoot.innerHTML = '<tr style="background:' + SUM_BG + ';font-weight:700;">' +
      '<td>Total</td>' +
      '<td style="text-align:right;">' + fmt(gId)  + '</td>' +
      '<td style="text-align:right;">' + fmt(gSup) + '</td>' +
      '<td style="text-align:right;color:#27ae60;">' + fmt(gId + gSup) + '</td>' +
      '</tr>';
  }
}


/** 2026-06-09 v3 — Community Action Projects.  Four canonical buckets
 *  (Public Health / Education / Infrastructure Maintenance /
 *  Infrastructure Creation) + an "Other" bucket for projects whose
 *  free-text "specify" field didn't keyword-match anything else.
 *  Vertical bar so the long category names stay readable. */
function _createCommunityActionChart(charts) {
  var ctx = document.getElementById('capCategoryChart');
  if (!ctx) return;
  if (chartInstances.capCategory) { try { chartInstances.capCategory.destroy(); } catch(e){} }

  // Canonical bucket order even if backend returns subset.
  var ORDER = ['Public Health','Education','Infrastructure Maintenance','Infrastructure Creation','Other'];
  var rows = (charts && Array.isArray(charts.community_action_categories)) ? charts.community_action_categories : [];
  var byKey = {};
  rows.forEach(function(r) { byKey[r.category] = Number(r.count || 0); });
  var labels = ORDER.slice();
  var data = ORDER.map(function(k) { return byKey[k] || 0; });
  var palette = ['#27ae60','#3498db','#f39c12','#732269','#7f8c8d'];

  chartInstances.capCategory = new Chart(ctx.getContext('2d'), {
    type: 'bar',
    data: { labels: labels, datasets: [{ label: 'Projects', data: data, backgroundColor: palette }] },
    options: {
      responsive: true,
      plugins: {
        legend: { display: false },
        datalabels: { color: '#333', anchor: 'end', align: 'end', font: { size: 11, weight: 'bold' } }
      },
      scales: {
        y: { beginAtZero: true, ticks: { precision: 0 }, title: { display: true, text: 'Project count' } },
        x: { ticks: { font: { size: 10 }, autoSkip: false, maxRotation: 30, minRotation: 0 } }
      }
    }
  });
}

/** 2026-06-09 v4 — Statewise Achievements as a DATA TABLE (was grouped bar
 *  chart; user feedback: "graph look not good").  Renders one row per
 *  state with right-aligned numeric columns plus a per-row Total, and a
 *  bolded grand-total row in the table footer.  We deliberately strip
 *  any old chart instance + clear the no-longer-used #achievementsTotals
 *  div so re-renders don't leave orphans behind. */
function _createAchievementsByStateChart(charts) {
  if (chartInstances.achState) { try { chartInstances.achState.destroy(); } catch(e){} delete chartInstances.achState; }
  var totDiv = document.getElementById('achievementsTotals');
  if (totDiv) totDiv.innerHTML = '';

  var tbody = document.getElementById('achievementsStateBody');
  var tfoot = document.getElementById('achievementsStateFoot');
  if (!tbody) return;

  var rows = (charts && Array.isArray(charts.achievements_by_state)) ? charts.achievements_by_state : [];
  if (!rows.length) {
    tbody.innerHTML = '<tr><td colspan="5" style="text-align:center;color:#999;padding:20px;">No data</td></tr>';
    if (tfoot) tfoot.innerHTML = '<tr><td colspan="5"></td></tr>';
    return;
  }
  function fmt(n) { return formatNumber(Number(n || 0)); }

  var byState = {}, stateOrder = [];
  rows.forEach(function(r) {
    var st = r.state || 'Unassigned';
    if (!byState[st]) { byState[st] = []; stateOrder.push(st); }
    byState[st].push(r);
  });

  var SUM_BG = '#fce4ec';
  var html = '';
  var gC = 0, gS = 0, gF = 0;
  stateOrder.forEach(function(st) {
    var children = byState[st];
    var sC = 0, sS = 0, sF = 0;
    children.forEach(function(r) {
      var c = Number(r.citizenship || 0);
      var s = Number(r.social_security || 0);
      var f = Number(r.financial_linkage || 0);
      sC += c; sS += s; sF += f;
      html += '<tr>' +
        '<td>' + escHtml(r.centre || '\u2014') + '</td>' +
        '<td style="text-align:right;">' + fmt(c) + '</td>' +
        '<td style="text-align:right;">' + fmt(s) + '</td>' +
        '<td style="text-align:right;">' + fmt(f) + '</td>' +
        '<td style="text-align:right;font-weight:600;">' + fmt(c + s + f) + '</td>' +
        '</tr>';
    });
    html += '<tr style="background:' + SUM_BG + ';font-weight:700;">' +
      '<td>' + escHtml(String(st).toUpperCase()) + '</td>' +
      '<td style="text-align:right;">' + fmt(sC) + '</td>' +
      '<td style="text-align:right;">' + fmt(sS) + '</td>' +
      '<td style="text-align:right;">' + fmt(sF) + '</td>' +
      '<td style="text-align:right;">' + fmt(sC + sS + sF) + '</td>' +
      '</tr>';
    gC += sC; gS += sS; gF += sF;
  });
  tbody.innerHTML = html;
  if (tfoot) {
    tfoot.innerHTML = '<tr style="background:' + SUM_BG + ';font-weight:700;">' +
      '<td>Total</td>' +
      '<td style="text-align:right;">' + fmt(gC) + '</td>' +
      '<td style="text-align:right;">' + fmt(gS) + '</td>' +
      '<td style="text-align:right;">' + fmt(gF) + '</td>' +
      '<td style="text-align:right;color:#732269;">' + fmt(gC + gS + gF) + '</td>' +
      '</tr>';
  }
}


/** 2026-06-09 — Socio-economic Profile: Caste / Religion / Education / Per-Capita.
 *  Donuts for Caste & Religion (categorical, low cardinality), vertical bars
 *  for Education and Per-Capita so the long labels stay readable. */
function _createSocioCharts(charts) {
  var palette = ['#732269','#9b3d8e','#c06bb3','#e74c3c','#f39c12','#27ae60','#3498db','#16a085','#8e44ad','#34495e'];
  function _arrToLabelsData(arr, labelKey) {
    var L = [], D = [];
    if (Array.isArray(arr)) arr.forEach(function(r) { L.push(r[labelKey] || 'Unspecified'); D.push(r.count || 0); });
    return { labels: L, data: D };
  }

  // Caste — donut
  var ctxC = document.getElementById('casteDistChart');
  if (ctxC) {
    if (chartInstances.casteDist) { try { chartInstances.casteDist.destroy(); } catch(e){} }
    var ld = _arrToLabelsData(charts && charts.caste_distribution, 'caste');
    chartInstances.casteDist = new Chart(ctxC.getContext('2d'), {
      type: 'doughnut',
      data: { labels: ld.labels, datasets: [{ data: ld.data, backgroundColor: palette.slice(0, ld.labels.length) }] },
      options: { responsive: true, plugins: { legend: { position: 'bottom', labels: { font: { size: 11 } } }, datalabels: PIE_DATALABEL_OPTS } }
    });
  }

  // Religion — donut
  var ctxR = document.getElementById('religionDistChart');
  if (ctxR) {
    if (chartInstances.religionDist) { try { chartInstances.religionDist.destroy(); } catch(e){} }
    var ld = _arrToLabelsData(charts && charts.religion_distribution, 'religion');
    chartInstances.religionDist = new Chart(ctxR.getContext('2d'), {
      type: 'doughnut',
      data: { labels: ld.labels, datasets: [{ data: ld.data, backgroundColor: palette.slice(0, ld.labels.length) }] },
      options: { responsive: true, plugins: { legend: { position: 'bottom', labels: { font: { size: 11 } } }, datalabels: PIE_DATALABEL_OPTS } }
    });
  }

  // Current Education — vertical bar
  var ctxE = document.getElementById('educationDistChart');
  if (ctxE) {
    if (chartInstances.educationDist) { try { chartInstances.educationDist.destroy(); } catch(e){} }
    var ld = _arrToLabelsData(charts && charts.education_distribution, 'education');
    chartInstances.educationDist = new Chart(ctxE.getContext('2d'), {
      type: 'bar',
      data: { labels: ld.labels, datasets: [{ label: 'FLPs', data: ld.data, backgroundColor: '#732269' }] },
      options: {
        responsive: true,
        plugins: { legend: { display: false }, datalabels: { color: '#333', anchor: 'end', align: 'end', font: { size: 10, weight: 'bold' } } },
        scales: { y: { beginAtZero: true, ticks: { precision: 0 } }, x: { ticks: { font: { size: 10 } } } }
      }
    });
  }

  // Per Capita Income — vertical bar (ordered low → high)
  var ctxP = document.getElementById('perCapitaChart');
  if (ctxP) {
    if (chartInstances.perCapita) { try { chartInstances.perCapita.destroy(); } catch(e){} }
    var ld = _arrToLabelsData(charts && charts.per_capita_distribution, 'bucket');
    chartInstances.perCapita = new Chart(ctxP.getContext('2d'), {
      type: 'bar',
      data: { labels: ld.labels, datasets: [{ label: 'FLPs', data: ld.data, backgroundColor: '#9b3d8e' }] },
      options: {
        responsive: true,
        plugins: { legend: { display: false }, datalabels: { color: '#333', anchor: 'end', align: 'end', font: { size: 10, weight: 'bold' } } },
        scales: { y: { beginAtZero: true, ticks: { precision: 0 } }, x: { ticks: { font: { size: 10 } } } }
      }
    });
  }
}

/** 2026-06-09 v2 — Trainings Done & Attended (Statewise) with Phase filter.
 *  The chart no longer encodes Phase as separate datasets; instead the
 *  user picks a Phase from the dropdown and the bars show the
 *  Trainings + Attendance totals for THAT phase per state.  "All Phases"
 *  sums across every phase. We cache the raw API rows + currently
 *  selected phase so onTrainingsPhaseFilterChange() can re-draw without
 *  another network round-trip. */
var _trainingByStateRows = [];          // last fetched rows
var _trainingPhaseSelected = '';        // '' = All Phases

function _createTrainingByStateChart(charts) {
  _trainingByStateRows = (charts && Array.isArray(charts.trainings_by_state_phase))
    ? charts.trainings_by_state_phase : [];
  // Refresh the Phase filter dropdown from the new dataset (preserve
  // current selection if it still exists, else fall back to All).
  _populateTrainingsPhaseFilter(_trainingByStateRows);
  _renderTrainingByStateChart();
}

function _populateTrainingsPhaseFilter(rows) {
  var sel = document.getElementById('trainingsPhaseFilter');
  if (!sel) return;
  var prev = sel.value;
  // Canonical-order first so the dropdown reads "Phase I, II, III, IV".
  var CANONICAL = ['Phase I','Phase II','Phase III','Phase IV','Unspecified'];
  var seen = {};
  rows.forEach(function(r) { if (r.phase) seen[r.phase] = true; });
  var phases = Object.keys(seen).sort(function(a,b) {
    var ai = CANONICAL.indexOf(a); var bi = CANONICAL.indexOf(b);
    if (ai < 0) ai = 99; if (bi < 0) bi = 99;
    return ai - bi;
  });
  sel.innerHTML = '<option value="">All Phases</option>';
  phases.forEach(function(p) {
    var o = document.createElement('option');
    o.value = p; o.textContent = p;
    sel.appendChild(o);
  });
  if (prev && phases.indexOf(prev) >= 0) sel.value = prev;
  else sel.value = '';
  _trainingPhaseSelected = sel.value;
}

/** Handler invoked from index.html when the user changes the Phase dropdown. */
function onTrainingsPhaseFilterChange() {
  var sel = document.getElementById('trainingsPhaseFilter');
  _trainingPhaseSelected = sel ? sel.value : '';
  _renderTrainingByStateChart();
}

function _renderTrainingByStateChart() {
  var ctx = document.getElementById('trainingsStateChart');
  if (!ctx) return;
  if (chartInstances.trainingsState) { try { chartInstances.trainingsState.destroy(); } catch(e){} }

  var rows = _trainingByStateRows;
  var phase = _trainingPhaseSelected || '';

  // Collapse rows to one entry per state by summing across the selected
  // phase set (single phase, or all phases when filter is empty).
  var perState = {}; var stateOrder = [];
  rows.forEach(function(r) {
    if (phase && r.phase !== phase) return;
    if (!perState[r.state]) {
      perState[r.state] = { trainings: 0, attendance: 0 };
      stateOrder.push(r.state);
    }
    perState[r.state].trainings  += Number(r.trainings || 0);
    perState[r.state].attendance += Number(r.attendance || 0);
  });
  var trainings  = stateOrder.map(function(s) { return perState[s].trainings; });
  var attendance = stateOrder.map(function(s) { return perState[s].attendance; });

  // Auto-widen so labels don't crush when many states are present.
  var wrap = document.getElementById('trainStateWrap');
  if (wrap) wrap.style.minWidth = Math.max(400, stateOrder.length * 130) + 'px';

  chartInstances.trainingsState = new Chart(ctx.getContext('2d'), {
    type: 'bar',
    data: {
      labels: stateOrder,
      datasets: [
        { label: 'Trainings',  data: trainings,  backgroundColor: '#732269' },
        { label: 'Attendance', data: attendance, backgroundColor: '#9b3d8e' }
      ]
    },
    options: {
      responsive: true,
      maintainAspectRatio: false,
      plugins: {
        legend: { position: 'bottom', labels: { font: { size: 11 } } },
        datalabels: { color: '#333', anchor: 'end', align: 'end', font: { size: 10, weight: 'bold' } },
        tooltip: { mode: 'index', intersect: false }
      },
      scales: {
        x: { ticks: { font: { size: 11 } } },
        y: { beginAtZero: true, ticks: { precision: 0 }, title: { display: true, text: 'Count' } }
      }
    }
  });
  ctx.style.height = '320px';
}

/** Internal: create the 3 survey analytics charts */
function _createSurveyCharts(charts) {
  // 1. Survey Status — Doughnut
  var ctx4 = document.getElementById('surveyStatusChart');
  if (ctx4) {
    var ssLabels = [];
    var ssData = [];
    if (charts && Array.isArray(charts.survey_status)) {
      charts.survey_status.forEach(function(item) { ssLabels.push(item.status); ssData.push(item.count); });
    }
    // Empty arrays render an empty doughnut — Chart.js handles this
    // gracefully. Demo fallbacks (28/12/4) removed: a wiped DB must
    // not look populated.
    var statusColors = { 'Approved': '#27ae60', 'Submitted': '#f39c12', 'Rejected': '#e74c3c', 'Draft': '#95a5a6' };
    var ssBg = ssLabels.map(function(l) { return statusColors[l] || '#732269'; });
    chartInstances.surveyStatus = new Chart(ctx4.getContext('2d'), {
      type: 'doughnut',
      data: { labels: ssLabels, datasets: [{ data: ssData, backgroundColor: ssBg }] },
      options: { responsive: true, plugins: { legend: { position: 'bottom', labels: { font: { size: 10 } } }, datalabels: PIE_DATALABEL_OPTS, title: { display: true, text: 'By Status', font: { size: 12 } } } }
    });
  }

  // 2. Surveys by State — Horizontal Bar
  var ctx5 = document.getElementById('surveysByStateChart');
  if (ctx5) {
    var sbsLabels = [];
    var sbsData = [];
    if (charts && Array.isArray(charts.surveys_by_state)) {
      charts.surveys_by_state.forEach(function(item) { sbsLabels.push(item.state); sbsData.push(item.count); });
    }
    // Empty arrays render an empty horizontal bar. Demo fallback removed
    // so the chart honestly reflects the database.
    chartInstances.surveysByState = new Chart(ctx5.getContext('2d'), {
      type: 'bar',
      data: { labels: sbsLabels, datasets: [{ label: 'Surveys', data: sbsData, backgroundColor: '#732269' }] },
      options: { responsive: true, indexAxis: 'y', plugins: { legend: { display: false }, datalabels: { display: false }, title: { display: true, text: 'By State', font: { size: 12 } } }, scales: { x: { beginAtZero: true } } }
    });
  }
}


