// 2026-06-06 v5: Wrap each <table.data-table> on the Assessment-flow
// pages in a <div.data-table-scroll> so the mobile CSS can attach
// overflow-x:auto to the wrapper. The table itself stays a single
// table-layout:fixed element so thead/tbody column widths line up
// (was previously diverging because each was its own display:table
// context, causing Action icons to land under "Endline Date").
// Idempotent — if the table is already wrapped, we skip.
function _wrapAssessmentTablesForMobile(pageId) {
  var page = document.getElementById('page-' + pageId);
  if (!page) return;
  var tables = page.querySelectorAll('table.data-table');
  for (var i = 0; i < tables.length; i++) {
    var tbl = tables[i];
    var parent = tbl.parentNode;
    if (parent && parent.classList && parent.classList.contains('data-table-scroll')) continue;
    var wrap = document.createElement('div');
    wrap.className = 'data-table-scroll';
    parent.insertBefore(wrap, tbl);
    wrap.appendChild(tbl);
  }
}

var _BR_PALETTE = ['#732269', '#9b3d8e', '#c06bb3', '#e0a3d4', '#3498db', '#27ae60', '#e67e22', '#f1c40f', '#16a085', '#34495e'];

function _brMakeChart(canvasId, config) {
  var prev = _brChartInstances[canvasId];
  if (prev) { try { prev.destroy(); } catch (e) {} }
  var el = document.getElementById(canvasId);
  if (!el) return;

  var t = (config && config.type) || '';
  var isScrollableType = (t === 'bar' || t === 'line');
  var isHorizontalBar = t === 'bar' &&
    config.options && config.options.indexAxis === 'y';

  // 2026-06-06 v10: Strip leftover .chart-canvas-outer/.chart-canvas-
  // inner wraps on desktop. See _akBrMakeChart for full rationale.
  var _wm = window.matchMedia;
  if (!(_wm && _wm('(max-width: 768px)').matches) &&
      el.parentElement &&
      el.parentElement.classList.contains('chart-canvas-inner')) {
    var _inner = el.parentElement;
    var _outer = _inner.parentElement;
    if (_outer && _outer.parentElement) {
      _outer.parentElement.insertBefore(el, _outer);
      _outer.parentElement.removeChild(_outer);
    }
  }

  // 2026-06-06 v9: MOBILE-ONLY wrap + tag + dimension fix.
  // Everything below is hard-gated behind a max-width:768px match.
  // Desktop / web view sees zero DOM mutation, zero class change,
  // zero inline style — Chart.js renders exactly as it did pre-
  // fix. See _akBrMakeChart for full rationale.
  var isMobile = window.matchMedia &&
                 window.matchMedia('(max-width: 768px)').matches;

  var innerEl = null;
  if (isMobile && isScrollableType && el.parentElement &&
      !el.parentElement.classList.contains('chart-canvas-inner')) {
    var outer = document.createElement('div');
    outer.className = 'chart-canvas-outer';
    var inner = document.createElement('div');
    inner.className = 'chart-canvas-inner';
    el.parentNode.insertBefore(outer, el);
    outer.appendChild(inner);
    inner.appendChild(el);
    innerEl = inner;
    outer.style.cssText = 'display:block;width:100%;overflow-x:auto;overflow-y:hidden;-webkit-overflow-scrolling:touch;';
    inner.style.cssText = 'display:block;width:800px;height:' +
      (isHorizontalBar ? '460px' : '340px') + ';position:relative;';
  } else if (isMobile && isScrollableType && el.parentElement &&
             el.parentElement.classList.contains('chart-canvas-inner')) {
    innerEl = el.parentElement;
  }

  var card = el.closest && el.closest('.chart-card');
  if (isMobile && card) {
    card.classList.remove('chart-bar', 'chart-line', 'chart-pie',
                          'chart-doughnut', 'chart-radar', 'chart-polarArea');
    if (t) card.classList.add('chart-' + t);
    card.classList.toggle('chart-horizontal-bar', !!isHorizontalBar);
  }

  if (isMobile && innerEl) { void innerEl.offsetHeight; }

  _brChartInstances[canvasId] = new Chart(el.getContext('2d'), config);
}

function _brPopulateFilters() {
  // State dropdown — once per session.
  if (!_brStateFilterLoaded) {
    _brStateFilterLoaded = true;
    var stateSel = document.getElementById('brFilterState');
    if (stateSel && typeof apiGeoDropdownStates === 'function') {
      apiGeoDropdownStates().then(function(resp) {
        var rows = (resp && resp.data) ? resp.data : (resp || []);
        rows.forEach(function(s) {
          var opt = document.createElement('option');
          opt.value = s.state_code; opt.textContent = s.state_name;
          stateSel.appendChild(opt);
        });
      }).catch(function() {});
    }
  }
  // Batch dropdown — cascades from State (and narrows further when a
  // Centre is picked). On first open with no state selected the dropdown
  // is empty + disabled with a "Select a state first" placeholder so the
  // user understands they need to pick a state to populate it.
  _brResetBatchDropdown();
}

// Reset the Batch dropdown to its empty + disabled state. Called on
// first load and whenever the State filter is cleared. Helpful prompt
// text tells the user the dropdown depends on the State filter.
function _brResetBatchDropdown() {
  var batchSel = document.getElementById('brFilterBatch');
  if (!batchSel) return;
  batchSel.innerHTML = '<option value="">Select a state first</option>';
  batchSel.disabled = true;
}

// Reload the Batch dropdown's options for the current State (and Centre,
// if any). Triggered by onBrStateChange / onBrCentreChange. Re-uses the
// existing /api/batches endpoint with state_code / centre_code filters
// — the same source the FLP list batch filter uses.
function _brReloadBatches() {
  var batchSel = document.getElementById('brFilterBatch');
  if (!batchSel) return;
  var sc = (document.getElementById('brFilterState')  || {}).value;
  var cc = (document.getElementById('brFilterCentre') || {}).value;
  if (!sc) { _brResetBatchDropdown(); return; }
  batchSel.innerHTML = '<option value="">Loading…</option>';
  batchSel.disabled = true;
  var params = { state_code: sc, limit: 500 };
  if (cc) params.centre_code = cc;
  apiBatches(params).then(function(resp) {
    var rows = (resp && resp.data) ? resp.data : (resp || []);
    batchSel.innerHTML = '<option value="">All Batches</option>';
    rows.forEach(function(b) {
      var opt = document.createElement('option');
      opt.value = b.id;
      opt.textContent = b.name + (b.year ? ' (' + b.year + ')' : '');
      batchSel.appendChild(opt);
    });
    batchSel.disabled = false;
    if (!rows.length) batchSel.innerHTML = '<option value="">No batches in this scope</option>';
  }).catch(function() {
    batchSel.innerHTML = '<option value="">Error loading batches</option>';
    batchSel.disabled = false;
  });
}

function onBrStateChange() {
  var sc = (document.getElementById('brFilterState') || {}).value;
  var distSel = document.getElementById('brFilterDistrict');
  var centreSel = document.getElementById('brFilterCentre');
  if (distSel)   distSel.innerHTML   = '<option value="">All Districts</option>';
  if (centreSel) centreSel.innerHTML = '<option value="">All Centres</option>';
  // State drives the Batch dropdown — empty + disabled when state cleared,
  // populated with that state's batches when a state is picked.
  _brReloadBatches();
  if (!sc) return;
  if (typeof apiGeoDropdownDistricts === 'function') {
    apiGeoDropdownDistricts(sc).then(function(resp) {
      var rows = (resp && resp.data) ? resp.data : (resp || []);
      rows.forEach(function(d) {
        var opt = document.createElement('option');
        opt.value = d.district_code; opt.textContent = d.district_name;
        distSel.appendChild(opt);
      });
    }).catch(function() {});
  }
}

function onBrDistrictChange() {
  var dc = (document.getElementById('brFilterDistrict') || {}).value;
  var centreSel = document.getElementById('brFilterCentre');
  if (centreSel) centreSel.innerHTML = '<option value="">All Centres</option>';
  if (!dc) return;
  if (typeof apiGeoDropdownCentres === 'function') {
    apiGeoDropdownCentres(dc).then(function(resp) {
      var rows = (resp && resp.data) ? resp.data : (resp || []);
      rows.forEach(function(c) {
        var opt = document.createElement('option');
        opt.value = c.centre_code; opt.textContent = c.centre_name;
        centreSel.appendChild(opt);
      });
    }).catch(function() {});
  }
}

// Centre change narrows the Batch dropdown further (within the already-
// state-scoped set). Wired through the Centre select's onchange in the
// HTML below.
function onBrCentreChange() {
  _brReloadBatches();
}

