// Generate Azad-report-style findings as a grid of categorized cards.
// Replaces the older flat bullet list with five themed sections — each a
// row of compact fact cards. Each card carries:
//   .br-kf-metric  — the headline number (the %)
//   .br-kf-label   — short label (e.g. "Q10 — Need permission to work")
//   .br-kf-desc    — one-line interpretive sentence
//   .br-kf-tag     — colored status pill (Progressive / Mixed / Concern)
// Card status (positive | mixed | concern) drives the left-border + bg
// tint via CSS classes declared inline on the page-baselineReport HTML.
function _brRenderKeyFindings(d, totalN, docsAny, smY, asY) {
  var host = document.getElementById('brKeyFindings');
  if (!host) return;
  if (!totalN) {
    host.innerHTML = '<div class="br-kf-empty">No completed baseline assessments in the current filter scope.</div>';
    return;
  }

  var pct = function(num, denom) { return denom ? Math.round(num * 100 / denom) : 0; };
  var esc = (typeof escHtml === 'function') ? escHtml : function(s) { return String(s == null ? '' : s); };

  // Build a single card.
  function card(opts) {
    var cls = 'br-kf-card' + (opts.status ? ' ' + opts.status : '');
    var tag = opts.tag ? '<span class="br-kf-tag">' + esc(opts.tag) + '</span>' : '';
    return '<div class="' + cls + '">'
         + '<div class="br-kf-label">' + esc(opts.label) + '</div>'
         + '<div class="br-kf-metric">' + opts.metric + '</div>'
         + (opts.desc ? '<div class="br-kf-desc">' + opts.desc + '</div>' : '')
         + tag
         + '</div>';
  }

  // Build a section block.
  function section(title, icon, cards) {
    if (!cards.length) return '';
    return '<div class="br-kf-section">'
         + '<div class="br-kf-section-title"><i class="fas ' + icon + '"></i>' + esc(title) + '</div>'
         + '<div class="br-kf-grid">' + cards.join('') + '</div>'
         + '</div>';
  }

  // Map a progressive-% to a status bucket. Thresholds mirror the report's
  // qualitative language: ≥60% = strong, 40-59 = mixed, <40 = concern.
  function statusForProgress(p) { return p >= 60 ? 'positive' : (p >= 40 ? 'mixed' : 'concern'); }
  function tagForProgress(p)    { return p >= 60 ? 'Progressive' : (p >= 40 ? 'Mixed' : 'Concern'); }

  // ===== 1. Demographics =====
  var demoCards = [];
  var ed = d.education_breakdown || [];
  if (ed.length) {
    var topEd = ed[0];
    demoCards.push(card({
      status: 'positive',
      label: 'Top Education Level',
      metric: esc(topEd.k),
      desc: '<b>' + topEd.c + '</b> of <b>' + totalN + '</b> (' + pct(topEd.c, totalN) + '%) — ' + ed.length + ' education level' + (ed.length === 1 ? '' : 's') + ' represented in this cohort.'
    }));
  }
  var cs = d.caste_breakdown || [];
  if (cs.length) {
    var topCs = cs[0];
    demoCards.push(card({
      status: 'positive',
      label: 'Largest Caste Group',
      metric: esc(topCs.k),
      desc: '<b>' + topCs.c + '</b> of <b>' + totalN + '</b> (' + pct(topCs.c, totalN) + '%) — diversity across ' + cs.length + ' caste categor' + (cs.length === 1 ? 'y' : 'ies') + '.'
    }));
  }
  var ageBuckets = d.age_buckets || [];
  if (ageBuckets.length) {
    var topAge = ageBuckets.reduce(function(a, b) { return (parseInt(a.c) >= parseInt(b.c)) ? a : b; });
    demoCards.push(card({
      status: 'positive',
      label: 'Predominant Age Group',
      metric: esc(topAge.bucket),
      desc: '<b>' + topAge.c + '</b> of <b>' + totalN + '</b> (' + pct(topAge.c, totalN) + '%) fall in this age bracket.'
    }));
  }

  // ===== 2. Gender Norms & Attitudes (Likert items) =====
  var attitudeCards = [];
  var likertLines = [
    { k: 'q10', label: 'Q10 — Need permission to work',           stmt: 'women need family permission to work' },
    { k: 'q11', label: 'Q11 — Marriage is life’s goal',       stmt: 'marriage and bearing children is a woman’s ultimate goal' },
    { k: 'q12', label: 'Q12 — Should not go out alone',           stmt: 'women should be escorted by a male family member outside' },
    { k: 'q14', label: 'Q14 — Gender stereotype (strong/emotional)', stmt: 'men are inherently strong, women are emotional' },
    { k: 'q17', label: 'Q17 — Work only if family needs',         stmt: 'married women should work only if the family needs income' }
  ];
  likertLines.forEach(function(L) {
    var arr = d['sec_b_' + L.k + '_dist'] || [];
    var prog = 0, total = 0;
    arr.forEach(function(r) { total += r.c; if (r.opt === 4 || r.opt === 5) prog += r.c; });
    if (!total) return;
    var p = pct(prog, total);
    attitudeCards.push(card({
      status: statusForProgress(p),
      label: L.label,
      metric: p + '%',
      desc: 'disagreed with the statement &ldquo;<i>' + L.stmt + '</i>&rdquo;.',
      tag: tagForProgress(p)
    }));
  });

  // ===== 3. Violence Awareness & Discrimination (vignettes) =====
  var violCards = [];
  // Q20 — LGBTQIA+ acceptance. opt 3 = positive, opt 1 = concern.
  var q20 = d.sec_b_q20_dist || [];
  var q20Bad = 0, q20Good = 0, q20Tot = 0;
  q20.forEach(function(r) { q20Tot += r.c; if (r.opt === 1) q20Bad += r.c; if (r.opt === 3) q20Good += r.c; });
  if (q20Tot) {
    var p20 = pct(q20Good, q20Tot);
    var b20 = pct(q20Bad, q20Tot);
    var lgbtqStatus = p20 >= 50 ? 'positive' : (b20 >= 40 ? 'concern' : 'mixed');
    violCards.push(card({
      status: lgbtqStatus,
      label: 'Q20 — LGBTQIA+ Awareness',
      metric: p20 + '%',
      desc: 'support normalising same-sex attraction and gender expression. <b>' + b20 + '%</b> still see queer identity as "abnormal".',
      tag: lgbtqStatus === 'positive' ? 'Progressive' : (lgbtqStatus === 'concern' ? 'Priority Sensitisation' : 'Mixed')
    }));
  }
  // Q21 — Marital consent. opt 2 = positive.
  var q21 = d.sec_b_q21_dist || [];
  var q21Good = 0, q21Tot = 0;
  q21.forEach(function(r) { q21Tot += r.c; if (r.opt === 2) q21Good += r.c; });
  if (q21Tot) {
    var p21 = pct(q21Good, q21Tot);
    violCards.push(card({
      status: statusForProgress(p21),
      label: 'Q21 — Marital Consent',
      metric: p21 + '%',
      desc: 'support a woman’s right to refuse physical intimacy if she is not ready.',
      tag: tagForProgress(p21)
    }));
  }
  // Q23 — Domestic violence response. opt 2 (helpline) = positive.
  var q23 = d.sec_b_q23_dist || [];
  var q23Good = 0, q23Tot = 0;
  q23.forEach(function(r) { q23Tot += r.c; if (r.opt === 2) q23Good += r.c; });
  if (q23Tot) {
    var p23 = pct(q23Good, q23Tot);
    violCards.push(card({
      status: statusForProgress(p23),
      label: 'Q23 — Domestic Violence Response',
      metric: p23 + '%',
      desc: 'would share a violence-redressal helpline — the rights-based response.',
      tag: tagForProgress(p23)
    }));
  }
  // Q22 — most cited form of violence.
  var q22 = d.sec_b_q22_options || [];
  if (q22.length) {
    var top22 = q22[0];
    violCards.push(card({
      status: 'positive',
      label: 'Q22 — Forms of Violence Identified',
      metric: pct(top22.c, totalN) + '%',
      desc: 'name <b>' + esc(top22.opt) + '</b> as a form of violence — the most-cited form in this cohort.'
    }));
  }
  // Q18 — Menstruation & ritual purity. opt 2 (continue, normal) = positive.
  var q18 = d.sec_b_q18_dist || [];
  var q18Good = 0, q18Tot = 0;
  q18.forEach(function(r) { q18Tot += r.c; if (r.opt === 2) q18Good += r.c; });
  if (q18Tot) {
    var p18 = pct(q18Good, q18Tot);
    violCards.push(card({
      status: statusForProgress(p18),
      label: 'Q18 — Menstruation & Ritual Purity',
      metric: p18 + '%',
      desc: 'reject the notion of impurity during menstruation.',
      tag: tagForProgress(p18)
    }));
  }
  // Q19 — Blame for daughters' births. opt 2 (not in parents' hands) = positive.
  var q19 = d.sec_b_q19_dist || [];
  var q19Good = 0, q19Tot = 0;
  q19.forEach(function(r) { q19Tot += r.c; if (r.opt === 2) q19Good += r.c; });
  if (q19Tot) {
    var p19 = pct(q19Good, q19Tot);
    violCards.push(card({
      status: statusForProgress(p19),
      label: 'Q19 — Blame for Daughters’ Births',
      metric: p19 + '%',
      desc: 'recognise that the sex of the child is not determined by the woman.',
      tag: tagForProgress(p19)
    }));
  }

  // ===== 4. Citizenship & Rights =====
  var citCards = [];
  var pDocs = pct(docsAny, totalN);
  citCards.push(card({
    status: statusForProgress(pDocs),
    label: 'Citizenship Documents',
    metric: pDocs + '%',
    desc: '<b>' + docsAny + '</b> of <b>' + totalN + '</b> hold at least one citizenship document.',
    tag: tagForProgress(pDocs)
  }));
  var pSm = pct(smY, totalN);
  citCards.push(card({
    status: statusForProgress(pSm),
    label: 'Self-Made Documents (Q25)',
    metric: pSm + '%',
    desc: '<b>' + smY + '</b> independently created at least one of their documents.',
    tag: tagForProgress(pSm)
  }));
  var pAs = pct(asY, totalN);
  citCards.push(card({
    status: statusForProgress(pAs),
    label: 'Assisted Others (Q26)',
    metric: pAs + '%',
    desc: '<b>' + asY + '</b> have helped family or community access documents / schemes.',
    tag: tagForProgress(pAs)
  }));

  // ===== 5. Leadership Readiness =====
  var ldrCards = [];
  var q27 = d.sec_d_q27_dist || [];
  if (q27.length) {
    var top27 = q27.reduce(function(a, b) { return (a.c >= b.c) ? a : b; });
    var lbl27 = (_BR_OPT_LABELS.q27 || {})[top27.opt] || ('Opt ' + top27.opt);
    ldrCards.push(card({
      status: 'positive',
      label: 'Q27 — Primary Leadership Motivation',
      metric: pct(top27.c, totalN) + '%',
      desc: 'cite <b>"' + esc(lbl27) + '"</b> as their main reason for wanting to lead.'
    }));
  }
  var q28 = d.sec_d_q28_dist || [];
  if (q28.length) {
    var top28 = q28.reduce(function(a, b) { return (a.c >= b.c) ? a : b; });
    var lbl28 = (_BR_OPT_LABELS.q28 || {})[top28.opt] || ('Opt ' + top28.opt);
    ldrCards.push(card({
      status: 'positive',
      label: 'Q28 — How Leadership Develops',
      metric: pct(top28.c, totalN) + '%',
      desc: 'see <b>"' + esc(lbl28) + '"</b> as the best way to learn leadership.'
    }));
  }
  var q29 = d.sec_d_q29_dist || [];
  if (q29.length) {
    var top29 = q29.reduce(function(a, b) { return (a.c >= b.c) ? a : b; });
    var lbl29 = (_BR_OPT_LABELS.q29 || {})[top29.opt] || ('Opt ' + top29.opt);
    ldrCards.push(card({
      status: 'positive',
      label: 'Q29 — Best Way to Contribute',
      metric: pct(top29.c, totalN) + '%',
      desc: 'choose <b>"' + esc(lbl29) + '"</b> as the best way to contribute to community.'
    }));
  }

  host.innerHTML =
    section('Demographics',                   'fa-user',          demoCards) +
    section('Gender Norms & Attitudes',       'fa-venus-mars',    attitudeCards) +
    section('Violence Awareness & Discrimination', 'fa-shield-alt', violCards) +
    section('Citizenship & Rights',           'fa-id-card',       citCards) +
    section('Leadership Readiness',           'fa-hands-helping', ldrCards);
}

function loadBaselineReport() {
  _brPopulateFilters();
  _refreshBaselineReport();
}

function _refreshBaselineReport() {
  apiBaselineReport(_brCollectFilters()).then(function(d) {
    _brRender(d || {});
  }).catch(function(err) { showUserError('loading Baseline Report', err); });
}

function _brRender(d) {
  var setText = function(id, v) {
    var el = document.getElementById(id);
    if (el) el.textContent = (v == null || v === '') ? '0' : String(v);
  };
  var k = d.kpis || {};
  var ag = d.sec_c_agency || {};
  var totalN = parseInt(k.total, 10) || 0;
  var smY    = parseInt(ag.self_made_yes, 10) || 0;
  var smN    = parseInt(ag.self_made_no,  10) || 0;
  var asY    = parseInt(ag.assisted_yes,  10) || 0;
  var asN    = parseInt(ag.assisted_no,   10) || 0;
  var docsAny= parseInt(ag.docs_any,      10) || 0;
  setText('brKpiTotal',       k.total);
  setText('brKpiAvgScore',    k.avg_score != null ? k.avg_score + '%' : '—');
  setText('brKpiProgressive', d.progressive_pct != null ? d.progressive_pct + '%' : '—');
  setText('brKpiSelfMade',    (smY + smN) ? Math.round(smY * 100 / (smY + smN)) + '%' : '—');
  setText('brKpiAssisted',    (asY + asN) ? Math.round(asY * 100 / (asY + asN)) + '%' : '—');
  setText('brKpiDocsHeld',    totalN ? Math.round(docsAny * 100 / totalN) + '%' : '—');

  // ----- Auto-generated key findings (narrative bullets, Azad-report style)
  _brRenderKeyFindings(d, totalN, docsAny, smY, asY);

  // ----- Citizenship summary table (Table 1 of the report) -----
  var docs = d.sec_c_docs_held || [];
  var topDocs = docs.slice(0, 6).map(function(r) { return r.opt + ' (' + r.c + ')'; }).join(', ') || '—';
  setText('brTblDocsAny',      docsAny);
  setText('brTblTopDocs',      topDocs);
  setText('brTblSelfMadeYes',  smY);
  setText('brTblSelfMadeNo',   smN);
  setText('brTblAssistedYes',  asY);
  setText('brTblAssistedNo',   asN);

  // ===== Section A — Demographics =====
  // Age + Caste charts removed on 2026-05-16; both are still summarised
  // in the Key Findings panel above. Education + Income charts retained
  // because their distribution shapes don't compress well into a single
  // headline number.
  var ed = d.education_breakdown || [];
  _brMakeChart('brEducationChart', {
    type: 'doughnut',
    data: { labels: ed.map(function(r) { return r.k; }),
            datasets: [{ data: ed.map(function(r) { return parseInt(r.c, 10) || 0; }), backgroundColor: _BR_PALETTE }] },
    options: { responsive: true, maintainAspectRatio: false, plugins: { legend: { position: 'right', labels: { boxWidth: 12, font: { size: 11 } } } } }
  });

  var inc = d.income_buckets || [];
  _brMakeChart('brIncomeChart', {
    type: 'bar',
    data: { labels: inc.map(function(r) { return r.bucket; }),
            datasets: [{ label: 'FLPs', data: inc.map(function(r) { return parseInt(r.c, 10) || 0; }), backgroundColor: '#27ae60', borderRadius: 4 }] },
    options: { responsive: true, maintainAspectRatio: false, plugins: { legend: { display: false } }, scales: { y: { beginAtZero: true, ticks: { precision: 0 } } } }
  });

  // ===== Section B — Gender Attitudes (full Likert distribution) =====
  // Stacked horizontal bar: 5 statements × 5 options. Red shades = regressive
  // (Completely Agree / Somewhat Agree), grey = neutral, green shades =
  // progressive (Somewhat Disagree / Completely Disagree).
  var likertKeys = ['q10','q11','q12','q14','q17'];
  var likertOptColors = ['#c0392b', '#e67e22', '#bdc3c7', '#27ae60', '#16a085'];
  var likertOptLabels = ['Completely Agree', 'Somewhat Agree', 'Neither', 'Somewhat Disagree', 'Completely Disagree'];
  // Build a 5-element count vector per statement.
  function _likertCounts(distArr) {
    var out = [0, 0, 0, 0, 0];
    (distArr || []).forEach(function(r) {
      var i = (parseInt(r.opt, 10) || 0) - 1;
      if (i >= 0 && i < 5) out[i] = parseInt(r.c, 10) || 0;
    });
    return out;
  }
  var likertData = likertKeys.map(function(k) { return _likertCounts(d['sec_b_' + k + '_dist']); });
  _brMakeChart('brLikertChart', {
    type: 'bar',
    data: {
      labels: likertKeys.map(function(k) { return _BR_LIKERT_LABELS[k]; }),
      datasets: likertOptLabels.map(function(lbl, optIdx) {
        return {
          label: lbl,
          data: likertData.map(function(row) { return row[optIdx]; }),
          backgroundColor: likertOptColors[optIdx]
        };
      })
    },
    options: {
      responsive: true, maintainAspectRatio: false, indexAxis: 'y',
      plugins: { legend: { position: 'bottom', labels: { boxWidth: 14, font: { size: 11 } } } },
      scales: { x: { stacked: true, beginAtZero: true, ticks: { precision: 0 } }, y: { stacked: true } }
    }
  });

  var q15 = d.sec_b_q15_options || [];
  _brMakeChart('brQ15Chart', {
    type: 'bar',
    data: { labels: q15.map(function(r) { return r.opt; }),
            datasets: [{ label: 'FLPs', data: q15.map(function(r) { return parseInt(r.c, 10) || 0; }), backgroundColor: '#c06bb3', borderRadius: 4 }] },
    options: { responsive: true, maintainAspectRatio: false, indexAxis: 'y', plugins: { legend: { display: false } }, scales: { x: { beginAtZero: true, ticks: { precision: 0 } } } }
  });

  var q22 = d.sec_b_q22_options || [];
  _brMakeChart('brQ22Chart', {
    type: 'bar',
    data: { labels: q22.map(function(r) { return r.opt; }),
            datasets: [{ label: 'FLPs', data: q22.map(function(r) { return parseInt(r.c, 10) || 0; }), backgroundColor: '#e74c3c', borderRadius: 4 }] },
    options: { responsive: true, maintainAspectRatio: false, indexAxis: 'y', plugins: { legend: { display: false } }, scales: { x: { beginAtZero: true, ticks: { precision: 0 } } } }
  });

  // Generic option-mix renderer for the 1..N scenario questions.
  function _brRenderOptDist(canvasId, qKey, sourceArr, color) {
    var labels = (sourceArr || []).map(function(r) {
      var lbl = (_BR_OPT_LABELS[qKey] || {})[r.opt];
      return lbl ? lbl : 'Opt ' + r.opt;
    });
    var data = (sourceArr || []).map(function(r) { return parseInt(r.c, 10) || 0; });
    _brMakeChart(canvasId, {
      type: 'bar',
      data: { labels: labels,
              datasets: [{ label: 'FLPs', data: data, backgroundColor: color, borderRadius: 4 }] },
      options: { responsive: true, maintainAspectRatio: false, plugins: { legend: { display: false } }, scales: { y: { beginAtZero: true, ticks: { precision: 0 } } } }
    });
  }
  // Note: per-question scenario charts (Q13/Q16/Q18/Q19/Q20/Q21/Q23) were
  // removed on 2026-05-16 because each is already summarised as a fact
  // card in the Key Findings panel — the report doesn't visualise these
  // separately either, it discusses them as narrative. The backend still
  // returns the distributions in case future tooling wants them.

  // ===== Section C — Citizenship Documents =====
  var docs = d.sec_c_docs_held || [];
  _brMakeChart('brDocsChart', {
    type: 'bar',
    data: { labels: docs.map(function(r) { return r.opt; }),
            datasets: [{ label: 'FLPs holding', data: docs.map(function(r) { return parseInt(r.c, 10) || 0; }), backgroundColor: '#732269', borderRadius: 4 }] },
    options: { responsive: true, maintainAspectRatio: false, indexAxis: 'y', plugins: { legend: { display: false } }, scales: { x: { beginAtZero: true, ticks: { precision: 0 } } } }
  });

  var ag2 = d.sec_c_agency || {};
  _brMakeChart('brAgencyChart', {
    type: 'bar',
    data: {
      labels: ['Self-made document (Q25)', 'Assisted others (Q26)'],
      datasets: [
        { label: 'Yes', data: [parseInt(ag2.self_made_yes, 10) || 0, parseInt(ag2.assisted_yes, 10) || 0], backgroundColor: '#27ae60', borderRadius: 4 },
        { label: 'No',  data: [parseInt(ag2.self_made_no,  10) || 0, parseInt(ag2.assisted_no,  10) || 0], backgroundColor: '#e74c3c', borderRadius: 4 }
      ]
    },
    options: { responsive: true, maintainAspectRatio: false, plugins: { legend: { position: 'bottom' } }, scales: { y: { beginAtZero: true, ticks: { precision: 0 } } } }
  });

  // ===== Section D — Community Leadership =====
  // Q27 / Q28 / Q29 are surfaced in Key Findings; only Q30 (multi-select
  // leadership characteristics) gets its own chart here so all 8 options
  // are visible at once.
  var q30 = d.sec_d_q30_options || [];
  _brMakeChart('brQ30Chart', {
    type: 'bar',
    data: { labels: q30.map(function(r) { return r.opt; }),
            datasets: [{ label: 'FLPs', data: q30.map(function(r) { return parseInt(r.c, 10) || 0; }), backgroundColor: '#16a085', borderRadius: 4 }] },
    options: { responsive: true, maintainAspectRatio: false, indexAxis: 'y', plugins: { legend: { display: false } }, scales: { x: { beginAtZero: true, ticks: { precision: 0 } } } }
  });
}


function initAssessmentCharts() {
  var preId = window._comparePreId;
  if (!preId) {
    document.getElementById('compareDetailBody').innerHTML = '<p style="text-align:center;color:#999;padding:30px;">No assessment selected for comparison.</p>';
    return;
  }

  apiAssessmentCompare(preId).then(function(data) {
    var pre = data.pre_assessment || {};
    var post = data.post_assessment || {};
    var preScore = data.pre_score || 0;
    var postScore = data.post_score || 0;
    // Recompute improvement from pre/post and clamp at 0.
    // Client requirement: "Improvement" should never display as negative —
    // by definition improvement is the non-negative gain after training.
    var improvement = Math.max(0, Math.round(postScore - preScore));

    // Populate header
    document.getElementById('cmpFlpName').textContent = data.flp_name || '—';
    document.getElementById('cmpEnrollment').textContent = data.enrollment_number || '—';
    document.getElementById('cmpLocation').textContent = data.location || '—';
    document.getElementById('cmpPreDate').textContent = pre.assessment_date ? formatDateNice(pre.assessment_date) : '—';
    document.getElementById('cmpPostDate').textContent = post && post.assessment_date ? formatDateNice(post.assessment_date) : '—';

    // Calculate gap
    if (pre.assessment_date && post && post.assessment_date) {
      var d1 = new Date(pre.assessment_date), d2 = new Date(post.assessment_date);
      var months = Math.round((d2 - d1) / (30.44 * 24 * 60 * 60 * 1000));
      document.getElementById('cmpGap').textContent = months + ' months';
    }

    // Scores
    document.getElementById('cmpPreScore').textContent = Math.round(preScore) + '%';
    document.getElementById('cmpPostScore').textContent = Math.round(postScore) + '%';
    document.getElementById('cmpImprovement').textContent = '+' + improvement + '%';

    // Calculate section-wise scores
    function sectionPct(obj, keys) {
      if (!obj) return 0;
      var total = 0, count = 0, max = 5;
      keys.forEach(function(k) { var v = obj[k]; if (v != null && typeof v === 'number') { total += v; count++; } });
      return count > 0 ? Math.round(total / (count * max) * 100) : 0;
    }
    var secBkeys = ['q10','q11','q12','q13','q14','q16','q17'];
    var secCkeys_scenario = ['q18','q19','q20','q21','q23'];
    var secDkeys = ['q27','q28','q29'];

    var preSections = [sectionPct(pre, secBkeys), sectionPct(pre, secCkeys_scenario), 0, sectionPct(pre, secDkeys)];
    var postSections = [sectionPct(post, secBkeys), sectionPct(post, secCkeys_scenario), 0, sectionPct(post, secDkeys)];

    // Charts
    if (chartInstances.assessCompare) chartInstances.assessCompare.destroy();
    if (chartInstances.assessRadar) chartInstances.assessRadar.destroy();

    var ctx6 = document.getElementById('assessmentCompareChart');
    if (ctx6) {
      chartInstances.assessCompare = new Chart(ctx6.getContext('2d'), {
        type: 'bar',
        data: {
          labels: ['Gender Attitudes\n(Q10-Q17)', 'Scenario\nResponses\n(Q18-Q23)', 'Citizenship\nDocuments\n(Q24-Q26)', 'Community\nLeadership\n(Q27-Q30)'],
          datasets: [
            { label: 'Baseline Score (%)', data: preSections, backgroundColor: '#e74c3c' },
            { label: 'Endline Score (%)', data: postSections, backgroundColor: '#27ae60' }
          ]
        },
        options: {
          responsive: true,
          scales: { y: { beginAtZero: true, max: 100, ticks: { callback: function(v) { return v + '%'; } } } },
          plugins: { legend: { position: 'bottom' }, datalabels: { display: false } }
        }
      });
    }

    // Radar chart — individual question scores
    var radarKeys = ['q10','q14','q20','q21','q23','q27','q28','q29'];
    var radarLabels = radarKeys.map(function(k) { return (_assessQLabels[k] || k).substring(0, 15); });
    var radarPre = radarKeys.map(function(k) { return (pre[k] != null) ? pre[k] : 0; });
    var radarPost = radarKeys.map(function(k) { return (post && post[k] != null) ? post[k] : 0; });

    var ctx7 = document.getElementById('assessmentRadarChart');
    if (ctx7) {
      chartInstances.assessRadar = new Chart(ctx7.getContext('2d'), {
        type: 'radar',
        data: {
          labels: radarLabels,
          datasets: [
            { label: 'Baseline', data: radarPre, backgroundColor: 'rgba(231,76,60,0.2)', borderColor: '#e74c3c', pointBackgroundColor: '#e74c3c' },
            { label: 'Endline', data: radarPost, backgroundColor: 'rgba(39,174,96,0.2)', borderColor: '#27ae60', pointBackgroundColor: '#27ae60' }
          ]
        },
        options: {
          responsive: true,
          scales: { r: { beginAtZero: true, max: 5, ticks: { stepSize: 1 } } },
          plugins: { legend: { position: 'bottom' }, datalabels: { display: false } }
        }
      });
    }

    // Build detail comparison tables
    _buildComparisonTables(pre, post);

  }).catch(function(err) {
    document.getElementById('compareDetailBody').innerHTML = '<p style="text-align:center;color:#e74c3c;padding:30px;">Failed to load comparison: ' + (err.message || err) + '</p>';
  });
}

function _buildComparisonTables(pre, post) {
  var container = document.getElementById('compareDetailBody');
  if (!container) return;

  function valDisplay(val, isCheckbox) {
    if (val == null || val === '') return '<span style="color:#999;">—</span>';
    if (Array.isArray(val)) return val.join(', ') + ' (' + val.length + ' selected)';
    if (typeof val === 'boolean') return val ? 'Yes' : 'No';
    if (_assessLikertLabels[val]) return _assessLikertLabels[val];
    return String(val);
  }

  function changeIcon(preVal, postVal) {
    if (preVal == null && postVal == null) return '<span style="color:#999;">—</span>';
    if (typeof preVal === 'number' && typeof postVal === 'number') {
      if (postVal > preVal) return '<span style="color:#27ae60;font-weight:700;"><i class="fas fa-arrow-up"></i> Improved</span>';
      if (postVal < preVal) return '<span style="color:#e74c3c;font-weight:700;"><i class="fas fa-arrow-down"></i> Declined</span>';
      return '<span style="color:#3498db;font-weight:700;"><i class="fas fa-equals"></i> Same</span>';
    }
    if (Array.isArray(preVal) && Array.isArray(postVal)) {
      if (postVal.length > preVal.length) return '<span style="color:#27ae60;font-weight:700;"><i class="fas fa-arrow-up"></i> +' + (postVal.length - preVal.length) + '</span>';
      if (postVal.length < preVal.length) return '<span style="color:#e74c3c;font-weight:700;"><i class="fas fa-arrow-down"></i> -' + (preVal.length - postVal.length) + '</span>';
      return '<span style="color:#3498db;font-weight:700;"><i class="fas fa-equals"></i> Same</span>';
    }
    if (String(preVal) !== String(postVal)) return '<span style="color:#27ae60;font-weight:700;"><i class="fas fa-arrow-up"></i> Changed</span>';
    return '<span style="color:#3498db;font-weight:700;"><i class="fas fa-equals"></i> Same</span>';
  }

  function badge(val, isPost) {
    var cls = isPost ? 'badge-approved' : 'badge-walkout';
    return '<span class="badge ' + cls + '">' + escHtml(valDisplay(val)) + '</span>';
  }

  function makeSection(title, icon, questions) {
    var html = '<div class="form-card" style="margin-top:15px;">';
    html += '<h3 style="color:#732269;margin-bottom:15px;border-bottom:2px solid #732269;padding-bottom:8px;"><i class="fas fa-' + icon + '"></i> ' + escHtml(title) + '</h3>';
    html += '<table class="data-table full-width"><thead><tr><th style="width:35%;">Question</th><th style="width:25%;">Baseline</th><th style="width:25%;">Endline</th><th style="width:15%;">Change</th></tr></thead><tbody>';
    questions.forEach(function(q) {
      var preV = pre[q.key]; var postV = post ? post[q.key] : null;
      html += '<tr><td>' + escHtml(q.label) + '</td><td>' + badge(preV, false) + '</td><td>' + badge(postV, true) + '</td><td>' + changeIcon(preV, postV) + '</td></tr>';
    });
    html += '</tbody></table></div>';
    return html;
  }

  var secB = [
    {key:'q10',label:'Q10. Women can work only with permission'},{key:'q11',label:"Q11. Women's goal is marriage & children"},
    {key:'q12',label:'Q12. Women should not go out alone'},{key:'q13',label:'Q13. Karva Chauth / Fasting customs'},
    {key:'q14',label:'Q14. Men strong, women emotional'},{key:'q15',label:'Q15. Suitable work for women'},
    {key:'q16',label:'Q16. Salary decision'},{key:'q17',label:'Q17. Married women work only if needed'},
    {key:'q18',label:'Q18. Periods & Puja'},{key:'q19',label:'Q19. Sex determination'},
    {key:'q20',label:'Q20. LGBTQ+ acceptance'},{key:'q21',label:'Q21. Marital consent'},
    {key:'q22',label:'Q22. Forms of violence identified'},{key:'q23',label:'Q23. Domestic violence response'}
  ];
  var secC = [
    {key:'q24',label:'Q24. Documents held'},{key:'q25_self_made',label:'Q25. Self-made document'},
    {key:'q26_assisted_others',label:'Q26. Assisted others'}
  ];
  var secD = [
    {key:'q27',label:'Q27. Why be a community leader?'},{key:'q28',label:'Q28. Leadership development'},
    {key:'q29',label:'Q29. Community contribution'},{key:'q30',label:'Q30. Leadership characteristics'}
  ];

  container.innerHTML =
    makeSection('Section B: Gender Attitudes — Question-Wise Comparison', 'venus-mars', secB) +
    makeSection('Section C: Citizenship Documents', 'id-card', secC) +
    makeSection('Section D: Community Leadership', 'hands-helping', secD);
}


