// ===== FLP FORM TABS =====
function switchFlpTab(tabId) {
  // Determine current tab
  var activeTab = document.querySelector('.tab-content.active');
  var currentTabId = activeTab ? activeTab.id.replace('tab-', '') : '';
  var tabNames = ['basicProfile','bankDetail','family','prevEmployment','documents','emergencyContacts','credential','reviewSubmit'];
  var currentIdx = tabNames.indexOf(currentTabId);
  var targetIdx = tabNames.indexOf(tabId);

  // Only validate when moving forward (Next button)
  if (targetIdx > currentIdx && currentTabId) {
    var missing = validateFlpTab(currentTabId);
    if (missing.length > 0) {
      alert('Please fill all mandatory fields:\n\n' + missing.join('\n'));
      return;
    }
    // Validate email format
    var emailInput = document.getElementById('flpEmail');
    if (currentTabId === 'basicProfile' && emailInput && emailInput.value) {
      var re = /^[^\s@]+@[^\s@]+\.[^\s@]+$/;
      if (!re.test(emailInput.value)) {
        alert('Please enter a valid Email ID');
        emailInput.focus();
        return;
      }
    }
  }

  document.querySelectorAll('.tab-content').forEach(function(t) { t.classList.remove('active'); });
  document.querySelectorAll('.tab-btn').forEach(function(b) { b.classList.remove('active'); });
  var tabEl = document.getElementById('tab-' + tabId);
  if (tabEl) tabEl.classList.add('active');
  var btns = document.querySelectorAll('.tab-btn');
  var idx = tabNames.indexOf(tabId);
  if (idx >= 0 && btns[idx]) btns[idx].classList.add('active');
  // Populate review tab when switching to it
  if (tabId === 'reviewSubmit' && typeof populateFlpReview === 'function') populateFlpReview();
}

function validateFlpTab(tabId) {
  var missing = [];
  if (tabId === 'basicProfile') {
    // Location (mandatory)
    if (!(document.getElementById('flpState') || {}).value) missing.push('- State is required');
    if (!(document.getElementById('flpDistrict') || {}).value) missing.push('- District is required');
    if (!(document.getElementById('flpCentre') || {}).value) missing.push('- Centre is required');
    if (!(document.getElementById('flpBatch') || {}).value) missing.push('- Batch is required');
    if (!document.getElementById('flpName').value.trim()) missing.push('- Name is required');
    var _dobVal = document.getElementById('flpDob').value;
    if (!_dobVal) missing.push('- Date of Birth is required');
    else {
      var _dobAge = calculateAgeFromDob(_dobVal);
      if (_dobAge !== null && _dobAge < 18) missing.push('- Candidate must be at least 18 years old at enrollment');
    }
    if (!document.getElementById('flpMobile').value || document.getElementById('flpMobile').value.length < 10) missing.push('- Mobile Number must be 10 digits');
    if (!document.getElementById('flpAddress').value.trim()) missing.push('- Address is required');
    if (!document.getElementById('monthlyIncome').value) missing.push('- Monthly Family Income is required');
    if (!document.getElementById('familyMembers').value) missing.push('- Number of Family Members is required');
    // Commitment Fund is mandatory; Amount is mandatory when Partial is selected
    var _cType = (document.getElementById('flpCommitmentType') || {}).value;
    if (!_cType) missing.push('- Commitment Fund (Full / Partial) is required');
    if (_cType === 'Partial') {
      var _cAmt = (document.getElementById('flpCommitmentAmount') || {}).value;
      var _cAmtNum = parseInt(_cAmt);
      if (!_cAmt || isNaN(_cAmtNum) || _cAmtNum <= 0) missing.push('- Commitment Fund Amount is required when "Partial" is selected');
      else if (_cAmtNum >= 2000) missing.push('- Partial Commitment Amount must be less than ₹2,000');
    }
  } else if (tabId === 'bankDetail') {
    var bankType = (document.getElementById('flpBankAccountType') || {}).value;
    if (!bankType) missing.push('- Bank Account Type is required');
    if (!document.getElementById('flpBankName').value.trim()) missing.push('- Bank Name is required');
    if (!document.getElementById('flpAccountHolder').value.trim()) missing.push('- Name as per Bank Details is required');
    if (!document.getElementById('flpAccountNumber').value.trim()) missing.push('- Bank Account Number is required');
    if (!document.getElementById('flpBankBranch').value.trim()) missing.push('- Branch is required');
    if (!document.getElementById('flpIfsc').value.trim()) missing.push('- IFSC Code is required');
  } else if (tabId === 'prevEmployment') {
    if (!document.getElementById('flpRelation').value.trim()) missing.push('- FLP Relation is required');
    var whyJoin = getWhyJoinCheckboxValues();
    if (whyJoin.length === 0) missing.push('- Why do you want to join FLP? (select at least 1 reason)');
    if (!document.getElementById('flpChallenges').value) missing.push('- Challenges/Obstacles is required');
    if (!document.getElementById('flpFutureGoal').value) missing.push('- Future Goal is required');
  }
  return missing;
}

