// ===== PER CAPITA CALCULATION =====
function calcPerCapita() {
  var income = parseFloat(document.getElementById('monthlyIncome').value) || 0;
  var members = parseInt(document.getElementById('familyMembers').value) || 0;
  var pc = members > 0 ? Math.round(income / members) : 0;
  document.getElementById('perCapita').value = pc > 0 ? '\u20B9' + pc.toLocaleString() : '';
  // Also update family tab per capita display
  var familyPc = document.getElementById('familyPerCapita');
  if (familyPc) familyPc.textContent = pc > 0 ? '\u20B9' + pc.toLocaleString() : '\u20B90';
}

// ===== EMAIL VALIDATION =====
function validateEmail(input) {
  if (!input || !input.value) return;
  var re = /^[^\s@]+@[^\s@]+\.[^\s@]+$/;
  if (!re.test(input.value)) {
    input.style.borderColor = 'red';
    input.title = 'Please enter a valid email address';
  } else {
    input.style.borderColor = '';
    input.title = '';
  }
}

// ===== FAMILY TABLE =====
function addFamilyRow() {
  var tbody = document.querySelector('#familyTable tbody');
  var row = document.createElement('tr');
  // Relation and Occupation cells now contain BOTH the dropdown and an
  // inline "Specify" text field shown only when the user picks "Other"
  // or "Any other". The specify input is marked with the `.fam-specify`
  // class so the save/load helpers can exclude it from the positional
  // `inputs[N]` indexing they already do — keeps existing index logic
  // intact while still letting us harvest the specify value separately.
  // The inline layout (`display:flex;gap:6px`) puts the specify field
  // beside the dropdown on the same line, per the field-staff request.
  row.innerHTML = '<td><input type="text" placeholder="Name" class="table-input" oninput="this.value=this.value.replace(/[0-9]/g,\'\')"></td>' +
    '<td>' +
      '<div style="display:flex;gap:6px;align-items:center;">' +
        '<select class="table-input fam-relation" onchange="_onFamilyRelationChange(this)" style="flex:1;min-width:0;">' +
          '<option value="">Select Relation</option>' +
          '<option>Father</option><option>Mother</option><option>Spouse</option>' +
          '<option>Brother</option><option>Sister</option><option>Child</option>' +
          '<option>Other</option>' +
        '</select>' +
        '<input type="text" class="table-input fam-specify fam-relation-other" placeholder="Specify" style="flex:1;min-width:0;display:none;">' +
      '</div>' +
    '</td>' +
    '<td><input type="number" placeholder="Age" class="table-input"></td>' +
    '<td><select class="table-input"><option value="">Select Education</option><option>Uneducated</option><option>Below 5th</option><option>5th</option><option>6th</option><option>7th</option><option>8th</option><option>9th</option><option>10th</option><option>11th</option><option>12th</option><option>Graduate</option><option>Post Graduate</option></select></td>' +
    '<td>' +
      '<div style="display:flex;gap:6px;align-items:center;">' +
        '<select class="table-input fam-occupation" onchange="_onFamilyOccupationChange(this)" style="flex:1;min-width:0;">' +
          '<option value="">Select Occupation</option>' +
          '<option>Employed</option><option>Self-employed</option>' +
          '<option>House wife</option><option>Student</option>' +
          '<option>Unemployed</option><option>Retired</option>' +
          '<option>Any other</option>' +
        '</select>' +
        '<input type="text" class="table-input fam-specify fam-occupation-other" placeholder="Specify" style="flex:1;min-width:0;display:none;">' +
      '</div>' +
    '</td>' +
    '<td><input type="number" placeholder="INR" class="table-input"></td>' +
    '<td><input type="text" placeholder="Contribution" class="table-input"></td>' +
    '<td><button class="btn-icon text-danger" title="Remove" onclick="this.closest(\'tr\').remove()"><i class="fas fa-trash-alt"></i></button></td>';
  tbody.appendChild(row);
}

// Toggle the inline "Specify" text field next to the Relation dropdown
// in a Family Details row. Visible only when relation === "Other".
// Clears the specify value when the user picks something else so a
// stale "Other"-specific note doesn't get saved alongside, e.g., a
// "Brother" row.
function _onFamilyRelationChange(sel) {
  var row = sel.closest('tr');
  if (!row) return;
  var spec = row.querySelector('.fam-relation-other');
  if (!spec) return;
  var isOther = (sel.value === 'Other');
  spec.style.display = isOther ? '' : 'none';
  if (!isOther) spec.value = '';
}

// Same toggle logic for the Occupation cell. The dropdown's special
// option is "Any other" (per the field-staff brief — distinct from the
// Relation dropdown's "Other" so we keep the option labels exactly as
// users see them).
function _onFamilyOccupationChange(sel) {
  var row = sel.closest('tr');
  if (!row) return;
  var spec = row.querySelector('.fam-occupation-other');
  if (!spec) return;
  var isOther = (sel.value === 'Any other');
  spec.style.display = isOther ? '' : 'none';
  if (!isOther) spec.value = '';
}

