// ===== WHY JOIN CHECKBOX VALUES =====
function getWhyJoinCheckboxValues() {
  var values = [];
  var cbs = document.querySelectorAll('input[name="whyJoin"]:checked');
  cbs.forEach(function(cb) {
    if (cb.value === 'Other') {
      var specifyEl = document.getElementById('flpWhyJoinOther');
      var specifyVal = specifyEl ? specifyEl.value.trim() : '';
      values.push(specifyVal ? 'Other: ' + specifyVal : 'Other');
    } else {
      values.push(cb.value);
    }
  });
  return values;
}

function setWhyJoinCheckboxValues(values) {
  if (!values || !Array.isArray(values)) return;
  var cbs = document.querySelectorAll('input[name="whyJoin"]');
  cbs.forEach(function(cb) { cb.checked = values.indexOf(cb.value) >= 0; });
}

// ===== DOCUMENT TABLE POPULATION =====
function addDocumentToTable() {
  var fileInput = document.getElementById('docUpload');
  var docType = document.getElementById('docType');
  if (!fileInput || !fileInput.files || fileInput.files.length === 0) {
    alert('Please select a file first');
    return;
  }
  var tbody = document.getElementById('documentsTableBody');
  var dtype = docType ? docType.value : 'Other';
  var today = new Date().toLocaleDateString('en-IN', { timeZone: 'Asia/Kolkata' });
  var uploadedBy = (currentUser && currentUser.name) ? currentUser.name : 'Admin';

  for (var i = 0; i < fileInput.files.length; i++) {
    var file = fileInput.files[i];
    var row = document.createElement('tr');
    row.innerHTML = '<td><i class="fas fa-file"></i> ' + escHtml(file.name) + '</td>' +
      '<td>' + escHtml(dtype) + '</td>' +
      '<td>' + today + '</td>' +
      '<td>' + escHtml(uploadedBy) + '</td>' +
      '<td>' +
        '<button class="btn-icon text-primary" title="View" onclick="viewDocumentFile(this)"><i class="fas fa-eye"></i></button> ' +
        '<button class="btn-icon text-danger" title="Remove" onclick="this.closest(\'tr\').remove()"><i class="fas fa-trash-alt"></i></button>' +
      '</td>';
    row._file = file;
    tbody.appendChild(row);
  }

  var selectedEl = document.getElementById('selectedFiles');
  if (selectedEl) selectedEl.innerHTML = '<span style="color:green;"><i class="fas fa-check"></i> ' + fileInput.files.length + ' file(s) added to documents</span>';
}

function viewDocumentFile(btn) {
  var row = btn.closest('tr');
  if (!row) return;
  // Newly uploaded file in this session — preview via object URL
  if (row._file) {
    var url = URL.createObjectURL(row._file);
    window.open(url, '_blank');
    return;
  }
  // Existing document loaded from the server (edit mode) — open via its URL
  if (row._fileUrl) {
    window.open(row._fileUrl, '_blank');
    return;
  }
  alert('File preview is not available for this document.');
}

// View-doc handler for the Review & Submit section — delegates to the source
// row in #documentsTableBody (which holds the File blob or file URL).
function _reviewViewDoc(idx) {
  var sourceRows = document.querySelectorAll('#documentsTableBody tr');
  var src = sourceRows[idx];
  if (!src) { alert('File preview not available.'); return; }
  if (src._file) {
    window.open(URL.createObjectURL(src._file), '_blank');
    return;
  }
  if (src._fileUrl) {
    window.open(src._fileUrl, '_blank');
    return;
  }
  alert('File preview is available after saving the record.');
}

