// ---- Centre Performance filter cascades ----
function loadPerfDistrictDropdown() {
  var distSel = document.getElementById('perfFilterDistrict');
  var centreSel = document.getElementById('perfFilterCentre');
  if (!distSel) return;
  // 2026-06-09 v3 — prime the state_name → state_code lookup so the
  // Apply button can scope the report by State without an extra
  // round-trip.  Idempotent — re-priming is a no-op once cached.
  if (typeof _ensurePerfStateCodeMap === 'function') _ensurePerfStateCodeMap();
  // Reset the State dropdown to "All States" on page open so the
  // visible filter never lies about the current scope.
  // 2026-06-30 — For PI / DL / SL pre-fill to the user's own state
  // (resolved earlier by _resolveDlPiScope) and then fire the cascade
  // so District + Centre populate without a manual click.  Admins
  // still see "All States".
  var stateSel = document.getElementById('perfFilterState');
  if (stateSel) {
    var _roleScoped = currentUser && (currentUser.role === 'pi' || currentUser.role === 'district_lead' || currentUser.role === 'state_lead');
    if (_roleScoped && currentUser.state_name) {
      stateSel.value = currentUser.state_name;
      setTimeout(function() {
        if (typeof onPerfFilterStateChange === 'function') onPerfFilterStateChange();
      }, 0);
    } else {
      stateSel.value = '';
    }
  }
  // Bump the seq so any in-flight legacy district-list response can no
  // longer overwrite the placeholder state we set below.
  _perfStateSeq = (typeof _perfStateSeq === 'number') ? (_perfStateSeq + 1) : 1;
  distSel.innerHTML = '<option value="">All Districts</option>';
  if (centreSel) centreSel.innerHTML = '<option value="">All Centres</option>';

  if (currentUser && (currentUser.role === 'district_lead' || currentUser.role === 'pi')) {
    _whenDlPiReady(function() {
      if (currentUser.district_code) {
        _autoSelectDlPiDropdowns(distSel, centreSel, currentUser);
      } else {
        _loadAllDistrictsAdmin(distSel);
      }
    });
    return;
  }

  // State Lead: load only their state's districts
  if (currentUser && currentUser.role === 'state_lead') {
    _resolveSlStateCodeThenLoad(distSel);
    return;
  }

  // Admin: District dropdown stays at the "All Districts" placeholder
  // only.  Per user spec — districts are loaded ONLY after the user
  // picks a State from the State filter (handled by
  // onPerfFilterStateChange).  No global list is fetched here.
}

function onPerfFilterDistrictChange() {
  var distCode = (document.getElementById('perfFilterDistrict') || {}).value;
  var centreSel = document.getElementById('perfFilterCentre');
  if (centreSel) centreSel.innerHTML = '<option value="">All Centres</option>';
  if (!distCode || typeof apiGeoDropdownCentres !== 'function') return;
  apiGeoDropdownCentres(distCode).then(function(result) {
    var centres = result.data || result || [];
    setDropdownOptions(
      centreSel, centres,
      function(c) { return c.centre_code; },
      function(c) { return c.centre_name; },
      { placeholder: '<option value="">All Centres</option>' }
    );
  }).catch(function() {});
}

/** 2026-06-09 v4 — Centre Performance State filter.
 *  Final behaviour per user spec:
 *    - Page open (State = "All States") → District dropdown shows ONLY
 *      the "All Districts" placeholder — no individual districts
 *      loaded.  No global list is fetched.
 *    - User picks a State (Delhi / Rajasthan / Tamil Nadu / West
 *      Bengal) → cascade: District dropdown is loaded with that
 *      state's districts.
 *    - User reverts to "All States" → District dropdown is cleared
 *      back to placeholder only.
 *  The cached state_name → state_code map (_perfStateCodeMap) drives
 *  both the cascade and the Apply-button report scope, so there's no
 *  per-click round-trip. */
var _perfStateCodeMap = {};   // { "delhi": "S07", "rajasthan": "S08", ... }
var _perfStateSeq = 0;

function onPerfFilterStateChange() {
  var stateName = (document.getElementById('perfFilterState') || {}).value || '';
  var distSel   = document.getElementById('perfFilterDistrict');
  var centreSel = document.getElementById('perfFilterCentre');
  var mySeq = ++_perfStateSeq;
  if (distSel)   distSel.innerHTML   = '<option value="">All Districts</option>';
  if (centreSel) centreSel.innerHTML = '<option value="">All Centres</option>';
  if (!stateName) {
    // "All States" → keep District at the placeholder only.  Per user
    // request: no global district list is loaded until a State is
    // picked.
    return;
  }
  // State picked → cascade to its districts.  Resolve via the cached
  // map first; if the map hasn't loaded yet, fetch /geo/dropdown/states
  // on demand and proceed.
  function _doCascade(stateCode) {
    if (!stateCode || typeof apiGeoDropdownDistricts !== 'function') return;
    apiGeoDropdownDistricts(stateCode).then(function(dResult) {
      if (mySeq !== _perfStateSeq) return;   // stale response — discard
      var districts = (dResult && (dResult.data || dResult)) || [];
      setDropdownOptions(
        distSel, districts,
        function(d) { return d.district_code; },
        function(d) { return d.district_name; },
        { placeholder: '<option value="">All Districts</option>' }
      );
    }).catch(function() {});
    // 2026-06-30 — Centre cascade by state.  Previously Centre only
    // populated when a District was picked, but the District filter
    // is hidden for PI / DL so they were stuck with an empty Centre
    // dropdown after selecting a State.  Hit /geo/dropdown/centres
    // with state_code so all of that state's centres land here.
    if (centreSel && typeof apiGet === 'function') {
      apiGet('/geo/dropdown/centres?state_code=' + encodeURIComponent(stateCode)).then(function(cResult) {
        if (mySeq !== _perfStateSeq) return;
        var centres = (cResult && (cResult.data || cResult)) || [];
        setDropdownOptions(
          centreSel, centres,
          function(c) { return c.centre_code; },
          function(c) { return c.centre_name; },
          { placeholder: '<option value="">All Centres</option>' }
        );
      }).catch(function() {});
    }
  }
  var cached = _perfStateCodeMap[stateName.toLowerCase()];
  if (cached) { _doCascade(cached); return; }
  // Lazy map fetch.
  if (typeof _ensurePerfStateCodeMap === 'function') {
    _ensurePerfStateCodeMap().then(function(map) {
      if (mySeq !== _perfStateSeq) return;
      _doCascade(map[stateName.toLowerCase()]);
    });
  }
}

/** Cache the live state_name → state_code map on first call so the
 *  Apply button can resolve the user's State pick without an extra
 *  HTTP round-trip.  Idempotent — re-calling is a no-op once cached. */
function _ensurePerfStateCodeMap() {
  if (Object.keys(_perfStateCodeMap).length > 0) return Promise.resolve(_perfStateCodeMap);
  if (typeof apiGeoDropdownStates !== 'function') return Promise.resolve({});
  return apiGeoDropdownStates().then(function(result) {
    var states = (result && (result.data || result)) || [];
    states.forEach(function(s) {
      if (s && s.state_name && s.state_code) {
        _perfStateCodeMap[s.state_name.toLowerCase()] = s.state_code;
      }
    });
    return _perfStateCodeMap;
  }).catch(function() { return {}; });
}

function resetPerfFilters() {
  // 2026-06-30 — re-apply PI/DL/SL lock after reset clears dropdowns
  setTimeout(function() { if (typeof _lockFlpFiltersForDlPi === 'function') _lockFlpFiltersForDlPi('perfFilterState', 'perfFilterDistrict', 'perfFilterCentre'); }, 50);
  var stateSel = document.getElementById('perfFilterState');
  var distSel = document.getElementById('perfFilterDistrict');
  var centreSel = document.getElementById('perfFilterCentre');
  var monthEl = document.getElementById('perfFilterMonth');
  var dateFromEl = document.getElementById('perfFilterDateFrom');
  var dateToEl   = document.getElementById('perfFilterDateTo');
  // 2026-06-09 v4 — Reset returns to the page-open scope: State =
  // "All States" + District placeholder only.  No global district list
  // is loaded — districts only appear after the user picks a State.
  if (stateSel) stateSel.value = '';
  if (centreSel) centreSel.innerHTML = '<option value="">All Centres</option>';
  _perfStateSeq++;
  if (distSel) distSel.innerHTML = '<option value="">All Districts</option>';
  // Reset returns the month to the previous calendar month rather than
  // blanking it — matches the page-open behavior so "Reset" never lands
  // the user in a state where Apply complains about an empty month.
  if (monthEl) monthEl.value = '';
  if (dateFromEl) dateFromEl.value = '';
  if (dateToEl) dateToEl.value = '';
  // Reset KPIs
  document.getElementById('perfKpiOverall').textContent = '0%';
  document.getElementById('perfKpiSurveys').textContent = '0';
  document.getElementById('perfKpiEnrolled').textContent = '0';
  document.getElementById('perfKpiOnTrack').textContent = '0/7';
  // Reset table
  var tbody = document.getElementById('perfTableBody');
  if (tbody) tbody.innerHTML = '<tr><td colspan="6" style="text-align:center; padding:30px; color:#999;">Loading…</td></tr>';
  // For PI/DL: re-populate centres from their district
  var isDlPi = currentUser && (currentUser.role === 'pi' || currentUser.role === 'district_lead');
  if (isDlPi && currentUser.district_code && centreSel) {
    apiGeoDropdownCentres(currentUser.district_code).then(function(result) {
      var centres = result.data || result || [];
      centres.forEach(function(c) {
        var opt = document.createElement('option');
        opt.value = c.centre_code;
        opt.textContent = c.centre_name;
        centreSel.appendChild(opt);
      });
    }).catch(function() {});
  }
  // 2026-06-17 v2: auto-reload after reset using the same walk-back
  // as page-init so reset lands on a month with real data.
  loadCentrePerformanceData(true);  /* 2026-06-17 v5: reset → all-months view */
}

// ---- New Assessment (Pre/Post) filter cascades ----
function onNewAssessmentStateChange() {
  var stateCode = (document.getElementById('newAssessmentState') || {}).value;
  var distSel = document.getElementById('newAssessmentDistrict');
  if (distSel) distSel.innerHTML = '<option value="">-- All Districts --</option>';
  if (stateCode && typeof apiGeoDropdownDistricts === 'function') {
    apiGeoDropdownDistricts(stateCode).then(function(result) {
      var districts = result.data || result || [];
      districts.forEach(function(d) {
        var opt = document.createElement('option');
        opt.value = d.district_code;
        opt.textContent = d.district_name;
        distSel.appendChild(opt);
      });
    }).catch(function() {});
  }
  // Also reload the FLP list immediately based on state selection
  filterAssessmentFLPs();
}

// Load target setting district dropdown using new geo schema
// For state_lead: auto-pick state from profile, load districts for that state
// For admin/super_admin: load all districts
function loadTargetCentreDropdown() {
  var distSel = document.getElementById('targetFilterDistrict');
  var centreSel = document.getElementById('targetFilterCentre');
  if (!distSel) return;
  distSel.innerHTML = '<option value="">Select District</option>';
  if (centreSel) centreSel.innerHTML = '<option value="">Select Centre</option>';

  // DL/PI: wait for scope resolution then auto-select
  if (currentUser && (currentUser.role === 'district_lead' || currentUser.role === 'pi')) {
    _whenDlPiReady(function() {
      if (currentUser.district_code) {
        _autoSelectDlPiDropdowns(distSel, centreSel, currentUser);
      } else {
        _loadAllDistrictsAdmin(distSel);
      }
    });
    return;
  }

  // State Lead: resolve state_code and load only their state's districts
  if (currentUser && currentUser.role === 'state_lead') {
    _resolveSlStateCodeThenLoad(distSel);
    return;
  }

  // Admin / Super Admin: load all districts
  _loadAllDistrictsAdmin(distSel);
}

function _resolveSlStateCodeThenLoad(distSel) {
  var sc = currentUser.state_code;
  if (sc) {
    _loadDistrictsForState(sc, distSel);
    return;
  }
  // Resolve from scope
  if (!currentUser.scope || typeof apiGeoDropdownStates !== 'function') return;
  apiGeoDropdownStates().then(function(result) {
    var states = result.data || result || [];
    var userScope = currentUser.scope.toLowerCase().replace(/ centre$/, '').trim();
    for (var i = 0; i < states.length; i++) {
      if ((states[i].state_name || '').toLowerCase().trim() === userScope ||
          (states[i].state_code || '').toLowerCase().trim() === userScope) {
        currentUser.state_code = states[i].state_code;
        localStorage.setItem('azadUserData', JSON.stringify(currentUser));
        _loadDistrictsForState(states[i].state_code, distSel);
        return;
      }
    }
  }).catch(function() {});
}

function _loadDistrictsForState(stateCode, selectEl) {
  if (!stateCode || typeof apiGeoDropdownDistricts !== 'function') return;
  apiGeoDropdownDistricts(stateCode).then(function(result) {
    var districts = result.data || result || [];
    // Atomic, deduped rewrite. Concurrent calls (one from initAllDropdowns
    // at startup, another from navigateTo) used to race here and produce
    // duplicate <option>s — setDropdownOptions guarantees idempotency.
    setDropdownOptions(
      selectEl, districts,
      function(d) { return d.district_code; },
      function(d) { return d.district_name; },
      { placeholder: '<option value="">All Districts</option>' }
    );
  }).catch(function() {});
}

// Fallback: load all districts for admin roles.
// Uses /geo/dropdown/districts (NOT the /geo/districts CRUD endpoint).
// The CRUD endpoint deliberately returns Inactive rows so the Master
// Data management screen can show & edit them; dropdowns must use the
// dropdown endpoint which applies the JWT-based active filter — web
// users see only Active, mobile FLPs see all.
function _loadAllDistrictsAdmin(distSel) {
  apiGet('/geo/dropdown/districts').then(function(result) {
    var districts = (result && (result.data || result)) || [];
    setDropdownOptions(
      distSel, districts,
      function(d) { return d.district_code; },
      function(d) { return d.district_name + (d.state_name ? ' (' + d.state_name + ')' : ''); },
      { placeholder: '<option value="">All Districts</option>' }
    );
  }).catch(function() {});
}

// Auto-select district and centre dropdowns for DL/PI based on their
// profile. Returns a Promise that resolves once BOTH the district and
// centre dropdowns are populated and auto-selected, so callers that
// need to read .value off the dropdowns afterwards (e.g. firing an
// initial Apply on FLP Performance / Centre Performance page-open)
// can await this. Existing callers that ignore the return value keep
// working unchanged.
function _autoSelectDlPiDropdowns(distSel, centreSel, user) {
  if (!user.state_code || !user.district_code) return Promise.resolve();
  return apiGeoDropdownDistricts(user.state_code).then(function(result) {
    var districts = result.data || result || [];
    setDropdownOptions(
      distSel, districts,
      function(d) { return d.district_code; },
      function(d) { return d.district_name; },
      {
        placeholder: '<option value="">All Districts</option>',
        selectedValue: user.district_code,
      }
    );
    // Now load centres for the selected district and auto-select.
    // Return the inner promise so the outer .then() awaits it before
    // resolving — without this, the chain resolved as soon as the
    // districts loaded and callers fired their data-fetch with an
    // unpopulated centre dropdown.
    if (centreSel && user.district_code) {
      return apiGeoDropdownCentres(user.district_code).then(function(cResult) {
        var centres = cResult.data || cResult || [];
        setDropdownOptions(
          centreSel, centres,
          function(c) { return c.centre_code; },
          function(c) { return c.centre_name; },
          {
            placeholder: '<option value="">All Centres</option>',
            selectedValue: user.centre_code,
          }
        );
      }).catch(function() {});
    }
  }).catch(function() {});
}

function onTargetFilterDistrictChange() {
  var distCode = (document.getElementById('targetFilterDistrict') || {}).value;
  var centreSel = document.getElementById('targetFilterCentre');
  if (centreSel) centreSel.innerHTML = '<option value="">Select Centre</option>';
  if (!distCode || typeof apiGeoDropdownCentres !== 'function') return;
  apiGeoDropdownCentres(distCode).then(function(result) {
    var centres = result.data || result || [];
    centres.forEach(function(c) {
      var opt = document.createElement('option');
      opt.value = c.centre_code;
      opt.textContent = c.centre_name;
      centreSel.appendChild(opt);
    });
  }).catch(function() {});
}

// Load geo area dropdown (cascaded from centre)
function loadGeoAreaDropdown(selectId, centreCode, defaultLabel) {
  var sel = document.getElementById(selectId);
  if (!sel) return;
  var lbl = defaultLabel || 'All Areas';
  sel.innerHTML = '<option value="">' + lbl + '</option>';
  if (!centreCode || typeof apiGeoDropdownAreas !== 'function') return;
  apiGeoDropdownAreas(centreCode).then(function(result) {
    var areas = result.data || result || [];
    areas.forEach(function(a) {
      var opt = document.createElement('option');
      opt.value = a.area_code;
      opt.textContent = a.area_name;
      sel.appendChild(opt);
    });
  }).catch(function() {});
}

// Initialize all dynamic dropdowns when page loads
function initAllDropdowns() {
  initFlpStateDropdown();
  // Dashboard state filter
  loadStateDropdown('dashFilterState', 'All States');
  // FLP form centre dropdown - now populated via cascade, not pre-loaded
  // loadCentreDropdown('flpCentre', 'Select Centre', false); // removed - cascade handles this
  // FLP list filter - State + Centre cascade
  loadStateDropdown('flpFilterState', 'All States');
  // Assessment list filter - State + Centre cascade
  loadStateDropdown('assessFilterState', 'All States');
  // Add Assessment - State + District cascade
  loadStateDropdown('newAssessmentState', '-- All States --');
  // Training filter — District dropdown (role-aware)
  _loadTrainingFilterDistricts();
  // Training form — District dropdown (role-aware: State Lead sees only their state)
  _loadTrainingFormDistricts();
  // Dashboard district filter is populated via cascade from state selection
  // (no pre-loading needed - updateDashDistrictOptions handles it)
  // User filter - State + District + Centre cascade
  loadStateDropdown('userFilterState', 'All States');
  // Target setting filter — state_lead sees only centres in their assigned state (new geo schema)
  loadTargetCentreDropdown();
  // Survey list filter - State + District cascade
  loadStateDropdown('surveyFilterState', 'All States');
  // Centre performance filter — State + Centre cascade using new geo schema
  loadPerfDistrictDropdown();
  // FLP performance filter (uses centre_id)
  loadFlpPerfDistrictDropdown();
  // Copy targets modals (uses centre_id)
  loadCentreDropdown('copySourceCentre', 'Select Centre', false);
  loadCentreDropdown('copyDestCentre', 'Select Centre', false);
  // Batch form centre (uses centre_id for API calls)
  loadStateDropdown('batchFormState', 'Select State');
  // WWW pipeline state filter
  loadStateDropdown('wwwFilterState', 'All');
  // District management state filter
  loadStateDropdown('districtFilterState', 'All States');
  // Area management state filter
  loadStateDropdown('areaFilterState', 'All States');
  // Centre management state filter
  loadStateDropdown('centreFilterState', 'All States');

  // Set default month to current month for all month pickers
  var now = new Date();
  var currentMonth = now.getFullYear() + '-' + String(now.getMonth() + 1).padStart(2, '0');
  ['targetFilterMonth', 'perfFilterMonth', 'flpPerfFilterMonth', 'reportFilterMonth'].forEach(function(id) {
    var el = document.getElementById(id);
    if (el && !el.value) el.value = currentMonth;
  });
}

var _dropdownsInitialized = false;
if (typeof window !== 'undefined') {
  window.addEventListener('DOMContentLoaded', function() {
    if (!_dropdownsInitialized) { _dropdownsInitialized = true; initAllDropdowns(); }
  });
  // Fallback in case DOMContentLoaded already fired
  setTimeout(function() {
    if (!_dropdownsInitialized) { _dropdownsInitialized = true; initAllDropdowns(); }
  }, 500);
}

// ===== PASSWORD GENERATOR =====
function generatePassword() {
  var chars = 'ABCDEFGHJKLMNPQRSTUVWXYZabcdefghijkmnopqrstuvwxyz23456789!@#$%';
  var pwd = '';
  for (var i = 0; i < 10; i++) pwd += chars.charAt(Math.floor(Math.random() * chars.length));
  document.getElementById('generatedPassword').value = pwd;
}

