// =============================================================================
// 9B. MASTER CRUD FUNCTIONS (State, District, City, Centre, Batch)
// =============================================================================

/** Return the correct DEMO array for a given master type */
function getMasterArray(type) {
  switch (type) {
    case 'state':    return DEMO_STATES;
    case 'district': return DEMO_DISTRICTS;
    case 'area':     return DEMO_CITIES;
    case 'centre':   return DEMO_CENTRES;
    case 'batch':    return DEMO_BATCHES;
    default:         return [];
  }
}

/** Friendly label for master type */
function getMasterLabel(type) {
  switch (type) {
    case 'state':    return 'State';
    case 'district': return 'District';
    case 'area':     return 'Area';
    case 'centre':   return 'Centre';
    case 'batch':    return 'Batch';
    default:         return type;
  }
}

/**
 * Open a master form modal for Add or Edit
 * @param {string} type - 'state','district','area','centre','batch'
 * @param {string} mode - 'add' or 'edit'
 * @param {number} idx  - index into DEMO array (only for edit)
 */
function openMasterForm(type, mode, idx) {
  masterModalMode = mode;
  editingMasterIdx = (mode === 'edit') ? idx : null;
  var label = getMasterLabel(type);
  var modalId = type + 'FormModal';
  var modal = document.getElementById(modalId);
  if (!modal) return;

  // Set title and submit button text
  var titleEl = document.getElementById(type + 'FormTitle');
  var submitEl = document.getElementById(type + 'FormSubmitText');
  if (titleEl) {
    titleEl.innerHTML = (mode === 'edit')
      ? '<i class="fas fa-edit"></i> Edit ' + label
      : '<i class="fas fa-plus-circle"></i> Add ' + label;
  }
  if (submitEl) {
    submitEl.textContent = (mode === 'edit') ? 'Update ' + label : 'Save ' + label;
  }

  // Clear / populate fields based on type
  if (type === 'state') {
    var nameEl = document.getElementById('stateFormName');
    var codeEl = document.getElementById('stateFormCode');
    var statusEl = document.getElementById('stateFormStatus');
    // Always clear first
    nameEl.value = '';
    if (codeEl) codeEl.value = '';
    statusEl.value = 'Active';
    if (mode === 'edit' && apiAvailable) {
      apiGet('/geo/states/' + encodeURIComponent(idx)).then(function(item) {
        nameEl.value = item.state_name || '';
        if (codeEl) codeEl.value = item.state_code || '';
        statusEl.value = item.status || 'Active';
      }).catch(function() {
        alert('Could not load state details for editing.');
      });
    } else if (mode === 'edit') {
      var item = DEMO_STATES[idx] || {};
      nameEl.value = item.name || '';
      if (codeEl) codeEl.value = item.short_code || '';
      statusEl.value = item.status || 'Active';
    }
  }

  if (type === 'district') {
    var nameEl = document.getElementById('districtFormName');
    var codeEl = document.getElementById('districtFormCode');
    var stateEl = document.getElementById('districtFormState');
    var statusEl = document.getElementById('districtFormStatus');
    // Always clear first
    nameEl.value = '';
    if (codeEl) codeEl.value = '';
    stateEl.value = '';
    statusEl.value = 'Active';
    // Load state dropdown options
    loadStateDropdown('districtFormState', 'Select State');
    if (mode === 'edit' && apiAvailable) {
      apiGet('/geo/districts/' + encodeURIComponent(idx)).then(function(item) {
        nameEl.value = item.district_name || '';
        if (codeEl) codeEl.value = item.district_code || '';
        // Set state after dropdown loads
        setTimeout(function() { stateEl.value = item.state_code || ''; }, 200);
        statusEl.value = item.status || 'Active';
      }).catch(function() {
        alert('Could not load district details for editing.');
      });
    } else if (mode === 'edit') {
      var item = DEMO_DISTRICTS[idx] || {};
      nameEl.value = item.name || '';
      if (codeEl) codeEl.value = '';
      statusEl.value = item.status || 'Active';
    }
  }

  if (type === 'area') {
    var codeEl = document.getElementById('areaFormCode');
    var nameEl = document.getElementById('areaFormName');
    var stateEl = document.getElementById('areaFormState');
    var distEl = document.getElementById('areaFormDistrict');
    var centreEl = document.getElementById('areaFormCentre');
    var statusEl = document.getElementById('areaFormStatus');
    // Always clear first
    if (codeEl) codeEl.value = '';
    nameEl.value = '';
    stateEl.value = '';
    distEl.innerHTML = '<option value="">Select District</option>';
    centreEl.innerHTML = '<option value="">Select Centre</option>';
    statusEl.value = 'Active';
    // Load state dropdown options
    loadStateDropdown('areaFormState', 'Select State');
    if (mode === 'edit' && apiAvailable) {
      apiGet('/geo/areas/' + encodeURIComponent(idx)).then(function(item) {
        if (codeEl) codeEl.value = item.area_code || '';
        nameEl.value = item.area_name || '';
        statusEl.value = item.status || 'Active';
        // Cascade: set state, then load districts, then set district, then load centres, then set centre
        setTimeout(function() {
          stateEl.value = item.state_code || '';
          loadGeoDistrictDropdown('areaFormDistrict', item.state_code, 'Select District');
          setTimeout(function() {
            distEl.value = item.district_code || '';
            loadGeoCentreDropdown('areaFormCentre', item.district_code, 'Select Centre');
            setTimeout(function() { centreEl.value = item.centre_code || ''; }, 300);
          }, 300);
        }, 200);
      }).catch(function() {
        alert('Could not load area details for editing.');
      });
    }
  }

  if (type === 'centre') {
    var codeEl = document.getElementById('centreFormCode');
    var nameEl = document.getElementById('centreFormName');
    var stateEl = document.getElementById('centreFormState');
    var distEl = document.getElementById('centreFormDistrict');
    var statusEl = document.getElementById('centreFormStatus');
    // Always clear first
    if (codeEl) codeEl.value = '';
    nameEl.value = '';
    stateEl.value = '';
    if (distEl) distEl.innerHTML = '<option value="">Select District</option>';
    statusEl.value = 'Active';
    // Load state dropdown options
    loadStateDropdown('centreFormState', 'Select State');
    if (mode === 'edit' && apiAvailable) {
      apiGet('/geo/centres/' + encodeURIComponent(idx)).then(function(item) {
        if (codeEl) codeEl.value = item.centre_code || '';
        nameEl.value = item.centre_name || '';
        statusEl.value = item.status || 'Active';
        // Cascade: set state, then load districts, then set district
        setTimeout(function() {
          stateEl.value = item.state_code || '';
          loadGeoDistrictDropdown('centreFormDistrict', item.state_code, 'Select District');
          setTimeout(function() {
            if (distEl) distEl.value = item.district_code || '';
          }, 300);
        }, 200);
      }).catch(function() {
        alert('Could not load centre details for editing.');
      });
    } else if (mode === 'edit') {
      var item = DEMO_CENTRES[idx];
      nameEl.value = item.name;
      statusEl.value = item.status || 'Active';
    }
  }

  if (type === 'batch') {
    var nameEl = document.getElementById('batchFormName');
    var yearEl = document.getElementById('batchFormYear');
    var stateEl = document.getElementById('batchFormState');
    var statusEl = document.getElementById('batchFormStatus');
    nameEl.value = '';
    yearEl.value = '';
    if (stateEl) stateEl.value = '';
    statusEl.value = 'Active';

    // State Lead: lock state dropdown to their own state and disable it
    var _isStateLead = currentUser && currentUser.role === 'state_lead';

    if (mode === 'edit' && apiAvailable) {
      var statePromise = apiGeoDropdownStates().then(function(states) {
        stateEl.innerHTML = '<option value="">Select State</option>';
        states.forEach(function(s) {
          // For state_lead: only include their own state so they cannot switch
          if (_isStateLead && currentUser.state_code && s.state_code !== currentUser.state_code) return;
          var opt = document.createElement('option');
          opt.value = s.state_code;
          opt.textContent = s.state_name;
          stateEl.appendChild(opt);
        });
      }).catch(function() {});
      var batchPromise = apiGet('/batches/' + idx);
      Promise.all([statePromise, batchPromise]).then(function(results) {
        var item = results[1];
        nameEl.value = item.name || '';
        yearEl.value = item.year || '';
        if (stateEl) {
          stateEl.value = item.state_code || '';
          if (_isStateLead) { stateEl.value = currentUser.state_code || stateEl.value; stateEl.disabled = true; }
        }
        statusEl.value = item.status || 'Active';
      }).catch(function() {
        alert('Could not load batch details for editing.');
      });
    } else if (_isStateLead && currentUser.state_code) {
      // Add mode — auto-select + disable state dropdown
      apiGeoDropdownStates().then(function(result) {
        var states = (result && result.data) || result || [];
        stateEl.innerHTML = '';
        states.forEach(function(s) {
          if (s.state_code !== currentUser.state_code) return;
          var opt = document.createElement('option');
          opt.value = s.state_code;
          opt.textContent = s.state_name;
          opt.selected = true;
          stateEl.appendChild(opt);
        });
        stateEl.value = currentUser.state_code;
        stateEl.disabled = true;
      }).catch(function() {});
    } else if (stateEl) {
      stateEl.disabled = false;
    }
  }

  modal.style.display = 'flex';
}

/** Close any master modal by ID */
function closeMasterModal(modalId) {
  var modal = document.getElementById(modalId);
  if (modal) modal.style.display = 'none';
}

// ----- SAVE FUNCTIONS PER MASTER TYPE -----

function saveMasterState() {
  var state_name = document.getElementById('stateFormName').value.trim();
  if (!state_name) { alert('Please enter a state name.'); return; }
  var state_code = (document.getElementById('stateFormCode') || {}).value || '';
  state_code = state_code.trim().toUpperCase();
  if (!state_code) { alert('Please enter a state code.'); return; }
  var status = document.getElementById('stateFormStatus').value;

  if (apiAvailable) {
    var payload = { state_code: state_code, state_name: state_name, status: status };
    if (masterModalMode === 'edit' && editingMasterIdx !== null) {
      apiGeoUpdateState(editingMasterIdx, payload).then(function() {
        alert('State updated successfully!');
        closeMasterModal('stateFormModal');
        loadStateManagementData(stateCurrentPage);
        refreshFlpFormDropdowns();
      }).catch(function(e) { showUserError('processing your request', e); });
    } else {
      apiGeoCreateState(payload).then(function() {
        alert('State added successfully!');
        closeMasterModal('stateFormModal');
        loadStateManagementData(1);
        refreshFlpFormDropdowns();
      }).catch(function(e) { showUserError('processing your request', e); });
    }
    return;
  }

  if (masterModalMode === 'edit' && editingMasterIdx !== null) {
    DEMO_STATES[editingMasterIdx].name = state_name;
    DEMO_STATES[editingMasterIdx].short_code = state_code;
    DEMO_STATES[editingMasterIdx].status = status;
    alert('State updated successfully!');
  } else {
    DEMO_STATES.push({ id: DEMO_STATES.length + 1, name: state_name, short_code: state_code, centres: 0, status: status });
    alert('State added successfully!');
  }
  closeMasterModal('stateFormModal');
  refreshMasterTable('state');
}

