function saveMasterBatch() {
  var name = document.getElementById('batchFormName').value.trim();
  var year = document.getElementById('batchFormYear').value.trim();
  var stateCode = (document.getElementById('batchFormState') || {}).value || '';
  // State Lead can only create/edit batches under their own state — override any tampered value
  if (currentUser && currentUser.role === 'state_lead' && currentUser.state_code) {
    stateCode = currentUser.state_code;
  }
  if (!name) { alert('Please enter a batch name.'); return; }
  if (!year) { alert('Please enter a year.'); return; }
  if (!stateCode) { alert('Please select a state.'); return; }
  var status = document.getElementById('batchFormStatus').value;

  if (apiAvailable) {
    var payload = { name: name, year: year, state_code: stateCode, status: status };
    if (masterModalMode === 'edit' && editingMasterIdx !== null) {
      apiUpdateBatch(editingMasterIdx, payload).then(function() {
        alert('Batch updated successfully!');
        closeMasterModal('batchFormModal');
        loadBatchManagementData(batchCurrentPage);
        refreshFlpFormDropdowns();
      }).catch(function(e) {
        var msg = (e && e.message) ? e.message : (typeof e === 'string' ? e : JSON.stringify(e));
        alert('Error: ' + msg);
      });
    } else {
      apiCreateBatch(payload).then(function() {
        alert('Batch added successfully!');
        closeMasterModal('batchFormModal');
        loadBatchManagementData(1);
        refreshFlpFormDropdowns();
      }).catch(function(e) {
        var msg = (e && e.message) ? e.message : (typeof e === 'string' ? e : JSON.stringify(e));
        alert('Error: ' + msg);
      });
    }
    return;
  }

  if (masterModalMode === 'edit' && editingMasterIdx !== null) {
    DEMO_BATCHES[editingMasterIdx].name = name;
    DEMO_BATCHES[editingMasterIdx].year = year;
    DEMO_BATCHES[editingMasterIdx].centre = centre;
    DEMO_BATCHES[editingMasterIdx].status = status;
    alert('Batch updated successfully!');
  } else {
    DEMO_BATCHES.push({ id: DEMO_BATCHES.length + 1, name: name, year: year, centre: centre, flpCount: 0, status: status });
    alert('Batch added successfully!');
  }
  closeMasterModal('batchFormModal');
  refreshMasterTable('batch');
}

// ----- REFRESH TABLE after Add/Edit -----

function refreshMasterTable(type) {
  var arr = getMasterArray(type);
  var tbodyId, buildRow;

  switch (type) {
    case 'state':
      tbodyId = 'stateManagementTableBody';
      buildRow = function(s, idx) {
        return '<tr>' +
          '<td>' + (idx + 1) + '</td>' +
          '<td>' + escHtml(s.name) + '</td>' +
          '<td>' + escHtml(s.short_code || '') + '</td>' +
          '<td>' + (s.centres || 0) + '</td>' +
          '<td>' + statusBadge(s.status || 'Active') + '</td>' +
          '<td>' +
            '<button class="btn-icon" title="View" onclick="viewMaster(\'state\',' + idx + ')"><i class="fas fa-eye"></i></button> ' +
            '<button class="btn-icon" title="Edit" onclick="openMasterForm(\'state\',\'edit\',' + idx + ')"><i class="fas fa-edit"></i></button>' +
          '</td></tr>';
      };
      break;
    case 'district':
      tbodyId = 'districtManagementTableBody';
      buildRow = function(d, idx) {
        return '<tr>' +
          '<td>' + (idx + 1) + '</td>' +
          '<td>' + escHtml(d.name) + '</td>' +
          '<td>' + escHtml(d.short_code || '') + '</td>' +
          '<td>' + escHtml(d.state) + '</td>' +
          '<td>' + (d.cities || 0) + '</td>' +
          '<td>' + statusBadge(d.status || 'Active') + '</td>' +
          '<td>' +
            '<button class="btn-icon" title="View" onclick="viewMaster(\'district\',' + idx + ')"><i class="fas fa-eye"></i></button> ' +
            '<button class="btn-icon" title="Edit" onclick="openMasterForm(\'district\',\'edit\',' + idx + ')"><i class="fas fa-edit"></i></button>' +
          '</td></tr>';
      };
      break;
    case 'area':
      tbodyId = 'areaManagementTableBody';
      buildRow = function(c, idx) {
        return '<tr>' +
          '<td>' + (idx + 1) + '</td>' +
          '<td>' + escHtml(c.name) + '</td>' +
          '<td>' + escHtml(c.short_code || '') + '</td>' +
          '<td>' + escHtml(c.centre || '') + '</td>' +
          '<td>' + escHtml(c.district) + '</td>' +
          '<td>' + escHtml(c.state) + '</td>' +
          '<td>' + statusBadge(c.status || 'Active') + '</td>' +
          '<td>' +
            '<button class="btn-icon" title="View" onclick="viewMaster(\'area\',' + idx + ')"><i class="fas fa-eye"></i></button> ' +
            '<button class="btn-icon" title="Edit" onclick="openMasterForm(\'area\',\'edit\',' + idx + ')"><i class="fas fa-edit"></i></button>' +
          '</td></tr>';
      };
      break;
    case 'centre':
      tbodyId = 'centreManagementTableBody';
      buildRow = function(c, idx) {
        return '<tr>' +
          '<td>' + (idx + 1) + '</td>' +
          '<td>' + escHtml(c.name) + '</td>' +
          '<td>' + escHtml(c.state) + '</td>' +
          '<td>' + (c.flpCount || 0) + '</td>' +
          '<td>' + statusBadge(c.status || 'Active') + '</td>' +
          '<td>' +
            '<button class="btn-icon" title="View" onclick="viewMaster(\'centre\',' + idx + ')"><i class="fas fa-eye"></i></button> ' +
            '<button class="btn-icon" title="Edit" onclick="openMasterForm(\'centre\',\'edit\',' + idx + ')"><i class="fas fa-edit"></i></button>' +
          '</td></tr>';
      };
      break;
    case 'batch':
      tbodyId = 'batchManagementTableBody';
      buildRow = function(b, idx) {
        return '<tr>' +
          '<td>' + (idx + 1) + '</td>' +
          '<td>' + escHtml(b.name) + '</td>' +
          '<td>' + escHtml(b.year) + '</td>' +
          '<td>' + escHtml(b.centre) + '</td>' +
          '<td>' + (b.flpCount || 0) + '</td>' +
          '<td>' + statusBadge(b.status || 'Active') + '</td>' +
          '<td>' +
            '<button class="btn-icon" title="View" onclick="viewMaster(\'batch\',' + idx + ')"><i class="fas fa-eye"></i></button> ' +
            '<button class="btn-icon" title="Edit" onclick="openMasterForm(\'batch\',\'edit\',' + idx + ')"><i class="fas fa-edit"></i></button>' +
          '</td></tr>';
      };
      break;
    default: return;
  }

  var tbody = document.getElementById(tbodyId);
  if (!tbody) return;
  var html = '';
  arr.forEach(function(item, idx) {
    html += buildRow(item, idx);
  });
  tbody.innerHTML = html;
}

// ----- VIEW MASTER -----

function viewMaster(type, idx) {
  viewMasterType = type;
  viewMasterIdx = idx;

  var titleEl = document.getElementById('masterViewTitle');
  var bodyEl = document.getElementById('masterViewBody');

  // For state, fetch from geo API by code
  if (type === 'state' && apiAvailable) {
    if (titleEl) titleEl.innerHTML = '<i class="fas fa-eye"></i> State Details';
    if (bodyEl) bodyEl.innerHTML = '<p style="text-align:center;color:#999;padding:20px;"><i class="fas fa-spinner fa-spin"></i> Loading...</p>';
    document.getElementById('masterViewModal').style.display = 'flex';

    apiGet('/geo/states/' + encodeURIComponent(idx)).then(function(item) {
      var html = '<table class="table" style="margin:0;">';
      html += '<tr><th style="width:140px;">State Name</th><td>' + escHtml(item.state_name) + '</td></tr>';
      html += '<tr><th>State Code</th><td>' + escHtml(item.state_code || '') + '</td></tr>';
      html += '<tr><th>Centres</th><td>' + (item.centre_count || 0) + '</td></tr>';
      html += '<tr><th>Status</th><td>' + statusBadge(item.status || 'Active') + '</td></tr>';
      html += '</table>';
      if (bodyEl) bodyEl.innerHTML = html;
    }).catch(function(e) {
      if (bodyEl) bodyEl.innerHTML = '<p style="color:red;padding:20px;">Error loading state details.</p>';
    });
    return;
  }

  // For district, fetch from geo API by code
  if (type === 'district' && apiAvailable) {
    if (titleEl) titleEl.innerHTML = '<i class="fas fa-eye"></i> District Details';
    if (bodyEl) bodyEl.innerHTML = '<p style="text-align:center;color:#999;padding:20px;"><i class="fas fa-spinner fa-spin"></i> Loading...</p>';
    document.getElementById('masterViewModal').style.display = 'flex';

    apiGet('/geo/districts/' + encodeURIComponent(idx)).then(function(item) {
      var html = '<table class="table" style="margin:0;">';
      html += '<tr><th style="width:140px;">District Name</th><td>' + escHtml(item.district_name) + '</td></tr>';
      html += '<tr><th>District Code</th><td>' + escHtml(item.district_code || '') + '</td></tr>';
      html += '<tr><th>State</th><td>' + escHtml(item.state_name || item.state_code || '') + '</td></tr>';
      html += '<tr><th>Centres</th><td>' + (item.centre_count || 0) + '</td></tr>';
      html += '<tr><th>Status</th><td>' + statusBadge(item.status || 'Active') + '</td></tr>';
      html += '</table>';
      if (bodyEl) bodyEl.innerHTML = html;
    }).catch(function(e) {
      if (bodyEl) bodyEl.innerHTML = '<p style="color:red;padding:20px;">Error loading district details.</p>';
    });
    return;
  }

  // For centre, fetch from geo API by code
  if (type === 'centre' && apiAvailable) {
    if (titleEl) titleEl.innerHTML = '<i class="fas fa-eye"></i> Centre Details';
    if (bodyEl) bodyEl.innerHTML = '<p style="text-align:center;color:#999;padding:20px;"><i class="fas fa-spinner fa-spin"></i> Loading...</p>';
    document.getElementById('masterViewModal').style.display = 'flex';

    apiGet('/geo/centres/' + encodeURIComponent(idx)).then(function(item) {
      var html = '<table class="table" style="margin:0;">';
      html += '<tr><th style="width:140px;">Centre Name</th><td>' + escHtml(item.centre_name) + '</td></tr>';
      html += '<tr><th>Centre Code</th><td>' + escHtml(item.centre_code || '') + '</td></tr>';
      html += '<tr><th>District</th><td>' + escHtml(item.district_name || item.district_code || '') + '</td></tr>';
      html += '<tr><th>State</th><td>' + escHtml(item.state_name || item.state_code || '') + '</td></tr>';
      html += '<tr><th>FLP Count</th><td>' + (item.flp_count || 0) + '</td></tr>';
      html += '<tr><th>Status</th><td>' + statusBadge(item.status || 'Active') + '</td></tr>';
      html += '</table>';
      if (bodyEl) bodyEl.innerHTML = html;
    }).catch(function(e) {
      if (bodyEl) bodyEl.innerHTML = '<p style="color:red;padding:20px;">Error loading centre details.</p>';
    });
    return;
  }

  // For area, fetch from geo API by code
  if (type === 'area' && apiAvailable) {
    if (titleEl) titleEl.innerHTML = '<i class="fas fa-eye"></i> Area Details';
    if (bodyEl) bodyEl.innerHTML = '<p style="text-align:center;color:#999;padding:20px;"><i class="fas fa-spinner fa-spin"></i> Loading...</p>';
    document.getElementById('masterViewModal').style.display = 'flex';

    apiGet('/geo/areas/' + encodeURIComponent(idx)).then(function(item) {
      var html = '<table class="table" style="margin:0;">';
      html += '<tr><th style="width:140px;">Area Name</th><td>' + escHtml(item.area_name) + '</td></tr>';
      html += '<tr><th>Area Code</th><td>' + escHtml(item.area_code || '') + '</td></tr>';
      html += '<tr><th>Centre</th><td>' + escHtml(item.centre_name || item.centre_code || '') + '</td></tr>';
      html += '<tr><th>District</th><td>' + escHtml(item.district_name || item.district_code || '') + '</td></tr>';
      html += '<tr><th>State</th><td>' + escHtml(item.state_name || item.state_code || '') + '</td></tr>';
      html += '<tr><th>Status</th><td>' + statusBadge(item.status || 'Active') + '</td></tr>';
      html += '</table>';
      if (bodyEl) bodyEl.innerHTML = html;
    }).catch(function(e) {
      if (bodyEl) bodyEl.innerHTML = '<p style="color:red;padding:20px;">Error loading area details.</p>';
    });
    return;
  }

  // For batch, fetch from API by ID instead of DEMO array
  if (type === 'batch' && apiAvailable) {
    if (titleEl) titleEl.innerHTML = '<i class="fas fa-eye"></i> Batch Details';
    if (bodyEl) bodyEl.innerHTML = '<p style="text-align:center;color:#999;padding:20px;"><i class="fas fa-spinner fa-spin"></i> Loading...</p>';
    document.getElementById('masterViewModal').style.display = 'flex';

    apiGet('/batches/' + idx).then(function(item) {
      var html = '<table class="table" style="margin:0;">';
      html += '<tr><th style="width:140px;">Batch Name</th><td>' + escHtml(item.name) + '</td></tr>';
      html += '<tr><th>Year</th><td>' + escHtml(item.year) + '</td></tr>';
      html += '<tr><th>State</th><td>' + escHtml(item.state_name || '') + '</td></tr>';
      html += '<tr><th>FLP Count</th><td>' + (item.flp_count || 0) + '</td></tr>';
      html += '<tr><th>Status</th><td>' + statusBadge(item.status || 'Active') + '</td></tr>';
      html += '</table>';
      if (bodyEl) bodyEl.innerHTML = html;
    }).catch(function(e) {
      if (bodyEl) bodyEl.innerHTML = '<p style="color:red;padding:20px;">Error loading batch details.</p>';
    });
    return;
  }

  var arr = getMasterArray(type);
  if (!arr || idx >= arr.length) return;
  var item = arr[idx];
  var label = getMasterLabel(type);

  if (titleEl) titleEl.innerHTML = '<i class="fas fa-eye"></i> ' + label + ' Details';
  if (!bodyEl) return;

  var html = '<table class="table" style="margin:0;">';

  switch (type) {
    case 'state':
      html += '<tr><th style="width:140px;">State Name</th><td>' + escHtml(item.name) + '</td></tr>';
      html += '<tr><th>State Code</th><td>' + escHtml(item.short_code || '') + '</td></tr>';
      html += '<tr><th>Centres</th><td>' + (item.centres || 0) + '</td></tr>';
      html += '<tr><th>Status</th><td>' + statusBadge(item.status || 'Active') + '</td></tr>';
      break;
    case 'district':
      html += '<tr><th style="width:140px;">District Name</th><td>' + escHtml(item.name) + '</td></tr>';
      html += '<tr><th>State</th><td>' + escHtml(item.state) + '</td></tr>';
      html += '<tr><th>Status</th><td>' + statusBadge(item.status || 'Active') + '</td></tr>';
      break;
    case 'area':
      html += '<tr><th style="width:140px;">Area Name</th><td>' + escHtml(item.name) + '</td></tr>';
      html += '<tr><th>District</th><td>' + escHtml(item.district) + '</td></tr>';
      html += '<tr><th>State</th><td>' + escHtml(item.state) + '</td></tr>';
      html += '<tr><th>Status</th><td>' + statusBadge(item.status || 'Active') + '</td></tr>';
      break;
    case 'centre':
      html += '<tr><th style="width:140px;">Centre Name</th><td>' + escHtml(item.name) + '</td></tr>';
      html += '<tr><th>State</th><td>' + escHtml(item.state) + '</td></tr>';
      html += '<tr><th>FLP Count</th><td>' + (item.flpCount || 0) + '</td></tr>';
      html += '<tr><th>Status</th><td>' + statusBadge(item.status || 'Active') + '</td></tr>';
      break;
    case 'batch':
      html += '<tr><th style="width:140px;">Batch Name</th><td>' + escHtml(item.name) + '</td></tr>';
      html += '<tr><th>Year</th><td>' + escHtml(item.year) + '</td></tr>';
      html += '<tr><th>Centre</th><td>' + escHtml(item.centre) + '</td></tr>';
      html += '<tr><th>FLP Count</th><td>' + (item.flpCount || 0) + '</td></tr>';
      html += '<tr><th>Status</th><td>' + statusBadge(item.status || 'Active') + '</td></tr>';
      break;
  }

  html += '</table>';
  bodyEl.innerHTML = html;

  document.getElementById('masterViewModal').style.display = 'flex';
}

/** Edit button inside View modal — close view, open edit form */
function editMasterFromView() {
  if (viewMasterType === null || viewMasterIdx === null) return;
  closeMasterModal('masterViewModal');
  openMasterForm(viewMasterType, 'edit', viewMasterIdx);
}


// =============================================================================
// 10. LEAFLET MAP
// =============================================================================

function initLeafletMap() {
  try {
  if (leafletMap) { leafletMap.remove(); leafletMap = null; }
  var mapEl = document.getElementById('leafletMap');
  if (!mapEl) return;

  leafletMap = L.map('leafletMap', {
    scrollWheelZoom: true,
    maxBounds: INDIA_BOUNDS,
    maxBoundsViscosity: 1.0,
    minZoom: 5,
    maxZoom: 12
  }).fitBounds(INDIA_BOUNDS);

  L.tileLayer('https://{s}.tile.openstreetmap.org/{z}/{x}/{y}.png', {
    attribution: '&copy; OpenStreetMap contributors',
    bounds: INDIA_BOUNDS
  }).addTo(leafletMap);

  // India state boundaries overlay
  loadIndiaBoundary();

  var states = [
    { name: 'Delhi', lat: 28.6139, lng: 77.2090, centres: 1, flps: 82, color: '#732269' },
    { name: 'Jaipur (Rajasthan)', lat: 26.9124, lng: 75.7873, centres: 1, flps: 45, color: '#9b3d8e' },
    { name: 'Kolkata (West Bengal)', lat: 22.5726, lng: 88.3639, centres: 1, flps: 65, color: '#732269' },
    { name: 'Chennai (Tamil Nadu)', lat: 13.0827, lng: 80.2707, centres: 1, flps: 32, color: '#9b3d8e' }
  ];

  states.forEach(function(s) {
    var radius = 15 + (s.flps / 82) * 25;
    var circle = L.circleMarker([s.lat, s.lng], {
      radius: radius,
      fillColor: s.color,
      color: '#5a1b52',
      weight: 2,
      opacity: 1,
      fillOpacity: 0.75
    }).addTo(leafletMap);

    var stateMatch = s.name.match(/\(([^)]+)\)/);
    var stateName = stateMatch ? stateMatch[1] : s.name;
    var popupContent =
      '<div style="font-family:Segoe UI,sans-serif;min-width:180px;">' +
      '<h4 style="margin:0 0 8px;color:#732269;">' + s.name + '</h4>' +
      '<p style="margin:4px 0;font-size:13px;"><strong>Centres:</strong> ' + s.centres + '</p>' +
      '<p style="margin:4px 0;font-size:13px;"><strong>FLPs:</strong> <a href="#" onclick="showDrillDownFlps(\'flp_by_state\',\'' + stateName + '\',\'FLPs in ' + stateName + '\');return false;" style="color:#732269;font-weight:600;">' + s.flps + '</a></p>' +
      '<a href="#" onclick="showDrillDownFlps(\'flp_by_state\',\'' + stateName + '\',\'FLPs in ' + stateName + '\');return false;" style="display:block;margin-top:8px;color:#732269;font-size:12px;">View FLP List &rarr;</a>' +
      '</div>';

    circle.bindPopup(popupContent);

    var label = L.divIcon({
      className: 'leaflet-map-label',
      html: '<div style="background:#732269;color:white;padding:2px 8px;border-radius:10px;font-size:11px;font-weight:700;white-space:nowrap;box-shadow:0 1px 4px rgba(0,0,0,0.3);">' + s.name.split(' (')[0] + ' (' + s.flps + ')</div>',
      iconSize: [0, 0],
      iconAnchor: [0, -radius - 5]
    });
    L.marker([s.lat, s.lng], { icon: label, interactive: false }).addTo(leafletMap);
  });

  // Force map size recalculation after render
  setTimeout(function() { if (leafletMap) leafletMap.invalidateSize(); }, 300);
  } catch(e) { console.warn('Map init error:', e); }
}

function loadIndiaBoundary() {
  // India state boundaries (includes J&K and Ladakh as per official Indian map)
  var geoUrl = 'https://raw.githubusercontent.com/adarshbiradar/maps-geojson/master/india.json';
  fetch(geoUrl)
    .then(function(r) {
      if (!r.ok) throw new Error('GeoJSON fetch failed');
      return r.json();
    })
    .then(function(geoData) {
      L.geoJSON(geoData, {
        style: {
          color: '#732269',
          weight: 1.5,
          fillColor: '#faf5f9',
          fillOpacity: 0.25
        },
        onEachFeature: function(feature, layer) {
          var stateName = feature.properties.st_nm || '';
          layer.bindTooltip(stateName, { sticky: true, className: 'map-state-tooltip' });
        }
      }).addTo(leafletMap);
    })
    .catch(function(err) {
      console.warn('India boundary load failed:', err);
    });
}


// =============================================================================
// 11. ASSESSMENT FLOW LOGIC
// =============================================================================

function toggleAssessmentType() {
  var type = document.getElementById('newAssessmentType').value;
  var preSection = document.getElementById('preAssessmentSection');
  var postSection = document.getElementById('postAssessmentSection');
  var btn = document.getElementById('btnProceedAssessment');

  // Hide State/District for PI/DL on Add Assessment page
  var isDlPi = currentUser && (currentUser.role === 'pi' || currentUser.role === 'district_lead');
  var isRestricted = currentUser && (currentUser.role === 'pi' || currentUser.role === 'district_lead' || currentUser.role === 'state_lead');
  var stateGroup = document.getElementById('newAssessmentStateGroup');
  var distGroup = document.getElementById('newAssessmentDistrictGroup');
  if (stateGroup) stateGroup.style.display = isRestricted ? 'none' : '';
  if (distGroup) distGroup.style.display = isDlPi ? 'none' : '';

  preSection.style.display = 'none';
  postSection.style.display = 'none';
  btn.disabled = true;

  if (type === 'pre') {
    preSection.style.display = 'block';
    loadPreAssessmentFLPs();
  } else if (type === 'post') {
    postSection.style.display = 'block';
    loadPostAssessmentFLPs();
  }
}

function loadPreAssessmentFLPs() {
  // PI/DL: hide both state and district (they're pre-scoped).
  // State Lead: hide state (single-state), but keep District visible + populated
  //             with districts of their assigned state.
  var stateGroup = document.getElementById('newAssessmentStateGroup');
  var distGroup = document.getElementById('newAssessmentDistrictGroup');
  var isDlPi = currentUser && (currentUser.role === 'pi' || currentUser.role === 'district_lead');
  var isStateLead = currentUser && currentUser.role === 'state_lead';
  var isRestricted = isDlPi || isStateLead;
  if (stateGroup) stateGroup.style.display = isRestricted ? 'none' : '';
  if (distGroup) distGroup.style.display = isDlPi ? 'none' : '';
  // For State Lead: eagerly populate districts from their state_code
  if (isStateLead) {
    var distSel = document.getElementById('newAssessmentDistrict');
    if (distSel && distSel.options.length <= 1) {
      distSel.innerHTML = '<option value="">-- All Districts --</option>';
      _resolveSlStateCodeThenLoad(distSel);
    }
  }

  var stateEl = document.getElementById('newAssessmentState');
  var distEl = document.getElementById('newAssessmentDistrict');
  var params = {};
  // Always scope by the user's own state for SL/DL/PI (not just DL/PI).
  if (isRestricted && currentUser.state_code) {
    params.state_code = currentUser.state_code;
    if (isDlPi && currentUser.district_code) params.district_code = currentUser.district_code;
  } else if (stateEl && stateEl.value) {
    params.state_code = stateEl.value;
  }
  if (!isDlPi && distEl && distEl.value) params.district_code = distEl.value;
  var tbody = document.getElementById('preFlpTableBody');
  var countEl = document.getElementById('preFlpCount');
  tbody.innerHTML = '<tr><td colspan="7" style="text-align:center;padding:20px;">Loading...</td></tr>';

  // Safety net: if SL/DL/PI and we don't yet have state_code (first paint),
  // resolve it from /geo/states by matching the user's scope string, then retry.
  if (isRestricted && !currentUser.state_code && currentUser.scope && typeof apiGeoDropdownStates === 'function') {
    apiGeoDropdownStates().then(function(result) {
      var list = (result && (result.data || result)) || [];
      var scope = String(currentUser.scope).split('(')[0].trim().toLowerCase();
      var match = list.find(function(s) { return (s.state_name || '').toLowerCase() === scope; });
      if (match) {
        currentUser.state_code = match.state_code;
        try { localStorage.setItem('azadUserData', JSON.stringify(currentUser)); } catch (e) {}
        loadPreAssessmentFLPs();
      }
    }).catch(function() {});
    return;
  }

  apiEmpanelledFlps(params).then(function(flps) {
    if (!flps || flps.length === 0) {
      tbody.innerHTML = '<tr><td colspan="7" style="text-align:center;padding:20px;color:var(--text-light);">No enrolled FLPs found</td></tr>';
      countEl.textContent = '';
      return;
    }
    var html = '';
    flps.forEach(function(f) {
      var dt = f.created_at ? new Date(f.created_at).toLocaleDateString('en-IN', {day:'numeric',month:'short',year:'numeric',timeZone:'Asia/Kolkata'}) : '—';
      html += '<tr>' +
        '<td><input type="radio" name="selectPreFlp" value="' + f.id + '" onchange="checkAssessmentSelection()"></td>' +
        '<td>' + (f.enrollment_number || '—') + '</td>' +
        '<td>' + (f.name || '') + '</td>' +
        '<td>' + ([f.district_name, f.state_name].filter(Boolean).join(', ') || '') + '</td>' +
        '<td>' + (f.batch_name || '—') + '</td>' +
        '<td>' + dt + '</td>' +
        '<td><span class="badge badge-active">Active</span></td>' +
        '</tr>';
    });
    tbody.innerHTML = html;
    countEl.textContent = 'Showing ' + flps.length + ' empanelled FLP(s)';
    checkAssessmentSelection();
  }).catch(function() {
    tbody.innerHTML = '<tr><td colspan="7" style="text-align:center;padding:20px;color:#e74c3c;">Failed to load FLPs</td></tr>';
  });
}

// Store FLP data from with-pre endpoint for post-assessment form population
window._postFlpDataMap = {};

function loadPostAssessmentFLPs() {
  var stateEl = document.getElementById('newAssessmentState');
  var distEl = document.getElementById('newAssessmentDistrict');
  var isDlPi = currentUser && (currentUser.role === 'pi' || currentUser.role === 'district_lead');
  var isStateLead = currentUser && currentUser.role === 'state_lead';
  // For State Lead: populate districts for their state if not already done
  if (isStateLead && distEl && distEl.options.length <= 1) {
    distEl.innerHTML = '<option value="">-- All Districts --</option>';
    _resolveSlStateCodeThenLoad(distEl);
  }
  var params = {};
  if (isDlPi && currentUser.state_code) {
    params.state_code = currentUser.state_code;
    if (currentUser.district_code) params.district_code = currentUser.district_code;
  } else if (isStateLead && currentUser.state_code) {
    params.state_code = currentUser.state_code;
  } else if (stateEl && stateEl.value) {
    params.state_code = stateEl.value;
  }
  if (!isDlPi && distEl && distEl.value) params.district_code = distEl.value;
  var tbody = document.getElementById('postFlpTableBody');
  var countEl = document.getElementById('postFlpCount');
  tbody.innerHTML = '<tr><td colspan="7" style="text-align:center;padding:20px;">Loading...</td></tr>';
  window._postFlpDataMap = {};

  var isRestrictedPost = isDlPi || isStateLead;
  if (isRestrictedPost && !currentUser.state_code && currentUser.scope && typeof apiGeoDropdownStates === 'function') {
    apiGeoDropdownStates().then(function(result) {
      var list = (result && (result.data || result)) || [];
      var scope = String(currentUser.scope).split('(')[0].trim().toLowerCase();
      var match = list.find(function(s) { return (s.state_name || '').toLowerCase() === scope; });
      if (match) {
        currentUser.state_code = match.state_code;
        try { localStorage.setItem('azadUserData', JSON.stringify(currentUser)); } catch (e) {}
        loadPostAssessmentFLPs();
      }
    }).catch(function() {});
    return;
  }

  apiFlpsWithPre(params).then(function(flps) {
    if (!flps || flps.length === 0) {
      tbody.innerHTML = '<tr><td colspan="7" style="text-align:center;padding:20px;color:var(--text-light);">No FLPs with completed Baseline found</td></tr>';
      countEl.textContent = '';
      return;
    }
    var html = '';
    flps.forEach(function(f) {
      // Cache full FLP data for post-assessment form population
      window._postFlpDataMap[f.id] = f;
      var preDt = f.pre_assessment_date ? new Date(f.pre_assessment_date).toLocaleDateString('en-IN', {day:'numeric',month:'short',year:'numeric',timeZone:'Asia/Kolkata'}) : '—';
      var score = f.pre_score != null ? '<span class="badge badge-walkout">' + f.pre_score + '%</span>' : '—';
      html += '<tr>' +
        '<td><input type="radio" name="selectPostFlp" value="' + f.id + '" onchange="checkAssessmentSelection()"></td>' +
        '<td>' + (f.enrollment_number || '—') + '</td>' +
        '<td>' + (f.name || '') + '</td>' +
        '<td>' + ([f.district_name, f.state_name].filter(Boolean).join(', ') || '') + '</td>' +
        '<td>' + preDt + '</td>' +
        '<td>' + score + '</td>' +
        '<td>—</td>' +
        '</tr>';
    });
    tbody.innerHTML = html;
    countEl.textContent = 'Showing ' + flps.length + ' FLP(s) with completed Baseline';
    checkAssessmentSelection();
  }).catch(function() {
    tbody.innerHTML = '<tr><td colspan="7" style="text-align:center;padding:20px;color:#e74c3c;">Failed to load FLPs</td></tr>';
  });
}

function searchPreFLPs() {
  var query = document.getElementById('preFlpSearch').value.trim().toLowerCase();
  var rows = document.querySelectorAll('#preFlpTableBody tr');
  rows.forEach(function(row) {
    if (!row.cells || row.cells.length < 3) return;
    var name = row.cells[2].textContent.toLowerCase();
    row.style.display = (!query || name.indexOf(query) >= 0) ? '' : 'none';
  });
  checkAssessmentSelection();
}

function searchPostFLPs() {
  var query = document.getElementById('postFlpSearch').value.trim().toLowerCase();
  var rows = document.querySelectorAll('#postFlpTableBody tr');
  rows.forEach(function(row) {
    if (!row.cells || row.cells.length < 3) return;
    var name = row.cells[2].textContent.toLowerCase();
    row.style.display = (!query || name.indexOf(query) >= 0) ? '' : 'none';
  });
  checkAssessmentSelection();
}

function filterAssessmentFLPs() {
  var type = document.getElementById('newAssessmentType').value;
  if (type === 'pre') loadPreAssessmentFLPs();
  if (type === 'post') loadPostAssessmentFLPs();
}

function checkAssessmentSelection() {
  var btn = document.getElementById('btnProceedAssessment');
  var type = document.getElementById('newAssessmentType').value;
  var selected = false;
  if (type === 'pre') {
    selected = document.querySelector('input[name="selectPreFlp"]:checked') !== null;
  } else if (type === 'post') {
    selected = document.querySelector('input[name="selectPostFlp"]:checked') !== null;
  }
  btn.disabled = !selected;
}

// Listen for radio selection changes to enable the Proceed button
document.addEventListener('change', function(e) {
  if (e.target.name === 'selectPreFlp' || e.target.name === 'selectPostFlp') {
    checkAssessmentSelection();
  }
});

function proceedToAssessment() {
  var type = document.getElementById('newAssessmentType').value;
  if (type === 'pre') {
    var selected = document.querySelector('input[name="selectPreFlp"]:checked');
    if (!selected) { alert('Please select an FLP first.'); return; }
    var row = selected.closest('tr');
    var flpData = {
      id: selected.value,
      enrollment_number: row.cells[1].textContent,
      name: row.cells[2].textContent,
      location: row.cells[3].textContent
    };
    resetPreAssessmentForm(flpData);
    navigateTo('assessmentForm');
  } else if (type === 'post') {
    var selected = document.querySelector('input[name="selectPostFlp"]:checked');
    if (!selected) { alert('Please select an FLP first.'); return; }
    var flpId = parseInt(selected.value);
    var flpData = window._postFlpDataMap[flpId];
    if (!flpData) { alert('FLP data not found. Please reload and try again.'); return; }
    populatePostAssessmentForm(flpData);
    navigateTo('assessmentFormPost');
  } else {
    alert('Please select assessment type.');
  }
}

// ---- Start Endline from Assessment List ----
function startPostAssessmentFromList(flpId, preId) {
  if (!flpId) { alert('FLP data not available.'); return; }
  // Fetch FLP data from with-pre endpoint (which includes pre-assessment details)
  apiFlpsWithPre({}).then(function(flps) {
    var flpData = flps.find(function(f) { return f.id === flpId; });
    if (!flpData) {
      // Fallback: fetch FLP detail directly
      apiFlpDetail(flpId).then(function(flp) {
        var data = {
          id: flp.id, name: flp.name, enrollment_number: flp.enrollment_number,
          location: [flp.district_name, flp.state_name].filter(Boolean).join(', '),
          date_of_birth: flp.date_of_birth,
          sec_a_name: flp.name, sec_a_mobile: flp.mobile, sec_a_address: flp.address,
          sec_a_age: flp.age_at_enrollment, sec_a_caste: flp.caste_category,
          sec_a_community: flp.community_religion, sec_a_education: flp.education,
          sec_a_income: flp.monthly_family_income, sec_a_family_members: flp.family_members_count,
          pre_assessment_id: preId
        };
        window._postFlpDataMap = window._postFlpDataMap || {};
        window._postFlpDataMap[flpId] = data;
        window.selectedPostFlpId = flpId;
        window.selectedPostPreId = preId;
        // Persist for F5 rehydrate — the Add Endline form (entered via the +
        // icon on the assessment list) blanks on refresh because the in-memory
        // selectedPostFlpId / selectedPostPreId reset. Mirror them to
        // sessionStorage; clear postAssessEditId so navigateTo's rehydrate
        // doesn't mistake this for an edit-resume.
        _ctxClear('postAssessEditId');
        _ctxSet('postAssessFlpId', flpId);
        _ctxSet('postAssessPreId', preId);
        populatePostAssessmentForm(data);
        navigateTo('assessmentFormPost');
      });
      return;
    }
    flpData.location = [flpData.district_name, flpData.state_name].filter(Boolean).join(', ');
    window._postFlpDataMap = window._postFlpDataMap || {};
    window._postFlpDataMap[flpId] = flpData;
    window.selectedPostFlpId = flpId;
    window.selectedPostPreId = flpData.pre_assessment_id || preId;
    // Persist for F5 rehydrate (see note above).
    _ctxClear('postAssessEditId');
    _ctxSet('postAssessFlpId', flpId);
    _ctxSet('postAssessPreId', window.selectedPostPreId);
    populatePostAssessmentForm(flpData);
    navigateTo('assessmentFormPost');
  }).catch(function() {
    alert('Failed to load FLP data. Please try again.');
  });
}

// ---- Edit Baseline from Assessment List ----
function editPreAssessmentFromList(preId, flpId) {
  if (!preId) { alert('Assessment ID not available.'); return; }
  // Fetch both assessment data AND FLP detail in parallel
  Promise.all([
    apiAssessmentDetail(preId),
    apiFlpDetail(flpId || 0).catch(function() { return null; })
  ]).then(function(results) {
    var assessment = results[0];
    var flpDetail = results[1];
    // Set FLP info in banner — use FLP detail for enrollment/location, assessment for name
    var flpData = {
      id: assessment.flp_id || flpId,
      name: assessment.sec_a_name || (flpDetail && flpDetail.name) || '',
      enrollment_number: (flpDetail && flpDetail.enrollment_number) || '',
      location: flpDetail ? [flpDetail.district_name, flpDetail.state_name].filter(Boolean).join(', ') : ''
    };
    window.selectedPreFlpId = flpData.id;
    window._editingPreAssessmentId = preId;
    // Persist edit context so refresh (F5) can resume editing this assessment
    _ctxSet('preAssessEditId', preId);
    _ctxSet('preAssessFlpId', flpData.id);

    // Set banner
    var nameEl = document.getElementById('preAssessFlpName');
    var enrEl = document.getElementById('preAssessEnrollment');
    var locEl = document.getElementById('preAssessLocation');
    var dateEl = document.getElementById('preAssessDate');
    if (nameEl) nameEl.textContent = flpData.name || '—';
    if (enrEl) enrEl.textContent = flpData.enrollment_number || '—';
    if (locEl) locEl.textContent = flpData.location || '—';
    if (dateEl) dateEl.textContent = assessment.assessment_date ? formatDateNice(assessment.assessment_date) : '—';

    // Populate Section A (demographics)
    var setVal = function(id, val) { var el = document.getElementById(id); if (el) el.value = val || ''; };
    setVal('preQ1', assessment.sec_a_name);
    setVal('preQ2', assessment.sec_a_mobile);
    setVal('preQ3', assessment.sec_a_address);
    setVal('preQ4', assessment.sec_a_age);
    setVal('preQ5', assessment.sec_a_caste);
    setVal('preQ6', assessment.sec_a_community);
    setVal('preQ7', assessment.sec_a_education);
    setVal('preQ8', assessment.sec_a_income);
    setVal('preQ9', assessment.sec_a_family_members);

    // Navigate first, then populate after DOM is ready
    navigateTo('assessmentForm');

    // Store assessment data and populate after a tick to ensure DOM is ready
    window._pendingAssessmentData = assessment;
    setTimeout(function() {
      var aData = window._pendingAssessmentData;
      if (!aData) return;
      window._pendingAssessmentData = null;

      var form = document.getElementById('page-assessmentForm');
      if (!form) { console.error('Assessment form not found'); return; }

      // Clear all inputs first
      form.querySelectorAll('input[type="radio"], input[type="checkbox"]').forEach(function(cb) { cb.checked = false; });
      form.querySelectorAll('.assessment-question input[type="text"]').forEach(function(inp) { inp.value = ''; });

      // Set radio values for Q10-Q14, Q16-Q21, Q23, Q27-Q29
      var radioFields = ['q10','q11','q12','q13','q14','q16','q17','q18','q19','q20','q21','q23','q27','q28','q29'];
      radioFields.forEach(function(name) {
        var val = aData[name];
        if (val !== null && val !== undefined) {
          var radio = form.querySelector('input[name="' + name + '"][value="' + val + '"]');
          if (radio) {
            radio.checked = true;
          }
        }
      });

      // Set checkbox values for Q15, Q22, Q24, Q30
      ['q15','q22','q24','q30'].forEach(function(name) {
        var val = aData[name];
        if (val && Array.isArray(val) && val.length > 0) {
          val.forEach(function(v) {
            var cb = form.querySelector('input[name="' + name + '"][value="' + v + '"]');
            if (cb) cb.checked = true;
          });
        }
      });

      // Q25 boolean
      if (aData.q25_self_made === true) {
        var r = form.querySelector('input[name="q25"][value="Yes"]'); if (r) r.checked = true;
      } else if (aData.q25_self_made === false) {
        var r = form.querySelector('input[name="q25"][value="No"]'); if (r) r.checked = true;
      }
      // Q26 boolean
      if (aData.q26_assisted_others === true) {
        var r = form.querySelector('input[name="q26"][value="Yes"]'); if (r) r.checked = true;
      } else if (aData.q26_assisted_others === false) {
        var r = form.querySelector('input[name="q26"][value="No"]'); if (r) r.checked = true;
      }

      // Text inputs
      if (aData.q25_which_document) {
        var q25docInp = form.querySelector('#preQ25doc');
        if (q25docInp) q25docInp.value = aData.q25_which_document;
      }
      if (aData.q26_scheme_name) {
        var q26schemeInp = form.querySelector('#preQ26scheme');
        if (q26schemeInp) q26schemeInp.value = aData.q26_scheme_name;
      }
    }, 100);
  }).catch(function(err) {
    alert('Failed to load assessment data: ' + (err.message || 'Unknown error'));
  });
}

// ---- Edit Endline Draft from Assessment List ----
function editPostAssessmentFromList(postId, flpId, preId) {
  if (!postId) { alert('Assessment ID not available.'); return; }
  Promise.all([
    apiAssessmentDetail(postId),
    apiFlpDetail(flpId || 0).catch(function() { return null; })
  ]).then(function(results) {
    var assessment = results[0];
    var flpDetail = results[1];

    window.selectedPostFlpId = flpId;
    window.selectedPostPreId = preId;
    window._editingPostAssessmentId = postId;  // For update-on-save
    // Persist edit context so refresh (F5) can resume editing this assessment
    _ctxSet('postAssessEditId', postId);
    _ctxSet('postAssessFlpId', flpId);
    _ctxSet('postAssessPreId', preId);

    // Set banner
    var el = function(id) { return document.getElementById(id); };
    if (el('postAssessFlpName')) el('postAssessFlpName').textContent = assessment.sec_a_name || (flpDetail && flpDetail.name) || '';
    if (el('postAssessEnrollment')) el('postAssessEnrollment').textContent = (flpDetail && flpDetail.enrollment_number) || '';
    if (el('postAssessLocation')) el('postAssessLocation').textContent = flpDetail ? [flpDetail.district_name, flpDetail.state_name].filter(Boolean).join(', ') : '';
    if (el('postAssessDate')) el('postAssessDate').textContent = assessment.assessment_date ? formatDateNice(assessment.assessment_date) : '';

    // Populate Section A
    var setVal = function(id, val) { var e = document.getElementById(id); if (e) e.value = val || ''; };
    setVal('postQ1', assessment.sec_a_name);
    setVal('postQ2', assessment.sec_a_mobile);
    setVal('postQ3', assessment.sec_a_address);
    setVal('postQ4', assessment.sec_a_age);
    setVal('postQ5', assessment.sec_a_caste);
    setVal('postQ6', assessment.sec_a_community);
    setVal('postQ7', assessment.sec_a_education);
    setVal('postQ8', assessment.sec_a_income);
    setVal('postQ9', assessment.sec_a_family_members);

    // Clear all radio/checkbox in post form
    var form = document.getElementById('page-assessmentFormPost');
    form.querySelectorAll('input[type="radio"], input[type="checkbox"]').forEach(function(cb) { cb.checked = false; });
    form.querySelectorAll('.assessment-question input[type="text"]').forEach(function(inp) { inp.value = ''; });

    // Populate saved radio values (pq* prefix for post form)
    var radioMap = {
      'pq10': 'q10', 'pq11': 'q11', 'pq12': 'q12', 'pq13': 'q13', 'pq14': 'q14',
      'pq16': 'q16', 'pq17': 'q17', 'pq18': 'q18', 'pq19': 'q19', 'pq20': 'q20', 'pq21': 'q21',
      'pq23': 'q23', 'pq27': 'q27', 'pq28': 'q28', 'pq29': 'q29'
    };
    Object.keys(radioMap).forEach(function(formName) {
      var dbField = radioMap[formName];
      var val = assessment[dbField];
      if (val !== null && val !== undefined) {
        var radio = form.querySelector('input[name="' + formName + '"][value="' + val + '"]');
        if (radio) radio.checked = true;
      }
    });

    // Checkbox fields
    var checkMap = {'pq15': 'q15', 'pq22': 'q22', 'pq24': 'q24', 'pq30': 'q30'};
    Object.keys(checkMap).forEach(function(formName) {
      var val = assessment[checkMap[formName]];
      if (val && Array.isArray(val) && val.length > 0) {
        val.forEach(function(v) {
          var cb = form.querySelector('input[name="' + formName + '"][value="' + v + '"]');
          if (cb) cb.checked = true;
        });
      }
    });

    // Boolean fields Q25/Q26
    if (assessment.q25_self_made === true) {
      var r = form.querySelector('input[name="pq25"][value="Yes"]'); if (r) r.checked = true;
    } else if (assessment.q25_self_made === false) {
      var r = form.querySelector('input[name="pq25"][value="No"]'); if (r) r.checked = true;
    }
    if (assessment.q26_assisted_others === true) {
      var r = form.querySelector('input[name="pq26"][value="Yes"]'); if (r) r.checked = true;
    } else if (assessment.q26_assisted_others === false) {
      var r = form.querySelector('input[name="pq26"][value="No"]'); if (r) r.checked = true;
    }

    navigateTo('assessmentFormPost');
  }).catch(function(err) {
    alert('Failed to load draft: ' + (err.message || 'Unknown error'));
  });
}

