function resetPreAssessmentForm(flpData) {
  // Clear editing ID for new assessments
  window._editingPreAssessmentId = null;
  window._editingPostAssessmentId = null;
  _ctxClear('preAssessEditId'); _ctxClear('preAssessFlpId');
  _ctxClear('postAssessEditId'); _ctxClear('postAssessFlpId'); _ctxClear('postAssessPreId');
  // Set banner info
  document.getElementById('preAssessFlpName').textContent = flpData.name || '—';
  document.getElementById('preAssessEnrollment').textContent = flpData.enrollment_number || '—';
  document.getElementById('preAssessLocation').textContent = flpData.location || '—';
  document.getElementById('preAssessDate').textContent = new Date().toLocaleDateString('en-IN', {day:'numeric',month:'short',year:'numeric',timeZone:'Asia/Kolkata'});

  // Clear all inputs in Section B-D
  var form = document.getElementById('page-assessmentForm');

  // Uncheck all radio buttons and checkboxes
  var checks = form.querySelectorAll('input[type="radio"], input[type="checkbox"]');
  checks.forEach(function(cb) { cb.checked = false; });

  // Clear text inputs in Section C (Q25.1, Q26.1)
  form.querySelectorAll('.assessment-question input[type="text"]').forEach(function(inp) { inp.value = ''; });

  // Store selected FLP id for submission
  window.selectedPreFlpId = flpData.id;

  // Fetch full FLP details and populate read-only Section A
  apiFlpDetail(flpData.id).then(function(flp) {
    document.getElementById('preQ1').value = flp.name || '';
    document.getElementById('preQ2').value = flp.mobile || '';
    document.getElementById('preQ3').value = flp.address || '';
    document.getElementById('preQ4').value = flp.age_at_enrollment || calculateAgeFromDob(flp.date_of_birth) || '';
    document.getElementById('preQ5').value = flp.caste_category || '';
    document.getElementById('preQ6').value = flp.community_religion || '';
    document.getElementById('preQ7').value = flp.education || '';
    document.getElementById('preQ8').value = flp.monthly_family_income || '';
    document.getElementById('preQ9').value = flp.family_members_count || '';
  });
}


// ---- SUBMIT PRE-ASSESSMENT ----
// ============================================================================
// REVIEW & SUBMIT MODAL FOR ASSESSMENTS
// ============================================================================
// Builds a read-only summary of every answered question in the live form
// (Baseline → page-assessmentForm, Endline → page-assessmentFormPost) and
// presents it in a modal with two actions:
//
//   - **Edit Answers** closes the modal and returns to the form so the
//     user can change any response.
//   - **Confirm & Submit** runs the caller's `onConfirm` callback, which
//     sets the per-flow `_preReviewConfirmed` / `_postReviewConfirmed`
//     flag and re-invokes the submitter — this time the function falls
//     through the review gate and POSTs the assessment.
//
// We render directly off the DOM (selected radios, checkboxes, text
// inputs) rather than re-fetching anything, so what the user sees in
// the review is byte-for-byte what they're about to submit.
function _showAssessmentReviewModal(formPageId, label, onConfirm) {
  var form = document.getElementById(formPageId);
  if (!form) { onConfirm(); return; }

  // Pull every labelled question. The assessment forms use
  // `.assessment-question` blocks each containing a question label, then
  // radios / checkboxes / inputs underneath. We walk the DOM in order
  // so the review preserves the user's question sequence.
  var blocks = form.querySelectorAll('.assessment-question, .question-block');
  // Fallback: if the form doesn't use those class names, walk every
  // group that has a name-prefixed input. Defensive for layout changes.
  var rows = [];
  if (!blocks.length) {
    var inputsAll = form.querySelectorAll('input[name], textarea[name], select[name]');
    var seenNames = {};
    inputsAll.forEach(function(inp) {
      if (seenNames[inp.name]) return;
      seenNames[inp.name] = true;
      var v = '';
      if (inp.type === 'radio') {
        var r = form.querySelector('input[name="' + inp.name + '"]:checked');
        v = r ? (r.dataset.label || r.value) : '';
      } else if (inp.type === 'checkbox') {
        var cs = form.querySelectorAll('input[name="' + inp.name + '"]:checked');
        var arr = []; cs.forEach(function(c) { arr.push(c.dataset.label || c.value); });
        v = arr.join(', ');
      } else {
        v = inp.value || '';
      }
      var heading = '';
      var grp = inp.closest('.form-group, .question-block, .assessment-question');
      if (grp) {
        var lab = grp.querySelector('label, .question-text, h4');
        if (lab) heading = lab.textContent.trim();
      }
      rows.push({ q: heading || inp.name, a: v });
    });
  } else {
    blocks.forEach(function(blk) {
      var lab = blk.querySelector('.question-text, h4, label');
      var heading = lab ? lab.textContent.trim() : '';
      // Pick up the answer
      var ans = '';
      var checked = blk.querySelectorAll('input[type="radio"]:checked, input[type="checkbox"]:checked');
      if (checked.length) {
        var arr = [];
        checked.forEach(function(c) {
          var ll = c.parentElement && c.parentElement.tagName === 'LABEL' ? c.parentElement.textContent.trim() : (c.dataset.label || c.value);
          arr.push(ll);
        });
        ans = arr.join(', ');
      } else {
        var txt = blk.querySelector('input[type="text"], input[type="number"], textarea, select');
        if (txt && txt.value) ans = txt.value;
      }
      rows.push({ q: heading, a: ans });
    });
  }

  // Strip rows that have no answer at all so the review isn't padded
  // with blanks (the validation pass above already required all
  // mandatory questions, so anything blank here is genuinely optional).
  rows = rows.filter(function(r) { return r.a && String(r.a).trim().length > 0; });

  // Build modal markup. Re-uses the app's existing modal styling via
  // the `.modal` and `.modal-content` classes.
  var existing = document.getElementById('assessmentReviewModal');
  if (existing) existing.remove();

  var rowsHtml = rows.map(function(r) {
    return '<tr><td style="padding:8px 10px;border:1px solid #e5d4e2;background:#faf3f8;font-weight:600;color:#732269;width:55%;">' +
           escHtml(r.q || '—') +
           '</td><td style="padding:8px 10px;border:1px solid #e5d4e2;">' +
           escHtml(r.a) +
           '</td></tr>';
  }).join('');
  if (!rowsHtml) {
    rowsHtml = '<tr><td colspan="2" style="padding:14px;text-align:center;color:#999;">No answers entered yet.</td></tr>';
  }

  var modal = document.createElement('div');
  modal.id = 'assessmentReviewModal';
  modal.className = 'modal';
  modal.style.cssText = 'display:flex;position:fixed;inset:0;background:rgba(0,0,0,.55);z-index:9999;align-items:center;justify-content:center;padding:20px;';
  modal.innerHTML =
    '<div class="modal-content" style="background:#fff;border-radius:10px;max-width:820px;width:100%;max-height:88vh;display:flex;flex-direction:column;box-shadow:0 12px 40px rgba(0,0,0,.25);">' +
      '<div style="padding:16px 22px;border-bottom:1px solid #eee;display:flex;justify-content:space-between;align-items:center;">' +
        '<h3 style="margin:0;color:#732269;"><i class="fas fa-clipboard-check"></i> Review &amp; Submit — ' + escHtml(label) + ' Assessment</h3>' +
        '<button type="button" aria-label="Close" onclick="document.getElementById(\'assessmentReviewModal\').remove();" style="border:0;background:transparent;font-size:24px;color:#999;cursor:pointer;">&times;</button>' +
      '</div>' +
      '<div style="padding:18px 22px;overflow-y:auto;flex:1;">' +
        '<p style="margin:0 0 12px 0;color:#666;">Please review the answers below. Click <strong>Confirm &amp; Submit</strong> to record this assessment, or <strong>Edit Answers</strong> to make changes.</p>' +
        '<table style="width:100%;border-collapse:collapse;font-size:14px;">' + rowsHtml + '</table>' +
      '</div>' +
      '<div style="padding:14px 22px;border-top:1px solid #eee;display:flex;gap:10px;justify-content:flex-end;">' +
        '<button type="button" class="btn btn-outline" id="assessmentReviewEdit"><i class="fas fa-pen"></i> Edit Answers</button>' +
        '<button type="button" class="btn btn-primary" id="assessmentReviewConfirm"><i class="fas fa-check-circle"></i> Confirm &amp; Submit</button>' +
      '</div>' +
    '</div>';
  document.body.appendChild(modal);
  document.getElementById('assessmentReviewEdit').addEventListener('click', function() {
    modal.remove();
  });
  document.getElementById('assessmentReviewConfirm').addEventListener('click', function() {
    modal.remove();
    if (typeof onConfirm === 'function') onConfirm();
  });
}

function submitPreAssessment(status) {
  if (!window.selectedPreFlpId) {
    alert('No FLP selected. Please go back and select an FLP.');
    return;
  }

  var form = document.getElementById('page-assessmentForm');

  // Helper: get selected radio value (as int) within the form
  function getRadioInt(name) {
    var el = form.querySelector('input[name="' + name + '"]:checked');
    return el ? parseInt(el.value) : null;
  }
  // Helper: get selected radio value (as string) within the form
  function getRadioStr(name) {
    var el = form.querySelector('input[name="' + name + '"]:checked');
    return el ? el.value : null;
  }
  // Helper: get checked checkbox values as array
  function getChecked(name) {
    var els = form.querySelectorAll('input[name="' + name + '"]:checked');
    var vals = [];
    els.forEach(function(el) { vals.push(el.value); });
    return vals.length > 0 ? vals : null;
  }

  // ---- VALIDATION (only for final submission, not for Draft) ----
  if (status === 'Completed') {
    var missing = [];
    var radioQuestions = ['q10','q11','q12','q13','q14','q16','q17','q18','q19','q20','q21','q23','q25','q26','q27','q28','q29'];
    radioQuestions.forEach(function(name) {
      var el = form.querySelector('input[name="' + name + '"]:checked');
      if (!el) missing.push(name.toUpperCase());
    });
    var checkboxQuestions = ['q15','q22','q24','q30'];
    checkboxQuestions.forEach(function(name) {
      var els = form.querySelectorAll('input[name="' + name + '"]:checked');
      if (els.length === 0) missing.push(name.toUpperCase());
    });
    if (missing.length > 0) {
      alert('Please answer all required questions before submitting.\n\nUnanswered: ' + missing.join(', '));
      return;
    }
    // Review & Submit gate. The user must confirm the review modal once
    // before we actually POST. We re-call ourselves with the same status
    // when they confirm, but with `window._preReviewConfirmed = true` so
    // this block is skipped on the second pass. Drafts skip the review
    // entirely (Save Draft is meant to be a quick stash, not a final
    // submission). Cancel just hides the modal and returns.
    if (!window._preReviewConfirmed) {
      _showAssessmentReviewModal('page-assessmentForm', 'Baseline', function() {
        window._preReviewConfirmed = true;
        submitPreAssessment('Completed');
      });
      return;
    }
    window._preReviewConfirmed = false;
  }

  // Build payload matching AssessmentCreate model
  var data = {
    flp_id: parseInt(window.selectedPreFlpId),
    type: 'Pre-Training',
    status: status || 'Completed',
    assessment_date: new Date().toISOString().split('T')[0],
    // Section A (demographics)
    sec_a_name: document.getElementById('preQ1').value || null,
    sec_a_mobile: document.getElementById('preQ2').value || null,
    sec_a_address: document.getElementById('preQ3').value || null,
    sec_a_age: document.getElementById('preQ4').value ? parseInt(document.getElementById('preQ4').value) : null,
    sec_a_caste: document.getElementById('preQ5').value || null,
    sec_a_community: document.getElementById('preQ6').value || null,
    sec_a_education: document.getElementById('preQ7').value || null,
    sec_a_income: document.getElementById('preQ8').value ? parseFloat(document.getElementById('preQ8').value) : null,
    sec_a_family_members: document.getElementById('preQ9').value ? parseInt(document.getElementById('preQ9').value) : null,
    // Section B
    q10: getRadioInt('q10'),
    q11: getRadioInt('q11'),
    q12: getRadioInt('q12'),
    q13: getRadioInt('q13'),
    q14: getRadioInt('q14'),
    q15: getChecked('q15'),
    q16: getRadioInt('q16'),
    q17: getRadioInt('q17'),
    q18: getRadioInt('q18'),
    q19: getRadioInt('q19'),
    q20: getRadioInt('q20'),
    q21: getRadioInt('q21'),
    q22: getChecked('q22'),
    q23: getRadioInt('q23'),
    // Section C
    q24: getChecked('q24'),
    q25_self_made: getRadioStr('q25') === 'Yes' ? true : (getRadioStr('q25') === 'No' ? false : null),
    q25_which_document: document.getElementById('preQ25doc') ? document.getElementById('preQ25doc').value || null : null,
    q26_assisted_others: getRadioStr('q26') === 'Yes' ? true : (getRadioStr('q26') === 'No' ? false : null),
    q26_scheme_name: document.getElementById('preQ26scheme') ? document.getElementById('preQ26scheme').value || null : null,
    // Section D
    q27: getRadioInt('q27'),
    q28: getRadioInt('q28'),
    q29: getRadioInt('q29'),
    q30: getChecked('q30')
  };

  // Disable buttons during submission
  var btns = form.querySelectorAll('.form-actions button');
  btns.forEach(function(b) { b.disabled = true; });

  // Use UPDATE if editing an existing assessment, CREATE if new
  var editId = window._editingPreAssessmentId;
  var apiCall = editId ? apiUpdateAssessment(editId, data) : apiCreateAssessment(data);

  apiCall
    .then(function(result) {
      btns.forEach(function(b) { b.disabled = false; });
      // Store the ID for future saves (so re-saving draft doesn't create duplicate)
      if (result.id) { window._editingPreAssessmentId = result.id; _ctxSet('preAssessEditId', result.id); }
      if (status === 'Draft') {
        alert('Baseline saved as draft. Score: ' + (result.total_score || 0) + '%');
      } else {
        window._editingPreAssessmentId = null;
        _ctxClear('preAssessEditId'); _ctxClear('preAssessFlpId');
        alert('Baseline submitted successfully! Score: ' + (result.total_score || 0) + '%');
        navigateTo('assessmentList');
      }
    })
    .catch(function(err) {
      btns.forEach(function(b) { b.disabled = false; });
      var msg = 'Failed to save assessment.';
      if (err && err.detail) msg += ' ' + (typeof err.detail === 'string' ? err.detail : JSON.stringify(err.detail));
      alert(msg);
    });
}

// ---- POPULATE POST-ASSESSMENT FORM ----
function populatePostAssessmentForm(flpData) {
  // Set banner header info
  document.getElementById('postAssessFlpName').textContent = flpData.name || '—';
  document.getElementById('postAssessEnrollment').textContent = flpData.enrollment_number || '—';
  document.getElementById('postAssessLocation').textContent = flpData.location || '—';
  document.getElementById('postAssessDate').textContent = new Date().toLocaleDateString('en-IN', {day:'numeric',month:'short',year:'numeric',timeZone:'Asia/Kolkata'});

  // Pre-assessment date
  var preDt = flpData.pre_assessment_date
    ? new Date(flpData.pre_assessment_date).toLocaleDateString('en-IN', {day:'numeric',month:'short',year:'numeric',timeZone:'Asia/Kolkata'})
    : '—';
  document.getElementById('postAssessPreDate').textContent = preDt;

  // Assessed By (from pre-assessment)
  document.getElementById('postAssessBy').textContent = flpData.pre_assessed_by || '—';

  // Section A: Demographics (Q1-Q9) — read-only, pre-filled from pre-assessment
  document.getElementById('postQ1').value = flpData.sec_a_name || '';
  document.getElementById('postQ2').value = flpData.sec_a_mobile || '';
  document.getElementById('postQ3').value = flpData.sec_a_address || '';
  document.getElementById('postQ4').value = flpData.sec_a_age || calculateAgeFromDob(flpData.date_of_birth) || '';
  document.getElementById('postQ5').value = flpData.sec_a_caste || '';
  document.getElementById('postQ6').value = flpData.sec_a_community || '';
  document.getElementById('postQ7').value = flpData.sec_a_education || '';
  document.getElementById('postQ8').value = flpData.sec_a_income || '';
  document.getElementById('postQ9').value = flpData.sec_a_family_members || '';

  // Clear all radio/checkbox inputs in Section B-D
  var form = document.getElementById('page-assessmentFormPost');
  form.querySelectorAll('input[type="radio"], input[type="checkbox"]').forEach(function(cb) { cb.checked = false; });
  form.querySelectorAll('.assessment-question input[type="text"]').forEach(function(inp) { inp.value = ''; });

  // Store selected FLP id and pre-assessment data for submission
  window.selectedPostFlpId = flpData.id;
  window.selectedPostFlpData = flpData;
}


// ---- SUBMIT POST-ASSESSMENT ----
function submitPostAssessment(status) {
  if (!window.selectedPostFlpId) {
    alert('No FLP selected. Please go back and select an FLP.');
    return;
  }

  var form = document.getElementById('page-assessmentFormPost');

  // Helper: get selected radio value (as int) within the form
  function getRadioInt(name) {
    var el = form.querySelector('input[name="' + name + '"]:checked');
    return el ? parseInt(el.value) : null;
  }
  // Helper: get selected radio value (as string) within the form
  function getRadioStr(name) {
    var el = form.querySelector('input[name="' + name + '"]:checked');
    return el ? el.value : null;
  }
  // Helper: get checked checkbox values as array
  function getChecked(name) {
    var els = form.querySelectorAll('input[name="' + name + '"]:checked');
    var vals = [];
    els.forEach(function(el) { vals.push(el.value); });
    return vals.length > 0 ? vals : null;
  }

  // ---- VALIDATION (only for final submission, not for Draft) ----
  if (status === 'Completed') {
    var missing = [];
    var radioQuestions = ['pq10','pq11','pq12','pq13','pq14','pq16','pq17','pq18','pq19','pq20','pq21','pq23','pq25','pq26','pq27','pq28','pq29'];
    radioQuestions.forEach(function(name) {
      var el = form.querySelector('input[name="' + name + '"]:checked');
      if (!el) missing.push(name.replace('pq','Q'));
    });
    var checkboxQuestions = ['pq15','pq22','pq24','pq30'];
    checkboxQuestions.forEach(function(name) {
      var els = form.querySelectorAll('input[name="' + name + '"]:checked');
      if (els.length === 0) missing.push(name.replace('pq','Q'));
    });
    if (missing.length > 0) {
      alert('Please answer all required questions before submitting.\n\nUnanswered: ' + missing.join(', '));
      return;
    }
    // Review & Submit gate (Endline). Same pattern as the Baseline
    // submit — first call shows the review modal; the modal's confirm
    // callback sets the `_postReviewConfirmed` flag and re-invokes
    // submitPostAssessment('Completed') so we fall through this block.
    if (!window._postReviewConfirmed) {
      _showAssessmentReviewModal('page-assessmentFormPost', 'Endline', function() {
        window._postReviewConfirmed = true;
        submitPostAssessment('Completed');
      });
      return;
    }
    window._postReviewConfirmed = false;
  }

  var preData = window.selectedPostFlpData || {};

  // Build payload matching AssessmentCreate model
  var data = {
    flp_id: parseInt(window.selectedPostFlpId),
    type: 'Post-Training',
    status: status || 'Completed',
    assessment_date: new Date().toISOString().split('T')[0],
    // Section A (demographics — copied from pre-assessment, read-only)
    sec_a_name: preData.sec_a_name || document.getElementById('postQ1').value || null,
    sec_a_mobile: preData.sec_a_mobile || document.getElementById('postQ2').value || null,
    sec_a_address: preData.sec_a_address || document.getElementById('postQ3').value || null,
    sec_a_age: preData.sec_a_age || (document.getElementById('postQ4').value ? parseInt(document.getElementById('postQ4').value) : null),
    sec_a_caste: preData.sec_a_caste || document.getElementById('postQ5').value || null,
    sec_a_community: preData.sec_a_community || document.getElementById('postQ6').value || null,
    sec_a_education: preData.sec_a_education || document.getElementById('postQ7').value || null,
    sec_a_income: preData.sec_a_income || (document.getElementById('postQ8').value ? parseFloat(document.getElementById('postQ8').value) : null),
    sec_a_family_members: preData.sec_a_family_members || (document.getElementById('postQ9').value ? parseInt(document.getElementById('postQ9').value) : null),
    // Section B (post-assessment uses pq* prefixed names)
    q10: getRadioInt('pq10'),
    q11: getRadioInt('pq11'),
    q12: getRadioInt('pq12'),
    q13: getRadioInt('pq13'),
    q14: getRadioInt('pq14'),
    q15: getChecked('pq15'),
    q16: getRadioInt('pq16'),
    q17: getRadioInt('pq17'),
    q18: getRadioInt('pq18'),
    q19: getRadioInt('pq19'),
    q20: getRadioInt('pq20'),
    q21: getRadioInt('pq21'),
    q22: getChecked('pq22'),
    q23: getRadioInt('pq23'),
    // Section C
    q24: getChecked('pq24'),
    q25_self_made: getRadioStr('pq25') === 'Yes' ? true : (getRadioStr('pq25') === 'No' ? false : null),
    q25_which_document: null,
    q26_assisted_others: getRadioStr('pq26') === 'Yes' ? true : (getRadioStr('pq26') === 'No' ? false : null),
    q26_scheme_name: null,
    // Section D
    q27: getRadioInt('pq27'),
    q28: getRadioInt('pq28'),
    q29: getRadioInt('pq29'),
    q30: getChecked('pq30')
  };

  // Get Q25.1 and Q26.1 text inputs
  var textInputs = form.querySelectorAll('.assessment-question input[type="text"][placeholder="Specify"]');
  if (textInputs.length >= 1) data.q25_which_document = textInputs[0].value || null;
  if (textInputs.length >= 2) data.q26_scheme_name = textInputs[1].value || null;

  // Disable buttons during submission
  var btns = form.querySelectorAll('.form-actions button');
  btns.forEach(function(b) { b.disabled = true; });

  // Use UPDATE if editing an existing post-assessment, CREATE if new
  var editPostId = window._editingPostAssessmentId;
  var apiCall = editPostId ? apiUpdateAssessment(editPostId, data) : apiCreateAssessment(data);

  apiCall
    .then(function(result) {
      btns.forEach(function(b) { b.disabled = false; });
      if (result.id) { window._editingPostAssessmentId = result.id; _ctxSet('postAssessEditId', result.id); }
      if (status === 'Draft') {
        alert('Endline saved as draft. Score: ' + (result.total_score || 0) + '%');
      } else {
        window._editingPostAssessmentId = null;
        _ctxClear('postAssessEditId'); _ctxClear('postAssessFlpId'); _ctxClear('postAssessPreId');
        alert('Endline submitted successfully! Score: ' + (result.total_score || 0) + '%');
        if (window._postFlpDataMap && window.selectedPostFlpId) {
          delete window._postFlpDataMap[window.selectedPostFlpId];
        }
        loadPostAssessmentFLPs();
        navigateTo('assessmentList');
      }
    })
    .catch(function(err) {
      btns.forEach(function(b) { b.disabled = false; });
      var msg = 'Failed to save post-assessment.';
      if (err && err.message) msg += ' ' + err.message;
      alert(msg);
    });
}


