/**
 * Reusable pagination renderer for all list pages.
 * @param {string} pagDivSelector - CSS selector for the pagination div
 * @param {number} total - total records
 * @param {number} page - current page
 * @param {number} limit - records per page
 * @param {string} loadFnName - JS function name to call on page change (e.g. 'loadFlpListData')
 */
function renderListPagination(pagDivSelector, total, page, limit, loadFnName) {
  var pagDiv = document.querySelector(pagDivSelector);
  if (!pagDiv) return;
  // Empty result set — render an honest "Showing 0 of 0" with no
  // pagination chips. Without this, a list that previously had results
  // would keep showing stale "Showing 1-10 of N" after a filtered
  // search returns nothing.
  total = parseInt(total, 10) || 0;
  if (total <= 0) {
    pagDiv.innerHTML = 'Showing 0 of 0';
    return;
  }
  var totalPages = Math.ceil(total / limit);
  var from = (page - 1) * limit + 1;
  var to = Math.min(page * limit, total);
  var html = 'Showing ' + from + '-' + to + ' of ' + formatNumber(total) + ' &nbsp; ';
  if (totalPages > 1) {
    html += '<button class="btn-icon" ' + (page <= 1 ? 'disabled' : 'onclick="' + loadFnName + '(' + (page - 1) + ')"') + '><i class="fas fa-chevron-left"></i></button> ';
    // Show page numbers: first, current-1, current, current+1, last
    var pages = [];
    pages.push(1);
    if (page - 1 > 1) pages.push(page - 1);
    if (page > 1 && page < totalPages) pages.push(page);
    if (page + 1 < totalPages) pages.push(page + 1);
    if (totalPages > 1) pages.push(totalPages);
    // Deduplicate and sort
    pages = pages.filter(function(v, i, a) { return a.indexOf(v) === i; }).sort(function(a, b) { return a - b; });
    var prevP = 0;
    pages.forEach(function(p) {
      if (p - prevP > 1) html += '<span style="padding:0 4px;">...</span>';
      html += '<button class="btn-icon" style="' + (p === page ? 'font-weight:bold;color:var(--primary);' : '') + '" onclick="' + loadFnName + '(' + p + ')">' + p + '</button> ';
      prevP = p;
    });
    html += '<button class="btn-icon" ' + (page >= totalPages ? 'disabled' : 'onclick="' + loadFnName + '(' + (page + 1) + ')"') + '><i class="fas fa-chevron-right"></i></button>';
  }
  pagDiv.innerHTML = html;
}

