function loadSystemActivityLog(page) {
  logCurrentPage = page || logCurrentPage || 1;
  var tbody = document.getElementById('systemActivityLogBody');

  if (apiAvailable) {
    var params = {
      page: logCurrentPage,
      limit: logPageLimit
    };
    // Read filter values
    var userFilter = document.getElementById('logFilterUser');
    var actionFilter = document.getElementById('logFilterAction');
    var sourceFilter = document.getElementById('logFilterSource');
    var startDate = document.getElementById('logFilterStartDate');
    var endDate = document.getElementById('logFilterEndDate');

    if (userFilter && userFilter.value) params.user_id = userFilter.value;
    if (actionFilter && actionFilter.value) params.action = actionFilter.value;
    if (sourceFilter && sourceFilter.value) params.source = sourceFilter.value;
    if (startDate && startDate.value) params.start_date = startDate.value;
    if (endDate && endDate.value) params.end_date = endDate.value;

    apiSystemLog(params).then(function(result) {
      // Populate filter dropdowns
      populateLogFilters(result.available_users, result.available_actions);
      // Update stats
      document.getElementById('logStatTotal').textContent = result.total;
      document.getElementById('logStatToday').textContent = result.today_count || 0;
      document.getElementById('logStatActiveUsers').textContent = result.active_users || 0;
      // Render table
      renderActivityLogTable(result.data, result.total, result.page, result.limit);
    }).catch(function(err) {
      console.error('Failed to load activity log:', err);
      renderActivityLogFallback();
    });
  } else {
    renderActivityLogFallback();
  }
}

function renderActivityLogFallback() {
  // Use demo data
  document.getElementById('logStatTotal').textContent = DEMO_SYSTEM_LOG.length;
  document.getElementById('logStatToday').textContent = DEMO_SYSTEM_LOG.length;
  document.getElementById('logStatActiveUsers').textContent = 5;
  renderActivityLogTable(DEMO_SYSTEM_LOG, DEMO_SYSTEM_LOG.length, 1, 50);
}

function populateLogFilters(users, actions) {
  var userSelect = document.getElementById('logFilterUser');
  var actionSelect = document.getElementById('logFilterAction');

  // Preserve current selections
  var currentUser = userSelect ? userSelect.value : '';
  var currentAction = actionSelect ? actionSelect.value : '';

  if (userSelect && userSelect.options.length <= 1) {
    (users || []).forEach(function(u) {
      var opt = document.createElement('option');
      opt.value = u.id;
      opt.textContent = u.name;
      userSelect.appendChild(opt);
    });
    if (currentUser) userSelect.value = currentUser;
  }

  if (actionSelect && actionSelect.options.length <= 1) {
    (actions || []).forEach(function(a) {
      var opt = document.createElement('option');
      opt.value = a;
      opt.textContent = a;
      actionSelect.appendChild(opt);
    });
    if (currentAction) actionSelect.value = currentAction;
  }
}

function renderActivityLogTable(data, total, page, limit) {
  var tbody = document.getElementById('systemActivityLogBody');
  if (!data || data.length === 0) {
    tbody.innerHTML = '<tr><td colspan="9" style="text-align:center; padding:40px; color:#999;"><i class="fas fa-inbox" style="font-size:24px;"></i><br>No activity log entries found</td></tr>';
    document.getElementById('logPaginationInfo').textContent = 'No entries';
    document.getElementById('logPaginationControls').innerHTML = '';
    return;
  }

  var actionColors = {
    'Login': '#27ae60', 'Create FLP': '#2980b9', 'Edit FLP': '#f39c12',
    'Submit Survey': '#8e44ad', 'Approve Survey': '#27ae60', 'Create Training': '#2980b9',
    'Assign Participants': '#16a085', 'View Report': '#7f8c8d', 'Export Report': '#34495e',
    'Create Assessment': '#2980b9', 'Edit User': '#f39c12', 'Create Centre': '#2980b9',
    'Create Batch': '#2980b9', 'Reset Password': '#e74c3c'
  };

  var rows = '';
  var startIdx = (page - 1) * limit;

  data.forEach(function(entry, i) {
    var ts = entry.created_at ? formatLogTimestamp(entry.created_at) : '-';
    var actionColor = actionColors[entry.action] || '#732269';
    var sourceClass = entry.source === 'mobile' ? 'background:#e8f5e9;color:#2e7d32;' : 'background:#e3f2fd;color:#1565c0;';
    var resource = '';
    if (entry.resource_type) {
      resource = entry.resource_type;
      if (entry.resource_id) resource += ' #' + entry.resource_id;
    }

    rows += '<tr>' +
      '<td style="color:#999; font-size:12px;">' + (startIdx + i + 1) + '</td>' +
      '<td style="font-size:12px; white-space:nowrap;">' + escHtml(ts) + '</td>' +
      '<td style="font-weight:600;">' + escHtml(entry.user_name || '-') + '</td>' +
      '<td style="font-size:12px; color:#666;">' + escHtml(entry.role_name || '-') + '</td>' +
      '<td><span style="display:inline-block; padding:2px 10px; border-radius:12px; font-size:12px; font-weight:600; background:' + actionColor + '1a; color:' + actionColor + ';">' + escHtml(entry.action) + '</span></td>' +
      '<td style="font-size:12px; color:#555;">' + escHtml(resource || '-') + '</td>' +
      '<td style="font-size:12px;">' + escHtml(entry.ip_address || '-') + (entry.city ? '<br><span style="color:#999; font-size:11px;">' + escHtml(entry.city) + '</span>' : '') + '</td>' +
      '<td><span style="display:inline-block; padding:2px 8px; border-radius:10px; font-size:11px; font-weight:600; ' + sourceClass + '">' + escHtml((entry.source || 'web').toUpperCase()) + '</span></td>' +
      '<td style="font-size:12px; color:#555; max-width:250px; overflow:hidden; text-overflow:ellipsis; white-space:nowrap;" title="' + escHtml(entry.description || '') + '">' + escHtml(entry.description || '-') + '</td>' +
    '</tr>';
  });

  tbody.innerHTML = rows;

  // Pagination info
  var showing = Math.min(data.length, limit);
  var from = startIdx + 1;
  var to = startIdx + showing;
  document.getElementById('logPaginationInfo').textContent = 'Showing ' + from + '-' + to + ' of ' + total + ' entries';

  // Pagination controls
  var totalPages = Math.ceil(total / limit);
  var pagControls = '';
  if (totalPages > 1) {
    pagControls += '<button class="btn btn-sm btn-outline" ' + (page <= 1 ? 'disabled' : 'onclick="loadSystemActivityLog(' + (page - 1) + ')"') + '>&laquo; Prev</button>';
    for (var p = 1; p <= totalPages && p <= 10; p++) {
      pagControls += '<button class="btn btn-sm ' + (p === page ? 'btn-primary' : 'btn-outline') + '" onclick="loadSystemActivityLog(' + p + ')">' + p + '</button>';
    }
    pagControls += '<button class="btn btn-sm btn-outline" ' + (page >= totalPages ? 'disabled' : 'onclick="loadSystemActivityLog(' + (page + 1) + ')"') + '>Next &raquo;</button>';
  }
  document.getElementById('logPaginationControls').innerHTML = pagControls;

  // Scroll to bottom for "live" feel — newest entries at bottom
  var wrapper = document.getElementById('logTableWrapper');
  if (wrapper && page === 1) {
    setTimeout(function() { wrapper.scrollTop = wrapper.scrollHeight; }, 100);
  }
}

function formatLogTimestamp(isoStr) {
  try {
    var d = new Date(isoStr);
    var day = String(d.getDate()).padStart(2, '0');
    var mon = ['Jan','Feb','Mar','Apr','May','Jun','Jul','Aug','Sep','Oct','Nov','Dec'][d.getMonth()];
    var yr = d.getFullYear();
    var hr = String(d.getHours()).padStart(2, '0');
    var min = String(d.getMinutes()).padStart(2, '0');
    var sec = String(d.getSeconds()).padStart(2, '0');
    return day + ' ' + mon + ' ' + yr + ' ' + hr + ':' + min + ':' + sec;
  } catch(e) {
    return isoStr;
  }
}

function clearLogFilters() {
  var userSelect = document.getElementById('logFilterUser');
  var actionSelect = document.getElementById('logFilterAction');
  var sourceSelect = document.getElementById('logFilterSource');
  var startDate = document.getElementById('logFilterStartDate');
  var endDate = document.getElementById('logFilterEndDate');

  if (userSelect) userSelect.value = '';
  if (actionSelect) actionSelect.value = '';
  if (sourceSelect) sourceSelect.value = '';
  if (startDate) startDate.value = '';
  if (endDate) endDate.value = '';

  logCurrentPage = 1;
  loadSystemActivityLog(1);
}

function toggleLogAutoRefresh() {
  var cb = document.getElementById('logAutoRefresh');
  var status = document.getElementById('logAutoRefreshStatus');

  if (cb && cb.checked) {
    logAutoRefreshInterval = setInterval(function() {
      loadSystemActivityLog(logCurrentPage);
    }, 15000); // refresh every 15 seconds
    if (status) status.textContent = 'Refreshing every 15s';
  } else {
    if (logAutoRefreshInterval) {
      clearInterval(logAutoRefreshInterval);
      logAutoRefreshInterval = null;
    }
    if (status) status.textContent = '';
  }
}


