// Helper: get only parent/top-level metrics (excludes sub-parameters)
function _topLevelMetrics() { return METRIC_DEFINITIONS.filter(function(m) { return !m.parent; }); }

// Helper: get metrics shown in Target table (hasTarget === true)
function _targetableMetrics() { return METRIC_DEFINITIONS.filter(function(m) { return m.hasTarget; }); }

// Helper: get sub-parameters of a parent metric
function _subMetricsOf(parentKey) { return METRIC_DEFINITIONS.filter(function(m) { return m.parent === parentKey; }); }

// Helper: check if a metric has dynamic row support
function _isDynamicMetric(m) { return m.inputType && m.inputType.indexOf('dynamic') === 0; }

