function openAddMgj() {
  mgjFormMode = 'add';
  editingMgjId = null;
  // 2026-07-06: Clear any photo left over from a previous add/edit so a
  // stale file doesn't get silently uploaded against the new member.
  mgjSelectedPhoto = null;
  navigateTo('addMgj');
  setTimeout(function() {
    var _pp = document.getElementById('mgjPhotoPreview');
    if (_pp) _pp.innerHTML = '<i class="fas fa-camera"></i>';
    // Clear the persistent file input too — without this, re-picking the
    // same file wouldn't fire onchange (see the input's onclick note in
    // index.html).
    var _pi = document.getElementById('mgjPhotoInput');
    if (_pi) _pi.value = '';
    // Breadcrumb text + header Update button — these toggle between
    // add and edit modes so the user always knows which mode they're in
    // and (in edit mode) can save changes from any tab via the header
    // button without scrolling all the way to the Review tab.
    var bc = document.getElementById('addMgjBcText');
    if (bc) bc.textContent = 'Add MGJ';
    var hdrUpdate = document.getElementById('btnMgjUpdateHeader');
    if (hdrUpdate) hdrUpdate.style.display = 'none';
    var submitEl = document.getElementById('mgjFormSubmitText');
    if (submitEl) submitEl.textContent = 'Save';
    // Clear all text/number inputs (mgjGroup is now a select — value-reset
    // here still works for selects; option-set is reset below).
    ['mgjEnrollment','mgjName','mgjDob','mgjAge','mgjMobile','mgjAddress','mgjGroup',
     'mgjChildren','mgjAgeAtMarriage','mgjSocialMediaDetails',
     'mgjFamilyCount','mgjEarningMembers','mgjFamilyIncome','mgjPerCapita',
     'mgjWomenBelow18','mgjMenBelow18','mgjWomenAbove18','mgjMenAbove18',
     'mgjWomenInAzadRel','mgjMenInAzadRel',
     'mgjEducationOther','mgjStudyingWhat',
     'mgjCareerStatus','mgjWorkPlace','mgjIncome','mgjFutureGoal',
     // 2026-07-06: The "Other — please specify" free-text fields were
     // missing from this list, so after submitting a member and opening
     // Add MGJ again they stayed autofilled with the previous member's
     // values (reported alongside stale Centre/Area — fixed below).
     'mgjAreaOther','mgjCasteOther','mgjReligionOther','mgjGenderOther','mgjWorkNatureOther'
    ].forEach(function(id) {
      var el = document.getElementById(id); if (el) el.value = '';
    });
    // Reset the Group dropdown's options too — otherwise a stale list from
    // a previous Add/Edit session would persist. Group repopulates once the
    // user picks an Area.
    var mgjGroupSel = document.getElementById('mgjGroup');
    if (mgjGroupSel) mgjGroupSel.innerHTML = '<option value="">Select Group</option>';
    // 2026-06-08: Same for the new Batch Number dropdown — reset to the
    // placeholder so a stale (now out-of-scope) batch from the previous
    // record can't leak into an Add flow. Batch repopulates when Centre
    // changes via _populateMgjBatchDropdown.
    var mgjBatchSel = document.getElementById('mgjBatch');
    if (mgjBatchSel) mgjBatchSel.innerHTML = '<option value="">Select Batch</option>';
    // 2026-07-06: Reset the geography cascade. This was the main source of
    // the "fields autofilled on the next Add" report — State/Centre/Area
    // were never in any reset list, so the previous member's selections
    // (and Centre/Area option lists from the previous State) persisted
    // into the new Add form. State's OPTION list is rebuilt by
    // _populateMgjFormState() below, but its selected value, and the
    // Centre/Area dropdowns' entire option sets, must be cleared here.
    var _mgjStateSel = document.getElementById('mgjState');
    if (_mgjStateSel) _mgjStateSel.value = '';
    var _mgjCentreSel = document.getElementById('mgjCentre');
    if (_mgjCentreSel) _mgjCentreSel.innerHTML = '<option value="">Select Centre</option>';
    var _mgjAreaSel = document.getElementById('mgjArea');
    if (_mgjAreaSel) _mgjAreaSel.innerHTML = '<option value="">Select Area</option>';
    // Reset all dropdowns
    ['mgjCaste','mgjReligion','mgjGender','mgjSocialMedia','mgjMarital',
     'mgjWomenInAzad','mgjMenInAzad','mgjEducation','mgjStillStudying',
     'mgjIsWorking'  // added 2026-05-27 (replaces mgjCareerStatus)
    ].forEach(function(id) {
      var el = document.getElementById(id); if (el) el.selectedIndex = 0;
    });
    // Reset work nature checkboxes + the new Year input
    document.querySelectorAll('input[name="mgjWorkNature"]').forEach(function(cb) { cb.checked = false; });
    var _ey = document.getElementById('mgjEducationYear'); if (_ey) _ey.value = '';
    // Year input upper bound = current year (per client rule).
    if (_ey) _ey.max = String(new Date().getFullYear());
    // Hide conditional fields (mgjStudyingWhatGrp removed from DOM 2026-05-27)
    // 2026-07-06: added the Caste/Religion/Gender/Area/WorkNature "Other"
    // groups and the Children group — these were missing, so a previous
    // member who used an "Other" value left the specify-box visible (and
    // filled) on the next Add.
    ['mgjSocialMediaDetailsGrp','mgjAgeAtMarriageGrp','mgjWomenInAzadRelGrp','mgjMenInAzadRelGrp','mgjEducationOtherGrp','mgjWorkDetailsGrp',
     'mgjCasteOtherGrp','mgjReligionOtherGrp','mgjGenderOtherGrp','mgjAreaOtherGrp','mgjWorkNatureOtherGrp','mgjChildrenGrp'].forEach(function(id) {
      var el = document.getElementById(id); if (el) el.style.display = 'none';
    });
    // Reset dynamic family-member detail blocks (Q5-Q8 right-side cards)
    ['women-below-18','men-below-18','women-above-18','men-above-18'].forEach(function(b) {
      var h = document.getElementById('mgjFamMembers-' + b);
      if (h) h.innerHTML = '<div class="mgj-fam-empty">Enter a count above to add per-member details.</div>';
    });
    // Switch to first tab
    switchMgjTab('basicProfile');
    var _mgjDob = document.getElementById('mgjDob'); if (_mgjDob) _mgjDob.max = new Date().toISOString().split('T')[0];
    // Populate state dropdown
    _populateMgjFormState();
    // 2026-06-08: For DL/PI roles, lock State (and Centre, for PI) to
    // the user's assigned MGJ-master scope. Deferred slightly so the
    // state-list XHR has fired before we override the option set.
    setTimeout(function() {
      if (typeof _lockMgjFormForDlPi === 'function') _lockMgjFormForDlPi();
    }, 120);
  }, 50);
}

function openEditMgj(id) {
  // 7-day Draft submit window — mirrors the FLP gate in openEditFlp.
  // For DRAFT records older than 7 days, only super_admin / admin may
  // open the edit form. Everyone else gets blocked with a message
  // telling them to contact a Super Admin. Active records are never
  // time-limited. On the day BEFORE the deadline (day 6, i.e. 6 full
  // days < age <= 7 days) we surface a heads-up alert so the user
  // knows they have 24 hours left to submit. The check runs before
  // navigateTo() so the form never even loads if blocked.
  apiMgjDetail(id).then(function(m) {
    var isDraft = (m.status === 'Draft');
    if (isDraft && m.created_at) {
      var created = new Date(m.created_at);
      var now = new Date();
      var daysOld = Math.floor((now - created) / (1000 * 60 * 60 * 24));
      var isExempt = currentUser && (currentUser.role === 'super_admin' || currentUser.role === 'admin');
      if (daysOld > 7 && !isExempt) {
        alert('This Draft MGJ Member record was created more than 7 days ago and can no longer be submitted. Please contact a Super Admin to reopen it.');
        return;
      }
      if (daysOld === 6 && !isExempt) {
        // Day-6 expiry warning. Non-blocking — we still open the form
        // afterwards, the user just knows the window closes tomorrow.
        alert('Heads up: this Draft MGJ Member record was created 6 days ago. You have 1 day left to complete and submit it before the 7-day window expires.');
      }
    }
    _proceedEditMgj(id);
  }).catch(function() {
    // Couldn't fetch detail for the gate — fall through to opening the
    // form anyway (it re-fetches on its own). Mirrors FLP behaviour.
    _proceedEditMgj(id);
  });
}

function _proceedEditMgj(id) {
  mgjFormMode = 'edit';
  editingMgjId = id;
  navigateTo('addMgj');
  setTimeout(function() {
    // ALWAYS reset to the Basic Profile tab. Without this, the form keeps
    // whichever tab was last active from a prior visit (Add MGJ, an
    // earlier Edit, etc.). If that prior tab was "Review & Submit", the
    // user landed on a blank Review panel because populateMgjReview()
    // hadn't run yet — looked like the form failed to load.
    switchMgjTab('basicProfile');

    // Breadcrumb shows "Edit MGJ"; header Update button becomes visible
    // so the user can save changes from any tab. Both the header button
    // and the Review-tab footer button trigger saveMgjRecord() — the
    // header one is just more discoverable when the user only wants to
    // tweak a single field.
    var bc = document.getElementById('addMgjBcText');
    if (bc) bc.textContent = 'Edit MGJ';
    var hdrUpdate = document.getElementById('btnMgjUpdateHeader');
    if (hdrUpdate) hdrUpdate.style.display = 'inline-flex';
    var submitTextEl = document.getElementById('mgjFormSubmitText');
    if (submitTextEl) submitTextEl.textContent = 'Update';
    _populateMgjFormState();
    // 2026-06-08: Lock State + Centre for DL/PI in edit mode too.
    // Defer past _populateMgjFormState's XHR. The lock overrides the
    // dropdown options to a single locked option matching the saved
    // record's state/centre (which by definition must equal the user's
    // own scope — PIs can only see records inside their centre).
    setTimeout(function() {
      if (typeof _lockMgjFormForDlPi === 'function') _lockMgjFormForDlPi();
    }, 120);
    apiMgjDetail(id).then(function(m) {
      // Basic Profile
      var _s = function(id, val) { var el = document.getElementById(id); if (el) el.value = val || ''; };
      _s('mgjEnrollment', m.enrollment_number);
      _s('mgjName', m.name);
      _s('mgjDob', m.date_of_birth);
      _s('mgjAge', m.age_at_enrollment);
      _s('mgjAddress', m.address);
      _s('mgjMobile', m.mobile);
      // 2026-07-06: Show the SAVED photo in the edit preview (previously
      // the preview only ever showed a freshly-picked local file via
      // FileReader — a saved photo_url was never loaded back). photo_url
      // is stored as a server-relative /uploads/... path, so prefix the
      // API origin the same way the FLP view does.
      mgjSelectedPhoto = null;
      // Also clear the persistent file input so picking the same file for
      // this member still fires onchange (SPA — the input survives across
      // members; a stale value suppresses the change event).
      var _pi = document.getElementById('mgjPhotoInput');
      if (_pi) _pi.value = '';
      var _pp = document.getElementById('mgjPhotoPreview');
      if (_pp) {
        _pp.innerHTML = m.photo_url
          ? '<img src="' + API_BASE.replace('/api', '') + m.photo_url + '" style="width:100%;height:100%;object-fit:cover;border-radius:6px;">'
          : '<i class="fas fa-camera"></i>';
      }
      // mgjGroup is now a dropdown filtered by mgjArea. We can't preselect it
      // here because the area cascade fires later (in the state→centre→area
      // chain below). The Group preselect happens after the area cascade
      // completes — see the chained setTimeout near the bottom of this fn.
      _s('mgjCaste', m.caste_category);
      _s('mgjReligion', m.community_religion);
      _s('mgjGender', m.gender);
      _s('mgjSocialMedia', m.social_media_account);
      _s('mgjSocialMediaDetails', m.social_media_details);
      toggleMgjConditional('mgjSocialMedia', 'Yes', 'mgjSocialMediaDetailsGrp');
      _s('mgjMarital', m.marital_status);
      _s('mgjAgeAtMarriage', m.age_at_marriage);
      _s('mgjChildren', m.number_of_children);
      // Reveal Age-at-Marriage + Children groups for the new multi-status
      // rule (Married / Separated / Divorced / Widow). onMgjMaritalChange()
      // owns the show/hide logic and also blanks values when hidden, so
      // setting values BEFORE calling it is correct — values are kept when
      // visible and cleared when hidden.
      onMgjMaritalChange();
      // Family
      _s('mgjFamilyCount', m.family_members_count);
      _s('mgjEarningMembers', m.earning_members);
      _s('mgjFamilyIncome', m.monthly_family_income);
      _s('mgjPerCapita', m.per_capita_income);
      _s('mgjWomenBelow18', m.women_below_18);
      _s('mgjMenBelow18', m.men_below_18);
      _s('mgjWomenAbove18', m.women_above_18);
      _s('mgjMenAbove18', m.men_above_18);
      // Build the dynamic member-detail cards + restore saved values
      if (typeof hydrateMgjFamDetails === 'function') {
        hydrateMgjFamDetails(m.family_member_details);
      }
      _s('mgjWomenInAzad', m.women_in_azad);
      _s('mgjWomenInAzadRel', m.women_in_azad_relation);
      toggleMgjConditional('mgjWomenInAzad', 'Yes', 'mgjWomenInAzadRelGrp');
      _s('mgjMenInAzad', m.men_in_azad);
      _s('mgjMenInAzadRel', m.men_in_azad_relation);
      toggleMgjConditional('mgjMenInAzad', 'Yes', 'mgjMenInAzadRelGrp');
      // Education — Year input + new dropdown set (the studying_what UI
      // was removed 2026-05-27; the DB column is kept but not hydrated).
      _s('mgjEducation', m.education);
      _s('mgjEducationOther', m.education_other);
      _s('mgjEducationYear', m.education_year);
      toggleMgjConditional('mgjEducation', 'Others', 'mgjEducationOtherGrp');
      _s('mgjStillStudying', m.still_studying);
      // Work — Career/Educational Status replaced by Is-Working dropdown
      // 2026-05-27. The detail block (Where / Income / Nature) is
      // shown/hidden by onMgjIsWorkingChange after we set the value.
      _s('mgjIsWorking', m.is_working);
      _s('mgjWorkPlace', m.work_place);
      _s('mgjIncome', m.monthly_income);
      onMgjIsWorkingChange();
      _s('mgjFutureGoal', m.future_goal);
      // Work nature checkboxes
      if (m.work_nature) {
        var natures = m.work_nature.split(',').map(function(n) { return n.trim(); });
        document.querySelectorAll('input[name="mgjWorkNature"]').forEach(function(cb) {
          cb.checked = natures.indexOf(cb.value) >= 0;
        });
      }
      // Set state and cascade centre → area → group
      if (m.state_code) {
        setTimeout(function() {
          document.getElementById('mgjState').value = m.state_code;
          onMgjFormStateChange(function() {
            if (m.centre_code) {
              document.getElementById('mgjCentre').value = m.centre_code;
              onMgjFormCentreChange();
              setTimeout(function() {
                if (m.area_code) {
                  document.getElementById('mgjArea').value = m.area_code;
                  // After Area is set, populate the Group dropdown for that area
                  // and preselect the saved group_number (auto-adds a "(legacy)"
                  // option if the saved value isn't in the current group list).
                  _mgjFillGroupSelectByArea('mgjGroup', m.area_code, m.group_number);
                }
                // 2026-06-08: Hydrate Batch Number. The Centre-change
                // cascade above fired _populateMgjBatchDropdown which
                // ran the XHR; wait a beat for it to land then pick the
                // saved batch_id. _populateMgjBatchDropdown also
                // preserves prev .value, so if the cascade returns
                // after this line the saved batch still sticks.
                if (m.batch_id) {
                  var _bSel = document.getElementById('mgjBatch');
                  if (_bSel) _bSel.value = String(m.batch_id);
                }
              }, 300);
            }
          });
        }, 300);
      }
    }).catch(function() { alert('Error loading MGJ member.'); });
  }, 50);
}

// Generic helper: populate any <select id=…> with MGJ Master states.
// Use this anywhere the MGJ module needs a State dropdown (replaces the
// FLP-bound `loadStateDropdown` in MGJ contexts).
function _mgjFillStateDropdown(selectId, defaultLabel) {
  var sel = document.getElementById(selectId);
  if (!sel) return;
  // 2026-06-03: skip the rebuild if the dropdown is already populated.
  // The previous version cleared sel.innerHTML synchronously and then
  // restored the preserved value AFTER the async state fetch resolved.
  // But any caller that read sel.value between the clear and the resolve
  // got an empty string — which is exactly what loadMgjLtList does two
  // lines after calling this helper. Result: picking Delhi and clicking
  // Search would send the API request with no state filter and return
  // every training. Once-populated dropdowns short-circuit immediately
  // so the user's pick stays visible and readable.
  if (sel.options.length > 1) return;
  sel.innerHTML = '<option value="">' + (defaultLabel || 'All States') + '</option>';
  apiGet('/mgj-master/dropdown/states').then(function(states) {
    var list = (states && states.data) ? states.data : states;
    (list || []).forEach(function(s) {
      var opt = document.createElement('option');
      opt.value = s.state_code; opt.textContent = s.state_name;
      sel.appendChild(opt);
    });
  }).catch(function() {});
}

function _populateMgjFormState() {
  // MGJ Add-Member form pulls geography from MGJ Master tables (not FLP).
  var sel = document.getElementById('mgjState');
  if (!sel) return;
  sel.innerHTML = '<option value="">Select State</option>';
  var xhr = new XMLHttpRequest();
  xhr.open('GET', window.location.origin + '/api/mgj-master/dropdown/states', true);
  xhr.onload = function() {
    if (xhr.status === 200) {
      var states = JSON.parse(xhr.responseText);
      var sel2 = document.getElementById('mgjState');
      if (!sel2) return;
      for (var i = 0; i < states.length; i++) {
        var opt = document.createElement('option');
        opt.value = states[i].state_code; opt.textContent = states[i].state_name;
        sel2.appendChild(opt);
      }
    }
  };
  xhr.send();
}

// 2026-06-08: Resolve the user's MGJ-master state_code + centre_code
// from their FLP scope and cache them on currentUser. Used by both
// the form lock (_lockMgjFormForDlPi) and the list scope helper
// (_applyMgjListScope) so they don't have to re-do the lookup each
// time. Returns a Promise that resolves AFTER the codes are cached
// (or immediately if already cached / user role doesn't need it).
//
// Why this is needed: MGJ has its own state/centre master tables.
// While state_code is shared with FLP in practice ("DL" for Delhi),
// centre_code is NOT — MGJ centres carry MGJ-master codes that
// don't equal FLP centre_code. Passing FLP centre_code as the MGJ
// list filter would return zero rows.
//
// Matching: state by code (with state_name fallback), centre by
// name from the user's scope ("Centre Name, District Name"). FLP
// districts often share the MGJ centre name (e.g. "North Delhi").
function _resolveMgjScopeForDlPi() {
  if (!currentUser) return Promise.resolve();
  var role = currentUser.role || '';
  // 2026-06-08: state_lead now also resolves through this helper.
  // SL doesn't have a centre — only a state — and the FLP state_code
  // matches the MGJ master state_code in practice (both 'DL' for
  // Delhi). Stamp mgj_state_code/name from the FLP fields so the
  // downstream MGJ lock helpers (which key on mgj_state_code) treat
  // SL the same as DL — state hard-locked, centre dropdown loads the
  // full state-scoped centre list.
  if (role === 'state_lead' && currentUser.state_code) {
    // 2026-06-09: previously this fell back to `state_code` as the
    // label when `state_name` wasn't on the JWT — which is exactly the
    // path that surfaced "S07" instead of "Delhi" everywhere SL hits a
    // locked State select.  Always look up the MGJ master so the
    // resolved name is canonical regardless of what login stamped on
    // currentUser.  Match the DL/PI lookup pattern below.
    var alreadyResolved =
      currentUser.mgj_state_code === currentUser.state_code &&
      currentUser.mgj_state_name &&
      currentUser.mgj_state_name !== currentUser.state_code;
    if (alreadyResolved) return Promise.resolve();
    return new Promise(function(resolve) {
      apiGet('/mgj-master/dropdown/states').then(function(states) {
        var list = (states && states.data) ? states.data : (states || []);
        var match = list.filter(function(s) {
          return s.state_code === currentUser.state_code;
        })[0];
        currentUser.mgj_state_code = currentUser.state_code;
        currentUser.mgj_state_name = (match && match.state_name) ||
                                     currentUser.state_name ||
                                     currentUser.state_code;
        // Also stamp the canonical state_name on the FLP-side field so
        // any other helper (SL state-only lock, dashboard chrome) that
        // reads currentUser.state_name benefits from the same lookup.
        if (match && match.state_name) currentUser.state_name = match.state_name;
        try { localStorage.setItem('azadUserData', JSON.stringify(currentUser)); } catch (e) {}
        resolve();
      }).catch(function() {
        currentUser.mgj_state_code = currentUser.state_code;
        currentUser.mgj_state_name = currentUser.state_name || currentUser.state_code;
        try { localStorage.setItem('azadUserData', JSON.stringify(currentUser)); } catch (e) {}
        resolve();
      });
    });
  }
  if (role !== 'pi' && role !== 'district_lead') return Promise.resolve();
  // Already cached — short-circuit. 2026-06-08: DL now also tries to
  // resolve a centre (when the user's district name matches a centre
  // name like "South Delhi" → South Delhi centre) so DL gets the same
  // soft 2-option Centre lock PI gets. If no matching centre exists,
  // mgj_centre_code stays unset and DL falls through to the state-
  // scoped centre list (legacy behaviour preserved).
  if (currentUser.mgj_state_code && currentUser.mgj_centre_code) {
    return Promise.resolve();
  }
  return new Promise(function(resolve) {
    _whenDlPiReady(function() {
      if (!currentUser.state_code) { resolve(); return; }
      var scopeParts = (currentUser.scope || '').split(',').map(function(s) { return s.trim(); });
      var centreName = scopeParts[0] || '';
      var districtName = scopeParts[1] || '';
      apiGet('/mgj-master/dropdown/states').then(function(states) {
        var list = (states && states.data) ? states.data : (states || []);
        var mgjState = list.filter(function(s) { return s.state_code === currentUser.state_code; })[0];
        if (!mgjState && currentUser.state_name) {
          mgjState = list.filter(function(s) {
            return s.state_name &&
                   s.state_name.toLowerCase() === currentUser.state_name.toLowerCase();
          })[0];
        }
        if (!mgjState) { resolve(); return; }
        currentUser.mgj_state_code = mgjState.state_code;
        currentUser.mgj_state_name = mgjState.state_name;
        // 2026-06-08: DL now also resolves centre — falls through to
        // the PI centre lookup below. Matches centre by candidate names
        // (centre_name first, then district_name) so a South Delhi DL
        // whose scope is "..., South Delhi" matches the South Delhi
        // centre row in mgj_centres. If no match, mgj_centre_code stays
        // unset and the lock helpers fall back to the state list.
        // PI / DL: resolve centre.
        apiGet('/mgj-master/dropdown/centres?state_code=' + encodeURIComponent(mgjState.state_code))
          .then(function(centres) {
            var cList = (centres && centres.data) ? centres.data : (centres || []);
            var mgjCentre = null;
            var candidates = [centreName, districtName].filter(Boolean);
            for (var i = 0; i < candidates.length && !mgjCentre; i++) {
              var nm = candidates[i].toLowerCase();
              mgjCentre = cList.filter(function(c) {
                return c.centre_name && c.centre_name.toLowerCase() === nm;
              })[0];
            }
            if (mgjCentre) {
              currentUser.mgj_centre_code = mgjCentre.centre_code;
              currentUser.mgj_centre_name = mgjCentre.centre_name;
            }
            try { localStorage.setItem('azadUserData', JSON.stringify(currentUser)); } catch (e) {}
            resolve();
          })
          .catch(function() { resolve(); });
      }).catch(function() { resolve(); });
    });
  });
}

// 2026-06-08: MGJ-specific scope application. Uses the cached
// MGJ-master codes (mgj_state_code / mgj_centre_code) resolved by
// _resolveMgjScopeForDlPi() rather than the FLP codes from
// currentUser.state_code/centre_code (which DON'T match MGJ records).
// Soft-fail: if MGJ centre couldn't be resolved (data drift between
// modules) we omit the centre_code filter and the user sees their
// state-wide records instead of an empty list — they're never
// locked out of seeing data.
function _applyMgjListScope(params) {
  params = params || {};
  if (!currentUser) return params;
  var role = currentUser.role || '';
  if (role === 'state_lead' && currentUser.state_code) {
    // State codes are shared with FLP in practice.
    params.state_code = currentUser.state_code;
  } else if (role === 'district_lead') {
    if (currentUser.mgj_state_code)  params.state_code = currentUser.mgj_state_code;
    else if (currentUser.state_code) params.state_code = currentUser.state_code;
  } else if (role === 'pi') {
    if (currentUser.mgj_state_code)  params.state_code  = currentUser.mgj_state_code;
    else if (currentUser.state_code) params.state_code  = currentUser.state_code;
    if (currentUser.mgj_centre_code) params.centre_code = currentUser.mgj_centre_code;
    // Deliberately NO FLP centre_code fallback — it would return 0 rows.
  } else if (role === 'mobiliser' || role === 'sangini') {
    if (currentUser.state_code)      params.state_code  = currentUser.state_code;
    if (currentUser.mgj_centre_code) params.centre_code = currentUser.mgj_centre_code;
  }
  return params;
}

// 2026-06-08: Generic lock helper for MGJ list / dashboard / report
// FILTER dropdowns (state + optional centre). Use on any MGJ page
// that has a State filter — and a Centre filter if present — so DL
// and PI users see only their assigned geography. Pass null for any
// id that doesn't exist on the page (e.g. a list with no Centre
// filter). Reuses the same _resolveMgjScopeForDlPi resolver as the
// form lock so the cache is shared.
//
// opts.centreMode (default 'hard'):
//   'hard' → centre rendered as a single-option disabled dropdown
//            (matches the State lock visual).
//   'soft' → centre stays an ENABLED dropdown but its only options
//            are "All Centres" placeholder + the user's centre.
//            Used on MGJ List per user request 2026-06-08 — the
//            field still looks/acts like a dropdown the user can
//            click, just with no other centres available to pick.
// opts.stateMode (default 'hard'):
//   'hard' → state rendered as a single-option disabled dropdown.
//   'soft' → state stays ENABLED with "All States" placeholder +
//            the user's state. Used on Case Studies List 2026-06-08
//            per user request ("All States and Delhi").
// 2026-06-30 — FLP role-based filter behavior.
// PI / SL: State LOCKED to user's state; District + Centre cascade
//          WITHIN that state (district dropdown pre-populated with all
//          districts of the user's state; centre cascades from district).
// DL:      State + District locked; Centre cascades within district.
// Admin / super_admin: no-op (existing cascade handlers work unchanged).
// Multi-timer retries [60/400/1200ms] win the race vs page's own loads.
function _lockFlpFiltersForDlPi(stateSelId, districtSelId, centreSelId) {
  if (!currentUser) return;
  var role = currentUser.role || '';
  if (role !== 'pi' && role !== 'district_lead' && role !== 'state_lead') return;
  [60, 400, 1200, 2500, 4000].forEach(function(delay) {
    setTimeout(function() { _doLockFlpFiltersInner(stateSelId, districtSelId, centreSelId); }, delay);
  });
}
function _doLockFlpFiltersInner(stateSelId, districtSelId, centreSelId) {
  if (!currentUser) return;
  var role = currentUser.role || '';
  var sc = currentUser.state_code, dc = currentUser.district_code;
  var sn = currentUser.state_name || sc;
  var dn = currentUser.district_name || dc;
  if (!sc) return;
  function lockSel(el, value, label) {
    if (!el) return;
    el.innerHTML = '<option value="' + escHtml(value) + '" selected>' + escHtml(label) + '</option>';
    el.value = value;
    el.disabled = true;
    el.style.backgroundColor = '#f5f5f5';
    el.style.cursor = 'not-allowed';
    el.title = 'Locked to your assigned scope';
    try { el.dispatchEvent(new Event('change', { bubbles: true })); } catch (e) {}
  }
  function populateDropdown(el, url, vk, lk, ph) {
    if (!el) return;
    var xhr = new XMLHttpRequest();
    xhr.open('GET', window.location.origin + url, true);
    xhr.onload = function() {
      if (xhr.status !== 200) return;
      var data = JSON.parse(xhr.responseText) || [];
      if (data.data) data = data.data;
      el.innerHTML = '<option value="">' + escHtml(ph) + '</option>';
      data.forEach(function(it) { var o = document.createElement('option'); o.value = it[vk]; o.textContent = it[lk]; el.appendChild(o); });
      el.disabled = false;
    };
    xhr.send();
  }
  var stateSel = stateSelId && document.getElementById(stateSelId);
  var districtSel = districtSelId && document.getElementById(districtSelId);
  var centreSel = centreSelId && document.getElementById(centreSelId);
  if (stateSel) lockSel(stateSel, sc, sn);
  if (role === 'district_lead') {
    if (districtSel && dc) lockSel(districtSel, dc, dn);
    if (centreSel && dc) populateDropdown(centreSel, '/api/geo/dropdown/centres?district_code=' + encodeURIComponent(dc), 'centre_code', 'centre_name', 'All Centres');
  } else if (role === 'pi') {
    // 2026-06-30 v3 — PI: state locked, district locked (if known), centre
    // HARD-locked to user's own centre. Earlier behavior populated with all
    // state's centres which let a PI see other centres in their state (e.g.
    // East Delhi PI seeing North/South Delhi). User rule: only own centre.
    if (districtSel && dc) lockSel(districtSel, dc, dn);
    if (centreSel && cc) lockSel(centreSel, cc, cn);
  } else {
    // SL — state locked, district + centre cascade within state.
    if (districtSel) populateDropdown(districtSel, '/api/geo/dropdown/districts?state_code=' + encodeURIComponent(sc), 'district_code', 'district_name', 'All Districts');
    if (centreSel) populateDropdown(centreSel, '/api/geo/dropdown/centres?state_code=' + encodeURIComponent(sc), 'centre_code', 'centre_name', 'All Centres');
  }
}

function _lockMgjFiltersForDlPi(stateSelId, centreSelId, opts) {
  if (!currentUser) return;
  var role = currentUser.role || '';
  // 2026-06-08: state_lead added — behaves like DL (state hard-locked,
  // centre is the full state-scoped centre list). _resolveMgjScopeForDlPi
  // now seeds mgj_state_code from currentUser.state_code for SL.
  if (role !== 'pi' && role !== 'district_lead' && role !== 'state_lead') return;
  opts = opts || {};
  var centreMode = opts.centreMode || 'hard';
  var stateMode  = opts.stateMode  || 'hard';

  _resolveMgjScopeForDlPi().then(function() {
    if (!currentUser.mgj_state_code) return;

    // 2026-06-08: apply the lock several times with growing delays.
    // Different MGJ pages fire their centre-loading XHR at different
    // times (60-1000ms after page-init), and the first lock often
    // gets overwritten by the late-arriving response. Re-running at
    // 60ms / 400ms / 1200ms guarantees the final paint is locked.
    [60, 400, 1200, 2500, 4000].forEach(function(delay) {
      setTimeout(function() { _doLockMgjFiltersInner(stateSelId, centreSelId, centreMode, stateMode); }, delay);
    });
  });
}

function _doLockMgjFiltersInner(stateSelId, centreSelId, centreMode, stateMode) {
  if (!currentUser || !currentUser.mgj_state_code) return;
  var role = currentUser.role || '';
  stateMode = stateMode || 'hard';
  {
      var stateSel = stateSelId && document.getElementById(stateSelId);
      if (stateSel) {
        if (stateMode === 'soft') {
          // Soft: "All States" placeholder + the user's state (enabled).
          var stateDefaultLabel = (stateSel.options[0] && stateSel.options[0].text) || 'All States';
          stateSel.innerHTML = '<option value="">' + escHtml(stateDefaultLabel) + '</option>' +
                               '<option value="' + escHtml(currentUser.mgj_state_code) + '">' +
                               escHtml(currentUser.mgj_state_name || currentUser.mgj_state_code) +
                               '</option>';
          stateSel.disabled = false;
          stateSel.style.backgroundColor = '';
          stateSel.style.cursor = '';
          stateSel.title = '';
        } else {
          stateSel.innerHTML = '<option value="' + escHtml(currentUser.mgj_state_code) + '" selected>' +
                               escHtml(currentUser.mgj_state_name || currentUser.mgj_state_code) + '</option>';
          stateSel.value = currentUser.mgj_state_code;
          stateSel.disabled = true;
          stateSel.style.backgroundColor = '#f5f5f5';
          stateSel.style.cursor = 'not-allowed';
          stateSel.title = 'Locked to your assigned State';
        }
      }

      var centreSel = centreSelId && document.getElementById(centreSelId);
      if (!centreSel) {
        // No centre filter on this page — done.
        if (stateSel) try { stateSel.dispatchEvent(new Event('change', { bubbles: true })); } catch (e) {}
        return;
      }

      if ((role === 'pi' || role === 'district_lead') && currentUser.mgj_centre_code) {
        // 2026-06-08: DL with a resolved centre (district name ==
        // centre name) now gets the same single-centre treatment PI
        // gets — user wants "All Centres + South Delhi" for the South
        // Delhi DL. The visual treatment depends on opts.centreMode.
        var defaultLabel = (centreSel.options[0] && centreSel.options[0].text) || 'All Centres';
        if (centreMode === 'soft') {
          // 2026-06-08 (final): Enabled dropdown with two options —
          // the page's default "All Centres" placeholder + the user's
          // assigned centre. User wants both ("show all centres and
          // North Delhi"). Backend scope filter still pins centre_code
          // to the user's centre on every API call, so picking
          // "All Centres" doesn't widen the data — it's a UX courtesy.
          centreSel.innerHTML = '<option value="">' + escHtml(defaultLabel) + '</option>' +
                                '<option value="' + escHtml(currentUser.mgj_centre_code) + '">' +
                                escHtml(currentUser.mgj_centre_name || currentUser.mgj_centre_code) +
                                '</option>';
          centreSel.disabled = false;
          centreSel.style.backgroundColor = '';
          centreSel.style.cursor = '';
          centreSel.title = '';
        } else {
          // Hard lock — single locked option, disabled, grey.
          centreSel.innerHTML = '<option value="' + escHtml(currentUser.mgj_centre_code) + '" selected>' +
                                escHtml(currentUser.mgj_centre_name || currentUser.mgj_centre_code) + '</option>';
          centreSel.value = currentUser.mgj_centre_code;
          centreSel.disabled = true;
          centreSel.style.backgroundColor = '#f5f5f5';
          centreSel.style.cursor = 'not-allowed';
          centreSel.title = 'Locked to your assigned Centre';
        }
        try { centreSel.dispatchEvent(new Event('change', { bubbles: true })); } catch (e) {}
        return;
      }
      // DL (or PI whose centre couldn't be resolved): populate centres
      // for the user's state, selectable.
      var xhr = new XMLHttpRequest();
      xhr.open('GET', window.location.origin + '/api/mgj-master/dropdown/centres?state_code=' +
               encodeURIComponent(currentUser.mgj_state_code), true);
      xhr.onload = function() {
        if (xhr.status !== 200) return;
        var centres = JSON.parse(xhr.responseText) || [];
        var fallbackLabel = (centreSel.options[0] && centreSel.options[0].text) || 'All Centres';
        centreSel.innerHTML = '<option value="">' + escHtml(fallbackLabel) + '</option>';
        centres.forEach(function(c) {
          var opt = document.createElement('option');
          opt.value = c.centre_code;
          opt.textContent = c.centre_name;
          centreSel.appendChild(opt);
        });
      };
      xhr.send();
  }
}

// 2026-06-08: Baseline Report — 4-cascade lock for DL/PI.
// The Baseline Report has State → District → Centre → Batch all
// cascading. Per user request 2026-06-08:
//   * State    — enabled dropdown, 2 options: "All States" + Delhi
//   * District — enabled dropdown, 2 options: "All Districts" + user's district
//   * Centre   — enabled dropdown, 2 options: "All Centres" + user's centre
//   * Batch    — pre-loaded with batches for the user's centre/state
// The cascade keeps working: picking the user's state re-fires the
// onMgjBrStateChange handler which the user's own onchange wires up.
function _lockMgjBrFiltersForDlPi() {
  if (!currentUser) return;
  var role = currentUser.role || '';
  if (role !== 'pi' && role !== 'district_lead') return;
  _resolveMgjScopeForDlPi().then(function() {
    if (!currentUser.mgj_state_code) return;
    [60, 400, 1200, 2500, 4000].forEach(function(delay) {
      setTimeout(_doLockMgjBrFiltersInner, delay);
    });
  });
}

function _doLockMgjBrFiltersInner() {
  if (!currentUser || !currentUser.mgj_state_code) return;
  var role = currentUser.role || '';
  var scope = (currentUser.scope || '').split(',').map(function(s) { return s.trim(); });
  var districtName = scope[1] || ''; // FLP district name = MGJ district name

  // 2026-06-08 (revised per user): two-option dropdowns. PLACEHOLDER is
  // the default selection so initial load + Reset both show "All
  // States" / "All Districts" / "All Centres" selected. The user's
  // assigned value is the ONLY other option — that's the scope guard.
  // When the user picks their value from the dropdown, the existing
  // cascade handlers fire and the Batch dropdown populates.

  // STATE — All States (default) + Delhi
  var stateSel = document.getElementById('mgjBrFilterState');
  if (stateSel) {
    stateSel.innerHTML = '<option value="" selected>All States</option>' +
                         '<option value="' + escHtml(currentUser.mgj_state_code) + '">' +
                         escHtml(currentUser.mgj_state_name || currentUser.mgj_state_code) + '</option>';
    stateSel.value = '';
    stateSel.disabled = false;
    stateSel.style.backgroundColor = '';
    stateSel.style.cursor = '';
    stateSel.title = '';
  }

  // DISTRICT — All Districts (default) + North Delhi
  if (role === 'pi' && districtName) {
    apiGet('/mgj-master/districts?state_code=' + encodeURIComponent(currentUser.mgj_state_code) + '&limit=500')
      .then(function(resp) {
        var rows = (resp && (resp.data || resp)) || [];
        var match = rows.filter(function(r) {
          return r.district_name && r.district_name.toLowerCase() === districtName.toLowerCase();
        })[0];
        var dSel = document.getElementById('mgjBrFilterDistrict');
        if (!dSel || !match) return;
        dSel.innerHTML = '<option value="" selected>All Districts</option>' +
                         '<option value="' + escHtml(match.district_code) + '">' +
                         escHtml(match.district_name) + '</option>';
        dSel.value = '';
        dSel.disabled = false;
        dSel.style.backgroundColor = '';
        dSel.style.cursor = '';
        currentUser.mgj_district_code = match.district_code;
        try { localStorage.setItem('azadUserData', JSON.stringify(currentUser)); } catch (e) {}
      })
      .catch(function() {});
  }

  // CENTRE — All Centres (default) + North Delhi
  if (currentUser.mgj_centre_code) {
    var cSel = document.getElementById('mgjBrFilterCentre');
    if (cSel) {
      cSel.innerHTML = '<option value="" selected>All Centres</option>' +
                       '<option value="' + escHtml(currentUser.mgj_centre_code) + '">' +
                       escHtml(currentUser.mgj_centre_name || currentUser.mgj_centre_code) + '</option>';
      cSel.value = '';
      cSel.disabled = false;
      cSel.style.backgroundColor = '';
      cSel.style.cursor = '';
    }
  }

  // BATCH — empty until the user picks State; existing onMgjBrStateChange
  // fires the /dropdown/batches?state_code=… fetch on user interaction.
  var bSel = document.getElementById('mgjBrFilterBatch');
  if (bSel) {
    bSel.innerHTML = '<option value="">All Batches</option>';
    bSel.value = '';
  }
}

// 2026-06-08: Lock State + Centre on the Add/Edit MGJ form for District
// Lead + Project Incharge roles, mirroring the State-Lead lock that
// already exists for AK (_lockStateOnlyForSL).
//   * DL → State locked to user's scope; Centre selectable within state.
//   * PI → State + Centre BOTH locked to a single option (user's scope).
function _lockMgjFormForDlPi() {
  if (!currentUser) return;
  // 2026-06-08: state_lead added — behaves like DL on the Add MGJ form
  // (state hard-locked to user's state; centre dropdown shows full
  // state-scoped centre list, selectable). User explicitly asked for
  // State to be auto-filled "Delhi" on the SL Add MGJ form.
  if (currentUser.role !== 'pi' && currentUser.role !== 'district_lead' && currentUser.role !== 'state_lead') return;

  _resolveMgjScopeForDlPi().then(function() {
    if (!currentUser.mgj_state_code) return;

    // Lock State select to the user's single state.
    var stateSel = document.getElementById('mgjState');
    if (stateSel) {
      stateSel.innerHTML = '<option value="' + escHtml(currentUser.mgj_state_code) + '" selected>' +
                           escHtml(currentUser.mgj_state_name || currentUser.mgj_state_code) + '</option>';
      stateSel.value = currentUser.mgj_state_code;
      stateSel.disabled = true;
      stateSel.style.backgroundColor = '#f5f5f5';
      stateSel.style.cursor = 'not-allowed';
      stateSel.title = 'Locked to your assigned State';
    }

    // Load centres for that state.
    var xhrC = new XMLHttpRequest();
    xhrC.open('GET', window.location.origin + '/api/mgj-master/dropdown/centres?state_code=' +
              encodeURIComponent(currentUser.mgj_state_code), true);
    xhrC.onload = function() {
      if (xhrC.status !== 200) return;
      var centres = JSON.parse(xhrC.responseText) || [];
      var centreSel = document.getElementById('mgjCentre');
      if (!centreSel) return;

      if ((currentUser.role === 'pi' || currentUser.role === 'district_lead') && currentUser.mgj_centre_code) {
        // 2026-06-08: DL with a resolved centre also gets the single-
        // option hard lock on the Add MGJ form Centre (user spec for
        // South Delhi DL: "Centre Field auto-filled with South Delhi").
        centreSel.innerHTML = '<option value="' + escHtml(currentUser.mgj_centre_code) + '" selected>' +
                              escHtml(currentUser.mgj_centre_name || currentUser.mgj_centre_code) + '</option>';
        centreSel.value = currentUser.mgj_centre_code;
        centreSel.disabled = true;
        centreSel.style.backgroundColor = '#f5f5f5';
        centreSel.style.cursor = 'not-allowed';
        centreSel.title = 'Locked to your assigned Centre';
        try { centreSel.dispatchEvent(new Event('change', { bubbles: true })); } catch (e) {}
        return;
      }
      // DL (or PI with no resolved centre — fail-safe): populate centres
      // for the user's state; centre stays selectable.
      centreSel.innerHTML = '<option value="">Select Centre</option>';
      centres.forEach(function(c) {
        var opt = document.createElement('option');
        opt.value = c.centre_code;
        opt.textContent = c.centre_name;
        centreSel.appendChild(opt);
      });
    };
    xhrC.send();
  });
}

function onMgjFormStateChange(cb) {
  var sc = (document.getElementById('mgjState') || {}).value;
  var centreSel = document.getElementById('mgjCentre');
  var areaSel = document.getElementById('mgjArea');
  if (centreSel) centreSel.innerHTML = '<option value="">Select Centre</option>';
  if (areaSel) areaSel.innerHTML = '<option value="">Select Area</option>';
  if (!sc) return;
  var xhr = new XMLHttpRequest();
  xhr.open('GET', window.location.origin + '/api/mgj-master/dropdown/centres?state_code=' + encodeURIComponent(sc), true);
  xhr.onload = function() {
    if (xhr.status === 200) {
      var centres = JSON.parse(xhr.responseText);
      var sel = document.getElementById('mgjCentre');
      if (!sel) return;
      var seenCode = {}, seenName = {};
      for (var i = 0; i < centres.length; i++) {
        var code = centres[i].centre_code;
        var nameKey = (centres[i].centre_name || '').trim().toLowerCase();
        if (seenCode[code] || (nameKey && seenName[nameKey])) continue;
        seenCode[code] = true;
        if (nameKey) seenName[nameKey] = true;
        var opt = document.createElement('option');
        opt.value = code; opt.textContent = centres[i].centre_name;
        sel.appendChild(opt);
      }
      if (typeof cb === 'function') cb();
    }
  };
  xhr.send();
}

// ---- MGJ FORM HELPERS ----
function switchMgjTab(tabId) {
  document.querySelectorAll('#page-addMgj .tab-content').forEach(function(t) { t.classList.remove('active'); });
  document.querySelectorAll('#page-addMgj .tab-btn').forEach(function(b) { b.classList.remove('active'); });
  var tab = document.getElementById('mgjTab-' + tabId);
  if (tab) tab.classList.add('active');
  var tabNames = ['basicProfile', 'family', 'education', 'work', 'reviewMgj'];
  var idx = tabNames.indexOf(tabId);
  var btns = document.querySelectorAll('#page-addMgj .tab-btn');
  if (btns[idx]) btns[idx].classList.add('active');
  if (tabId === 'reviewMgj' && typeof populateMgjReview === 'function') populateMgjReview();
}

function toggleMgjConditional(selectId, showValue, groupId) {
  var sel = document.getElementById(selectId);
  var grp = document.getElementById(groupId);
  if (sel && grp) grp.style.display = (sel.value === showValue) ? '' : 'none';
}

// ─────────────────────────────────────────────────────────────────────
// Inline (per-field) validation for the MGJ Member form.
// Added 2026-05-27. Previously all validation errors only appeared on
// submit via alert(); now the same rules also surface inline as the
// user blurs / changes each field. Submit-time validation is unchanged
// — saveMgjRecord() still runs the full sweep — so this is purely an
// earlier-feedback layer on top of the existing safety net.
//
// Wire-up uses event delegation on #page-addMgj so we don't have to
// add 14 individual oninput / onblur attributes to the HTML.
// Validators below return null if OK, or an error string to show.
// ─────────────────────────────────────────────────────────────────────
var _MGJ_INLINE_VALIDATORS = {
  // Setup row (top of form)
  mgjState:        function(v) { return v ? null : 'Please select a State.'; },
  mgjCentre:       function(v) { return v ? null : 'Please select a Centre.'; },
  mgjArea:         function(v) { return v ? null : 'Please select an Area.'; },
  mgjAreaOther:    function(v, fn) {
    var area = (document.getElementById('mgjArea') || {}).value || '';
    if (area !== 'OTHER') return null;
    return v ? null : 'Please specify the area name.';
  },
  mgjGroup:        function(v) { return v ? null : 'Please select the Group Number.'; },
  // Basic identity strip
  mgjName:         function(v) { return v ? null : 'Please enter the Name.'; },
  mgjDob:          function(v) {
    if (!v) return 'Please enter Date of Birth.';
    var dob = new Date(v);
    var now = new Date();
    if (isNaN(dob.getTime())) return 'Please enter a valid Date of Birth.';
    if (dob > now)            return 'Date of Birth cannot be a future date.';
    var age = now.getFullYear() - dob.getFullYear();
    var md  = now.getMonth() - dob.getMonth();
    if (md < 0 || (md === 0 && now.getDate() < dob.getDate())) age--;
    if (age < 13 || age > 25) return 'Age must be between 13 and 25 years (current: ' + age + ').';
    return null;
  },
  mgjMobile:       function(v) {
    if (!v) return 'Please enter the 10-digit Mobile Number.';
    if (v.length !== 10) return 'Mobile Number must be exactly 10 digits.';
    return null;
  },
  mgjAddress:      function(v) { return v ? null : 'Please enter the Address.'; },
  // Other-Specify conditionals — only required when parent select = 'Others'
  mgjCasteOther:    function(v) {
    return (document.getElementById('mgjCaste')    || {}).value === 'Others'
      ? (v ? null : 'Please specify caste category.') : null;
  },
  mgjReligionOther: function(v) {
    return (document.getElementById('mgjReligion') || {}).value === 'Others'
      ? (v ? null : 'Please specify religion.') : null;
  },
  mgjGenderOther:   function(v) {
    return (document.getElementById('mgjGender')   || {}).value === 'Others'
      ? (v ? null : 'Please specify gender.') : null;
  },
  // Family details
  mgjFamilyCount:    function(v) { return v ? null : 'Please enter Number of Family Members.'; },
  mgjEarningMembers: function(v) { return v ? null : 'Please enter number of earning members.'; },
  mgjFamilyIncome:   function(v) { return v ? null : 'Please enter Monthly Family Income.'; },
  mgjWomenInAzad:    function(v) { return v ? null : 'Please select Yes or No.'; },
  mgjMenInAzad:      function(v) { return v ? null : 'Please select Yes or No.'; },
  mgjWomenInAzadRel: function(v) {
    return (document.getElementById('mgjWomenInAzad') || {}).value === 'Yes'
      ? (v ? null : 'Please enter the relation.') : null;
  },
  mgjMenInAzadRel:   function(v) {
    return (document.getElementById('mgjMenInAzad')   || {}).value === 'Yes'
      ? (v ? null : 'Please enter the relation.') : null;
  },
  // Education — 2026-05-27 set
  mgjEducationYear:  function(v) {
    if (!v) return 'Please enter the Year.';
    var n = parseInt(v, 10);
    var cy = new Date().getFullYear();
    if (isNaN(n) || n < 1950 || n > cy) return 'Year must be between 1950 and ' + cy + '.';
    return null;
  },
  mgjEducation:      function(v) { return v ? null : 'Please select Education Qualification.'; },
  mgjEducationOther: function(v) {
    return (document.getElementById('mgjEducation') || {}).value === 'Others'
      ? (v ? null : 'Please specify education details.') : null;
  },
  // Work — 2026-05-27 set
  mgjIsWorking:      function(v) { return v ? null : 'Please select Yes or No.'; },
};

function _mgjShowInline(input, msg) {
  if (!input) return;
  input.style.borderColor = '#e74c3c';
  var grp = input.closest ? input.closest('.form-group') : input.parentElement;
  if (!grp) return;
  var err = grp.querySelector(':scope > .mgj-field-err');
  if (!err) {
    err = document.createElement('div');
    err.className = 'mgj-field-err';
    err.style.cssText = 'color:#e74c3c;font-size:12px;margin-top:4px;line-height:1.3;';
    grp.appendChild(err);
  }
  err.textContent = msg;
}

function _mgjClearInline(input) {
  if (!input) return;
  input.style.borderColor = '';
  var grp = input.closest ? input.closest('.form-group') : input.parentElement;
  if (!grp) return;
  var err = grp.querySelector(':scope > .mgj-field-err');
  if (err) err.remove();
}

function _mgjRunInline(input) {
  if (!input || !input.id) return;
  var fn = _MGJ_INLINE_VALIDATORS[input.id];
  if (!fn) return;
  var v = (input.value || '').trim();
  var msg = fn(v);
  if (msg) _mgjShowInline(input, msg);
  else     _mgjClearInline(input);
}

// Run once on page load — page-addMgj exists in DOM even when hidden.
(function _mgjBootstrapInlineValidators() {
  var attach = function() {
    var page = document.getElementById('page-addMgj');
    if (!page || page.dataset.mgjInlineWired) return;
    page.dataset.mgjInlineWired = '1';
    // focusout bubbles (unlike blur), so one delegated listener covers
    // every field in the form.
    page.addEventListener('focusout', function(e) {
      if (e.target && e.target.id && _MGJ_INLINE_VALIDATORS[e.target.id]) {
        _mgjRunInline(e.target);
      }
    });
    // Clear the error as soon as the user starts editing — no re-validate
    // here on purpose, so the user isn't fighting with a "must be 10 digits"
    // message that flickers while they're typing the 4th digit.
    page.addEventListener('input', function(e) {
      if (e.target && e.target.id && _MGJ_INLINE_VALIDATORS[e.target.id]) {
        _mgjClearInline(e.target);
      }
    });
    // change is what <select> fires; re-validate immediately on select.
    page.addEventListener('change', function(e) {
      if (e.target && e.target.id && _MGJ_INLINE_VALIDATORS[e.target.id]) {
        _mgjRunInline(e.target);
      }
    });
  };
  if (document.readyState === 'loading') {
    document.addEventListener('DOMContentLoaded', attach);
  } else {
    attach();
  }
})();

// Marital Status drives BOTH "Age at Marriage" and "Number of Children"
// visibility — multi-value trigger, so toggleMgjConditional (single-value)
// isn't enough. The fields are shown when the user has plausibly been
// married (Married / Separated / Divorced / Widow) and hidden otherwise.
// Called from the <select onchange="..."> AND from the edit-mode hydrate.
var _MGJ_MARITAL_WITH_KIDS = ['Married', 'Separated', 'Divorced', 'Widow'];

// "Are you working?" gates the Work-detail block (Where / Income /
// Nature). When set to "No", we hide the block and blank its inputs so
// stale values don't sneak into the save. The save handler also
// scrubs work_place / monthly_income / work_nature → null when
// is_working !== 'Yes' (belt-and-braces).
function onMgjIsWorkingChange() {
  var sel = document.getElementById('mgjIsWorking');
  var grp = document.getElementById('mgjWorkDetailsGrp');
  if (!sel || !grp) return;
  var show = sel.value === 'Yes';
  grp.style.display = show ? '' : 'none';
  if (!show) {
    var wp = document.getElementById('mgjWorkPlace'); if (wp) wp.value = '';
    var inc = document.getElementById('mgjIncome');   if (inc) inc.value = '';
    document.querySelectorAll('input[name="mgjWorkNature"]').forEach(function(cb) { cb.checked = false; });
    var wno = document.getElementById('mgjWorkNatureOther'); if (wno) wno.value = '';
    var wnoGrp = document.getElementById('mgjWorkNatureOtherGrp'); if (wnoGrp) wnoGrp.style.display = 'none';
  }
}
function onMgjMaritalChange() {
  var sel = document.getElementById('mgjMarital');
  var show = sel && _MGJ_MARITAL_WITH_KIDS.indexOf(sel.value) !== -1;
  ['mgjAgeAtMarriageGrp', 'mgjChildrenGrp'].forEach(function(gid) {
    var g = document.getElementById(gid);
    if (g) g.style.display = show ? '' : 'none';
  });
  // When hidden, blank the underlying inputs so a stale value isn't
  // submitted to the API after the user toggles status back.
  if (!show) {
    var a = document.getElementById('mgjAgeAtMarriage'); if (a) a.value = '';
    var k = document.getElementById('mgjChildren');      if (k) k.value = '';
  }
}

function calcMgjAge() {
  var dob = document.getElementById('mgjDob');
  var ageEl = document.getElementById('mgjAge');
  if (!dob || !dob.value || !ageEl) return;
  var birth = new Date(dob.value);
  var today = new Date();
  var age = today.getFullYear() - birth.getFullYear();
  var m = today.getMonth() - birth.getMonth();
  if (m < 0 || (m === 0 && today.getDate() < birth.getDate())) age--;
  ageEl.value = age;
}

function calcMgjPerCapita() {
  var income = parseFloat((document.getElementById('mgjFamilyIncome') || {}).value) || 0;
  var members = parseInt((document.getElementById('mgjFamilyCount') || {}).value) || 0;
  var pc = document.getElementById('mgjPerCapita');
  if (pc) pc.value = members > 0 ? (income / members).toFixed(2) : '';
}

function onMgjFormCentreChange() {
  var centreCode = (document.getElementById('mgjCentre') || {}).value;
  var areaSel = document.getElementById('mgjArea');
  if (areaSel) areaSel.innerHTML = '<option value="">Select Area</option>';
  // Hide area specify field
  var areaOtherGrp = document.getElementById('mgjAreaOtherGrp');
  if (areaOtherGrp) areaOtherGrp.style.display = 'none';
  // 2026-06-08: Repopulate Batch dropdown scoped to the (State, Centre)
  // pair the user just landed on. The previous batch value is reset
  // because batches are centre-scoped — a now-out-of-scope batch_id
  // would silently send a stale FK on save.
  var stateCode = (document.getElementById('mgjState') || {}).value;
  _populateMgjBatchDropdown(stateCode, centreCode);
  if (!centreCode) return;
  var xhr = new XMLHttpRequest();
  xhr.open('GET', window.location.origin + '/api/mgj-master/dropdown/areas?centre_code=' + encodeURIComponent(centreCode), true);
  xhr.onload = function() {
    if (xhr.status === 200) {
      var areas = JSON.parse(xhr.responseText);
      var sel = document.getElementById('mgjArea');
      if (!sel) return;
      var seen = {};
      for (var i = 0; i < areas.length; i++) {
        var code = areas[i].area_code;
        var name = areas[i].area_name;
        // Skip if duplicate or if it's "Any Other" from API (will add manually at end)
        if (seen[code] || name === 'Any Other') continue;
        seen[code] = true;
        var opt = document.createElement('option');
        opt.value = code; opt.textContent = name;
        sel.appendChild(opt);
      }
      // Add single "Any Other" at the end
      var otherOpt = document.createElement('option');
      otherOpt.value = 'OTHER'; otherOpt.textContent = 'Any Other';
      sel.appendChild(otherOpt);
    }
  };
  xhr.send();
}

// 2026-06-08: Populate the Add MGJ form's Batch Number dropdown from
// the MGJ Batch Management master, scoped to (state_code, centre_code)
// so a North Delhi PI sees only batches that belong to North Delhi.
// Preserves the current .value when the same batch_id still exists in
// the refreshed list (handy when an Edit hydrates the dropdown after
// _populateMgjBatchDropdown has already run via the cascade).
function _populateMgjBatchDropdown(stateCode, centreCode) {
  var sel = document.getElementById('mgjBatch');
  if (!sel) return;
  var prev = sel.value;
  sel.innerHTML = '<option value="">Select Batch</option>';
  if (!stateCode && !centreCode) return;
  var parts = [];
  if (stateCode)  parts.push('state_code='  + encodeURIComponent(stateCode));
  if (centreCode) parts.push('centre_code=' + encodeURIComponent(centreCode));
  var qs = parts.length ? '?' + parts.join('&') : '';
  apiGet('/mgj-master/dropdown/batches' + qs).then(function(rs) {
    var list = (rs && rs.data) ? rs.data : (Array.isArray(rs) ? rs : []);
    var s2 = document.getElementById('mgjBatch');
    if (!s2) return;
    var html = '<option value="">Select Batch</option>';
    var seen = {};
    list.forEach(function(b) {
      if (!b || b.id == null || seen[b.id]) return;
      seen[b.id] = 1;
      var label = (b.name || ('Batch ' + b.id)) + (b.year ? ' (' + b.year + ')' : '');
      html += '<option value="' + b.id + '">' + escHtml(label) + '</option>';
    });
    s2.innerHTML = html;
    // Restore prior selection if still in scope.
    if (prev && seen[prev]) s2.value = prev;
  }).catch(function() {});
}

function populateMgjReview() {
  // Renders the Review & Submit panel for the MGJ Member form.
  //
  // Refactored 2026-05-25: the previous version rendered only ~15 of ~30
  // form fields and was completely blind to the "Other / Specify" pattern
  // — when a user picked "Others" for Caste/Religion/Gender/Education or
  // "Yes" for Social Media / Azad-member-association / Still-Studying,
  // their typed-in Specify text never appeared in the review even though
  // the save handler stored it. Same story for the Work-Nature "Other"
  // checkbox. This version walks every field defined in the form and
  // surfaces the Specify companion whenever the trigger value is set.
  var content = document.getElementById('mgjReviewContent');
  if (!content) return;

  function _rv(id) { var el = document.getElementById(id); return el ? (el.value || '') : ''; }
  function _trim(s) { return (s || '').trim(); }
  function _row(l, v) { return '<div class="detail-item"><label>' + l + '</label><span>' + escHtml(v || '—') + '</span></div>'; }
  // 2026-06-08: Non-escaping sibling of _row. Caller takes responsibility
  // for the value's safety. Used by the per-member-details breakdown
  // (Women/Men Below 18, Women/Men Above 18) where the value is a pre-
  // built HTML fragment whose user-supplied bits were already passed
  // through escHtml. Without this, _row's escHtml() turned the HTML
  // into literal <div>/<span>/<b> text in the Review panel.
  function _rowHtml(l, v) { return '<div class="detail-item"><label>' + l + '</label><span>' + (v || '—') + '</span></div>'; }
  function _section(title, icon, rows) { return '<div class="view-section" style="margin-bottom:14px;"><h4><i class="fas fa-' + icon + '" style="color:#e67e22;margin-right:6px;"></i>' + title + '</h4><div class="detail-grid">' + rows + '</div></div>'; }

  // Renders "<main>" or "<main> — <specify>" when the user picked a
  // trigger value (defaults to "Others"). Mirrors how saveMgjRecord()
  // serialises these fields to the API, so what the user reviews here
  // is what actually gets saved.
  function _withSpecify(mainId, specifyId, trigger) {
    trigger = trigger || 'Others';
    var main = _rv(mainId);
    if (main === trigger) {
      var spec = _trim(_rv(specifyId));
      return trigger + (spec ? ' — ' + spec : '');
    }
    return main;
  }
  // Same shape for Yes/No fields that gate a follow-up text input.
  function _withFollowUp(mainId, followUpId, trigger) {
    trigger = trigger || 'Yes';
    var main = _rv(mainId);
    if (main === trigger) {
      var fu = _trim(_rv(followUpId));
      return trigger + (fu ? ' — ' + fu : '');
    }
    return main;
  }
  // Work-Nature checkbox group: collect picks, and if "Other" is among
  // them, replace it with "Other — <specify text>".
  function _workNature() {
    var picks = [];
    document.querySelectorAll('input[name="mgjWorkNature"]:checked').forEach(function(cb) { picks.push(cb.value); });
    var i = picks.indexOf('Other');
    if (i >= 0) {
      var spec = _trim(_rv('mgjWorkNatureOther'));
      picks[i] = 'Other' + (spec ? ' — ' + spec : '');
    }
    return picks.join(', ');
  }

  // ── Basic Profile ─────────────────────────────────────────────────
  var basic = '';
  basic += _row('Name',                  _rv('mgjName'));
  basic += _row('Date of Birth',         _rv('mgjDob'));
  basic += _row('Age at Enrollment',     _rv('mgjAge'));
  basic += _row('Address',               _rv('mgjAddress'));
  basic += _row('Mobile',                _rv('mgjMobile'));
  basic += _row('Caste Category',        _withSpecify('mgjCaste',    'mgjCasteOther'));
  basic += _row('Community (Religion)',  _withSpecify('mgjReligion', 'mgjReligionOther'));
  basic += _row('Gender',                _withSpecify('mgjGender',   'mgjGenderOther'));
  basic += _row('Social Media Account',  _withFollowUp('mgjSocialMedia', 'mgjSocialMediaDetails'));
  basic += _row('Group Number',          _rv('mgjGroup'));
  var marital = _rv('mgjMarital');
  basic += _row('Marital Status', marital);
  // Mirror the form-rule (2026-05-27): Age at Marriage + Number of Children
  // are only meaningful — and only filled by the user — when marital status
  // is Married / Separated / Divorced / Widow. Hide them on the review for
  // other statuses so the reviewer doesn't see "—" rows for irrelevant fields.
  if (_MGJ_MARITAL_WITH_KIDS.indexOf(marital) !== -1) {
    basic += _row('Age at Marriage',  _rv('mgjAgeAtMarriage'));
    basic += _row('Number of Children', _rv('mgjChildren'));
  }

  // ── Family Details ────────────────────────────────────────────────
  var fam = '';
  fam += _row('Number of Family Members',  _rv('mgjFamilyCount'));
  fam += _row('Earning Members',           _rv('mgjEarningMembers'));
  fam += _row('Monthly Family Income',     _rv('mgjFamilyIncome'));
  fam += _row('Per Capita Income',         _rv('mgjPerCapita'));
  fam += _row('Women members - below 18',  _rv('mgjWomenBelow18'));
  fam += _row('Men members - below 18',    _rv('mgjMenBelow18'));
  fam += _row('Women members - above 18',  _rv('mgjWomenAbove18'));
  fam += _row('Men members - above 18',    _rv('mgjMenAbove18'));
  // Per-member breakdown cards — read live from the form's dynamic cards
  // since they were freshly built/hydrated by the Edit hydrate path.
  var _famBreakdown = (typeof collectMgjFamDetails === 'function') ? collectMgjFamDetails() : null;
  if (_famBreakdown) {
    var _famLabels = {
      women_below_18: { title: 'Women below 18 — per-member details',  fields: [['edu','Education']] },
      men_below_18:   { title: 'Men below 18 — per-member details',    fields: [['edu','Education']] },
      women_above_18: { title: 'Women above 18 — per-member details',  fields: [['act','Currently Doing'], ['mar','Marital Status']] },
      men_above_18:   { title: 'Men above 18 — per-member details',    fields: [['act','Currently Doing'], ['mar','Marital Status']] }
    };
    Object.keys(_famLabels).forEach(function(key) {
      var arr = _famBreakdown[key] || [];
      if (!arr.length) return;
      var spec = _famLabels[key];
      var lines = arr.map(function(entry, idx) {
        var parts = spec.fields.map(function(f) {
          var v = entry[f[0]] || '—';
          // If the dropdown value is "Other" and a Specify follow-up exists,
          // render it inline as "Other (free text)" for clarity.
          var specKey = f[0] + '_spec';
          if (v === 'Other' && entry[specKey]) {
            v = 'Other (' + escHtml(entry[specKey]) + ')';
            return f[1] + ': <b>' + v + '</b>';
          }
          return f[1] + ': <b>' + escHtml(v) + '</b>';
        }).join(' &nbsp;·&nbsp; ');
        return '<div style="padding:4px 0;border-bottom:1px dashed #eee;font-size:12px;">' +
               '<span style="color:#732269;font-weight:600;">Member ' + (idx + 1) + ':</span> ' +
               parts + '</div>';
      }).join('');
      fam += _rowHtml(spec.title, '<div style="display:block;">' + lines + '</div>');
    });
  }
  fam += _row("Any women member associated with Azad's Program",
              _withFollowUp('mgjWomenInAzad', 'mgjWomenInAzadRel'));
  fam += _row("Any men member associated with Azad's Program",
              _withFollowUp('mgjMenInAzad',   'mgjMenInAzadRel'));

  // ── Education ─────────────────────────────────────────────────────
  var edu = '';
  edu += _row('Education Qualification', _withSpecify('mgjEducation', 'mgjEducationOther'));
  edu += _row('Year of qualification', _rv('mgjEducationYear'));
  edu += _row('Are you still studying?', _rv('mgjStillStudying'));

  // ── Work Status & Details ─────────────────────────────────────────
  var work = '';
  // 2026-05-27 — Career/Educational Status replaced by Are You Working?
  work += _row('Are you working?', _rv('mgjIsWorking'));
  work += _row('Nature of Work',            _workNature());
  work += _row('Where are you working',     _rv('mgjWorkPlace'));
  work += _row('Monthly Income',            _rv('mgjIncome'));
  work += _row('Future Goal',               _rv('mgjFutureGoal'));

  content.innerHTML =
    _section('Basic Profile',         'user',           basic) +
    _section('Family Details',        'users',          fam) +
    _section('Education',             'graduation-cap', edu) +
    _section('Work Status & Details', 'briefcase',      work) +
    '<p style="color:#666;font-size:13px;font-style:italic;margin-top:12px;">' +
    '<i class="fas fa-info-circle"></i> Review all details. Click "Review &amp; Edit" to modify, or "Save" to submit.</p>';
}

function saveMgjRecord(asDraft) {
  // `asDraft = true` is the Save-as-Draft path. It relaxes required-field
  // validation so a PI can park a half-filled MGJ record and finish later.
  // The full submit path is still gated by the existing validators below.
  //
  // Draft minimum requirements: Name + State + Centre + Area + Group. We
  // need at least those because the enrollment_number generated by the
  // backend is derived from the geography, and the row is invisible /
  // unfindable in the list without a Name. Everything else is optional
  // in draft mode and saved as NULL / blank.
  //
  // Status:  asDraft=true → 'Draft'    asDraft=false → 'Active'
  // 7-day edit window for Drafts is enforced in openEditMgj (mirrors FLP).
  asDraft = !!asDraft;

  // Helper to get value and highlight error
  function _v(id) { var el = document.getElementById(id); return el ? (el.value || '').trim() : ''; }
  function _err(id, msg, tab) {
    var el = document.getElementById(id);
    if (el) { el.style.borderColor = '#e74c3c'; el.focus(); }
    alert(msg);
    if (tab) switchMgjTab(tab);
    // Reset border after 3s
    setTimeout(function() { if (el) el.style.borderColor = ''; }, 3000);
    return true;
  }

  // ---- Draft mode: only the bare-minimum required to make the row
  //      identifiable + generate the enrollment number. Skip everything
  //      else and let the user come back to finish within 7 days.
  if (asDraft) {
    if (!_v('mgjState'))  return _err('mgjState',  'To save a draft, please pick a State.',  'basicProfile');
    if (!_v('mgjCentre')) return _err('mgjCentre', 'To save a draft, please pick a Centre.', 'basicProfile');
    if (!_v('mgjArea'))   return _err('mgjArea',   'To save a draft, please pick an Area.',  'basicProfile');
    if (!_v('mgjGroup'))  return _err('mgjGroup',  'To save a draft, please pick a Group Number.', 'basicProfile');
    if (!_v('mgjName'))   return _err('mgjName',   'To save a draft, please enter the Name.', 'basicProfile');
    // Mobile is only validated for format if entered.
    var draftMobile = _v('mgjMobile');
    if (draftMobile && draftMobile.length !== 10) {
      return _err('mgjMobile', 'Mobile Number must be exactly 10 digits (or leave blank for the draft).', 'basicProfile');
    }
    // DOB age range only validated if entered.
    if (_v('mgjDob')) {
      var dobD = new Date(_v('mgjDob')); var nowD = new Date();
      if (dobD > nowD) return _err('mgjDob', 'Date of Birth cannot be a future date.', 'basicProfile');
      var ageD = nowD.getFullYear() - dobD.getFullYear();
      var mdD = nowD.getMonth() - dobD.getMonth();
      if (mdD < 0 || (mdD === 0 && nowD.getDate() < dobD.getDate())) ageD--;
      if (ageD < 13 || ageD > 25) {
        return _err('mgjDob', 'Age must be between 13 and 25 years (current: ' + ageD + ').', 'basicProfile');
      }
    }
    // Skip every other field-level validation — jump straight to payload.
  } else {
    // Submit-time validation gauntlet (unchanged) follows.

  // ---- Basic Profile validations ----
  if (!_v('mgjState')) return _err('mgjState', 'Please select a State.', 'basicProfile');
  if (!_v('mgjCentre')) return _err('mgjCentre', 'Please select a Centre.', 'basicProfile');
  if (!_v('mgjArea')) return _err('mgjArea', 'Please select an Area.', 'basicProfile');
  if (!_v('mgjGroup')) return _err('mgjGroup', 'Please select the Group Number.', 'basicProfile');
  if (!_v('mgjName')) return _err('mgjName', 'Please enter the Name.', 'basicProfile');
  if (!_v('mgjDob')) return _err('mgjDob', 'Please enter Date of Birth.', 'basicProfile');
  if (!_v('mgjAddress')) return _err('mgjAddress', 'Please enter the Address.', 'basicProfile');
  // Mobile is now required AND must be exactly 10 digits (rule 2026-05-27).
  // The input's oninput already strips non-digits and maxlength caps to 10,
  // so the only failure modes here are "empty" or "shorter than 10".
  var mobile = _v('mgjMobile');
  if (!mobile) return _err('mgjMobile', 'Please enter the 10-digit Mobile Number.', 'basicProfile');
  if (mobile.length !== 10) return _err('mgjMobile', 'Mobile Number must be exactly 10 digits.', 'basicProfile');

  // ---- Family Details validations ----
  if (!_v('mgjFamilyCount')) return _err('mgjFamilyCount', 'Please enter Number of Family Members.', 'family');
  if (!_v('mgjEarningMembers')) return _err('mgjEarningMembers', 'Please enter number of earning members.', 'family');
  if (!_v('mgjFamilyIncome')) return _err('mgjFamilyIncome', 'Please enter Monthly Family Income.', 'family');
  // 2026-06-03: reject zero or negative income amounts. Input regex already
  // strips non-digits so this is mainly a guard against 0 and against any
  // value that somehow squeaks through (paste, browser auto-fill, API replay).
  var _incomeVal = parseFloat(_v('mgjFamilyIncome'));
  if (isNaN(_incomeVal) || _incomeVal <= 0) {
    return _err('mgjFamilyIncome',
      'Monthly Family Income must be greater than 0. Zero or negative amounts are not allowed.',
      'family');
  }
  if (!_v('mgjWomenInAzad')) return _err('mgjWomenInAzad', 'Please select if any women member associated with Azad.', 'family');
  if (_v('mgjWomenInAzad') === 'Yes' && !_v('mgjWomenInAzadRel')) return _err('mgjWomenInAzadRel', 'Please enter relation (women member).', 'family');
  if (!_v('mgjMenInAzad')) return _err('mgjMenInAzad', 'Please select if any men member associated with Azad.', 'family');
  if (_v('mgjMenInAzad') === 'Yes' && !_v('mgjMenInAzadRel')) return _err('mgjMenInAzadRel', 'Please enter relation (men member).', 'family');

  // Sum-check (rule 2026-05-27): the four age/gender buckets must add up
  // to the family-members count entered above. The user IS one of the four,
  // so the total includes self. We only run the check if all four buckets
  // have a value — leaving any of them blank means "user hasn't broken it
  // down yet" and would be a different validation problem (not the user's
  // current ask). 0 is a valid bucket value (e.g. no women below 18).
  var _famCount   = parseInt(_v('mgjFamilyCount'),   10);
  var _wB         = parseInt(_v('mgjWomenBelow18'),  10);
  var _mB         = parseInt(_v('mgjMenBelow18'),    10);
  var _wA         = parseInt(_v('mgjWomenAbove18'),  10);
  var _mA         = parseInt(_v('mgjMenAbove18'),    10);
  if (!isNaN(_famCount) && [_wB, _mB, _wA, _mA].every(function(x) { return !isNaN(x); })) {
    var _sum = _wB + _mB + _wA + _mA;
    if (_sum !== _famCount) {
      return _err('mgjWomenBelow18',
        'Family-member breakdown must add up to ' + _famCount + ' (Number of Family Members). ' +
        'Current sum is ' + _sum + '. Adjust the Women/Men below-18 and above-18 counts.',
        'family');
    }
  }

  // ---- Logical-consistency validation (2026-06-03) ----
  // Family-size sanity: Number of Family Members must be a positive
  // integer (>0) and Earning Members can never exceed it.
  if (!isNaN(_famCount) && _famCount <= 0) {
    return _err('mgjFamilyCount',
      'Number of Family Members must be greater than 0.',
      'family');
  }
  var _earnCount = parseInt(_v('mgjEarningMembers'), 10);
  if (!isNaN(_earnCount) && _earnCount < 0) {
    return _err('mgjEarningMembers',
      'Earning Members cannot be negative.',
      'family');
  }
  if (!isNaN(_famCount) && !isNaN(_earnCount) && _earnCount > _famCount) {
    return _err('mgjEarningMembers',
      'Earning Members (' + _earnCount + ') cannot exceed Number of Family Members (' + _famCount + ').',
      'family');
  }

  // ---- Dynamic family-member detail validation (skipped for Draft) ----
  // When count > 0 the per-member Education / Activity / Marital fields are required.
  if (!asDraft && typeof validateMgjFamDetails === 'function') {
    var famErr = validateMgjFamDetails();
    if (famErr) {
      switchMgjTab('family');
      var fEl = document.getElementById(famErr.focusId);
      if (fEl) { try { fEl.scrollIntoView({behavior:'smooth', block:'center'}); } catch(e){} setTimeout(function(){ fEl.focus(); }, 250); }
      alert(famErr.message);
      return;
    }
  }

  // ---- Education validations ----
  // 2026-05-27: Year is required; range checked client-side. studying_what
  // is gone (UI removed) so its validator went too. The "Is working?" gate
  // on the Work tab adds a new required check below.
  if (!_v('mgjEducationYear')) return _err('mgjEducationYear', 'Please enter the Year of qualification.', 'education');
  var _eyVal = parseInt(_v('mgjEducationYear'), 10);
  var _currYr = new Date().getFullYear();
  if (isNaN(_eyVal) || _eyVal < 1950 || _eyVal > _currYr) {
    return _err('mgjEducationYear', 'Year must be between 1950 and ' + _currYr + '.', 'education');
  }
  // 2026-06-03: educational timeline must follow birth year. Qualification
  // Year can't predate (or equal) DOB year — you can't earn a credential
  // before you're born. Reject "DOB 2005 + Qualification 1999" patterns.
  if (_v('mgjDob')) {
    var _dobYr = new Date(_v('mgjDob')).getFullYear();
    if (!isNaN(_dobYr) && !isNaN(_eyVal) && _eyVal < _dobYr) {
      return _err('mgjEducationYear',
        'Year of qualification (' + _eyVal + ') cannot be earlier than the year of birth (' + _dobYr + ').',
        'education');
    }
  }
  if (!_v('mgjEducation')) return _err('mgjEducation', 'Please select Education Qualification.', 'education');
  if (_v('mgjEducation') === 'Others' && !_v('mgjEducationOther')) return _err('mgjEducationOther', 'Please specify education details.', 'education');
  // ---- Work validations ----
  if (!_v('mgjIsWorking')) return _err('mgjIsWorking', 'Please select Yes or No for "Are you working?".', 'work');

  // Other-Specify validations
  if (_v('mgjCaste') === 'Others') {
    var co = document.getElementById('mgjCasteOther');
    if (!co || !co.value.trim()) return _err('mgjCasteOther', 'Please specify caste category.', 'basicProfile');
  }
  if (_v('mgjReligion') === 'Others') {
    var ro = document.getElementById('mgjReligionOther');
    if (!ro || !ro.value.trim()) return _err('mgjReligionOther', 'Please specify religion.', 'basicProfile');
  }
  if (_v('mgjGender') === 'Others') {
    var go = document.getElementById('mgjGenderOther');
    if (!go || !go.value.trim()) return _err('mgjGenderOther', 'Please specify gender.', 'basicProfile');
  }
  // DOB validations:
  //   1. Cannot be a future date.
  //   2. Computed age must be in [13, 25] inclusive (rule 2026-05-27).
  // Age is recomputed here (not read from the auto-calc field) so a user
  // editing the date right before submit can't slip through with a stale
  // value in #mgjAge.
  if (_v('mgjDob')) {
    var dob = new Date(_v('mgjDob'));
    var _now = new Date();
    if (dob > _now) return _err('mgjDob', 'Date of Birth cannot be a future date.', 'basicProfile');
    var _age = _now.getFullYear() - dob.getFullYear();
    var _md  = _now.getMonth() - dob.getMonth();
    if (_md < 0 || (_md === 0 && _now.getDate() < dob.getDate())) _age--;
    if (_age < 13 || _age > 25) {
      return _err('mgjDob', 'Age must be between 13 and 25 years. Current age from Date of Birth is ' + _age + '.', 'basicProfile');
    }
  }
  }  // end of `if (!asDraft) { ... validation gauntlet ... }`

  // Mobile may be untouched on the Draft path — pick it up safely here so
  // it's defined in both branches before the payload is built.
  if (typeof mobile === 'undefined') {
    mobile = _v('mgjMobile');
  }

  // Collect work nature checkboxes. On Draft, the "Other"-specify check
  // is relaxed — we just take whatever is checked and serialise it
  // without insisting on a Specify text.
  var workNature = [];
  document.querySelectorAll('input[name="mgjWorkNature"]:checked').forEach(function(cb) { workNature.push(cb.value); });
  if (workNature.indexOf('Other') >= 0) {
    var wno = document.getElementById('mgjWorkNatureOther');
    if (!asDraft && (!wno || !wno.value.trim())) {
      return _err('mgjWorkNatureOther', 'Please specify the nature of work.', 'work');
    }
    var wnoText = wno ? (wno.value || '').trim() : '';
    workNature = workNature.filter(function(v) { return v !== 'Other'; });
    workNature.push(wnoText ? ('Other: ' + wnoText) : 'Other');
  }

  var data = {
    name: _v('mgjName'),
    date_of_birth: _v('mgjDob') || null,
    age_at_enrollment: parseInt(_v('mgjAge')) || null,
    mobile: mobile || null,
    address: _v('mgjAddress') || null,
    state_code: _v('mgjState'),
    centre_code: _v('mgjCentre') || null,
    area_code: _v('mgjArea') || null,
    // 2026-06-08: Batch Number FK — optional. Sent as integer when set,
    // null when the user left it on the placeholder. parseInt guards
    // against the dropdown value being a numeric-as-string.
    batch_id: (function() { var v = _v('mgjBatch'); return v ? parseInt(v, 10) || null : null; })(),
    group_number: _v('mgjGroup'),
    caste_category: (function() { var v = (document.getElementById('mgjCaste') || {}).value; return v === 'Others' ? 'Others: ' + ((document.getElementById('mgjCasteOther') || {}).value || '') : v || null; })(),
    community_religion: (function() { var v = (document.getElementById('mgjReligion') || {}).value; return v === 'Others' ? 'Others: ' + ((document.getElementById('mgjReligionOther') || {}).value || '') : v || null; })(),
    gender: (function() { var v = (document.getElementById('mgjGender') || {}).value; return v === 'Others' ? 'Others: ' + ((document.getElementById('mgjGenderOther') || {}).value || '') : v || null; })(),
    social_media_account: (document.getElementById('mgjSocialMedia') || {}).value || null,
    social_media_details: (document.getElementById('mgjSocialMediaDetails') || {}).value || null,
    marital_status: (document.getElementById('mgjMarital') || {}).value || null,
    age_at_marriage: parseInt((document.getElementById('mgjAgeAtMarriage') || {}).value) || null,
    number_of_children: parseInt((document.getElementById('mgjChildren') || {}).value) || null,
    // Family
    family_members_count: parseInt((document.getElementById('mgjFamilyCount') || {}).value) || null,
    earning_members: parseInt((document.getElementById('mgjEarningMembers') || {}).value) || null,
    monthly_family_income: parseFloat((document.getElementById('mgjFamilyIncome') || {}).value) || null,
    per_capita_income: parseFloat((document.getElementById('mgjPerCapita') || {}).value) || null,
    women_below_18: parseInt((document.getElementById('mgjWomenBelow18') || {}).value) || null,
    men_below_18: parseInt((document.getElementById('mgjMenBelow18') || {}).value) || null,
    women_above_18: parseInt((document.getElementById('mgjWomenAbove18') || {}).value) || null,
    men_above_18: parseInt((document.getElementById('mgjMenAbove18') || {}).value) || null,
    women_in_azad: (document.getElementById('mgjWomenInAzad') || {}).value || null,
    women_in_azad_relation: (document.getElementById('mgjWomenInAzadRel') || {}).value || null,
    men_in_azad: (document.getElementById('mgjMenInAzad') || {}).value || null,
    men_in_azad_relation: (document.getElementById('mgjMenInAzadRel') || {}).value || null,
    // Dynamic per-member breakdowns — JSONB column on mgj_members.
    family_member_details: (typeof collectMgjFamDetails === 'function') ? collectMgjFamDetails() : null,
    // Education
    education: (document.getElementById('mgjEducation') || {}).value || null,
    education_other: (document.getElementById('mgjEducationOther') || {}).value || null,
    education_year: parseInt((document.getElementById('mgjEducationYear') || {}).value, 10) || null,
    still_studying: (document.getElementById('mgjStillStudying') || {}).value || null,
    // studying_what column is kept in DB for legacy data; UI removed
    // 2026-05-27. Always send null so the value isn't accidentally
    // copied across edits.
    studying_what: null,
    // Work — "Are you working?" now gates the detail block. When 'No',
    // we explicitly null out the work-detail fields so a partially-filled
    // form doesn't persist stale data.
    is_working: (document.getElementById('mgjIsWorking') || {}).value || null,
    // career_status column kept for legacy data; UI replaced 2026-05-27.
    career_status: null,
    work_nature: ((document.getElementById('mgjIsWorking') || {}).value === 'Yes' && workNature.length)
                 ? workNature.join(', ') : null,
    work_place:    ((document.getElementById('mgjIsWorking') || {}).value === 'Yes')
                 ? ((document.getElementById('mgjWorkPlace') || {}).value || null) : null,
    monthly_income:((document.getElementById('mgjIsWorking') || {}).value === 'Yes')
                 ? (parseFloat((document.getElementById('mgjIncome') || {}).value) || null) : null,
    future_goal: (document.getElementById('mgjFutureGoal') || {}).value || null,
    status: asDraft ? 'Draft' : 'Active',
  };

  var _draftMsg     = ' saved as Draft. You can come back to finish it within 7 days.';
  var _submitMsg    = '!';
  var _isEditMode   = mgjFormMode === 'edit' && editingMgjId;
  var _verb         = _isEditMode ? 'updated' : 'created';
  var _saveLabel    = asDraft ? 'MGJ member ' + _verb + _draftMsg
                              : 'MGJ member ' + _verb + _submitMsg;

  var _afterSave = function(resp) {
    // 2026-07-06: Upload the picked photo BEFORE navigating away. This was
    // the missing half of the MGJ photo feature — previewMgjPhoto captured
    // the file into mgjSelectedPhoto but nothing ever uploaded it, so
    // photo_url stayed NULL in the DB. Mirrors the AK save flow
    // (apiAkUploadPhoto after apiCreateAk/apiUpdateAk).
    var savedId = (resp && resp.id) || editingMgjId;
    var _finish = function() {
      alert(_saveLabel);
      // On a Submit (asDraft=false) we navigate back to the list — that's
      // the existing behavior. On a Draft save we ALSO navigate back so
      // the user can see the row appear with the orange "Draft" badge in
      // the list (matches FLP). They can re-open it from the list to
      // continue editing — the 7-day window starts from the first save.
      navigateTo('mgjList');
    };
    if (mgjSelectedPhoto && savedId) {
      apiMgjUploadPhoto(savedId, mgjSelectedPhoto).then(function() {
        mgjSelectedPhoto = null;
        // Clear the file input so the NEXT member's photo pick always
        // fires onchange, even if it's the same file (SPA — the input
        // persists across members; this was why "update image on one
        // user, then another" silently did nothing until a refresh).
        var _pi = document.getElementById('mgjPhotoInput');
        if (_pi) _pi.value = '';
        _finish();
      }).catch(function(err) {
        // Member record itself saved fine — don't block the flow, but
        // tell the user the photo specifically failed so they can retry
        // from Edit rather than assuming everything persisted.
        mgjSelectedPhoto = null;
        var _pi = document.getElementById('mgjPhotoInput');
        if (_pi) _pi.value = '';
        alert('Member saved, but the photo upload failed: ' + (err && err.message ? err.message : 'unknown error') + '\nOpen the member in Edit and re-select the photo to retry.');
        navigateTo('mgjList');
      });
    } else {
      _finish();
    }
  };

  if (_isEditMode) {
    apiUpdateMgj(editingMgjId, data).then(_afterSave)
      .catch(function(err) { showUserError('processing your request', err); });
  } else {
    apiCreateMgj(data).then(_afterSave)
      .catch(function(err) { showUserError('processing your request', err); });
  }
}

// ---- VIEW MGJ ----
function viewMgjDetail(id) {
  viewingMgjId = id;
  _ctxSet('viewMgj', id);
  navigateTo('viewMgj');
}

function loadMgjDetail(id) {
  function _d(label, val) { return '<div class="detail-item"><label>' + label + '</label><span>' + escHtml(val || '—') + '</span></div>'; }
  function _dFull(label, val) { return '<div class="detail-item full-width"><label>' + label + '</label><span>' + escHtml(val || '—') + '</span></div>'; }
  function _dMoney(label, val) { return '<div class="detail-item"><label>' + label + '</label><span>' + (val ? '\u20B9' + formatNumber(val) : '—') + '</span></div>'; }

  apiMgjDetail(id).then(function(m) {
    // FLP-style profile header: name in <h2>, secondary summary line in <p>
    // Status badge goes FIRST in the summary line (mirrors FLP) so the
    // "Dropout" pill renders directly below the member name — the most
    // glanceable position for the at-a-glance state of the record.
    document.getElementById('mgjViewName').textContent = m.name || '—';
    // 2026-07-06: Render the member photo in the profile header. The view
    // page previously had NO photo rendering at all — only the static
    // user-circle icon — even though the backend GET returns photo_url
    // (SELECT m.*). Mirrors the AK view (akViewPhotoContainer) with the
    // FLP view's URL construction (API_BASE.replace('/api','') + relative
    // /uploads/... path).
    var _photoC = document.getElementById('mgjViewPhoto');
    if (_photoC) {
      _photoC.innerHTML = m.photo_url
        ? '<img src="' + API_BASE.replace('/api', '') + m.photo_url + '" alt="Photo" style="width:80px;height:80px;border-radius:50%;object-fit:cover;">'
        : '<i class="fas fa-user-circle" style="font-size:80px;color:#732269;"></i>';
    }
    var sumParts = [
      m.enrollment_number || '',
      m.group_number ? 'Group ' + m.group_number : '',
      [m.area_name || m.area_code, m.centre_name, m.state_name].filter(Boolean).join(', '),
    ].filter(Boolean);
    var summaryEl = document.getElementById('mgjViewSummary');
    if (summaryEl) {
      summaryEl.innerHTML = statusBadge(m.status) +
        ' &nbsp; ' + sumParts.map(escHtml).join(' &nbsp;·&nbsp; ');
    }

    // Show/hide Dropout button — only for Active members (mirrors FLP/AK).
    // Already-dropped-out members cannot be dropped out twice; viewing one
    // hides the button entirely.
    var woBtn = document.getElementById('btnMgjWalkOut');
    if (woBtn) {
      woBtn.style.display = (m.status === 'Active') ? 'inline-flex' : 'none';
    }

    // Section 1: Basic Profile
    var bg = document.getElementById('mgjViewBasicGrid');
    if (bg) {
      bg.innerHTML =
        _d('State', m.state_name) +
        _d('Centre', m.centre_name) +
        _d('Area', m.area_name || m.area_code) +
        // 2026-06-08: Batch Number — same source (mgj_master_batches)
        // as the new Batch column in the list. m.batch_name comes from
        // the LEFT JOIN in routes/mgj.py::get_mgj.
        _d('Batch Number', m.batch_name) +
        _d('Group Number', m.group_number) +
        _d('1. Name', m.name) +
        _d('2. Date of Birth', m.date_of_birth ? formatDateNice(m.date_of_birth) : null) +
        // 2026-05-28: Present Age cell rendered beside Age at Enrollment.
        // Computed live from m.date_of_birth — view-only, not persisted.
        _d('3. Age at Enrollment', m.age_at_enrollment != null ? String(m.age_at_enrollment) : null) +
        _d('Present Age', (function() { var pa = _computePresentAge(m.date_of_birth); return pa != null ? String(pa) + ' years' : null; })()) +
        _dFull('4. Address', m.address) +
        _d('5. Mobile Number', m.mobile) +
        _d('6. Caste Category', m.caste_category) +
        _d('7. Community (Religion)', m.community_religion) +
        _d('8. Gender', m.gender) +
        _d('9. Social Media Account', m.social_media_account) +
        _d('10. Social Media Details', m.social_media_details) +
        _d('11. Marital Status', m.marital_status) +
        _d('12. Age at Marriage', m.age_at_marriage != null ? String(m.age_at_marriage) : null) +
        _d('13. Number of Children', m.number_of_children != null ? String(m.number_of_children) : null);
    }

    // Section 2: Family Details
    var fg = document.getElementById('mgjViewFamilyGrid');
    if (fg) {
      fg.innerHTML =
        _d('14. Number of Family Members', m.family_members_count != null ? String(m.family_members_count) : null) +
        _d('15. Earning Members', m.earning_members != null ? String(m.earning_members) : null) +
        _dMoney('16. Monthly Family Income', m.monthly_family_income) +
        _dMoney('17. Per Capita Income', m.per_capita_income) +
        _d('18. Women Below 18', m.women_below_18 != null ? String(m.women_below_18) : null) +
        _d('19. Men Below 18', m.men_below_18 != null ? String(m.men_below_18) : null) +
        _d('20. Women Above 18', m.women_above_18 != null ? String(m.women_above_18) : null) +
        _d('21. Men Above 18', m.men_above_18 != null ? String(m.men_above_18) : null) +
        _d('22. Any Women Member Associated with Azad', m.women_in_azad) +
        _d('23. Women Member Relation', m.women_in_azad_relation) +
        _d('24. Any Men Member Associated with Azad', m.men_in_azad) +
        _d('25. Men Member Relation', m.men_in_azad_relation);
    }

    // Section 3: Education Details (now with multi-entry history)
    var eg = document.getElementById('mgjViewEducationGrid');
    if (eg) {
      eg.innerHTML =
        _d('Year of qualification', m.education_year != null ? String(m.education_year) : null) +
        _d('Education Qualification', m.education) +
        _d('Education (Other)', m.education_other) +
        _d('Still Studying', m.still_studying);
    }
    // Load the per-member education history into the table below the
    // primary grid. The "Add current education qualification" button
    // (rendered statically in index.html) opens openMgjAddEduEntryModal
    // which appends a row and triggers this same refresh on success.
    _mgjViewedMemberId = m.id;
    _refreshMgjEduHistoryTable();

    // Section 4: Work Status & Details — "Are you working?" replaces
    // the legacy free-text "Career Status". When "No", the detail rows
    // (Where / Income / Nature) are hidden in the View; we still render
    // any legacy values for backward compatibility.
    var wg = document.getElementById('mgjViewWorkGrid');
    if (wg) {
      var rows = _d('Are you working?', m.is_working);
      if (m.is_working === 'Yes' || m.work_nature || m.work_place || m.monthly_income) {
        rows +=
          _d('Nature of Work', m.work_nature) +
          _d('Work Place', m.work_place) +
          _dMoney('Monthly Income', m.monthly_income);
      }
      rows += _dFull('Future Goal / Aspiration', m.future_goal);
      wg.innerHTML = rows;
    }
  }).catch(function(err) {
    console.error('MGJ view error:', err);
    var bg = document.getElementById('mgjViewBasicGrid');
    if (bg) bg.innerHTML = '<p style="color:red;">Error loading MGJ member details.</p>';
  });
}

function editMgjFromView() {
  if (viewingMgjId) openEditMgj(viewingMgjId);
}

// ─────────────────────────────────────────────────────────────────────
// MGJ Member education-history modal (View page).
// The "Add current education qualification" button is rendered
// statically on page-viewMgj and never removed — clicking it always
// opens openMgjAddEduEntryModal, which loads the modal's blank form.
// On Save, the entry posts to /api/mgj/{member_id}/education and the
// history table on the View page refreshes immediately. Delete on a
// row also refreshes immediately. _mgjViewedMemberId tracks the
// currently-open member so the modal knows where to attach.
// ─────────────────────────────────────────────────────────────────────
var _mgjViewedMemberId = null;

function openMgjAddEduEntryModal() {
  if (!_mgjViewedMemberId) return;
  // Reset the modal each time so a stale value from a previous open
  // doesn't survive into a new entry.
  var y  = document.getElementById('mgjEduEntryYear');         if (y)  y.value = '';
  var q  = document.getElementById('mgjEduEntryQualification');if (q)  q.selectedIndex = 0;
  var qo = document.getElementById('mgjEduEntryOther');        if (qo) qo.value = '';
  var og = document.getElementById('mgjEduEntryOtherGrp');     if (og) og.style.display = 'none';
  var st = document.getElementById('mgjEduEntryStatus');       if (st) st.textContent = '';
  // Clamp year input's max to the current year (matches the form rule).
  if (y) y.max = String(new Date().getFullYear());
  document.getElementById('mgjEduHistoryModal').style.display = 'flex';
}

function saveMgjEduEntry() {
  if (!_mgjViewedMemberId) return;
  var year = parseInt((document.getElementById('mgjEduEntryYear') || {}).value, 10);
  var qual = ((document.getElementById('mgjEduEntryQualification') || {}).value || '').trim();
  var other = ((document.getElementById('mgjEduEntryOther') || {}).value || '').trim();
  var status = document.getElementById('mgjEduEntryStatus');
  var btn    = document.getElementById('mgjEduEntrySaveBtn');
  if (!qual)             { if (status) status.textContent = 'Please pick a Qualification.'; return; }
  var cy = new Date().getFullYear();
  if (!year || year < 1950 || year > cy) {
    if (status) status.textContent = 'Year must be between 1950 and ' + cy + '.';
    return;
  }
  if (qual === 'Others' && !other) {
    if (status) status.textContent = 'Please specify the qualification.';
    return;
  }
  if (status) status.textContent = '';
  if (btn) btn.disabled = true;
  apiMgjAddEducation(_mgjViewedMemberId, {
    year: year, qualification: qual, qualification_other: other || null,
  }).then(function() {
    if (btn) btn.disabled = false;
    closeMasterModal('mgjEduHistoryModal');
    _refreshMgjEduHistoryTable();
  }).catch(function(err) {
    if (btn) btn.disabled = false;
    if (status) status.textContent = (err && err.message) ? err.message : 'Could not save. Try again.';
  });
}

function _refreshMgjEduHistoryTable() {
  if (!_mgjViewedMemberId) return;
  var tbl  = document.getElementById('mgjEduHistoryTable');
  var body = document.getElementById('mgjEduHistoryBody');
  if (!tbl || !body) return;
  apiMgjListEducation(_mgjViewedMemberId).then(function(rows) {
    if (!rows || !rows.length) {
      tbl.style.display = 'none';
      return;
    }
    tbl.style.display = '';
    body.innerHTML = rows.map(function(r) {
      var qual = escHtml(r.qualification || '—');
      if (r.qualification === 'Others' && r.qualification_other) {
        qual += ' — ' + escHtml(r.qualification_other);
      }
      return '<tr>'
        + '<td>' + (r.year != null ? r.year : '—') + '</td>'
        + '<td>' + qual + '</td>'
        + '<td style="text-align:center;">'
        +   '<button type="button" class="btn-icon" title="Delete" onclick="deleteMgjEduEntry(' + r.id + ')" style="color:#e74c3c;"><i class="fas fa-trash"></i></button>'
        + '</td>'
        + '</tr>';
    }).join('');
  }).catch(function() {
    tbl.style.display = '';
    body.innerHTML = '<tr><td colspan="3" style="text-align:center;color:#e74c3c;padding:14px;">Could not load education history.</td></tr>';
  });
}

function deleteMgjEduEntry(entryId) {
  if (!confirm('Delete this education entry? This cannot be undone.')) return;
  apiMgjDeleteEducation(entryId).then(function() {
    _refreshMgjEduHistoryTable();
  }).catch(function(err) {
    showUserError('deleting education entry', err);
  });
}

// ---- MGJ DROPOUT (mirrors FLP openWalkOutForm / submitWalkOut). The
// modal collects date + reason; backend POSTs to /api/mgj/{id}/walkout
// which sets status='Walkout' (rendered as "Dropout" via statusBadge).
function openMgjWalkOutForm() {
  var modal = document.getElementById('mgjWalkOutModal');
  if (!modal) return;
  var dateEl = document.getElementById('mgjWalkOutDate');
  if (dateEl) dateEl.value = new Date().toISOString().split('T')[0];
  var reasonEl = document.getElementById('mgjWalkOutReason');
  if (reasonEl) reasonEl.value = '';
  modal.style.display = 'flex';
}

function closeMgjWalkOutModal() {
  var modal = document.getElementById('mgjWalkOutModal');
  if (modal) modal.style.display = 'none';
}

function submitMgjWalkOut() {
  var dateEl = document.getElementById('mgjWalkOutDate');
  var reasonEl = document.getElementById('mgjWalkOutReason');
  var walkoutDate   = dateEl   ? dateEl.value : '';
  var walkoutReason = reasonEl ? reasonEl.value.trim() : '';
  if (!walkoutDate)   { alert('Please select the Date of Dropout.'); return; }
  if (!walkoutReason) { alert('Please enter the Reason for Dropout.'); return; }
  if (!confirm('Are you sure you want to mark this MGJ Member as Dropout? This action cannot be easily undone.')) return;
  var memberId = viewingMgjId;
  if (!memberId) { alert('MGJ Member ID not found.'); return; }
  apiPost('/mgj/' + memberId + '/walkout', {
    walkout_date: walkoutDate,
    walkout_reason: walkoutReason
  }).then(function() {
    alert('MGJ Member has been marked as Dropout successfully.');
    closeMgjWalkOutModal();
    loadMgjDetail(memberId);
  }).catch(function(err) {
    showUserError('processing dropout', err);
  });
}

// ---- MGJ Print / Download (mirror of openFlpDetailsPrintView). Opens a
// new window with the member's details rendered as printable HTML +
// a fixed top bar with Print and Download PDF buttons. Walks every
// `.view-section` block on page-viewMgj, harvesting either the
// `.detail-grid` items or any `<table>` content. The MGJ view page has
// no real photo upload (just an avatar icon) so the printout starts
// with the placeholder avatar; if MGJ ever gains photo support, the
// existing `viewMgjPhoto` <img> selector below will pick it up
// automatically.
function openMgjDetailsPrintView() {
  var pageEl = document.getElementById('page-viewMgj');
  if (!pageEl || !pageEl.classList.contains('active')) {
    alert('Please open an MGJ profile first.');
    return;
  }
  var name = (document.getElementById('mgjViewName') || {}).textContent || 'MGJ Member';
  // Summary line contains the status badge first (as innerHTML); for the
  // printout we want plain text so the badge renders as the word only.
  var summary = (document.getElementById('mgjViewSummary') || {}).textContent || '';
  var photoImg = document.getElementById('viewMgjPhoto');
  var photoSrc = '';
  if (photoImg && photoImg.style.display !== 'none' && photoImg.src) {
    photoSrc = photoImg.src;
  }

  var esc = function(s) {
    return String(s == null ? '' : s)
      .replace(/&/g, '&amp;').replace(/</g, '&lt;')
      .replace(/>/g, '&gt;').replace(/"/g, '&quot;');
  };

  // Walk every `.view-section` in document order; for each, grab its <h3>
  // heading and harvest either the `.detail-grid` items or the table
  // contents. Identical logic to openFlpDetailsPrintView — kept as a
  // sibling copy rather than abstracted so each module can evolve its
  // print layout independently (e.g. add module-specific footers).
  var sectionsHtml = '';
  var sections = pageEl.querySelectorAll('.view-section');
  for (var s = 0; s < sections.length; s++) {
    var sec = sections[s];
    var heading = sec.querySelector('h3');
    var headingText = heading ? heading.textContent.trim() : 'Details';

    var grid = sec.querySelector('.detail-grid');
    var table = sec.querySelector('table');
    var inner = '';

    if (grid) {
      var items = grid.querySelectorAll('.detail-item');
      var rows = '';
      for (var i = 0; i < items.length; i++) {
        var item = items[i];
        if (item.offsetParent === null) continue;
        var lab = item.querySelector('label');
        var val = null;
        for (var dc = 0; dc < item.children.length; dc++) {
          if (item.children[dc].tagName === 'SPAN') { val = item.children[dc]; break; }
        }
        if (!lab || !val) continue;
        var labText = lab.textContent.replace(/\*/g, '').replace(/\s+/g, ' ').trim();
        var valText = val.textContent.trim();
        if (!valText || valText === '-' || valText === '—') continue;
        rows += '<tr><th style="text-align:left;width:40%;padding:6px 10px;background:#faf3f8;border:1px solid #e5d4e2;font-weight:600;color:#732269;">' +
                esc(labText) + '</th><td style="padding:6px 10px;border:1px solid #e5d4e2;">' +
                esc(valText) + '</td></tr>';
      }
      if (rows) {
        inner = '<table style="width:100%;border-collapse:collapse;font-size:13px;margin-top:6px;">' + rows + '</table>';
      } else {
        continue;
      }
    } else if (table) {
      var theadCells = table.querySelectorAll('thead th');
      var tbodyRows = table.querySelectorAll('tbody tr');
      var hasReal = false;
      for (var r = 0; r < tbodyRows.length; r++) {
        var firstCell = tbodyRows[r].querySelector('td');
        if (firstCell && firstCell.getAttribute('colspan') == null) {
          hasReal = true; break;
        }
      }
      if (!hasReal) continue;
      var headHtml = '<tr>';
      for (var h = 0; h < theadCells.length; h++) {
        headHtml += '<th style="padding:6px 10px;background:#732269;color:#fff;border:1px solid #5e1c57;text-align:left;font-size:12px;">' +
                    esc(theadCells[h].textContent.trim()) + '</th>';
      }
      headHtml += '</tr>';
      var bodyHtml = '';
      for (var r2 = 0; r2 < tbodyRows.length; r2++) {
        var tds = tbodyRows[r2].querySelectorAll('td');
        if (tds.length === 0) continue;
        if (tds.length === 1 && tds[0].getAttribute('colspan') != null) continue;
        bodyHtml += '<tr>';
        for (var c = 0; c < tds.length; c++) {
          bodyHtml += '<td style="padding:6px 10px;border:1px solid #e5d4e2;font-size:12px;">' +
                      esc(tds[c].textContent.trim()) + '</td>';
        }
        bodyHtml += '</tr>';
      }
      inner = '<table style="width:100%;border-collapse:collapse;margin-top:6px;">' +
              '<thead>' + headHtml + '</thead><tbody>' + bodyHtml + '</tbody></table>';
    } else {
      continue;
    }

    sectionsHtml += '<section style="margin-top:18px;page-break-inside:avoid;">' +
                    '<h3 style="color:#732269;border-bottom:2px solid #732269;padding-bottom:4px;margin:0 0 6px 0;font-size:15px;">' +
                    esc(headingText) + '</h3>' + inner + '</section>';
  }

  var generatedAt = new Date().toLocaleString('en-IN', { timeZone: 'Asia/Kolkata' });
  var safeFile = String(name).replace(/[^a-z0-9_\- ]+/gi, '_').replace(/\s+/g, '_').slice(0, 60) || 'MGJ';
  var pdfFileName = 'MGJ_' + safeFile + '_Details.pdf';

  var html = '' +
    '<!doctype html><html><head><meta charset="utf-8">' +
    '<title>MGJ Member Details — ' + esc(name) + '</title>' +
    '<style>' +
      '*{box-sizing:border-box}' +
      'body{font-family:Arial,Helvetica,sans-serif;color:#222;margin:0;padding:24px;background:#fff;}' +
      '.bar{position:sticky;top:0;background:#fff;padding:12px 0 16px 0;border-bottom:1px solid #ddd;display:flex;gap:10px;justify-content:flex-end;z-index:10;}' +
      '.btn{padding:8px 18px;border-radius:50px;border:1px solid #732269;font-weight:600;cursor:pointer;font-size:13px;}' +
      '.btn-primary{background:#732269;color:#fff;}' +
      '.btn-outline{background:#fff;color:#732269;}' +
      '.header{display:flex;align-items:center;gap:18px;margin-top:14px;padding-bottom:14px;border-bottom:2px solid #732269;}' +
      '.header img{width:88px;height:88px;border-radius:50%;object-fit:cover;border:2px solid #732269;}' +
      '.header .ph{width:88px;height:88px;border-radius:50%;background:#faf3f8;color:#732269;font-size:48px;display:flex;align-items:center;justify-content:center;border:2px solid #732269;}' +
      '.title{margin:0;color:#732269;}' +
      '.subtitle{margin:4px 0 0 0;color:#666;font-size:13px;}' +
      'h3{margin:0;}' +
      'table{width:100%;}' +
      '.foot{margin-top:24px;padding-top:8px;border-top:1px solid #ddd;color:#888;font-size:11px;text-align:right;}' +
      '@media print {' +
        '.bar{display:none !important;}' +
        'body{padding:12px;}' +
      '}' +
    '</style>' +
    '<script src="https://cdnjs.cloudflare.com/ajax/libs/html2pdf.js/0.10.1/html2pdf.bundle.min.js"></script>' +
    '</head><body>' +
    '<div class="bar">' +
      '<button class="btn btn-outline" onclick="window.print()"><i></i> Print</button>' +
      '<button class="btn btn-primary" onclick="downloadPdf()"><i></i> Download PDF</button>' +
    '</div>' +
    '<div id="printable">' +
      '<div class="header">' +
        (photoSrc
          ? '<img src="' + esc(photoSrc) + '" alt="">'
          : '<div class="ph">&#128100;</div>') +
        '<div>' +
          '<h2 class="title">' + esc(name) + '</h2>' +
          '<p class="subtitle">' + esc(summary) + '</p>' +
        '</div>' +
      '</div>' +
      sectionsHtml +
      '<div class="foot">Generated on ' + esc(generatedAt) + ' &middot; Azad Foundation MIS</div>' +
    '</div>' +
    '<script>' +
    'function downloadPdf(){' +
      'if(typeof html2pdf!=="function"){' +
        'alert("PDF library is still loading. Please wait a moment and try again."); return;' +
      '}' +
      'var node=document.getElementById("printable");' +
      'var opt={margin:[10,10,10,10],filename:' + JSON.stringify(pdfFileName) +
        ',image:{type:"jpeg",quality:.95},html2canvas:{scale:2,useCORS:true},' +
        'jsPDF:{unit:"mm",format:"a4",orientation:"portrait"},' +
        'pagebreak:{mode:["css","legacy"]}};' +
      'html2pdf().set(opt).from(node).save().catch(function(e){alert("PDF generation failed: "+e);});' +
    '}' +
    '</script>' +
    '</body></html>';

  var w = window.open('', '_blank', 'width=900,height=1000,scrollbars=yes,resizable=yes');
  if (!w) {
    alert('Your browser blocked the print window. Please allow pop-ups for this site and try again.');
    return;
  }
  w.document.open();
  w.document.write(html);
  w.document.close();
  try { w.focus(); } catch (e) {}
}


// =============================================================================
// AZAD KISHORI (AK) MODULE
// =============================================================================
var akCurrentPage = 1, akPageLimit = 10, _akFilterStateLoaded = false;
var akFormMode = 'add', editingAkId = null, viewingAkId = null;
var akTrCurrentPage = 1, akTrPageLimit = 10, _akTrFilterStateLoaded = false;
var akTrFormMode = 'add', editingAkTrId = null, viewingAkTrainingId = null;
var akAssigningTrainingId = null;
var akBatchCurrentPage = 1, akBatchPageLimit = 10;
var editingAkBatchId = null, allocatingAkBatchId = null;
var akSelectedPhoto = null;

// ---- AK LIST ----
function loadAkListData(page) {
  // apiAvailable check removed - AK/MGJ APIs work independently
  if (typeof page === 'number') akCurrentPage = page;
  if (!_akFilterStateLoaded) {
    _akFilterStateLoaded = true;
    _populateAkStatesInto('akFilterState', 'All States');
  }
  // Auto-populate batch dropdown on page open so users can filter by
  // batch without first picking a state. Re-runs whenever the active
  // state filter changes (tracked via _akBatchFilterStateCode).
  _populateAkBatchFilter();
  var p = { page: akCurrentPage, limit: akPageLimit };
  var s = document.getElementById('akFilterState');
  var c = document.getElementById('akFilterCentre');
  var b = document.getElementById('akFilterBatch');
  var n = document.getElementById('akFilterName');
  var df = document.getElementById('akFilterDateFrom');
  var dt = document.getElementById('akFilterDateTo');
  var st = document.getElementById('akFilterStatus');
  if (s && s.value) p.state_code = s.value;
  if (c && c.value) p.centre_code = c.value;
  if (b && b.value) p.batch_id = b.value;
  if (n && n.value.trim()) p.name = n.value.trim();
  if (df && df.value) p.date_from = df.value;
  if (dt && dt.value) p.date_to = dt.value;
  // 2026-06-04: Status filter handling. Backend precedence is
  //   if status → use it; elif not include_dropout → default-exclude.
  // So if the user picks Active or Dropout, we send `status` and
  // omit include_dropout (backend will honor the explicit choice).
  // If the user leaves Status="All" we send include_dropout=true so
  // Active AND Dropout rows both render — matching the dashboard's
  // total. include_dropout=true was already being set since 2026-05-30
  // but was silently dropped by apiAkList; that wrapper-level bug
  // ALSO fixed in this push (api.js).
  if (st && st.value) {
    p.status = st.value;
  } else {
    p.include_dropout = true;
  }
  p = _applyRoleScopeFloor(p);
  apiAkList(p).then(function(result) {
    var data = result.data || [];
    var tbody = document.getElementById('akListTableBody');
    if (!tbody) return;
    if (!data.length) {
      tbody.innerHTML = '<tr><td colspan="6" style="text-align:center;color:#999;padding:30px;">No AK records found.</td></tr>';
      // Reset pagination to reflect the empty result — otherwise it
      // keeps showing the previous load's "Showing N-M of T".
      renderListPagination('#page-akList .pagination', 0, akCurrentPage, akPageLimit, 'loadAkListData');
      return;
    }
    var html = '';
    var _canDel = _canDeleteRecord();
    data.forEach(function(m, i) {
      var loc = [m.centre_name, m.state_name].filter(Boolean).join(', ');
      var _safeName = escHtml(m.name || '').replace(/\'/g, "\\'");
      // 2026-05-30: Dropout members are read-only — once a leader is
      // marked Dropout (the backend uses 'Walkout' as the actual status
      // string; UI labels it "Dropout") we hide the Edit pencil so the
      // record stays viewable for reference but cannot be modified.
      // The View button is always available. Delete (admin only) is
      // also always available; deleting a dropout record is intentional
      // and distinct from editing it.
      var _isDropout = (m.status === 'Walkout' || m.status === 'Dropout');
      html += '<tr><td>' + ((akCurrentPage - 1) * akPageLimit + i + 1) + '</td>' +
        '<td>' + escHtml(m.name || '') + '</td>' +
        '<td>' + escHtml(loc) + '</td>' +
        '<td>' + escHtml(m.batch_name || '—') + '</td>' +
        '<td>' + statusBadge(m.status) + '</td>' +
        '<td><button class="btn-icon" title="View" onclick="viewAkDetail(' + m.id + ')"><i class="fas fa-eye"></i></button>' +
        (_isDropout ? '' :
          '<button class="btn-icon" title="Edit" onclick="openEditAk(' + m.id + ')"><i class="fas fa-edit"></i></button>') +
        (_canDel ? '<button class="btn-icon text-danger" title="Delete" onclick="deleteAkFromList(' + m.id + ',\'' + _safeName + '\')"><i class="fas fa-trash-alt"></i></button>' : '') +
        '</td></tr>';
    });
    tbody.innerHTML = html;
    renderListPagination('#page-akList .pagination', result.total || 0, akCurrentPage, akPageLimit, 'loadAkListData');
  }).catch(function(e) { console.error('AK list error:', e); });
}
function applyAkFilters() { akCurrentPage = 1; loadAkListData(1); }
function resetAkFilters() {
  _clearListFilters('akList');
  // 2026-06-04: include akFilterStatus in the reset list so the new
  // Status dropdown also returns to "All" when the user clicks Reset.
  ['akFilterState','akFilterCentre','akFilterBatch','akFilterName','akFilterDateFrom','akFilterDateTo','akFilterStatus'].forEach(function(id) {
    var el = document.getElementById(id); if (el) el.value = '';
  });
  // 2026-06-08: For SL / DL / PI, re-apply the soft 2-option lock so
  // the Centre dropdown shows "All Centres + <user's centre>" again
  // (otherwise Reset wipes the dropdown to placeholder only and the
  // user sees no centre option).
  var _r = currentUser && currentUser.role || '';
  if ((_r === 'pi' || _r === 'district_lead' || _r === 'state_lead') &&
      typeof _lockAkFiltersForDlPi === 'function') {
    _lockAkFiltersForDlPi('akFilterState', 'akFilterCentre', { stateMode: 'soft', centreMode: 'soft' });
  }
  // Force the batch dropdown to refetch (clear filter -> all batches).
  _akBatchFilterStateCode = null;
  akCurrentPage = 1; loadAkListData(1);
}
function onAkFilterStateChange() {
  var sc = (document.getElementById('akFilterState') || {}).value;
  _loadAkCentresInto('akFilterCentre', sc, null, 'All Centres');
  // Reset the cached state-code so the batch-filter helper actually
  // re-fetches when the state cascades (would otherwise short-circuit).
  _akBatchFilterStateCode = null;
  _populateAkBatchFilter();
}
// 2026-06-06: Centre→Batch cascade for AK List per user spec — when a
// specific centre is picked, Batch dropdown narrows to batches mapped
// to that centre in Batch Management; when Centre is cleared, falls
// back to state-wide batches.
function onAkFilterCentreChange() {
  var sc = (document.getElementById('akFilterState')  || {}).value || '';
  var cc = (document.getElementById('akFilterCentre') || {}).value || '';
  _akBatchFilterStateCode = null;
  _loadAkBatchesInto('akFilterBatch', sc, null, 'All Batches', cc);
}

// Tracks which state the batch dropdown was last populated for, so
// loadAkListData() can call this on every render without re-fetching
// when nothing changed. Mirrors _flpBatchFilterStateCode for FLP list.
var _akBatchFilterStateCode = null;
function _populateAkBatchFilter() {
  var sc = (document.getElementById('akFilterState') || {}).value || '';
  if (_akBatchFilterStateCode === sc) return;
  _akBatchFilterStateCode = sc;
  _loadAkBatchesInto('akFilterBatch', sc, null, 'All Batches');
}
function exportAkToExcel() {
  // 2026-06-04: export now forwards every active filter so the file the
  // user downloads matches the on-screen list 1:1. Previously only state,
  // centre and name were forwarded — batch + date range + status were
  // silently dropped, and the export had no notion of "include dropouts",
  // so the file diverged from the visible list (sometimes more rows than
  // shown, sometimes fewer). With Status="All" we also forward include
  // _dropout=true so Active AND Dropout rows land in the Excel; with an
  // explicit Status="Active" or "Dropout" the backend's status filter
  // takes precedence (Dropout is aliased server-side to match historical
  // 'Walkout' rows too).
  var s  = document.getElementById('akFilterState');
  var c  = document.getElementById('akFilterCentre');
  var b  = document.getElementById('akFilterBatch');
  var n  = document.getElementById('akFilterName');
  var st = document.getElementById('akFilterStatus');
  var p = {};
  if (s  && s.value)  p.state_code  = s.value;
  if (c  && c.value)  p.centre_code = c.value;
  if (b  && b.value)  p.batch_id    = b.value;
  if (n  && n.value)  p.name        = n.value;
  if (st && st.value) {
    p.status = st.value;
  } else {
    p.include_dropout = true;
  }
  p = _applyRoleScopeFloor(p);
  window.open(API_BASE + '/ak/export/excel' + _qs(p), '_blank');
}

// ---- ADD/EDIT AK ----
function openAddAk() {
  akFormMode = 'add'; editingAkId = null; akSelectedPhoto = null;
  navigateTo('addAk');
  setTimeout(function() {
    var _t = document.getElementById('addAkTitle'); if (_t) _t.innerHTML = '<i class="fas fa-user-plus"></i> Add New AK Leader';
    var _s = document.getElementById('akFormSubmitText'); if (_s) _s.textContent = 'Submit AK Record';
    var _b = document.getElementById('addAkBcText'); if (_b) _b.textContent = 'Add AK';
    // Clear all fields
    ['akName','akAddress','akContact','akYearJoining','akDob','akAge','akStreamOther','akCategoryOther','akReligionOther',
     'akGenderOther',
     'akMotherName','akMotherOccupation','akFatherName','akFatherOccupation','akFamilyIncome','akFamilyMembers','akPerCapita'
    ].forEach(function(id) { var el = document.getElementById(id); if (el) el.value = ''; });
    ['akState','akCentre','akBatch','akCurrentEducation','akStream','akCategory','akReligion','akGender'].forEach(function(id) {
      var el = document.getElementById(id); if (el) el.selectedIndex = 0;
    });
    // 2026-05-28: akStreamGrp included — Stream (+2) starts hidden until
    // Current Education is set to 11th or 12th (see onAkEducationChange).
    // 2026-05-30: akGenderOtherGrp also reset hidden — only shown on
    // Gender=Other.
    ['akStreamGrp','akStreamOtherGrp','akCategoryOtherGrp','akReligionOtherGrp','akGenderOtherGrp'].forEach(function(id) {
      var el = document.getElementById(id); if (el) el.style.display = 'none';
    });
    var _pp = document.getElementById('akPhotoPreview'); if (_pp) _pp.innerHTML = '<i class="fas fa-camera"></i>';
    var _dob = document.getElementById('akDob'); if (_dob) _dob.max = new Date().toISOString().split('T')[0];
    // 2026-05-30: Reset Alumni-batch notice + cached payload so a previous
    // edit doesn't bleed into the Add flow (the cached _akViewPayload is
    // used by saveAkRecord to preserve non-Active statuses across edits).
    var _nb = document.getElementById('akBatchAlumniNotice'); if (_nb) _nb.style.display = 'none';
    _akViewPayload = null;
    // Add mode shows all three workflow buttons (Save Draft + Review + Submit).
    var _bDraft = document.getElementById('btnAkSaveDraft'); if (_bDraft) _bDraft.style.display = '';
    var _bRev   = document.getElementById('btnAkReview');    if (_bRev)   _bRev.style.display = '';
    // Clear any inline validation marks left over from a previous failed save.
    if (typeof _clearFieldErrors === 'function') _clearFieldErrors('page-addAk');
    // Always load states fresh using direct XHR
    _loadAkStatesForModal('akState');
  }, 100);
}
function openEditAk(id) {
  // 2026-06-02: 7-day Draft submit window — mirrors openEditMgj.
  // For DRAFT records older than 7 days, only super_admin / admin may
  // open the edit form. Everyone else gets blocked with a message. Active
  // (submitted) records are never time-limited. On day 6 (the day before
  // the deadline) we show a heads-up so the user knows they have 24h left.
  apiAkDetail(id).then(function(m) {
    var isDraft = (m && m.status === 'Draft');
    if (isDraft && m && m.created_at) {
      var created = new Date(m.created_at);
      var now = new Date();
      var daysOld = Math.floor((now - created) / (1000 * 60 * 60 * 24));
      var role = (typeof currentUser !== 'undefined' && currentUser) ? (currentUser.role || '') : '';
      var isExempt = (role === 'super_admin' || role === 'admin' || role === 'super admin');
      if (daysOld > 7 && !isExempt) {
        alert('This Draft AK Leader record was created more than 7 days ago and can no longer be edited or submitted. Please contact a Super Admin to reopen it.');
        return;
      }
      if (daysOld === 6 && !isExempt) {
        alert('Heads up: this Draft AK Leader record was created 6 days ago. You have 1 day left to complete and submit it before the 7-day window expires.');
      }
    }
    _proceedEditAk(id);
  }).catch(function() {
    // If detail fetch fails, fall through to opening the form — the form
    // itself will retry the fetch and surface any error there.
    _proceedEditAk(id);
  });
}

function _proceedEditAk(id) {
  akFormMode = 'edit'; editingAkId = id; akSelectedPhoto = null;
  navigateTo('addAk');
  setTimeout(function() {
    var _t = document.getElementById('addAkTitle'); if (_t) _t.innerHTML = '<i class="fas fa-user-edit"></i> Edit AK Leader';
    var _s = document.getElementById('akFormSubmitText'); if (_s) _s.textContent = 'Update';
    var _b = document.getElementById('addAkBcText'); if (_b) _b.textContent = 'Edit AK';
    // 2026-05-30: In edit mode, hide the Save-as-Draft button (the record is
    // already past the draft stage by definition). Keep Review so the user
    // can still preview before pushing the change. Submit becomes "Update".
    var _bDraft = document.getElementById('btnAkSaveDraft'); if (_bDraft) _bDraft.style.display = 'none';
    var _bRev   = document.getElementById('btnAkReview');    if (_bRev)   _bRev.style.display = '';
    _loadAkStatesForModal('akState');
    apiAkDetail(id).then(function(m) {
      _akViewPayload = m;
      if (m.state_code) { document.getElementById('akState').value = m.state_code; onAkFormStateChange(function() {
        if (m.centre_code) {
          document.getElementById('akCentre').value = m.centre_code;
          onAkFormCentreChange();
          // Set batch after batches load
          if (m.batch_id) setTimeout(function() { var bs = document.getElementById('akBatch'); if (bs) bs.value = m.batch_id; }, 500);
        }
      }); }
      document.getElementById('akName').value = m.name || '';
      document.getElementById('akAddress').value = m.address || '';
      document.getElementById('akContact').value = m.contact_number || '';
      document.getElementById('akYearJoining').value = m.year_of_joining || '';
      document.getElementById('akDob').value = m.dob || '';
      document.getElementById('akAge').value = m.age || '';
      document.getElementById('akCurrentEducation').value = m.current_education || '';
      document.getElementById('akStream').value = m.stream_chosen || '';
      document.getElementById('akStreamOther').value = m.stream_other || '';
      // 2026-05-28: cascading visibility for the Stream group — runs
      // after both Stream + StreamOther are set so the "Any Other"
      // sub-toggle inside onAkEducationChange sees the correct values.
      onAkEducationChange();
      document.getElementById('akCategory').value = m.category || '';
      toggleAkConditional('akCategory', 'Any Others', 'akCategoryOtherGrp');
      document.getElementById('akCategoryOther').value = m.category_other || '';
      document.getElementById('akReligion').value = m.religion || '';
      toggleAkConditional('akReligion', 'Any Other', 'akReligionOtherGrp');
      document.getElementById('akReligionOther').value = m.religion_other || '';
      // 2026-05-30: Gender on load — split "Other - <specify>" back into
      // the dropdown + Specify input. Plain values (Cis Woman / Non-Binary
      // / Trans* / Prefer Not to Say / legacy "Trans Woman" / blank) just
      // pass through. Anything that doesn't match a known option falls
      // back to "Other" with the original string going into the Specify
      // field so legacy/unknown values aren't silently dropped.
      (function() {
        var sel = document.getElementById('akGender');
        var oth = document.getElementById('akGenderOther');
        var raw = (m.gender || '').trim();
        if (!sel) return;
        var KNOWN = ['Cis Woman','Non-Binary','Trans*','Prefer Not to Say'];
        if (!raw) {
          sel.value = '';
          if (oth) oth.value = '';
        } else if (raw.indexOf('Other - ') === 0) {
          sel.value = 'Other';
          if (oth) oth.value = raw.slice('Other - '.length);
        } else if (raw === 'Other') {
          sel.value = 'Other';
          if (oth) oth.value = '';
        } else if (KNOWN.indexOf(raw) !== -1) {
          sel.value = raw;
          if (oth) oth.value = '';
        } else {
          // Legacy value (e.g. "Trans Woman" from before the option rename)
          // — keep the dropdown blank so the user is nudged to re-pick,
          // and stash the raw value in Specify so it isn't lost.
          sel.value = '';
          if (oth) oth.value = raw;
        }
        // Reveal the Specify group iff the dropdown ended up on Other or
        // we stuffed a legacy value into akGenderOther.
        toggleAkConditional('akGender','Other','akGenderOtherGrp');
        var grp = document.getElementById('akGenderOtherGrp');
        if (grp && oth && oth.value && sel.value !== 'Other') grp.style.display = '';
      })();
      document.getElementById('akMotherName').value = m.mother_name || '';
      document.getElementById('akMotherOccupation').value = m.mother_occupation || '';
      document.getElementById('akFatherName').value = m.father_name || '';
      document.getElementById('akFatherOccupation').value = m.father_occupation || '';
      document.getElementById('akFamilyIncome').value = m.family_monthly_income || '';
      document.getElementById('akFamilyMembers').value = m.family_members || '';
      document.getElementById('akPerCapita').value = m.per_capita_income || '';
      if (m.photo_url) { document.getElementById('akPhotoPreview').innerHTML = '<img src="' + m.photo_url + '" style="width:100%;height:100%;object-fit:cover;border-radius:6px;">'; }
    });
  }, 100);
}

// ── Add-AK form: F5 / refresh rehydrate ────────────────────────────────────
// When the user is on the Add AK page and presses F5 (or lands here via a
// direct deep link), openAddAk() / openEditAk() do NOT run because there's
// no button click. Without re-running the dropdown loaders the State /
// Centre / Batch dropdowns stay on their placeholder option and the form
// is unusable. This init helper checks for that "empty form" state and
// re-populates dropdowns. Called from the navigateTo router (page hook).
function _initAddAkFormOnEntry() {
  // Don't disturb a partially-filled form mid-session (edit-in-progress).
  // Only re-init when the State dropdown is empty (only the placeholder
  // option). Use a tiny defer so the page DOM is settled.
  setTimeout(function() {
    var stateSel = document.getElementById('akState');
    if (!stateSel) return;
    if (stateSel.options.length <= 1) {
      if (typeof _loadAkStatesForModal === 'function') _loadAkStatesForModal('akState');
      // Also re-cap the DOB max date and clear any stale red error highlights.
      var _dob = document.getElementById('akDob');
      if (_dob) _dob.max = new Date().toISOString().split('T')[0];
      _clearFieldErrors('page-addAk');
    }
  }, 120);
}

// ── Generic form inline-error helpers ──────────────────────────────────────
// These are page-scoped (you pass the page id as the first arg) so multiple
// forms can use them without colliding. The CSS rules .field-error-input
// + .field-error-msg + .form-error-banner live in styles.css.
function _showFieldError(fieldId, msg) {
  var el = document.getElementById(fieldId);
  if (!el) return;
  el.classList.add('field-error-input');
  // Create-or-update the helper-text div directly after the input.
  var errId = fieldId + '__error';
  var errEl = document.getElementById(errId);
  if (!errEl) {
    errEl = document.createElement('div');
    errEl.id = errId;
    errEl.className = 'field-error-msg';
    var parent = el.parentNode;
    if (parent) parent.appendChild(errEl);
  }
  errEl.textContent = msg;
  errEl.style.display = 'block';
}
function _clearFieldErrors(pageId) {
  var root = pageId ? document.getElementById(pageId) : document;
  if (!root) return;
  (root.querySelectorAll ? root.querySelectorAll('.field-error-input') : []).forEach(function(el) {
    el.classList.remove('field-error-input');
  });
  (root.querySelectorAll ? root.querySelectorAll('.field-error-msg') : []).forEach(function(el) {
    el.style.display = 'none';
    el.textContent = '';
  });
  // Hide the top banner if present.
  var banner = root.querySelector ? root.querySelector('.form-error-banner') : null;
  if (banner) banner.style.display = 'none';
}
function _showFormBanner(pageId, msg) {
  var root = document.getElementById(pageId);
  if (!root) return;
  var banner = root.querySelector('.form-error-banner');
  if (!banner) {
    banner = document.createElement('div');
    banner.className = 'form-error-banner';
    banner.innerHTML = '<i class="fas fa-exclamation-circle"></i> <span></span>';
    // Insert right after the page header.
    var header = root.querySelector('.page-header');
    if (header && header.nextSibling) root.insertBefore(banner, header.nextSibling);
    else root.insertBefore(banner, root.firstChild);
  }
  var span = banner.querySelector('span');
  if (span) span.textContent = msg;
  banner.style.display = 'flex';
}

// 2026-05-30: saveAkRecord now accepts a mode argument:
//   'draft'  — skip validation, persist with status='Draft' (so the user
//              can come back and finish later without losing what they typed)
//   'submit' — full validation, persist as Active OR Alumni (the latter when
//              the selected batch is Inactive / Alumni Batch)
// The legacy no-arg call site (autosave / older code paths) defaults to
// 'submit' to preserve previous behaviour.
function saveAkRecord(mode) {
  if (!mode) mode = 'submit';
  var isDraft = (mode === 'draft');
  function _v(id) { var el = document.getElementById(id); return el ? (el.value || '').trim() : ''; }

  // Clear any previous inline errors before re-validating. This lets the
  // user see ALL of their issues at once (red border + helper text under
  // each empty/invalid field) instead of a chain of dismiss-one-popup-
  // at-a-time alerts. _showFieldError / _clearFieldErrors are defined
  // below alongside _initAkFormDropdowns.
  _clearFieldErrors('page-addAk');

  var contact = _v('akContact');
  if (!isDraft) {
    var errors = [];
    if (!_v('akState'))            errors.push(['akState',            'Please select a State.']);
    if (!_v('akCentre'))           errors.push(['akCentre',           'Please select a Centre.']);
    if (!_v('akBatch'))            errors.push(['akBatch',            'Please select a Batch.']);
    if (!_v('akName'))             errors.push(['akName',             'Please enter Name of Leader.']);
    if (!_v('akAddress'))          errors.push(['akAddress',          'Please enter Address.']);
    // Contact — optional, but if filled must be exactly 10 digits.
    if (contact) {
      if (/[^0-9]/.test(contact)) errors.push(['akContact', 'Only digits (0–9) are allowed.']);
      else if (contact.length !== 10) errors.push(['akContact', 'Enter a valid 10-digit contact number.']);
    }
    if (!_v('akDob')) {
      errors.push(['akDob', 'Please enter Date of Birth.']);
    } else if (new Date(_v('akDob')) > new Date()) {
      errors.push(['akDob', 'Date of Birth cannot be a future date.']);
    }
    if (!_v('akCurrentEducation')) errors.push(['akCurrentEducation', 'Please select Current Education.']);
    var edu = _v('akCurrentEducation');
    if ((edu === '11th' || edu === '12th') && !_v('akStream')) {
      errors.push(['akStream', 'Please select Stream (required for 11th / 12th).']);
    }
    if (_v('akStream')   === 'Any Other'  && !_v('akStreamOther'))   errors.push(['akStreamOther',   'Please specify the stream.']);
    if (!_v('akCategory'))                                            errors.push(['akCategory',      'Please select Category.']);
    if (_v('akCategory') === 'Any Others' && !_v('akCategoryOther')) errors.push(['akCategoryOther', 'Please specify the category.']);
    if (!_v('akReligion'))                                            errors.push(['akReligion',      'Please select Religion.']);
    if (_v('akReligion') === 'Any Other'  && !_v('akReligionOther')) errors.push(['akReligionOther', 'Please specify the religion.']);
    if (!_v('akGender'))           errors.push(['akGender',           'Please select Gender.']);
    // 2026-05-30: If Gender is "Other", the Specify input is required so
    // we capture what the user actually wanted to say (otherwise saving
    // an opaque "Other" loses information).
    if (_v('akGender') === 'Other' && !_v('akGenderOther')) {
      errors.push(['akGenderOther', 'Please specify gender.']);
    }
    if (!_v('akMotherName'))       errors.push(['akMotherName',       'Please enter Name of Mother.']);
    if (!_v('akFatherName'))       errors.push(['akFatherName',       'Please enter Name of Father.']);
    if (!_v('akFamilyIncome'))     errors.push(['akFamilyIncome',     'Please enter Family Monthly Income.']);
    if (!_v('akFamilyMembers'))    errors.push(['akFamilyMembers',    'Please enter Number of Family Members.']);

    if (errors.length) {
      errors.forEach(function(e) { _showFieldError(e[0], e[1]); });
      // Top-of-form banner so the user knows what just happened — useful
      // when the offending fields are below the fold.
      _showFormBanner('page-addAk',
        'Please correct the highlighted field' + (errors.length === 1 ? '' : 's') + ' below.');
      // Scroll the first invalid field into view.
      var first = document.getElementById(errors[0][0]);
      if (first && first.scrollIntoView) first.scrollIntoView({ behavior:'smooth', block:'center' });
      if (first && first.focus) try { first.focus(); } catch (e) {}
      return;
    }
  } else {
    // Draft mode — Name is the only minimum we insist on so the row has
    // something to identify it by in the list. Everything else can be
    // filled in later.
    if (!_v('akName')) {
      _showFieldError('akName', 'Please enter at least the Leader name to save a draft.');
      _showFormBanner('page-addAk', 'Name of Leader is required even for a draft.');
      var nameEl = document.getElementById('akName');
      if (nameEl && nameEl.focus) try { nameEl.focus(); } catch (e) {}
      return;
    }
  }

  // Decide the final status. Default is Active for a fresh submit; Draft
  // for an explicit draft; Alumni when the selected batch is Inactive
  // (Alumni Batch). In edit mode we preserve any non-Active status the
  // record already had unless the batch picker now points at an Alumni
  // batch — in which case we still flip to Alumni.
  var finalStatus;
  var batchId = _v('akBatch');
  var selBatch = batchId ? _akBatchCache[String(batchId)] : null;
  var batchIsAlumni = !!(selBatch && selBatch.status === 'Inactive');
  if (isDraft) {
    finalStatus = 'Draft';
  } else if (batchIsAlumni) {
    finalStatus = 'Alumni';
  } else if (akFormMode === 'edit' && _akViewPayload && _akViewPayload.status &&
             _akViewPayload.status !== 'Draft') {
    // Preserve whatever non-Draft lifecycle status the record already had
    // (Active, Alumni, Walkout, …) so a routine edit doesn't accidentally
    // reset the leader to Active.
    finalStatus = _akViewPayload.status;
  } else {
    finalStatus = 'Active';
  }

  var data = {
    state_code: _v('akState') || null, centre_code: _v('akCentre') || null,
    batch_id: parseInt(_v('akBatch')) || null,
    name: _v('akName'), address: _v('akAddress') || null, contact_number: contact || null,
    year_of_joining: parseInt(_v('akYearJoining')) || null,
    dob: _v('akDob') || null, age: parseInt(_v('akAge')) || null,
    current_education: _v('akCurrentEducation') || null,
    stream_chosen: _v('akStream') || null, stream_other: _v('akStreamOther') || null,
    category: _v('akCategory') || null, category_other: _v('akCategoryOther') || null,
    religion: _v('akReligion') || null, religion_other: _v('akReligionOther') || null,
    // 2026-05-30: Gender concat — when the picker is "Other", store the
    // value as "Other - <specify>" so the backend (which has no
    // gender_other column) preserves the user's free-text without a
    // schema change. openEditAk splits this back into the two fields.
    gender: (function() {
      var g = _v('akGender');
      var go = _v('akGenderOther');
      if (g === 'Other' && go) return 'Other - ' + go;
      return g || null;
    })(),
    mother_name: _v('akMotherName') || null, mother_occupation: _v('akMotherOccupation') || null,
    father_name: _v('akFatherName') || null, father_occupation: _v('akFatherOccupation') || null,
    family_monthly_income: parseFloat(_v('akFamilyIncome')) || null,
    family_members: parseInt(_v('akFamilyMembers')) || null,
    per_capita_income: parseFloat(_v('akPerCapita')) || null,
    status: finalStatus
  };

  var promise = (akFormMode === 'edit' && editingAkId) ? apiUpdateAk(editingAkId, data) : apiCreateAk(data);
  promise.then(function(res) {
    var newId = res.id || editingAkId;
    var savedMsg;
    if (isDraft) {
      savedMsg = 'AK Leader saved as Draft. You can come back and complete it later.';
    } else if (akFormMode === 'edit') {
      savedMsg = 'AK Leader updated!';
    } else if (batchIsAlumni) {
      savedMsg = 'AK Leader created as Alumni (batch has already passed out).';
    } else {
      savedMsg = 'AK Leader created!';
    }
    // Upload photo if selected
    if (akSelectedPhoto && newId) {
      apiAkUploadPhoto(newId, akSelectedPhoto).then(function() {
        alert(savedMsg);
        navigateTo('akList');
      });
    } else {
      alert(savedMsg);
      navigateTo('akList');
    }
  }).catch(function(err) { showUserError('processing your request', err); });
}

// ── Review modal ───────────────────────────────────────────────────────────
// 2026-05-30: Opened by the Review button on the Add AK form. Renders a
// read-only summary of every field the user has filled in so they can sanity-
// check before final submit. Confirm & Submit calls saveAkRecord('submit')
// to push through the same validation + persistence path as the form button.
function openAkReviewModal() {
  function _v(id) { var el = document.getElementById(id); return el ? (el.value || '').trim() : ''; }
  function _label(sel) {
    var el = document.getElementById(sel);
    if (!el || el.tagName !== 'SELECT') return _v(sel);
    var o = el.options[el.selectedIndex];
    return o ? (o.textContent || o.value || '') : '';
  }
  function row(l, v) {
    return '<div class="detail-item"><label>' + escHtml(l) + '</label><span>' +
           escHtml(v || '—') + '</span></div>';
  }
  var bid = _v('akBatch');
  var selBatch = bid ? _akBatchCache[String(bid)] : null;
  var batchIsAlumni = !!(selBatch && selBatch.status === 'Inactive');
  var finalStatusPreview = batchIsAlumni ? 'Alumni' :
    ((akFormMode === 'edit' && _akViewPayload && _akViewPayload.status && _akViewPayload.status !== 'Draft')
       ? _akViewPayload.status : 'Active');
  var banner = batchIsAlumni
    ? '<div style="padding:10px 14px;background:#fdf6e3;border:1px solid #f0c36d;border-radius:6px;color:#8a6d3b;font-size:13px;margin-bottom:14px;"><i class="fas fa-info-circle"></i> The selected Batch is marked <strong>Alumni Batch</strong> — this leader will be saved with status <strong>Alumni</strong>.</div>'
    : '';
  var html = banner +
    '<h4 style="margin:6px 0 10px;color:#732269;font-size:14px;"><i class="fas fa-map-marker-alt"></i> Programme Placement</h4>' +
    '<div class="detail-grid">' +
      row('State',  _label('akState')) +
      row('Centre', _label('akCentre')) +
      row('Batch',  _label('akBatch')) +
      row('Year of Joining AK', _v('akYearJoining')) +
      row('Status on Submit', finalStatusPreview) +
    '</div>' +
    '<h4 style="margin:18px 0 10px;color:#732269;font-size:14px;"><i class="fas fa-user"></i> Basic Profile</h4>' +
    '<div class="detail-grid">' +
      row('Name',           _v('akName')) +
      row('Contact Number', _v('akContact')) +
      row('Date of Birth',  _v('akDob')) +
      row('Age at Enrollment', _v('akAge')) +
      row('Address',        _v('akAddress')) +
      row('Current Education', _label('akCurrentEducation')) +
      row('Stream Chosen', _label('akStream')) +
      (_v('akStreamOther')   ? row('Stream (Other)',   _v('akStreamOther'))   : '') +
      row('Category',       _label('akCategory')) +
      (_v('akCategoryOther') ? row('Category (Other)', _v('akCategoryOther')) : '') +
      row('Religion',       _label('akReligion')) +
      (_v('akReligionOther') ? row('Religion (Other)', _v('akReligionOther')) : '') +
      row('Gender',         _label('akGender')) +
      // 2026-05-30: Show the Specify text on its own line so the reviewer
      // sees what was actually typed.
      (_v('akGenderOther')   ? row('Gender (Other)',   _v('akGenderOther'))   : '') +
    '</div>' +
    '<h4 style="margin:18px 0 10px;color:#732269;font-size:14px;"><i class="fas fa-users"></i> Family Details</h4>' +
    '<div class="detail-grid">' +
      row('Mother Name',        _v('akMotherName')) +
      row('Mother Occupation',  _v('akMotherOccupation')) +
      row('Father Name',        _v('akFatherName')) +
      row('Father Occupation',  _v('akFatherOccupation')) +
      row('Family Monthly Income', _v('akFamilyIncome')) +
      row('Family Members',     _v('akFamilyMembers')) +
      row('Per Capita Income',  _v('akPerCapita')) +
    '</div>';
  var box = document.getElementById('akReviewSummary');
  if (box) box.innerHTML = html;
  var m = document.getElementById('akReviewModal');
  if (m) m.style.display = 'flex';
}
function closeAkReviewModal() {
  var m = document.getElementById('akReviewModal');
  if (m) m.style.display = 'none';
}
function confirmAkSubmit() {
  closeAkReviewModal();
  saveAkRecord('submit');
}

// ---- AK FORM HELPERS ----
var _akStateLoadingMap = {};
function _populateAkStatesInto(selectId, defaultLabel) {
  var sel = document.getElementById(selectId);
  if (!sel) return;
  // 2026-06-06: State Lead short-circuit — same reason as the modal
  // helper: avoid a late-arriving XHR clobbering the SL state lock.
  // We stamp the dropdown with their state directly and skip the fetch.
  if (currentUser && currentUser.role === 'state_lead' && currentUser.state_code) {
    var slName = currentUser.state_name || currentUser.state_code;
    sel.innerHTML = '<option value="' + escHtml(currentUser.state_code) + '" selected>' + escHtml(slName) + '</option>';
    sel.value = currentUser.state_code;
    sel.disabled = true;
    sel.style.backgroundColor = '#f5f5f5';
    sel.style.cursor = 'not-allowed';
    sel.title = 'Locked to your assigned State';
    _akStateLoadingMap[selectId] = false;
    if (!currentUser.state_name) {
      apiGet('/ak-master/dropdown/states').then(function(rows) {
        (rows || []).some(function(r) {
          if (r.state_code === currentUser.state_code) {
            currentUser.state_name = r.state_name;
            try { localStorage.setItem('azadUserData', JSON.stringify(currentUser)); } catch (e) {}
            var s2 = document.getElementById(selectId);
            if (s2) s2.innerHTML = '<option value="' + escHtml(currentUser.state_code) + '" selected>' + escHtml(r.state_name) + '</option>';
            return true;
          }
          return false;
        });
      }).catch(function() {});
    }
    try { sel.dispatchEvent(new Event('change', { bubbles: true })); } catch (e) {}
    return;
  }
  if (sel.options.length > 1) return; // already has states
  if (_akStateLoadingMap[selectId]) return; // XHR in progress
  _akStateLoadingMap[selectId] = true;
  var lbl = defaultLabel || 'Select State';
  sel.innerHTML = '<option value="">' + lbl + '</option>';
  var url = window.location.origin + '/api/ak/geo/states';
  var xhr = new XMLHttpRequest();
  xhr.open('GET', url, true);
  xhr.onload = function() {
    try {
      if (xhr.status === 200) {
        var states = JSON.parse(xhr.responseText);
        var s2 = document.getElementById(selectId);
        if (s2) {
          for (var i = 0; i < states.length; i++) {
            var o = document.createElement('option');
            o.value = states[i].state_code;
            o.textContent = states[i].state_name;
            s2.appendChild(o);
          }
        }
      }
    } catch(e) { console.error('[AK] state parse error:', e); }
    // CRITICAL: clear the in-flight flag so the next modal open can reload
    _akStateLoadingMap[selectId] = false;
  };
  xhr.onerror = function() { _akStateLoadingMap[selectId] = false; };
  xhr.send();
}

function _populateAkFormState() {
  // 2026-06-04: same stuck-flag defense as _populateAkTrFormState —
  // see the comment block there. Add AK Member form shares the same
  // _akStateLoadingMap, so a stuck flag on 'akState' from a previous
  // aborted XHR would empty its State dropdown too.
  if (typeof _akStateLoadingMap !== 'undefined') {
    _akStateLoadingMap['akState'] = false;
  }
  _populateAkStatesInto('akState');
}
function _loadAkCentresInto(selectId, stateCode, cb, defaultLabel) {
  var sel = document.getElementById(selectId);
  if (!sel) return;
  var lbl = defaultLabel || 'Select Centre';
  // 2026-06-08 (round 7): For DL/PI with a resolved centre_code, the
  // Centre dropdown must NEVER widen to the full state-centre list —
  // that leaks data they're not scoped for and silently breaks the
  // hard-lock applied at form open. Replace with a SOFT 2-option
  // ("<placeholder>" + user's centre), skip the fetch, and fire the
  // callback so any downstream cascade (Batch fetch, etc.) still runs.
  //
  // Why soft instead of hard? Form pages additionally call
  // `_lockAkFiltersForDlPi(state, centre)` (hard mode) at navigateTo
  // — its 60/400/1200ms retries will overlay this soft option with a
  // hard, disabled single-option dropdown. Filter pages that want
  // "All Centres + <user centre>" land exactly there with no extra
  // work. SL is deliberately untouched — SL can pick any centre in
  // their state.
  if (currentUser && currentUser.centre_code &&
      (currentUser.role === 'district_lead' || currentUser.role === 'pi')) {
    var _esc = (typeof escHtml === 'function') ? escHtml : function(x) { return x; };
    var _name = (currentUser.centre_name || currentUser.centre_code);
    // Preserve the dropdown's current lock state. If the form's hard-
    // lock helper has already disabled the select (single option,
    // disabled), keep it hard-locked — otherwise apply the soft
    // 2-option pattern ("<placeholder>" + user's centre) that the
    // filter pages expect.
    var wasDisabled = sel.disabled;
    if (wasDisabled) {
      sel.innerHTML = '<option value="' + _esc(currentUser.centre_code) + '" selected>' +
                      _esc(_name) + '</option>';
      sel.value = currentUser.centre_code;
    } else {
      sel.innerHTML = '<option value="">' + _esc(lbl) + '</option>' +
                      '<option value="' + _esc(currentUser.centre_code) + '">' +
                      _esc(_name) + '</option>';
    }
    if (typeof cb === 'function') cb();
    return;
  }
  sel.innerHTML = '<option value="">' + lbl + '</option>';
  if (!stateCode) return;
  var url = window.location.origin + '/api/ak/geo/centres?state_code=' + encodeURIComponent(stateCode);
  var xhr = new XMLHttpRequest();
  xhr.open('GET', url, true);
  xhr.onload = function() {
    if (xhr.status !== 200) return;
    try {
      var centres = JSON.parse(xhr.responseText);
      var s2 = document.getElementById(selectId);
      if (!s2) return;
      // Atomic rebuild (last-write-wins) — see _loadAkStatesForModal note.
      var prev = s2.value;
      var seen = {};
      var html = '<option value="">' + lbl + '</option>';
      for (var i = 0; i < centres.length; i++) {
        var code = centres[i].centre_code;
        if (!code || seen[code]) continue;
        seen[code] = 1;
        var name = centres[i].centre_name || code;
        html += '<option value="' + escHtml(code) + '">' + escHtml(name) + '</option>';
      }
      s2.innerHTML = html;
      if (prev) s2.value = prev;
      if (typeof cb === 'function') cb();
    } catch(e) { console.error('[AK] _loadAkCentresInto parse error:', e); }
  };
  xhr.send();
}

function onAkFormStateChange(cb) {
  var sc = (document.getElementById('akState') || {}).value;
  // Reset both downstream dropdowns when State changes (cascade root).
  // 2026-06-08: Batch dropdown stays empty until a Centre is picked —
  // mirrors the Add Training / AK List / Dashboard flow. Previously
  // we eagerly loaded state-wide batches as soon as a State was picked
  // which confused users into thinking they could skip Centre.
  var batchSel = document.getElementById('akBatch');
  if (batchSel) batchSel.innerHTML = '<option value="">Select Batch</option>';
  // Reload Centres scoped to the new State.
  _loadAkCentresInto('akCentre', sc, cb);
  // (No state-wide batch preload — Centre selection is mandatory before
  // the Batch dropdown populates.)
}
function onAkFormCentreChange() {
  var sc = (document.getElementById('akState')  || {}).value;
  var cc = (document.getElementById('akCentre') || {}).value;
  var batchSel = document.getElementById('akBatch');
  if (batchSel) batchSel.innerHTML = '<option value="">Select Batch</option>';
  // 2026-06-08: When Centre is cleared OR unset, Batch dropdown stays
  // empty — no state-wide fallback. Batches only populate once a
  // specific Centre is chosen.
  if (!cc) return;
  _loadAkFormBatches(sc, cc);
}
// Helper: load active batches into #akBatch, scoped by state and (optionally)
// centre. Dedupes against any options already present so a race between two
// rapid state/centre changes can't double-fill the dropdown.
//
// 2026-05-30: We now ALSO pull batches with status=Inactive (Alumni Batch),
// because once a batch passes out the leaders we register against it should
// be saved directly as Alumni. The dropdown labels Alumni batches inline so
// the user knows which they're picking. _akBatchCache stores full batch rows
// keyed by batch id so onAkBatchChange() can pluck year + status without
// re-fetching.
var _akBatchCache = {};
function _loadAkFormBatches(stateCode, centreCode) {
  var batchSel = document.getElementById('akBatch');
  if (!batchSel) return;
  // Drop the 'status=Active' filter — we want Alumni batches too so the
  // auto-Alumni leader path can fire when one is picked.
  var qs = ['limit=200'];
  if (stateCode)  qs.push('state_code='  + encodeURIComponent(stateCode));
  if (centreCode) qs.push('centre_code=' + encodeURIComponent(centreCode));
  var url = window.location.origin + '/api/ak-batches?' + qs.join('&');
  var xhr = new XMLHttpRequest();
  xhr.open('GET', url, true);
  xhr.onload = function() {
    if (xhr.status !== 200) return;
    try {
      var result = JSON.parse(xhr.responseText);
      var data = Array.isArray(result) ? result : (result.data || []);
      var b2 = document.getElementById('akBatch');
      if (!b2) return;
      // Atomic rebuild (last-write-wins) — see _loadAkStatesForModal note.
      var prev = b2.value;
      var seen = {};
      var html = '<option value="">Select Batch</option>';
      data.forEach(function(b) {
        if (!b || !b.id || seen[b.id]) return;
        seen[b.id] = 1;
        _akBatchCache[String(b.id)] = b;
        var alumniTag = (b.status === 'Inactive') ? ' [Alumni Batch]' : '';
        var label = b.name + (b.year ? ' (' + b.year + ')' : '') + alumniTag;
        html += '<option value="' + escHtml(String(b.id)) + '">' + escHtml(label) + '</option>';
      });
      b2.innerHTML = html;
      if (prev) {
        b2.value = prev;
        // Re-fire onAkBatchChange so the year + alumni banner stay in sync
        // after a centre/state change rebuilds the dropdown.
        if (typeof onAkBatchChange === 'function') onAkBatchChange();
      }
    } catch (e) { console.error('[AK] _loadAkFormBatches parse error:', e); }
  };
  xhr.send();
}

// 2026-05-30: Fired when the user picks a Batch on the Add AK form.
// Two side-effects:
//   1. Year of Joining AK Program is auto-filled from the batch's "year"
//      string (e.g. "2026-27" → 2026). Falls back to the current calendar
//      year when the batch row has no year.
//   2. If the batch's status = 'Inactive' (relabelled "Alumni Batch" in the
//      Batch master), show the akBatchAlumniNotice banner so the user knows
//      this leader will be saved as Alumni instead of Active.
function onAkBatchChange() {
  var batchSel = document.getElementById('akBatch');
  var bid = batchSel ? batchSel.value : '';
  var batch = bid ? _akBatchCache[String(bid)] : null;
  var yj = document.getElementById('akYearJoining');
  var notice = document.getElementById('akBatchAlumniNotice');
  if (yj) {
    if (batch && batch.year) {
      // Pull the first 4-digit year out of "2026-27" / "2026" / etc.
      var m = String(batch.year).match(/\d{4}/);
      yj.value = m ? m[0] : '';
    } else if (batch) {
      // Batch picked but has no year set — fall back to current year so the
      // field isn't left blank.
      yj.value = String(new Date().getFullYear());
    } else {
      yj.value = '';
    }
  }
  if (notice) {
    notice.style.display = (batch && batch.status === 'Inactive') ? '' : 'none';
  }
}
function toggleAkConditional(selectId, showValue, groupId) {
  var sel = document.getElementById(selectId);
  var grp = document.getElementById(groupId);
  if (sel && grp) grp.style.display = (sel.value === showValue) ? '' : 'none';
}

// 2026-05-28: Show the Stream (+2) + StreamOther groups only when
// Current Education is 11th or 12th. Clear values when hiding so we
// don't carry stale data through to the backend on submit.
function onAkEducationChange() {
  var edu = (document.getElementById('akCurrentEducation') || {}).value || '';
  var streamRelevant = (edu === '11th' || edu === '12th');
  var streamGrp = document.getElementById('akStreamGrp');
  var streamSel = document.getElementById('akStream');
  var streamOtherGrp = document.getElementById('akStreamOtherGrp');
  var streamOther = document.getElementById('akStreamOther');
  if (streamGrp) streamGrp.style.display = streamRelevant ? '' : 'none';
  if (!streamRelevant) {
    if (streamSel) streamSel.value = '';
    if (streamOther) streamOther.value = '';
    if (streamOtherGrp) streamOtherGrp.style.display = 'none';
  } else {
    // Re-evaluate the "Any Other" sub-toggle in case Stream already has a value.
    toggleAkConditional('akStream', 'Any Other', 'akStreamOtherGrp');
  }
}
function calcAkAge() {
  var dob = document.getElementById('akDob');
  var age = document.getElementById('akAge');
  if (!dob || !dob.value || !age) return;
  var b = new Date(dob.value), t = new Date();
  var a = t.getFullYear() - b.getFullYear();
  if (t.getMonth() < b.getMonth() || (t.getMonth() === b.getMonth() && t.getDate() < b.getDate())) a--;
  age.value = a;
}
function calcAkPerCapita() {
  var inc = parseFloat((document.getElementById('akFamilyIncome') || {}).value) || 0;
  var mem = parseInt((document.getElementById('akFamilyMembers') || {}).value) || 0;
  var pc = document.getElementById('akPerCapita');
  if (pc) pc.value = mem > 0 ? (inc / mem).toFixed(2) : '';
}
function previewAkPhoto(input) {
  if (input.files && input.files[0]) {
    akSelectedPhoto = input.files[0];
    var reader = new FileReader();
    reader.onload = function(e) { document.getElementById('akPhotoPreview').innerHTML = '<img src="' + e.target.result + '" style="width:100%;height:100%;object-fit:cover;border-radius:6px;">'; };
    reader.readAsDataURL(input.files[0]);
  }
}
var mgjSelectedPhoto = null;
function previewMgjPhoto(input) {
  if (input.files && input.files[0]) {
    mgjSelectedPhoto = input.files[0];
    var reader = new FileReader();
    reader.onload = function(e) {
      var preview = document.getElementById('mgjPhotoPreview');
      if (preview) preview.innerHTML = '<img src="' + e.target.result + '" style="width:100%;height:100%;object-fit:cover;border-radius:6px;">';
    };
    reader.readAsDataURL(input.files[0]);
  }
}


// ---- VIEW AK ----
function viewAkDetail(id) { viewingAkId = id; _ctxSet('viewAk', id); navigateTo('viewAk'); }
// 2026-05-28: Cache the last-loaded payload so the inline-edit save
// path (saveAkEditCell) can rebuild the full PUT payload using all
// the fields it isn't touching. apiAkDetail returns the full leader
// row — we re-use it for the merge instead of re-fetching.
var _akViewPayload = null;
function loadAkDetail(id) {
  function _d(l, v) { return '<div class="detail-item"><label>' + l + '</label><span>' + escHtml(v || '—') + '</span></div>'; }
  // 2026-05-28: Editable detail cell — used for Current Education +
  // Stream Chosen on the AK View page. Renders the value plus a
  // pencil icon; clicking it swaps the cell content via enterAkEditCell.
  // `field` is the key in the leader payload (current_education / stream_chosen).
  function _dEdit(l, v, field) {
    var displayId = 'akViewCell-' + field;
    return '<div class="detail-item" id="' + displayId + '" data-ak-edit-field="' + field + '">' +
             '<label style="display:flex;align-items:center;gap:8px;">' + escHtml(l) +
               '<button type="button" class="btn-icon" title="Edit ' + escHtml(l) + '" ' +
                 'style="padding:2px 6px;color:#732269;font-size:11px;cursor:pointer;background:transparent;border:none;" ' +
                 'onclick="enterAkEditCell(\'' + field + '\')">' +
                 '<i class="fas fa-pencil-alt"></i></button>' +
             '</label>' +
             '<span class="ak-edit-display">' + escHtml(v || '—') + '</span>' +
           '</div>';
  }
  apiAkDetail(id).then(function(m) {
    _akViewPayload = m;
    document.getElementById('akViewName').textContent = m.name || '—';
    var summary = document.getElementById('akViewSummary');
    if (summary) summary.innerHTML = '<strong>' + escHtml(m.enrollment_number || '') + '</strong> &nbsp;|&nbsp; ' +
      escHtml(m.centre_name || '') + ' &nbsp;|&nbsp; ' + escHtml(m.batch_name || '') + ' &nbsp;|&nbsp; ' + statusBadge(m.status);
    var wo = document.getElementById('btnAkWalkOut');
    if (wo) wo.style.display = (m.status === 'Active') ? '' : 'none';
    if (m.photo_url) {
      var pc = document.getElementById('akViewPhotoContainer');
      if (pc) pc.innerHTML = '<img src="' + m.photo_url + '" alt="Photo" style="width:80px;height:80px;border-radius:50%;object-fit:cover;">';
    }
    var bg = document.getElementById('akViewBasicGrid');
    if (bg) {
      bg.innerHTML = _d('State', m.state_name) + _d('Centre', m.centre_name) + _d('Batch', m.batch_name) +
        _d('Name', m.name) + _d('Address', m.address) + _d('Contact Number', m.contact_number) +
        _d('Year of Joining', m.year_of_joining ? String(m.year_of_joining) : null) +
        // 2026-05-28: "Age" → "Age at Enrollment" (the value captured at
        // enrolment time) and a new "Present Age" cell beside it that's
        // computed from the live DOB. View-only — neither field is
        // editable here; the underlying m.age column is unchanged.
        _d('DOB', m.dob ? formatDateNice(m.dob) : null) +
        _d('Age at Enrollment', m.age != null ? String(m.age) : null) +
        _d('Present Age', (function() { var pa = _computePresentAge(m.dob); return pa != null ? String(pa) + ' years' : null; })()) +
        // 2026-05-28: Current Education + Stream Chosen are inline-
        // editable on the View page for all user roles (per user
        // request). The pencil swaps the cell to an editor; Save
        // calls apiUpdateAk with the full payload merged from
        // _akViewPayload. Stream cell is only editable when
        // Current Education is 11th / 12th — enterAkEditCell guards.
        _dEdit('Current Education', m.current_education, 'current_education') +
        _dEdit('Stream Chosen',     m.stream_chosen,     'stream_chosen') +
        (m.stream_other ? _d('Stream (Other)', m.stream_other) : '') +
        _d('Category', m.category) + (m.category_other ? _d('Category (Other)', m.category_other) : '') +
        _d('Religion', m.religion) + (m.religion_other ? _d('Religion (Other)', m.religion_other) : '') +
        // 2026-05-30: Gender is now inline-editable on the View page so the
        // user can correct or update it any time after the leader profile
        // has been submitted. Uses _AK_GENDER_OPTIONS — see enterAkEditCell.
        _dEdit('Gender', m.gender, 'gender');
    }
    var fg = document.getElementById('akViewFamilyGrid');
    if (fg) {
      fg.innerHTML = _d('Mother Name', m.mother_name) + _d('Mother Occupation', m.mother_occupation) +
        _d('Father Name', m.father_name) + _d('Father Occupation', m.father_occupation) +
        _d('Family Monthly Income', m.family_monthly_income ? '\u20B9' + formatNumber(m.family_monthly_income) : null) +
        _d('Family Members', m.family_members != null ? String(m.family_members) : null) +
        _d('Per Capita Income', m.per_capita_income ? '\u20B9' + formatNumber(m.per_capita_income) : null);
    }
    if (m.walkout_reason) {
      fg.innerHTML += '<div class="detail-item full-width" style="border-top:1px solid #eee;padding-top:10px;margin-top:10px;"><label style="color:#e74c3c;">Walkout Reason</label><span>' + escHtml(m.walkout_reason) + '</span></div>';
    }
  }).catch(function() { var bg = document.getElementById('akViewBasicGrid'); if (bg) bg.innerHTML = '<p style="color:red;">Error loading AK leader.</p>'; });
}

// ---- AK View page: inline-edit cells (Current Education + Stream Chosen) ----
// 2026-05-28: All roles can edit these two fields from the View page,
// even after the leader profile has been submitted. The backend PUT
// /api/ak/{id} accepts the full AKCreate payload with no role check,
// so we merge the edited value into the cached _akViewPayload and
// resubmit. Stream is only offered when Current Education is 11th /
// 12th (mirrors the form's onAkEducationChange gating).

var _AK_EDU_OPTIONS    = ['8th','9th','10th','11th','12th'];
var _AK_STREAM_OPTIONS = ['Humanities/Arts','Commerce','Science','Any Other'];
// 2026-05-30: Gender option list — kept in sync with the Add AK form's
// <select id="akGender"> dropdown. New entries must be added to BOTH places.
var _AK_GENDER_OPTIONS = ['Cis Woman','Non-Binary','Trans*','Prefer Not to Say','Other'];
var _AK_EDU_NEEDS_STREAM = function(edu) { return edu === '11th' || edu === '12th'; };

function enterAkEditCell(field) {
  if (!_akViewPayload) return;
  var cell = document.getElementById('akViewCell-' + field);
  if (!cell) return;
  var display = cell.querySelector('.ak-edit-display');
  if (!display) return;

  // Stream cell is only editable when current_education qualifies. If
  // someone clicks the pencil while edu is 10th-or-below, gently nudge
  // them to change Current Education first instead of opening a useless
  // empty dropdown.
  if (field === 'stream_chosen' && !_AK_EDU_NEEDS_STREAM(_akViewPayload.current_education)) {
    alert('Stream applies only when Current Education is 11th or 12th. ' +
          'Update Current Education first if needed.');
    return;
  }

  var current = _akViewPayload[field] || '';
  // 2026-05-30: Pick the right option list for the field being edited.
  // Defaults to Stream so existing two-field behaviour is preserved.
  var options;
  if (field === 'current_education')      options = _AK_EDU_OPTIONS;
  else if (field === 'gender')            options = _AK_GENDER_OPTIONS;
  else                                    options = _AK_STREAM_OPTIONS;
  var optsHtml = '<option value="">-- Select --</option>' + options.map(function(o) {
    return '<option value="' + escHtml(o) + '"' + (o === current ? ' selected' : '') + '>' + escHtml(o) + '</option>';
  }).join('');

  // Build the editor HTML: dropdown + Save + Cancel inline.
  display.outerHTML =
    '<div class="ak-edit-display" style="display:flex;flex-wrap:wrap;gap:6px;align-items:center;">' +
      '<select id="akEditSel-' + field + '" style="flex:1 1 160px;padding:4px 8px;">' + optsHtml + '</select>' +
      '<button type="button" class="btn btn-primary btn-sm" style="padding:4px 10px;font-size:12px;" ' +
        'onclick="saveAkEditCell(\'' + field + '\')"><i class="fas fa-save"></i> Save</button>' +
      '<button type="button" class="btn btn-outline btn-sm" style="padding:4px 10px;font-size:12px;" ' +
        'onclick="cancelAkEditCell(\'' + field + '\')">Cancel</button>' +
    '</div>';
}

function cancelAkEditCell(field) {
  // Just re-render the View — easiest restore.
  if (viewingAkId) loadAkDetail(viewingAkId);
}

function saveAkEditCell(field) {
  if (!_akViewPayload || !viewingAkId) return;
  var sel = document.getElementById('akEditSel-' + field);
  if (!sel) return;
  var newVal = sel.value || null;

  // Build a fresh payload from the cached AK leader row + the edited field.
  // The PUT endpoint takes every persisted column; missing keys would
  // be sent as undefined and the backend would write NULL — so we
  // explicitly pass through everything we have, then overwrite the one
  // field the user changed.
  var m = _akViewPayload;
  var payload = {
    name: m.name || '',
    state_code: m.state_code || null,
    centre_code: m.centre_code || null,
    batch_id: m.batch_id || null,
    address: m.address || null,
    contact_number: m.contact_number || null,
    year_of_joining: m.year_of_joining || null,
    dob: m.dob || null,
    age: m.age != null ? m.age : null,
    current_education: m.current_education || null,
    stream_chosen: m.stream_chosen || null,
    stream_other: m.stream_other || null,
    category: m.category || null,
    category_other: m.category_other || null,
    religion: m.religion || null,
    religion_other: m.religion_other || null,
    gender: m.gender || null,
    mother_name: m.mother_name || null,
    mother_occupation: m.mother_occupation || null,
    father_name: m.father_name || null,
    father_occupation: m.father_occupation || null,
    family_monthly_income: m.family_monthly_income != null ? m.family_monthly_income : null,
    family_members: m.family_members != null ? m.family_members : null,
    per_capita_income: m.per_capita_income != null ? m.per_capita_income : null,
    status: m.status || null,
    created_by: m.created_by || null,
  };
  payload[field] = newVal;

  // If Current Education is being changed to a non-11th/12th value,
  // clear the now-irrelevant Stream + StreamOther so they don't linger
  // as stale data in the DB.
  if (field === 'current_education' && !_AK_EDU_NEEDS_STREAM(newVal)) {
    payload.stream_chosen = null;
    payload.stream_other  = null;
  }

  apiUpdateAk(viewingAkId, payload).then(function() {
    // Reload the detail to refresh both cells (and pick up any side-effect
    // like the auto-cleared Stream when Current Education was demoted).
    loadAkDetail(viewingAkId);
  }).catch(function(err) { showUserError('updating AK leader', err); });
}

// ---- AK WALKOUT ----
function openAkWalkOutForm() {
  var m = document.getElementById('akWalkOutModal'); if (!m) return;
  document.getElementById('akWalkOutDate').value = new Date().toISOString().split('T')[0];
  document.getElementById('akWalkOutReason').value = '';
  m.style.display = 'flex';
}
function closeAkWalkOutModal() { var m = document.getElementById('akWalkOutModal'); if (m) m.style.display = 'none'; }
function submitAkWalkOut() {
  var d = (document.getElementById('akWalkOutDate') || {}).value;
  var r = (document.getElementById('akWalkOutReason') || {}).value;
  if (!d || !r.trim()) { alert('Both date and reason are required.'); return; }
  if (!confirm('Are you sure you want to mark this leader as Dropout?')) return;
  apiAkWalkout(viewingAkId, { walkout_date: d, walkout_reason: r.trim() }).then(function() {
    closeAkWalkOutModal(); loadAkDetail(viewingAkId);
  }).catch(function(e) { showUserError('processing your request', e); });
}

// ---- AK TRAINING LIST ----
function loadAkTrainingListData(page) {
  // apiAvailable check removed - AK/MGJ APIs work independently
  if (typeof page === 'number') akTrCurrentPage = page;
  if (!_akTrFilterStateLoaded) {
    _akTrFilterStateLoaded = true;
    _populateAkStatesInto('akTrFilterState', 'All States');
  }
  var p = { page: akTrCurrentPage, limit: akTrPageLimit };
  var s = document.getElementById('akTrFilterState');
  var c = document.getElementById('akTrFilterCentre');
  var b = document.getElementById('akTrFilterBatch');
  var cat = document.getElementById('akTrFilterCategory');
  var d = document.getElementById('akTrFilterDate');
  var t = document.getElementById('akTrFilterTopic');
  if (s && s.value) p.state_code = s.value;
  if (c && c.value) p.centre_code = c.value;
  if (b && b.value) p.batch_id = b.value;
  if (cat && cat.value) p.category = cat.value;
  if (d && d.value) p.training_date = d.value;
  if (t && t.value.trim()) p.topic_name = t.value.trim();
  p = _applyRoleScopeFloor(p);
  apiAkTrainingList(p).then(function(result) {
    var data = result.data || [];
    var tbody = document.getElementById('akTrainingListBody');
    if (!tbody) return;
    if (!data.length) {
      tbody.innerHTML = '<tr><td colspan="8" style="text-align:center;color:#999;padding:30px;">No trainings found.</td></tr>';
      renderListPagination('#page-akTrainingList .pagination', 0, akTrCurrentPage, akTrPageLimit, 'loadAkTrainingListData');
      return;
    }
    var html = '';
    var _canDel = _canDeleteRecord();
    data.forEach(function(t, i) {
      var loc = [t.centre_name, t.state_name].filter(Boolean).join(', ');
      var _label = escHtml(t.topic_name || ('training #' + t.id)).replace(/\'/g, "\\'");
      html += '<tr><td>' + ((akTrCurrentPage - 1) * akTrPageLimit + i + 1) + '</td>' +
        '<td>' + escHtml(loc) + '</td><td>' + escHtml(t.batch_name || '—') + '</td>' +
        '<td>' + escHtml(t.category || '—') + '</td><td>' + escHtml(t.topic_name || '') + '</td>' +
        '<td>' + (t.training_date ? formatDateNice(t.training_date) : '—') + '</td>' +
        '<td>' + (t.participant_count || 0) + '</td>' +
        '<td>' +
          '<button class="btn-icon" title="Assign Participants" onclick="openAkAssignLeaders(' + t.id + ')"><i class="fas fa-user-plus"></i></button>' +
          '<button class="btn-icon" title="View" onclick="viewAkTrainingDetail(' + t.id + ')"><i class="fas fa-eye"></i></button>' +
          '<button class="btn-icon" title="Edit" onclick="openEditAkTraining(' + t.id + ')"><i class="fas fa-edit"></i></button>' +
          '<button class="btn-icon" title="Images" onclick="openAkTrainingImages(' + t.id + ')"><i class="fas fa-camera"></i></button>' +
          (_canDel ? '<button class="btn-icon text-danger" title="Delete" onclick="deleteAkTrainingFromList(' + t.id + ',\'' + _label + '\')"><i class="fas fa-trash-alt"></i></button>' : '') +
        '</td></tr>';
    });
    tbody.innerHTML = html;
    renderListPagination('#page-akTrainingList .pagination', result.total || 0, akTrCurrentPage, akTrPageLimit, 'loadAkTrainingListData');
  }).catch(function(e) { console.error('AK training list error:', e); });
}
function applyAkTrainingFilters() { akTrCurrentPage = 1; loadAkTrainingListData(1); }
function resetAkTrainingFilters() {
  _clearListFilters('akTrainingList');
  ['akTrFilterState','akTrFilterCentre','akTrFilterBatch','akTrFilterCategory','akTrFilterDate','akTrFilterTopic'].forEach(function(id) {
    var el = document.getElementById(id); if (el) el.value = '';
  });
  // 2026-06-08: SL/DL/PI re-apply soft 2-option lock so Centre dropdown
  // keeps "All Centres + <user centre>" after Reset.
  var _r = currentUser && currentUser.role || '';
  if ((_r === 'pi' || _r === 'district_lead' || _r === 'state_lead') &&
      typeof _lockAkFiltersForDlPi === 'function') {
    _lockAkFiltersForDlPi('akTrFilterState', 'akTrFilterCentre', { stateMode: 'soft', centreMode: 'soft' });
  }
  akTrCurrentPage = 1; loadAkTrainingListData(1);
}
function onAkTrFilterStateChange() {
  var sc = (document.getElementById('akTrFilterState') || {}).value;
  _loadAkCentresInto('akTrFilterCentre', sc, null, 'All Centres');
  _loadAkBatchesInto('akTrFilterBatch', sc, null, 'All Batches');
}
// 2026-06-06: Centre→Batch cascade for Training List per user spec.
function onAkTrFilterCentreChange() {
  var sc = (document.getElementById('akTrFilterState')  || {}).value || '';
  var cc = (document.getElementById('akTrFilterCentre') || {}).value || '';
  _loadAkBatchesInto('akTrFilterBatch', sc, null, 'All Batches', cc);
}
function exportAkTrainingToExcel() { /* TODO */ alert('Export coming soon'); }

// ---- ADD/EDIT AK TRAINING ----
// 2026-05-29: Topic/Training Name is now a dropdown — when the user picks
// "Other" we reveal the akTrTopicOther free-text input. This list is the
// canonical set of training topic options shown in the dropdown.
//
// 2026-06-04: synced with the 44-session standardized master deployed in
