function onAkTrTopicChange() {
  var sel = document.getElementById('akTrTopic');
  var grp = document.getElementById('akTrTopicOtherGrp');
  var oth = document.getElementById('akTrTopicOther');
  if (!sel || !grp) return;
  var isOther = (sel.value === 'Other');
  grp.style.display = isOther ? '' : 'none';
  if (!isOther && oth) oth.value = '';
}
// When hydrating an existing record whose topic_name doesn't match any
// dropdown option (typically a legacy free-text entry), we treat it as
// "Other" and pre-fill the Specify input so the value isn't lost on save.
function _hydrateAkTrTopic(topicName) {
  var sel = document.getElementById('akTrTopic');
  var oth = document.getElementById('akTrTopicOther');
  if (!sel) return;
  topicName = topicName || '';
  var inSet = window._AK_TR_TOPIC_OPTIONS.indexOf(topicName) > -1 && topicName !== 'Other';
  if (topicName && !inSet) {
    sel.value = 'Other';
    if (oth) oth.value = topicName;
  } else {
    sel.value = topicName;
    if (oth) oth.value = '';
  }
  onAkTrTopicChange();
}

function openAddAkTraining() {
  akTrFormMode = 'add'; editingAkTrId = null;
  navigateTo('addAkTraining');
  setTimeout(function() {
    var _tt = document.getElementById('addAkTrainingTitle'); if (_tt) _tt.innerHTML = '<i class="fas fa-chalkboard-teacher"></i> Add New Training';
    var _ts = document.getElementById('akTrSubmitText'); if (_ts) _ts.textContent = 'Submit';
    var _tb = document.getElementById('addAkTrBcText'); if (_tb) _tb.textContent = 'Add Training';
    ['akTrDate','akTrTrainer','akTrTopicOther'].forEach(function(id) { var el = document.getElementById(id); if (el) el.value = ''; });
    // 2026-05-30: akTrMonth added to the reset list. Required dropdown.
    ['akTrMonth','akTrState','akTrCentre','akTrBatch','akTrCategory','akTrTopic'].forEach(function(id) { var el = document.getElementById(id); if (el) el.selectedIndex = 0; });
    onAkTrTopicChange();  // make sure the Specify group is hidden on a fresh form
    _populateAkTrFormState();
  }, 100);
}
function openEditAkTraining(id) {
  akTrFormMode = 'edit'; editingAkTrId = id;
  navigateTo('addAkTraining');
  setTimeout(function() {
    var _tt = document.getElementById('addAkTrainingTitle'); if (_tt) _tt.innerHTML = '<i class="fas fa-chalkboard-teacher"></i> Edit Training';
    var _ts = document.getElementById('akTrSubmitText'); if (_ts) _ts.textContent = 'Update';
    var _tb = document.getElementById('addAkTrBcText'); if (_tb) _tb.textContent = 'Edit Training';
    _populateAkTrFormState();
    apiAkTrainingDetail(id).then(function(t) {
      if (t.state_code) { document.getElementById('akTrState').value = t.state_code; onAkTrFormStateChange(function() {
        if (t.centre_code) document.getElementById('akTrCentre').value = t.centre_code;
        _loadAkTrBatchOptions(t.state_code, t.batch_id);
      }); }
      document.getElementById('akTrCategory').value = t.category || '';
      _hydrateAkTrTopic(t.topic_name || '');
      document.getElementById('akTrDate').value = t.training_date || '';
      document.getElementById('akTrTrainer').value = t.trainer_name || '';
      // 2026-05-30: Hydrate Month — falls back to the month name derived
      // from training_date so records created BEFORE this column existed
      // still show a meaningful value in the dropdown.
      var _mEl = document.getElementById('akTrMonth');
      if (_mEl) {
        var monthVal = t.training_month || '';
        if (!monthVal && t.training_date) {
          var _d = new Date(t.training_date);
          if (!isNaN(_d.getTime())) {
            monthVal = ['January','February','March','April','May','June',
                        'July','August','September','October','November','December'][_d.getMonth()];
          }
        }
        _mEl.value = monthVal;
      }
    });
  }, 100);
}
function saveAkTraining() {
  function _v(id) { var el = document.getElementById(id); return el ? (el.value || '').trim() : ''; }
  // 2026-05-30: Month is required (reporting month). Validated first so
  // the user gets the alert before they discover the rest of the row.
  if (!_v('akTrMonth')) { alert('Please select Month.'); return; }
  if (!_v('akTrState')) { alert('Please select State.'); return; }
  if (!_v('akTrCentre')) { alert('Please select Centre.'); return; }
  if (!_v('akTrBatch')) { alert('Please select Batch.'); return; }
  if (!_v('akTrCategory')) { alert('Please select Category.'); return; }
  // 2026-06-04: alert wording updated per user spec — the field is now
  // called "Monthly Leadership Session" throughout the UI.
  if (!_v('akTrTopic')) { alert('Please select Monthly Leadership Session.'); return; }
  // When the user picks "Other" they must fill in the Specify input. We
  // store the specified text in topic_name so downstream rendering /
  // exports keep working without a schema change.
  var topicValue = _v('akTrTopic');
  if (topicValue === 'Other') {
    var other = _v('akTrTopicOther');
    if (!other) { alert('Please specify the Topic/Training Name in "Specify, If any other".'); return; }
    topicValue = other;
  }
  if (!_v('akTrDate')) { alert('Please select Date.'); return; }
  var data = {
    training_month: _v('akTrMonth'),
    state_code: _v('akTrState'), centre_code: _v('akTrCentre'),
    batch_id: parseInt(_v('akTrBatch')), category: _v('akTrCategory'),
    topic_name: topicValue, training_date: _v('akTrDate'),
    trainer_name: _v('akTrTrainer') || null
  };
  var promise = (akTrFormMode === 'edit' && editingAkTrId) ? apiUpdateAkTraining(editingAkTrId, data) : apiCreateAkTraining(data);
  promise.then(function() {
    alert(akTrFormMode === 'edit' ? 'Training updated!' : 'Training created!');
    navigateTo('akTrainingList');
  }).catch(function(e) { showUserError('processing your request', e); });
}
function _populateAkTrFormState() {
  // 2026-06-04 (v2): user reports State dropdown still empty after the
  // v1 stuck-flag fix. Bypass the shared _akStateLoadingMap +
  // _populateAkStatesInto path entirely with a bulletproof inline XHR
  // dedicated to akTrState. No flags, no early-returns, no shared
  // state — every call wipes the dropdown to placeholder and fires a
  // fresh request. If two requests race, the last to complete wins
  // because each callback re-wipes innerHTML before appending. This
  // mirrors the pattern AK Adda Form uses (line ~23698) which has
  // never reported this class of bug.
  var sel = document.getElementById('akTrState');
  if (!sel) return;
  // 2026-06-06: State Lead short-circuit. The bulletproof XHR below
  // ALWAYS rewrites the dropdown to "Select State" + all states, so it
  // would clobber any state lock applied earlier. Same fix pattern as
  // _loadAkStatesForModal / _populateAkStatesInto.
  if (currentUser && currentUser.role === 'state_lead' && currentUser.state_code) {
    var slName = currentUser.state_name || currentUser.state_code;
    sel.innerHTML = '<option value="' + escHtml(currentUser.state_code) + '" selected>' + escHtml(slName) + '</option>';
    sel.value = currentUser.state_code;
    sel.disabled = true;
    sel.style.backgroundColor = '#f5f5f5';
    sel.style.cursor = 'not-allowed';
    sel.title = 'Locked to your assigned State';
    if (!currentUser.state_name) {
      apiGet('/ak-master/dropdown/states').then(function(rows) {
        (rows || []).some(function(r) {
          if (r.state_code === currentUser.state_code) {
            currentUser.state_name = r.state_name;
            try { localStorage.setItem('azadUserData', JSON.stringify(currentUser)); } catch (e) {}
            var s2 = document.getElementById('akTrState');
            if (s2) s2.innerHTML = '<option value="' + escHtml(currentUser.state_code) + '" selected>' + escHtml(r.state_name) + '</option>';
            return true;
          }
          return false;
        });
      }).catch(function() {});
    }
    // Fire change so the Centre cascade runs against the SL's state.
    try { sel.dispatchEvent(new Event('change', { bubbles: true })); } catch (e) {}
    return;
  }
  sel.innerHTML = '<option value="">Select State</option>';
  var xhr = new XMLHttpRequest();
  xhr.open('GET', window.location.origin + '/api/ak/geo/states', true);
  xhr.onload = function() {
    if (xhr.status !== 200) {
      console.error('[AK Training] state XHR HTTP', xhr.status);
      return;
    }
    try {
      var states = JSON.parse(xhr.responseText);
      var s2 = document.getElementById('akTrState');
      if (!s2) return;
      // Re-wipe right before appending to win over any racing XHR.
      s2.innerHTML = '<option value="">Select State</option>';
      for (var i = 0; i < states.length; i++) {
        var o = document.createElement('option');
        o.value = states[i].state_code;
        o.textContent = states[i].state_name;
        s2.appendChild(o);
      }
    } catch (e) { console.error('[AK Training] state parse error:', e); }
  };
  xhr.onerror = function() { console.error('[AK Training] state XHR network error'); };
  xhr.send();
}
function onAkTrFormStateChange(cb) {
  var sc = (document.getElementById('akTrState') || {}).value;
  _loadAkCentresInto('akTrCentre', sc, cb);
  // 2026-06-06: Per user spec, Batch must stay empty until a Centre is
  // picked — picking just a State should NOT pre-populate batches.
  // Reset the Batch dropdown to its placeholder and let
  // onAkTrFormCentreChange fill it on the next cascade step.
  var bSel = document.getElementById('akTrBatch');
  if (bSel) bSel.innerHTML = '<option value="">Select Batch</option>';
}
// 2026-06-06: Centre→Batch cascade for Add Training. When the user
// picks a Centre, narrow the Batch dropdown to that centre's batches.
// If Centre is cleared, Batch stays empty (per user spec).
function onAkTrFormCentreChange() {
  var sc = (document.getElementById('akTrState')  || {}).value || '';
  var cc = (document.getElementById('akTrCentre') || {}).value || '';
  var bSel = document.getElementById('akTrBatch');
  if (bSel) bSel.innerHTML = '<option value="">Select Batch</option>';
  // No centre picked => leave Batch as the placeholder only.
  if (!cc) return;
  _loadAkBatchesInto('akTrBatch', sc, null, 'Select Batch', cc);
}
// 2026-06-06: Per-select request token map. Each call increments the
// counter for its select id; only the response matching the latest
// counter renders. Prevents the State→Centre cascade and Centre→Batch
// cascade from racing two XHRs that both append to the dropdown.
var _akBatchesReqSeqMap = {};
function _loadAkBatchesInto(selectId, stateCode, selectedId, defaultLabel, centreCode) {
  var bSel = document.getElementById(selectId);
  if (!bSel) return;
  var lbl = defaultLabel || 'Select Batch';
  bSel.innerHTML = '<option value="">' + lbl + '</option>';
  // 2026-06-05: For State Lead, if the caller didn't pass an explicit
  // stateCode (e.g. early load before the State cascade has fired), fall
  // back to their assigned state so the dropdown never momentarily shows
  // all-states batches. Mobiliser/Sangini also get this floor for the
  // (rare) case they reach an AK page that calls this helper directly.
  if (!stateCode && currentUser && currentUser.state_code) {
    var role = currentUser.role || '';
    if (role === 'state_lead' || role === 'district_lead' || role === 'pi' ||
        role === 'mobiliser' || role === 'sangini') {
      stateCode = currentUser.state_code;
    }
  }
  // 2026-06-06: Per user spec, when a Centre is provided the batch
  // dropdown narrows to that centre's batches only. Centre takes
  // precedence over state when both are present so the Centre→Batch
  // cascade (Dashboard, AK List, Add AK, Training List, Add Training)
  // shows only batches mapped to the picked centre in Batch Management.
  var qs = 'status=Active&limit=100';
  if (centreCode) {
    qs += '&centre_code=' + encodeURIComponent(centreCode);
  } else if (stateCode) {
    qs += '&state_code=' + encodeURIComponent(stateCode);
  }
  // 2026-06-06: Request-token + id-dedupe (same pattern as
  // _loadAkDashBatches). Multiple cascade events (State change fires
  // both Centre population AND Batch reset; SL auto-fire on lock can
  // overlap with the user's first Centre pick) used to race two XHRs
  // that both appended to the dropdown, doubling every batch. Now:
  //   * each call increments a per-select sequence — only the latest
  //     response renders; older responses are dropped on the floor.
  //   * append-time dedupe by batch.id covers the (rare) case where
  //     the backend itself returns the same batch twice.
  _akBatchesReqSeqMap[selectId] = (_akBatchesReqSeqMap[selectId] || 0) + 1;
  var mySeq = _akBatchesReqSeqMap[selectId];
  var url = window.location.origin + '/api/ak-batches?' + qs;
  var xhr = new XMLHttpRequest();
  xhr.open('GET', url, true);
  xhr.onload = function() {
    if (xhr.status === 200) {
      try {
        // Drop stale responses.
        if (_akBatchesReqSeqMap[selectId] !== mySeq) return;
        var result = JSON.parse(xhr.responseText);
        var data = Array.isArray(result) ? result : (result.data || []);
        var s2 = document.getElementById(selectId);
        if (!s2) return;
        var seen = {};
        for (var i = 0; i < data.length; i++) {
          if (!data[i] || data[i].id == null) continue;
          if (seen[data[i].id]) continue;
          seen[data[i].id] = 1;
          var o = document.createElement('option');
          o.value = data[i].id;
          // When loading across all states (no state filter), append the
          // state name so users can disambiguate batches with the same
          // name across different states. Mirrors the FLP list behaviour.
          // 2026-06-05: Drop the state-name suffix entirely per user
          // request. SL/DL/PI never see batches from other states (the
          // backend role-scope helper pins the state filter for them),
          // and Admin/Super Admin can disambiguate via the State filter
          // they're already using. Cleaner labels everywhere.
          var label = data[i].name + (data[i].year ? ' (' + data[i].year + ')' : '');
          o.textContent = label;
          if (selectedId && data[i].id == selectedId) o.selected = true;
          s2.appendChild(o);
        }
      } catch(e) {}
    }
  };
  xhr.send();
}
function _loadAkTrBatchOptions(stateCode, selectedId) {
  _loadAkBatchesInto('akTrBatch', stateCode, selectedId);
}

// ---- VIEW AK TRAINING ----
function viewAkTrainingDetail(id) { viewingAkTrainingId = id; _ctxSet('viewAkTraining', id); navigateTo('viewAkTraining'); }
function loadAkTrainingDetail(id) {
  apiAkTrainingDetail(id).then(function(t) {
    var dg = document.getElementById('akTrViewDetails');
    if (dg) {
      dg.innerHTML =
        // 2026-05-30: Month rendered first (matches the form ordering on
        // the Add Training screen). Falls back to deriving from training_date
        // for legacy rows without the new column.
        '<div class="detail-item"><label>Month</label><span>' + escHtml(
          t.training_month || (t.training_date ? (function() {
            var _d = new Date(t.training_date);
            return isNaN(_d.getTime()) ? '' : ['January','February','March','April','May','June',
              'July','August','September','October','November','December'][_d.getMonth()];
          })() : '') || '—'
        ) + '</span></div>' +
        '<div class="detail-item"><label>State</label><span>' + escHtml(t.state_name || '—') + '</span></div>' +
        '<div class="detail-item"><label>Centre</label><span>' + escHtml(t.centre_name || '—') + '</span></div>' +
        '<div class="detail-item"><label>Batch</label><span>' + escHtml(t.batch_name || '—') + '</span></div>' +
        '<div class="detail-item"><label>Category</label><span>' + escHtml(t.category || '—') + '</span></div>' +
        '<div class="detail-item"><label>Date</label><span>' + (t.training_date ? formatDateNice(t.training_date) : '—') + '</span></div>' +
        '<div class="detail-item"><label>Facilitator Name</label><span>' + escHtml(t.trainer_name || '—') + '</span></div>' +
        '<div class="detail-item"><label>Total Participants</label><span>' + ((t.participants || []).length) + '</span></div>';
    }
    var tp = document.getElementById('akTrViewTopics');
    if (tp) tp.innerHTML = '<span style="background:#fff3cd;color:#856404;padding:4px 12px;border-radius:20px;font-size:13px;">' + escHtml(t.topic_name || '—') + '</span>';
    document.getElementById('akTrParticipantCount').textContent = (t.participants || []).length;
    var tbody = document.getElementById('akTrParticipantsBody');
    if (tbody) {
      var parts = t.participants || [];
      if (!parts.length) { tbody.innerHTML = '<tr><td colspan="5" style="text-align:center;color:#999;">No participants assigned.</td></tr>'; }
      else {
        var html = '';
        parts.forEach(function(p, i) {
          html += '<tr><td>' + (i + 1) + '</td><td>' + escHtml(p.leader_name || '') + '</td><td>' + escHtml(p.batch_name || '—') + '</td>' +
            '<td>' + statusBadge(p.leader_status || 'Active') + '</td>' +
            '<td id="akAtt_' + p.leader_id + '">' + (p.attendance === 'Present' ? '<span style="color:green;">Present</span>' : p.attendance === 'Absent' ? '<span style="color:red;">Absent</span>' : '—') + '</td></tr>';
        });
        tbody.innerHTML = html;
      }
    }
    // attendance stats
    var parts = t.participants || [];
    var present = parts.filter(function(p) { return p.attendance === 'Present'; }).length;
    var absent = parts.filter(function(p) { return p.attendance === 'Absent'; }).length;
    var statsDiv = document.getElementById('akTrAttendanceStats');
    if (statsDiv && parts.length) {
      statsDiv.style.display = 'flex';
      statsDiv.innerHTML = '<span><strong>Present:</strong> ' + present + '</span><span><strong>Absent:</strong> ' + absent + '</span><span><strong>Attendance%:</strong> ' + (parts.length ? ((present / parts.length) * 100).toFixed(1) : 0) + '%</span>';
    }
  }).catch(function(e) { console.error('AK training view error:', e); });
}
function toggleAkAttendanceMode() {
  // Toggle attendance dropdowns in participant table
  var tbody = document.getElementById('akTrParticipantsBody');
  if (!tbody) return;
  var rows = tbody.querySelectorAll('tr');
  var isEditMode = tbody.getAttribute('data-edit') === '1';
  if (isEditMode) {
    // Save attendance
    var attendances = [];
    rows.forEach(function(row) {
      var sel = row.querySelector('select');
      var lid = row.getAttribute('data-lid');
      if (sel && lid) attendances.push({ leader_id: parseInt(lid), attendance: sel.value });
    });
    if (attendances.length) {
      apiAkTrainingAttendance(viewingAkTrainingId, attendances).then(function() {
        alert('Attendance saved!'); loadAkTrainingDetail(viewingAkTrainingId);
      }).catch(function(e) { showUserError('processing your request', e); });
    }
    tbody.setAttribute('data-edit', '0');
    document.getElementById('btnAkMarkAttendance').innerHTML = '<i class="fas fa-clipboard-check"></i> Mark Attendance';
  } else {
    // Enter edit mode - replace attendance cells with dropdowns
    rows.forEach(function(row) {
      var cells = row.querySelectorAll('td');
      if (cells.length >= 5) {
        var attCell = cells[4];
        var current = attCell.textContent.trim();
        var lid = attCell.id ? attCell.id.replace('akAtt_', '') : '';
        row.setAttribute('data-lid', lid);
        attCell.innerHTML = '<select style="padding:4px 8px;border-radius:4px;border:1px solid #ddd;"><option value="Present"' + (current === 'Present' ? ' selected' : '') + '>Present</option><option value="Absent"' + (current === 'Absent' ? ' selected' : '') + '>Absent</option></select>';
      }
    });
    tbody.setAttribute('data-edit', '1');
    document.getElementById('btnAkMarkAttendance').innerHTML = '<i class="fas fa-save"></i> Save Attendance';
  }
}

// ---- AK ASSIGN LEADERS ----
function openAkAssignLeaders(trainingId) {
  akAssigningTrainingId = trainingId;
  navigateTo('akAssignLeaders');
  apiAkTrainingDetail(trainingId).then(function(t) {
    var info = document.getElementById('akAssignTrainingInfo');
    if (info) info.innerHTML = '<div class="info-item"><strong>State:</strong> ' + escHtml(t.state_name || '') + '</div>' +
      '<div class="info-item"><strong>Centre:</strong> ' + escHtml(t.centre_name || '') + '</div>' +
      '<div class="info-item"><strong>Batch:</strong> ' + escHtml(t.batch_name || '') + '</div>' +
      '<div class="info-item"><strong>Category:</strong> ' + escHtml(t.category || '') + '</div>' +
      '<div class="info-item"><strong>Topic:</strong> ' + escHtml(t.topic_name || '') + '</div>' +
      '<div class="info-item"><strong>Date:</strong> ' + (t.training_date ? formatDateNice(t.training_date) : '') + '</div>';
    var sub = document.getElementById('akAssignSubtitle');
    if (sub) sub.textContent = 'All Enrolled AKs (Select to assign)';
    return apiAkTrainingEligible(trainingId);
  }).then(function(leaders) {
    var list = leaders.data || leaders || [];
    var tbody = document.getElementById('akAssignLeadersBody');
    if (!tbody) return;
    if (!list.length) { tbody.innerHTML = '<tr><td colspan="4" style="text-align:center;color:#999;">No eligible leaders found.</td></tr>'; return; }
    var html = '';
    list.forEach(function(l) {
      html += '<tr><td><input type="checkbox" class="akAssignCb" value="' + l.id + '" onchange="updateAkAssignCounter()"></td>' +
        '<td>' + escHtml(l.name) + '</td><td>' + escHtml(l.batch_name || '—') + '</td><td>' + statusBadge(l.status) + '</td></tr>';
    });
    tbody.innerHTML = html;
    updateAkAssignCounter();
  });
}
function toggleAkAssignAll(cb) {
  document.querySelectorAll('.akAssignCb').forEach(function(c) { c.checked = cb.checked; });
  updateAkAssignCounter();
}
function updateAkAssignCounter() {
  var all = document.querySelectorAll('.akAssignCb');
  var checked = document.querySelectorAll('.akAssignCb:checked');
  var el = document.getElementById('akAssignCounter');
  if (el) el.textContent = checked.length + ' of ' + all.length + ' AKs selected';
}
function saveAkAssignments() {
  var ids = [];
  document.querySelectorAll('.akAssignCb:checked').forEach(function(c) { ids.push(parseInt(c.value)); });
  if (!ids.length) { alert('Please select at least one leader.'); return; }
  apiAkTrainingAssign(akAssigningTrainingId, ids).then(function() {
    alert('Leaders assigned successfully!');
    navigateTo('akTrainingList');
  }).catch(function(e) { showUserError('processing your request', e); });
}

// ---- AK TRAINING IMAGES ----
function openAkTrainingImages(trainingId) {
  viewingAkTrainingId = trainingId;
  var modal = document.getElementById('akTrainingImageModal');
  if (modal) modal.style.display = 'flex';
  apiAkTrainingImages(trainingId).then(function(images) {
    var list = images.data || images || [];
    var tbody = document.getElementById('akTrainingImageListBody');
    if (!tbody) return;
    if (!list.length) { tbody.innerHTML = '<tr><td colspan="4" style="text-align:center;color:#999;">No images uploaded.</td></tr>'; return; }
    var html = '';
    list.forEach(function(img, i) {
      var fp = img.file_path || '';
      var nameSafe = (img.file_name || '').replace(/'/g, "\\'");
      html += '<tr><td>' + (i + 1) + '</td><td>' + escHtml(img.file_name || '') + '</td><td>' + (img.uploaded_at ? formatDateNice(img.uploaded_at) : '—') + '</td>' +
        '<td style="text-align:center;white-space:nowrap;">' +
          '<button class="btn btn-outline btn-sm" style="margin-right:6px;" onclick="window.open(\'' + fp + '\',\'_blank\')" title="View"><i class="fas fa-eye"></i></button>' +
          '<a class="btn btn-outline btn-sm" href="' + fp + '" download style="margin-right:6px;" title="Download"><i class="fas fa-download"></i></a>' +
          '<button class="btn btn-outline btn-sm" style="color:#c0392b;border-color:#c0392b;" onclick="deleteAkTrainingImage(' + (img.id || 0) + ', \'' + nameSafe + '\')" title="Delete"><i class="fas fa-trash"></i></button>' +
        '</td></tr>';
    });
    tbody.innerHTML = html;
  });
}
function uploadAkTrainingImage(input) {
  if (!input.files || !input.files[0]) return;
  apiAkTrainingUploadImage(viewingAkTrainingId, input.files[0]).then(function() {
    openAkTrainingImages(viewingAkTrainingId);
    input.value = '';
  }).catch(function(e) { showUserError('uploading file', e); });
}
function deleteAkTrainingImage(imgId, fileName) {
  if (!imgId) { alert('Cannot delete: image id missing.'); return; }
  var msg = 'Delete this image?' + (fileName ? '\n\n' + fileName : '') + '\n\nThis action cannot be undone.';
  if (!confirm(msg)) return;
  // Lock the row visually while delete is in flight
  var tbody = document.getElementById('akTrainingImageListBody');
  if (tbody) {
    var btns = tbody.querySelectorAll('button, a');
    btns.forEach(function(b) { b.disabled = true; b.style.opacity = '0.5'; b.style.pointerEvents = 'none'; });
  }
  apiAkTrainingDeleteImage(imgId).then(function() {
    // Refresh modal contents
    openAkTrainingImages(viewingAkTrainingId);
  }).catch(function(e) {
    showUserError('deleting image', e);
    // Re-enable buttons on failure so user can retry
    if (tbody) {
      var btns2 = tbody.querySelectorAll('button, a');
      btns2.forEach(function(b) { b.disabled = false; b.style.opacity = ''; b.style.pointerEvents = ''; });
    }
  });
}

// ---- AK ASSESSMENT ----
var akAssessCurrentPage = 1, akAssessPageLimit = 10;
function loadAkAssessmentListData(page) {
  _populateAkStatesInto('akAsFilterState', 'All States');
  akAssessCurrentPage = page || akAssessCurrentPage || 1;
  var p = { page: akAssessCurrentPage, limit: akAssessPageLimit };
  var s = document.getElementById('akAsFilterState');
  var c = document.getElementById('akAsFilterCentre');
  var n = document.getElementById('akAsFilterName');
  var t = document.getElementById('akAsFilterType');
  var st = document.getElementById('akAsFilterStatus');
  if (s && s.value)        p.state_code = s.value;
  if (c && c.value)        p.centre_code = c.value;
  if (n && n.value.trim()) p.leader_name = n.value.trim();
  if (t && t.value)        p.assessment_type = t.value;
  if (st && st.value)      p.status = st.value;
  p = _applyRoleScopeFloor(p);
  apiGet('/ak-assessments/list/grouped' + _qs(p)).then(function(result) {
    var data = result.data || [];
    var total = result.total || 0;
    var tbody = document.getElementById('akAssessmentListBody');
    if (!tbody) return;
    if (!data.length) {
      tbody.innerHTML = '<tr><td colspan="8" style="text-align:center;color:#999;padding:30px;">No assessments found. Click <b>+ Add Assessment</b> to start one.</td></tr>';
      var pag = document.querySelector('#page-akAssessmentList .pagination');
      if (pag) pag.textContent = 'Showing 0 of 0';
      return;
    }
    var startIdx = (akAssessCurrentPage - 1) * akAssessPageLimit;
    var canDelete = !currentUser || currentUser.role === 'admin' || currentUser.role === 'super_admin' || currentUser.role === 'project_incharge';
    var html = '';
    data.forEach(function(r, i) {
      var loc = [r.centre_name, r.state_name].filter(Boolean).join(', ') || '—';
      var bDate = r.baseline_date ? formatDateNice(r.baseline_date) : '—';
      var mDate = r.midline_date  ? formatDateNice(r.midline_date)  : '—';
      var eDate = r.endline_date  ? formatDateNice(r.endline_date)  : '—';

      var baselineSubmitted = (r.baseline_status === 'Submitted');
      var midlineSubmitted  = (r.midline_status  === 'Submitted');
      var endlineSubmitted  = (r.endline_status  === 'Submitted');
      var bothSubmitted = (baselineSubmitted && endlineSubmitted);
      var actions = '';

      // ⚖️ Compare — when both baseline & endline are submitted
      if (bothSubmitted && r.baseline_id && r.endline_id) {
        actions += '<button class="btn-icon" title="View Comparison" onclick="viewAkAssessmentCompare(' + r.baseline_id + ',' + r.endline_id + ')"><i class="fas fa-balance-scale"></i></button> ';
      }
      // ➕ Start Next Stage — pick the next missing stage in baseline → midline → endline order
      var nextStage = null;
      if (baselineSubmitted && !r.midline_id) nextStage = 'Midline Assessment';
      else if (baselineSubmitted && midlineSubmitted && !r.endline_id) nextStage = 'Endline Assessment';
      else if (baselineSubmitted && !r.endline_id && !r.midline_id) nextStage = 'Midline Assessment';
      if (nextStage) {
        actions += '<button class="btn-icon" title="Start ' + nextStage.replace(' Assessment','') + '" onclick="startAkNextStageFromList(' + r.leader_id + ',\'' + nextStage + '\')"><i class="fas fa-plus-circle"></i></button> ';
      }
      // ✎ Edit — open the most relevant assessment for editing
      var editTargetId = null;
      if (r.endline_id  && r.endline_status  !== 'Submitted') editTargetId = r.endline_id;
      else if (r.midline_id  && r.midline_status  !== 'Submitted') editTargetId = r.midline_id;
      else if (r.baseline_id && r.baseline_status !== 'Submitted') editTargetId = r.baseline_id;
      else if (r.endline_id) editTargetId = r.endline_id;
      else if (r.midline_id) editTargetId = r.midline_id;
      else if (r.baseline_id) editTargetId = r.baseline_id;
      if (editTargetId) {
        actions += '<button class="btn-icon" title="Edit / View Assessment" onclick="editAkAssessmentFromList(' + editTargetId + ')"><i class="fas fa-edit"></i></button> ';
      }
      // 🗑 Delete — admin / project incharge only. Normalized to the same
      // icon + class the other lists use (fa-trash-alt + text-danger) so
      // the AK Assessment row matches the rest of the UI.
      if (canDelete && r.leader_id) {
        actions += '<button class="btn-icon text-danger" title="Delete Assessment" onclick="deleteAkAssessmentFromList(' + r.leader_id + ',\'' + escHtml(r.leader_name || '').replace(/\'/g, "\\\\\'") + '\')"><i class="fas fa-trash-alt"></i></button>';
      }

      html += '<tr>' +
        '<td>' + (startIdx + i + 1) + '</td>' +
        '<td>' + escHtml(r.leader_name || '') + '</td>' +
        '<td>' + escHtml(r.enrollment_number || '—') + '</td>' +
        '<td>' + escHtml(loc) + '</td>' +
        '<td>' + bDate + '</td>' +
        '<td>' + mDate + '</td>' +
        '<td>' + eDate + '</td>' +
        '<td style="white-space:nowrap;">' + actions + '</td>' +
      '</tr>';
    });
    tbody.innerHTML = html;
    var pag = document.querySelector('#page-akAssessmentList .pagination');
    if (pag && typeof renderListPagination === 'function') {
      renderListPagination('#page-akAssessmentList .pagination', total, akAssessCurrentPage, akAssessPageLimit, 'loadAkAssessmentListData');
    }
  }).catch(function(err) { showUserError('loading AK assessment list', err); });
}

// ----- Row-level action helpers -----

function startAkEndlineFromList(leaderId) {
  // kept for backward compat; new flow goes through startAkNextStageFromList
  startAkNextStageFromList(leaderId, 'Endline Assessment');
}

function startAkNextStageFromList(leaderId, assessmentType) {
  // Defer the server-side create until Save Draft / Submit, so the leader's
  // row in the list doesn't gain a phantom Draft just from clicking the icon.
  _akAfState.assessmentId    = null;
  _akAfState.pendingLeaderId = leaderId;
  _akAfState.assessmentType  = assessmentType;
  _akAfState.responses       = {};
  _akAfState.familyMembers   = [{ position: 1 }];
  _akAfState.dirty           = false;
  _akAfPersistId();
  navigateTo('akAssessmentForm');
}

function editAkAssessmentFromList(assessmentId) {
  _akAfState.assessmentId = assessmentId;
  _akAfState.assessmentType = null;  // will be set from GET payload
  _akAfPersistId();
  navigateTo('akAssessmentForm');
}

function deleteAkAssessmentFromList(leaderId, leaderName) {
  if (!confirm('Delete all draft assessments for ' + (leaderName || 'this leader') + '?\n\nNote: submitted (locked) assessments will be kept — only drafts are removable.')) return;
  apiGet('/ak-assessments?leader_name=' + encodeURIComponent(leaderName || '') + '&limit=50')
    .then(function(resp) {
      var rows = (resp.data || []).filter(function(x) { return x.leader_id === leaderId && x.status === 'Draft'; });
      if (!rows.length) {
        alert('No draft assessments to delete for this leader.');
        return;
      }
      return Promise.all(rows.map(function(r) {
        return apiDelete('/ak-assessments/' + r.id).catch(function(err) {
          // continue even if some fail (e.g., race with submit)
          console.warn('delete failed for assessment', r.id, err);
        });
      })).then(function() {
        alert('Deleted ' + rows.length + ' draft assessment(s).');
        loadAkAssessmentListData();
      });
    })
    .catch(function(err) { showUserError('deleting assessment', err); });
}

// ============================================================================
// AK Assessment — Baseline vs Endline comparison
// ============================================================================
// Mirrors the FLP viewAssessmentCompare flow but renders AK-specific data.
// AK assessments live in ak_assessments with `responses` JSONB keyed by
// the 9-section form (general / family / marriage / gbv / srh / gender /
// mobility / efficacy / digital). For each question that appears in either
// baseline or endline we render one row with Before / After / Change.
window._akCmpData = null;  // cached {baseline, endline, rows} for re-renders

var AK_CMP_SECTION_LABELS = {
  general:  'General Info',
  family:   'Family Details',
  marriage: 'Marriage',
  gbv:      'GBV',
  srh:      'SRH',
  gender:   'Gender Norms',
  mobility: 'Mobility',
  efficacy: 'Self-Efficacy',
  digital:  'Digital Literacy'
};
var AK_CMP_SECTION_ORDER = ['general','family','marriage','gbv','srh','gender','mobility','efficacy','digital'];

function _akCmpNormalize(v) {
  if (v === null || v === undefined) return '';
  if (typeof v === 'object') {
    try { return JSON.stringify(v); } catch (e) { return String(v); }
  }
  if (typeof v === 'boolean') return v ? 'Yes' : 'No';
  return String(v).trim();
}
function _akCmpHumanizeKey(k) {
  if (!k) return '';
  // q1 / q_attitude_5 → Q1 / Attitude 5
  return String(k)
    .replace(/^q[_-]?/i, 'Q')
    .replace(/_/g, ' ')
    .replace(/\s+/g, ' ')
    .replace(/\b\w/g, function(c) { return c.toUpperCase(); })
    .trim();
}
function _akCmpClassifyChange(b, e) {
  var bs = _akCmpNormalize(b);
  var es = _akCmpNormalize(e);
  if (!bs && !es) return { type: 'empty',   label: '—',           cssColor: '#bdc3c7' };
  if (!bs &&  es) return { type: 'newly',   label: 'Newly answered', cssColor: '#3498db' };
  if ( bs && !es) return { type: 'dropped', label: 'Dropped',     cssColor: '#95a5a6' };
  if (bs === es)  return { type: 'same',    label: 'No change',   cssColor: '#f39c12' };
  return { type: 'changed', label: 'Changed', cssColor: '#27ae60' };
}

function viewAkAssessmentCompare(baselineId, endlineId) {
  if (!baselineId || !endlineId) {
    alert('Both Baseline and Endline must be Submitted before comparison is available.');
    return;
  }
  window._akCmpData = { baselineId: baselineId, endlineId: endlineId, baseline: null, endline: null, rows: [] };
  navigateTo('akAssessmentCompare');
  // Skeleton state
  ['akCmpLeaderName','akCmpEnrollment','akCmpLocation','akCmpBaselineDate','akCmpEndlineDate','akCmpGap',
   'akCmpBaselineAnswered','akCmpEndlineAnswered','akCmpChanged','akCmpChangeRate'].forEach(function(id) {
    var el = document.getElementById(id); if (el) el.textContent = '…';
  });
  var body = document.getElementById('akCmpTableBody');
  if (body) body.innerHTML = '<tr><td colspan="5" style="text-align:center;color:#999;padding:30px;">Loading comparison data…</td></tr>';
  // Fetch both assessments in parallel
  Promise.all([
    apiAkAssessmentDetail(baselineId).catch(function(e){ return { _error: e, _which: 'baseline' }; }),
    apiAkAssessmentDetail(endlineId).catch(function(e){ return { _error: e, _which: 'endline' }; })
  ]).then(function(results) {
    var b = results[0], e = results[1];
    if (b && b._error) { showUserError('loading baseline assessment', b._error); return; }
    if (e && e._error) { showUserError('loading endline assessment', e._error); return; }
    window._akCmpData.baseline = b;
    window._akCmpData.endline  = e;
    _akCmpPopulateBanner();
    _akCmpBuildRows();
    _akCmpRenderCharts();
    renderAkCompareTable();
  }).catch(function(err) { showUserError('loading comparison', err); });
}

function _akCmpPopulateBanner() {
  var d = window._akCmpData || {};
  var bL = (d.baseline && d.baseline.leader) || {};
  var eL = (d.endline && d.endline.leader) || {};
  // Prefer baseline leader (same kishori — both records point at the same leader)
  var L = (bL.name ? bL : eL) || {};
  var loc = [L.centre_name, L.state_name].filter(Boolean).join(', ') || '—';
  var bA = (d.baseline && d.baseline.assessment) || {};
  var eA = (d.endline  && d.endline.assessment)  || {};
  var bDate = bA.submitted_at || bA.assessment_date || '';
  var eDate = eA.submitted_at || eA.assessment_date || '';
  var bDateFmt = bDate ? formatDateNice(bDate) : '—';
  var eDateFmt = eDate ? formatDateNice(eDate) : '—';
  var gap = '—';
  if (bDate && eDate) {
    var ms = (new Date(eDate)) - (new Date(bDate));
    if (isFinite(ms) && ms > 0) {
      var days = Math.round(ms / 86400000);
      if (days >= 730)      gap = Math.round(days / 365) + ' yr';
      else if (days >= 60)  gap = Math.round(days / 30)  + ' mo';
      else                  gap = days + ' d';
    }
  }
  function _set(id, v) { var el = document.getElementById(id); if (el) el.textContent = v || '—'; }
  _set('akCmpLeaderName',  L.name);
  _set('akCmpEnrollment',  L.enrollment_number);
  _set('akCmpLocation',    loc);
  _set('akCmpBaselineDate', bDateFmt);
  _set('akCmpEndlineDate',  eDateFmt);
  _set('akCmpGap',          gap);
}

function _akCmpBuildRows() {
  var d = window._akCmpData;
  if (!d) return;
  var bResp = ((d.baseline && d.baseline.assessment) || {}).responses || {};
  var eResp = ((d.endline  && d.endline.assessment)  || {}).responses || {};
  var rows = [];
  var bAnsweredTot = 0, eAnsweredTot = 0;
  var counters = { changed: 0, same: 0, newly: 0, dropped: 0, empty: 0 };
  var sectionCoverage = {};  // section → { baseline, endline }

  // Iterate every section we know about (and also any unexpected sections
  // that may have crept into responses — graceful for future sections).
  var sectionsSeen = {};
  AK_CMP_SECTION_ORDER.forEach(function(s) { sectionsSeen[s] = true; });
  Object.keys(bResp).forEach(function(s) { sectionsSeen[s] = true; });
  Object.keys(eResp).forEach(function(s) { sectionsSeen[s] = true; });
  var orderedSections = AK_CMP_SECTION_ORDER.slice();
  Object.keys(sectionsSeen).forEach(function(s) {
    if (orderedSections.indexOf(s) === -1) orderedSections.push(s);
  });

  orderedSections.forEach(function(section) {
    var bSec = (bResp[section] && typeof bResp[section] === 'object') ? bResp[section] : {};
    var eSec = (eResp[section] && typeof eResp[section] === 'object') ? eResp[section] : {};
    // Union of all question keys in this section across both assessments
    var keys = {};
    Object.keys(bSec).forEach(function(k) { keys[k] = 1; });
    Object.keys(eSec).forEach(function(k) { keys[k] = 1; });
    var keyList = Object.keys(keys).sort();
    var bCount = 0, eCount = 0;
    keyList.forEach(function(qkey) {
      var bv = bSec[qkey], ev = eSec[qkey];
      var bn = _akCmpNormalize(bv), en = _akCmpNormalize(ev);
      if (bn) bCount++;
      if (en) eCount++;
      var c = _akCmpClassifyChange(bv, ev);
      counters[c.type] = (counters[c.type] || 0) + 1;
      rows.push({
        section: section,
        sectionLabel: AK_CMP_SECTION_LABELS[section] || _akCmpHumanizeKey(section),
        question: _akCmpHumanizeKey(qkey),
        baseline: bn || '—',
        endline:  en || '—',
        change: c
      });
    });
    bAnsweredTot += bCount; eAnsweredTot += eCount;
    sectionCoverage[section] = { baseline: bCount, endline: eCount, total: keyList.length };
  });

  d.rows = rows;
  d.counters = counters;
  d.sectionCoverage = sectionCoverage;
  d.bAnsweredTot = bAnsweredTot;
  d.eAnsweredTot = eAnsweredTot;

  // KPI cards
  function _set(id, v) { var el = document.getElementById(id); if (el) el.textContent = v; }
  _set('akCmpBaselineAnswered', bAnsweredTot);
  _set('akCmpEndlineAnswered',  eAnsweredTot);
  _set('akCmpChanged',          counters.changed || 0);
  var denom = (counters.changed || 0) + (counters.same || 0);
  var pct = denom > 0 ? Math.round(((counters.changed || 0) / denom) * 100) : 0;
  _set('akCmpChangeRate', pct + '%');
}

function _akCmpRenderCharts() {
  var d = window._akCmpData; if (!d || !d.sectionCoverage) return;
  // Section-wise grouped bar (Baseline vs Endline answer counts)
  var labels = [], baseData = [], endData = [];
  AK_CMP_SECTION_ORDER.forEach(function(s) {
    var sc = d.sectionCoverage[s] || { baseline: 0, endline: 0 };
    labels.push(AK_CMP_SECTION_LABELS[s] || s);
    baseData.push(sc.baseline);
    endData.push(sc.endline);
  });
  _akCmpDestroyChart('_akCmpSectionChartObj');
  var sectionCanvas = document.getElementById('akCmpSectionChart');
  if (sectionCanvas && window.Chart) {
    window._akCmpSectionChartObj = new Chart(sectionCanvas.getContext('2d'), {
      type: 'bar',
      data: {
        labels: labels,
        datasets: [
          { label: 'Baseline', data: baseData, backgroundColor: '#9b3d8e' },
          { label: 'Endline',  data: endData,  backgroundColor: '#27ae60' }
        ]
      },
      options: {
        responsive: true,
        maintainAspectRatio: false,
        plugins: { legend: { position: 'bottom' } },
        scales: { y: { beginAtZero: true, ticks: { stepSize: 1 } } }
      }
    });
  }
  // Change distribution donut
  _akCmpDestroyChart('_akCmpChangeChartObj');
  var changeCanvas = document.getElementById('akCmpChangeChart');
  if (changeCanvas && window.Chart) {
    var c = d.counters || {};
    window._akCmpChangeChartObj = new Chart(changeCanvas.getContext('2d'), {
      type: 'doughnut',
      data: {
        labels: ['Changed', 'No change', 'Newly answered', 'Dropped'],
        datasets: [{
          data: [c.changed || 0, c.same || 0, c.newly || 0, c.dropped || 0],
          backgroundColor: ['#27ae60', '#f39c12', '#3498db', '#95a5a6']
        }]
      },
      options: {
        responsive: true,
        maintainAspectRatio: false,
        plugins: { legend: { position: 'bottom' } }
      }
    });
  }
}
function _akCmpDestroyChart(key) {
  try { if (window[key]) { window[key].destroy(); window[key] = null; } } catch (e) {}
}

function renderAkCompareTable() {
  var d = window._akCmpData; if (!d || !d.rows) return;
  var section = (document.getElementById('akCmpSectionFilter') || {}).value || '';
  var change  = (document.getElementById('akCmpChangeFilter')  || {}).value || '';
  var rows = d.rows.filter(function(r) {
    if (section && r.section !== section) return false;
    if (change  && r.change.type !== change) return false;
    return true;
  });
  var body = document.getElementById('akCmpTableBody');
  if (!body) return;
  if (!rows.length) {
    body.innerHTML = '<tr><td colspan="5" style="text-align:center;color:#999;padding:30px;">No questions match the current filters.</td></tr>';
    return;
  }
  body.innerHTML = rows.map(function(r) {
    return '<tr>' +
      '<td><span style="display:inline-block;padding:2px 8px;background:#fef5e7;color:#e67e22;border-radius:10px;font-size:11px;font-weight:600;">' + escHtml(r.sectionLabel) + '</span></td>' +
      '<td>' + escHtml(r.question) + '</td>' +
      '<td>' + escHtml(r.baseline) + '</td>' +
      '<td>' + escHtml(r.endline)  + '</td>' +
      '<td><span style="display:inline-block;padding:3px 9px;background:' + r.change.cssColor + ';color:#fff;border-radius:10px;font-size:11px;font-weight:600;">' + escHtml(r.change.label) + '</span></td>' +
    '</tr>';
  }).join('');
}

function exportAkAssessmentComparePDF() {
  var d = window._akCmpData;
  if (!d || !d.rows) { alert('No comparison data to export.'); return; }
  var bL = (d.baseline && d.baseline.leader) || {};
  var eL = (d.endline && d.endline.leader) || {};
  var L = (bL.name ? bL : eL) || {};
  var bA = (d.baseline && d.baseline.assessment) || {};
  var eA = (d.endline  && d.endline.assessment)  || {};
  var info = {
    'Leader':     L.name || '—',
    'Enrollment': L.enrollment_number || '—',
    'Location':   [L.centre_name, L.state_name].filter(Boolean).join(', ') || '—',
    'Baseline':   bA.submitted_at ? formatDateNice(bA.submitted_at) : '—',
    'Endline':    eA.submitted_at ? formatDateNice(eA.submitted_at) : '—'
  };
  var win = window.open('', '_blank');
  var html = '<!DOCTYPE html><html><head><title>AK Assessment Comparison — ' + (L.name || '') + '</title>';
  html += '<style>';
  html += 'body{font-family:Segoe UI,Tahoma,sans-serif;margin:30px;color:#333;}';
  html += 'h1{color:#732269;font-size:22px;border-bottom:3px solid #732269;padding-bottom:8px;}';
  html += 'h2{color:#732269;font-size:16px;margin-top:25px;}';
  html += '.info-row{display:flex;flex-wrap:wrap;gap:18px;margin:15px 0;padding:12px;background:#f7f3f6;border-radius:8px;font-size:13px;}';
  html += '.info-row strong{color:#732269;margin-right:4px;}';
  html += 'table{width:100%;border-collapse:collapse;margin-top:12px;font-size:12px;}';
  html += 'th{background:#732269;color:#fff;padding:9px 8px;text-align:left;}';
  html += 'td{padding:7px 8px;border-bottom:1px solid #e0d4de;vertical-align:top;}';
  html += 'tr:nth-child(even){background:#fafafa;}';
  html += '.tag{display:inline-block;padding:2px 8px;border-radius:10px;font-size:10px;font-weight:600;color:#fff;}';
  html += '@media print{body{margin:15px;}}';
  html += '</style></head><body>';
  html += '<h1>AK Assessment Comparison — Baseline vs Endline</h1>';
  html += '<div class="info-row">';
  Object.keys(info).forEach(function(k) { html += '<div><strong>' + k + ':</strong> ' + info[k] + '</div>'; });
  html += '</div>';
  html += '<h2>Question-Wise Comparison</h2>';
  html += '<table><thead><tr><th style="width:14%;">Section</th><th style="width:32%;">Question</th><th style="width:20%;">Baseline</th><th style="width:20%;">Endline</th><th style="width:14%;">Change</th></tr></thead><tbody>';
  d.rows.forEach(function(r) {
    html += '<tr>' +
      '<td>' + escHtml(r.sectionLabel) + '</td>' +
      '<td>' + escHtml(r.question) + '</td>' +
      '<td>' + escHtml(r.baseline) + '</td>' +
      '<td>' + escHtml(r.endline) + '</td>' +
      '<td><span class="tag" style="background:' + r.change.cssColor + ';">' + escHtml(r.change.label) + '</span></td>' +
    '</tr>';
  });
  html += '</tbody></table>';
  html += '<p style="margin-top:30px;font-size:11px;color:#999;text-align:center;">Generated on ' + new Date().toLocaleDateString('en-IN', {timeZone:'Asia/Kolkata'}) + ' — Azad Foundation MIS</p>';
  html += '<script>window.onload=function(){window.print();}<\/script>';
  html += '</body></html>';
  win.document.write(html); win.document.close();
}

function exportAkAssessmentToExcel() {
  // Use the same filter set for export
  var p = { limit: 1000 };
  var s = document.getElementById('akAsFilterState'),
      c = document.getElementById('akAsFilterCentre'),
      n = document.getElementById('akAsFilterName'),
      t = document.getElementById('akAsFilterType'),
      st = document.getElementById('akAsFilterStatus');
  if (s && s.value)        p.state_code = s.value;
  if (c && c.value)        p.centre_code = c.value;
  if (n && n.value.trim()) p.leader_name = n.value.trim();
  if (t && t.value)        p.assessment_type = t.value;
  if (st && st.value)      p.status = st.value;
  p = _applyRoleScopeFloor(p);
  apiGet('/ak-assessments/list/grouped' + _qs(p)).then(function(resp) {
    var rows = resp.data || [];
    var csv = 'S.No,Leader Name,Enrollment No.,Location,Baseline Date,Midline Date,Endline Date,Baseline Status,Midline Status,Endline Status\n';
    rows.forEach(function(r, i) {
      csv += [
        (i+1),
        '"' + (r.leader_name || '') + '"',
        '"' + (r.enrollment_number || '') + '"',
        '"' + [r.centre_name, r.state_name].filter(Boolean).join(', ') + '"',
        (r.baseline_date || ''),
        (r.midline_date  || ''),
        (r.endline_date  || ''),
        (r.baseline_status || ''),
        (r.midline_status  || ''),
        (r.endline_status  || ''),
      ].join(',') + '\n';
    });
    var blob = new Blob([csv], {type:'text/csv'}); var url = URL.createObjectURL(blob);
    var a = document.createElement('a'); a.href = url; a.download = 'ak-assessments.csv'; a.click();
    URL.revokeObjectURL(url);
  });
}
function applyAkAssessmentFilters() { loadAkAssessmentListData(1); }
function resetAkAssessmentFilters() {
  if (typeof _clearListFilters === 'function') _clearListFilters('akAssessmentList');
  // 2026-06-05: Mobiliser/Sangini Reset preserves the locked State +
  // Centre (only Type / Status / Name are cleared). The lock is then
  // re-asserted so the dropdowns can't fall out of sync.
  var role = (currentUser && currentUser.role) || '';
  var locked = (role === 'mobiliser' || role === 'sangini');
  var clearIds = locked
    ? ['akAsFilterType','akAsFilterStatus','akAsFilterName']
    : ['akAsFilterState','akAsFilterCentre','akAsFilterType','akAsFilterStatus','akAsFilterName'];
  clearIds.forEach(function(id) {
    var el = document.getElementById(id); if (el) el.value = '';
  });
  if (!locked) {
    // Re-populate Centre dropdown to its default ("All Centres") since clearing State should reset it.
    var c = document.getElementById('akAsFilterCentre');
    if (c) c.innerHTML = '<option value="">All Centres</option>';
  } else if (typeof _lockGeoFiltersForRestrictedRole === 'function') {
    _lockGeoFiltersForRestrictedRole('akAsFilterState', null, 'akAsFilterCentre');
  }
  loadAkAssessmentListData(1);
}
function openAddAkAssessment() {
  navigateTo('addAkAssessment');
  // Reset selection state when opening fresh
  ['akAsType','akAsState','akAsCentre','akAsSearchLeader'].forEach(function(id) {
    var el = document.getElementById(id); if (el) el.value = '';
  });
  var sec = document.getElementById('akAddLeaderSection'); if (sec) sec.style.display = 'none';
  var btn = document.getElementById('btnProceedAkAssessment'); if (btn) btn.disabled = true;
}
function onAkAssessmentTypeChange() {
  var t = (document.getElementById('akAsType') || {}).value;
  var sec = document.getElementById('akAddLeaderSection');
  if (sec) sec.style.display = t ? '' : 'none';
  // 2026-06-06: Mobile hint flips inverse — visible when picker hidden
  // so Sangini users on a phone aren't left wondering what to do next.
  var hint = document.getElementById('akAddMemberHint');
  if (hint) hint.style.display = t ? 'none' : '';
  var banner = document.getElementById('akAddLeaderBannerText');
  if (banner) {
    if (t === 'Baseline Assessment') {
      banner.innerHTML = '<strong>Baseline</strong> — Select an active leader. The leader\'s profile will be used to pre-fill the General Info tab.';
    } else if (t === 'Midline Assessment') {
      banner.innerHTML = '<strong>Midline</strong> — Select a leader who already has a submitted Baseline assessment.';
    } else if (t === 'Endline Assessment') {
      banner.innerHTML = '<strong>Endline</strong> — Select a leader who already has a submitted Baseline assessment to capture the Endline.';
    }
  }
  // Reset any selection so Proceed disables until the user picks a leader
  var btn = document.getElementById('btnProceedAkAssessment'); if (btn) btn.disabled = true;
  if (t) _loadAkAssessmentLeaders();
}
function onAkAsStateChange() {
  var sc = (document.getElementById('akAsState') || {}).value;
  _loadAkCentresInto('akAsCentre', sc);
  // Auto-load leaders for the selected state when type already chosen
  if ((document.getElementById('akAsType') || {}).value) _loadAkAssessmentLeaders();
}
function onAkAsFilterStateChange() {
  var sc = (document.getElementById('akAsFilterState') || {}).value;
  _loadAkCentresInto('akAsFilterCentre', sc, null, 'All Centres');
}
function _loadAkAssessmentLeaders() {
  // Don't load until Type is selected (the leader section is gated on it).
  var t = (document.getElementById('akAsType') || {}).value;
  if (!t) return;
  var sc   = (document.getElementById('akAsState')        || {}).value;
  var cc   = (document.getElementById('akAsCentre')       || {}).value;
  var name = (document.getElementById('akAsSearchLeader') || {}).value;

  // Eligibility-aware fetch: backend filters leaders to those who meet the
  // prerequisite for the chosen stage (Midline needs submitted Baseline;
  // Endline needs submitted Baseline + Midline). Baseline returns all active.
  // 2026-06-05: Build params object first, then apply the role-scope
  // floor (state/district/centre forced to currentUser's assignment
  // for Sangini / state_lead / DL / PI), then serialise back to qs.
  // This ensures a Sangini East-Delhi user only sees East-Delhi
  // leaders here, ignoring any wider value the dropdowns might hold.
  var params = { assessment_type: t };
  if (sc)   params.state_code  = sc;
  if (cc)   params.centre_code = cc;
  if (name && name.trim().length >= 2) params.name = name.trim();
  params = _applyRoleScopeFloor(params);
  var qs = '?' + Object.keys(params).map(function(k) {
    return encodeURIComponent(k) + '=' + encodeURIComponent(params[k]);
  }).join('&');

  apiGet('/ak-assessments/eligible-leaders' + qs).then(function(result) {
    var data = result.data || [];
    var tbody = document.getElementById('akAsLeaderListBody');
    var countEl = document.getElementById('akAsLeaderCount');
    if (!tbody) return;
    if (!data.length) {
      var emptyMsg;
      if (t === 'Midline Assessment') {
        emptyMsg = 'No leaders are eligible for Midline yet — no leaders with a submitted Baseline match the chosen filters.';
      } else if (t === 'Endline Assessment') {
        emptyMsg = 'No leaders are eligible for Endline yet — no leaders with both a submitted Baseline and a submitted Midline match the chosen filters.';
      } else {
        emptyMsg = 'No leaders found for the chosen filters.';
      }
      tbody.innerHTML = '<tr><td colspan="6" style="text-align:center;color:#999;padding:18px;">' + emptyMsg + '</td></tr>';
      if (countEl) countEl.textContent = '';
      return;
    }
    var html = '';
    data.forEach(function(l) {
      html += '<tr>' +
        '<td><input type="radio" name="akAsLeader" value="' + l.id + '" onchange="_onAkAsLeaderSelect()"></td>' +
        '<td>' + escHtml(l.name || '') + '</td>' +
        '<td>' + escHtml(l.enrollment_number || '—') + '</td>' +
        '<td>' + escHtml(l.centre_name || l.centre_code || '—') + '</td>' +
        '<td>' + escHtml(l.batch_name || '—') + '</td>' +
        '<td>' + statusBadge(l.status || 'Active') + '</td>' +
      '</tr>';
    });
    tbody.innerHTML = html;
    if (countEl) countEl.textContent = 'Showing ' + data.length + ' eligible leader(s) for ' + t.replace(' Assessment','');
  }).catch(function(err) { showUserError('loading leaders', err); });
}
function _onAkAsLeaderSelect() {
  var sel = document.querySelector('input[name="akAsLeader"]:checked');
  var btn = document.getElementById('btnProceedAkAssessment');
  if (btn) btn.disabled = !sel;
}
function searchAkLeaderForAssessment() {
  _loadAkAssessmentLeaders();
}
function proceedAkAssessment() {
  var type = (document.getElementById('akAsType') || {}).value;
  if (!type) { alert('Please select Assessment Type.'); return; }
  var radio = document.querySelector('input[name="akAsLeader"]:checked');
  if (!radio) { alert('Please select a leader.'); return; }
  // Don't create the Draft on the server yet — only when the user explicitly
  // clicks Save Draft or Submit. Until then, hold the (leader_id, type) pair
  // in client state so abandoned forms don't pollute the list.
  _akAfState.assessmentId    = null;
  _akAfState.pendingLeaderId = parseInt(radio.value, 10);
  _akAfState.assessmentType  = type;
  _akAfState.responses       = {};
  _akAfState.familyMembers   = [{ position: 1 }];
  _akAfState.dirty           = false;
  _akAfPersistId();
  navigateTo('akAssessmentForm');
}

