var AK_AF_I18N = { en: AK_AF_I18N_EN, hi: AK_AF_I18N_HI, bn: AK_AF_I18N_BN };

// Active language for the AK assessment form. Persisted to localStorage so
// the surveyor's preference survives a refresh.
var _akAfLang = (function() {
  try { return localStorage.getItem('akAfLang') || 'en'; } catch (e) { return 'en'; }
})();
function _akAfSetLang(lang) {
  if (lang !== 'en' && lang !== 'hi' && lang !== 'bn') return;
  _akAfLang = lang;
  try { localStorage.setItem('akAfLang', lang); } catch (e) {}
}

// Lookup helper. Returns the active-language translation if present, falls
// back to English text. Never returns an empty string for a valid key.
function _akAfTr(qNum, kind, key) {
  var bank   = AK_AF_I18N[_akAfLang] || AK_AF_I18N_EN;
  var enBank = AK_AF_I18N_EN;
  if (kind === 'label') {
    return (bank[qNum] && bank[qNum].label) ||
           (enBank[qNum] && enBank[qNum].label) || '';
  }
  if (kind === 'option') {
    var v = bank[qNum] && bank[qNum].options && bank[qNum].options[key];
    return v || key;  // fall back to the English value string itself
  }
  if (kind === 'scale')   return (bank.__scale   && bank.__scale[key])   || key;
  if (kind === 'section') return (bank.__sections && bank.__sections[key]) || enBank.__sections[key] || key;
  if (kind === 'chrome')  return (bank.__chrome  && bank.__chrome[key])  || enBank.__chrome[key]  || key;
  if (kind === 'family')  {
    // key is "relation:Mother" / "marital:Married" / "education:8th Pass" / "occupation:Driver"
    var parts = String(key).split(':');
    var grp = parts[0]; var val = parts.slice(1).join(':');
    var fam = bank.__family && bank.__family[grp + 's'];
    return (fam && fam[val]) || val;
  }
  return key;
}

// ----------------------------------------------------------------------------
// 2026-06-01 (i18n): AK language switcher behaviour. Mirrors the MGJ
// implementation — _akAfSwitchLang captures in-flight DOM values into the
// response state, flips _akAfLang (persisted to localStorage), re-renders
// every tab, and refreshes the tab pill labels + active-language pill.
// ----------------------------------------------------------------------------

function _akAfSwitchLang(lang) {
  if (lang !== 'en' && lang !== 'hi' && lang !== 'bn') return;
  if (lang === _akAfLang) { _akAfPaintLangBar(); return; }
  // 1) capture in-flight DOM values so nothing gets lost on re-render
  _akAfCollectAllVisible();
  // 2) flip language
  _akAfSetLang(lang);
  // 3) re-render every tab — _akAfState.responses still holds the user's
  // answers so prior selections re-appear pre-selected.
  AK_AF_TAB_ORDER.forEach(function(t) {
    if (t === 'family') akAfRenderFamilyTab();
    else                akAfRenderQuestionTab(t);
  });
  // 4) repaint tab pill labels + active language pill
  _akAfPaintTabLabels();
  _akAfPaintLangBar();
  // 5) keep the user on the same tab
  var current = (_akAfState && _akAfState.currentTab) || 'general';
  akAfShowTab(current, true);
}

// Read every visible question control in the AK form and write its current
// value back to _akAfState.responses. Mirrors what akAfOnAnswerChange does
// field-by-field, but in bulk for switch / submit. Family tab inputs are
// captured by their existing onchange wiring (family table writes to
// _akAfState.familyMembers directly), so we skip data-fmf cells here.
function _akAfCollectAllVisible() {
  if (!_akAfState || !_akAfState.responses) return;
  // Text/number/textarea + select: read .value directly.
  document.querySelectorAll('#page-akAssessmentForm [data-q]').forEach(function(el) {
    var qkey = el.getAttribute('data-q');
    if (!qkey || el.getAttribute('data-fmf') !== null) return;
    if (el.type === 'radio') {
      if (el.checked) _akAfState.responses[qkey] = el.value;
    } else if (el.type === 'checkbox') {
      // collect all checked checkboxes for this q-key
      var checks = document.querySelectorAll('#page-akAssessmentForm input[type=checkbox][data-q="' + qkey + '"]:checked');
      if (checks.length) {
        _akAfState.responses[qkey] = Array.from(checks).map(function(c) { return c.value; });
      } else {
        delete _akAfState.responses[qkey];
      }
    } else {
      if (el.value != null && el.value !== '') _akAfState.responses[qkey] = el.value;
    }
  });
  // "Please specify" sibling inputs
  document.querySelectorAll('#page-akAssessmentForm [data-q-other]').forEach(function(el) {
    var qkey = el.getAttribute('data-q-other');
    if (!qkey) return;
    if (el.value && el.value.trim()) _akAfState.responses[qkey + '_other'] = el.value;
    else delete _akAfState.responses[qkey + '_other'];
  });
}

function _akAfPaintLangBar() {
  var bar = document.getElementById('akAfLangBar'); if (!bar) return;
  bar.querySelectorAll('.akaf-lang-btn').forEach(function(b) {
    var on = b.getAttribute('data-akaf-lang') === _akAfLang;
    b.style.background = on ? '#732269' : '#fff';
    b.style.color      = on ? '#fff'    : '#732269';
  });
}

// 2026-06-01: status bar i18n. Every write to #akAfStatus now goes through
// _akAfSetStatus(key, extra) so the language-switch repaint can reproduce
// the current message. `key` is a chrome-bank entry; `extra` carries the
// timestamp/date that appears after some keys.
//
// Recognised keys (must mirror chrome bank entries):
//   newDraft, draft, saving, savedAt (extra=time), draftSavedAt (extra=time),
//   saveFailed, saveFailedRetry, noAssessment, submittedOn (extra=date)
var _akAfStatusKey   = null;
var _akAfStatusExtra = '';
function _akAfSetStatus(key, extra) {
  _akAfStatusKey   = key;
  _akAfStatusExtra = extra || '';
  _akAfPaintStatus();
}
function _akAfPaintStatus() {
  var el = document.getElementById('akAfStatus');
  if (!el) return;
  if (!_akAfStatusKey) { el.textContent = ' '; return; }
  var map = {
    newDraft:        ['statusNewDraft',        false, 'Save Draft'],
    draft:           ['statusDraft',           false, 'Save Draft'],
    saving:          ['statusSaving',          false, null],
    savedAt:         ['statusSavedAt',         true,  null],   // <text> <time>
    draftSavedAt:    ['statusDraftSavedAt',    true,  null],   // ✓ <text> <time>
    saveFailed:      ['statusSaveFailed',      false, null],
    saveFailedRetry: ['statusSaveFailedRetry', false, null],
    noAssessment:    ['statusNoAssessment',    false, null],
    submittedOn:     ['statusSubmittedOn',     true,  null]    // ✓ <text> <date>
  };
  var spec = map[_akAfStatusKey]; if (!spec) { el.textContent = ''; return; }
  var text = _akAfTr(null, 'chrome', spec[0]);
  // Bold the "Save Draft" phrase inside the draft/newDraft prompts in
  // whichever language; we look up the localized button label and bold the
  // first occurrence.
  var withBoldCTA = text;
  if (spec[2]) {
    var ctaLocalized = _akAfTr(null, 'chrome', 'btnSaveDraft');
    withBoldCTA = text.replace(ctaLocalized, '<b>' + ctaLocalized + '</b>');
  }
  // Prefix ✓ check icon for "saved" / "submitted" states.
  var prefix = '';
  if (_akAfStatusKey === 'draftSavedAt' || _akAfStatusKey === 'submittedOn') {
    prefix = '<i class="fas fa-check-circle" style="color:#27ae60;"></i> ';
  }
  // Build final HTML. When `extra` is set it appears after the localized
  // text (typical pattern: "<text> <time>" / "<text> <date>").
  var html = prefix + withBoldCTA + (_akAfStatusExtra ? ' ' + escHtml(_akAfStatusExtra) : '');
  if (_akAfStatusKey === 'saveFailed') {
    html = '<span style="color:#e74c3c;">' + html + '</span>';
  }
  el.innerHTML = html;
}

function _akAfPaintTabLabels() {
  var nav = document.querySelector('#page-akAssessmentForm .tab-nav');
  if (!nav) return;
  nav.querySelectorAll('.tab-btn[data-akaf-tab]').forEach(function(b) {
    b.textContent = _akAfTr(null, 'section', b.getAttribute('data-akaf-tab'));
  });
  // 2026-06-01: also repaint footer buttons + breadcrumb + language label
  // + Back-to-List button + Family-tab content if the family pane is the
  // active one. These DOM nodes have stable IDs so we update them in place.
  function setHtml(id, html) { var el = document.getElementById(id); if (el) el.innerHTML = html; }
  setHtml('akAfPrevBtn',   '<i class="fas fa-arrow-left"></i> ' + escHtml(_akAfTr(null, 'chrome', 'btnPrevious')));
  setHtml('akAfDraftBtn',  '<i class="fas fa-save"></i> '       + escHtml(_akAfTr(null, 'chrome', 'btnSaveDraft')));
  setHtml('akAfNextBtn',   escHtml(_akAfTr(null, 'chrome', 'btnNext')) + ' <i class="fas fa-arrow-right"></i>');
  setHtml('akAfSubmitBtn', '<i class="fas fa-check-circle"></i> ' + escHtml(_akAfTr(null, 'chrome', 'btnSubmit')));
  // Back-to-List button is the only .btn-outline inside the AK form's
  // page-header — find it via the parent of #akAfBreadcrumbType for safety.
  var backBtn = document.querySelector('#page-akAssessmentForm .page-header > .btn');
  if (backBtn) {
    backBtn.innerHTML = '<i class="fas fa-arrow-left"></i> ' + escHtml(_akAfTr(null, 'chrome', 'btnBackToList'));
  }
  // Breadcrumb anchors (Home, Assessment) live inside .breadcrumb at the
  // top of the page. Set their innerHTML preserving the icon for "Home".
  var crumbs = document.querySelectorAll('#page-akAssessmentForm .breadcrumb a');
  if (crumbs.length >= 2) {
    crumbs[0].innerHTML = '<i class="fas fa-home"></i> ' + escHtml(_akAfTr(null, 'chrome', 'breadcrumbHome'));
    crumbs[1].textContent = _akAfTr(null, 'chrome', 'breadcrumbAssessment');
  }
  // Language label inside #akAfLangBar
  var langLabel = document.querySelector('#akAfLangBar > span');
  if (langLabel) {
    langLabel.innerHTML = '<i class="fas fa-language"></i> ' + escHtml(_akAfTr(null, 'chrome', 'languageLabel'));
  }
  // If the Family pane is currently rendered, repaint it so its chrome
  // (table headings, add button) picks up the new language too. Other
  // panes are repainted by _akAfSwitchLang's tab loop.
  var famPane = document.getElementById('akAfPane-family');
  if (famPane && famPane.classList.contains('active')) akAfRenderFamilyTab();
  // Also repaint the status bar in the active language.
  _akAfPaintStatus();
}

