// =============================================================================
// AAG (Azad Alumni Group) — paid membership module
// =============================================================================
var akAagCurrentPage = 1, akAagPageLimit = 10, _akAagFilterStateLoaded = false;
var aagPickerCurrentPage = 1, aagPickerPageLimit = 25, _aagPickerStateLoaded = false;
var _aagSelectedAlumniId = null, _aagSelectedAlumniName = '';
var viewingAagId = null, _payingAagId = null, _payingAagOutstanding = 0;

function _aagStatusBadge(s) {
  if (!s) return '<span class="badge" style="background:#eee;color:#555;">—</span>';
  var c = '#7f8c8d', bg = '#eee';
  if (s === 'Fully Paid') { c = '#fff'; bg = '#27ae60'; }
  else if (s === 'Partial') { c = '#fff'; bg = '#f39c12'; }
  else if (s === 'Pending') { c = '#fff'; bg = '#e74c3c'; }
  else if (s === 'Inactive') { c = '#fff'; bg = '#95a5a6'; }
  return '<span class="badge" style="background:' + bg + ';color:' + c + ';padding:3px 8px;border-radius:10px;font-size:11px;">' + escHtml(s) + '</span>';
}
function _aagMoney(v) {
  if (v == null || v === '') return '—';
  var n = Number(v); if (!isFinite(n)) return escHtml(String(v));
  return '₹' + n.toFixed(2).replace(/\B(?=(\d{3})+(?!\d))/g, ',');
}

// ---- AAG LIST PAGE ----
function loadAkAagListData(page) {
  if (typeof page === 'number') akAagCurrentPage = page;
  if (!_akAagFilterStateLoaded) {
    _akAagFilterStateLoaded = true;
    // 2026-06-08: For SL render State soft 2-option ("All States" +
    // user's state). Pre-load Centre + Batch scoped to user's state.
    // 2026-06-08 (round 4): DL + PI use _lockAkFiltersForDlPi so the
    // Centre dropdown becomes soft 2-option ("All Centres + <user
    // centre>") instead of all state centres.
    var _role = (currentUser && currentUser.role) || '';
    if (_role === 'state_lead' && currentUser.state_code) {
      var _sSel = document.getElementById('akAagFilterState');
      if (_sSel) {
        var _esc = (typeof escHtml === 'function') ? escHtml : function(x) { return x; };
        _sSel.innerHTML = '<option value="">All States</option>' +
                          '<option value="' + _esc(currentUser.state_code) + '">' +
                          _esc(currentUser.state_name || currentUser.state_code) + '</option>';
      }
      _loadAkCentresInto('akAagFilterCentre', currentUser.state_code, null, 'All Centres');
      _loadAkAlumniBatchesInto('akAagFilterBatch', currentUser.state_code, '', 'All Batches');
    } else if ((_role === 'district_lead' || _role === 'pi') &&
               typeof _lockAkFiltersForDlPi === 'function') {
      _lockAkFiltersForDlPi('akAagFilterState', 'akAagFilterCentre', { stateMode: 'soft', centreMode: 'soft' });
      if (currentUser.state_code) {
        _loadAkAlumniBatchesInto('akAagFilterBatch', currentUser.state_code, '', 'All Batches');
      }
    } else {
      _populateAkStatesInto('akAagFilterState', 'All States');
      _loadAkAlumniBatchesInto('akAagFilterBatch', '', '', 'All Batches');
    }
  }
  var p = { page: akAagCurrentPage, limit: akAagPageLimit };
  var s = document.getElementById('akAagFilterState');
  var c = document.getElementById('akAagFilterCentre');
  var b = document.getElementById('akAagFilterBatch');
  var t = document.getElementById('akAagFilterType');
  var n = document.getElementById('akAagFilterName');
  if (s && s.value) p.state_code = s.value;
  if (c && c.value) p.centre_code = c.value;
  if (b && b.value) p.batch = b.value;
  if (t && t.value) p.type_of_alumni = t.value;
  if (n && n.value.trim()) p.name = n.value.trim();
  p = _applyRoleScopeFloor(p);
  apiAagList(p).then(function(result) {
    var data = result.data || [];
    var tbody = document.getElementById('akAagListBody');
    if (!tbody) return;
    if (!data.length) {
      tbody.innerHTML = '<tr><td colspan="7" style="text-align:center;color:#999;padding:30px;">No AAG members found.</td></tr>';
      renderListPagination('#page-akAagList .pagination', 0, akAagCurrentPage, akAagPageLimit, 'loadAkAagListData');
      return;
    }
    // Delete is gated strictly on the super_admin role per the 2026-05-29 spec.
    // Lower-privilege roles (admin, project_incharge, coordinator) still see
    // View + Edit but never see the trash icon.
    var isSuperAdmin = !!(currentUser && currentUser.role === 'super_admin');
    var html = '';
    data.forEach(function(r, i) {
      var loc = [r.centre_name, r.state_name].filter(Boolean).join(', ') || '—';
      var nameSafe = (r.name || '').replace(/'/g, "\\'");
      html += '<tr>' +
        '<td>' + ((akAagCurrentPage - 1) * akAagPageLimit + i + 1) + '</td>' +
        '<td>' + escHtml(r.name || '') + '</td>' +
        '<td>' + escHtml(r.batch || '—') + '</td>' +
        '<td>' + escHtml(loc) + '</td>' +
        '<td>' + escHtml(r.type_of_alumni || '—') + '</td>' +
        // Member lifecycle status (Active / Walkout) — drawn from
        // ak_alumni.status, NOT the payment_status. statusBadge() already
        // handles the Active/Walkout colouring used elsewhere in AK.
        '<td>' + statusBadge(r.alumni_status || 'Active') + '</td>' +
        '<td>' +
          '<button class="btn-icon" title="View" onclick="viewAagMember(' + r.aag_id + ')"><i class="fas fa-eye"></i></button>' +
          '<button class="btn-icon" title="Edit Alumni" onclick="openEditAkAlumni(' + r.alumni_id + ')"><i class="fas fa-edit"></i></button>' +
          (isSuperAdmin ? '<button class="btn-icon text-danger" title="Delete AAG Membership (Super Admin only)" onclick="deleteAagMember(' + r.aag_id + ', \'' + nameSafe + '\')"><i class="fas fa-trash-alt"></i></button>' : '') +
        '</td></tr>';
    });
    tbody.innerHTML = html;
    renderListPagination('#page-akAagList .pagination', result.total || 0, akAagCurrentPage, akAagPageLimit, 'loadAkAagListData');
  }).catch(function(e) { showUserError('loading AAG members', e); });
}
function deleteAagMember(aagId, name) {
  if (!aagId) return;
  if (!currentUser || currentUser.role !== 'super_admin') {
    alert('Only Super Admin users can delete AAG memberships.');
    return;
  }
  var msg = 'Delete AAG membership' + (name ? ' for "' + name + '"' : '') +
            '?\n\nThis removes the member from the AAG list and erases their payment history.\n' +
            'The underlying alumni record is NOT deleted.';
  if (!confirm(msg)) return;
  apiAagDelete(aagId).then(function() {
    alert('AAG membership deleted.');
    loadAkAagListData(akAagCurrentPage);
  }).catch(function(e) { showUserError('deleting AAG membership', e); });
}
