// ---- ADD AAG (alumni picker) ----
function _aagPickerEmptyState(msg) {
  var tbody = document.getElementById('aagPickerBody');
  if (tbody) tbody.innerHTML = '<tr><td colspan="6" style="text-align:center;color:#999;padding:30px;">' + (msg || 'Select a State above to load eligible alumni.') + '</td></tr>';
  var pag = document.getElementById('aagPickerPagination');
  if (pag) pag.textContent = '';
  _aagSetProceedEnabled(false);
}
function _aagSetProceedEnabled(enabled) {
  var btn = document.getElementById('btnProceedAag');
  if (btn) btn.disabled = !enabled;
}
function openAddAagPicker() {
  _aagSelectedAlumniId = null; _aagSelectedAlumniName = '';
  navigateTo('akAddAag');
  setTimeout(function() {
    // 2026-06-08: For State Lead, hard-lock the picker State to the
    // user's state (single locked option, disabled, greyed). The
    // existing onAagPickerStateChange cascade then loads Centre + Batch
    // scoped + the eligible-alumni table, so the SL lands on a
    // fully-scoped picker without any extra clicks.
    // 2026-06-08 (round 4): SL + DL + PI all get auto-fill. SL gets
    // state hard-lock + state-scoped Centre. DL/PI get the full
    // _lockAkFiltersForDlPi treatment (state + centre both hard-locked
    // when centre_code is resolved). The cascade onAagPickerStateChange
    // fires via dispatchEvent so candidates + centre + batch load.
    var role = (currentUser && currentUser.role) || '';
    var nameEl0 = document.getElementById('aagPickerName');
    if (nameEl0) nameEl0.value = '';
    // 2026-06-08 (round 6): For DL/PI with centre_code resolved, hard-
    // lock Centre to user's centre AND skip the onAagPickerStateChange
    // dispatch. Firing the state-change cascade calls _loadAkCentresInto
    // which would replace the Centre dropdown with the full list of
    // state centres, wiping the lock. Instead, lock both fields, load
    // Batch directly (centre-scoped), and trigger the eligible-alumni
    // load via loadAagEligibleAlumni(1) — no cascade involved.
    if ((role === 'district_lead' || role === 'pi') &&
        currentUser.state_code && currentUser.centre_code) {
      if (typeof _lockAkFiltersForDlPi === 'function') {
        _lockAkFiltersForDlPi('aagPickerState', 'aagPickerCentre');
      }
      _loadAagPickerBatchesInto(currentUser.state_code, currentUser.centre_code);
      // Multi-attempt load — the lock's value-setter runs through 60/400/1200
      // retries; mirror that so we don't fetch with empty state_code on the
      // first try. Each attempt is harmlessly idempotent.
      [200, 600, 1500].forEach(function(d) {
        setTimeout(function() { loadAagEligibleAlumni(1); }, d);
      });
      return;
    }
    // SL keeps the cascade — the Centre dropdown is supposed to list
    // every centre in the user's state for an SL.
    if (role === 'state_lead' && currentUser.state_code) {
      var cElSL = document.getElementById('aagPickerCentre');
      if (cElSL) cElSL.innerHTML = '<option value="">-- All Centres --</option>';
      if (typeof _lockAkFiltersForDlPi === 'function') {
        _lockAkFiltersForDlPi('aagPickerState', 'aagPickerCentre');
      }
      setTimeout(function() {
        var s = document.getElementById('aagPickerState');
        if (s) try { s.dispatchEvent(new Event('change', { bubbles: true })); } catch (e) {}
      }, 1400);
      return;
    }
    // Always (re)populate dropdowns from the canonical tables: ak_states,
    // ak_centres (via cascade), ak_batches. _populateAkStatesInto already
    // guards against duplicate XHRs once the list is loaded.
    _populateAkStatesInto('aagPickerState', '-- Select State --');
    _loadAagPickerBatchesInto('', '');
    ['aagPickerCentre','aagPickerName','aagPickerState','aagPickerBatch'].forEach(function(id) {
      var el = document.getElementById(id);
      // Don't blank state/batch options just-loaded — only clear .value
      if (el && (id === 'aagPickerCentre' || id === 'aagPickerName')) {
        // Centre is rebuilt by onAagPickerStateChange; clear Name input
        if (id === 'aagPickerName') el.value = '';
      } else if (el) {
        el.value = '';
      }
    });
    var cEl = document.getElementById('aagPickerCentre');
    if (cEl) cEl.innerHTML = '<option value="">-- All Centres --</option>';
    _aagPickerEmptyState();
  }, 100);
}
function onAagPickerStateChange() {
  var sc = (document.getElementById('aagPickerState') || {}).value;
  _loadAkCentresInto('aagPickerCentre', sc, null, '-- All Centres --');
  _loadAagPickerBatchesInto(sc, '');
  _aagSelectedAlumniId = null; _aagSelectedAlumniName = '';
  if (sc) loadAagEligibleAlumni(1);
  else _aagPickerEmptyState();
}
function onAagPickerCentreChange() {
  var sc = (document.getElementById('aagPickerState') || {}).value;
  var cc = (document.getElementById('aagPickerCentre') || {}).value;
  _loadAagPickerBatchesInto(sc, cc);
  loadAagEligibleAlumni(1);
}
function loadAagEligibleAlumni(page) {
  if (typeof page === 'number') aagPickerCurrentPage = page;
  var p = { page: aagPickerCurrentPage, limit: aagPickerPageLimit };
  var s = document.getElementById('aagPickerState');
  var c = document.getElementById('aagPickerCentre');
  var b = document.getElementById('aagPickerBatch');
  var n = document.getElementById('aagPickerName');
  if (!s || !s.value) {
    _aagPickerEmptyState('Please select a State to load eligible alumni.');
    return;
  }
  p.state_code = s.value;
  if (c && c.value) p.centre_code = c.value;
  if (b && b.value) p.batch = b.value;
  if (n && n.value.trim()) p.name = n.value.trim();
  apiAagEligibleAlumni(p).then(function(result) {
    var data = result.data || [];
    var tbody = document.getElementById('aagPickerBody');
    if (!tbody) return;
    if (!data.length) {
      tbody.innerHTML = '<tr><td colspan="6" style="text-align:center;color:#999;padding:30px;">No eligible alumni found. Either nobody matches your filters or all matching alumni are already AAG members.</td></tr>';
      var pag = document.getElementById('aagPickerPagination');
      if (pag) pag.textContent = '0 of 0 alumni';
      _aagSetProceedEnabled(false);
      return;
    }
    var html = '';
    data.forEach(function(r) {
      var loc = [r.centre_name, r.state_name].filter(Boolean).join(', ') || '—';
      var nameSafe = (r.name || '').replace(/'/g, "\\'");
      html += '<tr>' +
        '<td style="text-align:center;"><input type="radio" name="aagPickerRadio" value="' + r.id + '" onclick="selectAagAlumni(' + r.id + ', \'' + nameSafe + '\')"></td>' +
        '<td>' + escHtml(r.name || '') + '</td>' +
        '<td>' + escHtml(r.batch || '—') + '</td>' +
        '<td>' + escHtml(loc) + '</td>' +
        '<td>' + escHtml(r.type_of_alumni || '—') + '</td>' +
        '<td>' + escHtml(r.status || '—') + '</td>' +
        '</tr>';
    });
    tbody.innerHTML = html;
    var pag2 = document.getElementById('aagPickerPagination');
    if (pag2) {
      var startIdx = (aagPickerCurrentPage - 1) * aagPickerPageLimit + 1;
      var endIdx = startIdx + data.length - 1;
      pag2.textContent = 'Showing ' + startIdx + '-' + endIdx + ' of ' + (result.total || data.length) + ' alumni';
    }
    _aagSetProceedEnabled(false);  // reset until user picks a radio
  }).catch(function(e) { showUserError('loading alumni', e); });
}
function selectAagAlumni(id, name) {
  _aagSelectedAlumniId = id;
  _aagSelectedAlumniName = name || '';
  _aagSetProceedEnabled(true);  // enable Proceed once an alumni is selected
}
function proceedToAagRegistration() {
  if (!_aagSelectedAlumniId) {
    alert('Please select an alumni from the list first.');
    return;
  }
  openAagRegistrationModal(_aagSelectedAlumniId, _aagSelectedAlumniName);
}

// ---- REGISTRATION MODAL ----
function openAagRegistrationModal(alumniId, alumniName) {
  document.getElementById('aagRegAlumniName').textContent = alumniName || '—';
  document.getElementById('aagRegFeeDeposited').value = '';
  document.getElementById('aagRegDepositType').value = '';
  var amtEl = document.getElementById('aagRegAmount');
  amtEl.value = ''; amtEl.readOnly = false;
  document.getElementById('aagRegDate').value = new Date().toISOString().slice(0, 10);
  document.getElementById('aagRegistrationModal').style.display = 'flex';
  document.getElementById('aagRegistrationModal').dataset.alumniId = String(alumniId);
}
function closeAagRegistrationModal() {
  document.getElementById('aagRegistrationModal').style.display = 'none';
}
function onAagDepositTypeChange() {
  var t = (document.getElementById('aagRegDepositType') || {}).value;
  var amt = document.getElementById('aagRegAmount');
  if (!amt) return;
  if (t === 'Full') {
    amt.value = '100'; amt.readOnly = true;
    amt.style.background = '#f5f5f5';
  } else if (t === 'Partial') {
    amt.value = ''; amt.readOnly = false;
    amt.style.background = '';
    amt.focus();
  } else {
    amt.value = ''; amt.readOnly = false;
    amt.style.background = '';
  }
}
function submitAagRegistration() {
  var modal = document.getElementById('aagRegistrationModal');
  var alumniId = parseInt(modal.dataset.alumniId, 10);
  if (!alumniId) { alert('Cannot register: alumni id missing.'); return; }
  var fee = (document.getElementById('aagRegFeeDeposited') || {}).value;
  var dtype = (document.getElementById('aagRegDepositType') || {}).value;
  var amt = parseFloat((document.getElementById('aagRegAmount') || {}).value);
  var date = (document.getElementById('aagRegDate') || {}).value;
  if (!fee) { alert('Please select Membership Fee Deposited.'); return; }
  if (!dtype) { alert('Please select Deposit Type.'); return; }
  if (!isFinite(amt) || amt < 0) { alert('Please enter a valid Amount.'); return; }
  if (amt > 100) { alert('Amount cannot exceed ₹100 (membership fee).'); return; }
  if (!date) { alert('Please select Date of Deposit.'); return; }
  apiAagRegister({
    alumni_id: alumniId,
    membership_fee_deposited: fee,
    deposit_type: dtype,
    amount_deposited: amt,
    date_of_deposit: date
  }).then(function() {
    closeAagRegistrationModal();
    alert('AAG member registered successfully.');
    // navigateTo triggers the akAagList page hook which calls
    // loadAkAagListData(1) for us — no extra setTimeout needed.
    akAagCurrentPage = 1;
    navigateTo('akAagList');
  }).catch(function(e) { showUserError('registering AAG member', e); });
}

// ---- VIEW AAG ----
function viewAagMember(aagId) {
  viewingAagId = aagId;
  navigateTo('akAagView');
  apiAagDetail(aagId).then(function(a) {
    function _d(l, v) { return '<div class="detail-item"><label>' + l + '</label><span>' + escHtml(v == null || v === '' ? '—' : String(v)) + '</span></div>'; }
    // Registration block — simplified per 2026-05-29 spec:
    //   1. Membership Fee Deposited?
    //   2. Membership Fee Required
    //   3. Amount Paid
    //   4. Remaining Amount (inline Pay Remaining when > 0)
    //   5. Deposit Type
    //   6. Registered On
    //   7. AAG Status
    // "Payment Status" was dropped — it's redundant with Remaining Amount.
    var reg = '';
    reg += _d('Membership Fee Deposited?', a.membership_fee_deposited);
    reg += _d('Membership Fee Required',   _aagMoney(a.membership_fee_required));
    reg += _d('Amount Paid',               _aagMoney(a.amount_paid));
    if (a.remaining > 0) {
      reg += '<div class="detail-item"><label>Remaining Amount</label>' +
             '<span style="display:inline-flex;align-items:center;gap:10px;">' +
             '<b style="color:#c0392b;">' + _aagMoney(a.remaining) + '</b>' +
             '<button class="btn btn-primary btn-sm" onclick="openAagPayRemainingModal()"><i class="fas fa-plus-circle"></i> Pay Remaining</button>' +
             '</span></div>';
    } else {
      reg += '<div class="detail-item"><label>Remaining Amount</label><span><b style="color:#27ae60;">₹0.00 — Completed / Paid</b></span></div>';
    }
    reg += _d('Deposit Type',  a.deposit_type);
    reg += _d('Registered On', a.registered_at ? formatDateNice(a.registered_at) : '');
    reg += _d('AAG Status',    a.aag_status);
    document.getElementById('aagViewRegistration').innerHTML = reg;
    // Member block — reuse alumni fields
    var mem = '';
    var loc = [a.centre_name, a.state_name].filter(Boolean).join(', ');
    mem += _d('Alumni Name', a.name);
    mem += _d('Batch', a.batch);
    mem += _d('Location', loc);
    mem += _d('Type of Alumni', a.type_of_alumni);
    mem += _d('Level of Engagement', a.level_of_engagement);
    mem += _d('Marital Status', a.marital_status);
    mem += _d('Religion', a.religion);
    mem += _d('Caste', a.caste);
    mem += _d('Mobile', a.mobile);
    mem += _d('Email', a.email);
    mem += _d('Address', a.address);
    document.getElementById('aagViewMember').innerHTML = mem;
    // Education
    var edu = '';
    edu += _d('Educational Status', a.educational_status);
    edu += _d('Are You Studying?', a.are_you_studying);
    if (a.are_you_studying === 'Yes') {
      edu += _d('If Yes, What?', a.studying_what);
      edu += _d('Name of the Current Institution', a.current_institution);
    }
    document.getElementById('aagViewEducation').innerHTML = edu;
    // Work
    var work = '';
    work += _d('Are You Working?', a.are_you_working);
    if (a.are_you_working === 'Yes') {
      work += _d('Type of Work', a.type_of_work);
      work += _d('Designation', a.designation);
      work += _d('Employer', a.employer_name);
      work += _d('Monthly Salary', _aagMoney(a.monthly_salary));
    }
    document.getElementById('aagViewWork').innerHTML = work;
    // Campaign
    var camp = '';
    camp += _d('Campaign Name', a.campaign_name);
    camp += _d('Campaign Date', a.campaign_date ? formatDateNice(a.campaign_date) : '');
    camp += _d('Exposure Visit', a.exposure_visit);
    camp += _d('Alumni Meet', a.alumni_meet);
    document.getElementById('aagViewCampaign').innerHTML = camp;
    // Payment history
    var pays = a.payments || [];
    var phb = document.getElementById('aagPaymentHistoryBody');
    if (phb) {
      if (!pays.length) {
        phb.innerHTML = '<tr><td colspan="5" style="text-align:center;color:#999;padding:18px;">No payments recorded yet.</td></tr>';
      } else {
        phb.innerHTML = pays.map(function(p, i) {
          return '<tr>' +
            '<td>' + (i + 1) + '</td>' +
            '<td>' + _aagMoney(p.amount) + '</td>' +
            '<td>' + (p.date_of_deposit ? formatDateNice(p.date_of_deposit) : '—') + '</td>' +
            '<td>' + escHtml(p.payment_type || '') + '</td>' +
            '<td>' + (p.created_at ? formatDateNice(p.created_at) : '—') + '</td>' +
            '</tr>';
        }).join('');
      }
    }
    // Stash on the view page for the Pay Remaining modal
    _payingAagId = aagId;
    _payingAagOutstanding = a.remaining || 0;
    document.getElementById('aagPayMemberName').textContent = a.name || '';
    document.getElementById('aagPayOutstandingDisplay').textContent = _aagMoney(a.remaining || 0);
  }).catch(function(e) { showUserError('loading AAG member', e); });
}
function editAagFromView() {
  // The user's spec: Edit icon opens the underlying alumni profile in editable
  // state — there's no AAG-specific editable view because the alumni data
  // lives on ak_alumni, and AAG payment state is managed via the Pay
  // Remaining modal (not a free-text form).
  apiAagDetail(viewingAagId).then(function(a) {
    if (a && a.alumni_id) openEditAkAlumni(a.alumni_id);
  }).catch(function(e) { showUserError('opening edit form', e); });
}

// ---- PAY REMAINING MODAL ----
function openAagPayRemainingModal() {
  if (!_payingAagId || _payingAagOutstanding <= 0) {
    alert('No outstanding balance for this member.');
    return;
  }
  var amtEl = document.getElementById('aagPayAmount');
  amtEl.value = (_payingAagOutstanding || 0).toFixed(2);
  amtEl.max = (_payingAagOutstanding || 0).toFixed(2);
  document.getElementById('aagPayDate').value = new Date().toISOString().slice(0, 10);
  document.getElementById('aagPayRemainingModal').style.display = 'flex';
}
function closeAagPayRemainingModal() {
  document.getElementById('aagPayRemainingModal').style.display = 'none';
}
function submitAagPayRemaining() {
  if (!_payingAagId) { alert('Cannot record payment: id missing.'); return; }
  var amt = parseFloat((document.getElementById('aagPayAmount') || {}).value);
  var date = (document.getElementById('aagPayDate') || {}).value;
  if (!isFinite(amt) || amt <= 0) { alert('Please enter a valid amount.'); return; }
  if (amt > _payingAagOutstanding + 0.001) {
    alert('Amount cannot exceed the outstanding balance (' + _aagMoney(_payingAagOutstanding) + ').');
    return;
  }
  if (!date) { alert('Please select Date of Deposit.'); return; }
  apiAagPay(_payingAagId, { amount: amt, date_of_deposit: date }).then(function() {
    closeAagPayRemainingModal();
    alert('Payment recorded successfully.');
    viewAagMember(_payingAagId);  // refresh view
  }).catch(function(e) { showUserError('recording payment', e); });
}

// ---- ADD/EDIT ALUMNI ----
// Tab order: Registration & Membership was removed 2026-05-29 per client.
// DB columns are kept; saveAkAlumni always sends those fields as null.
// 2026-06-02: Education / Work / Campaign tabs moved to the Transformation
// Tracking page (quarterly snapshots). Only Member Detail remains on Add Alumni.
var _alumniTabNames = ['alumniMember'];
var _alumniCurrentTab = 0;
// Class-based show/hide for the conditional groups in the Alumni form.
// Mirrors what toggleAkConditional did for a single wrapper, but operates
// on every .alumni-working-field / .alumni-fee-field at once so the
// fields can sit directly inside the parent form-grid and stay aligned.
function _toggleAlumniWorking() {
  var sel = document.getElementById('alumniWorking');
  var show = sel && sel.value === 'Yes';
  document.querySelectorAll('#alumniTab-alumniWork .alumni-working-field').forEach(function(el) {
    el.style.display = show ? '' : 'none';
  });
}
function _toggleAlumniFee() {
  var sel = document.getElementById('alumniFeeDep');
  var show = sel && sel.value === 'Yes';
  document.querySelectorAll('#alumniTab-alumniRegistration .alumni-fee-field').forEach(function(el) {
    el.style.display = show ? '' : 'none';
  });
}

function switchAkAlumniTab(tabId) {
  document.querySelectorAll('#page-addAkAlumni .tab-content').forEach(function(t) { t.classList.remove('active'); });
  document.querySelectorAll('#page-addAkAlumni .tab-btn').forEach(function(b) { b.classList.remove('active'); });
  var tab = document.getElementById('alumniTab-' + tabId);
  if (tab) tab.classList.add('active');
  var idx = _alumniTabNames.indexOf(tabId);
  _alumniCurrentTab = idx >= 0 ? idx : 0;
  var btns = document.querySelectorAll('#page-addAkAlumni .tab-btn');
  if (btns[_alumniCurrentTab]) btns[_alumniCurrentTab].classList.add('active');
  _updateAlumniNavButtons();
}
function _updateAlumniNavButtons() {
  var prevBtn = document.getElementById('akAlumniPrevBtn');
  var nextBtn = document.getElementById('akAlumniNextBtn');
  var saveBtn = document.getElementById('akAlumniSaveBtn');
  var cancelBtn = document.getElementById('akAlumniCancelBtn');
  var isLast = _alumniCurrentTab === _alumniTabNames.length - 1;
  var isFirst = _alumniCurrentTab === 0;
  if (prevBtn) prevBtn.style.display = isFirst ? 'none' : '';
  if (nextBtn) nextBtn.style.display = isLast ? 'none' : '';
  if (saveBtn) saveBtn.style.display = isLast ? '' : 'none';
  // Cancel is shown ONLY on the first tab (Member Detail) — once the user is
  // past that, Previous already provides backwards navigation, so Cancel
  // would be redundant clutter on later tabs.
  if (cancelBtn) cancelBtn.style.display = isFirst ? '' : 'none';
}
function alumniTabNav(dir) {
  var newIdx = _alumniCurrentTab + dir;
  if (newIdx < 0 || newIdx >= _alumniTabNames.length) return;
  switchAkAlumniTab(_alumniTabNames[newIdx]);
  window.scrollTo(0, 0);
}
function openAddAkAlumni() {
  akAlumniFormMode = 'add'; editingAkAlumniId = null;
  navigateTo('addAkAlumni');
  setTimeout(function() {
    var _b = document.getElementById('addAlumniBcText'); if (_b) _b.textContent = 'Add Alumni';
    var _s = document.getElementById('akAlumniSubmitText'); if (_s) _s.textContent = 'Submit';
    // Clear all fields. 2026-06-02: Education/Work/Campaign field IDs no
    // longer live on this form (moved to the Transformation Tracking page).
    ['alumniName','alumniReligionOther','alumniCasteOther','alumniFamilyIncome','alumniFamilyMembers','alumniPerCapita',
     'alumniMobile','alumniEmail','alumniAddress','alumniCapacityOther'].forEach(function(id) { var el = document.getElementById(id); if (el) el.value = ''; });
    // Batch is now a dropdown — clear its options so the only entry is the
    // "Select Batch" placeholder. _loadAkAlumniBatchesInto will refill once
    // State/Centre are picked.
    var _bSel = document.getElementById('alumniBatch');
    if (_bSel) _bSel.innerHTML = '<option value="">Select Batch</option>';
    ['alumniState','alumniCentre','alumniType','alumniEngagement','alumniCapacity','alumniMarital','alumniReligion','alumniCaste'
     ].forEach(function(id) { var el = document.getElementById(id); if (el) el.selectedIndex = 0; });
    ['alumniReligionOtherGrp','alumniCasteOtherGrp','alumniCapacityOtherGrp'].forEach(function(id) { var el = document.getElementById(id); if (el) el.style.display = 'none'; });
    // 2026-06-04 (v2): reset the Leader vs Peer name controls to the
    // default (Peer-style text input visible, Leader dropdown hidden,
    // disabled, single "Select Leader" placeholder). onAlumniTypeChange
    // will swap them when the user picks a Type; the Leader dropdown
    // stays disabled until State + Centre + Batch are all set.
    var _nameInp = document.getElementById('alumniName');
    var _nameSel = document.getElementById('alumniNameSelect');
    if (_nameInp) { _nameInp.style.display = ''; _nameInp.value = ''; }
    if (_nameSel) {
      _nameSel.style.display = 'none';
      _nameSel.innerHTML = '<option value="">Select Leader</option>';
      _nameSel.value = '';
      _nameSel.disabled = true;
    }
    // 2026-06-04: reset auto-fill lock so a fresh form starts editable
    // (Peer-default). onAlumniTypeChange re-locks when user picks Leader.
    _setAlumniAutoFillReadOnly(false);
    switchAkAlumniTab('alumniMember');
    // 2026-06-04 (v3): load states from AK State Management Master.
    _loadAkAlumniStatesFromMaster('alumniState');
    // 2026-06-04 (v4): seed Centre + Batch with the spec's "first step"
    // placeholders so the user sees the dependency immediately rather
    // than an empty "Select Centre" they cannot use.
    _setAlumniPlaceholder('alumniCentre', 'Select State First', true);
    _setAlumniPlaceholder('alumniBatch',  'Select Centre First', true);
  }, 100);
}
function openEditAkAlumni(id) {
  akAlumniFormMode = 'edit'; editingAkAlumniId = id;
  navigateTo('addAkAlumni');
  setTimeout(function() {
    var _b = document.getElementById('addAlumniBcText'); if (_b) _b.textContent = 'Edit Alumni';
    var _s = document.getElementById('akAlumniSubmitText'); if (_s) _s.textContent = 'Update';
    // 2026-06-04: in Edit mode keep Name as a free-text input regardless
    // of the original Type (the leader lookup is only needed at create
    // time for auto-fill; once saved the alumni record stands on its
    // own and every inherited field is editable per user spec).
    var _nameInp = document.getElementById('alumniName');
    var _nameSel = document.getElementById('alumniNameSelect');
    if (_nameInp) _nameInp.style.display = '';
    if (_nameSel) _nameSel.style.display = 'none';
    // 2026-06-04: in Edit mode every field should be editable (the
    // saved record stands alone; user updates inherited fields here).
    _setAlumniAutoFillReadOnly(false);
    switchAkAlumniTab('alumniMember');
    // 2026-06-04 (v3): load states from AK State Management Master.
    _loadAkAlumniStatesFromMaster('alumniState');
    apiAkAlumniDetail(id).then(function(a) {
      setTimeout(function() {
        if (a.state_code) {
          document.getElementById('alumniState').value = a.state_code;
          // 2026-06-04 (v3): in Edit hydration, load centres + batches
          // straight from the AK Master so the saved values resolve
          // even on records that pre-date the master rewire.
          _loadAkAlumniCentresFromMaster('alumniCentre', a.state_code);
          setTimeout(function() {
            if (a.centre_code) document.getElementById('alumniCentre').value = a.centre_code;
            var _bEl = document.getElementById('alumniBatch');
            if (_bEl && a.batch) {
              // Inject the saved value as a temporary option so .value sticks
              // even before the async batch list resolves.
              _bEl.innerHTML = '<option value="' + (typeof escHtml === 'function' ? escHtml(a.batch) : a.batch) + '" selected>' +
                               (typeof escHtml === 'function' ? escHtml(a.batch) : a.batch) + '</option>';
            }
            _loadAkAlumniBatchesFromMaster('alumniBatch', a.state_code, a.centre_code || '');
          }, 300);
        }
        document.getElementById('alumniName').value = a.name || '';
        document.getElementById('alumniType').value = a.type_of_alumni || '';
        document.getElementById('alumniEngagement').value = a.level_of_engagement || '';
        // 2026-06-04: Capacity Training hydration. Mirror Religion/Caste —
        // set the dropdown value, fire toggleAkConditional so the
        // Specify wrapper shows when value === 'Other', then write the
        // saved custom name into the input.
        var _capEl = document.getElementById('alumniCapacity');
        if (_capEl) _capEl.value = a.capacity_training || '';
        toggleAkConditional('alumniCapacity','Other','alumniCapacityOtherGrp');
        var _capOtherEl = document.getElementById('alumniCapacityOther');
        if (_capOtherEl) _capOtherEl.value = a.other_capacity_training || '';
        document.getElementById('alumniMarital').value = a.marital_status || '';
        document.getElementById('alumniReligion').value = a.religion || '';
        toggleAkConditional('alumniReligion','Any Other','alumniReligionOtherGrp');
        document.getElementById('alumniReligionOther').value = a.religion_other || '';
        document.getElementById('alumniCaste').value = a.caste || '';
        toggleAkConditional('alumniCaste','Any Others','alumniCasteOtherGrp');
        document.getElementById('alumniCasteOther').value = a.caste_other || '';
        document.getElementById('alumniFamilyIncome').value = a.family_monthly_income || '';
        document.getElementById('alumniFamilyMembers').value = a.family_members || '';
        document.getElementById('alumniPerCapita').value = a.per_capita_income || '';
        document.getElementById('alumniMobile').value = a.mobile || '';
        document.getElementById('alumniEmail').value = a.email || '';
        document.getElementById('alumniAddress').value = a.address || '';
        // 2026-06-02: Education / Work / Campaign field hydration removed
        // here — those fields now live on the Transformation Tracking page.
        // Registration & Membership fields are likewise legacy (2026-05-29).
      }, 500);
    });
  }, 100);
}
// =============================================================================
// 2026-06-04 (v3): Add Alumni cascade loaders — straight from the AK Master
// tables. The previous version used _loadAkStatesForModal (hits
// /api/ak/geo/states) and _loadAkAlumniBatchesInto (hits /api/ak-batches
// with status=Inactive). Both returned data that didn't match user expectation:
// states came from the programme geography table (not the Master), and batches
// were filtered to "Alumni Batches" (Inactive) which on stage = 0 rows.
//
// These new loaders go to the canonical AK Master endpoints:
//   /ak-master/states                       → Active states
//   /ak-master/centres?state_code=…         → Active centres mapped to state
//   /ak-batches?state_code=…&centre_code=…  → all batches mapped to centre
//   /ak?state_code=…&centre_code=…&batch_id=…&status=Active → leaders
// =============================================================================

// 2026-06-04 (v4): cascade-state UX per spec
//   "Implement Dynamic State → Centre → Batch Dropdown Population"
//
// Loading states (during fetch):
//   State  → "Loading states..."
//   Centre → "Loading centres..."   (only after a state is picked)
//   Batch  → "Loading batches..."   (only after a centre is picked)
//
// First-step hints (before a parent is picked):
//   Centre → "Select State First"
//   Batch  → "Select Centre First"
//
// Empty-data hints (when Master returns 0 rows):
//   Centre → "No centres available"
//   Batch  → "No batches available"
//
// The dropdowns stay DISABLED while the parent isn't picked yet, and
// also while the network request is in flight, so the user can't
// click into a stale list. They re-enable as soon as options arrive.
function _setAlumniPlaceholder(selectId, text, disabled) {
  var sel = document.getElementById(selectId);
  if (!sel) return;
  sel.innerHTML = '<option value="">' + text + '</option>';
  sel.value = '';
  sel.disabled = !!disabled;
}

function _loadAkAlumniStatesFromMaster(selectId) {
  var sel = document.getElementById(selectId);
  if (!sel) return;
  // 2026-06-08: For State Lead, hard-lock the State to their assigned
  // state (single locked option, disabled, greyed). Then dispatch a
  // change event so the Centre + Batch cascade kicks off automatically
  // and the user lands on a fully-scoped form. Other roles keep the
  // full state-master fetch.
  // 2026-06-08 (round 3): DL + PI also fall into this branch — state
  // hard-locked + cascade fires for centre/area/batch. After the
  // cascade populates Centre, a follow-up setTimeout pins Centre to
  // user's centre_code (hard-lock, greyed) so it auto-fills to the
  // user's assigned centre (e.g. South Delhi for South Delhi DL).
  var role = (currentUser && currentUser.role) || '';
  var _isDlPiSL = (role === 'state_lead' || role === 'district_lead' || role === 'pi');
  if (_isDlPiSL && currentUser.state_code) {
    var esc = (typeof escHtml === 'function') ? escHtml : function(x) { return x; };
    sel.innerHTML = '<option value="' + esc(currentUser.state_code) + '" selected>' +
                    esc(currentUser.state_name || currentUser.state_code) + '</option>';
    sel.value = currentUser.state_code;
    sel.disabled = true;
    sel.style.backgroundColor = '#f5f5f5';
    sel.style.cursor = 'not-allowed';
    sel.title = 'Locked to your assigned State';
    // Kick the cascade so Centre + Batch dropdowns reload scoped to
    // the state without the user needing to re-pick it.
    try { sel.dispatchEvent(new Event('change', { bubbles: true })); } catch (e) {}
    // 2026-06-08: For DL/PI with a resolved centre_code, follow up
    // after the cascade lands and hard-lock Centre too. The cascade
    // takes ~200 ms; we schedule 400 / 1200 ms retries to defeat the
    // race.
    if ((role === 'district_lead' || role === 'pi') && currentUser.centre_code) {
      [400, 1200].forEach(function(delay) {
        setTimeout(function() {
          var cSel = document.getElementById('alumniCentre');
          if (!cSel) return;
          var cName = currentUser.centre_name;
          if (!cName && currentUser.scope) {
            var m = String(currentUser.scope).match(/^(.+?), /);
            if (m) cName = m[1].trim();
          }
          cName = cName || currentUser.centre_code;
          cSel.innerHTML = '<option value="' + esc(currentUser.centre_code) + '" selected>' +
                           esc(cName) + '</option>';
          cSel.value = currentUser.centre_code;
          cSel.disabled = true;
          cSel.style.backgroundColor = '#f5f5f5';
          cSel.style.cursor = 'not-allowed';
          cSel.title = 'Locked to your assigned Centre';
        }, delay);
      });
    }
    return;
  }
  _setAlumniPlaceholder(selectId, 'Loading states...', true);
  apiAkMStates({ limit: 500 }).then(function(resp) {
    var rows = (resp && resp.data) || resp || [];
    var seen = {};
    var opts = [];
    rows.forEach(function(s) {
      var code = s.state_code;
      if (!code || seen[code]) return;
      // Per user spec: only Active states should appear.
      var status = String(s.status || 'Active');
      if (status.toLowerCase() === 'inactive') return;
      seen[code] = 1;
      opts.push({ code: code, name: s.state_name || code });
    });
    var esc = (typeof escHtml === 'function') ? escHtml : function(x) { return x; };
    var html = '<option value="">Select State</option>';
    opts.forEach(function(o) {
      html += '<option value="' + esc(o.code) + '">' + esc(o.name) + '</option>';
    });
    sel.innerHTML = html;
    sel.disabled = false;
  }).catch(function(err) {
    console.error('[Alumni] state-master load failed:', err);
    _setAlumniPlaceholder(selectId, 'Select State', false);
  });
}

function _loadAkAlumniCentresFromMaster(selectId, stateCode) {
  var sel = document.getElementById(selectId);
  if (!sel) return;
  if (!stateCode) {
    _setAlumniPlaceholder(selectId, 'Select State First', true);
    return;
  }
  _setAlumniPlaceholder(selectId, 'Loading centres...', true);
  apiGet('/ak-master/centres?state_code=' + encodeURIComponent(stateCode) + '&limit=500').then(function(resp) {
    var rows = (resp && resp.data) || resp || [];
    var seen = {};
    var opts = [];
    rows.forEach(function(c) {
      var code = c.centre_code;
      if (!code || seen[code]) return;
      var status = String(c.status || 'Active');
      if (status.toLowerCase() === 'inactive') return;
      seen[code] = 1;
      opts.push({ code: code, name: c.centre_name || code });
    });
    if (!opts.length) {
      _setAlumniPlaceholder(selectId, 'No centres available', true);
      return;
    }
    var esc = (typeof escHtml === 'function') ? escHtml : function(x) { return x; };
    var html = '<option value="">Select Centre</option>';
    opts.forEach(function(o) {
      html += '<option value="' + esc(o.code) + '">' + esc(o.name) + '</option>';
    });
    sel.innerHTML = html;
    sel.disabled = false;
  }).catch(function(err) {
    console.error('[Alumni] centre-master load failed:', err);
    _setAlumniPlaceholder(selectId, 'Select Centre', false);
  });
}

function _loadAkAlumniBatchesFromMaster(selectId, stateCode, centreCode) {
  var sel = document.getElementById(selectId);
  if (!sel) return;
  if (!stateCode || !centreCode) {
    _setAlumniPlaceholder(selectId, 'Select Centre First', true);
    return;
  }
  _setAlumniPlaceholder(selectId, 'Loading batches...', true);
  // No status filter on the Add Alumni batch picker — the user wants
  // every batch mapped to the chosen centre, not the legacy "Alumni
  // Batches (Inactive)" subset which on stage = 0 rows. The leader list
  // call further down still scopes to status=Active so the Name dropdown
  // only surfaces active leaders.
  apiAkBatchList({ limit: 500, state_code: stateCode, centre_code: centreCode }).then(function(resp) {
    var rows = (resp && resp.data) || resp || [];
    var seen = {};
    var opts = [];
    rows.forEach(function(b) {
      var label = b.name || b.batch_name || ('Batch ' + b.id);
      if (seen[label]) return;
      seen[label] = 1;
      opts.push({ label: label, id: b.id });
    });
    if (!opts.length) {
      _setAlumniPlaceholder(selectId, 'No batches available', true);
      return;
    }
    var esc = (typeof escHtml === 'function') ? escHtml : function(x) { return x; };
    var html = '<option value="">Select Batch</option>';
    opts.forEach(function(o) {
      var bidAttr = (o.id != null) ? (' data-batch-id="' + o.id + '"') : '';
      html += '<option value="' + esc(o.label) + '"' + bidAttr + '>' + esc(o.label) + '</option>';
    });
    sel.innerHTML = html;
    sel.disabled = false;
  }).catch(function(err) {
    console.error('[Alumni] batch-master load failed:', err);
    _setAlumniPlaceholder(selectId, 'Select Batch', false);
  });
}

// 2026-06-04: Add Alumni form — Leader vs Peer flow.
//
// onAlumniTypeChange swaps the Name field between a free-text input
// (Peer) and a leader-picker dropdown (Leader). Picking a leader from
// the dropdown auto-fills Religion / Caste / Mobile / Email / Address
// from /api/ak/{id}. State+Centre+Batch cascade still works in both
// modes; in Leader mode every cascade change refreshes the leader
// dropdown.
function onAlumniTypeChange() {
  var t = (document.getElementById('alumniType') || {}).value || '';
  var nameInput = document.getElementById('alumniName');
  var nameSelect = document.getElementById('alumniNameSelect');
  if (!nameInput || !nameSelect) return;
  if (t === 'Leader Alumni') {
    nameInput.style.display = 'none';
    nameSelect.style.display = '';
    _refreshAlumniLeaderNameOptions();
    // Lock auto-fill fields immediately. Even before the user picks a
    // leader, the spec says these fields are non-editable in this mode.
    // They unlock automatically when the user switches to Peer below.
    _setAlumniAutoFillReadOnly(true);
    // 2026-06-04 (later): per spec amendment, Marital Status + Email ID
    // MUST be blank on entering Leader mode (and stay editable). Wipe
    // any stale values from a previous selection so the user starts
    // from a clean slate.
    var mEl = document.getElementById('alumniMarital'); if (mEl) mEl.value = '';
    var eEl = document.getElementById('alumniEmail');   if (eEl) eEl.value = '';
  } else {
    nameSelect.style.display = 'none';
    nameInput.style.display = '';
    nameSelect.value = '';
    // Peer mode: unlock every auto-fill field so the user can type in
    // values manually. We leave any value already in the inputs intact
    // — switching from Leader -> Peer keeps the last leader's values
    // as editable defaults rather than blanking them.
    _setAlumniAutoFillReadOnly(false);
  }
}

function _refreshAlumniLeaderNameOptions() {
  // 2026-06-04 (v2): per user spec, the Leader Name dropdown stays
  // empty + disabled until State + Centre + Batch are ALL selected.
  // No "Pick State + Centre first" hint text — just a clean "Select
  // Leader" placeholder. The batch_id is read from the selected Batch
  // option's data-batch-id attribute (the option's value= is the batch
  // NAME for backward-compat with saveAkAlumni; data-batch-id was
  // added to each option in _loadAkAlumniBatchesInto for this purpose).
  var sel = document.getElementById('alumniNameSelect');
  if (!sel) return;
  var keep = sel.value;
  var st = (document.getElementById('alumniState')  || {}).value;
  var ce = (document.getElementById('alumniCentre') || {}).value;
  var bSel = document.getElementById('alumniBatch');
  var btName = (bSel || {}).value || '';
  var btId = '';
  if (bSel && btName) {
    var picked = bSel.options[bSel.selectedIndex];
    if (picked) btId = picked.getAttribute('data-batch-id') || '';
  }

  // Reset to the bare placeholder + disabled until every cascade slot is set.
  sel.innerHTML = '<option value="">Select Leader</option>';
  if (!st || !ce || !btName || !btId) {
    sel.disabled = true;
    return;
  }
  sel.disabled = false;

  var params = {
    state_code: st,
    centre_code: ce,
    batch_id: parseInt(btId, 10),
    limit: 200,
    status: 'Active',
  };
  apiAkList(params).then(function(resp) {
    var rows = (resp && resp.data) || resp || [];
    rows.forEach(function(r) {
      var opt = document.createElement('option');
      opt.value = String(r.id);
      var label = (r.name || '—');
      if (r.enrollment_number) label += ' — ' + r.enrollment_number;
      opt.textContent = label;
      // Stash the leader's plain name so onAlumniNameSelectChange can
      // mirror it into the hidden text input (which saveAkAlumni reads).
      opt.setAttribute('data-leader-name', r.name || '');
      sel.appendChild(opt);
    });
    if (keep) sel.value = keep;
  }).catch(function() {});
}

function onAlumniNameSelectChange() {
  var sel = document.getElementById('alumniNameSelect');
  if (!sel || !sel.value) return;
  var leaderId = sel.value;
  var opt = sel.options[sel.selectedIndex];
  var pickedName = (opt && opt.getAttribute('data-leader-name')) || '';
  // Mirror name into the hidden text input so the same saveAkAlumni
  // path keeps working — it always reads from #alumniName.
  var nameInput = document.getElementById('alumniName');
  if (nameInput) nameInput.value = pickedName;

  apiAkDetail(leaderId).then(function(a) {
    var set = function(id, v) { var el = document.getElementById(id); if (el) el.value = (v == null ? '' : v); };
    // Religion / Caste have a conditional "Other" follow-up — call the
    // toggler after setting the value so the follow-up shows/hides
    // correctly when the leader's saved value is "Any Other" / "Any Others".
    set('alumniReligion',      a.religion);
    set('alumniReligionOther', a.religion_other);
    if (typeof toggleAkConditional === 'function') toggleAkConditional('alumniReligion', 'Any Other', 'alumniReligionOtherGrp');
    // AK Leader's caste column is `category` (with category_other).
    set('alumniCaste',         a.category);
    set('alumniCasteOther',    a.category_other);
    if (typeof toggleAkConditional === 'function') toggleAkConditional('alumniCaste', 'Any Others', 'alumniCasteOtherGrp');
    set('alumniMobile',        a.contact_number);
    // 2026-06-04 (later): Marital Status + Email ID are intentionally
    // NOT auto-filled for Leader Alumni per user spec. They must remain
    // blank and editable so the user enters them manually each time.
    // Explicitly blank them here in case a prior leader pick (or any
    // other code path) populated them.
    set('alumniEmail',         '');
    set('alumniMarital',       '');
    set('alumniAddress',       a.address);
    // 2026-06-04: extended auto-fill per user spec — Family income,
    // Family members, Per-Capita auto-calc. (Marital Status moved out
    // of this list per the 2026-06-04 spec amendment — see comment
    // above; user types it manually.)
    set('alumniFamilyIncome',  a.family_monthly_income);
    set('alumniFamilyMembers', a.family_members);
    set('alumniPerCapita',     a.per_capita_income);
    // Force a recompute in case stored per_capita_income drifts from
    // income / members (defensive — uses the same client formula the
    // Save form already runs).
    if (typeof calcAlumniPerCapita === 'function') calcAlumniPerCapita();
    // Lock all auto-fillable fields against manual editing for Leader
    // Alumni per user spec ("User should not manually edit…").
    _setAlumniAutoFillReadOnly(true);
  }).catch(function() {});
}

// 2026-06-04: helper — toggle readonly/disabled on the fields that
// are auto-filled from the Leader profile. <select>s use .disabled
// (they don't honour readOnly); text inputs + textareas use .readOnly.
// Visual cue: greyed background so the user sees the lock.
//
// 2026-06-04 (later): per spec amendment, Marital Status and Email ID
// are NO LONGER auto-filled for Leader Alumni — the user enters them
// manually — so they're removed from the lock lists below. Other
// auto-filled fields (income, members, religion, caste, mobile,
// address) still toggle readonly with the Leader/Peer switch.
function _setAlumniAutoFillReadOnly(readOnly) {
  var inputs = ['alumniFamilyIncome','alumniFamilyMembers',
                'alumniMobile','alumniAddress'];
  var selects = ['alumniReligion','alumniCaste'];
  inputs.forEach(function(id) {
    var el = document.getElementById(id);
    if (!el) return;
    el.readOnly = !!readOnly;
    el.style.background = readOnly ? '#f5f5f5' : '';
    el.style.cursor     = readOnly ? 'not-allowed' : '';
  });
  selects.forEach(function(id) {
    var el = document.getElementById(id);
    if (!el) return;
    el.disabled = !!readOnly;
    el.style.background = readOnly ? '#f5f5f5' : '';
    el.style.cursor     = readOnly ? 'not-allowed' : '';
  });
  // Per Capita Income is always calculated, never user-edited — its
  // readonly attribute is set in the HTML and isn't touched here.
}

// Called by the Batch dropdown onchange. In Leader mode, refreshes the
// Name dropdown so it only lists leaders matching the new Batch. In
// Peer mode it's a no-op (we don't touch the free-text Name).
function onAlumniBatchChange() {
  var t = (document.getElementById('alumniType') || {}).value || '';
  if (t === 'Leader Alumni') _refreshAlumniLeaderNameOptions();
}

function onAlumniFormStateChange(cb) {
  // 2026-06-04 (v3): single canonical path. Centre + Batch cascades
  // pull from the AK Master tables exclusively. The legacy XHR to
  // /api/ak/geo/centres and the legacy _loadAkAlumniBatchesInto
  // (status=Inactive) calls have been removed — they were the cause
  // of the empty State / empty Batch dropdowns the user reported.
  //
  // 2026-06-04 (v4): per spec, State change MUST reset BOTH children.
  // Batch is reset to "Select Centre First" (the next step the user
  // has to take) and disabled until centre is picked. Centre is reset
  // inside _loadAkAlumniCentresFromMaster (to either "Loading…" or
  // "Select State First" depending on whether the state was cleared).
  var sc = (document.getElementById('alumniState') || {}).value;
  _setAlumniPlaceholder('alumniBatch', 'Select Centre First', true);
  _loadAkAlumniCentresFromMaster('alumniCentre', sc);
  // Leader mode: clear + disable the Name dropdown so stale leader
  // options from the old centre don't linger.
  if ((document.getElementById('alumniType') || {}).value === 'Leader Alumni') {
    var nameSel = document.getElementById('alumniNameSelect');
    if (nameSel) {
      nameSel.innerHTML = '<option value="">Select Leader</option>';
      nameSel.disabled = true;
    }
  }
  // 2026-06-04: callback support kept for openEditAkAlumni hydration —
  // fire it after the master centre fetch settles (300ms guess matches
  // the existing setTimeout-based hydration cadence).
  if (typeof cb === 'function') setTimeout(cb, 300);
}
// Cascade: State → Centre → Batch. Triggered when the user changes Centre
// in the Add/Edit Alumni form. Refreshes the Batch dropdown to show only
// batches matching the current state+centre (active + inactive both).
function onAlumniFormCentreChange() {
  var sc = (document.getElementById('alumniState') || {}).value;
  var cc = (document.getElementById('alumniCentre') || {}).value;
  // 2026-06-04 (v3): batches now come from the AK Master Batch endpoint
  // without the legacy "status=Inactive (Alumni Batch)" filter — that
  // filter returns 0 rows on stage, leaving the dropdown empty even
  // when batches exist. The Name dropdown's leader query still
  // restricts to status=Active so dropouts don't show.
  _loadAkAlumniBatchesFromMaster('alumniBatch', sc, cc);
  // Leader mode — refresh the Name dropdown so it now lists leaders for
  // the just-picked centre (filtered further once batch is chosen).
  if ((document.getElementById('alumniType') || {}).value === 'Leader Alumni') {
    _refreshAlumniLeaderNameOptions();
  }
}
function calcAlumniPerCapita() {
  var inc = parseFloat((document.getElementById('alumniFamilyIncome') || {}).value) || 0;
  var mem = parseInt((document.getElementById('alumniFamilyMembers') || {}).value) || 0;
  var pc = document.getElementById('alumniPerCapita');
  if (pc) pc.value = mem > 0 ? (inc / mem).toFixed(2) : '';
}
function saveAkAlumni() {
  function _v(id) { var el = document.getElementById(id); return el ? (el.value || '').trim() : ''; }
  if (!_v('alumniState')) { alert('Please select State.'); switchAkAlumniTab('alumniMember'); return; }
  if (!_v('alumniCentre')) { alert('Please select Centre.'); switchAkAlumniTab('alumniMember'); return; }
  if (!_v('alumniName')) { alert('Please enter Name.'); switchAkAlumniTab('alumniMember'); return; }
  // 2026-06-04: alert wording — Batch is a dropdown, not a text field;
  // the spec calls it out as "mandatory" so "select" is the right verb.
  if (!_v('alumniBatch')) { alert('Please select Batch.'); switchAkAlumniTab('alumniMember'); return; }
  if (!_v('alumniType')) { alert('Please select Type of Alumni.'); switchAkAlumniTab('alumniMember'); return; }
  // 2026-06-04: Capacity Training is required per user spec.
  // If user picked "Other", the Specify input is also required and
  // capped at 100 chars (HTML maxlength + trim here).
  if (!_v('alumniCapacity')) {
    alert('Please select Capacity Training.');
    var _focEl = document.getElementById('alumniCapacity'); if (_focEl && _focEl.focus) _focEl.focus();
    switchAkAlumniTab('alumniMember'); return;
  }
  if (_v('alumniCapacity') === 'Other' && !_v('alumniCapacityOther')) {
    alert('Please specify the capacity training.');
    var _focEl2 = document.getElementById('alumniCapacityOther'); if (_focEl2 && _focEl2.focus) _focEl2.focus();
    switchAkAlumniTab('alumniMember'); return;
  }
  if (!_v('alumniAddress')) { alert('Please enter Address.'); switchAkAlumniTab('alumniMember'); return; }
  var mob = _v('alumniMobile');
  if (mob && !/^\d{10}$/.test(mob)) { alert('Mobile must be 10 digits.'); switchAkAlumniTab('alumniMember'); return; }

  var data = {
    state_code: _v('alumniState'), centre_code: _v('alumniCentre'),
    name: _v('alumniName'), batch: _v('alumniBatch'),
    type_of_alumni: _v('alumniType'), level_of_engagement: _v('alumniEngagement') || null,
    // 2026-06-04: Capacity Training fields. Only send the "Other" custom
    // text when the dropdown is set to 'Other'; otherwise it's null so
    // the DB row stays clean if the user picks one of the canonical
    // options after a previous "Other" entry.
    capacity_training: _v('alumniCapacity') || null,
    other_capacity_training: (_v('alumniCapacity') === 'Other') ? (_v('alumniCapacityOther').slice(0,100) || null) : null,
    marital_status: _v('alumniMarital') || null, religion: _v('alumniReligion') || null,
    religion_other: _v('alumniReligionOther') || null, caste: _v('alumniCaste') || null,
    caste_other: _v('alumniCasteOther') || null,
    family_monthly_income: parseFloat(_v('alumniFamilyIncome')) || null,
    family_members: parseInt(_v('alumniFamilyMembers')) || null,
    per_capita_income: parseFloat(_v('alumniPerCapita')) || null,
    mobile: mob || null, email: _v('alumniEmail') || null, address: _v('alumniAddress'),
    // 2026-06-02: Education / Work / Campaign fields moved to Transformation
    // Tracking. Send nulls here so the legacy ak_alumni columns keep their
    // existing schema; new values flow through the tracking entries only.
    educational_status: null, are_you_studying: null, studying_what: null, current_institution: null,
    are_you_working: null, type_of_work: null, designation: null, employer_name: null, monthly_salary: null,
    campaign_name: null, campaign_date: null, exposure_visit: null, alumni_meet: null,
    // Registration & Membership tab removed 2026-05-29.
    registration_done: null, membership_fee_deposited: null,
    deposit_installment: null, amount_deposited: null,
    date_of_deposit: null
  };
  var promise = (akAlumniFormMode === 'edit' && editingAkAlumniId) ? apiUpdateAkAlumni(editingAkAlumniId, data) : apiCreateAkAlumni(data);
  promise.then(function() {
    alert(akAlumniFormMode === 'edit' ? 'Alumni updated!' : 'Alumni created!');
    navigateTo('akAlumni');
  }).catch(function(e) {
    var msg = e.message || (typeof e === 'string' ? e : JSON.stringify(e));
    alert('Error: ' + msg);
  });
}

// ---- VIEW ALUMNI ----
function viewAkAlumniDetail(id) { viewingAkAlumniId = id; _ctxSet('viewAkAlumni', id); navigateTo('viewAkAlumni'); }

// 2026-06-01 (v2): inline-editable cell renderer for the 4 "living"
// alumni fields on the View page (Marital Status, Address, Monthly
// Income / monthly_salary, Mobile / Phone Number). Each cell shows
// the value with a pencil icon; click swaps to input/select + save/
// cancel; save PATCHes only that field via apiAkAlumniInlineEdit.
// Other Alumni fields stay read-only and still need the full Edit
// form for changes.
//
// spec.field    - UI key (marital_status, address, monthly_income, mobile,
//                 family_monthly_income, family_members)
// spec.type     - 'select' | 'textarea' | 'number' | 'tel'
// spec.options  - array of strings, only for type === 'select'
// spec.format   - 'money' to prefix the rupee glyph + thousands separators in read mode
// spec.min      - numeric, applied as HTML5 min + client-side floor
// spec.integer  - true to reject decimals (step="1" + parse-check)
// spec.required - true to reject blank submits with a friendly message
function _renderAlumniEditable(label, value, spec) {
  var displayVal;
  if (value == null || value === '') {
    displayVal = '—';
  } else if (spec.format === 'money') {
    displayVal = '₹' + formatNumber(value);
  } else {
    displayVal = escHtml(String(value));
  }
  var rawAttr = (value == null) ? '' : String(value);
  return '<div class="detail-item alumni-inline-cell"' +
         ' data-field="'    + spec.field + '"' +
         ' data-type="'     + spec.type  + '"' +
         ' data-label="'    + escHtml(label) + '"' +
         (spec.format ? ' data-format="' + spec.format + '"' : '') +
         (spec.options ? ' data-options="' + escHtml(spec.options.join('|')) + '"' : '') +
         (spec.min != null ? ' data-min="' + spec.min + '"' : '') +
         (spec.integer ? ' data-integer="1"' : '') +
         (spec.required ? ' data-required="1"' : '') +
         '>' +
           '<label>' + escHtml(label) + '</label>' +
           '<span class="alumni-inline-display" style="display:inline-flex;align-items:center;gap:8px;">' +
             '<span class="alumni-inline-value" data-raw-value="' + escHtml(rawAttr) + '">' + displayVal + '</span>' +
             '<button type="button" class="btn-icon alumni-inline-edit-btn" title="Edit ' + escHtml(label) +
               '" onclick="alumniInlineEditStart(this)" style="padding:2px 6px;color:#732269;">' +
               '<i class="fas fa-pencil-alt"></i></button>' +
           '</span>' +
         '</div>';
}

function alumniInlineEditStart(btn) {
  var cell = btn.closest('.alumni-inline-cell');
  if (!cell) return;
  var type  = cell.getAttribute('data-type');
  var optsAttr = cell.getAttribute('data-options') || '';
  var raw = (cell.querySelector('.alumni-inline-value') || {}).getAttribute('data-raw-value') || '';
  var inputHtml;
  if (type === 'select') {
    var opts = optsAttr.split('|').filter(Boolean);
    inputHtml = '<select class="alumni-inline-input" style="min-width:160px;padding:4px 6px;border:1px solid #ddd;border-radius:4px;">' +
                  '<option value="">— Clear —</option>' +
                  opts.map(function(o) {
                    var sel = (o === raw) ? ' selected' : '';
                    return '<option value="' + escHtml(o) + '"' + sel + '>' + escHtml(o) + '</option>';
                  }).join('') +
                '</select>';
  } else if (type === 'textarea') {
    inputHtml = '<textarea class="alumni-inline-input" rows="2" style="min-width:220px;padding:4px 6px;border:1px solid #ddd;border-radius:4px;">' + escHtml(raw) + '</textarea>';
  } else if (type === 'number') {
    // 2026-06-04: pull spec attrs off the cell so Family Members can
    // enforce step="1" (integer-only) and min="1" while Family Monthly
    // Income keeps step="any" and min="0". HTML5 attrs give the user
    // up/down spinners + browser-level validation; the JS save handler
    // re-validates the same rules so a clipboard paste can't bypass.
    var minAttr  = cell.getAttribute('data-min');
    var stepAttr = (cell.getAttribute('data-integer') === '1') ? '1' : 'any';
    var minHtml  = (minAttr != null && minAttr !== '') ? (' min="' + escHtml(minAttr) + '"') : '';
    inputHtml = '<input class="alumni-inline-input" type="number"' + minHtml +
                ' step="' + stepAttr + '" value="' + escHtml(raw) +
                '" style="width:140px;padding:4px 6px;border:1px solid #ddd;border-radius:4px;">';
  } else if (type === 'tel') {
    inputHtml = '<input class="alumni-inline-input" type="text" maxlength="10" value="' + escHtml(raw) +
                '" oninput="this.value=this.value.replace(/[^0-9]/g,\'\')" placeholder="10-digit" style="width:160px;padding:4px 6px;border:1px solid #ddd;border-radius:4px;">';
  } else {
    inputHtml = '<input class="alumni-inline-input" type="text" value="' + escHtml(raw) + '" style="min-width:160px;padding:4px 6px;border:1px solid #ddd;border-radius:4px;">';
  }
  var display = cell.querySelector('.alumni-inline-display');
  if (!display) return;
  display.style.display = 'none';
  var editor = document.createElement('span');
  editor.className = 'alumni-inline-editor';
  editor.style.cssText = 'display:inline-flex;align-items:center;gap:6px;';
  editor.innerHTML = inputHtml +
    '<button type="button" class="btn-icon" title="Save" onclick="alumniInlineEditSave(this)" style="padding:2px 6px;color:#27ae60;">' +
      '<i class="fas fa-check"></i></button>' +
    '<button type="button" class="btn-icon" title="Cancel" onclick="alumniInlineEditCancel(this)" style="padding:2px 6px;color:#e74c3c;">' +
      '<i class="fas fa-times"></i></button>';
  display.parentNode.insertBefore(editor, display.nextSibling);
  var input = editor.querySelector('.alumni-inline-input');
  if (input && input.focus) try { input.focus(); } catch (e) {}
}

function alumniInlineEditCancel(btn) {
  var cell = btn.closest('.alumni-inline-cell');
  if (!cell) return;
  var editor = cell.querySelector('.alumni-inline-editor');
  if (editor) editor.parentNode.removeChild(editor);
  var display = cell.querySelector('.alumni-inline-display');
  if (display) display.style.display = '';
}

function alumniInlineEditSave(btn) {
  var cell = btn.closest('.alumni-inline-cell');
  if (!cell || !viewingAkAlumniId) return;
  var field    = cell.getAttribute('data-field');
  var type     = cell.getAttribute('data-type');
  var label    = cell.getAttribute('data-label') || field;
  var required = cell.getAttribute('data-required') === '1';
  var integer  = cell.getAttribute('data-integer') === '1';
  var minRaw   = cell.getAttribute('data-min');
  var minVal   = (minRaw != null && minRaw !== '') ? parseFloat(minRaw) : null;
  var input    = cell.querySelector('.alumni-inline-input');
  if (!input) return;
  var rawNew = (input.value || '').trim();

  // 2026-06-04: per-field validation per the user spec for
  // Family Monthly Income + Family Members. Existing validations for
  // the older inline fields (mobile / monthly_income) are preserved
  // verbatim below.
  if (required && rawNew === '') {
    alert(label + ' is required.');
    if (input.focus) input.focus();
    return;
  }
  if (type === 'number' && rawNew !== '') {
    var parsed = parseFloat(rawNew);
    if (isNaN(parsed)) {
      alert('Only numeric values are allowed.');
      if (input.focus) input.focus();
      return;
    }
    if (integer && parsed !== Math.floor(parsed)) {
      alert('Only whole numbers are allowed.');
      if (input.focus) input.focus();
      return;
    }
    if (minVal != null && parsed < minVal) {
      // Field-specific negative-income message per spec; generic for
      // other fields with a custom minimum.
      if (field === 'family_monthly_income' && minVal === 0) {
        alert('Income cannot be negative.');
      } else if (field === 'family_members' && minVal === 1) {
        alert('Family Members must be greater than 0.');
      } else {
        alert(label + ' must be ' + minVal + ' or greater.');
      }
      if (input.focus) input.focus();
      return;
    }
  }
  // Legacy validations kept verbatim for older inline fields.
  if (type === 'tel' && rawNew && rawNew.length !== 10) {
    alert('Phone Number must be exactly 10 digits.');
    if (input.focus) input.focus();
    return;
  }
  if (type === 'number' && field === 'monthly_income' && rawNew !== '' && parseFloat(rawNew) < 0) {
    alert('Monthly Income must be 0 or greater.');
    if (input.focus) input.focus();
    return;
  }
  // Disable controls during the round-trip so a double-click can't
  // fire two PATCHes.
  var editor = cell.querySelector('.alumni-inline-editor');
  if (editor) editor.querySelectorAll('button,input,select,textarea').forEach(function(el) { el.disabled = true; });
  apiAkAlumniInlineEdit(viewingAkAlumniId, {
    field: field,
    value: rawNew === '' ? null : rawNew
  }).then(function(resp) {
    var stored = (resp && 'value' in resp) ? resp.value : rawNew;
    var displayVal;
    if (stored == null || stored === '') {
      displayVal = '—';
    } else if (cell.getAttribute('data-format') === 'money') {
      displayVal = '₹' + formatNumber(stored);
    } else {
      displayVal = escHtml(String(stored));
    }
    var valSpan = cell.querySelector('.alumni-inline-value');
    if (valSpan) {
      valSpan.innerHTML = displayVal;
      valSpan.setAttribute('data-raw-value', stored == null ? '' : String(stored));
    }
    if (editor) editor.parentNode.removeChild(editor);
    var display = cell.querySelector('.alumni-inline-display');
    if (display) display.style.display = '';
    // 2026-06-04: when Family Monthly Income or Family Members changes,
    // the backend recomputes per_capita_income in the same transaction
    // and returns it on the response. Reflect it in the read-only Per
    // Capita Income row without a full page refetch. If the backend
    // chose to leave per_capita NULL (e.g. members = 0 — which the new
    // pos_int validator now rejects, so shouldn't happen in practice),
    // we fall back to the dash placeholder.
    if (resp && 'per_capita_income' in resp &&
        (field === 'family_monthly_income' || field === 'family_members')) {
      var pcEl = document.getElementById('alumniViewPerCapita');
      if (pcEl) {
        var pc = resp.per_capita_income;
        pcEl.innerHTML = (pc != null && pc !== '') ? ('₹' + formatNumber(pc)) : '—';
      }
    }
  }).catch(function(err) {
    if (editor) editor.querySelectorAll('button,input,select,textarea').forEach(function(el) { el.disabled = false; });
    showUserError('saving ' + field, err);
  });
}

function loadAkAlumniView(id) {
  function _d(l, v) { return '<div class="detail-item"><label>' + l + '</label><span>' + escHtml(v || '—') + '</span></div>'; }
  function _dMoney(l, v) { return '<div class="detail-item"><label>' + l + '</label><span>' + (v ? '\u20B9' + formatNumber(v) : '—') + '</span></div>'; }
  apiAkAlumniDetail(id).then(function(a) {
    var mg = document.getElementById('alumniViewMember');
    if (mg) mg.innerHTML = _d('State', a.state_name) + _d('Centre', a.centre_name) + _d('Name', a.name) + _d('Batch', a.batch) +
      _d('Type of Alumni', a.type_of_alumni) + _d('Level of Engagement', a.level_of_engagement) +
      // 2026-06-04: Capacity Training. Spec example: "Display Other
      // value when 'Other' was selected" — so when capacity_training is
      // 'Other' we surface the custom name (other_capacity_training)
      // directly, not the literal word "Other". Otherwise show the
      // canonical option.
      _d('Capacity Training',
         (a.capacity_training === 'Other'
            ? (a.other_capacity_training || 'Other')
            : a.capacity_training)) +
      // 2026-06-01 (v2): Marital Status / Mobile / Address render as
      // pencil-edit cells. Click the pencil to update one field at a
      // time without leaving the View page (uses _renderAlumniEditable
      // + apiAkAlumniInlineEdit defined above).
      _renderAlumniEditable('Marital Status', a.marital_status, {
        field: 'marital_status', type: 'select',
        options: ['Single', 'Married', 'Widow', 'Divorced', 'Separated']
      }) +
      _d('Religion', a.religion) + (a.religion_other ? _d('Religion (Other)', a.religion_other) : '') +
      _d('Caste', a.caste) + (a.caste_other ? _d('Caste (Other)', a.caste_other) : '') +
      // 2026-06-04: Family Monthly Income + Family Members now editable
      // inline (pencil → input → Save/Cancel), same architecture as
      // Marital / Mobile / Address. Per Capita Income remains read-only
      // and is recomputed server-side whenever either source field
      // changes; the PATCH response carries the new per_capita_income
      // and the save handler writes it into #alumniViewPerCapita without
      // a page refetch.
      _renderAlumniEditable('Family Monthly Income', a.family_monthly_income, {
        field: 'family_monthly_income', type: 'number',
        format: 'money', min: 0, required: true
      }) +
      _renderAlumniEditable('Family Members', a.family_members, {
        field: 'family_members', type: 'number',
        integer: true, min: 1, required: true
      }) +
      '<div class="detail-item"><label>Per Capita Income</label>' +
        '<span id="alumniViewPerCapita">' +
          (a.per_capita_income ? ('₹' + formatNumber(a.per_capita_income)) : '—') +
        '</span>' +
        '<small style="display:block;color:#888;font-size:11px;margin-top:2px;">(Auto Calculated)</small>' +
      '</div>' +
      _renderAlumniEditable('Mobile', a.mobile, { field: 'mobile', type: 'tel' }) +
      _d('Email', a.email) +
      _renderAlumniEditable('Address', a.address, { field: 'address', type: 'textarea' });
    // 2026-06-02: Education / Work / Campaign sections moved to the
    // Transformation Tracking page. Their containers remain in the DOM as
    // hidden divs (no-op render) for backwards-compat with cached HTML.
    // Load tracking history in view
    trackingAlumniId = id;
    trackingAlumniName = a.name || '';
    _loadAlumniTrackingHistory(id, 'alumniViewTrackingBody');
  });
}

// ---- ALUMNI TRANSFORMATION TRACKING ----
var trackingAlumniId = null, trackingAlumniName = '';
var viewingTrackingId = null;

// 2026-06-03 (v10): Transformation Tracking screen now uses MGJ-style
// tabs. switchTrackTab swaps visibility just like MGJ's switchMgjTab —
// toggles `.tab-content.active` and `.tab-btn.active` classes scoped to
// page-addAlumniTracking. The 4 tab names map to the 4 sections:
//   tracking  -> Transformation Tracking — [Name]
//   education -> Education Engagement
//   work      -> Work Engagement
//   campaign  -> Campaign & Activity
function switchTrackTab(id) {
  var names = ['tracking', 'education', 'work', 'campaign'];
  document.querySelectorAll('#page-addAlumniTracking .tab-content').forEach(function(t) { t.classList.remove('active'); });
  document.querySelectorAll('#page-addAlumniTracking .tab-btn').forEach(function(b) { b.classList.remove('active'); });
  var tab = document.getElementById('trackTab-' + id);
  if (tab) tab.classList.add('active');
  var btns = document.querySelectorAll('#page-addAlumniTracking .tab-btn');
  var idx = names.indexOf(id);
  if (idx >= 0 && btns[idx]) btns[idx].classList.add('active');
  window.scrollTo(0, 0);
}

function openAlumniTrackingModal(alumniId, alumniName) {
  trackingAlumniId = alumniId;
  trackingAlumniName = alumniName || '';
  navigateTo('addAlumniTracking');
  setTimeout(function() {
    // Always open on tab 1 (Transformation Tracking).
    switchTrackTab('tracking');
    var nameEl = document.getElementById('trackingAlumniName');
    if (nameEl) nameEl.textContent = trackingAlumniName;
    // ---- Tracking core: Q1-Q10 + Month + Engagement (unchanged) ----
    ['trackMonth','trackQ8','trackQ10','trackQ12','trackQ14','trackQ16','trackQ18','trackQ20','trackQ22','trackQ24','trackQ25'].forEach(function(id) {
      var el = document.getElementById(id); if (el) el.value = '';
    });
    ['trackEngagement','trackQ7','trackQ9','trackQ11','trackQ13','trackQ15','trackQ17','trackQ19','trackQ21','trackQ23'].forEach(function(id) {
      var el = document.getElementById(id); if (el) el.selectedIndex = 0;
    });
    ['trackQ8Grp','trackQ10Grp','trackQ12Grp','trackQ14Grp','trackQ16Grp','trackQ18Grp','trackQ20Grp','trackQ22Grp','trackQ24Grp'].forEach(function(id) {
      var el = document.getElementById(id); if (el) el.style.display = 'none';
    });
    // ---- Education / Work / Campaign sections (v8) ----
    ['alumniEduStatus','alumniStudyingWhat','alumniInstitution',
     'alumniWorkType','alumniDesignation','alumniEmployer','alumniSalary',
     'alumniCampaignName','alumniCampaignDate'].forEach(function(id) {
      var el = document.getElementById(id); if (el) el.value = '';
    });
    ['alumniStudying','alumniWorking','alumniExposure','alumniMeet'].forEach(function(id) {
      var el = document.getElementById(id); if (el) el.selectedIndex = 0;
    });
    ['alumniStudyingGrp','alumniInstitutionGrp'].forEach(function(id) {
      var el = document.getElementById(id); if (el) el.style.display = 'none';
    });
    document.querySelectorAll('#page-addAlumniTracking .alumni-working-field').forEach(function(el) { el.style.display = 'none'; });
    // Pre-fill from the most recent tracking entry (single fetch — feeds
    // both the history table and the snapshot pre-fill).
    apiAkAlumniTracking(alumniId).then(function(entries) {
      var list = Array.isArray(entries) ? entries : (entries.data || []);
      if (list.length) {
        var last = list[0]; // GET endpoint orders DESC by created_at
        var setVal = function(id, v) { var el = document.getElementById(id); if (el && v != null) el.value = v; };
        setVal('alumniEduStatus', last.educational_status);
        setVal('alumniStudying', last.are_you_studying);
        setVal('alumniStudyingWhat', last.studying_what);
        setVal('alumniInstitution', last.current_institution);
        if (typeof onAlumniStudyingChange === 'function') onAlumniStudyingChange();
        setVal('alumniWorking', last.are_you_working);
        if (typeof _toggleAlumniWorking === 'function') _toggleAlumniWorking();
        setVal('alumniWorkType', last.type_of_work);
        setVal('alumniDesignation', last.designation);
        setVal('alumniEmployer', last.employer_name);
        setVal('alumniSalary', last.monthly_salary);
        setVal('alumniCampaignName', last.campaign_name);
        setVal('alumniCampaignDate', last.campaign_date);
        setVal('alumniExposure', last.exposure_visit);
        setVal('alumniMeet', last.alumni_meet);
      }
      // Render Previous Tracking Entries from the same fetch.
      var tbody = document.getElementById('trackingHistoryBody');
      if (tbody) {
        if (!list.length) {
          tbody.innerHTML = '<tr><td colspan="5" style="text-align:center;color:#999;">No previous entries.</td></tr>';
        } else {
          var html = '';
          list.forEach(function(e, i) {
            html += '<tr><td>' + (i + 1) + '</td><td>' + escHtml(e.month || '') + '</td>' +
              '<td>' + escHtml(e.level_of_engagement || '—') + '</td>' +
              '<td>' + (e.created_at ? formatDateNice(e.created_at) : '—') + '</td>' +
              '<td style="text-align:center;"><button class="btn-icon" title="View" onclick="viewAlumniTrackingEntry(' + e.id + ')"><i class="fas fa-eye"></i></button></td></tr>';
          });
          tbody.innerHTML = html;
        }
      }
    }).catch(function() {
      // Network / API failure — fall back to the original simple history loader.
      _loadAlumniTrackingHistory(alumniId, 'trackingHistoryBody');
    });
  }, 100);
}

function _loadAlumniTrackingHistory(alumniId, tbodyId) {
  apiAkAlumniTracking(alumniId).then(function(entries) {
    var list = Array.isArray(entries) ? entries : (entries.data || []);
    var tbody = document.getElementById(tbodyId);
    if (!tbody) return;
    if (!list.length) { tbody.innerHTML = '<tr><td colspan="5" style="text-align:center;color:#999;">No previous entries.</td></tr>'; return; }
    var html = '';
    list.forEach(function(e, i) {
      html += '<tr><td>' + (i + 1) + '</td><td>' + escHtml(e.month || '') + '</td>' +
        '<td>' + escHtml(e.level_of_engagement || '—') + '</td>' +
        '<td>' + (e.created_at ? formatDateNice(e.created_at) : '—') + '</td>' +
        '<td style="text-align:center;"><button class="btn-icon" title="View" onclick="viewAlumniTrackingEntry(' + e.id + ')"><i class="fas fa-eye"></i></button></td></tr>';
    });
    tbody.innerHTML = html;
  });
}

// ---- AK Alumni Tracking: Month + auto Quarter ----
function _akQuarterFromMonth(monthInputVal) {
  // monthInputVal is "YYYY-MM" from <input type="month">
  if (!monthInputVal || monthInputVal.length < 7) return '';
  var parts = monthInputVal.split('-');
  var y = parts[0]; var m = parseInt(parts[1], 10);
  if (!m || m < 1 || m > 12) return '';
  var q = Math.floor((m - 1) / 3) + 1;   // calendar quarter: Jan-Mar=Q1...
  return 'Q' + q + ' ' + y;
}
function _akMonthLabel(monthInputVal) {
  if (!monthInputVal || monthInputVal.length < 7) return '';
  var parts = monthInputVal.split('-');
  var names = ['Jan','Feb','Mar','Apr','May','Jun','Jul','Aug','Sep','Oct','Nov','Dec'];
  var m = parseInt(parts[1], 10);
  if (!m || m < 1 || m > 12) return '';
  return names[m - 1] + ' ' + parts[0];
}
function onAkTrackMonthChange() {
  var mi = document.getElementById('trackMonthInput');
  var qOut = document.getElementById('trackQuarter');
  if (!qOut) return;
  qOut.value = mi ? _akQuarterFromMonth(mi.value) : '';
}

function saveAlumniTracking() {
  var monthInputVal = (document.getElementById('trackMonthInput') || {}).value || '';
  if (!monthInputVal) { alert('Please select a Month.'); return; }
  var monthLabel = _akMonthLabel(monthInputVal);
  var quarter = _akQuarterFromMonth(monthInputVal);
  // Combined into existing `month` column so backend / history table / view page keep working.
  var month = monthLabel + (quarter ? ' (' + quarter + ')' : '');
  var data = {
    month: month,
    level_of_engagement: (document.getElementById('trackEngagement') || {}).value || null,
    initiative_admission: (document.getElementById('trackQ7') || {}).value || null,
    initiative_admission_details: (document.getElementById('trackQ8') || {}).value || null,
    supported_leaders: (document.getElementById('trackQ9') || {}).value || null,
    supported_leaders_details: (document.getElementById('trackQ10') || {}).value || null,
    negotiated_marriage: (document.getElementById('trackQ11') || {}).value || null,
    negotiated_marriage_details: (document.getElementById('trackQ12') || {}).value || null,
    spoke_against_violence: (document.getElementById('trackQ13') || {}).value || null,
    spoke_against_violence_details: (document.getElementById('trackQ14') || {}).value || null,
    social_action: (document.getElementById('trackQ15') || {}).value || null,
    social_action_details: (document.getElementById('trackQ16') || {}).value || null,
    completed_higher_education: (document.getElementById('trackQ17') || {}).value || null,
    completed_higher_education_details: (document.getElementById('trackQ18') || {}).value || null,
    started_job: (document.getElementById('trackQ19') || {}).value || null,
    started_job_details: (document.getElementById('trackQ20') || {}).value || null,
    moved_other_cities: (document.getElementById('trackQ21') || {}).value || null,
    moved_other_cities_details: (document.getElementById('trackQ22') || {}).value || null,
    travel_alone: (document.getElementById('trackQ23') || {}).value || null,
    travel_alone_details: (document.getElementById('trackQ24') || {}).value || null,
    goals: (document.getElementById('trackQ25') || {}).value || null,
    // 2026-06-02: Educational Engagement / Work Engagement / Campaign &
    // Activity snapshot, taken at the time this tracking entry is saved.
    educational_status: (document.getElementById('alumniEduStatus') || {}).value || null,
    are_you_studying: (document.getElementById('alumniStudying') || {}).value || null,
    studying_what: (document.getElementById('alumniStudyingWhat') || {}).value || null,
    current_institution: (document.getElementById('alumniInstitution') || {}).value || null,
    are_you_working: (document.getElementById('alumniWorking') || {}).value || null,
    type_of_work: (document.getElementById('alumniWorkType') || {}).value || null,
    designation: (document.getElementById('alumniDesignation') || {}).value || null,
    employer_name: (document.getElementById('alumniEmployer') || {}).value || null,
    monthly_salary: parseFloat((document.getElementById('alumniSalary') || {}).value) || null,
    campaign_name: (document.getElementById('alumniCampaignName') || {}).value || null,
    campaign_date: (document.getElementById('alumniCampaignDate') || {}).value || null,
    exposure_visit: (document.getElementById('alumniExposure') || {}).value || null,
    alumni_meet: (document.getElementById('alumniMeet') || {}).value || null
  };
  apiAddAkAlumniTracking(trackingAlumniId, data).then(function() {
    alert('Transformation tracking saved!');
    _loadAlumniTrackingHistory(trackingAlumniId, 'trackingHistoryBody');
    // Clear form
    var _mi = document.getElementById('trackMonthInput'); if (_mi) _mi.value = '';
    var _qo = document.getElementById('trackQuarter'); if (_qo) _qo.value = '';
    ['trackEngagement','trackQ7','trackQ9','trackQ11','trackQ13','trackQ15','trackQ17','trackQ19','trackQ21','trackQ23'].forEach(function(id) {
      var el = document.getElementById(id); if (el) el.selectedIndex = 0;
    });
    ['trackQ8','trackQ10','trackQ12','trackQ14','trackQ16','trackQ18','trackQ20','trackQ22','trackQ24','trackQ25'].forEach(function(id) {
      var el = document.getElementById(id); if (el) el.value = '';
    });
    ['trackQ8Grp','trackQ10Grp','trackQ12Grp','trackQ14Grp','trackQ16Grp','trackQ18Grp','trackQ20Grp','trackQ22Grp','trackQ24Grp'].forEach(function(id) {
      var el = document.getElementById(id); if (el) el.style.display = 'none';
    });
  }).catch(function(e) { showUserError('processing your request', e); });
}

// ---- VIEW SINGLE TRACKING ENTRY ----
function viewAlumniTrackingEntry(trackingId) {
  viewingTrackingId = trackingId;
  navigateTo('viewAlumniTracking');
  // Fetch the specific entry via the alumni's tracking list
  // We need to find which alumni this belongs to - use a direct XHR
  var xhr = new XMLHttpRequest();
  xhr.open('GET', window.location.origin + '/api/ak-alumni/' + trackingAlumniId + '/tracking', true);
  xhr.onload = function() {
    if (xhr.status === 200) {
      var entries = JSON.parse(xhr.responseText);
      var list = Array.isArray(entries) ? entries : (entries.data || []);
      var entry = null;
      for (var i = 0; i < list.length; i++) { if (list[i].id === trackingId) { entry = list[i]; break; } }
      if (!entry) { document.getElementById('viewTrackingGrid').innerHTML = '<p style="color:red;">Entry not found.</p>'; return; }
      var nameEl = document.getElementById('viewTrackingAlumniName');
      if (nameEl) nameEl.textContent = trackingAlumniName || '';
      function _d(l, v) { return '<div class="detail-item"><label>' + l + '</label><span>' + escHtml(v || '—') + '</span></div>'; }
      var grid = document.getElementById('viewTrackingGrid');
      if (grid) {
        // 2026-06-02: Education / Work / Campaign snapshots are now part
        // of each Transformation Tracking entry, so the view page shows
        // them as their own grouped sections above the Yes/No questions.
        var eduBlock = '<div style="grid-column:1/-1;margin-top:8px;font-weight:600;color:#e67e22;">Educational Engagement</div>' +
          _d('Educational Status', entry.educational_status) +
          _d('Are You Studying?', entry.are_you_studying) +
          (entry.are_you_studying === 'Yes' ? _d('Studying What', entry.studying_what) + _d('Current Institution', entry.current_institution) : '');
        var workBlock = '<div style="grid-column:1/-1;margin-top:8px;font-weight:600;color:#e67e22;">Work Engagement</div>' +
          _d('Are You Working?', entry.are_you_working) +
          (entry.are_you_working === 'Yes'
            ? _d('Type of Work', entry.type_of_work) + _d('Designation', entry.designation) + _d('Employer', entry.employer_name) + _d('Monthly Salary', entry.monthly_salary)
            : '');
        var campBlock = '<div style="grid-column:1/-1;margin-top:8px;font-weight:600;color:#e67e22;">Campaign &amp; Activity</div>' +
          _d('Campaign Name', entry.campaign_name) +
          _d('Campaign Date', entry.campaign_date ? formatDateNice(entry.campaign_date) : null) +
          _d('Exposure Visit', entry.exposure_visit) +
          _d('Alumni Meet', entry.alumni_meet);
        grid.innerHTML = _d('Month', entry.month) + _d('Level of Engagement', entry.level_of_engagement) +
          eduBlock + workBlock + campBlock +
          '<div style="grid-column:1/-1;margin-top:8px;font-weight:600;color:#e67e22;">Transformation Indicators</div>' +
          _d('1. Initiative in admission of girls', entry.initiative_admission) + (entry.initiative_admission === 'Yes' ? _d('Details', entry.initiative_admission_details) : '') +
          _d('2. Supported other leaders', entry.supported_leaders) + (entry.supported_leaders === 'Yes' ? _d('Details', entry.supported_leaders_details) : '') +
          _d('3. Negotiated own marriage', entry.negotiated_marriage) + (entry.negotiated_marriage === 'Yes' ? _d('Details', entry.negotiated_marriage_details) : '') +
          _d('4. Spoke against Violence at home', entry.spoke_against_violence) + (entry.spoke_against_violence === 'Yes' ? _d('Details', entry.spoke_against_violence_details) : '') +
          _d('5. Took up social action', entry.social_action) + (entry.social_action === 'Yes' ? _d('Details', entry.social_action_details) : '') +
          _d('6. Completed higher education', entry.completed_higher_education) + (entry.completed_higher_education === 'Yes' ? _d('Details', entry.completed_higher_education_details) : '') +
          _d('7. Started job and sustained', entry.started_job) + (entry.started_job === 'Yes' ? _d('Details', entry.started_job_details) : '') +
          _d('8. Able to move other cities', entry.moved_other_cities) + (entry.moved_other_cities === 'Yes' ? _d('Details', entry.moved_other_cities_details) : '') +
          _d('9. Able to travel alone in evenings', entry.travel_alone) + (entry.travel_alone === 'Yes' ? _d('Details', entry.travel_alone_details) : '') +
          _d('10. Goals/Plans', entry.goals);
      }
    }
  };
  xhr.send();
}

function exportAlumniTracking() {
  if (!trackingAlumniId) { alert('No alumni selected.'); return; }
  window.open(window.location.origin + '/api/ak-alumni/' + trackingAlumniId + '/tracking/export', '_blank');
}

function goBackFromTrackingView() {
  if (trackingAlumniId) {
    openAlumniTrackingModal(trackingAlumniId, trackingAlumniName);
  } else {
    navigateTo('akAlumni');
  }
}

// ============================================================================
// COMMUNITY ACTION — BEFORE / AFTER IMAGE UPLOADS
// ============================================================================
// Client-side persistence (localStorage) so uploads survive navigation.
//
// Key (v2): azadCaImg2:<flp>:<centre>:<month>:<metric>:<rowIdx>:<before|after>
// Value:    JSON array of { id, name, date, data (base64 dataURI) }
//
// History — the original (v1) key was `azadCaImg:<centre>:<month>:...`
// but the FLP Reporting page has no centre-filter element so `<centre>`
// was hard-coded to the literal string `unknown`. That meant every FLP
// reporting in the same month shared the same key, so FLP-B saw FLP-A's
// uploaded Community Action photos. v2 includes the FLP id so images
// are uniquely bound to (FLP, month, metric, row, kind). The IIFE at
// the bottom of this section deletes any leftover v1 keys so they
// can't leak through.

var _caCurrent = { metricKey: null, rowIdx: -1 };

function _caReportCtx() {
  // FLP Reporting page is per-FLP per-month. The FLP id is the true
  // primary scope; centre is captured opportunistically for cross-page
  // dedupe but defaults to '' when no centre filter exists on the page.
  var flp    = (document.getElementById('reportFilterFlp')    || {}).value || 'unknown';
  var month  = (document.getElementById('reportFilterMonth')  || document.getElementById('targetFilterMonth')  || {}).value || 'unknown';
  var centre = (document.getElementById('reportFilterCentre') || document.getElementById('targetFilterCentre') || {}).value || '';
  return { flp: flp, centre: centre, month: month };
}

function _caPerfCtx() {
  // Centre Performance page filters by centre + month + (optional) FLP.
  // Match the same key shape as the report context so images uploaded
  // through Reporting line up here. perfFilterFlp may not exist on
  // every variant of the page; default to '' so the centre-level scope
  // still matches when no specific FLP is selected.
  var flp    = (document.getElementById('perfFilterFlp')    || {}).value || '';
  var month  = (document.getElementById('perfFilterMonth')  || {}).value || 'unknown';
  var centre = (document.getElementById('perfFilterCentre') || {}).value || '';
  return { flp: flp, centre: centre, month: month };
}

function _caStoreKey(ctx, metricKey, rowIdx, kind) {
  // v2 prefix — see history block above. FLP id is the lead scope.
  return 'azadCaImg2:' + (ctx.flp || '') + ':' + (ctx.centre || '') + ':' + ctx.month + ':' + metricKey + ':' + rowIdx + ':' + kind;
}

// One-time purge of v1 keys. Runs on script load. v1 keys never had a
// reliable FLP scope so reads from them caused the bug; deleting them
// also frees up localStorage quota (each image is base64-encoded so the
// old generic keys can be quite large).
(function _caPurgeLegacyV1() {
  try {
    for (var i = localStorage.length - 1; i >= 0; i--) {
      var k = localStorage.key(i);
      // Match 'azadCaImg:' but NOT 'azadCaImg2:' (v2 stays).
      if (k && k.indexOf('azadCaImg:') === 0) localStorage.removeItem(k);
    }
  } catch (e) {}
})();

function _caLoad(ctx, metricKey, rowIdx, kind) {
  try {
    var raw = localStorage.getItem(_caStoreKey(ctx, metricKey, rowIdx, kind));
    return raw ? JSON.parse(raw) : [];
  } catch (e) { return []; }
}

function _caSave(ctx, metricKey, rowIdx, kind, list) {
  try {
    localStorage.setItem(_caStoreKey(ctx, metricKey, rowIdx, kind), JSON.stringify(list));
  } catch (e) {
    alert('Unable to save image — browser storage quota may be full. Try smaller images.');
  }
}

function _caRowImageCounts(metricKey, rowIdx) {
  var ctx = _caReportCtx();
  return {
    before: _caLoad(ctx, metricKey, rowIdx, 'before').length,
    after:  _caLoad(ctx, metricKey, rowIdx, 'after').length
  };
}

function _caRowImageCountsFromRow(metricKey, row, rowIdx) {
  var ctx = _caPerfCtx();
  return {
    before: _caLoad(ctx, metricKey, rowIdx, 'before').length,
    after:  _caLoad(ctx, metricKey, rowIdx, 'after').length
  };
}

// ---- Upload modal (Reporting / edit) ----
function openCaUploadImagesModal(metricKey, rowIdx) {
  _caCurrent = { metricKey: metricKey, rowIdx: rowIdx, context: 'report' };
  _caRenderUploadTables();
  var m = document.getElementById('caUploadImagesModal');
  if (m) m.style.display = 'flex';
}

function closeCaUploadImagesModal() {
  var m = document.getElementById('caUploadImagesModal');
  if (m) m.style.display = 'none';
  // Refresh the CA row badge counts by re-rendering the metric rows
  var mk = _caCurrent.metricKey;
  _caCurrent = { metricKey: null, rowIdx: -1 };
  if (mk) {
    try { _renderDynamicRows(mk, false); } catch (e) {}
  }
}

function _caRenderUploadTables() {
  var ctx = _caReportCtx();
  ['before','after'].forEach(function(kind) {
    var tableId = kind === 'before' ? 'caBeforeTable' : 'caAfterTable';
    var tbody = document.querySelector('#' + tableId + ' tbody');
    if (!tbody) return;
    var list = _caLoad(ctx, _caCurrent.metricKey, _caCurrent.rowIdx, kind);
    if (!list.length) {
      tbody.innerHTML = '<tr><td colspan="4" style="text-align:center;color:#999;padding:20px;font-size:13px;">No images uploaded yet.</td></tr>';
      return;
    }
    var html = '';
    list.forEach(function(img, i) {
      html += '<tr>' +
        '<td>' + (i + 1) + '</td>' +
        '<td>' + escHtml(img.name) + '</td>' +
        '<td>' + escHtml(img.date) + '</td>' +
        '<td>' +
          '<button class="btn-icon" title="View" onclick="_caPreviewImage(\'' + img.id + '\',\'' + kind + '\')"><i class="fas fa-eye"></i></button> ' +
          '<button class="btn-icon text-danger" title="Delete" onclick="_caDeleteImage(\'' + img.id + '\',\'' + kind + '\')"><i class="fas fa-trash-alt"></i></button>' +
        '</td>' +
        '</tr>';
    });
    tbody.innerHTML = html;
  });
}

function _caTriggerUpload(kind) {
  var input = document.getElementById('caUploadImageInput');
  if (!input) return;
  input.setAttribute('data-kind', kind);
  input.value = '';
  input.click();
}

function _caHandleImageInput(input) {
  var files = Array.from(input.files || []);
  if (!files.length) return;
  var kind = input.getAttribute('data-kind') || 'before';
  if (_caCurrent.metricKey == null) return;
  var ctx = _caReportCtx();
  var list = _caLoad(ctx, _caCurrent.metricKey, _caCurrent.rowIdx, kind);

  var MAX_BYTES = 800 * 1024; // 800 KB per image cap for localStorage safety
  var remaining = files.length;

  files.forEach(function(file) {
    if (!file.type || !file.type.startsWith('image/')) {
      remaining--;
      if (remaining === 0) _caFinalizeUpload(ctx, kind, list);
      return;
    }
    if (file.size > MAX_BYTES) {
      alert('Image "' + file.name + '" is larger than 800 KB. Please use a smaller file.');
      remaining--;
      if (remaining === 0) _caFinalizeUpload(ctx, kind, list);
      return;
    }
    var reader = new FileReader();
    reader.onload = function(e) {
      list.push({
        id: 'img_' + Date.now() + '_' + Math.floor(Math.random() * 1e6),
        name: file.name,
        date: new Date().toISOString().slice(0, 10),
        data: e.target.result
      });
      remaining--;
      if (remaining === 0) _caFinalizeUpload(ctx, kind, list);
    };
    reader.onerror = function() {
      remaining--;
      if (remaining === 0) _caFinalizeUpload(ctx, kind, list);
    };
    reader.readAsDataURL(file);
  });
}

function _caFinalizeUpload(ctx, kind, list) {
  _caSave(ctx, _caCurrent.metricKey, _caCurrent.rowIdx, kind, list);
  _caRenderUploadTables();
}

function _caDeleteImage(imgId, kind) {
  if (!confirm('Delete this image?')) return;
  var ctx = _caReportCtx();
  var list = _caLoad(ctx, _caCurrent.metricKey, _caCurrent.rowIdx, kind);
  list = list.filter(function(x) { return x.id !== imgId; });
  _caSave(ctx, _caCurrent.metricKey, _caCurrent.rowIdx, kind, list);
  _caRenderUploadTables();
}

function _caPreviewImage(imgId, kind) {
  var ctx = _caCurrent.context === 'perf' ? _caPerfCtx() : _caReportCtx();
  var list = _caLoad(ctx, _caCurrent.metricKey, _caCurrent.rowIdx, kind);
  var img = list.find(function(x) { return x.id === imgId; });
  if (!img) return;
  document.getElementById('caImagePreviewTitle').innerHTML = '<i class="fas fa-image"></i> ' + escHtml(img.name);
  document.getElementById('caImagePreviewImg').src = img.data;
  var m = document.getElementById('caImagePreviewModal');
  if (m) m.style.display = 'flex';
}

function closeCaImagePreview() {
  var m = document.getElementById('caImagePreviewModal');
  if (m) m.style.display = 'none';
}

// ---- View modal (Centre Performance / read-only) ----
function openCaViewImagesModal(metricKey, rowIdx) {
  _caCurrent = { metricKey: metricKey, rowIdx: rowIdx, context: 'perf' };
  var ctx = _caPerfCtx();
  var before = _caLoad(ctx, metricKey, rowIdx, 'before').map(function(x) { x._kind = 'Before'; return x; });
  var after  = _caLoad(ctx, metricKey, rowIdx, 'after').map(function(x)  { x._kind = 'After';  return x; });
  var all = before.concat(after);
  var tbody = document.querySelector('#caViewImagesTable tbody');
  if (tbody) {
    if (!all.length) {
      tbody.innerHTML = '<tr><td colspan="5" style="text-align:center;color:#999;padding:20px;font-size:13px;">No images available.</td></tr>';
    } else {
      var html = '';
      all.forEach(function(img, i) {
        var kindL = img._kind.toLowerCase();
        html += '<tr>' +
          '<td>' + (i + 1) + '</td>' +
          '<td>' + escHtml(img.name) + '</td>' +
          '<td>' + escHtml(img._kind) + '</td>' +
          '<td>' + escHtml(img.date) + '</td>' +
          '<td>' +
            '<button class="btn-icon" title="Preview" onclick="_caPreviewImage(\'' + img.id + '\',\'' + kindL + '\')"><i class="fas fa-eye"></i></button> ' +
            '<button class="btn-icon" title="Download" onclick="_caDownloadImage(\'' + img.id + '\',\'' + kindL + '\')" style="color:#27ae60;"><i class="fas fa-download"></i></button>' +
          '</td>' +
          '</tr>';
      });
      tbody.innerHTML = html;
    }
  }
  var m = document.getElementById('caViewImagesModal');
  if (m) m.style.display = 'flex';
}

function closeCaViewImagesModal() {
  var m = document.getElementById('caViewImagesModal');
  if (m) m.style.display = 'none';
}

function _caDownloadImage(imgId, kind) {
  var ctx = _caPerfCtx();
  var list = _caLoad(ctx, _caCurrent.metricKey, _caCurrent.rowIdx, kind);
  var img = list.find(function(x) { return x.id === imgId; });
  if (!img) return;
  var a = document.createElement('a');
  a.href = img.data;
  a.download = img.name || ('image_' + imgId + '.png');
  document.body.appendChild(a); a.click(); document.body.removeChild(a);
}

// ============================================================================
// DASHBOARD — EXPORT ALL MODULES
// ============================================================================
// Single multi-sheet .xlsx export respecting the Dashboard's filters AND
// the current user's role scope. The role scope is PINNED — even if a
// State Lead / DL / PI clears their state dropdown, the export stays scoped
// to their geography. Admin / Super Admin have no role floor.
function exportAllModules() {
  // Wait for any pending DL/PI scope resolution + State Lead state-code
  // resolution before firing the request, otherwise a freshly-logged-in
  // user could miss their state/district/centre filter.
  _whenDlPiReady(function() {
    _ensureStateLeadStateCodeReady(function() {
      _doExportAllModules();
    });
  });
}

function _ensureStateLeadStateCodeReady(cb) {
  if (!currentUser || currentUser.role !== 'state_lead' ||
      currentUser.state_code || !currentUser.scope ||
      typeof apiGeoDropdownStates !== 'function') {
    cb(); return;
  }
  apiGeoDropdownStates().then(function(states) {
    var scopeLower = String(currentUser.scope || '')
      .toLowerCase().replace(/ centre$/, '').trim();
    var match = (states || []).find(function(s) {
      return s.state_name && s.state_name.toLowerCase().indexOf(scopeLower) >= 0;
    });
    if (match && match.state_code) {
      currentUser.state_code = match.state_code;
      try { localStorage.setItem('azadUserData', JSON.stringify(currentUser)); } catch (e) {}
    }
    cb();
  }).catch(function() { cb(); });
}

function _doExportAllModules() {
  var stateEl    = document.getElementById('dashFilterState');
  var districtEl = document.getElementById('dashFilterDistrict');
  var dateFrom   = document.getElementById('dashFilterDateFrom');
  var dateTo     = document.getElementById('dashFilterDateTo');

  var role = (currentUser && currentUser.role) || '';
  var roleStateCode    = (currentUser && currentUser.state_code) || '';
  var roleDistrictCode = (currentUser && currentUser.district_code) || '';
  var roleCentreCode   = (currentUser && currentUser.centre_code) || '';

  // Decide effective scope. The role floor overrides any wider value the
  // user might have selected in the filter dropdowns.
  var stateCode = (stateEl && stateEl.value) || '';
  var districtCode = (districtEl && districtEl.value) || '';
  var centreCode = '';

  if (role === 'state_lead') {
    if (roleStateCode) stateCode = roleStateCode;            // pin to their state
  } else if (role === 'district_lead') {
    if (roleStateCode) stateCode = roleStateCode;
    if (roleDistrictCode) districtCode = roleDistrictCode;   // pin to their district
  } else if (role === 'pi') {
    if (roleStateCode) stateCode = roleStateCode;
    if (roleDistrictCode) districtCode = roleDistrictCode;
    if (roleCentreCode) centreCode = roleCentreCode;         // pin to their centre
  }
  // Admin / Super Admin / Power User: free-form, use whatever the user
  // selected in the dropdowns (may be unfiltered = all states).

  var qs = [];
  if (stateCode)    qs.push('state_code=' + encodeURIComponent(stateCode));
  if (districtCode) qs.push('district_code=' + encodeURIComponent(districtCode));
  if (centreCode)   qs.push('centre_code=' + encodeURIComponent(centreCode));
  if (dateFrom && dateFrom.value) qs.push('date_from=' + dateFrom.value);
  if (dateTo   && dateTo.value)   qs.push('date_to=' + dateTo.value);

  var url = API_BASE + '/export/all' + (qs.length ? '?' + qs.join('&') : '');
  window.location.href = url;
}

// ============================================================================
// MEETING (Peer Group Feminist Engagement) MODULE
// ============================================================================
// Meetings are now shared across all users via the server-side store
// (/api/meetings-store). Starts empty — populated entirely by real user adds
// so any meeting created by a PI is immediately visible to DL / SL / Admin /
// Super Admin (subject to each role's geo scope).
var DEMO_MEETINGS = [];

var meetingCurrentPage = 1;
var meetingPageLimit = 10;
var editingMeetingId = null;
var viewingMeetingId = null;
var _meetingPageInitialized = false;
// Bridge from edit-mode init to the later state-cascade reload so a preselect
// batch name survives the async re-scoping of the Batch dropdown.
var _pendingMeetingBatchPreselect = null;

// ---- Meeting persistence (server-side JSON store + localStorage fallback) ----
// DEMO_MEETINGS is the initial seed. Every add/edit/delete syncs the full list
// to the backend via PUT /api/meetings-store so all roles and devices see the
// same data. localStorage is kept as a write-through cache / offline fallback.
// Bumped to v2 (2026-04-28) after a live cleanup wiped the server-side
// meetings store: every existing browser had a stale 'azadMeetings' cache
// that the safety-belt push-on-empty code in _syncMeetingsFromServer() kept
// re-uploading, repopulating the cleared file. Renaming the key forces a
// fresh empty cache on next load so the cleanup actually sticks. Old
// 'azadMeetings' entries linger harmlessly in users' localStorage until
// their browser evicts them.
var _MEETINGS_STORAGE_KEY = 'azadMeetings_v2';
var _MEETINGS_SERVER_LOADED = false;

function _saveMeetingsToStorage() {
  // Local cache first so UI is snappy
  try { localStorage.setItem(_MEETINGS_STORAGE_KEY, JSON.stringify(DEMO_MEETINGS)); } catch (e) {}
  // Then sync to server (fire-and-forget; errors don't block UI)
  if (typeof API_BASE !== 'undefined') {
    try {
      fetch(API_BASE + '/meetings-store', {
        method: 'PUT',
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify(DEMO_MEETINGS)
      }).catch(function() {});
    } catch (e) {}
  }
}

function _loadMeetingsFromStorage() {
  // Synchronous path — read localStorage for an instant first paint
  try {
    var raw = localStorage.getItem(_MEETINGS_STORAGE_KEY);
    if (raw) {
      var saved = JSON.parse(raw);
      if (Array.isArray(saved) && saved.length) {
        DEMO_MEETINGS.length = 0;
        saved.forEach(function(r) { DEMO_MEETINGS.push(r); });
      }
    }
  } catch (e) {}
}

// Async: fetch the shared list from the server and merge it in, then re-render
// the Meeting List if it's currently visible. Runs once per page load.
function _syncMeetingsFromServer() {
  if (_MEETINGS_SERVER_LOADED) return;
  _MEETINGS_SERVER_LOADED = true;
  if (typeof API_BASE === 'undefined') return;
  try {
    fetch(API_BASE + '/meetings-store', { method: 'GET' })
      .then(function(r) { return r.ok ? r.json() : null; })
      .then(function(payload) {
        if (!payload) return;
        var list = (payload && payload.data) || [];
        if (!Array.isArray(list)) return;
        // CRITICAL: never wipe local data when the server returns an empty
        // list — that could happen if the server was reset or a PUT was lost.
        // If we have local meetings but server is empty, push ours up so the
        // data isn't lost on the next refresh.
        if (list.length === 0) {
          if (DEMO_MEETINGS.length > 0) {
            _saveMeetingsToStorage();
          }
          return;
        }
        // Merge: server wins for matching ids, but any unsynced local entries
        // that aren't on the server yet are preserved (keeps user's latest
        // adds visible even if the PUT hasn't finished round-tripping).
        var byId = {};
        list.forEach(function(r) { if (r && r.id != null) byId[r.id] = r; });
        var merged = list.slice();
        var pendingPush = false;
        DEMO_MEETINGS.forEach(function(local) {
          if (local && local.id != null && !byId[local.id]) {
            merged.unshift(local);
            pendingPush = true;
          }
        });
        DEMO_MEETINGS.length = 0;
        merged.forEach(function(r) { DEMO_MEETINGS.push(r); });
        try { localStorage.setItem(_MEETINGS_STORAGE_KEY, JSON.stringify(DEMO_MEETINGS)); } catch (e) {}
        // Push back any local-only entries that weren't on the server
        if (pendingPush) _saveMeetingsToStorage();
        if (typeof loadMeetingListData === 'function' &&
            document.getElementById('page-meetingList') &&
            document.getElementById('page-meetingList').classList.contains('active')) {
          loadMeetingListData(meetingCurrentPage);
        }
      })
      .catch(function() {});
  } catch (e) {}
}

// Rehydrate from storage as soon as this script loads — before any list render.
_loadMeetingsFromStorage();
// Kick off the server sync (async — non-blocking)
setTimeout(_syncMeetingsFromServer, 0);

function initMeetingPage(preserveFilters) {
  var role = (currentUser && currentUser.role) || '';
  var distGrp = document.getElementById('meetingFilterDistrictGrp');
  if (distGrp) distGrp.style.display = (role === 'pi' || role === 'district_lead') ? 'none' : '';
  populateMeetingFilterDropdowns();
  if (preserveFilters) {
    // Returning from a detail page — restore saved filter values + the saved
    // pagination page, then reload directly (do NOT route through
    // applyMeetingFilters — it resets meetingCurrentPage to 1).
    setTimeout(function() {
      _restoreListFilters('meetingList');
      var p = _savedListPage('meetingList') || meetingCurrentPage || 1;
      loadMeetingListData(p);
    }, 400);
  } else {
    resetMeetingFilters();
  }
  // Always refresh from the shared server store on each visit so other roles'
  // recent additions are immediately visible.
  _MEETINGS_SERVER_LOADED = false;
  _syncMeetingsFromServer();
}

function populateMeetingFilterDropdowns() {
  // Year picker (input[type=number]): no max cap — future years allowed
  var yEl = document.getElementById('meetingFilterYear');
  if (yEl && yEl.tagName === 'INPUT') {
    yEl.removeAttribute('max');
  } else if (yEl && yEl.tagName === 'SELECT' && yEl.options.length <= 1) {
    var cy = new Date().getFullYear();
    for (var y = cy + 5; y >= cy - 10; y--) {
      var o = document.createElement('option'); o.value = String(y); o.textContent = String(y); yEl.appendChild(o);
    }
  }
  // District dropdown — role-restricted, cascades to Centre
  _populateMeetingDistrictFilter();
  // Centre dropdown — role-restricted
  _populateMeetingCentreFilter();
}

// Populate District filter for Meeting List, scoped by role. Each option carries
// a data-code attribute so the centre cascade can resolve without a reverse lookup.
function _populateMeetingDistrictFilter() {
  var distEl = document.getElementById('meetingFilterDistrict');
  if (!distEl) return;
  distEl.innerHTML = '<option value="">All Districts</option>';
  var role = (currentUser && currentUser.role) || '';
  var stateCode = (currentUser && currentUser.state_code) || '';
  var districtCode = (currentUser && currentUser.district_code) || '';

  // PI / District Lead: restrict to their own district, pre-selected
  if ((role === 'pi' || role === 'district_lead') && districtCode && typeof apiGeoDropdownDistricts === 'function') {
    apiGeoDropdownDistricts(stateCode).then(function(r) {
      var list = (r && (r.data || r)) || [];
      var match = list.find(function(d) { return d.district_code === districtCode; });
      if (match) {
        var o = document.createElement('option');
        o.value = match.district_name;
        o.textContent = match.district_name;
        o.setAttribute('data-code', match.district_code);
        o.selected = true;
        distEl.appendChild(o);
        distEl.disabled = true;
        // Auto-cascade centres to this district
        _cascadeMeetingCentresByDistrict(match.district_code);
      }
    }).catch(function() {});
    return;
  }
  distEl.disabled = false;
  // State Lead / Admin / Super Admin: show districts within their state
  // (or all). Both branches now hit the /dropdown endpoint so Inactive
  // districts are filtered out for web users (the previous CRUD-list
  // fallback `/geo/districts?limit=500` was leaking Inactive rows into
  // the Peer Engagement filter for Admin / Super Admin).
  var fetchFn = (typeof apiGeoDropdownDistricts === 'function' && stateCode)
    ? apiGeoDropdownDistricts(stateCode)
    : (typeof apiGet === 'function' ? apiGet('/geo/dropdown/districts') : Promise.resolve({ data: [] }));
  fetchFn.then(function(r) {
    var list = (r && (r.data || r)) || [];
    var seen = {};
    list.forEach(function(d) {
      var name = d.district_name;
      if (!name || seen[name]) return;
      seen[name] = true;
      var o = document.createElement('option');
      o.value = name;
      o.textContent = name;
      o.setAttribute('data-code', d.district_code || '');
      distEl.appendChild(o);
    });
  }).catch(function() {});
}

// When District filter changes, re-scope the Centre filter.
function _onMeetingFilterDistrictChange() {
  var distEl = document.getElementById('meetingFilterDistrict');
  if (!distEl) return;
  var opt = distEl.selectedOptions && distEl.selectedOptions[0];
  var districtCode = opt ? (opt.getAttribute('data-code') || '') : '';
  if (!districtCode) {
    // "All Districts" → fall back to role-scoped full centre list
    _populateMeetingCentreFilter();
    return;
  }
  _cascadeMeetingCentresByDistrict(districtCode);
}

function _cascadeMeetingCentresByDistrict(districtCode) {
  var centreEl = document.getElementById('meetingFilterCentre');
  if (!centreEl) return;
  var myToken = ++_meetingCentreFilterToken;  // invalidate any in-flight call
  centreEl.innerHTML = '<option value="">All Centres</option>';
  if (!districtCode || typeof apiGeoDropdownCentres !== 'function') return;
  apiGeoDropdownCentres(districtCode).then(function(r) {
    if (myToken !== _meetingCentreFilterToken) return;
    _appendUniqueCentreOptions(centreEl, (r && (r.data || r)) || []);
  }).catch(function() {});
}

// Sanitize year input to digits-only, up to 4 digits. Future years are allowed.
function _clampMeetingYear(el) {
  if (!el) return;
  if (el.value) el.value = String(el.value).replace(/[^0-9]/g, '').slice(0, 4);
}

// Show/hide a floating year-picker popup. The popup is moved to document.body
// so no ancestor clip (overflow/transform/filter) can hide it.
function _toggleMeetingYearPicker() {
  var popup = document.getElementById('meetingFilterYearPopup');
  var wrap = document.getElementById('meetingFilterYearWrap');
  if (!popup) return;
  if (popup.style.display === 'block') {
    popup.style.display = 'none';
    return;
  }
  _renderMeetingYearPicker();
  // Portal-mount to <body> if not already there
  if (popup.parentNode && popup.parentNode !== document.body) {
    document.body.appendChild(popup);
  }
  if (wrap) {
    var rect = wrap.getBoundingClientRect();
    var popupWidth = 220;
    var left = Math.max(8, rect.right - popupWidth);
    // If there's not enough room below the input, show above it instead
    var popupHeight = 260;
    var top = rect.bottom + 4;
    if (top + popupHeight > window.innerHeight - 8) {
      top = Math.max(8, rect.top - popupHeight - 4);
    }
    popup.style.position = 'fixed';
    popup.style.top = top + 'px';
    popup.style.left = left + 'px';
    popup.style.width = popupWidth + 'px';
    popup.style.maxHeight = popupHeight + 'px';
    popup.style.zIndex = '10000';
  }
  popup.style.display = 'block';
  setTimeout(function() {
    document.addEventListener('click', _meetingYearPickerOutsideClick, true);
    window.addEventListener('scroll', _meetingYearPickerReposition, true);
    window.addEventListener('resize', _meetingYearPickerReposition);
  }, 0);
}

// Keep the popup anchored to the input on scroll/resize.
function _meetingYearPickerReposition() {
  var popup = document.getElementById('meetingFilterYearPopup');
  var wrap = document.getElementById('meetingFilterYearWrap');
  if (!popup || !wrap || popup.style.display !== 'block') return;
  var rect = wrap.getBoundingClientRect();
  var popupWidth = parseFloat(popup.style.width) || 220;
  var popupHeight = parseFloat(popup.style.maxHeight) || 260;
  var top = rect.bottom + 4;
  if (top + popupHeight > window.innerHeight - 8) top = Math.max(8, rect.top - popupHeight - 4);
  popup.style.top = top + 'px';
  popup.style.left = Math.max(8, rect.right - popupWidth) + 'px';
}

function _meetingYearPickerOutsideClick(e) {
  var wrap = document.getElementById('meetingFilterYearWrap');
  var popup = document.getElementById('meetingFilterYearPopup');
  if (!wrap || !popup) return;
  // Clicks inside wrap (input/button) or inside the portal-mounted popup itself count as "inside"
  if (wrap.contains(e.target) || popup.contains(e.target)) return;
  popup.style.display = 'none';
  document.removeEventListener('click', _meetingYearPickerOutsideClick, true);
  window.removeEventListener('scroll', _meetingYearPickerReposition, true);
  window.removeEventListener('resize', _meetingYearPickerReposition);
}

function _renderMeetingYearPicker() {
  var popup = document.getElementById('meetingFilterYearPopup');
  if (!popup) return;
  var cy = new Date().getFullYear();
  var current = parseInt((document.getElementById('meetingFilterYear') || {}).value, 10);
  // Show 15 years back + 5 years ahead (future years allowed)
  var years = [];
  for (var y = cy + 5; y >= cy - 15; y--) years.push(y);
  var html = '<div style="display:grid;grid-template-columns:repeat(3,1fr);gap:4px;">';
  years.forEach(function(y) {
    var active = (y === current);
    var style = 'padding:6px 8px;border-radius:4px;text-align:center;font-size:13px;cursor:pointer;border:1px solid ' +
      (active ? '#732269' : 'transparent') + ';background:' + (active ? '#732269' : 'transparent') +
      ';color:' + (active ? '#fff' : '#333') + ';';
    html += '<div class="meeting-year-item" data-year="' + y + '" onclick="_pickMeetingYear(' + y + ')" onmouseover="if(!this.classList.contains(\'active\'))this.style.background=\'#faf3f8\'" onmouseout="if(!this.classList.contains(\'active\'))this.style.background=\'transparent\'" style="' + style + '">' + y + '</div>';
  });
  html += '</div>';
  popup.innerHTML = html;
}

function _pickMeetingYear(y) {
  var inp = document.getElementById('meetingFilterYear');
  if (inp) inp.value = String(y);
  var popup = document.getElementById('meetingFilterYearPopup');
  if (popup) popup.style.display = 'none';
  document.removeEventListener('click', _meetingYearPickerOutsideClick, true);
  window.removeEventListener('scroll', _meetingYearPickerReposition, true);
  window.removeEventListener('resize', _meetingYearPickerReposition);
  if (typeof applyMeetingFilters === 'function') applyMeetingFilters();
}

// ---- Add/Edit Meeting FORM year picker (mirrors the list filter picker) ----
function _clampMeetingFormYear(el) {
  if (!el) return;
  if (el.value) el.value = String(el.value).replace(/[^0-9]/g, '').slice(0, 4);
}

function _toggleMeetingFormYearPicker() {
  var popup = document.getElementById('meetingYearPopup');
  var wrap = document.getElementById('meetingYearWrap');
  if (!popup) return;
  if (popup.style.display === 'block') { popup.style.display = 'none'; return; }
  _renderMeetingFormYearPicker();
  if (popup.parentNode && popup.parentNode !== document.body) document.body.appendChild(popup);
  if (wrap) {
    var rect = wrap.getBoundingClientRect();
    var popupWidth = 220, popupHeight = 260;
    var left = Math.max(8, rect.right - popupWidth);
    var top = rect.bottom + 4;
    if (top + popupHeight > window.innerHeight - 8) top = Math.max(8, rect.top - popupHeight - 4);
    Object.assign(popup.style, {
      position: 'fixed', top: top + 'px', left: left + 'px',
      width: popupWidth + 'px', maxHeight: popupHeight + 'px',
      background: '#fff', border: '1px solid #ddd', borderRadius: '8px',
      boxShadow: '0 4px 12px rgba(0,0,0,0.12)', padding: '6px',
      overflowY: 'auto', zIndex: '10000'
    });
  }
  popup.style.display = 'block';
  setTimeout(function() {
    document.addEventListener('click', _meetingFormYearPickerOutsideClick, true);
    window.addEventListener('scroll', _meetingFormYearPickerReposition, true);
    window.addEventListener('resize', _meetingFormYearPickerReposition);
  }, 0);
}

function _meetingFormYearPickerReposition() {
  var popup = document.getElementById('meetingYearPopup');
  var wrap = document.getElementById('meetingYearWrap');
  if (!popup || !wrap || popup.style.display !== 'block') return;
  var rect = wrap.getBoundingClientRect();
  var popupWidth = parseFloat(popup.style.width) || 220;
  var popupHeight = parseFloat(popup.style.maxHeight) || 260;
  var top = rect.bottom + 4;
  if (top + popupHeight > window.innerHeight - 8) top = Math.max(8, rect.top - popupHeight - 4);
  popup.style.top = top + 'px';
  popup.style.left = Math.max(8, rect.right - popupWidth) + 'px';
}

function _meetingFormYearPickerOutsideClick(e) {
  var wrap = document.getElementById('meetingYearWrap');
  var popup = document.getElementById('meetingYearPopup');
  if (!wrap || !popup) return;
  if (wrap.contains(e.target) || popup.contains(e.target)) return;
  popup.style.display = 'none';
  document.removeEventListener('click', _meetingFormYearPickerOutsideClick, true);
  window.removeEventListener('scroll', _meetingFormYearPickerReposition, true);
  window.removeEventListener('resize', _meetingFormYearPickerReposition);
}

function _renderMeetingFormYearPicker() {
  var popup = document.getElementById('meetingYearPopup');
  if (!popup) return;
  var cy = new Date().getFullYear();
  var current = parseInt((document.getElementById('meetingYear') || {}).value, 10);
  var years = [];
  for (var y = cy + 5; y >= cy - 15; y--) years.push(y);
  var html = '<div style="display:grid;grid-template-columns:repeat(3,1fr);gap:4px;">';
  years.forEach(function(y) {
    var active = (y === current);
    var style = 'padding:6px 8px;border-radius:4px;text-align:center;font-size:13px;cursor:pointer;border:1px solid ' +
      (active ? '#732269' : 'transparent') + ';background:' + (active ? '#732269' : 'transparent') +
      ';color:' + (active ? '#fff' : '#333') + ';';
    html += '<div class="meeting-form-year-item" data-year="' + y + '" onclick="_pickMeetingFormYear(' + y + ')" onmouseover="if(this.getAttribute(\'data-active\')!==\'1\')this.style.background=\'#faf3f8\'" onmouseout="if(this.getAttribute(\'data-active\')!==\'1\')this.style.background=\'transparent\'" style="' + style + '">' + y + '</div>';
  });
  html += '</div>';
  popup.innerHTML = html;
}

function _pickMeetingFormYear(y) {
  var inp = document.getElementById('meetingYear');
  if (inp) inp.value = String(y);
  var popup = document.getElementById('meetingYearPopup');
  if (popup) popup.style.display = 'none';
  document.removeEventListener('click', _meetingFormYearPickerOutsideClick, true);
  window.removeEventListener('scroll', _meetingFormYearPickerReposition, true);
  window.removeEventListener('resize', _meetingFormYearPickerReposition);
}

// Dedupe + append centre options to a <select>
function _appendUniqueCentreOptions(selectEl, list) {
  var seen = {};
  (list || []).forEach(function(c) {
    var name = c.centre_name || c.name;
    if (!name || seen[name]) return;
    seen[name] = true;
    var o = document.createElement('option');
    o.value = name;
    o.textContent = name;
    selectEl.appendChild(o);
  });
}

// Load centres into the Meeting List centre filter, restricted by role/state.
var _meetingCentreFilterToken = 0;
function _populateMeetingCentreFilter() {
  var cEl = document.getElementById('meetingFilterCentre');
  if (!cEl) return;
  var myToken = ++_meetingCentreFilterToken;  // Invalidate any in-flight earlier call
  cEl.innerHTML = '<option value="">All Centres</option>';
  var role = (currentUser && currentUser.role) || '';
  var stateCode = (currentUser && currentUser.state_code) || '';
  var districtCode = (currentUser && currentUser.district_code) || '';

  // PI / District Lead: centres in their district only
  if ((role === 'pi' || role === 'district_lead') && districtCode && typeof apiGeoDropdownCentres === 'function') {
    apiGeoDropdownCentres(districtCode).then(function(r) {
      if (myToken !== _meetingCentreFilterToken) return;
      _appendUniqueCentreOptions(cEl, (r && (r.data || r)) || []);
    }).catch(function() {});
    return;
  }
  // State Lead: centres scoped to their state
  if (role === 'state_lead' && stateCode && typeof apiGeoDropdownCentresByState === 'function') {
    apiGeoDropdownCentresByState(stateCode).then(function(r) {
      if (myToken !== _meetingCentreFilterToken) return;
      _appendUniqueCentreOptions(cEl, r.data || r || []);
    }).catch(function() {});
    return;
  }
  // Super Admin / Admin: all centres. Use /dropdown/centres so the
  // JWT-aware Active filter applies (web admin sees Active only).
  if (typeof apiGet === 'function') {
    apiGet('/geo/dropdown/centres').then(function(r) {
      if (myToken !== _meetingCentreFilterToken) return;
      _appendUniqueCentreOptions(cEl, (r && (r.data || r)) || []);
    }).catch(function() {
      if (myToken !== _meetingCentreFilterToken) return;
      if (typeof DEMO_CENTRES !== 'undefined') _appendUniqueCentreOptions(cEl, DEMO_CENTRES);
    });
  }
}

function resetMeetingFilters() {
  _clearListFilters('meetingList');
  var ids = ['meetingFilterYear', 'meetingFilterMonth', 'meetingFilterDistrict', 'meetingFilterCentre', 'meetingFilterName'];
  ids.forEach(function(id) { var el = document.getElementById(id); if (el) el.value = ''; });
  // Repopulate centre to the full role-scoped list (district filter cleared)
  if (typeof _populateMeetingCentreFilter === 'function') _populateMeetingCentreFilter();
  meetingCurrentPage = 1;
  loadMeetingListData(1);
}

function applyMeetingFilters() {
  meetingCurrentPage = 1;
  loadMeetingListData(1);
}

// Cached mapping from user's state_code -> state_name (resolved from the
// /geo/states endpoint once per session). Used to scope the Meeting List
// to the user's assigned state for State Lead / DL / PI roles.
var _meetingUserStateName = null;
var _meetingUserStateResolving = false;
function _resolveMeetingUserStateName() {
  if (_meetingUserStateName != null || _meetingUserStateResolving) return;
  var sc = (currentUser && currentUser.state_code) || '';
  // Fallback: derive from `scope` / `geo_scope` / `state` (e.g. "Delhi") when
  // the user object doesn't carry a state_code.
  var scopeGuess = currentUser ? (currentUser.state || currentUser.geo_scope || currentUser.scope || '') : '';
  if (!sc && scopeGuess) {
    // scope may be "Delhi" or "Delhi (All Centres)" — take the first word group up to '('.
    var cleaned = String(scopeGuess).split('(')[0].trim();
    if (cleaned) _meetingUserStateName = cleaned;
    return;
  }
  if (!sc) return;
  _meetingUserStateResolving = true;
  if (typeof DEMO_STATES !== 'undefined') {
    var demo = DEMO_STATES.find(function(s) { return (s.short_code || '').toUpperCase() === sc.toUpperCase(); });
    if (demo) _meetingUserStateName = demo.name;
  }
  if (typeof apiGet === 'function') {
    apiGet('/geo/states').then(function(r) {
      var list = (r && (r.data || r)) || [];
      var match = list.find(function(s) { return s.state_code === sc; });
      if (match) _meetingUserStateName = match.state_name || match.name || _meetingUserStateName;
      _meetingUserStateResolving = false;
      if (typeof loadMeetingListData === 'function') loadMeetingListData(meetingCurrentPage);
    }).catch(function() { _meetingUserStateResolving = false; });
  }
}

function getFilteredMeetings() {
  var y = (document.getElementById('meetingFilterYear') || {}).value || '';
  var m = (document.getElementById('meetingFilterMonth') || {}).value || '';
  var d = (document.getElementById('meetingFilterDistrict') || {}).value || '';
  var c = (document.getElementById('meetingFilterCentre') || {}).value || '';
  var n = ((document.getElementById('meetingFilterName') || {}).value || '').trim().toLowerCase();

  // --- Role-based scoping ---
  var role = (currentUser && currentUser.role) || '';
  var restrictedRole = (role === 'state_lead' || role === 'pi' || role === 'district_lead');
  var scopedState = null;      // state_name filter
  var scopedDistrict = null;   // district_name filter (PI / DL)
  if (restrictedRole) {
    if (_meetingUserStateName == null) _resolveMeetingUserStateName();
    scopedState = _meetingUserStateName;
    // If we haven't resolved the user's state yet, show no rows rather than
    // leaking other states' meetings.
    if (!scopedState) return [];
    // PI / District Lead: also scope by district. Resolve their district_name
    // lazily via /geo/districts?district_code=... (cached on currentUser).
    if ((role === 'pi' || role === 'district_lead') && currentUser.district_code) {
      if (!currentUser._district_name && typeof apiGet === 'function') {
        if (!currentUser._district_name_resolving) {
          currentUser._district_name_resolving = true;
          apiGet('/geo/districts?district_code=' + encodeURIComponent(currentUser.district_code)).then(function(r) {
            var list = (r && (r.data || r)) || [];
            var m = list.find(function(d) { return d.district_code === currentUser.district_code; });
            if (m) currentUser._district_name = m.district_name;
            currentUser._district_name_resolving = false;
            if (typeof loadMeetingListData === 'function') loadMeetingListData(meetingCurrentPage);
          }).catch(function() { currentUser._district_name_resolving = false; });
        }
        return [];  // wait for resolution
      }
      scopedDistrict = currentUser._district_name;
    }
  }

  return DEMO_MEETINGS.filter(function(r) {
    if (scopedState && r.state !== scopedState) return false;
    if (scopedDistrict && (r.district || '') !== scopedDistrict) return false;
    if (y && String(r.year) !== y) return false;
    if (m && r.month !== m) return false;
    if (d && (r.district || '') !== d) return false;
    if (c && r.centre !== c) return false;
    if (n && r.flp_leader.toLowerCase().indexOf(n) === -1) return false;
    return true;
  });
}

function loadMeetingListData(page) {
  if (typeof page === 'number') meetingCurrentPage = page;
  var tbody = document.getElementById('meetingListTableBody');
  if (!tbody) return;
  var rows = getFilteredMeetings();
  var total = rows.length;
  var start = (meetingCurrentPage - 1) * meetingPageLimit;
  var pageRows = rows.slice(start, start + meetingPageLimit);
  if (pageRows.length === 0) {
    tbody.innerHTML = '<tr><td colspan="9" style="text-align:center;color:#999;padding:30px;">No meeting records found matching your search criteria.</td></tr>';
    var pagDiv = document.querySelector('#page-meetingList .pagination');
    if (pagDiv) pagDiv.textContent = 'Showing 0 of 0';
    return;
  }
  var html = '';
  pageRows.forEach(function(r, i) {
    var sno = start + i + 1;
    var topic = r.held === 'Yes' ? (r.topic || '-') : '<span style="color:#999;">No meeting</span>';
    var participants = r.held === 'Yes' ? (r.attended || 0) : '-';
    html += '<tr>' +
      '<td>' + sno + '</td>' +
      '<td>' + escHtml(String(r.year)) + '</td>' +
      '<td>' + escHtml(r.month) + '</td>' +
      '<td>' + escHtml(r.centre) + '</td>' +
      '<td><a href="#" onclick="viewMeetingDetail(' + r.id + ');return false;" style="color:var(--primary);font-weight:600;">' + escHtml(r.flp_leader) + '</a></td>' +
      '<td style="text-align:center;">' + r.peer_count + '</td>' +
      '<td>' + topic + '</td>' +
      '<td style="text-align:center;">' + participants + '</td>' +
      '<td>' +
        '<button class="btn-icon" title="View" onclick="viewMeetingDetail(' + r.id + ')"><i class="fas fa-eye"></i></button> ' +
        '<button class="btn-icon" title="Edit" onclick="openEditMeeting(' + r.id + ')"><i class="fas fa-edit"></i></button> ' +
        '<button class="btn-icon text-danger" title="Delete" onclick="deleteMeeting(' + r.id + ')"><i class="fas fa-trash-alt"></i></button>' +
      '</td>' +
      '</tr>';
  });
  tbody.innerHTML = html;
  if (typeof renderListPagination === 'function') {
    renderListPagination('#page-meetingList .pagination', total, meetingCurrentPage, meetingPageLimit, 'loadMeetingListData');
  }
  var selLimit = document.getElementById('meetingItemsPerPage');
  if (selLimit) selLimit.value = String(meetingPageLimit);
}

function exportMeetingToExcel() {
  var rows = getFilteredMeetings();
  if (!rows.length) { alert('No meeting records to export.'); return; }
  var headers = ['S.No','Year','Month','State','Centre','Batch','FLP Leader','No. of Peer Group Member','Area','Dropped','Joined (New)','Meeting Held?','Topic','Date of Meeting','Participants','Activity Held?','Activity Specify'];
  var lines = [headers.join(',')];
  rows.forEach(function(r, i) {
    var vals = [
      i + 1, r.year, r.month, r.state, r.centre, r.batch, r.flp_leader, r.peer_count, r.area,
      r.dropped, r.joined, r.held, r.topic, r.meeting_date, r.attended, r.activity, r.activity_specify
    ].map(function(v) {
      var s = String(v == null ? '' : v).replace(/"/g, '""');
      return /[",\n]/.test(s) ? '"' + s + '"' : s;
    });
    lines.push(vals.join(','));
  });
  var blob = new Blob([lines.join('\n')], { type: 'text/csv;charset=utf-8;' });
  var url = URL.createObjectURL(blob);
  var a = document.createElement('a');
  a.href = url; a.download = 'meeting_list_' + new Date().toISOString().slice(0,10) + '.csv';
  document.body.appendChild(a); a.click(); document.body.removeChild(a);
  URL.revokeObjectURL(url);
}

// ---- Add / Edit form ----
function openAddMeeting() {
  editingMeetingId = null;
  _ctxClear('meetingEditId');
  navigateTo('addMeeting');
}

function openEditMeeting(id) {
  editingMeetingId = id;
  _ctxSet('meetingEditId', id);  // persist so F5 refresh can rehydrate
  navigateTo('addMeeting');
}

function _populateMeetingBatchDropdown(preselect, forcedStateCode) {
  var batchEl = document.getElementById('meetingBatch');
  if (!batchEl) return;
  batchEl.innerHTML = '<option value="">Select Batch</option>';
  var role = (currentUser && currentUser.role) || '';
  var userStateCode = (currentUser && currentUser.state_code) || '';
  var params = { status: 'Active', limit: 500 };
  // Priority: explicit forcedStateCode (from the form's State dropdown)
  // > user's profile state (SL/PI/DL). Super Admin / Admin have no profile
  // state, so they rely on the State dropdown selection to scope batches.
  if (forcedStateCode) {
    params.state_code = forcedStateCode;
  } else if ((role === 'state_lead' || role === 'pi' || role === 'district_lead') && userStateCode) {
    params.state_code = userStateCode;
  } else {
    // Super Admin / Admin with no state selected yet → show empty list
    return;
  }
  function _applyPreselect() {
    if (!preselect) return;
    // If the preselect name isn't already an option (e.g. inactive/orphaned batch
    // on an existing record), inject a synthetic option so the value sticks.
    var found = Array.from(batchEl.options).some(function(o) { return o.value === preselect; });
    if (!found) {
      var extra = document.createElement('option');
      extra.value = preselect;
      extra.textContent = preselect;
      batchEl.appendChild(extra);
    }
    batchEl.value = preselect;
  }
  if (typeof apiBatches === 'function') {
    apiBatches(params).then(function(r) {
      var list = (r && (r.data || r)) || [];
      var seen = {};
      list.forEach(function(b) {
        if (b.status && b.status !== 'Active') return;
        var name = b.name || '';
        if (!name || seen[name]) return;
        seen[name] = true;
        var o = document.createElement('option');
        o.value = name;
        o.textContent = b.year ? (name + ' (' + b.year + ')') : name;
        batchEl.appendChild(o);
      });
      _applyPreselect();
    }).catch(function() {
      if (typeof DEMO_BATCHES !== 'undefined') {
        var seen2 = {};
        DEMO_BATCHES.forEach(function(b) {
          if (b.status && b.status !== 'Active') return;
          if (!b.name || seen2[b.name]) return;
          seen2[b.name] = true;
          var o = document.createElement('option');
          o.value = b.name;
          o.textContent = b.year ? (b.name + ' (' + b.year + ')') : b.name;
          batchEl.appendChild(o);
        });
      }
      _applyPreselect();
    });
  } else {
    _applyPreselect();
  }
}

function _populateMeetingStateDropdown() {
  // Role-aware state dropdown for the Add/Edit Meeting form.
  // Option value = state_name (for display/filter compatibility with DEMO_MEETINGS),
  // option's data-code attribute = state_code (used to fetch districts).
  // Returns a Promise that resolves once the dropdown options are in the DOM —
  // edit flow awaits this before trying to set the state value.
  var stateEl = document.getElementById('meetingState');
  if (!stateEl) return Promise.resolve();
  stateEl.innerHTML = '<option value="">Select State</option>';
  var role = (currentUser && currentUser.role) || '';
  var stateCode = (currentUser && currentUser.state_code) || '';
  var fetchStates = (typeof apiGet === 'function')
    ? apiGet('/geo/states').then(function(r) { return (r && (r.data || r)) || []; })
    : Promise.resolve([]);

  // SL / PI / DL: only their state, pre-selected and locked
  if ((role === 'state_lead' || role === 'pi' || role === 'district_lead') && stateCode) {
    return fetchStates.then(function(list) {
      var match = list.find(function(s) { return s.state_code === stateCode; });
      var stateName = match ? (match.state_name || match.name) : '';
      if (!stateName && typeof DEMO_STATES !== 'undefined') {
        var demo = DEMO_STATES.find(function(s) { return (s.short_code || '').toUpperCase() === stateCode.toUpperCase(); });
        if (demo) stateName = demo.name;
      }
      if (stateName) {
        var o = document.createElement('option');
        o.value = stateName; o.textContent = stateName;
        o.setAttribute('data-code', stateCode);
        o.selected = true;
        stateEl.appendChild(o);
        stateEl.disabled = true;
      }
    }).catch(function() {});
  }
  // Super Admin / Admin: all states
  stateEl.disabled = false;
  return fetchStates.then(function(list) {
    list.forEach(function(s) {
      var name = s.state_name || s.name;
      if (!name) return;
      var o = document.createElement('option'); o.value = name; o.textContent = name;
      o.setAttribute('data-code', s.state_code || '');
      stateEl.appendChild(o);
    });
  }).catch(function() {
    if (typeof DEMO_STATES !== 'undefined') {
      DEMO_STATES.forEach(function(s) {
        var o = document.createElement('option'); o.value = s.name; o.textContent = s.name; stateEl.appendChild(o);
      });
    }
  });
}

function initMeetingForm() {
  // Rehydrate if user refreshed during edit mode
  if (!editingMeetingId) {
    var _mEditId = _ctxGetInt('meetingEditId');
    if (_mEditId) editingMeetingId = _mEditId;
  }

  // Resolve the edit record up-front so we can drive the cascade properly
  var _editRec = editingMeetingId ? DEMO_MEETINGS.find(function(r) { return r.id === editingMeetingId; }) : null;
  // Stash the batch preselect so the batch dropdown picks it up once its options load
  _pendingMeetingBatchPreselect = _editRec ? _editRec.batch : null;

  // Kick off state dropdown populate (returns a Promise now)
  var _statePromise = _populateMeetingStateDropdown();
  // Year input — typable number field with calendar picker; no need to pre-fill

  // Reset or rehydrate
  switchMeetingTab('basic');
  var bc = document.getElementById('addMeetingBreadcrumb');
  var saveTxt = document.getElementById('meetingSaveBtnText');
  if (editingMeetingId && _editRec) {
    if (bc) bc.innerHTML = '<a href="#" onclick="navigateTo(\'dashboard\');return false;"><i class="fas fa-home"></i> Home</a> <span class="bc-sep">›</span> <a href="#" onclick="navigateTo(\'meetingList\');return false;">Peer Engagement</a> <span class="bc-sep">›</span> Edit Peer Engagement';
    if (saveTxt) saveTxt.textContent = 'Update';
    var rec = _editRec;

    // Non-cascade fields — safe to set immediately
    document.getElementById('meetingFlpLeader').value = rec.flp_leader || '';
    document.getElementById('meetingPeerCount').value = rec.peer_count || '';
    document.getElementById('meetingArea').value = rec.area || '';
    document.getElementById('meetingYear').value = rec.year ? String(rec.year) : '';
    document.getElementById('meetingMonth').value = rec.month || '';
    document.getElementById('meetingDropped').value = rec.dropped || '';
    document.getElementById('meetingJoined').value = rec.joined || '';
    document.getElementById('meetingHeld').value = rec.held || '';
    toggleMeetingHeldFields();
    document.getElementById('meetingTopic').value = rec.topic || '';
    document.getElementById('meetingDate').value = rec.meeting_date || '';
    document.getElementById('meetingAttended').value = rec.attended || '';
    document.getElementById('meetingActivity').value = rec.activity || '';
    toggleMeetingActivityField();
    document.getElementById('meetingActivitySpecify').value = rec.activity_specify || '';

    // Cascade: state → district → centre, chained on Promises so each level waits
    // for its options to populate before setting the saved value.
    _statePromise.then(function() {
      var stateEl = document.getElementById('meetingState');
      if (stateEl) stateEl.value = rec.state || '';
      return updateMeetingDistrictOptions();
    }).then(function() {
      var distEl = document.getElementById('meetingDistrict');
      if (distEl) distEl.value = rec.district || '';
      return updateMeetingCentreOptions();
    }).then(function() {
      var centreEl = document.getElementById('meetingCentre');
      if (centreEl) centreEl.value = rec.centre || '';
    }).catch(function() {});
  } else {
    if (bc) bc.innerHTML = '<a href="#" onclick="navigateTo(\'dashboard\');return false;"><i class="fas fa-home"></i> Home</a> <span class="bc-sep">›</span> <a href="#" onclick="navigateTo(\'meetingList\');return false;">Peer Engagement</a> <span class="bc-sep">›</span> Add Peer Engagement';
    if (saveTxt) saveTxt.textContent = 'Save';
    // After state dropdown populates, trigger district cascade so SL/PI/DL see their auto-filled districts
    _statePromise.then(function() {
      var stateEl = document.getElementById('meetingState');
      if (stateEl && stateEl.value) updateMeetingDistrictOptions();
    }).catch(function() {});
    // Populate batches in parallel (for SL/PI/DL it auto-scopes to their state)
    _populateMeetingBatchDropdown(null);
    resetMeetingForm();
  }
}

function resetMeetingForm() {
  var ids = ['meetingState','meetingDistrict','meetingCentre','meetingBatch','meetingFlpLeader','meetingPeerCount','meetingArea','meetingYear','meetingMonth','meetingDropped','meetingJoined','meetingHeld','meetingTopic','meetingDate','meetingAttended','meetingActivity','meetingActivitySpecify'];
  ids.forEach(function(id) { var el = document.getElementById(id); if (el) el.value = ''; });
  updateMeetingDistrictOptions();
  toggleMeetingHeldFields();
  toggleMeetingActivityField();
}

// Cascade: State change -> load districts + batches for that state, clear centre.
// Returns a Promise that resolves once district options are populated (edit flow awaits this).
function updateMeetingDistrictOptions() {
  var stateEl = document.getElementById('meetingState');
  var distEl = document.getElementById('meetingDistrict');
  var centreEl = document.getElementById('meetingCentre');
  if (distEl) { distEl.innerHTML = '<option value="">Select District</option>'; distEl.disabled = false; }
  if (centreEl) centreEl.innerHTML = '<option value="">Select Centre</option>';
  if (!stateEl) return Promise.resolve();
  var opt = stateEl.selectedOptions && stateEl.selectedOptions[0];
  var stateCode = opt ? (opt.getAttribute('data-code') || '') : '';
  // Re-scope batches to the currently-chosen state (Super Admin / Admin flow).
  // Carry over any pending preselect (from edit mode) so it sticks after the
  // cascade fires — then clear it to avoid reapplying on later state changes.
  if (typeof _populateMeetingBatchDropdown === 'function') {
    _populateMeetingBatchDropdown(_pendingMeetingBatchPreselect || null, stateCode);
    _pendingMeetingBatchPreselect = null;
  }
  if (!stateCode || !distEl || typeof apiGeoDropdownDistricts !== 'function') return Promise.resolve();
  var role = (currentUser && currentUser.role) || '';
  var userDistrictCode = (currentUser && currentUser.district_code) || '';
  return apiGeoDropdownDistricts(stateCode).then(function(result) {
    var list = (result && (result.data || result)) || [];
    // PI / District Lead: show only their assigned district, pre-selected & locked
    if ((role === 'pi' || role === 'district_lead') && userDistrictCode) {
      var match = list.find(function(d) { return d.district_code === userDistrictCode; });
      if (match) {
        var o = document.createElement('option');
        o.value = match.district_name; o.textContent = match.district_name;
        o.setAttribute('data-code', match.district_code);
        o.selected = true;
        distEl.appendChild(o);
        distEl.disabled = true;
        return updateMeetingCentreOptions();
      }
      return;
    }
    list.forEach(function(d) {
      var o = document.createElement('option');
      o.value = d.district_name;
      o.textContent = d.district_name;
      o.setAttribute('data-code', d.district_code || '');
      distEl.appendChild(o);
    });
  }).catch(function() {});
}

// Cascade: District change -> load centres for that district.
// Returns a Promise that resolves once centre options are populated (edit flow awaits this).
function updateMeetingCentreOptions() {
  var distEl = document.getElementById('meetingDistrict');
  var centreEl = document.getElementById('meetingCentre');
  if (centreEl) centreEl.innerHTML = '<option value="">Select Centre</option>';
  if (!distEl || !centreEl) return Promise.resolve();
  var opt = distEl.selectedOptions && distEl.selectedOptions[0];
  var distCode = opt ? (opt.getAttribute('data-code') || '') : '';
  if (!distCode || typeof apiGeoDropdownCentres !== 'function') return Promise.resolve();
  return apiGeoDropdownCentres(distCode).then(function(result) {
    var list = (result && (result.data || result)) || [];
    list.forEach(function(c) {
      var o = document.createElement('option');
      o.value = c.centre_name;
      o.textContent = c.centre_name;
      o.setAttribute('data-code', c.centre_code || '');
      centreEl.appendChild(o);
    });
  }).catch(function() {});
}

function toggleMeetingHeldFields() {
  var val = (document.getElementById('meetingHeld') || {}).value;
  var show = val === 'Yes';
  ['meetingTopicGrp', 'meetingDateGrp', 'meetingAttendedGrp'].forEach(function(id) {
    var el = document.getElementById(id);
    if (el) el.style.display = show ? '' : 'none';
  });
  if (!show) {
    ['meetingTopic','meetingDate','meetingAttended'].forEach(function(id) { var el = document.getElementById(id); if (el) el.value = ''; });
  }
}

function toggleMeetingActivityField() {
  var val = (document.getElementById('meetingActivity') || {}).value;
  var el = document.getElementById('meetingActivitySpecifyGrp');
  if (el) el.style.display = val === 'Yes' ? '' : 'none';
  if (val !== 'Yes') {
    var inp = document.getElementById('meetingActivitySpecify'); if (inp) inp.value = '';
  }
}

function switchMeetingTab(tabName) {
  ['basic','details'].forEach(function(t) {
    var btn = document.getElementById('meetingTabBtn-' + t);
    var pane = document.getElementById('meetingTab-' + t);
    if (btn) btn.classList.toggle('active', t === tabName);
    if (pane) pane.classList.toggle('active', t === tabName);
  });
}

function validateMeetingBasic() {
  var state = document.getElementById('meetingState').value;
  var district = (document.getElementById('meetingDistrict') || {}).value;
  var centre = document.getElementById('meetingCentre').value;
  var leader = document.getElementById('meetingFlpLeader').value.trim();
  var peer = document.getElementById('meetingPeerCount').value;
  if (!state) { alert('Please select State.'); return false; }
  if (!district) { alert('Please select District.'); return false; }
  if (!centre) { alert('Please select Centre.'); return false; }
  if (!leader) { alert('Please enter Name of FLP Leader.'); return false; }
  if (peer === '' || isNaN(parseInt(peer))) { alert('Please enter Number of peer group member.'); return false; }
  return true;
}

function meetingNextToDetails() {
  if (!validateMeetingBasic()) return;
  switchMeetingTab('details');
}

function saveMeetingRecord() {
  if (!validateMeetingBasic()) { switchMeetingTab('basic'); return; }
  var year = document.getElementById('meetingYear').value;
  var month = document.getElementById('meetingMonth').value;
  var held = document.getElementById('meetingHeld').value;
  var activity = document.getElementById('meetingActivity').value;
  if (!year) { alert('Please select Year.'); return; }
  if (!month) { alert('Please select Month.'); return; }
  if (!held) { alert('Please select whether any meeting was held this month.'); return; }
  if (held === 'Yes') {
    if (!document.getElementById('meetingTopic').value.trim()) { alert('Please enter Topic of the meeting.'); return; }
    if (!document.getElementById('meetingDate').value) { alert('Please select Date of the meeting.'); return; }
    if (document.getElementById('meetingAttended').value === '') { alert('Please enter how many peer/group members attended.'); return; }
  }
  if (!activity) { alert('Please select whether any activity was held.'); return; }
  if (activity === 'Yes' && !document.getElementById('meetingActivitySpecify').value.trim()) {
    alert('Please specify the activity held.'); return;
  }

  var record = {
    state: document.getElementById('meetingState').value,
    district: (document.getElementById('meetingDistrict') || {}).value || '',
    centre: document.getElementById('meetingCentre').value,
    batch: document.getElementById('meetingBatch').value,
    flp_leader: document.getElementById('meetingFlpLeader').value.trim(),
    peer_count: parseInt(document.getElementById('meetingPeerCount').value, 10) || 0,
    area: document.getElementById('meetingArea').value.trim(),
    year: parseInt(year, 10),
    month: month,
    dropped: parseInt(document.getElementById('meetingDropped').value, 10) || 0,
    joined: parseInt(document.getElementById('meetingJoined').value, 10) || 0,
    held: held,
    topic: held === 'Yes' ? document.getElementById('meetingTopic').value.trim() : '',
    meeting_date: held === 'Yes' ? document.getElementById('meetingDate').value : '',
    attended: held === 'Yes' ? (parseInt(document.getElementById('meetingAttended').value, 10) || 0) : 0,
    activity: activity,
    activity_specify: activity === 'Yes' ? document.getElementById('meetingActivitySpecify').value.trim() : ''
  };

  if (editingMeetingId) {
    var idx = DEMO_MEETINGS.findIndex(function(r) { return r.id === editingMeetingId; });
    if (idx !== -1) { record.id = editingMeetingId; DEMO_MEETINGS[idx] = record; }
    alert('Meeting record updated successfully.');
  } else {
    record.id = (DEMO_MEETINGS.reduce(function(m, r) { return Math.max(m, r.id); }, 0) || 0) + 1;
    DEMO_MEETINGS.unshift(record);
    alert('Meeting record saved successfully.');
  }
  _saveMeetingsToStorage();
  editingMeetingId = null;
  _ctxClear('meetingEditId');
  navigateTo('meetingList');
}

// ---- View ----
function viewMeetingDetail(id) {
  viewingMeetingId = id;
  _ctxSet('viewMeeting', id);  // persist so F5 refresh rehydrates the view
  navigateTo('viewMeeting');
}

function editMeetingFromView() {
  if (viewingMeetingId) openEditMeeting(viewingMeetingId);
}

function loadMeetingView() {
  var rec = DEMO_MEETINGS.find(function(r) { return r.id === viewingMeetingId; });
  if (!rec) return;
  var setText = function(id, v) { var el = document.getElementById(id); if (el) el.textContent = v || '—'; };
  setText('viewMeetingName', rec.flp_leader);
  setText('viewMeetingCentre', rec.centre);
  setText('viewMeetingPeriod', (rec.month || '') + ' ' + (rec.year || ''));
  setText('viewMeetingTopic', rec.held === 'Yes' ? (rec.topic || '-') : 'No meeting held');

  var basic = document.getElementById('viewMeetingBasicGrid');
  if (basic) {
    basic.innerHTML =
      _meetingDetailItem('State', rec.state) +
      _meetingDetailItem('Centre', rec.centre) +
      _meetingDetailItem('Batch', rec.batch) +
      _meetingDetailItem('Name of FLP Leader', rec.flp_leader) +
      _meetingDetailItem('Number of peer group member', rec.peer_count) +
      _meetingDetailItem('Area from where group members are', rec.area);
  }
  var det = document.getElementById('viewMeetingDetailsGrid');
  if (det) {
    det.innerHTML =
      _meetingDetailItem('Year', rec.year) +
      _meetingDetailItem('Month', rec.month) +
      _meetingDetailItem('Peer members dropped', rec.dropped) +
      _meetingDetailItem('Peer members joined (new)', rec.joined) +
      _meetingDetailItem('Meeting held this month?', rec.held) +
      (rec.held === 'Yes' ? (
        _meetingDetailItem('Topic of the meeting', rec.topic) +
        _meetingDetailItem('Date of the meeting', formatDateDMY(rec.meeting_date)) +
        _meetingDetailItem('Members attended', rec.attended)
      ) : '') +
      _meetingDetailItem('Activity held?', rec.activity) +
      (rec.activity === 'Yes' ? _meetingDetailItem('Activity specified', rec.activity_specify) : '');
  }
}

function _meetingDetailItem(label, val) {
  var display = (val === null || val === undefined || val === '') ? '—' : String(val);
  return '<div class="detail-item"><label>' + escHtml(label) + '</label><span>' + escHtml(display) + '</span></div>';
}

// ---- Delete ----
function deleteMeeting(id) {
  var rec = DEMO_MEETINGS.find(function(r) { return r.id === id; });
  if (!rec) return;
  if (!confirm('Delete meeting record for "' + rec.flp_leader + '" (' + rec.month + ' ' + rec.year + ')? This cannot be undone.')) return;
  var idx = DEMO_MEETINGS.findIndex(function(r) { return r.id === id; });
  if (idx !== -1) DEMO_MEETINGS.splice(idx, 1);
  _saveMeetingsToStorage();
  loadMeetingListData(meetingCurrentPage);
}

// =============================================================================
// INTERNSHIP MODULE — Organizations + Assignments + Reports
// =============================================================================

var orgCurrentPage = 1, orgPageLimit = 10;
var editingOrgId = null;
var internshipCurrentPage = 1, internshipPageLimit = 10;
var editingInternshipId = null;
var viewingInternshipId = null;
var _internshipFilterOrgsLoaded = false;
var _internshipFilterGeoLoaded = false;
var _currentReportAssignmentId = null;

// ---- ORGANIZATIONS LIST ----
function loadOrganizationListData(page) {
  if (typeof page === 'number') orgCurrentPage = page;
  var name = (document.getElementById('orgFilterName') || {}).value || '';
  var type = (document.getElementById('orgFilterType') || {}).value || '';
  var status = (document.getElementById('orgFilterStatus') || {}).value || '';

  apiOrganizations({
    name: name, org_type: type, status: status,
    page: orgCurrentPage, limit: orgPageLimit,
  }).then(function(resp) {
    var rows = (resp.data || []);
    var total = resp.total || 0;
    var tbody = document.getElementById('organizationListTableBody');
    if (!tbody) return;
    if (!rows.length) {
      tbody.innerHTML = '<tr><td colspan="7" style="text-align:center;color:#999;padding:30px;">No organizations found. Click <b>+ Add Organization</b> to get started.</td></tr>';
      // colspan 7 matches new column count (S.No, Name, Type, Contact, Linked FLPs, Status, Actions)
      var pag = document.querySelector('#page-organizationList .pagination');
      if (pag) pag.textContent = 'Showing 0 of 0';
      return;
    }
    var html = '';
    rows.forEach(function(o, idx) {
      var sno = (orgCurrentPage - 1) * orgPageLimit + idx + 1;
      var typeLabel = o.org_type === 'Other' && o.org_type_other
        ? (o.org_type + ': ' + o.org_type_other)
        : (o.org_type || '');
      html += '<tr>' +
        '<td>' + sno + '</td>' +
        '<td><strong>' + escHtml(o.name) + '</strong></td>' +
        '<td>' + (typeLabel ? '<span class="badge" style="background:#f8f0f7;color:#732269;padding:2px 8px;">' + escHtml(typeLabel) + '</span>' : '—') + '</td>' +
        '<td>' + escHtml(o.contact_number || '—') + '</td>' +
        '<td>' + (parseInt(o.flp_count) || 0) + '</td>' +
        '<td>' + statusBadge(o.status || 'Active') + '</td>' +
        '<td>' +
          '<button class="btn-icon" title="View" onclick="viewOrganization(' + o.id + ')"><i class="fas fa-eye"></i></button> ' +
          '<button class="btn-icon" title="Edit" onclick="openOrgForm(\'edit\',' + o.id + ')"><i class="fas fa-edit"></i></button> ' +
          '<button class="btn-icon text-danger" title="Delete" onclick="deleteOrganization(' + o.id + ')"><i class="fas fa-trash-alt"></i></button>' +
        '</td>' +
      '</tr>';
    });
    tbody.innerHTML = html;
    renderListPagination('#page-organizationList .pagination', total, orgCurrentPage, orgPageLimit, 'loadOrganizationListData');
  }).catch(function(err) { showUserError('loading organizations', err); });
}

function applyOrgFilters() { orgCurrentPage = 1; loadOrganizationListData(1); }
function resetOrgFilters() {
  var n = document.getElementById('orgFilterName'); if (n) n.value = '';
  var t = document.getElementById('orgFilterType'); if (t) t.value = '';
  var s = document.getElementById('orgFilterStatus'); if (s) s.value = '';
  orgCurrentPage = 1; loadOrganizationListData(1);
}

// ---- ADD / EDIT ORGANIZATION ----
function toggleOrgTypeOther() {
  var typeEl = document.getElementById('orgFormType');
  var otherEl = document.getElementById('orgFormTypeOther');
  if (!typeEl || !otherEl) return;
  if (typeEl.value === 'Other') {
    otherEl.style.display = '';
  } else {
    otherEl.style.display = 'none';
    otherEl.value = '';
  }
}

function openOrgForm(mode, id) {
  editingOrgId = (mode === 'edit') ? id : null;
  var title = document.getElementById('orgFormTitle');
  var submit = document.getElementById('orgFormSubmitText');
  // Clear all
  ['orgFormName','orgFormContactPerson','orgFormContactNumber','orgFormEmail','orgFormAddress','orgFormTypeOther'].forEach(function(fid) {
    var el = document.getElementById(fid); if (el) el.value = '';
  });
  var typeEl = document.getElementById('orgFormType'); if (typeEl) typeEl.value = '';
  var statusEl = document.getElementById('orgFormStatus'); if (statusEl) statusEl.value = 'Active';
  toggleOrgTypeOther();

  if (mode === 'edit') {
    if (title) title.innerHTML = '<i class="fas fa-edit"></i> Edit Organization';
    if (submit) submit.textContent = 'Update Organization';
    apiOrganizationDetail(id).then(function(o) {
      document.getElementById('orgFormName').value = o.name || '';
      document.getElementById('orgFormType').value = o.org_type || '';
      var otherEl = document.getElementById('orgFormTypeOther');
      if (otherEl) otherEl.value = o.org_type_other || '';
      toggleOrgTypeOther();
      document.getElementById('orgFormContactPerson').value = o.contact_person || '';
      document.getElementById('orgFormContactNumber').value = (o.contact_number || '').replace(/\D/g, '');
      document.getElementById('orgFormEmail').value = o.email || '';
      document.getElementById('orgFormAddress').value = o.address || '';
      var stEl = document.getElementById('orgFormStatus');
      if (stEl) stEl.value = o.status || 'Active';
    }).catch(function(err) { showUserError('loading organization', err); });
  } else {
    if (title) title.innerHTML = '<i class="fas fa-plus-circle"></i> Add Organization';
    if (submit) submit.textContent = 'Save Organization';
  }
  document.getElementById('organizationFormModal').style.display = 'flex';
}

function saveOrganization() {
  var name = (document.getElementById('orgFormName').value || '').trim();
  var orgType = (document.getElementById('orgFormType') || {}).value || '';
  var orgTypeOther = ((document.getElementById('orgFormTypeOther') || {}).value || '').trim();
  var contactNumber = ((document.getElementById('orgFormContactNumber') || {}).value || '').trim();
  var email = ((document.getElementById('orgFormEmail') || {}).value || '').trim();

  if (!name) { alert('Organization Name is required.'); return; }
  if (!orgType) { alert('Type of Organization is required.'); return; }
  if (orgType === 'Other' && !orgTypeOther) { alert('Please specify the organisation type.'); return; }
  if (!contactNumber) { alert('Contact Number is required.'); return; }
  if (!/^\d{10}$/.test(contactNumber)) { alert('Contact Number must be exactly 10 digits.'); return; }
  if (email && !/^[^@\s]+@[^@\s]+\.[^@\s]+$/.test(email)) { alert('Please enter a valid Email ID.'); return; }

  var payload = {
    name: name,
    org_type: orgType,
    org_type_other: orgType === 'Other' ? orgTypeOther : null,
    contact_person: (document.getElementById('orgFormContactPerson') || {}).value || null,
    contact_number: contactNumber,
    email: email || null,
    address: (document.getElementById('orgFormAddress') || {}).value || null,
    status: (document.getElementById('orgFormStatus') || {}).value || 'Active',
  };
  var p = editingOrgId ? apiUpdateOrganization(editingOrgId, payload) : apiCreateOrganization(payload);
  p.then(function() {
    alert(editingOrgId ? 'Organization updated!' : 'Organization added!');
    closeMasterModal('organizationFormModal');
    loadOrganizationListData(orgCurrentPage);
  }).catch(function(err) { showUserError('saving organization', err); });
}

function deleteOrganization(id) {
  if (!confirm('Delete this organization? If FLPs are currently assigned, deletion will be blocked.')) return;
  apiDeleteOrganization(id).then(function() {
    alert('Organization deleted.');
    loadOrganizationListData(orgCurrentPage);
  }).catch(function(err) { showUserError('deleting organization', err); });
}

function viewOrganization(id) {
  apiOrganizationDetail(id).then(function(o) {
    var body = document.getElementById('organizationViewBody');
    if (!body) return;
    var flpsHtml = '';
    if (o.linked_flps && o.linked_flps.length) {
      flpsHtml = '<h4 style="margin:16px 0 8px 0;color:#732269;">Linked FLPs (' + o.linked_flps.length + ')</h4>' +
        '<table class="data-table full-width"><thead><tr><th>Name</th><th>Enrollment</th><th>Duration</th><th>Status</th></tr></thead><tbody>' +
        o.linked_flps.map(function(f) {
          return '<tr><td>' + escHtml(f.flp_name) + '</td><td>' + escHtml(f.enrollment_number || '—') + '</td>' +
            '<td>' + f.start_date + ' → ' + f.end_date + '</td><td>' + escHtml(f.status || '—') + '</td></tr>';
        }).join('') + '</tbody></table>';
    } else {
      flpsHtml = '<div style="color:#999;padding:12px 0;">No FLPs currently assigned.</div>';
    }
    var typeDisplay = o.org_type === 'Other' && o.org_type_other
        ? (o.org_type + ': ' + o.org_type_other)
        : o.org_type;
    body.innerHTML =
      '<div class="detail-grid" style="display:grid;grid-template-columns:1fr 1fr;gap:10px;">' +
        _detailCell('Organization Name', o.name) +
        _detailCell('Type', typeDisplay) +
        _detailCell('Contact Person', o.contact_person) +
        _detailCell('Contact Number', o.contact_number) +
        _detailCell('Email', o.email) +
        _detailCell('Status', o.status) +
        '<div class="detail-item" style="grid-column:1 / -1;"><label>Address</label><span>' + escHtml(o.address || '—') + '</span></div>' +
      '</div>' + flpsHtml;
    document.getElementById('organizationViewModal').style.display = 'flex';
  }).catch(function(err) { showUserError('loading organization', err); });
}

function _detailCell(label, val) {
  return '<div class="detail-item"><label>' + escHtml(label) + '</label><span>' + escHtml(val || '—') + '</span></div>';
}

// =============================================================================
// INTERNSHIP ASSIGNMENTS
// =============================================================================

function loadInternshipListData(page) {
  if (typeof page === 'number') internshipCurrentPage = page;
  // Defer the whole render through _whenDlPiReady so SL/DL/PI never see
  // an unscoped first paint. Without the gate, navigating to the page
  // immediately after login fires before /users/me has resolved
  // currentUser.state_code — both `_populateInternshipFilterState`
  // (which scopes the State dropdown to the user's own state) and
  // `_applyRoleScopeFloor` (which pins state_code on the apiInternships
  // query) silently fall through unscoped, so the user sees a national
  // list and "All States" in the dropdown until they hard-refresh.
  // _whenDlPiReady is a synchronous no-op once the scope promise has
  // already resolved, so subsequent pagination / filter calls don't
  // pay any latency.
  _whenDlPiReady(function() { _internshipLoadListBody(page); });
}

function _internshipLoadListBody(page) {
  // Lazy-load filter dropdowns
  if (!_internshipFilterGeoLoaded) {
    _internshipFilterGeoLoaded = true;
    _populateInternshipFilterState();
    _populateInternshipFilterBatch();
  }
  if (!_internshipFilterOrgsLoaded) {
    _internshipFilterOrgsLoaded = true;
    _populateInternshipFilterOrg();
  }

  var stateEl = document.getElementById('internshipFilterState');
  var batchEl = document.getElementById('internshipFilterBatch');
  var nameEl = document.getElementById('internshipFilterFlpName');
  var orgEl = document.getElementById('internshipFilterOrg');
  var fromEl = document.getElementById('internshipFilterDateFrom');
  var toEl = document.getElementById('internshipFilterDateTo');

  var params = { page: internshipCurrentPage, limit: internshipPageLimit };
  if (stateEl && stateEl.value) params.state_code = stateEl.value;
  if (batchEl && batchEl.value) params.batch_id = parseInt(batchEl.value);
  if (nameEl && nameEl.value.trim()) params.flp_name = nameEl.value.trim();
  if (orgEl && orgEl.value) params.organization_id = parseInt(orgEl.value);
  if (fromEl && fromEl.value) params.date_from = fromEl.value;
  if (toEl && toEl.value) params.date_to = toEl.value;
  params = _applyRoleScopeFloor(params);

  apiInternships(params).then(function(resp) {
    var rows = resp.data || [];
    var total = resp.total || 0;
    var tbody = document.getElementById('internshipListTableBody');
    if (!tbody) return;
    if (!rows.length) {
      tbody.innerHTML = '<tr><td colspan="8" style="text-align:center;color:#999;padding:30px;">No internship assignments found.</td></tr>';
      var pag = document.querySelector('#page-internshipAssignment .pagination');
      if (pag) pag.textContent = 'Showing 0 of 0';
      return;
    }
    var html = '';
    rows.forEach(function(r, idx) {
      var sno = (internshipCurrentPage - 1) * internshipPageLimit + idx + 1;
      html += '<tr>' +
        '<td>' + sno + '</td>' +
        '<td><strong>' + escHtml(r.flp_name || '—') + '</strong><br><small style="color:#999;">' + escHtml(r.enrollment_number || '') + '</small></td>' +
        '<td>' + escHtml(r.state_name || '—') + '</td>' +
        '<td>' + escHtml(r.batch_name || '—') + '</td>' +
        '<td>' + escHtml(r.organization_name || '—') + '</td>' +
        '<td>' + _fmtDate(r.start_date) + ' → ' + _fmtDate(r.end_date) + '</td>' +
        '<td>' + statusBadge(r.status) + '</td>' +
        '<td>' +
          '<button class="btn-icon" title="View" onclick="navigateToViewInternship(' + r.id + ')"><i class="fas fa-eye"></i></button> ' +
          '<button class="btn-icon" title="Edit" onclick="openInternshipForm(\'edit\',' + r.id + ')"><i class="fas fa-edit"></i></button> ' +
          '<button class="btn-icon" title="Add Report" onclick="openReportForm(' + r.id + ')"><i class="fas fa-plus"></i></button>' +
        '</td>' +
      '</tr>';
    });
    tbody.innerHTML = html;
    renderListPagination('#page-internshipAssignment .pagination', total, internshipCurrentPage, internshipPageLimit, 'loadInternshipListData');
  }).catch(function(err) { showUserError('loading internship assignments', err); });
}

function _fmtDate(s) { if (!s) return '—'; try { return (typeof formatDateNice === 'function') ? formatDateNice(s) : String(s).substring(0, 10); } catch(e) { return String(s).substring(0, 10); } }

function applyInternshipFilters() { internshipCurrentPage = 1; loadInternshipListData(1); }
function resetInternshipFilters() {
  ['internshipFilterState','internshipFilterBatch','internshipFilterOrg','internshipFilterFlpName','internshipFilterDateFrom','internshipFilterDateTo'].forEach(function(id) {
    var el = document.getElementById(id); if (el) el.value = '';
  });
  internshipCurrentPage = 1; loadInternshipListData(1);
}

function exportInternshipsToExcel() {
  var qs = [];
  var stateEl = document.getElementById('internshipFilterState');
  var batchEl = document.getElementById('internshipFilterBatch');
  var nameEl = document.getElementById('internshipFilterFlpName');
  var orgEl = document.getElementById('internshipFilterOrg');
  var fromEl = document.getElementById('internshipFilterDateFrom');
  var toEl = document.getElementById('internshipFilterDateTo');
  if (stateEl && stateEl.value) qs.push('state_code=' + encodeURIComponent(stateEl.value));
  if (batchEl && batchEl.value) qs.push('batch_id=' + batchEl.value);
  if (nameEl && nameEl.value.trim()) qs.push('flp_name=' + encodeURIComponent(nameEl.value.trim()));
  if (orgEl && orgEl.value) qs.push('organization_id=' + orgEl.value);
  if (fromEl && fromEl.value) qs.push('date_from=' + fromEl.value);
  if (toEl && toEl.value) qs.push('date_to=' + toEl.value);
  window.location.href = API_BASE + '/internships/export/excel' + (qs.length ? '?' + qs.join('&') : '');
}

function _populateInternshipFilterState() {
  var sel = document.getElementById('internshipFilterState');
  if (!sel) return;
  // Role-scoped: SL / DL / PI must see only their own state. Lock the
  // dropdown to that state and disable it so the user can't widen the
  // filter to other states.
  var role = (currentUser && currentUser.role) || '';
  var roleStateCode = (currentUser && currentUser.state_code) || '';
  var locked = (role === 'state_lead' || role === 'district_lead' || role === 'pi') && !!roleStateCode;

  sel.innerHTML = '<option value="">All States</option>';
  apiGet('/geo/dropdown/states').then(function(states) {
    var rows = states || [];
    if (locked) {
      rows = rows.filter(function(s) { return s.state_code === roleStateCode; });
    }
    rows.forEach(function(s) {
      var opt = document.createElement('option');
      opt.value = s.state_code; opt.textContent = s.state_name;
      sel.appendChild(opt);
    });
    if (locked && rows.length === 1) {
      sel.value = rows[0].state_code;
      sel.disabled = true;
    } else {
      sel.disabled = false;
    }
  }).catch(function() {});
}

function _populateInternshipFilterBatch() {
  var sel = document.getElementById('internshipFilterBatch');
  if (!sel) return;
  sel.innerHTML = '<option value="">All Batches</option>';

  // Role-scoped: SL / DL / PI must see only batches in their assigned
  // state. Push state_code into the API query so the backend (which
  // already supports `?state_code=`) returns just that state's batches.
  // Admin / Power User keep the unscoped national list.
  var role = (currentUser && currentUser.role) || '';
  var roleStateCode = (currentUser && currentUser.state_code) || '';
  var scoped = (role === 'state_lead' || role === 'district_lead' || role === 'pi') && !!roleStateCode;

  var path = '/batches?status=Active&limit=200' +
             (scoped ? '&state_code=' + encodeURIComponent(roleStateCode) : '');

  apiGet(path).then(function(resp) {
    var rows = (resp && resp.data) ? resp.data : (resp || []);
    rows.forEach(function(b) {
      var opt = document.createElement('option');
      opt.value = b.id; opt.textContent = b.name + (b.state_name ? ' (' + b.state_name + ')' : '');
      sel.appendChild(opt);
    });
  }).catch(function() {});
}

function _populateInternshipFilterOrg() {
  var sel = document.getElementById('internshipFilterOrg');
  if (!sel) return;
  sel.innerHTML = '<option value="">All Organizations</option>';
  apiOrganizations({ status: 'Active', limit: 500 }).then(function(resp) {
    (resp.data || []).forEach(function(o) {
      var opt = document.createElement('option');
      opt.value = o.id; opt.textContent = o.name;
      sel.appendChild(opt);
    });
  }).catch(function() {});
}

// =============================================================================
// INTERNSHIP FORM MODAL — Assign / Edit with cascading geo + FLP dropdowns
// =============================================================================

function openInternshipForm(mode, id) {
  editingInternshipId = (mode === 'edit') ? id : null;
  var title = document.getElementById('internshipFormTitle');
  var submit = document.getElementById('internshipFormSubmitText');

  // Reset form
  ['internshipFormStartDate','internshipFormEndDate'].forEach(function(fid) {
    var el = document.getElementById(fid); if (el) el.value = '';
  });
  ['internshipFormState','internshipFormDistrict','internshipFormCentre','internshipFormBatch','internshipFormFlp','internshipFormOrg'].forEach(function(fid) {
    var el = document.getElementById(fid); if (el) el.selectedIndex = 0;
  });
  document.getElementById('internshipFormDistrict').innerHTML = '<option value="">Select District</option>';
  document.getElementById('internshipFormCentre').innerHTML = '<option value="">Select Centre</option>';
  document.getElementById('internshipFormBatch').innerHTML = '<option value="">Select Batch</option>';
  document.getElementById('internshipFormFlp').innerHTML = '<option value="">Select FLP (choose Centre / Batch first)</option>';

  _populateInternshipFormState();
  _populateInternshipFormOrg();

  if (mode === 'edit') {
    if (title) title.innerHTML = '<i class="fas fa-edit"></i> Edit FLP Internship Tracking';
    if (submit) submit.textContent = 'Update Assignment';
    apiInternshipDetail(id).then(function(r) {
      setTimeout(function() {
        var s = document.getElementById('internshipFormState');
        if (s && r.state_code) { s.value = r.state_code; onInternshipFormStateChange(function() {
          var d = document.getElementById('internshipFormDistrict');
          if (d && r.district_code) { d.value = r.district_code; onInternshipFormDistrictChange(function() {
            var c = document.getElementById('internshipFormCentre');
            if (c && r.centre_code) { c.value = r.centre_code; onInternshipFormCentreChange(function() {
              var b = document.getElementById('internshipFormBatch');
              if (b && r.batch_id) { b.value = r.batch_id; onInternshipFormBatchChange(function() {
                var f = document.getElementById('internshipFormFlp');
                if (f && r.flp_id) f.value = r.flp_id;
              }); }
            }); }
          }); }
        }); }
        var o = document.getElementById('internshipFormOrg');
        if (o && r.organization_id) o.value = r.organization_id;
        var sd = document.getElementById('internshipFormStartDate'); if (sd) sd.value = (r.start_date || '').substring(0, 10);
        var ed = document.getElementById('internshipFormEndDate'); if (ed) ed.value = (r.end_date || '').substring(0, 10);
      }, 300);
    }).catch(function(err) { showUserError('loading internship', err); });
  } else {
    if (title) title.innerHTML = '<i class="fas fa-plus-circle"></i> Assign FLP to Internship';
    if (submit) submit.textContent = 'Save Assignment';
  }

  document.getElementById('internshipFormModal').style.display = 'flex';
}

function _populateInternshipFormState() {
  var sel = document.getElementById('internshipFormState');
  if (!sel) return;
  // Role-scoped: SL / DL / PI must only be allowed to assign FLPs within
  // their own state. Filter the dropdown to that one state, auto-select
  // it, disable the control, and trigger the cascade so the dependent
  // District / Centre / Batch / FLP dropdowns also narrow correctly.
  var role = (currentUser && currentUser.role) || '';
  var roleStateCode = (currentUser && currentUser.state_code) || '';
  var locked = (role === 'state_lead' || role === 'district_lead' || role === 'pi') && !!roleStateCode;

  sel.innerHTML = '<option value="">Select State</option>';
  apiGet('/geo/dropdown/states').then(function(states) {
    var rows = states || [];
    if (locked) {
      rows = rows.filter(function(s) { return s.state_code === roleStateCode; });
    }
    rows.forEach(function(s) {
      var opt = document.createElement('option');
      opt.value = s.state_code; opt.textContent = s.state_name;
      sel.appendChild(opt);
    });
    if (locked && rows.length === 1) {
      sel.value = rows[0].state_code;
      sel.disabled = true;
      // Cascade so the dependent dropdowns load for the locked state.
      onInternshipFormStateChange();
    } else {
      sel.disabled = false;
    }
  }).catch(function() {});
}

function onInternshipFormStateChange(cb) {
  var sc = (document.getElementById('internshipFormState') || {}).value;
  var distSel = document.getElementById('internshipFormDistrict');
  var centreSel = document.getElementById('internshipFormCentre');
  var batchSel = document.getElementById('internshipFormBatch');
  var flpSel = document.getElementById('internshipFormFlp');
  if (distSel) distSel.innerHTML = '<option value="">Select District</option>';
  if (centreSel) centreSel.innerHTML = '<option value="">Select Centre</option>';
  if (batchSel) batchSel.innerHTML = '<option value="">Select Batch</option>';
  if (flpSel) flpSel.innerHTML = '<option value="">Select FLP</option>';
  if (!sc) return;

  // DL / PI must only be allowed to pick their own district. Lock the
  // dropdown to that district and trigger the next cascade automatically.
  var role = (currentUser && currentUser.role) || '';
  var roleDistrict = (currentUser && currentUser.district_code) || '';
  var lockToDistrict = (role === 'district_lead' || role === 'pi') && !!roleDistrict;

  apiGet('/geo/dropdown/districts?state_code=' + encodeURIComponent(sc)).then(function(ds) {
    var rows = ds || [];
    if (lockToDistrict) {
      rows = rows.filter(function(d) { return d.district_code === roleDistrict; });
    }
    rows.forEach(function(d) {
      var opt = document.createElement('option');
      opt.value = d.district_code; opt.textContent = d.district_name;
      distSel.appendChild(opt);
    });
    if (lockToDistrict && rows.length === 1 && distSel) {
      distSel.value = rows[0].district_code;
      distSel.disabled = true;
      // Cascade to centres immediately
      onInternshipFormDistrictChange(cb);
      return;
    } else if (distSel) {
      distSel.disabled = false;
    }
    if (typeof cb === 'function') cb();
  }).catch(function() {});
}

function onInternshipFormDistrictChange(cb) {
  var dc = (document.getElementById('internshipFormDistrict') || {}).value;
  var centreSel = document.getElementById('internshipFormCentre');
  var batchSel = document.getElementById('internshipFormBatch');
  var flpSel = document.getElementById('internshipFormFlp');
  if (centreSel) centreSel.innerHTML = '<option value="">Select Centre</option>';
  if (batchSel) batchSel.innerHTML = '<option value="">Select Batch</option>';
  if (flpSel) flpSel.innerHTML = '<option value="">Select FLP</option>';
  if (!dc) return;

  // PI must only see their own centre. DL keeps every centre in the
  // (already-locked) district.
  var role = (currentUser && currentUser.role) || '';
  var roleCentre = (currentUser && currentUser.centre_code) || '';
  var lockToCentre = (role === 'pi') && !!roleCentre;

  apiGet('/geo/dropdown/centres?district_code=' + encodeURIComponent(dc)).then(function(cs) {
    var seen = {};
    var rows = (cs || []).filter(function(c) {
      if (seen[c.centre_code]) return false;
      seen[c.centre_code] = true;
      return true;
    });
    if (lockToCentre) {
      rows = rows.filter(function(c) { return c.centre_code === roleCentre; });
    }
    rows.forEach(function(c) {
      var opt = document.createElement('option');
      opt.value = c.centre_code; opt.textContent = c.centre_name;
      centreSel.appendChild(opt);
    });
    if (lockToCentre && rows.length === 1 && centreSel) {
      centreSel.value = rows[0].centre_code;
      centreSel.disabled = true;
      // Cascade to batch + FLP
      onInternshipFormCentreChange(cb);
      return;
    } else if (centreSel) {
      centreSel.disabled = false;
    }
    if (typeof cb === 'function') cb();
  }).catch(function() {});
}

function onInternshipFormCentreChange(cb) {
  var sc = (document.getElementById('internshipFormState') || {}).value;
  var cc = (document.getElementById('internshipFormCentre') || {}).value;
  var batchSel = document.getElementById('internshipFormBatch');
  var flpSel = document.getElementById('internshipFormFlp');
  if (batchSel) batchSel.innerHTML = '<option value="">Select Batch</option>';
  if (flpSel) flpSel.innerHTML = '<option value="">Select FLP</option>';
  if (!sc || !cc) return;
  // Batches filtered by state (existing UX) — user picks the relevant one
  apiGet('/batches?state_code=' + encodeURIComponent(sc) + '&status=Active&limit=200').then(function(resp) {
    var rows = (resp && resp.data) ? resp.data : (resp || []);
    rows.forEach(function(b) {
      var opt = document.createElement('option');
      opt.value = b.id; opt.textContent = b.name;
      batchSel.appendChild(opt);
    });
    if (typeof cb === 'function') cb();
  }).catch(function() {});
}

function onInternshipFormBatchChange(cb) {
  var sc = (document.getElementById('internshipFormState') || {}).value;
  var cc = (document.getElementById('internshipFormCentre') || {}).value;
  var bid = (document.getElementById('internshipFormBatch') || {}).value;
  var flpSel = document.getElementById('internshipFormFlp');
  if (flpSel) flpSel.innerHTML = '<option value="">Select FLP</option>';
  if (!bid) return;
  apiFlps({ state_code: sc, centre_code: cc, batch_id: parseInt(bid), status: 'Active', limit: 500 }).then(function(resp) {
    var rows = (resp && resp.data) ? resp.data : (resp || []);
    rows.forEach(function(f) {
      var opt = document.createElement('option');
      opt.value = f.id; opt.textContent = f.name + (f.enrollment_number ? ' (' + f.enrollment_number + ')' : '');
      flpSel.appendChild(opt);
    });
    if (typeof cb === 'function') cb();
  }).catch(function() {});
}

function _populateInternshipFormOrg() {
  var sel = document.getElementById('internshipFormOrg');
  if (!sel) return;
  sel.innerHTML = '<option value="">Select Organization</option>';
  apiOrganizations({ status: 'Active', limit: 500 }).then(function(resp) {
    (resp.data || []).forEach(function(o) {
      var opt = document.createElement('option');
      opt.value = o.id; opt.textContent = o.name;
      sel.appendChild(opt);
    });
  }).catch(function() {});
}

function saveInternship() {
  var v = function(id) { var el = document.getElementById(id); return el ? (el.value || '').trim() : ''; };
  var state = v('internshipFormState');
  var district = v('internshipFormDistrict');
  var centre = v('internshipFormCentre');
  var batch = v('internshipFormBatch');
  var flp = v('internshipFormFlp');
  var org = v('internshipFormOrg');
  var sd = v('internshipFormStartDate');
  var ed = v('internshipFormEndDate');

  if (!state) { alert('Please select State.'); return; }
  if (!district) { alert('Please select District.'); return; }
  if (!centre) { alert('Please select Centre.'); return; }
  if (!batch) { alert('Please select Batch.'); return; }
  if (!flp) { alert('Please select FLP.'); return; }
  if (!org) { alert('Please select Organization.'); return; }
  if (!sd) { alert('Please enter Start Date.'); return; }
  if (!ed) { alert('Please enter End Date.'); return; }
  if (sd > ed) { alert('Start Date must be on or before End Date.'); return; }

  var payload = {
    flp_id: parseInt(flp),
    organization_id: parseInt(org),
    state_code: state,
    district_code: district,
    centre_code: centre,
    batch_id: parseInt(batch),
    start_date: sd,
    end_date: ed,
    status: 'Active',
  };
  var p = editingInternshipId ? apiUpdateInternship(editingInternshipId, payload) : apiCreateInternship(payload);
  p.then(function() {
    alert(editingInternshipId ? 'Assignment updated!' : 'Assignment saved!');
    closeMasterModal('internshipFormModal');
    loadInternshipListData(internshipCurrentPage);
  }).catch(function(err) { showUserError('saving assignment', err); });
}

// =============================================================================
// VIEW INTERNSHIP DETAILS
// =============================================================================

function navigateToViewInternship(id) {
  viewingInternshipId = id;
  _ctxSet('viewInternship', id);
  navigateTo('viewInternship');
}

function loadViewInternship() {
  if (!viewingInternshipId) { viewingInternshipId = _ctxGetInt('viewInternship'); }
  if (!viewingInternshipId) return;
  var id = viewingInternshipId;

  var addBtn = document.getElementById('viewInternshipAddReportBtn');
  if (addBtn) addBtn.onclick = function() { openReportForm(id); };

  apiInternshipDetail(id).then(function(r) {
    document.getElementById('viewInternshipFlpName').textContent = r.flp_name || '—';
    document.getElementById('viewInternshipOrgName').textContent = r.organization_name || '—';
    document.getElementById('viewInternshipDuration').textContent = (_fmtDate(r.start_date) + ' → ' + _fmtDate(r.end_date));
    var sb = document.getElementById('viewInternshipStatus');
    if (sb) sb.innerHTML = statusBadge(r.status);

    // --- FLP details only ---
    var flpGrid = document.getElementById('viewInternshipFlpGrid');
    if (flpGrid) {
      flpGrid.innerHTML =
        _detailCell('FLP Name', r.flp_name) +
        _detailCell('Enrollment No.', r.enrollment_number) +
        _detailCell('Mobile', r.mobile) +
        _detailCell('State', r.state_name) +
        _detailCell('District', r.district_name) +
        _detailCell('Centre', r.centre_name) +
        _detailCell('Batch', r.batch_name);
    }

    // --- Placement details only ---
    var placeGrid = document.getElementById('viewInternshipPlacementGrid');
    if (placeGrid) {
      var orgTypeDisplay = (r.org_type === 'Other' && r.org_type_other)
        ? (r.org_type + ': ' + r.org_type_other)
        : r.org_type;
      placeGrid.innerHTML =
        _detailCell('Organization', r.organization_name) +
        _detailCell('Organization Type', orgTypeDisplay) +
        _detailCell('Start Date', _fmtDate(r.start_date)) +
        _detailCell('End Date', _fmtDate(r.end_date)) +
        _detailCell('Status', r.status) +
        '<div class="detail-item" style="grid-column:1 / -1;"><label>Organization Address</label><span>' + escHtml(r.organization_address || '—') + '</span></div>';
    }

    var repWrap = document.getElementById('viewInternshipReports');
    if (!repWrap) return;
    if (!r.reports || !r.reports.length) {
      repWrap.innerHTML = '<div style="color:#999;padding:20px;text-align:center;">No reports submitted yet. Click <b>+ Add Report</b> to add one.</div>';
      return;
    }
    repWrap.innerHTML = r.reports.map(function(rep) {
      var filesHtml = '';
      var docs = (rep.files || []).filter(function(f) { return f.file_kind === 'doc'; });
      var imgs = (rep.files || []).filter(function(f) { return f.file_kind === 'image'; });
      if (docs.length) {
        filesHtml += '<div style="margin-top:10px;"><strong style="font-size:12px;color:#666;">Documents:</strong><ul style="margin:4px 0 0 20px;">' +
          docs.map(function(f) { return '<li><a href="' + escHtml(f.url) + '" target="_blank"><i class="fas fa-file-pdf"></i> ' + escHtml(f.file_name || 'document') + '</a></li>'; }).join('') +
          '</ul></div>';
      }
      if (imgs.length) {
        filesHtml += '<div style="margin-top:10px;"><strong style="font-size:12px;color:#666;">Images:</strong><div style="display:flex;gap:8px;margin-top:4px;flex-wrap:wrap;">' +
          imgs.map(function(f) { return '<a href="' + escHtml(f.url) + '" target="_blank"><img src="' + escHtml(f.url) + '" alt="" style="width:80px;height:80px;object-fit:cover;border-radius:4px;border:1px solid #eee;"></a>'; }).join('') +
          '</div></div>';
      }
      return '<div style="border:1px solid #eee;border-radius:8px;padding:16px;margin-bottom:14px;">' +
        '<div style="display:flex;justify-content:space-between;align-items:center;margin-bottom:8px;">' +
          '<strong style="color:#732269;">' + escHtml(rep.topic_name || 'Untagged topic') + '</strong>' +
          '<small style="color:#999;">' + _fmtDate(rep.created_at) + '</small>' +
        '</div>' +
        (rep.description ? '<div style="margin-bottom:6px;"><strong style="font-size:12px;color:#666;">Description:</strong><br>' + escHtml(rep.description) + '</div>' : '') +
        (rep.key_learnings ? '<div style="margin-bottom:6px;"><strong style="font-size:12px;color:#666;">Key Learnings:</strong><br>' + escHtml(rep.key_learnings) + '</div>' : '') +
        (rep.challenges ? '<div style="margin-bottom:6px;"><strong style="font-size:12px;color:#666;">Challenges:</strong><br>' + escHtml(rep.challenges) + '</div>' : '') +
        filesHtml +
      '</div>';
    }).join('');
  }).catch(function(err) { showUserError('loading internship details', err); });
}

// =============================================================================
// ADD REPORT MODAL
// =============================================================================

// Append-style file lists for the Add Report modal — rebuilt on every open.
// Using a custom list lets users click "Add …" multiple times and accumulate
// files, instead of each native picker replacing the previous selection.
var _reportPickedDocs = [];
var _reportPickedImages = [];

function _renderReportFilesList(kind) {
  var listId = kind === 'doc' ? 'reportFormDocsList' : 'reportFormImagesList';
  var arr = kind === 'doc' ? _reportPickedDocs : _reportPickedImages;
  var ul = document.getElementById(listId);
  if (!ul) return;
  if (!arr.length) { ul.innerHTML = ''; return; }
  ul.innerHTML = arr.map(function(f, idx) {
    var icon = kind === 'doc' ? 'fa-file-alt' : 'fa-image';
    var sizeKb = (f.size / 1024).toFixed(1) + ' KB';
    return '<li style="display:flex;align-items:center;gap:8px;padding:6px 10px;background:#f8f9fa;border-radius:4px;margin-bottom:4px;">' +
      '<i class="fas ' + icon + '" style="color:#732269;"></i>' +
      '<span style="flex:1;overflow:hidden;text-overflow:ellipsis;white-space:nowrap;">' + escHtml(f.name) + '</span>' +
      '<span style="color:#999;font-size:11px;">' + sizeKb + '</span>' +
      '<button type="button" class="btn-icon text-danger" title="Remove" onclick="removeReportFile(\'' + kind + '\',' + idx + ')"><i class="fas fa-trash-alt"></i></button>' +
      '</li>';
  }).join('');
}

function addReportFiles(kind, input) {
  if (!input || !input.files) return;
  var arr = kind === 'doc' ? _reportPickedDocs : _reportPickedImages;
  for (var i = 0; i < input.files.length; i++) arr.push(input.files[i]);
  _renderReportFilesList(kind);
  // Reset the hidden input so the SAME file can be re-selected later if needed
  input.value = '';
}

function removeReportFile(kind, index) {
  var arr = kind === 'doc' ? _reportPickedDocs : _reportPickedImages;
  if (index >= 0 && index < arr.length) arr.splice(index, 1);
  _renderReportFilesList(kind);
}

// Show/hide the Monthly Salary field based on the Employment dropdown.
// Salary is only meaningful when the FLP was employed after the internship,
// so we hide it otherwise to keep the form tidy.
function _toggleReportSalaryField() {
  var sel = document.getElementById('reportFormEmployedAfter');
  var grp = document.getElementById('reportFormSalaryGrp');
  if (!sel || !grp) return;
  grp.style.display = (sel.value === 'Yes') ? '' : 'none';
  if (sel.value !== 'Yes') {
    var sal = document.getElementById('reportFormMonthlySalary');
    if (sal) sal.value = '';
  }
}

function openReportForm(assignmentId) {
  _currentReportAssignmentId = assignmentId;
  // Reset text fields
  ['reportFormDescription','reportFormKeyLearnings','reportFormChallenges',
   'reportFormEmployedAfter','reportFormMonthlySalary'].forEach(function(id) {
    var el = document.getElementById(id); if (el) el.value = '';
  });
  // Hide the conditionally-shown salary group on form open.
  var salaryGrp = document.getElementById('reportFormSalaryGrp');
  if (salaryGrp) salaryGrp.style.display = 'none';
  // Reset hidden file inputs AND internal arrays
  ['reportFormDocsHidden','reportFormImagesHidden'].forEach(function(id) {
    var el = document.getElementById(id); if (el) el.value = '';
  });
  _reportPickedDocs = [];
  _reportPickedImages = [];
  _renderReportFilesList('doc');
  _renderReportFilesList('image');

  var st = document.getElementById('reportFormStatus'); if (st) st.textContent = '';
  // Populate topics
  var topicSel = document.getElementById('reportFormTopic');
  if (topicSel) {
    topicSel.innerHTML = '<option value="">Select Topic</option>';
    apiTrainingTopics({ limit: 200 }).then(function(resp) {
      var rows = (resp && resp.data) ? resp.data : (resp || []);
      rows.forEach(function(t) {
        var opt = document.createElement('option');
        opt.value = t.id; opt.textContent = t.name;
        topicSel.appendChild(opt);
      });
    }).catch(function() {});
  }
  document.getElementById('internshipReportFormModal').style.display = 'flex';
}

function saveInternshipReport() {
  var aid = _currentReportAssignmentId;
  if (!aid) return;
  var topicId = (document.getElementById('reportFormTopic') || {}).value || null;
  var keyLearnings = ((document.getElementById('reportFormKeyLearnings') || {}).value || '').trim();
  if (!topicId) { alert('Please select a Topic / Area of Learning.'); return; }
  if (!keyLearnings) { alert('Key Learnings is required.'); return; }

  var employedAfter = (document.getElementById('reportFormEmployedAfter') || {}).value || null;
  var salaryStr     = (document.getElementById('reportFormMonthlySalary') || {}).value || '';
  // Only send a salary number when the FLP was employed after the
  // internship; otherwise it's noise even if the input briefly held a
  // value before the user changed Employment to "No".
  var monthlySalary = (employedAfter === 'Yes' && salaryStr.trim() !== '')
    ? parseFloat(salaryStr) : null;
  var payload = {
    topic_id: parseInt(topicId),
    description: (document.getElementById('reportFormDescription') || {}).value || null,
    key_learnings: keyLearnings,
    challenges: (document.getElementById('reportFormChallenges') || {}).value || null,
    employed_after: employedAfter,
    monthly_salary: monthlySalary,
  };

  var statusEl = document.getElementById('reportFormStatus');
  if (statusEl) statusEl.textContent = 'Saving report...';

  apiCreateInternshipReport(aid, payload).then(function(resp) {
    var reportId = resp.id;
    // Read from the accumulated picked-lists (not from input.files, which only holds the last picker batch).
    var allFiles = [];
    (_reportPickedDocs || []).forEach(function(f) { allFiles.push({ kind: 'doc', file: f }); });
    (_reportPickedImages || []).forEach(function(f) { allFiles.push({ kind: 'image', file: f }); });

    if (!allFiles.length) return Promise.resolve([]);

    // Upload SEQUENTIALLY. Parallel + multipart can race the file-save on some
    // FastAPI configs; serial is bulletproof and gives us clear per-file progress.
    var results = [];
    var failures = [];
    var chain = Promise.resolve();
    allFiles.forEach(function(entry, idx) {
      chain = chain.then(function() {
        if (statusEl) statusEl.textContent =
          'Uploading ' + (idx + 1) + ' of ' + allFiles.length + ': ' + (entry.file.name || 'file');
        return apiUploadInternshipReportFile(reportId, entry.kind, entry.file)
          .then(function(r) { results.push(r); })
          .catch(function(e) { failures.push({ name: entry.file.name, err: (e && e.message) || String(e) }); });
      });
    });
    return chain.then(function() { return { reportId: reportId, ok: results, failed: failures }; });
  }).then(function(result) {
    closeMasterModal('internshipReportFormModal');
    if (result && result.failed && result.failed.length) {
      alert(
        'Report saved — uploaded ' + (result.ok ? result.ok.length : 0) + ' of ' +
        ((result.ok ? result.ok.length : 0) + result.failed.length) + ' file(s).\n\nFailed:\n' +
        result.failed.map(function(f) { return '• ' + f.name + ' — ' + f.err; }).join('\n')
      );
    } else {
      alert('Report saved!');
    }
    // Refresh whichever page is active
    var listActive = document.getElementById('page-internshipAssignment') && document.getElementById('page-internshipAssignment').classList.contains('active');
    var viewActive = document.getElementById('page-viewInternship') && document.getElementById('page-viewInternship').classList.contains('active');
    if (viewActive) loadViewInternship();
    else if (listActive) loadInternshipListData(internshipCurrentPage);
  }).catch(function(err) { showUserError('saving report', err); });
}

// =============================================================================
// SANGINI (AK) — monthly entries
