var sanginiCurrentPage = 1, sanginiPageLimit = 10;
var editingSanginiId = null;
var viewingSanginiId = null;
var _sanginiFilterNamesLoaded = false;
var _sanginiFilterMonthsLoaded = false;
var _sanginiNameListLoaded = false;

function _monthLabel(ym) {
  if (!ym) return '—';
  // ym = 'YYYY-MM'
  var parts = ym.split('-');
  if (parts.length < 2) return ym;
  var names = ['January','February','March','April','May','June','July','August','September','October','November','December'];
  var m = parseInt(parts[1], 10);
  return names[m - 1] + ' ' + parts[0];
}

function loadSanginiListData(page) {
  if (typeof page === 'number') sanginiCurrentPage = page;
  if (!_sanginiFilterMonthsLoaded) { _sanginiFilterMonthsLoaded = true; _populateSanginiFilterMonths(); }
  if (!_sanginiFilterNamesLoaded)  { _sanginiFilterNamesLoaded = true;  _populateSanginiFilterNames(); }

  var month = (document.getElementById('sanginiFilterMonth') || {}).value || '';
  var name = (document.getElementById('sanginiFilterName') || {}).value || '';
  var params = { page: sanginiCurrentPage, limit: sanginiPageLimit };
  if (month) params.month = month;
  if (name) params.sangini_name = name;

  apiSanginiList(params).then(function(resp) {
    var rows = resp.data || [];
    var total = resp.total || 0;
    var tbody = document.getElementById('sanginiListTableBody');
    if (!tbody) return;
    if (!rows.length) {
      tbody.innerHTML = '<tr><td colspan="8" style="text-align:center;color:#999;padding:30px;">No Sangini records found. Click <b>+ Add Sangini</b> to get started.</td></tr>';
      var pag = document.querySelector('#page-akSangini .pagination');
      if (pag) pag.textContent = 'Showing 0 of 0';
      return;
    }
    var html = '';
    var _canDel = _canDeleteRecord();
    rows.forEach(function(r, idx) {
      var sno = (sanginiCurrentPage - 1) * sanginiPageLimit + idx + 1;
      var _safeName = escHtml(r.sangini_name || '').replace(/\'/g, "\\'");
      // 2026-06-01: Phone Calls column removed from list per user
      // request (it was already removed from the Add/Edit form 2026-
      // 05-30). The DB column stays for legacy reads.
      html += '<tr>' +
        '<td>' + sno + '</td>' +
        '<td><strong>' + escHtml(r.sangini_name) + '</strong></td>' +
        '<td>' + escHtml(r.month_label || _monthLabel(r.month_ym)) + '</td>' +
        '<td>' + (parseInt(r.active_leaders) || 0) + '</td>' +
        '<td>' + (parseInt(r.active_addas) || 0) + '</td>' +
        '<td>' + (parseInt(r.home_visits) || 0) + '</td>' +
        '<td>' + (parseInt(r.choupals) || 0) + '</td>' +
        '<td style="white-space:nowrap;">' +
          '<button class="btn-icon" title="View" onclick="navigateToViewSangini(' + r.id + ')"><i class="fas fa-eye"></i></button>' +
          '<button class="btn-icon" title="Edit" onclick="openSanginiForm(\'edit\',' + r.id + ')"><i class="fas fa-edit"></i></button>' +
          (_canDel ? '<button class="btn-icon text-danger" title="Delete" onclick="deleteSanginiFromList(' + r.id + ',\'' + _safeName + '\')"><i class="fas fa-trash-alt"></i></button>' : '') +
        '</td>' +
      '</tr>';
    });
    tbody.innerHTML = html;
    renderListPagination('#page-akSangini .pagination', total, sanginiCurrentPage, sanginiPageLimit, 'loadSanginiListData');
  }).catch(function(err) { showUserError('loading Sangini list', err); });
}

function applySanginiFilters() { sanginiCurrentPage = 1; loadSanginiListData(1); }
function resetSanginiFilters() {
  _clearListFilters('akSangini');
  ['sanginiFilterMonth','sanginiFilterName'].forEach(function(id){ var el = document.getElementById(id); if (el) el.value = ''; });
  sanginiCurrentPage = 1; loadSanginiListData(1);
}

function _populateSanginiFilterMonths() {
  var sel = document.getElementById('sanginiFilterMonth');
  if (!sel) return;
  apiSanginiMonths().then(function(rows) {
    // Keep the "All Months" placeholder, then distinct months from data
    sel.innerHTML = '<option value="">All Months</option>';
    (rows || []).forEach(function(r) {
      var opt = document.createElement('option');
      opt.value = r.ym; opt.textContent = r.label;
      sel.appendChild(opt);
    });
    // Fallback: if no entries yet, seed with a range of recent months for UX
    if (!rows || !rows.length) {
      var now = new Date();
      for (var i = 0; i < 12; i++) {
        var d = new Date(now.getFullYear(), now.getMonth() - i, 1);
        var ym = d.getFullYear() + '-' + String(d.getMonth() + 1).padStart(2, '0');
        var opt = document.createElement('option');
        opt.value = ym; opt.textContent = _monthLabel(ym);
        sel.appendChild(opt);
      }
    }
  }).catch(function() {});
}

function _populateSanginiFilterNames() {
  var sel = document.getElementById('sanginiFilterName');
  if (!sel) return;
  apiSanginiNames().then(function(names) {
    sel.innerHTML = '<option value="">All Sanginis</option>';
    (names || []).forEach(function(n) {
      var opt = document.createElement('option');
      opt.value = n; opt.textContent = n;
      sel.appendChild(opt);
    });
  }).catch(function() {});
}

function exportSanginiToExcel() {
  var qs = [];
  var m = (document.getElementById('sanginiFilterMonth') || {}).value;
  var n = (document.getElementById('sanginiFilterName') || {}).value;
  if (m) qs.push('month=' + encodeURIComponent(m));
  if (n) qs.push('sangini_name=' + encodeURIComponent(n));
  window.location.href = API_BASE + '/sangini/export/excel' + (qs.length ? '?' + qs.join('&') : '');
}

