function switchSanginiTab(tabId) {
  document.querySelectorAll('#page-addSangini .tab-content').forEach(function(t) { t.classList.remove('active'); });
  document.querySelectorAll('#page-addSangini .tab-btn').forEach(function(b) { b.classList.remove('active'); });
  var pane = document.getElementById('sanginiTab-' + tabId);
  if (pane) pane.classList.add('active');
  var btnIdx = (tabId === 'basic') ? 0 : 1;
  var btns = document.querySelectorAll('#page-addSangini .tab-btn');
  if (btns[btnIdx]) btns[btnIdx].classList.add('active');
}

function _resetSanginiForm() {
  ['sanginiFormName','sanginiFormBatch','sanginiFormMonth','sanginiFormAddaId',
   'sanginiFormActiveLeaders','sanginiFormActiveAddas','sanginiFormActiveAddaMembers',
   'sanginiFormHomeVisits','sanginiFormHvParticipants','sanginiFormHvMale','sanginiFormHvFemale',
   'sanginiFormChoupals','sanginiFormChParticipants','sanginiFormChMale','sanginiFormChFemale',
  ].forEach(function(id) { var el = document.getElementById(id); if (el) el.value = ''; });
  var body = document.getElementById('sanginiFormTrainingsBody');
  if (body) body.innerHTML = '';
  // Reset the Name dropdown to its placeholder option (its options are
  // refilled by _populateSanginiAddaDropdown / on edit hydration).
  var sel = document.getElementById('sanginiFormName');
  if (sel) sel.selectedIndex = 0;
  var bSel = document.getElementById('sanginiFormBatch');
  if (bSel) bSel.selectedIndex = 0;
  var hint = document.getElementById('sanginiReuseHint');
  if (hint) hint.style.display = 'none';
  switchSanginiTab('basic');
}

// 2026-05-30: Name of Sangini is now a SELECT populated from the Adda
// Profile (one option per active Adda). When the user picks a Sangini,
// the three count fields (Active Leaders / Active Addas / Active Adda
// Members) auto-fill from the chosen Adda's centre-scope aggregates,
// served by /api/sangini/adda-profiles. The cached _sanginiAddaProfiles
// keeps onSanginiAddaChange synchronous after the initial fetch.
var _sanginiAddaProfiles = [];

function _populateSanginiAddaDropdown(force) {
  var sel = document.getElementById('sanginiFormName');
  if (!sel) return Promise.resolve();
  // Re-fetch only when not yet loaded or caller explicitly asks; the
  // Add/Edit form lifecycle resets the form but keeps the option list
  // because the source data (Adda profiles) is independent of the form.
  if (_sanginiAddaProfiles.length && !force) return Promise.resolve(_sanginiAddaProfiles);
  return apiSanginiAddaProfiles().then(function(resp) {
    var rows = (resp && resp.data) || [];
    // 2026-06-06: For State Lead, restrict the Sangini dropdown to
    // Addas in their assigned state — Delhi SL sees only East/North/
    // South Delhi Sanginis, Rajasthan SL sees only Rajasthan, etc.
    // Filter is client-side because the backend /api/sangini/adda-
    // profiles endpoint returns the full list; the role-scope helper
    // doesn't yet flow into this endpoint. If the row lacks a
    // state_code (legacy data) we keep it visible rather than hide
    // it silently.
    //
    // 2026-06-08 (round 9): DL + PI now also restrict — for North
    // Delhi PI, only Sanginis whose adda belongs to the North Delhi
    // centre are shown. Falls back to district scope for DL when
    // centre_code isn't resolved, and state scope when neither is.
    if (currentUser && currentUser.role === 'state_lead' && currentUser.state_code) {
      var sc = currentUser.state_code;
      rows = rows.filter(function(r) {
        return !r.state_code || r.state_code === sc;
      });
    } else if (currentUser &&
               (currentUser.role === 'pi' || currentUser.role === 'district_lead')) {
      var cc = currentUser.centre_code;
      var dc = currentUser.district_code;
      var sc2 = currentUser.state_code;
      if (cc) {
        rows = rows.filter(function(r) { return !r.centre_code || r.centre_code === cc; });
      } else if (dc) {
        rows = rows.filter(function(r) { return !r.district_code || r.district_code === dc; });
      } else if (sc2) {
        rows = rows.filter(function(r) { return !r.state_code || r.state_code === sc2; });
      }
    }
    _sanginiAddaProfiles = rows;
    // Always rebuild the options list so a refresh picks up new Addas.
    var first = sel.options[0]; // keep the "-- Select --" placeholder
    sel.innerHTML = '';
    if (first) sel.appendChild(first);
    // 2026-06-06: Dedupe by Sangini name (case-insensitive trim) per
    // user spec — "name of sangini should be unique". A Sangini can be
    // associated with multiple Addas (different centres), and a centre
    // could potentially have two Addas with the same Sangini; we want
    // her listed exactly once. The first hit's adda_id wins (matches
    // the backend's existing (sangini_name, centre_code) dedupe order).
    var seenNames = {};
    rows.forEach(function(r) {
      var rawName = (r.sangini_name || '').trim();
      var nameKey = rawName.toLowerCase();
      if (!nameKey || seenNames[nameKey]) return;
      seenNames[nameKey] = 1;
      var opt = document.createElement('option');
      opt.value = String(r.adda_id);
      // Show the Sangini name with the centre in parens so the user
      // sees which centre this Sangini's first Adda belongs to.
      var loc = r.centre_name ? ' (' + r.centre_name + ')' : '';
      opt.textContent = rawName + loc;
      opt.setAttribute('data-sangini-name', rawName);
      opt.setAttribute('data-active-leaders', String(r.active_leaders || 0));
      opt.setAttribute('data-active-addas',   String(r.active_addas   || 0));
      opt.setAttribute('data-active-members', String(r.active_adda_members || 0));
      sel.appendChild(opt);
    });
    return rows;
  }).catch(function() { return []; });
}

function onSanginiAddaChange() {
  // 2026-06-02: First-time Add no longer auto-fills the 3 counts from
  // Adda-profile aggregates. The Sangini cycle now works as:
  //   - Pick Name of Sangini + Batch
  //   - If (name, batch) combo already exists, _lookupSanginiReuse() pulls
  //     the last record's 3 counts so the user can revise them for the
  //     new reporting period.
  //   - Otherwise all 3 counts stay blank for manual entry.
  // We still capture the adda_id from the option (it's stored for cross-
  // referencing in the backend payload) but no longer pre-populate counts.
  var sel = document.getElementById('sanginiFormName');
  var hid = document.getElementById('sanginiFormAddaId');
  if (!sel) return;
  var opt = sel.options[sel.selectedIndex];
  if (hid) hid.value = (opt && opt.value) ? opt.value : '';
  // Trigger the reuse lookup when both Name and Batch are now set.
  _lookupSanginiReuse();
}

// 2026-06-02: When (Name of Sangini, Batch) already exists in the
// system, the 3 count fields pre-fill from the most recent saved
// record so the user just updates the new-cycle deltas. If no prior
// record matches, all 3 stay blank and editable for first-time entry.
function _lookupSanginiReuse() {
  var nameSel = document.getElementById('sanginiFormName');
  var batchSel = document.getElementById('sanginiFormBatch');
  var leadersEl = document.getElementById('sanginiFormActiveLeaders');
  var addasEl   = document.getElementById('sanginiFormActiveAddas');
  var membersEl = document.getElementById('sanginiFormActiveAddaMembers');
  var hint = document.getElementById('sanginiReuseHint');
  if (!nameSel || !batchSel) return;
  var nameOpt = nameSel.options[nameSel.selectedIndex];
  var name = nameOpt ? (nameOpt.getAttribute('data-sangini-name') || '').trim() : '';
  var batch = (batchSel.value || '').trim();
  if (!name || !batch) {
    if (hint) hint.style.display = 'none';
    return;
  }
  var xhr = new XMLHttpRequest();
  xhr.open('GET', window.location.origin +
    '/api/sangini/reuse-lookup?sangini_name=' + encodeURIComponent(name) +
    '&batch=' + encodeURIComponent(batch), true);
  xhr.onload = function() {
    if (xhr.status === 200) {
      try {
        var d = JSON.parse(xhr.responseText);
        if (d && d.found) {
          if (leadersEl) leadersEl.value = d.active_leaders != null ? d.active_leaders : '';
          if (addasEl)   addasEl.value   = d.active_addas != null ? d.active_addas : '';
          if (membersEl) membersEl.value = d.active_adda_members != null ? d.active_adda_members : '';
          if (hint) hint.style.display = 'block';
        } else {
          // No prior record — leave any user-entered values intact in case
          // the user has already started typing. The hint stays hidden.
          if (hint) hint.style.display = 'none';
        }
      } catch (e) { /* silent — fall through to manual entry */ }
    }
  };
  xhr.send();
}

// 2026-06-02: Populate the Batch dropdown on the Sangini form. Lists
// all active AK batches globally (no state/centre scope — the user
// can pick any active batch for the reuse cycle lookup).
function _loadSanginiBatchOptions(selectedBatch) {
  var sel = document.getElementById('sanginiFormBatch');
  if (!sel) return;
  apiAkBatchList({ status: 'Active', limit: 500 }).then(function(resp) {
    var rows = (resp && resp.data) || resp || [];
    // Reset to placeholder.
    sel.innerHTML = '<option value="">-- Select Batch --</option>';
    rows.forEach(function(b) {
      var opt = document.createElement('option');
      // We send the batch NAME as the value (not id) because sangini_entries
      // stores a free-text VARCHAR — that survives batch-id renames and
      // keeps the (name, batch) composite key human-readable.
      opt.value = b.name || b.batch_name || '';
      opt.textContent = opt.value;
      sel.appendChild(opt);
    });
    if (selectedBatch) {
      // Inject a fallback option if the saved batch isn't in the current
      // active list (legacy / renamed batch).
      var found = false;
      for (var i = 0; i < sel.options.length; i++) {
        if (sel.options[i].value === selectedBatch) { found = true; break; }
      }
      if (!found) {
        var extra = document.createElement('option');
        extra.value = selectedBatch;
        extra.textContent = selectedBatch + ' (legacy)';
        sel.appendChild(extra);
      }
      sel.value = selectedBatch;
    }
  }).catch(function() { /* leave just the placeholder */ });
}

// 2026-06-04: Sangini Capacity Training rows now use a dropdown
// (Feminist Way of Mentoring / Community Mobilization / Perspective
// Building on Adolescents / Other) instead of the previous free-text
// input. When "Other" is selected, an inline Specify input appears
// to the RIGHT of the dropdown inside the SAME <td> (flex layout).
// Legacy rows whose saved training_name isn't in the 4 canonical
// options are preserved by injecting a one-off "(legacy)" option so
// the saved value still renders without data loss.
function addSanginiTrainingRow(name, dateStr, customName) {
  var body = document.getElementById('sanginiFormTrainingsBody');
  if (!body) return;
  var CANONICAL = ['Feminist Way of Mentoring', 'Community Mobilization',
                   'Perspective Building on Adolescents', 'Other'];
  var saved = (name || '').trim();
  var legacyOpt = '';
  if (saved && CANONICAL.indexOf(saved) === -1) {
    legacyOpt = '<option value="' + escHtml(saved) + '" selected>' + escHtml(saved) + ' (legacy)</option>';
  }
  var options = '<option value="">Select Training</option>' +
    CANONICAL.map(function(o) {
      var sel = (saved === o) ? ' selected' : '';
      return '<option value="' + escHtml(o) + '"' + sel + '>' + escHtml(o) + '</option>';
    }).join('') + legacyOpt;
  var showSpecify = (saved === 'Other');
  var custom = customName ? escHtml(customName) : '';
  var tr = document.createElement('tr');
  tr.innerHTML =
    '<td>' +
      '<div style="display:flex;gap:8px;align-items:center;">' +
        '<select class="sangini-tr-name" onchange="onSanginiTrainingNameChange(this)" ' +
          'style="flex:0 0 240px;padding:6px 8px;border:1px solid #ddd;border-radius:4px;background:#fff;">' +
          options +
        '</select>' +
        '<input type="text" class="sangini-tr-name-other" placeholder="Specify if other" maxlength="100" ' +
          'value="' + custom + '" ' +
          'style="flex:1;min-width:160px;padding:6px 8px;border:1px solid #ddd;border-radius:4px;' +
          (showSpecify ? '' : 'display:none;') + '">' +
      '</div>' +
    '</td>' +
    '<td><input type="date" class="sangini-tr-date" style="width:100%;padding:6px 8px;border:1px solid #ddd;border-radius:4px;" value="' + (dateStr ? escHtml(dateStr) : '') + '"></td>' +
    '<td style="text-align:center;"><button type="button" class="btn-icon text-danger" title="Remove" onclick="this.closest(\'tr\').remove()"><i class="fas fa-trash-alt"></i></button></td>';
  body.appendChild(tr);
}

// 2026-06-04: toggle the inline Specify input next to a Capacity
// Training dropdown based on whether 'Other' is selected. The Specify
// input lives in the SAME flex container; we only flip its display
// style. When Other is unselected, also clear the value so it doesn't
// silently submit a stale custom name.
function onSanginiTrainingNameChange(selectEl) {
  if (!selectEl) return;
  var wrap = selectEl.parentNode;
  if (!wrap) return;
  var specify = wrap.querySelector('.sangini-tr-name-other');
  if (!specify) return;
  if (selectEl.value === 'Other') {
    specify.style.display = '';
    if (specify.focus) try { specify.focus(); } catch (e) {}
  } else {
    specify.style.display = 'none';
    specify.value = '';
  }
}

function openSanginiForm(mode, id) {
  editingSanginiId = (mode === 'edit') ? id : null;
  _resetSanginiForm();
  // 2026-05-30: Load Adda profiles for the Name dropdown before
  // hydrating edit mode so the saved sangini_name can be matched to an
  // option (we fall back to a free-text option when the saved name
  // doesn't appear in the current Adda list — e.g. legacy entries).
  var profilesP = _populateSanginiAddaDropdown();
  var submit = document.getElementById('sanginiFormSubmitText');
  var bc = document.getElementById('addSanginiBreadcrumb');
  // 2026-06-02: Load active AK batches for the new Batch dropdown. On
  // edit mode we set the saved batch as the pre-selected value after
  // detail loads so the reuse hint can fire immediately.
  if (mode !== 'edit') _loadSanginiBatchOptions();
  // Hide the reuse hint until a (Name, Batch) match is confirmed.
  var hintEl = document.getElementById('sanginiReuseHint');
  if (hintEl) hintEl.style.display = 'none';

  if (mode === 'edit') {
    if (submit) submit.textContent = 'Update';
    if (bc) bc.innerHTML = '<a href="#" onclick="navigateTo(\'akHome\');return false;"><i class="fas fa-home"></i> Home</a> <span class="bc-sep">&rsaquo;</span> <a href="#" onclick="navigateTo(\'akSangini\');return false;">Sangini List</a> <span class="bc-sep">&rsaquo;</span> Edit Sangini';
    navigateTo('addSangini');
    Promise.all([profilesP, apiSanginiDetail(id)]).then(function(parts) {
      var r = parts[1];
      document.getElementById('sanginiFormMonth').value = r.month_ym || '';
      // 2026-06-02: hydrate the new Batch dropdown with the saved value.
      _loadSanginiBatchOptions(r.batch || '');
      // Match the saved sangini_name to an option in the dropdown; if
      // no Adda profile carries that name today, append a one-off
      // option so the edit form can render the legacy value without
      // silently dropping it.
      var sel = document.getElementById('sanginiFormName');
      var saved = (r.sangini_name || '').trim().toLowerCase();
      var matched = false;
      if (sel) {
        for (var i = 0; i < sel.options.length; i++) {
          var oName = (sel.options[i].getAttribute('data-sangini-name') || '').trim().toLowerCase();
          if (oName && oName === saved) {
            sel.selectedIndex = i; matched = true; break;
          }
        }
        if (!matched && r.sangini_name) {
          var extra = document.createElement('option');
          extra.value = '__legacy__';
          extra.textContent = r.sangini_name + ' (legacy)';
          extra.setAttribute('data-sangini-name', r.sangini_name);
          sel.appendChild(extra);
          sel.value = '__legacy__';
        }
      }
      document.getElementById('sanginiFormAddaId').value             = matched ? (sel.value || '') : '';
      document.getElementById('sanginiFormActiveLeaders').value      = r.active_leaders != null ? r.active_leaders : '';
      document.getElementById('sanginiFormActiveAddas').value        = r.active_addas != null ? r.active_addas : '';
      document.getElementById('sanginiFormActiveAddaMembers').value  = r.active_adda_members != null ? r.active_adda_members : '';
      document.getElementById('sanginiFormHomeVisits').value         = r.home_visits != null ? r.home_visits : '';
      document.getElementById('sanginiFormHvParticipants').value     = r.home_visit_participants != null ? r.home_visit_participants : '';
      document.getElementById('sanginiFormHvMale').value             = r.home_visit_male != null ? r.home_visit_male : '';
      document.getElementById('sanginiFormHvFemale').value           = r.home_visit_female != null ? r.home_visit_female : '';
      document.getElementById('sanginiFormChoupals').value           = r.choupals != null ? r.choupals : '';
      document.getElementById('sanginiFormChParticipants').value     = r.choupal_participants != null ? r.choupal_participants : '';
      document.getElementById('sanginiFormChMale').value             = r.choupal_male != null ? r.choupal_male : '';
      document.getElementById('sanginiFormChFemale').value           = r.choupal_female != null ? r.choupal_female : '';
      var body = document.getElementById('sanginiFormTrainingsBody');
      if (body) body.innerHTML = '';
      // 2026-06-04: pass through the saved custom name so the Specify
      // input rehydrates when training_name === 'Other'.
      (r.trainings || []).forEach(function(t) {
        addSanginiTrainingRow(
          t.training_name,
          t.training_date ? String(t.training_date).substring(0, 10) : '',
          t.custom_training_name || ''
        );
      });
    }).catch(function(err) { showUserError('loading Sangini record', err); });
  } else {
    if (submit) submit.textContent = 'Save';
    if (bc) bc.innerHTML = '<a href="#" onclick="navigateTo(\'akHome\');return false;"><i class="fas fa-home"></i> Home</a> <span class="bc-sep">&rsaquo;</span> <a href="#" onclick="navigateTo(\'akSangini\');return false;">Sangini List</a> <span class="bc-sep">&rsaquo;</span> Add Sangini';
    navigateTo('addSangini');
  }
}

function saveSangini() {
  var v = function(id) { var el = document.getElementById(id); return el ? (el.value || '').trim() : ''; };
  var n = function(id) { var s = v(id); return s === '' ? null : parseInt(s, 10); };

  var month = v('sanginiFormMonth');
  // 2026-05-30: Name now comes from the dropdown — extract the
  // displayed Sangini name via the selected option's data attribute
  // (the option value is the adda_id, not the name).
  var sel = document.getElementById('sanginiFormName');
  var selOpt = sel ? sel.options[sel.selectedIndex] : null;
  var name = selOpt ? (selOpt.getAttribute('data-sangini-name') || '').trim() : '';
  // 2026-06-02: Batch added as a required composite-key field so the reuse
  // lookup (Name + Batch) can disambiguate cycles. Counts are user-entered.
  var batch   = v('sanginiFormBatch');
  var leaders = v('sanginiFormActiveLeaders');
  var addas   = v('sanginiFormActiveAddas');
  var addaMem = v('sanginiFormActiveAddaMembers');

  if (!name)            { alert('Please select Name of Sangini.'); switchSanginiTab('basic'); return; }
  if (!batch)           { alert('Please select Batch.'); switchSanginiTab('basic'); return; }
  if (leaders === '')   { alert('Please enter Number of Active Leaders.'); switchSanginiTab('basic'); return; }
  if (addas === '')     { alert('Please enter Number of Active Addas.');   switchSanginiTab('basic'); return; }
  if (addaMem === '')   { alert('Please enter Number of Active Adda Members.'); switchSanginiTab('basic'); return; }
  if (!month)           { alert('Please select Month.'); switchSanginiTab('basic'); return; }

  // 2026-05-30: Activities — Participants required in both sections,
  // and Male + Female must equal Total Participants (sum check). The
  // checks run AFTER Basic Details so the user fixes top-down. Empty
  // Male / Female default to 0 for the sum (matches payload semantics).
  var hvP = n('sanginiFormHvParticipants');
  var chP = n('sanginiFormChParticipants');
  if (hvP === null) {
    alert('Number of Participants is required in Home Visits.');
    switchSanginiTab('activities');
    var hp = document.getElementById('sanginiFormHvParticipants'); if (hp && hp.focus) hp.focus();
    return;
  }
  if (chP === null) {
    alert('Number of Participants is required in Choupal.');
    switchSanginiTab('activities');
    var cp = document.getElementById('sanginiFormChParticipants'); if (cp && cp.focus) cp.focus();
    return;
  }
  var hvM = n('sanginiFormHvMale')   || 0;
  var hvF = n('sanginiFormHvFemale') || 0;
  var chM = n('sanginiFormChMale')   || 0;
  var chF = n('sanginiFormChFemale') || 0;
  if (hvM + hvF !== hvP) {
    alert('Home Visits: Male (' + hvM + ') + Female (' + hvF + ') = ' + (hvM + hvF) +
          ' does not match Number of Participants (' + hvP + '). Please correct the values so they add up.');
    switchSanginiTab('activities');
    var hpx = document.getElementById('sanginiFormHvMale'); if (hpx && hpx.focus) hpx.focus();
    return;
  }
  if (chM + chF !== chP) {
    alert('Choupal: Male (' + chM + ') + Female (' + chF + ') = ' + (chM + chF) +
          ' does not match Number of Participants (' + chP + '). Please correct the values so they add up.');
    switchSanginiTab('activities');
    var cpx = document.getElementById('sanginiFormChMale'); if (cpx && cpx.focus) cpx.focus();
    return;
  }

  // 2026-06-04: Capacity Training rows now use a dropdown. Per spec:
  //   - Each row that exists in the table must have a training picked
  //     ("Please select a training.").
  //   - When training is "Other", the inline Specify input is required
  //     ("Please specify the training name.").
  //   - Custom name is trimmed + capped at 100 chars on the frontend
  //     (HTML maxlength=100 + slice here as belt-and-braces).
  //   - Payload carries both training_name and custom_training_name;
  //     backend nulls custom_training_name when training != 'Other'.
  // If the user opened the screen but never touched the dropdown on a
  // row, we treat that row as a stray (no selection, no date, no
  // specify) and silently drop it instead of blocking the Save —
  // matches the old "drop empty rows" behaviour for backward compat.
  var trainings = [];
  var capRows = document.querySelectorAll('#sanginiFormTrainingsBody tr');
  var capErr = null, capFocus = null;
  capRows.forEach(function(row) {
    if (capErr) return;
    var selEl = row.querySelector('.sangini-tr-name');
    var spEl  = row.querySelector('.sangini-tr-name-other');
    var dtEl  = row.querySelector('.sangini-tr-date');
    var tn = (selEl ? selEl.value : '').trim();
    var sp = (spEl  ? spEl.value  : '').trim();
    var td = (dtEl  ? dtEl.value  : '').trim();
    // Stray row (never touched) → skip silently.
    if (!tn && !sp && !td) return;
    if (!tn) {
      capErr = 'Please select a training.';
      capFocus = selEl;
      return;
    }
    if (tn === 'Other' && !sp) {
      capErr = 'Please specify the training name.';
      capFocus = spEl;
      return;
    }
    var cust = (tn === 'Other') ? sp.slice(0, 100) : null;
    trainings.push({
      training_name: tn,
      training_date: td || null,
      custom_training_name: cust
    });
  });
  if (capErr) {
    alert(capErr);
    switchSanginiTab('activities');
    if (capFocus && capFocus.focus) try { capFocus.focus(); } catch (e) {}
    return;
  }

  // phone_calls left at 0 — column kept in DB for backward compat with
  // pre-2026-05-30 entries; the Add/Edit form no longer collects it.
  var payload = {
    month: month,
    sangini_name: name,
    batch: batch,
    active_leaders:          parseInt(leaders, 10)  || 0,
    active_addas:            parseInt(addas, 10)    || 0,
    active_adda_members:     parseInt(addaMem, 10)  || 0,
    home_visits:             n('sanginiFormHomeVisits')     || 0,
    home_visit_participants: hvP,
    home_visit_male:         hvM,
    home_visit_female:       hvF,
    phone_calls:             0,
    choupals:                n('sanginiFormChoupals')       || 0,
    choupal_participants:    chP,
    choupal_male:            chM,
    choupal_female:          chF,
    trainings: trainings,
    status: 'Active',
  };

  var p = editingSanginiId ? apiUpdateSangini(editingSanginiId, payload) : apiCreateSangini(payload);
  p.then(function() {
    alert(editingSanginiId ? 'Sangini entry updated!' : 'Sangini entry saved!');
    // Invalidate cached filter lists so new name/month appears
    _sanginiFilterNamesLoaded = false; _sanginiFilterMonthsLoaded = false; _sanginiNameListLoaded = false;
    navigateTo('akSangini');
  }).catch(function(err) { showUserError('saving Sangini entry', err); });
}

// =============================================================================
// VIEW SANGINI (read-only)
