function navigateToViewSangini(id) {
  viewingSanginiId = id;
  _ctxSet('viewSangini', id);
  navigateTo('viewSangini');
}

function loadSanginiView() {
  if (!viewingSanginiId) { viewingSanginiId = _ctxGetInt('viewSangini'); }
  if (!viewingSanginiId) return;
  var id = viewingSanginiId;
  var editBtn = document.getElementById('viewSanginiEditBtn');
  if (editBtn) editBtn.onclick = function() { openSanginiForm('edit', id); };

  apiSanginiDetail(id).then(function(r) {
    document.getElementById('viewSanginiName').textContent = r.sangini_name || '—';
    document.getElementById('viewSanginiMonth').textContent = r.month_label || _monthLabel(r.month_ym);
    var sb = document.getElementById('viewSanginiStatus');
    if (sb) sb.innerHTML = statusBadge(r.status);

    var basic = document.getElementById('viewSanginiBasicGrid');
    if (basic) {
      basic.innerHTML =
        _detailCell('Sangini Name', r.sangini_name) +
        _detailCell('Month', r.month_label || _monthLabel(r.month_ym)) +
        _detailCell('Active Leaders', (r.active_leaders != null ? r.active_leaders : 0)) +
        _detailCell('Active Addas', (r.active_addas != null ? r.active_addas : 0)) +
        _detailCell('Active Adda Members', (r.active_adda_members != null ? r.active_adda_members : 0)) +
        _detailCell('Status', r.status);
    }

    var act = document.getElementById('viewSanginiActivitiesGrid');
    if (act) {
      act.innerHTML =
        _detailCell('Home Visits', r.home_visits != null ? r.home_visits : 0) +
        _detailCell('HV Participants', r.home_visit_participants != null ? r.home_visit_participants : 0) +
        _detailCell('HV Male', r.home_visit_male != null ? r.home_visit_male : 0) +
        _detailCell('HV Female', r.home_visit_female != null ? r.home_visit_female : 0) +
        _detailCell('Phone Calls', r.phone_calls != null ? r.phone_calls : 0) +
        _detailCell('Choupals', r.choupals != null ? r.choupals : 0) +
        _detailCell('Ch Participants', r.choupal_participants != null ? r.choupal_participants : 0) +
        _detailCell('Ch Male', r.choupal_male != null ? r.choupal_male : 0) +
        _detailCell('Ch Female', r.choupal_female != null ? r.choupal_female : 0);
    }

    var tb = document.getElementById('viewSanginiTrainingsBody');
    if (tb) {
      if (!r.trainings || !r.trainings.length) {
        tb.innerHTML = '<tr><td colspan="3" style="text-align:center;color:#999;padding:20px;">No trainings recorded.</td></tr>';
      } else {
        // 2026-06-04: surface the custom name when the row was saved
        // with training_name === 'Other'. Spec example: "For Other:
        // Training Name: Leadership Workshop" — i.e. show the typed
        // label, not the literal word "Other".
        tb.innerHTML = r.trainings.map(function(t, idx) {
          var d = t.training_date ? String(t.training_date).substring(0, 10) : '';
          var label = (t.training_name === 'Other' && t.custom_training_name)
                        ? t.custom_training_name
                        : (t.training_name || '');
          return '<tr>' +
            '<td>' + (idx + 1) + '</td>' +
            '<td>' + escHtml(label) + '</td>' +
            '<td>' + (d ? _fmtDate(d) : '—') + '</td>' +
          '</tr>';
        }).join('');
      }
    }
  }).catch(function(err) { showUserError('loading Sangini details', err); });
}

// =============================================================================
// MGJ OVERALL ACTIVITIES — monthly KPI tracker
// =============================================================================

var mgjActCurrentPage = 1, mgjActPageLimit = 10;
var editingMgjActId = null;
var viewingMgjActId = null;
var _mgjActCentresLoaded = false;
var _mgjActBatchesLoaded = false;
// chip buffers per kind (pakhwada / sports / assignment)
var _mgjActChips = { pakhwada: [], sports: [], assignment: [] };

var MGJ_ACT_FY_MONTHS_SHORT = ['Apr','May','Jun','Jul','Aug','Sep','Oct','Nov','Dec','Jan','Feb','Mar'];

function _mgjActMonthLabel(ym) {
  if (!ym) return '—';
  var p = ym.split('-');
  if (p.length < 2) return ym;
  var names = ['Jan','Feb','Mar','Apr','May','Jun','Jul','Aug','Sep','Oct','Nov','Dec'];
  var m = parseInt(p[1], 10);
  return names[m - 1] + '-' + p[0].slice(2);
}

function _mgjActFyRange(year) {
  // year = 'YYYY-YY'  → array of 12 'YYYY-MM' strings, Apr → Mar
  if (!year || year.indexOf('-') < 0) return [];
  var startYear = parseInt(year.split('-')[0], 10);
  var ms = [];
  for (var i = 0; i < 12; i++) {
    var monthIndex = (4 - 1 + i) % 12;       // 0-based
    var year_offset = i < 9 ? 0 : 1;          // Jan-Mar of next year
    var y = startYear + year_offset;
    ms.push(y + '-' + String(monthIndex + 1).padStart(2, '0'));
  }
  return ms;
}

// ---- LIST ----
function loadMgjActListData(page) {
  if (typeof page === 'number') mgjActCurrentPage = page;

  if (!_mgjActCentresLoaded) { _mgjActCentresLoaded = true; _mgjActPopulateCentreFilters(); }
  if (!_mgjActBatchesLoaded)  { _mgjActBatchesLoaded = true;  _mgjActPopulateBatchFilters(); }
  var year = (document.getElementById('mgjActFilterYear') || {}).value || '';
  var month = (document.getElementById('mgjActFilterMonth') || {}).value || '';
  var centre = (document.getElementById('mgjActFilterCentre') || {}).value || '';
  var batch = (document.getElementById('mgjActFilterBatch') || {}).value || '';
  var status = (document.getElementById('mgjActFilterStatus') || {}).value || '';

  var params = { page: mgjActCurrentPage, limit: mgjActPageLimit };
  if (year) params.year = year;
  if (month) params.month = month;
  if (centre) params.centre_code = centre;
  if (batch) params.batch_id = parseInt(batch, 10);
  if (status) params.status = status;
  params = _applyRoleScopeFloor(params, 'mgj');

  apiMgjMonthlyList(params).then(function(resp) {
    var rows = resp.data || []; var total = resp.total || 0;
    var tbody = document.getElementById('mgjActListTableBody');
    if (!tbody) return;
    if (!rows.length) {
      tbody.innerHTML = '<tr><td colspan="10" style="text-align:center;color:#999;padding:30px;">No Overall Activities entries found. Click <b>+ Add Activities</b> to start.</td></tr>';
      var pag = document.querySelector('#page-mgjActivitiesList .pagination');
      if (pag) pag.textContent = 'Showing 0 of 0';
      return;
    }
    tbody.innerHTML = rows.map(function(r, i) {
      var sno = (mgjActCurrentPage - 1) * mgjActPageLimit + i + 1;
      var pak = (parseInt(r.pakhwada_planned) || 0) + ' / ' + (parseInt(r.pakhwada_conducted) || 0);
      var sports = parseInt(r.sports_sessions) || 0;
      var pmTotal = parseInt(r.parent_meeting_total) || 0;
      var pmM = parseInt(r.parent_meeting_male) || 0;
      var pmF = parseInt(r.parent_meeting_female) || 0;
      var camp = parseInt(r.campaign_count) || 0;
      var lead = parseInt(r.leader_community_actions) || 0;
      return '<tr>' +
        '<td>' + sno + '</td>' +
        '<td><strong>' + escHtml(r.month_label || _mgjActMonthLabel(r.month_ym)) + '</strong></td>' +
        '<td>' + escHtml(r.centre_name || r.centre_code || '—') + '</td>' +
        '<td>' + escHtml(r.batch_name || '—') + '</td>' +
        '<td style="text-align:center;">' + pak + '</td>' +
        '<td style="text-align:center;">' + sports + '</td>' +
        '<td style="text-align:center;">' + pmTotal + '<br><small style="color:#888;">' + pmM + 'M / ' + pmF + 'F</small></td>' +
        '<td style="text-align:center;">' + camp + '</td>' +
        '<td style="text-align:center;">' + lead + '</td>' +
        '<td style="text-align:center;white-space:nowrap;">' +
          '<button class="btn-icon" title="View" onclick="navigateToViewMgjActivity(' + r.id + ')"><i class="fas fa-eye"></i></button> ' +
          '<button class="btn-icon" title="Edit" onclick="openMgjActivityForm(\'edit\',' + r.id + ')"><i class="fas fa-edit"></i></button> ' +
          '<button class="btn-icon text-danger" title="Delete" onclick="deleteMgjActivity(' + r.id + ')"><i class="fas fa-trash-alt"></i></button>' +
        '</td>' +
      '</tr>';
    }).join('');
    renderListPagination('#page-mgjActivitiesList .pagination', total, mgjActCurrentPage, mgjActPageLimit, 'loadMgjActListData');
  }).catch(function(err) { showUserError('loading Overall Activities list', err); });
}

