// English-side chrome strings — paired with the i18n bank so the renderer
// can do a uniform lookup. The English `__sections` already matches the
// existing _mgjAfPrettySection map.
var MGJ_AF_I18N_EN = {
  __chrome: {
    langLabel: { en: 'English', hi: 'Hindi', bn: 'Bangla' },
    fromProfile: '(from profile)',
    submittedRO:  'Submitted — read-only.',
    pendingSection: 'Question content for this section is pending.',
    selectPlaceholder: '-- Select --',
    answerRequired: 'Please answer',
    submitErrorHeading: 'Please fill the missing required questions.',
    // 2026-06-01: English source-of-truth for footer + status chrome.
    breadcrumbHome:   'Home',
    breadcrumbAssessment: 'Assessment',
    btnBackToList:    'Back to List',
    btnPrevious:      'Previous',
    btnNext:          'Next',
    btnSaveDraft:     'Save Draft',
    btnSubmit:        'Submit Assessment',
    languageLabel:    'Language:',
    statusSaving:        'Saving…',
    statusDraftSavedAt:  'Draft saved at',
    statusSaveFailedRetry: 'Save failed — will retry on next change.',
    statusDraftSavedTime:  'Draft saved at'
  },
  __scale: {
    '1': 'Strongly Disagree', '2': 'Disagree', '3': 'Neutral',
    '4': 'Agree',             '5': 'Strongly Agree'
  },
  __sections: {
    demographic: 'Demographic', knowledge: 'Knowledge',
    attitudes:   'Attitudes (Beliefs & Perceptions)',
    situational: 'Situational & Emotional',
    practices:   'Practices (Behaviours)',
    vignettes:   'Vignettes (Scenarios)',
    community:   'Community Engagement'
  }
};

// Banks indexed by language code so the renderer can pick one at run time.
// `null` lookups (a question id missing from a translation table) fall back
// to the English label/option text — we never silently render a blank.
var MGJ_AF_I18N = { en: MGJ_AF_I18N_EN, hi: MGJ_AF_I18N_HI, bn: MGJ_AF_I18N_BN };

// Currently-selected display language (persisted across page loads via
// localStorage so the surveyor's preference survives a hard refresh).
var _mgjAfLang = (function() {
  try { return localStorage.getItem('mgjAfLang') || 'en'; } catch (e) { return 'en'; }
})();
function _mgjAfSetLang(lang) {
  if (lang !== 'en' && lang !== 'hi' && lang !== 'bn') return;
  _mgjAfLang = lang;
  try { localStorage.setItem('mgjAfLang', lang); } catch (e) {}
}

// Look up the translation for a question label / option / scale value /
// section name / chrome string. ALWAYS returns the English string when no
// translation has been provided for the current language, so the form is
// never blank.
function _mgjAfTr(qid, kind, key) {
  var bank = MGJ_AF_I18N[_mgjAfLang] || MGJ_AF_I18N_EN;
  var enBank = MGJ_AF_I18N_EN;
  if (kind === 'label') {
    return (bank[qid] && bank[qid].label) || (enBank[qid] && enBank[qid].label) || '';
  }
  if (kind === 'option') {
    var langOpt = bank[qid] && bank[qid].options && bank[qid].options[key];
    return langOpt || key;  // fall back to the English value itself
  }
  if (kind === 'scale')   return (bank.__scale   && bank.__scale[key])   || enBank.__scale[key]   || key;
  if (kind === 'section') return (bank.__sections && bank.__sections[key]) || enBank.__sections[key] || key;
  if (kind === 'chrome')  return (bank.__chrome  && bank.__chrome[key])  || enBank.__chrome[key]  || key;
  return key;
}

// ----------------------------------------------------------------------------
// 2026-06-01 (i18n): Language switcher behaviour.
//
// _mgjAfSwitchLang(lang) is the click handler wired into the 3-button bar
// rendered in index.html (#mgjAfLangBar). Switching language must NOT lose
// any data the user has typed/selected, so we:
//   1) call _mgjAfCollectAllVisible() to copy every <input>/<select> value
//      currently in the DOM back into _mgjAfResponses (the autosave-backed
//      state map)
//   2) call _mgjAfSetLang() (writes to localStorage)
//   3) re-render every tab so the question/option text and section names
//      reflect the new language; the renderer reads from _mgjAfResponses
//      so prior answers reappear pre-selected
//   4) re-paint the active language pill + tab pill labels
//   5) re-show whichever tab the user was on
// ----------------------------------------------------------------------------

function _mgjAfSwitchLang(lang) {
  if (lang !== 'en' && lang !== 'hi' && lang !== 'bn') return;
  if (lang === _mgjAfLang) {
    _mgjAfPaintLangBar();
    return;
  }
  // 1) capture in-flight DOM values so nothing is lost on re-render
  _mgjAfCollectAllVisible();
  // 2) flip language (persists to localStorage too)
  _mgjAfSetLang(lang);
  // 3) re-render every tab — _mgjAfResponses still has the user's answers
  MGJ_AF_TAB_ORDER.forEach(mgjAfRenderTab);
  // 4) update tab pill labels + language pill highlight
  _mgjAfPaintTabLabels();
  _mgjAfPaintLangBar();
  // 5) keep the user on the same section
  mgjAfShowTab(_mgjAfActiveSection || 'demographic');
}

// Read every visible question control inside the assessment form panes
// and write its current value back to _mgjAfResponses. Mirrors what the
// onchange handler does field-by-field, but in bulk for switch / submit.
function _mgjAfCollectAllVisible() {
  for (var sec in MGJ_AF_QUESTIONS) {
    var qs = MGJ_AF_QUESTIONS[sec] || [];
    qs.forEach(function(q) {
      var id = 'mgjaf-' + q.id;
      var el = document.getElementById(id);
      if (!el && q.type !== 'radio' && q.type !== 'checkbox' && q.type !== 'scale') return;
      if (q.type === 'radio' || q.type === 'scale') {
        var sel = document.querySelector('input[name="' + id + '"]:checked');
        if (sel) _mgjAfResponses[q.id] = sel.value;
      } else if (q.type === 'checkbox') {
        var arr = [];
        document.querySelectorAll('input[name="' + id + '"]:checked').forEach(function(cb) {
          arr.push(cb.value);
        });
        if (arr.length) _mgjAfResponses[q.id] = arr;
        else if (_mgjAfResponses.hasOwnProperty(q.id)) delete _mgjAfResponses[q.id];
      } else if (el) {
        if (el.value != null && el.value !== '') _mgjAfResponses[q.id] = el.value;
      }
    });
  }
}

// Highlight the currently-active language pill. Called on every re-render
// and on every language switch.
function _mgjAfPaintLangBar() {
  var bar = document.getElementById('mgjAfLangBar'); if (!bar) return;
  var btns = bar.querySelectorAll('.mgjaf-lang-btn');
  btns.forEach(function(b) {
    var on = b.getAttribute('data-mgjaf-lang') === _mgjAfLang;
    b.style.background = on ? '#732269' : '#fff';
    b.style.color      = on ? '#fff'    : '#732269';
  });
}

// Re-paint the tab pill labels (the 7 buttons at the top of the form) so
// they show the active-language section names. Called after openForm and
// after every language switch.
function _mgjAfPaintTabLabels() {
  var nav = document.getElementById('mgjAfTabNav'); if (!nav) return;
  nav.querySelectorAll('.tab-btn[data-mgjaf-tab]').forEach(function(b) {
    var sec = b.getAttribute('data-mgjaf-tab');
    b.textContent = _mgjAfTr(null, 'section', sec);
  });
  // 2026-06-01: AK-parity — also repaint breadcrumb anchors, Back-to-List
  // button, footer buttons (Previous / Save Draft / Next / Submit), the
  // language label inside #mgjAfLangBar, and the status line in the
  // active language. All targets have stable IDs / structural anchors.
  function setHtml(id, html) { var el = document.getElementById(id); if (el) el.innerHTML = html; }
  setHtml('mgjAfPrevBtn',   '<i class="fas fa-arrow-left"></i> ' + escHtml(_mgjAfTr(null, 'chrome', 'btnPrevious')));
  setHtml('mgjAfDraftBtn',  '<i class="fas fa-save"></i> '       + escHtml(_mgjAfTr(null, 'chrome', 'btnSaveDraft')));
  setHtml('mgjAfNextBtn',   escHtml(_mgjAfTr(null, 'chrome', 'btnNext')) + ' <i class="fas fa-arrow-right"></i>');
  setHtml('mgjAfSubmitBtn', '<i class="fas fa-check-circle"></i> ' + escHtml(_mgjAfTr(null, 'chrome', 'btnSubmit')));
  // Back-to-List button = the only .btn-outline inside the MGJ form's
  // page-header next to the breadcrumb.
  var backBtn = document.querySelector('#page-mgjAssessmentForm .page-header > .btn');
  if (backBtn) {
    backBtn.innerHTML = '<i class="fas fa-arrow-left"></i> ' + escHtml(_mgjAfTr(null, 'chrome', 'btnBackToList'));
  }
  // Breadcrumb: Home + Assessment anchors.
  var crumbs = document.querySelectorAll('#page-mgjAssessmentForm .breadcrumb a');
  if (crumbs.length >= 2) {
    crumbs[0].innerHTML = '<i class="fas fa-home"></i> ' + escHtml(_mgjAfTr(null, 'chrome', 'breadcrumbHome'));
    crumbs[1].textContent = _mgjAfTr(null, 'chrome', 'breadcrumbAssessment');
  }
  // Language label inside the switcher bar.
  var langLabel = document.querySelector('#mgjAfLangBar > span');
  if (langLabel) {
    langLabel.innerHTML = '<i class="fas fa-language"></i> ' + escHtml(_mgjAfTr(null, 'chrome', 'languageLabel'));
  }
  // Re-paint the status bar with whichever message it currently holds.
  _mgjAfPaintStatus();
}

// 2026-06-01: MGJ status-bar i18n. Same contract as AK's _akAfSetStatus —
// every write to #mgjAfStatus now flows through _mgjAfSetStatus(key, extra)
// so a language switch can reproduce the current message.
//
// Recognised keys: 'draftSavedAt' (extra=time), 'saveFailedRetry',
// 'submittedRO'. Form-only chrome (the "Submitted" banner shown for
// locked forms) reuses chrome.submittedRO.
var _mgjAfStatusKey   = null;
var _mgjAfStatusExtra = '';
function _mgjAfSetStatus(key, extra) {
  _mgjAfStatusKey   = key;
  _mgjAfStatusExtra = extra || '';
  _mgjAfPaintStatus();
}
function _mgjAfPaintStatus() {
  var el = document.getElementById('mgjAfStatus');
  if (!el) return;
  if (!_mgjAfStatusKey) return;  // leave whatever is there (e.g. " ")
  if (_mgjAfStatusKey === 'draftSavedAt') {
    el.innerHTML = '<i class="fas fa-check-circle" style="color:#27ae60;"></i> ' +
                   escHtml(_mgjAfTr(null, 'chrome', 'statusDraftSavedTime')) +
                   (_mgjAfStatusExtra ? ' ' + escHtml(_mgjAfStatusExtra) : '');
  } else if (_mgjAfStatusKey === 'saveFailedRetry') {
    el.textContent = _mgjAfTr(null, 'chrome', 'statusSaveFailedRetry');
  } else if (_mgjAfStatusKey === 'submittedRO') {
    el.textContent = _mgjAfTr(null, 'chrome', 'submittedRO');
  }
}

// Tab order — drives Next / Previous navigation and the progress bar.
var MGJ_AF_TAB_ORDER = ['demographic','knowledge','attitudes','situational','practices','vignettes','community'];

// Per-form state. Reset by openMgjAssessmentForm on every entry.
var _mgjAfActiveSection = 'demographic';
var _mgjAfResponses     = {};        // { q1: 'value', q2: ['a','b'], … }
var _mgjAfMember        = null;      // member profile (for autofill)
var _mgjAfMeta          = null;      // assessment row (status, type, …)
var _mgjAfAutosaveT     = null;      // debounce timer for autosave

function openMgjAssessmentForm(assessmentId) {
  _mgjAsCurrentDraftId  = assessmentId;
  _mgjAfActiveSection   = 'demographic';
  _mgjAfResponses       = {};
  _mgjAfMember          = null;
  _mgjAfMeta            = null;
  navigateTo('mgjAssessmentForm');
  // Defer the data fetch until the page is on-screen so the tab nav has
  // mounted and mgjAfShowTab can target the right panes.
  setTimeout(function() { _mgjAfHydrateAndRender(assessmentId); }, 80);
}

function _mgjAfHydrateAndRender(id) {
  apiMgjAssessmentDetail(id).then(function(payload) {
    _mgjAfMeta     = payload.assessment || {};
    _mgjAfMember   = payload.member     || {};
    _mgjAfResponses = (_mgjAfMeta.responses && typeof _mgjAfMeta.responses === 'object') ? _mgjAfMeta.responses : {};
    // 2026-05-28: Context bar removed from DOM; breadcrumb is the only
    // chrome above the tab content. Guard every previously-required
    // element lookup so the legacy code path doesn't throw when an
    // element was deliberately removed.
    var typeLabel = _mgjAfMeta.assessment_type || 'Assessment';
    var bcEl = document.getElementById('mgjAfBreadcrumbType');
    if (bcEl) bcEl.textContent = typeLabel;
    var titleEl = document.getElementById('mgjAfTitle');
    if (titleEl) titleEl.innerHTML = '<i class="fas fa-clipboard-check"></i> ' + escHtml(typeLabel) + ' Assessment';
    var sumEl = document.getElementById('mgjAfSummary');
    if (sumEl) {
      var sum = '<b>' + escHtml(_mgjAfMember.name || 'Member') + '</b>';
      if (_mgjAfMember.enrollment_number) sum += ' (' + escHtml(_mgjAfMember.enrollment_number) + ')';
      if (_mgjAfMember.centre_name) sum += ' &middot; ' + escHtml(_mgjAfMember.centre_name);
      if (_mgjAfMember.state_name)  sum += ', ' + escHtml(_mgjAfMember.state_name);
      sum += ' &middot; Status: <b>' + escHtml(_mgjAfMeta.status || 'Draft') + '</b>';
      sumEl.innerHTML = sum;
    }
    // Restore the last tab the user was on (saved by autosave) — defaults
    // to Demographic on first open.
    var resumeAt = _mgjAfMeta.last_tab && MGJ_AF_TAB_ORDER.indexOf(_mgjAfMeta.last_tab) >= 0
                   ? _mgjAfMeta.last_tab : 'demographic';
    // Render every pane up front so prefilled values persist as the user
    // tabs through (instead of being re-derived from the bank each time).
    MGJ_AF_TAB_ORDER.forEach(mgjAfRenderTab);
    // 2026-06-01 (i18n): paint tab pill labels + language switcher chrome
    // in whatever language was active when the user last left the form.
    _mgjAfPaintTabLabels();
    _mgjAfPaintLangBar();
    mgjAfShowTab(resumeAt);
    // If the assessment was already Submitted, lock the form (no save / no submit).
    if (_mgjAfMeta.status === 'Submitted') _mgjAfLockForm();
  }).catch(function(err) { showUserError('loading MGJ assessment', err); });
}

function _mgjAfLockForm() {
  ['mgjAfDraftBtn','mgjAfSubmitBtn','mgjAfDeleteBtn'].forEach(function(id) {
    var b = document.getElementById(id); if (b) b.style.display = 'none';
  });
  // Disable every form input inside the panes.
  MGJ_AF_TAB_ORDER.forEach(function(sec) {
    var pane = document.getElementById('mgjAfPane-' + sec); if (!pane) return;
    pane.querySelectorAll('input, select, textarea').forEach(function(el) { el.disabled = true; });
  });
  // 2026-06-01: status message localizes via the active language chrome bank.
  document.getElementById('mgjAfStatus').textContent = _mgjAfTr(null, 'chrome', 'submittedRO');
}

// Render one section's pane HTML from MGJ_AF_QUESTIONS[sectionId]. Each
// rendered control is named mgjaf-<questionId> and wires its onchange/
// oninput to _mgjAfOnFieldChange so the central response map stays in
// sync and the debounced autosave gets queued.
function mgjAfRenderTab(sectionId) {
  var pane = document.getElementById('mgjAfPane-' + sectionId);
  if (!pane) return;
  var qs = MGJ_AF_QUESTIONS[sectionId] || [];
  if (!qs.length) {
    pane.innerHTML = '<div style="padding:30px;text-align:center;color:#888;border:1px dashed #ddd;border-radius:10px;">' +
      '<i class="fas fa-comment-dots" style="font-size:28px;color:#732269;margin-bottom:10px;display:block;"></i>' +
      '<div style="font-weight:600;color:#732269;margin-bottom:6px;">' + escHtml(_mgjAfTr(null, 'chrome', 'pendingSection')) + '</div>' +
      '<div style="font-size:13px;max-width:520px;margin:0 auto;">Paste the English-only question text for <b>' + _mgjAfPrettySection(sectionId) + '</b> in chat and the form will be rebuilt on the next deploy.</div>' +
      '</div>';
    return;
  }
  // 2026-05-30: Orange Demographic info banner removed per user request
  // for exact AK parity (AK form has no equivalent banner). The (from
  // profile) tag beside each prefilled field label is now the only
  // signal that those values are read-only — same as AK's autofill
  // marker pattern.
  pane.innerHTML = _mgjAfRenderQuestionGroup(null, qs, null, sectionId);
}

// Renders a group of questions under an optional sub-heading. Each
// field is laid out in an auto-fit grid: short fields (text/number/date/
// select) flow at minmax(260px, 1fr) — so 3-4 fit per row on wide
// screens — while wide fields (radio/checkbox/scale/textarea) span the
// full width via `full-width` class. This matches the AK form rhythm.
function _mgjAfRenderQuestionGroup(heading, qs, headingIcon, sectionId) {
  if (!qs || !qs.length) return '';
  var html = '';
  if (heading) {
    html += '<div style="margin:8px 0 14px;padding:8px 0;border-bottom:2px solid #732269;display:flex;align-items:center;gap:10px;">' +
              (headingIcon ? '<i class="fas ' + headingIcon + '" style="color:#732269;font-size:16px;"></i>' : '') +
              '<span style="font-size:15px;font-weight:700;color:#732269;letter-spacing:0.3px;">' + escHtml(heading) + '</span>' +
            '</div>';
  }
  // 2026-05-30: Unified grid minmax to 280px across all sections to match
  // the AK Assessment Form rhythm exactly (was 220px on Demographic /
  // 260px elsewhere, which produced visibly different column counts per
  // section). The standard .form-grid CSS already uses 280px globally —
  // we now defer to it instead of inlining a section-specific override.
  html += '<div class="form-grid" style="margin-bottom:18px;">';
  qs.forEach(function(q) {
    var val;
    if (_mgjAfResponses.hasOwnProperty(q.id)) {
      val = _mgjAfResponses[q.id];
    } else if (q.autofill) {
      val = _mgjAfAutofillValue(q.autofill);
      // Seed the autofilled value into _mgjAfResponses so it gets persisted
      // on the next autosave (otherwise the prefilled Demographic fields
      // would silently disappear from the saved JSONB).
      if (val !== '' && val != null) _mgjAfResponses[q.id] = val;
    } else {
      val = '';
    }
    var req = q.required ? ' <span style="color:#e74c3c;">*</span>' : '';
    var readonly = !!q.readonly;
    // 2026-05-28: A readonly autofill radio/select is RENDERED AS A
    // PLAIN TEXT INPUT (locked) so all prefilled fields fit uniformly
    // in the grid and the Demographic prefilled block lays out as a
    // single horizontal row of compact cells.
    var effectiveType = q.type;
    if (readonly && q.autofill && (q.type === 'radio' || q.type === 'select')) {
      effectiveType = 'text';
    }
    // Wide controls take the whole row; short ones share the auto-fit grid.
    // 2026-05-28: For Attitudes — render scale options VERTICALLY so the
    // 5 options stack one-per-line; other sections stay horizontal-wrap.
    // Read-only-as-text override above demotes prefilled radios out of
    // the wide-types set so they fit in the grid uniformly.
    var wideTypes = (effectiveType === 'textarea' || effectiveType === 'checkbox' || effectiveType === 'radio' || effectiveType === 'scale');
    // 2026-06-01: pull the display label from the i18n bank using the
    // question id; fall back to q.label (English) when no translation
    // exists. The `Q3. `/`Q3a. ` prefix is stripped in all three
    // languages so the label area shows just the question text.
    var rawLabel = _mgjAfTr(q.id, 'label') || q.label;
    var displayLabel = rawLabel.replace(/^Q\d+[a-z]?\.\s*/, '');
    var groupStyle = 'margin-bottom:0;' + (wideTypes ? 'grid-column:1/-1;' : '');
    // 2026-05-30: showIf — conditionally hide a question until its
    // trigger answer matches. We always emit the markup so the user's
    // prior answer is preserved across show/hide cycles; the wrapper
    // toggles `display` in _mgjAfOnFieldChange. Attributes mirror the
    // AK pattern (`_akAfEvalShowIf` / `.ak-af-conditional`).
    var showIfAttrs = '';
    if (q.showIf) {
      var visible = _mgjAfEvalShowIf(q.showIf);
      showIfAttrs = ' data-mgjaf-showif-target="' + q.id + '"' +
                    ' data-mgjaf-showif-q="' + q.showIf.q + '"';
      if (!visible) groupStyle += 'display:none;';
    }
    html += '<div class="form-group"' + showIfAttrs + ' style="' + groupStyle + '">';
    html += '<label style="display:block;margin-bottom:5px;font-weight:600;font-size:13px;color:#333;">' + escHtml(displayLabel) + req +
            (q.autofill ? ' <small style="color:#732269;font-weight:normal;">' + escHtml(_mgjAfTr(null, 'chrome', 'fromProfile')) + '</small>' : '') + '</label>';
    html += _mgjAfRenderControl(q, val, readonly, sectionId, effectiveType);
    html += '<div class="mgjaf-err" id="err-mgjaf-' + q.id + '" style="color:#e74c3c;font-size:11px;margin-top:4px;display:none;"></div>';
    html += '</div>';
  });
  html += '</div>';
  return html;
}

function _mgjAfRenderControl(q, val, readonly, sectionId, effectiveType) {
  var id = 'mgjaf-' + q.id;
  var type = effectiveType || q.type;
  // 2026-05-30: Readonly styling aligned to AK — neutral light-grey
  // (#f5f5f5) background with the standard border, no programme-purple
  // tint. Matches the readonly inputs on the AK Add form (Year of
  // Joining, Per Capita Income, etc.). The (from profile) label
  // beside the field already signals "auto-filled".
  var roTxtStyle = readonly
    ? ' readonly style="width:100%;background:#f5f5f5;cursor:not-allowed;"'
    : ' style="width:100%;"';
  var safeVal = (val == null) ? '' : String(val);
  var on = readonly ? '' : ' oninput="_mgjAfOnFieldChange(\'' + q.id + '\')" onchange="_mgjAfOnFieldChange(\'' + q.id + '\')"';
  if (type === 'textarea') {
    return '<textarea id="' + id + '" rows="3"' + roTxtStyle + on + '>' + escHtml(safeVal) + '</textarea>';
  }
  if (type === 'number') {
    return '<input type="number" id="' + id + '" value="' + escHtml(safeVal) + '"' + roTxtStyle + on + '>';
  }
  if (type === 'date') {
    return '<input type="date" id="' + id + '" value="' + escHtml(safeVal) + '"' + roTxtStyle + on + '>';
  }
  if (type === 'select') {
    // 2026-06-01: i18n — `value` is the English option string (stays in
    // storage / dashboards) while the visible <option> text uses the
    // active-language translation from MGJ_AF_I18N.
    var opts = '<option value="">' + escHtml(_mgjAfTr(null, 'chrome', 'selectPlaceholder')) + '</option>' + (q.options || []).map(function(o) {
      var v = (typeof o === 'string') ? o : o.value;
      var enLbl = (typeof o === 'string') ? o : o.label;
      var trLbl = _mgjAfTr(q.id, 'option', enLbl);
      var sel = (safeVal === v) ? ' selected' : '';
      return '<option value="' + escHtml(v) + '"' + sel + '>' + escHtml(trLbl) + '</option>';
    }).join('');
    var selStyle = readonly
      ? ' disabled style="width:100%;background:#f5f5f5;cursor:not-allowed;"'
      : ' style="width:100%;"';
    return '<select id="' + id + '"' + on + selStyle + '>' + opts + '</select>';
  }
  if (type === 'radio' || type === 'scale') {
    // 2026-05-30: Option rendering rewritten to mirror the AK Assessment
    // Form exactly (app.js ~line 21863). AK uses a vertical column of
    // plain `<label>`-with-`<input>` rows — NO chip boxes, NO purple
    // tints, NO horizontal flow. Spacing 8px between rows. Selected
    // state is implicit on the native radio. Readonly grays the input
    // out via the standard `disabled` attribute. This matches AK's
    // `.ak-af-options-list` styling one-to-one.
    // 2026-05-30: Numeric "N — " prefix dropped from scale labels per
    // user request (applies to all `type: 'scale'` questions across
    // Attitudes + Practices). Stored values stay 1-5 numeric so any
    // downstream scoring math is unaffected — only the display text
    // changes.
    // 2026-06-01: i18n — scale labels come from MGJ_AF_I18N.<lang>.__scale;
    // radio option labels come from MGJ_AF_I18N.<lang>[qid].options[<englishLabel>].
    // English option VALUE remains in the `value` attribute so storage +
    // analytics stay consistent across languages.
    var options = (type === 'scale')
      ? [
          {value:'1', label: _mgjAfTr(null, 'scale', '1')},
          {value:'2', label: _mgjAfTr(null, 'scale', '2')},
          {value:'3', label: _mgjAfTr(null, 'scale', '3')},
          {value:'4', label: _mgjAfTr(null, 'scale', '4')},
          {value:'5', label: _mgjAfTr(null, 'scale', '5')}
        ]
      : (q.options || []).map(function(o) {
          var v   = (typeof o === 'string') ? o : o.value;
          var enL = (typeof o === 'string') ? o : o.label;
          return { value: v, label: _mgjAfTr(q.id, 'option', enL) };
        });
    return '<div class="mgjaf-options-list" style="display:flex;flex-direction:column;gap:8px;">' +
      options.map(function(o) {
        var sel = (safeVal === o.value) ? ' checked' : '';
        return '<label class="mgjaf-opt" style="display:flex;align-items:flex-start;gap:10px;font-weight:normal;cursor:pointer;line-height:1.4;">' +
                 '<input type="radio" name="' + id + '" value="' + escHtml(o.value) + '"' + sel + on +
                 (readonly ? ' disabled' : '') +
                 ' style="width:auto;margin:3px 0 0;flex-shrink:0;">' +
                 '<span>' + escHtml(o.label) + '</span></label>';
      }).join('') + '</div>';
  }
  if (q.type === 'checkbox') {
    // 2026-06-01: same i18n contract as radio — checkbox VALUES stay
    // English (so the stored array is comparable across languages) while
    // each <span> shows the translated label.
    var values = Array.isArray(val) ? val.map(String) : (safeVal ? [safeVal] : []);
    return '<div class="mgjaf-options-list" style="display:flex;flex-direction:column;gap:8px;">' +
      (q.options || []).map(function(o) {
        var v = (typeof o === 'string') ? o : o.value;
        var enLbl = (typeof o === 'string') ? o : o.label;
        var trLbl = _mgjAfTr(q.id, 'option', enLbl);
        var sel = values.indexOf(v) >= 0 ? ' checked' : '';
        return '<label class="mgjaf-opt" style="display:flex;align-items:flex-start;gap:10px;font-weight:normal;cursor:pointer;line-height:1.4;">' +
                 '<input type="checkbox" name="' + id + '" value="' + escHtml(v) + '"' + sel + on +
                 (readonly ? ' disabled' : '') +
                 ' style="width:auto;margin:3px 0 0;flex-shrink:0;">' +
                 '<span>' + escHtml(trLbl) + '</span></label>';
      }).join('') + '</div>';
  }
  // default: text — uses the same readonly/editable style block as the
  // typed branches above (this fallthrough was the source of the
  // "ro is not defined" runtime error after the earlier refactor that
  // renamed the local var).
  return '<input type="text" id="' + id + '" value="' + escHtml(safeVal) + '"' + roTxtStyle + on + '>';
}

function _mgjAfPrettySection(sec) {
  // 2026-06-01: section names sourced from MGJ_AF_I18N so they switch with
  // the active form language (English / Hindi / Bangla).
  return _mgjAfTr(null, 'section', sec) || sec;
}

// 2026-05-30: Evaluate a question's `showIf` clause against the live
// _mgjAfResponses map. Schema: `showIf: { q: 'q39', equals: 'Yes' }`
// — `equals` accepts a string or an array of acceptable strings (any
// match wins). Mirrors AK's `_akAfEvalShowIf` so the two assessment
// forms share the same conditional-visibility semantics.
function _mgjAfEvalShowIf(cond) {
  if (!cond || cond.q == null) return true;
  var v = _mgjAfResponses[cond.q];
  if (cond.equals !== undefined) {
    var expected = Array.isArray(cond.equals) ? cond.equals : [cond.equals];
    if (Array.isArray(v)) {
      // Multi-select trigger (checkbox): show if any chosen value matches.
      return v.some(function(item) { return expected.indexOf(item) >= 0; });
    }
    return expected.indexOf(v) >= 0;
  }
  return true;
}

function _mgjAfAutofillValue(spec) {
  if (!spec || !_mgjAfMember) return '';
  if (spec.indexOf('profile.') === 0) {
    var key = spec.substring(8);
    // Special-case area_name — mgj_assessments.fetch_member returns area
    // via area_code; the profile lookup didn't always join the area table
    // historically, so fall back to area_code if no area_name exists.
    if (key === 'area_name') return _mgjAfMember.area_name || _mgjAfMember.area_code || '';
    // Special-case role — we don't currently expose Leader vs Member on
    // the member profile (would need a join into mgj_leaders). Default to
    // 'MGJ Member' since that covers everyone enrolled in mgj_members; the
    // surveyor can override to 'MGJ Leader' on the form if applicable.
    if (key === 'role') return _mgjAfMember.role || 'MGJ Member';
    return _mgjAfMember[key] || '';
  }
  return '';
}

// Reads the live DOM value for a question and writes it into _mgjAfResponses.
function _mgjAfOnFieldChange(qid) {
  var id = 'mgjaf-' + qid;
  var el = document.getElementById(id);
  var q = _mgjAfFindQuestion(qid);
  if (!q) return;
  var v;
  if (q.type === 'checkbox') {
    v = [];
    document.querySelectorAll('input[name="' + id + '"]:checked').forEach(function(c) { v.push(c.value); });
  } else if (q.type === 'radio' || q.type === 'scale') {
    var checked = document.querySelector('input[name="' + id + '"]:checked');
    v = checked ? checked.value : '';
  } else {
    v = el ? el.value : '';
  }
  _mgjAfResponses[qid] = v;
  _mgjAfClearErr(qid);
  // 2026-05-30: After every change, re-evaluate any dependents whose
  // showIf clause references this question, toggling display + clearing
  // hidden answers so stale data doesn't reach the autosave. Mirrors
  // AK's `akAfOnAnswerChange` showIf wiring.
  _mgjAfToggleDependents(qid);
  _mgjAfQueueAutosave();
}

function _mgjAfToggleDependents(qid) {
  document.querySelectorAll('[data-mgjaf-showif-q="' + qid + '"]').forEach(function(wrap) {
    var targetQid = wrap.getAttribute('data-mgjaf-showif-target');
    var targetQ = _mgjAfFindQuestion(targetQid);
    if (!targetQ || !targetQ.showIf) return;
    var visible = _mgjAfEvalShowIf(targetQ.showIf);
    wrap.style.display = visible ? '' : 'none';
    if (!visible) {
      // Trigger flipped off → drop any stored answer + reset the UI so
      // nothing leaks back into the JSONB on next autosave.
      delete _mgjAfResponses[targetQid];
      var name = 'mgjaf-' + targetQid;
      wrap.querySelectorAll('#' + name + ', [name="' + name + '"]').forEach(function(node) {
        if (node.tagName === 'SELECT') node.value = '';
        else if (node.type === 'checkbox' || node.type === 'radio') node.checked = false;
        else node.value = '';
      });
      _mgjAfClearErr(targetQid);
    }
  });
}

function _mgjAfFindQuestion(qid) {
  for (var sec in MGJ_AF_QUESTIONS) {
    var arr = MGJ_AF_QUESTIONS[sec] || [];
    for (var i = 0; i < arr.length; i++) if (arr[i].id === qid) return arr[i];
  }
  return null;
}

function _mgjAfQueueAutosave() {
  var status = document.getElementById('mgjAfStatus');
  if (status) status.textContent = 'Unsaved changes…';
  if (_mgjAfAutosaveT) clearTimeout(_mgjAfAutosaveT);
  _mgjAfAutosaveT = setTimeout(function() { mgjAfSaveDraft(true); }, 1200);
}

function _mgjAfClearErr(qid) {
  var box = document.getElementById('err-mgjaf-' + qid);
  if (box) { box.textContent = ''; box.style.display = 'none'; }
}
function _mgjAfSetErr(qid, msg) {
  var box = document.getElementById('err-mgjaf-' + qid);
  if (box) { box.textContent = msg; box.style.display = 'block'; }
}

// Validate every required question in a single section. Returns true if
// all pass. Stops short of cross-section checks (those run only at Submit).
function _mgjAfValidateSection(sectionId) {
  var ok = true;
  (MGJ_AF_QUESTIONS[sectionId] || []).forEach(function(q) {
    if (!q.required) return;
    // 2026-05-30: Skip questions hidden by an unmet showIf — they
    // aren't on screen, so they can't possibly fail validation.
    if (q.showIf && !_mgjAfEvalShowIf(q.showIf)) return;
    var v = q.autofill ? _mgjAfAutofillValue(q.autofill) : _mgjAfResponses[q.id];
    var empty = (v == null) || v === '' || (Array.isArray(v) && v.length === 0);
    // 2026-05-27 (v2): a readonly autofill field that's empty means
    // the underlying member profile doesn't have that value yet — the
    // surveyor cannot fix it here. Don't block submission on it; just
    // skip the validation. The user can update the profile later if
    // they care; meanwhile the assessment moves forward.
    if (empty && q.readonly && q.autofill) return;
    if (empty) {
      // 2026-06-01: localized inline error text per active form language.
      _mgjAfSetErr(q.id, _mgjAfTr(null, 'chrome', 'answerRequired'));
      ok = false;
    }
    else _mgjAfClearErr(q.id);
  });
  return ok;
}

// Tab switching. Updates the active button + active pane, recomputes the
// progress bar, and toggles the Submit button vs Next on the final tab.
function mgjAfShowTab(sectionId) {
  if (MGJ_AF_TAB_ORDER.indexOf(sectionId) < 0) return;
  _mgjAfActiveSection = sectionId;
  // Tab buttons + panes
  document.querySelectorAll('#mgjAfTabNav .tab-btn').forEach(function(b) {
    b.classList.toggle('active', b.getAttribute('data-mgjaf-tab') === sectionId);
  });
  MGJ_AF_TAB_ORDER.forEach(function(s) {
    var pane = document.getElementById('mgjAfPane-' + s);
    if (pane) pane.classList.toggle('active', s === sectionId);
  });
  // Progress bar — % through the tab order
  var idx = MGJ_AF_TAB_ORDER.indexOf(sectionId);
  var pct = Math.round(((idx + 1) / MGJ_AF_TAB_ORDER.length) * 100);
  var bar = document.getElementById('mgjAfProgressBar');
  if (bar) bar.style.width = pct + '%';
  // Footer buttons
  var prev   = document.getElementById('mgjAfPrevBtn');
  var next   = document.getElementById('mgjAfNextBtn');
  var submit = document.getElementById('mgjAfSubmitBtn');
  if (prev)   prev.style.display   = (idx === 0) ? 'none' : '';
  if (next)   next.style.display   = (idx === MGJ_AF_TAB_ORDER.length - 1) ? 'none' : '';
  if (submit && _mgjAfMeta && _mgjAfMeta.status !== 'Submitted') {
    submit.style.display = (idx === MGJ_AF_TAB_ORDER.length - 1) ? '' : 'none';
  }
  // Persist last_tab on the next autosave (no extra round-trip).
  _mgjAfQueueAutosave();
}

function mgjAfNextTab() {
  // Soft-validate: warn but allow forward navigation so the user can
  // come back later. Hard validation runs only at Submit.
  _mgjAfValidateSection(_mgjAfActiveSection);
  var idx = MGJ_AF_TAB_ORDER.indexOf(_mgjAfActiveSection);
  if (idx < MGJ_AF_TAB_ORDER.length - 1) mgjAfShowTab(MGJ_AF_TAB_ORDER[idx + 1]);
}
function mgjAfPrevTab() {
  var idx = MGJ_AF_TAB_ORDER.indexOf(_mgjAfActiveSection);
  if (idx > 0) mgjAfShowTab(MGJ_AF_TAB_ORDER[idx - 1]);
}

function mgjAfSaveDraft(silent) {
  if (!_mgjAsCurrentDraftId) return;
  if (_mgjAfMeta && _mgjAfMeta.status === 'Submitted') return;
  // 2026-05-30: Save Draft now mirrors the AK spinner feedback — the
  // button is disabled with a spinner icon while the PUT is in flight,
  // then re-enabled on success/failure. Silent (autosave) saves don't
  // touch the button so background activity stays invisible to the user.
  // 2026-06-01 (i18n): spinner label + Save Draft button text both
  // localize via the chrome bank. The status line is set through the new
  // _mgjAfSetStatus helper so a later language switch can re-paint it.
  var btn = silent ? null : document.getElementById('mgjAfDraftBtn');
  var origHtml = btn ? btn.innerHTML : null;
  var savingLbl = _mgjAfTr(null, 'chrome', 'statusSaving');
  if (btn) {
    btn.disabled = true;
    btn.innerHTML = '<i class="fas fa-spinner fa-spin"></i> ' + escHtml(savingLbl);
  }
  function _restoreBtn() {
    if (btn) { btn.disabled = false; btn.innerHTML = origHtml; }
  }
  // (Autofilled values are seeded into _mgjAfResponses by the renderer the
  // first time a question is shown; saving here just persists whatever is
  // currently in the responses dict, which respects later user edits.)
  var body = { responses: _mgjAfResponses, last_tab: _mgjAfActiveSection };
  // apiPut wrapper — falls back to fetch if missing
  var url = (typeof API_BASE !== 'undefined' ? API_BASE : '/api') + '/mgj-assessments/' + _mgjAsCurrentDraftId;
  var headers = { 'Content-Type': 'application/json' };
  if (typeof _authHeaders === 'function') Object.assign(headers, _authHeaders());
  fetch(url, { method: 'PUT', headers: headers, body: JSON.stringify(body), credentials: 'include' })
    .then(function(r) {
      if (!r.ok) throw new Error('HTTP ' + r.status);
      _mgjAfSetStatus('draftSavedAt', new Date().toLocaleTimeString());
      _restoreBtn();
      if (!silent) alert('Draft saved.');
    }).catch(function(err) {
      _mgjAfSetStatus('saveFailedRetry');
      _restoreBtn();
      if (!silent) showUserError('saving MGJ assessment draft', err);
    });
}

function submitMgjAssessmentDraft() {
  if (!_mgjAsCurrentDraftId) { alert('No draft to submit.'); return; }
  // Hard-validate every section that has questions. (Empty sections are
  // skipped — they'll be validated once their question banks ship.)
  // 2026-05-27 (v2): collect failing section IDs so we can navigate to
  // the first one + count missing fields for a clearer alert.
  var failing = [];
  var failingIds = [];
  var missingCount = 0;
  MGJ_AF_TAB_ORDER.forEach(function(sec) {
    if ((MGJ_AF_QUESTIONS[sec] || []).length === 0) return;
    var ok = _mgjAfValidateSection(sec);
    if (!ok) {
      failingIds.push(sec);
      failing.push(_mgjAfPrettySection(sec));
      // Count missing required fields in this section for the alert text.
      // Mirrors the readonly+autofill exemption in _mgjAfValidateSection
      // so the count stays in sync with what actually blocks submit.
      (MGJ_AF_QUESTIONS[sec] || []).forEach(function(q) {
        if (!q.required) return;
        // 2026-05-30: showIf-hidden required fields don't count as
        // missing — they're off-screen by design.
        if (q.showIf && !_mgjAfEvalShowIf(q.showIf)) return;
        var v = q.autofill ? _mgjAfAutofillValue(q.autofill) : _mgjAfResponses[q.id];
        var empty = (v == null) || v === '' || (Array.isArray(v) && v.length === 0);
        if (empty && q.readonly && q.autofill) return;
        if (empty) missingCount++;
      });
    }
  });
  if (failing.length) {
    // Navigate to the FIRST failing section so the inline red errors
    // become visible — previously the user might be sitting on a later
    // tab (e.g. Community Engagement) while errors were in Demographic,
    // so they couldn't see what was missing.
    mgjAfShowTab(failingIds[0]);
    // Scroll the first error into view inside the now-active pane.
    setTimeout(function() {
      var firstErr = document.querySelector('#mgjAfPane-' + failingIds[0] + ' .mgjaf-err[style*="display: block"], #mgjAfPane-' + failingIds[0] + ' .mgjaf-err[style*="display:block"]');
      if (firstErr && firstErr.scrollIntoView) {
        firstErr.scrollIntoView({behavior:'smooth', block:'center'});
      }
    }, 200);
    // 2026-06-01: alert heading localizes; the section list + count remain
    // in the surveyor's chosen language since section names already come
    // from _mgjAfPrettySection (which is i18n-aware).
    var fieldsLabel = missingCount + ' required field' + (missingCount === 1 ? '' : 's');
    alert(_mgjAfTr(null, 'chrome', 'submitErrorHeading') + '\n\n' + fieldsLabel + ': ' + failing.join(', '));
    return;
  }
  if (!confirm('Submit this assessment? Once submitted it cannot be edited.')) return;
  // Save first so the latest responses go with the submit.
  mgjAfSaveDraft(true);
  setTimeout(function() {
    apiMgjAssessmentSubmit(_mgjAsCurrentDraftId).then(function() {
      alert('Assessment submitted.');
      navigateTo('mgjAssessmentList');
    }).catch(function(err) { showUserError('submitting MGJ assessment', err); });
  }, 400);
}

function deleteMgjAssessmentDraft() {
  if (!_mgjAsCurrentDraftId) { alert('No draft to delete.'); return; }
  if (!confirm('Delete this Draft assessment? This cannot be undone.')) return;
  apiMgjAssessmentDelete(_mgjAsCurrentDraftId).then(function() {
    alert('Draft deleted.');
    navigateTo('mgjAssessmentList');
  }).catch(function(err) { showUserError('deleting MGJ assessment', err); });
}

