// 2026-07-06: These six MGJ Master exports previously built CLIENT-SIDE
// text/csv Blobs saved as mgj-*.csv — the reported ".csv instead of .xlsx"
// issue. They now hit the new backend /api/mgj-master/export/excel endpoint,
// which reuses the same list queries and returns a real .xlsx via
// export_helper (same pattern as the member-list export).
function exportMgjMStateToExcel() {
  window.location.href = API_BASE + '/mgj-master/export/excel?entity=states';
}
function _renderMgjMPagination(targetId, total, page, limit, fnName) {
  // Reuse the FLP renderListPagination markup so MGJ Master pagination looks
  // identical to the FLP State/District/Centre/Area pages — chevrons, ellipsis
  // for skipped pages, "Showing X-Y of Z" prefix.
  if (typeof renderListPagination === 'function') {
    renderListPagination('#' + targetId, total, page, limit, fnName);
    return;
  }
  // Fallback (shouldn't be needed once the FLP helper is loaded)
  var el = document.getElementById(targetId);
  if (!el) return;
  var totalPages = Math.max(1, Math.ceil(total / limit));
  var startIdx = (page - 1) * limit + 1;
  var endIdx = Math.min(page * limit, total);
  var html = 'Showing ' + startIdx + '-' + endIdx + ' of ' + total + ' &nbsp; ';
  if (totalPages > 1) {
    html += '<button class="btn-icon" ' + (page <= 1 ? 'disabled' : 'onclick="' + fnName + '(' + (page - 1) + ')"') + '><i class="fas fa-chevron-left"></i></button> ';
    var pages = [1];
    if (page - 1 > 1) pages.push(page - 1);
    if (page > 1 && page < totalPages) pages.push(page);
    if (page + 1 < totalPages) pages.push(page + 1);
    if (totalPages > 1) pages.push(totalPages);
    pages = pages.filter(function(v, i, a) { return a.indexOf(v) === i; }).sort(function(a, b) { return a - b; });
    var prevP = 0;
    pages.forEach(function(p) {
      if (p - prevP > 1) html += '<span style="padding:0 4px;">...</span>';
      html += '<button class="btn-icon" style="' + (p === page ? 'font-weight:bold;color:var(--primary);' : '') + '" onclick="' + fnName + '(' + p + ')">' + p + '</button> ';
      prevP = p;
    });
    html += '<button class="btn-icon" ' + (page >= totalPages ? 'disabled' : 'onclick="' + fnName + '(' + (page + 1) + ')"') + '><i class="fas fa-chevron-right"></i></button>';
  }
  el.innerHTML = html;
}
function resetMgjMStateFilters() {
  ['mgjMStateFilterName','mgjMStateFilterStatus'].forEach(function(id) { var el = document.getElementById(id); if (el) el.value = ''; });
  loadMgjMStates();
}
function openMgjMStateForm(mode, code) {
  editingMgjMState = (mode === 'edit') ? code : null;
  document.getElementById('mgjMStateFormCode').value = '';
  document.getElementById('mgjMStateFormName').value = '';
  document.getElementById('mgjMStateFormStatus').value = 'Active';
  var titleEl = document.getElementById('mgjMStateFormTitle');
  var submitEl = document.getElementById('mgjMStateFormSubmitText');
  if (mode === 'edit') {
    if (titleEl) titleEl.innerHTML = '<i class="fas fa-edit"></i> Edit State';
    if (submitEl) submitEl.textContent = 'Update';
    apiMgjMStates({ limit: 500 }).then(function(resp) {
      var s = (resp.data || []).find(function(x) { return x.state_code === code; });
      if (!s) return;
      document.getElementById('mgjMStateFormCode').value = s.state_code;
      document.getElementById('mgjMStateFormCode').readOnly = true;
      document.getElementById('mgjMStateFormName').value = s.state_name;
      document.getElementById('mgjMStateFormStatus').value = s.status || 'Active';
    });
  } else {
    if (titleEl) titleEl.innerHTML = '<i class="fas fa-plus-circle"></i> Add State';
    if (submitEl) submitEl.textContent = 'Save';
    document.getElementById('mgjMStateFormCode').readOnly = false;
  }
  document.getElementById('mgjMStateFormModal').style.display = 'flex';
}
function saveMgjMState() {
  var code = (document.getElementById('mgjMStateFormCode').value || '').trim().toUpperCase();
  var name = (document.getElementById('mgjMStateFormName').value || '').trim();
  var status = document.getElementById('mgjMStateFormStatus').value;
  if (!code) { alert('State code is required.'); return; }
  if (!name) { alert('State name is required.'); return; }
  var p = editingMgjMState
    ? apiMgjMUpdateState(editingMgjMState, { state_name: name, status: status })
    : apiMgjMCreateState({ state_code: code, state_name: name, status: status });
  p.then(function() {
    alert(editingMgjMState ? 'State updated!' : 'State added!');
    closeMasterModal('mgjMStateFormModal');
    loadMgjMStates(mgjMStateCurrentPage);
  }).catch(function(err) { showUserError('saving state', err); });
}
function deleteMgjMState(code) {
  if (!confirm('Delete state ' + code + '? This cannot be undone if districts exist under it.')) return;
  apiMgjMDeleteState(code).then(function() { alert('State deleted.'); loadMgjMStates(mgjMStateCurrentPage); })
    .catch(function(err) { showUserError('deleting state', err); });
}

