// 2026-06-08: Shared hard-lock for the MGJ Master Add modals (Batch +
// Group). For SL/DL/PI, render State as a single locked option (auto-
// filled to user's MGJ state) and — when the user has a resolved
// centre — render Centre as a single locked option (auto-filled to
// user's MGJ centre). For SL (no centre), Centre becomes a state-
// scoped selectable list. Other roles: no change (the helpers above
// already populated the dropdowns).
function _applyMgjMasterFormLock(stateSelId, centreSelId) {
  if (!currentUser) return;
  var role = currentUser.role || '';
  if (role !== 'pi' && role !== 'district_lead' && role !== 'state_lead') return;
  if (typeof _resolveMgjScopeForDlPi !== 'function') return;
  _resolveMgjScopeForDlPi().then(function() {
    if (!currentUser.mgj_state_code) return;
    [60, 400, 1200, 2500, 4000].forEach(function(delay) {
      setTimeout(function() {
        var sSel = document.getElementById(stateSelId);
        if (sSel) {
          sSel.innerHTML = '<option value="' + escHtml(currentUser.mgj_state_code) + '" selected>' +
                           escHtml(currentUser.mgj_state_name || currentUser.mgj_state_code) + '</option>';
          sSel.value = currentUser.mgj_state_code;
          sSel.disabled = true;
          sSel.style.backgroundColor = '#f5f5f5';
          sSel.style.cursor = 'not-allowed';
          sSel.title = 'Locked to your assigned State';
        }
        var cSel = document.getElementById(centreSelId);
        if (!cSel) return;
        if ((role === 'pi' || role === 'district_lead') && currentUser.mgj_centre_code) {
          cSel.innerHTML = '<option value="' + escHtml(currentUser.mgj_centre_code) + '" selected>' +
                           escHtml(currentUser.mgj_centre_name || currentUser.mgj_centre_code) + '</option>';
          cSel.value = currentUser.mgj_centre_code;
          cSel.disabled = true;
          cSel.style.backgroundColor = '#f5f5f5';
          cSel.style.cursor = 'not-allowed';
          cSel.title = 'Locked to your assigned Centre';
        } else {
          // SL or DL/PI with no resolved centre: load state-scoped list.
          _mgjMFillCentreSelectByState(centreSelId, currentUser.mgj_state_code, false);
        }
      }, delay);
    });
  });
}
