function openMgjMGroupForm(mode, id) {
  editingMgjMGroup = (mode === 'edit') ? id : null;
  document.getElementById('mgjMGroupFormName').value = '';
  document.getElementById('mgjMGroupFormStatus').value = 'Active';
  document.getElementById('mgjMGroupFormCentre').innerHTML = '<option value="">Select Centre</option>';
  document.getElementById('mgjMGroupFormArea').innerHTML   = '<option value="">Select Area</option>';
  var titleEl  = document.getElementById('mgjMGroupFormTitle');
  var submitEl = document.getElementById('mgjMGroupFormSubmitText');
  if (mode === 'edit') {
    if (titleEl)  titleEl.innerHTML = '<i class="fas fa-edit"></i> Edit Group';
    if (submitEl) submitEl.textContent = 'Update';
    // Fetch the row, then cascade-fill the dropdowns and preselect values.
    apiMgjMGroups({ limit: 2000 }).then(function(resp) {
      var g = (resp.data || []).find(function(x) { return x.id === id; });
      if (!g) return;
      _mgjMFillStateSelect('mgjMGroupFormState', false, g.state_code).then(function() {
        return _mgjMFillCentreSelectByState('mgjMGroupFormCentre', g.state_code, false, g.centre_code);
      }).then(function() {
        return _mgjMFillAreaSelectByCentre('mgjMGroupFormArea', g.centre_code, false, g.area_code);
      });
      document.getElementById('mgjMGroupFormName').value   = g.name;
      document.getElementById('mgjMGroupFormStatus').value = g.status || 'Active';
    });
  } else {
    if (titleEl)  titleEl.innerHTML = '<i class="fas fa-plus-circle"></i> Add Group';
    if (submitEl) submitEl.textContent = 'Save';
    _mgjMFillStateSelect('mgjMGroupFormState', false);
    // 2026-06-08: For SL / DL / PI, hard-lock State + Centre to user's
    // MGJ scope. Area cascades from Centre via the existing
    // onMgjMGroupFormCentreChange handler — fire a centre-change after
    // the lock dispatches so the Area dropdown loads automatically.
    _applyMgjMasterFormLock('mgjMGroupFormState', 'mgjMGroupFormCentre');
    setTimeout(function() {
      var cSel = document.getElementById('mgjMGroupFormCentre');
      if (cSel && cSel.value && typeof onMgjMGroupFormCentreChange === 'function') {
        try { onMgjMGroupFormCentreChange(); } catch (e) {}
      }
    }, 1300);
  }
  document.getElementById('mgjMGroupFormModal').style.display = 'flex';
}

function saveMgjMGroup() {
  var state  = document.getElementById('mgjMGroupFormState').value;
  var centre = document.getElementById('mgjMGroupFormCentre').value;
  var area   = document.getElementById('mgjMGroupFormArea').value;
  var name   = (document.getElementById('mgjMGroupFormName').value || '').trim();
  var status = document.getElementById('mgjMGroupFormStatus').value;
  if (!state)  { alert('Please select a State.');  return; }
  if (!centre) { alert('Please select a Centre.'); return; }
  if (!area)   { alert('Please select an Area.');  return; }
  if (!name)   { alert('Group name is required.'); return; }
  var data = {
    name: name, status: status,
    state_code: state || null, centre_code: centre || null, area_code: area || null,
    group_code: null,
  };
  var p = editingMgjMGroup
    ? apiMgjMUpdateGroup(editingMgjMGroup, data)
    : apiMgjMCreateGroup(data);
  p.then(function() {
    alert(editingMgjMGroup ? 'Group updated!' : 'Group added!');
    closeMasterModal('mgjMGroupFormModal');
    loadMgjMGroups(mgjMGroupCurrentPage);
  }).catch(function(err) { showUserError('saving group', err); });
}

function deleteMgjMGroup(id) {
  if (!confirm('Delete this group?')) return;
  apiMgjMDeleteGroup(id).then(function() { alert('Group deleted.'); loadMgjMGroups(mgjMGroupCurrentPage); })
    .catch(function(err) { showUserError('deleting group', err); });
}

// =============================================================================
// Reusable: populate a Group-Number <select> filtered by area_code.
// Used wherever a form has an Area → Group cascade (MGJ Member form,
// Pakhwada Session form, future forms). Returns a Promise so callers can
// chain a preselect (e.g. on Edit) after the options have loaded. The
// option value is the group NAME — that's what we persist into the
// downstream group_number columns (which are plain strings, not FKs).
function _mgjFillGroupSelectByArea(selectId, areaCode, currentValue) {
  var sel = document.getElementById(selectId);
  if (!sel) return Promise.resolve();
  sel.innerHTML = '<option value="">Select Group</option>';
  if (!areaCode || areaCode === 'OTHER') return Promise.resolve();
  return apiMgjMGroupsDropdown({ area_code: areaCode }).then(function(rows) {
    (rows || []).forEach(function(r) {
      var opt = document.createElement('option');
      opt.value = r.name; opt.textContent = r.name;
      sel.appendChild(opt);
    });
    // If we have a saved value but no matching option (legacy data, or the
    // group was renamed / soft-deleted in master), append it as a
    // "(legacy)" option so the existing record's value is preserved on
    // Submit instead of being silently nulled.
    if (currentValue) {
      var found = false;
      for (var i = 0; i < sel.options.length; i++) {
        if (sel.options[i].value === String(currentValue)) { found = true; break; }
      }
      if (!found) {
        var lo = document.createElement('option');
        lo.value = String(currentValue);
        lo.textContent = String(currentValue) + ' (legacy)';
        sel.appendChild(lo);
      }
      sel.value = String(currentValue);
    }
  });
}

// ── Wire the Area → Group cascade for the MGJ Member form ─────────────────
// `mgjArea` was already an existing dropdown; we just added a call to this
// from its onchange (see index.html, mgjArea select). When Area changes,
// repopulate the Group dropdown to show only the groups created for that
// area in Master ▸ Group Management.
