  var name = (document.getElementById('akMDistrictFormName').value || '').trim();
  var status = document.getElementById('akMDistrictFormStatus').value;
  if (!state) { alert('Please select a state.'); return; }
  if (!code) { alert('District code is required.'); return; }
  if (!name) { alert('District name is required.'); return; }
  var p = _editingAkMDistrict
    ? apiAkMUpdateDistrict(_editingAkMDistrict, { state_code: state, district_name: name, status: status })
    : apiAkMCreateDistrict({ state_code: state, district_code: code, district_name: name, status: status });
