// ============================================================================
// AAG AGM — Annual General Meeting records under AK Alumni.
// Single flat table; list page + Add/Edit modal + read-only View modal.
// ============================================================================

var _akAgmPage = 1, _akAgmLimit = 10, _akAgmTotal = 0;
var _akAgmEditingId = null;

// ---- List ------------------------------------------------------------------

function loadAkAgmList(page) {
  if (typeof page === 'number') _akAgmPage = page;
  var p = { page: _akAgmPage, limit: _akAgmLimit };
  var y  = (document.getElementById('akAgmFilterYear')  || {}).value;
  var df = (document.getElementById('akAgmFilterFrom')  || {}).value;
  var dt = (document.getElementById('akAgmFilterTo')    || {}).value;
  var tp = (document.getElementById('akAgmFilterTopic') || {}).value;
  if (y && y.trim())  p.year = y.trim();
  if (tp && tp.trim()) p.topic = tp.trim();
  if (df) p.date_from = df;
  if (dt) p.date_to   = dt;
  p = _applyRoleScopeFloor(p);

  var tbody = document.getElementById('akAgmTableBody');
  if (tbody) tbody.innerHTML = '<tr><td colspan="6" style="text-align:center;color:#999;padding:20px;">Loading…</td></tr>';

  apiAkAgmList(p).then(function(result) {
    _akAgmTotal = result.total || 0;
    var rows = result.data || [];
    if (!rows.length) {
      if (tbody) tbody.innerHTML = '<tr><td colspan="6" style="text-align:center;color:#999;padding:30px;">No AGM records found.</td></tr>';
    } else {
      var html = '';
      var _canDel = _canDeleteRecord();
      rows.forEach(function(r, i) {
        var sno = (_akAgmPage - 1) * _akAgmLimit + i + 1;
        var _label = escHtml((r.year || '') + ' / ' + (r.topic || '') || ('AGM #' + r.id)).replace(/\'/g, "\\'");
        html += '<tr>'
          + '<td>' + sno + '</td>'
          + '<td>' + escHtml(r.year || '-') + '</td>'
          + '<td>' + escHtml(r.topic || '-') + '</td>'
          + '<td>' + (r.agm_date ? formatDateNice(r.agm_date) : '-') + '</td>'
          + '<td>' + (r.participants != null ? r.participants : '-') + '</td>'
          + '<td>'
            + '<button class="btn-icon" title="View" onclick="openViewAkAgm(' + r.id + ')"><i class="fas fa-eye"></i></button>'
            + '<button class="btn-icon" title="Edit" onclick="openEditAkAgm(' + r.id + ')"><i class="fas fa-edit"></i></button>'
            + (_canDel ? '<button class="btn-icon text-danger" title="Delete" onclick="deleteAkAgmFromList(' + r.id + ',\'' + _label + '\')"><i class="fas fa-trash-alt"></i></button>' : '')
          + '</td>'
        + '</tr>';
      });
      if (tbody) tbody.innerHTML = html;
    }
    if (typeof renderListPagination === 'function') {
      renderListPagination('#page-akAlumniAgm .pagination', _akAgmTotal, _akAgmPage, _akAgmLimit, 'loadAkAgmList');
    }
    var ipp = document.getElementById('akAgmItemsPerPage');
    if (ipp) ipp.value = String(_akAgmLimit);
  }).catch(function(err) {
    if (tbody) tbody.innerHTML = '<tr><td colspan="6" style="text-align:center;color:#c0392b;padding:30px;">Failed to load — ' + escHtml((err && err.message) || 'unknown error') + '</td></tr>';
  });
}

function applyAkAgmFilters() { loadAkAgmList(1); }

function resetAkAgmFilters() {
  _clearListFilters('akAlumniAgm');
  ['akAgmFilterYear','akAgmFilterFrom','akAgmFilterTo','akAgmFilterTopic'].forEach(function(id) {
    var el = document.getElementById(id); if (el) el.value = '';
  });
  loadAkAgmList(1);
}

function exportAkAgmList() {
  var p = {};
  var y  = (document.getElementById('akAgmFilterYear')  || {}).value;
  var df = (document.getElementById('akAgmFilterFrom')  || {}).value;
  var dt = (document.getElementById('akAgmFilterTo')    || {}).value;
  var tp = (document.getElementById('akAgmFilterTopic') || {}).value;
  if (y && y.trim())  p.year = y.trim();
  if (tp && tp.trim()) p.topic = tp.trim();
  if (df) p.date_from = df;
  if (dt) p.date_to = dt;
  p = _applyRoleScopeFloor(p);
  var url = API_BASE + '/ak/alumni-agm/export/excel' + _qs(p);
  fetch(url, { headers: authToken ? { 'Authorization': 'Bearer ' + authToken } : {} })
    .then(function(r) { if (!r.ok) throw new Error('Export failed (HTTP ' + r.status + ')'); return r.blob(); })
    .then(function(blob) {
      var a = document.createElement('a');
      a.href = URL.createObjectURL(blob);
      a.download = 'AAG_AGM_' + (new Date()).toISOString().slice(0, 10) + '.xlsx';
      document.body.appendChild(a); a.click(); document.body.removeChild(a);
      setTimeout(function() { URL.revokeObjectURL(a.href); }, 1000);
    })
    .catch(function(err) { alert('Export failed: ' + (err.message || err)); });
}

// ---- Add / Edit modal ------------------------------------------------------

function openAddAkAgm() {
  _akAgmEditingId = null;
  _resetAkAgmModal();
  var t  = document.getElementById('akAgmFormTitle');
  var st = document.getElementById('akAgmSubmitText');
  if (t)  t.innerHTML = '<i class="fas fa-plus-circle"></i> Add AGM';
  if (st) st.textContent = 'Save';
  document.getElementById('akAgmFormModal').style.display = 'flex';
}

function openEditAkAgm(id) {
  _akAgmEditingId = id;
  _resetAkAgmModal();
  var t  = document.getElementById('akAgmFormTitle');
  var st = document.getElementById('akAgmSubmitText');
  if (t)  t.innerHTML = '<i class="fas fa-edit"></i> Edit AGM';
  if (st) st.textContent = 'Update';
  document.getElementById('akAgmFormModal').style.display = 'flex';
  apiAkAgmDetail(id).then(function(d) {
    _setVal('akAgmYear',         d.year);
    _setVal('akAgmTopic',        d.topic);
    _setVal('akAgmDate',         d.agm_date);
    _setVal('akAgmParticipants', d.participants);
  }).catch(function(err) { showUserError('loading AGM', err); });
}

function closeAkAgmModal() {
  document.getElementById('akAgmFormModal').style.display = 'none';
}

function _resetAkAgmModal() {
  ['akAgmYear','akAgmTopic','akAgmDate','akAgmParticipants'].forEach(function(id) {
    var el = document.getElementById(id); if (el) el.value = '';
  });
}

function saveAkAgm() {
  function _v(id) { var el = document.getElementById(id); return el ? (el.value || '').trim() : ''; }
  if (!_v('akAgmYear'))         { alert('Please enter Year.'); return; }
  if (!_v('akAgmTopic'))        { alert('Please enter Topic of AGM.'); return; }
  if (!_v('akAgmDate'))         { alert('Please select Date.'); return; }
  if (!_v('akAgmParticipants')) { alert('Please enter No. of Participants.'); return; }

  var payload = {
    year:         _v('akAgmYear'),
    topic:        _v('akAgmTopic'),
    agm_date:     _v('akAgmDate'),
    participants: parseInt(_v('akAgmParticipants'), 10),
    status:       'Active',
  };

  var promise = _akAgmEditingId
    ? apiUpdateAkAgm(_akAgmEditingId, payload)
    : apiCreateAkAgm(payload);
  promise
    .then(function() {
      alert('AGM ' + (_akAgmEditingId ? 'updated' : 'saved') + ' successfully.');
      _akAgmEditingId = null;
      closeAkAgmModal();
      loadAkAgmList(_akAgmPage);
    })
    .catch(function(err) { showUserError('saving AGM', err); });
}

// ---- View modal (read-only) ------------------------------------------------

function openViewAkAgm(id) {
  apiAkAgmDetail(id).then(function(d) {
    var setText = function(elId, v) {
      var el = document.getElementById(elId);
      if (el) el.textContent = (v === null || v === undefined || v === '') ? '-' : v;
    };
    setText('vAkAgmYear',         d.year);
    setText('vAkAgmDate',         d.agm_date ? formatDateNice(d.agm_date) : '');
    setText('vAkAgmTopic',        d.topic);
    setText('vAkAgmParticipants', d.participants);
    setText('vAkAgmStatus',       d.status);
    document.getElementById('akAgmViewModal').style.display = 'flex';
  }).catch(function(err) { showUserError('loading AGM detail', err); });
}

function closeAkAgmViewModal() {
  document.getElementById('akAgmViewModal').style.display = 'none';
}

// ============================================================================
// MGJ DASHBOARD — mirrors FLP dashboard wiring patterns. Filters / KPIs /
// charts / drill-down all hit /api/mgj-dashboard/*. Uses Chart.js (same
// CHART_COLORS palette as FLP for visual continuity).
// ============================================================================

var _MGJ_CHART_COLORS = (typeof CHART_COLORS !== 'undefined')
  ? CHART_COLORS
  : ['#732269','#9b3d8e','#c06bb3','#e0a3d4','#f0d1ea','#3498db','#27ae60','#f39c12','#e74c3c','#1abc9c'];
var _MGJ_STAGE_ORDER  = ['Enrolled','In Pakhwada','Promoted to Leader','Leader Trained','Alumni'];
var _MGJ_STAGE_COLORS = ['#732269','#9b3d8e','#c06bb3','#3498db','#27ae60'];
var _mgjDashChartInstances = {};
var _mgjDashFilterDropdownsLoaded = false;

function _mgjDashCollectFilters() {
  var p = {};
  var st = (document.getElementById('mgjDashFilterState')    || {}).value;
  var di = (document.getElementById('mgjDashFilterDistrict') || {}).value;
  var ce = (document.getElementById('mgjDashFilterCentre')   || {}).value;
  var df = (document.getElementById('mgjDashFilterDateFrom') || {}).value;
  var dt = (document.getElementById('mgjDashFilterDateTo')   || {}).value;
  if (st)  p.state_code    = st;
  if (di)  p.district_code = di;
  if (ce)  p.centre_code   = ce;
  if (df)  p.date_from     = df;
  if (dt)  p.date_to       = dt;
  return _applyRoleScopeFloor(p, 'mgj');
}

function _populateMgjDashFilterDropdowns() {
  if (_mgjDashFilterDropdownsLoaded) return;
  _mgjDashFilterDropdownsLoaded = true;
  // 2026-06-08: For SL / DL / PI users, skip the all-states fetch (the
  // soft lock wired in navigateTo for mgjHome already hard-locks State
  // to the user's MGJ state). Then pre-load the District dropdown with
  // the user's state districts so Delhi SL sees the 3 Delhi districts
  // (East/North/South) immediately. Centre stays empty until District
  // is picked — that's the user's spec ("centre according to district").
  var role = (currentUser && currentUser.role) || '';
  var isDlPiSl = (role === 'pi' || role === 'district_lead' || role === 'state_lead');
  if (isDlPiSl && typeof _resolveMgjScopeForDlPi === 'function') {
    _resolveMgjScopeForDlPi().then(function() {
      if (!currentUser.mgj_state_code) return;
      if (typeof apiMgjMDistrictsDropdown !== 'function') return;
      apiMgjMDistrictsDropdown({ state_code: currentUser.mgj_state_code }).then(function(rows) {
        var dSel = document.getElementById('mgjDashFilterDistrict');
        if (!dSel) return;
        dSel.innerHTML = '<option value="">All Districts</option>';
        (rows || []).forEach(function(r) {
          var o = document.createElement('option');
          o.value = r.district_code; o.textContent = r.district_name;
          dSel.appendChild(o);
        });
      }).catch(function() {});
    });
    return;
  }
  // Use MGJ master endpoints so the dashboard only ever sees MGJ geo.
  apiMgjMStatesDropdown().then(function(rows) {
    var sel = document.getElementById('mgjDashFilterState');
    if (!sel) return;
    (rows || []).forEach(function(r) {
      var o = document.createElement('option');
      o.value = r.state_code; o.textContent = r.state_name;
      sel.appendChild(o);
    });
  }).catch(function() {});
}

function onMgjDashStateChange() {
  // 2026-06-04: also wipe .value (not just innerHTML) so a stale
  // selection from the previous state can't survive the cascade.
  // Mirrors the AK Dashboard reset pattern.
  var sc = (document.getElementById('mgjDashFilterState') || {}).value || '';
  var dSel = document.getElementById('mgjDashFilterDistrict');
  var cSel = document.getElementById('mgjDashFilterCentre');
  if (dSel) { dSel.innerHTML = '<option value="">All Districts</option>'; dSel.value = ''; }
  if (cSel) { cSel.innerHTML = '<option value="">All Centres</option>';   cSel.value = ''; }
  if (!sc) return;
  apiMgjMDistrictsDropdown({ state_code: sc }).then(function(rows) {
    (rows || []).forEach(function(r) {
      var o = document.createElement('option');
      o.value = r.district_code; o.textContent = r.district_name;
      dSel.appendChild(o);
    });
  }).catch(function() {});
}

function onMgjDashDistrictChange() {
  // 2026-06-04: also wipe .value, as above.
  var dc = (document.getElementById('mgjDashFilterDistrict') || {}).value || '';
  var cSel = document.getElementById('mgjDashFilterCentre');
  if (cSel) { cSel.innerHTML = '<option value="">All Centres</option>'; cSel.value = ''; }
  if (!dc) return;
  apiMgjMCentresDropdown({ district_code: dc }).then(function(rows) {
    (rows || []).forEach(function(r) {
      var o = document.createElement('option');
      o.value = r.centre_code; o.textContent = r.centre_name;
      cSel.appendChild(o);
    });
  }).catch(function() {});
}

function loadMgjDashboard() {
  _populateMgjDashFilterDropdowns();
  _refreshMgjDashboard();
}

function applyMgjDashboardFilters() { _refreshMgjDashboard(); }

function resetMgjDashboardFilters() {
  ['mgjDashFilterState','mgjDashFilterDistrict','mgjDashFilterCentre',
   'mgjDashFilterDateFrom','mgjDashFilterDateTo'].forEach(function(id) {
    var el = document.getElementById(id); if (el) el.value = '';
  });
  // Reset cascaded children.
  document.getElementById('mgjDashFilterDistrict').innerHTML = '<option value="">All Districts</option>';
  document.getElementById('mgjDashFilterCentre').innerHTML   = '<option value="">All Centres</option>';
  // 2026-06-08: After clearing, re-apply the SL/DL/PI lock so the
  // State dropdown gets re-pinned and the District list is repopulated
  // with the user's state districts. Centre stays empty (it cascades
  // from District). Pass null for centreSelId so the lock doesn't
  // overwrite the empty centre dropdown with a pre-filled state list.
  if (typeof _lockMgjFiltersForDlPi === 'function') {
    _lockMgjFiltersForDlPi('mgjDashFilterState', null, { centreMode: 'soft' });
  }
  // Reset the once-only flag so _populateMgjDashFilterDropdowns reloads
  // the District list for SL/DL/PI after Reset.
  _mgjDashFilterDropdownsLoaded = false;
  _populateMgjDashFilterDropdowns();
  _refreshMgjDashboard();
}

function _refreshMgjDashboard() {
  var f = _mgjDashCollectFilters();
  // KPIs (top 5 cards above the process flow — kept from old layout).
  // The 5th card was Pakhwada Sessions; on 2026-05-14 it was swapped to
  // Active Alumni per client request. Pakhwada totals still live in the
  // monthly/quarter charts and the Pakhwada Coverage card below.
  apiMgjDashboardStats(f).then(function(d) {
    var setText = function(id, v) { var el = document.getElementById(id); if (el) el.textContent = (v != null ? v : 0); };
    setText('mgjKpiStates',  d.states);
    setText('mgjKpiCentres', d.total_centres);
    setText('mgjKpiMembers', d.total_members);
    setText('mgjKpiLeaders', d.active_leaders);
    setText('mgjKpiAlumni',  d.total_alumni);
  }).catch(function(err) { showUserError('loading MGJ KPIs', err); });

  // New MIS-style sections — single call to /api/mgj-dashboard/mis
  apiMgjDashboardMis(f).then(function(d) {
    _mgjRenderMisSections(d || {});
  }).catch(function(err) { showUserError('loading MGJ MIS data', err); });
}

// ---- Chart factories ----
// Each one destroys its previous instance before re-rendering so filter
// changes don't stack canvases.
function _mgjMakeChart(canvasId, config) {
  var prev = _mgjDashChartInstances[canvasId];
  if (prev) { try { prev.destroy(); } catch(e) {} }
  var el = document.getElementById(canvasId);
  if (!el) return;
  _mgjDashChartInstances[canvasId] = new Chart(el.getContext('2d'), config);
}

// ---- MGJ Dashboard renderer ----
// Single top-level paint from /api/mgj-dashboard/mis. The dashboard
// reuses FLP's .chart-card / .kpi-card primitives so the visual rhythm
// matches the rest of the MIS. Chart palette is the same FLP_STATUS_-
// adjacent purple family (CHART_COLORS) for consistency.

function _mgjRenderMisSections(d) {
  var t  = d.totals || {};
  var tr = d.monthly_trend || [];
  // Real Pakhwada Session data (from mgj_pakhwada_sessions, the same table
  // the Pakhwada Session tab reads). Previously this dashboard pulled
  // Pakhwada numbers from mgj_monthly_activities (the manually-typed
  // monthly KPI form) which diverged from what PIs actually log.
  var psM    = d.pakhwada_sessions_monthly || [];
  var psCov  = d.pakhwada_coverage || {};
  var ld = d.leaders_by_state || [];
  var camp = d.campaigns || [];
  var alumni = d.alumni || {};
  var setText = function(id, v) {
    var el = document.getElementById(id);
    if (el) el.textContent = (v == null || v === '') ? '0' : String(v);
  };
  var setWidth = function(id, pct) {
    var el = document.getElementById(id);
    if (el) el.style.width = (Math.max(0, Math.min(100, pct))) + '%';
  };

  // ----- Monthly Sessions — Pakhwada (Input) vs Pakhwada (Sports) -----
  // Grouped bar. Counts INPUT vs SPORTS sessions logged in the Pakhwada
  // Session tab, grouped by month of planned_date. 1:1 with what's shown
  // in the Pakhwada tab list — no dependence on the Overall Activities form.
  _mgjMakeChart('misMonthlyTrendChart', {
    type: 'bar',
    data: {
      labels: psM.map(function(r) { return r.label; }),
      datasets: [
        { label: 'Pakhwada (Input)',  data: psM.map(function(r) { return parseInt(r.input_sessions,  10) || 0; }), backgroundColor:'#732269', borderRadius:4 },
        { label: 'Pakhwada (Sports)', data: psM.map(function(r) { return parseInt(r.sports_sessions, 10) || 0; }), backgroundColor:'#c06bb3', borderRadius:4 },
      ]
    },
    options: { responsive:true, maintainAspectRatio:false, plugins:{ legend:{ position:'bottom', labels:{ padding:14 } } }, scales:{ y:{ beginAtZero:true, ticks:{ precision:0 } } } }
  });

  // ----- Monthly Activities — stacked bar from the Overall Activities
  // monthly form. Replaces the old Quarter-wise Comparison (which was a
  // duplicate of the Monthly Sessions chart bucketed differently) and the
  // multi-line version (lines crossed messily with sparse data points).
  // Stacked bars show total monthly engagement + the composition of each
  // activity bucket in one glance, and visually distinct from the
  // grouped-bar Monthly Sessions chart next to it.
  _mgjMakeChart('misMonthlyActivitiesChart', {
    type: 'bar',
    data: {
      labels: tr.map(function(r) { return r.label; }),
      datasets: [
        // Palette: monochromatic MGJ purple progression, darkest at the
        // bottom (Pakhwada — the foundational activity) fading to lightest
        // at the top. Same family used by FLP's status pie, so the MGJ
        // dashboard reads as a natural extension of the rest of the MIS.
        { label: 'Pakhwada Sessions', data: tr.map(function(r) { return parseInt(r.pakhwada,        10) || 0; }), backgroundColor:'#4a1543', borderRadius:{ topLeft:0, topRight:0, bottomLeft:4, bottomRight:4 }, stack:'activities' },
        { label: 'Sports Sessions',   data: tr.map(function(r) { return parseInt(r.sports,          10) || 0; }), backgroundColor:'#732269', stack:'activities' },
        { label: 'Parent Meetings',   data: tr.map(function(r) { return parseInt(r.parent_meetings, 10) || 0; }), backgroundColor:'#a05798', stack:'activities' },
        { label: 'Assignments',       data: tr.map(function(r) { return parseInt(r.assignments,     10) || 0; }), backgroundColor:'#d4a3c5', borderRadius:{ topLeft:4, topRight:4, bottomLeft:0, bottomRight:0 }, stack:'activities' },
      ]
    },
    options: {
      responsive:true, maintainAspectRatio:false,
      plugins: {
        legend: { position:'bottom', labels:{ padding:12, boxWidth:14, font:{ size:11 } } },
        tooltip: {
          callbacks: {
            footer: function(items) {
              var sum = items.reduce(function(a, it) { return a + (it.parsed.y || 0); }, 0);
              return 'Total: ' + sum;
            }
          }
        }
      },
      scales: {
        x: { stacked:true, grid:{ display:false } },
        y: { stacked:true, beginAtZero:true, ticks:{ precision:0 } }
      }
    }
  });

  // ----- Pakhwada Coverage (from real session table, NOT the KPI form) -----
  // planned = total sessions in scope, conducted = sessions with
  // status='Conducted'. Reading from mgj_pakhwada_sessions makes this
  // match the Pakhwada Session tab's "5 of 7 planned" indicator exactly.
  var done    = parseInt(psCov.conducted, 10) || 0;
  var planned = parseInt(psCov.planned,   10) || 0;
  var pct     = planned ? Math.round(done * 100 / planned) : 0;
  setText('misCoverageDone',  done);
  setText('misCoverageTotal', planned);
  setText('misCoveragePct',   pct + '%');
  setWidth('misCoverageFill', pct);

  // ----- Row 4: Campaigns (table) + Outreach (inline stats) -----
  setText('misCanopy',              t.canopy_activities);
  setText('misMikePrachar',         t.mike_prachar);
  setText('misSynergyMeetings',     t.synergy_meetings);
  setText('misSynergyParticipants', t.synergy_participants);
  setText('misAlumniMeetP',         t.alumni_meet_participants);

  var totalP = camp.reduce(function(a,r) { return a + (parseInt(r.participants,10)||0); }, 0);
  var campBody = document.getElementById('misCampaignsBody');
  if (campBody) {
    if (!camp.length) {
      campBody.innerHTML = '<tr><td colspan="4" style="text-align:center;color:#999;padding:20px;">No campaign entries.</td></tr>';
    } else {
      campBody.innerHTML = camp.map(function(r) {
        var p = parseInt(r.participants, 10) || 0;
        var pct = totalP ? Math.round(p * 100 / totalP) : 0;
        return '<tr>'
          + '<td>' + escHtml(r.campaign_type || '—') + '</td>'
          + '<td>' + (r.events || 0) + '</td>'
          + '<td>' + p + '</td>'
          + '<td><div style="display:inline-block;width:70px;height:8px;background:#f0e6ed;border-radius:4px;overflow:hidden;vertical-align:middle;margin-right:6px;"><div style="width:' + pct + '%;height:100%;background:#732269;"></div></div>' + pct + '%</td>'
        + '</tr>';
      }).join('');
    }
  }

  // ----- Row 5: WWW Linkages funnel + GBV callout/trend -----
  // New 3-stage funnel (replaces the old Enabled→Enrolled pair on 2026-05-26).
  // Conversion = Enrollment / Interested.
  var interested = parseInt(t.www_women_interested, 10) || 0;
  var registered = parseInt(t.www_women_registered, 10) || 0;
  var enrollment = parseInt(t.www_women_enrollment, 10) || 0;
  setText('misWwwInterested', interested);
  setText('misWwwRegistered', registered);
  setText('misWwwEnrollment', enrollment);
  setText('misWwwConv', interested ? Math.round(enrollment * 100 / interested) + '%' : '—');

  setText('misGbvReached', t.gbv_reached);
  _mgjMakeChart('misGbvTrendChart', {
    type: 'line',
    data: {
      labels: tr.map(function(r) { return r.label; }),
      datasets: [{ label:'Engagement (period)', data: tr.map(function(r) { return parseInt(r.total_engagement, 10) || 0; }),
                   borderColor:'#e74c3c', backgroundColor:'rgba(231,76,60,.12)', fill:true, tension:.3, pointRadius:3 }]
    },
    options: { responsive:true, maintainAspectRatio:false, plugins:{ legend:{ display:false } }, scales:{ y:{ beginAtZero:true } } }
  });

  // ----- Row 6: Leader's Log totals (inline stats) + per-state table -----
  // Trimmed to 2 series on 2026-05-26 (Vaccinations + Unpaid-Care boys
  // were dropped from the form). The matching DOM elements have also
  // been removed from index.html, so the setText calls for those two
  // are gone — leaving them would silently no-op anyway.
  setText('misLeaderCommunity',     t.leader_community_actions);
  setText('misLeaderWwwForms',      t.leader_www_forms);

  var ldBody = document.getElementById('misLeadersStateBody');
  if (ldBody) {
    if (!ld.length) {
      ldBody.innerHTML = '<tr><td colspan="4" style="text-align:center;color:#999;padding:20px;">No leader-log entries.</td></tr>';
    } else {
      ldBody.innerHTML = ld.map(function(r) {
        var total = (parseInt(r.community_actions,10)||0) + (parseInt(r.www_forms,10)||0);
        return '<tr>'
          + '<td>' + escHtml(r.state_name || '—') + '</td>'
          + '<td>' + (r.community_actions || 0) + '</td>'
          + '<td>' + (r.www_forms         || 0) + '</td>'
          + '<td><b style="color:var(--primary);">' + total + '</b></td>'
        + '</tr>';
      }).join('');
    }
  }

  // ----- Row 7: Survey completion bars + Alumni stats -----
  // Normalise survey counts to a 0..100% width vs the largest sample so
  // the relative magnitude across stages is visually obvious.
  var surveyVals = [
    parseInt(t.baseline_count, 10) || 0,
    parseInt(t.midline_y1,     10) || 0,
    parseInt(t.midline_y2,     10) || 0,
    parseInt(t.endline_count,  10) || 0,
  ];
  var surveyMax = Math.max.apply(null, surveyVals.concat([1]));
  setText('misBaseline',  surveyVals[0]); setWidth('misBaselineBar',  surveyVals[0] * 100 / surveyMax);
  setText('misMidlineY1', surveyVals[1]); setWidth('misMidlineY1Bar', surveyVals[1] * 100 / surveyMax);
  setText('misMidlineY2', surveyVals[2]); setWidth('misMidlineY2Bar', surveyVals[2] * 100 / surveyMax);
  setText('misEndline',   surveyVals[3]); setWidth('misEndlineBar',   surveyVals[3] * 100 / surveyMax);

  setText('misAlumniTotal',    alumni.total);
  setText('misAlumniAttended', alumni.attended);
}

// ---- Drill-down modal (lightweight; reuses any existing modal infra) ----
function _mgjOpenDrillDown(chart, value) {
  var f = _mgjDashCollectFilters();
  f.chart = chart;
  f.value = value;
  apiMgjDashboardDrill(f).then(function(resp) {
    var rows = (resp && resp.data) || [];
    var html = '<div style="position:fixed;inset:0;background:rgba(0,0,0,.45);z-index:9999;display:flex;align-items:center;justify-content:center;" onclick="this.remove()">'
      + '<div style="background:#fff;border-radius:8px;width:min(820px,92vw);max-height:80vh;overflow:auto;padding:18px 22px;" onclick="event.stopPropagation()">'
      + '<div style="display:flex;justify-content:space-between;align-items:center;margin-bottom:10px;">'
      +   '<h3 style="margin:0;color:#732269;">' + escHtml(chart) + ' — ' + escHtml(value) + ' (' + rows.length + ')</h3>'
      +   '<button class="btn-icon" onclick="this.closest(\'div[style*=fixed]\').remove()">&times;</button>'
      + '</div>'
      + '<table class="data-table full-width"><thead><tr><th>Name</th><th>Enrollment</th><th>Gender</th><th>Age</th><th>State</th><th>Status</th></tr></thead><tbody>'
      + (rows.length
          ? rows.map(function(r) {
              return '<tr><td>' + escHtml(r.name || '-') + '</td>'
                   + '<td>' + escHtml(r.enrollment_number || '-') + '</td>'
                   + '<td>' + escHtml(r.gender || '-') + '</td>'
                   + '<td>' + (r.age_at_enrollment != null ? r.age_at_enrollment : '-') + '</td>'
                   + '<td>' + escHtml(r.state_name || '-') + '</td>'
                   + '<td>' + escHtml(r.status || '-') + '</td></tr>';
            }).join('')
          : '<tr><td colspan="6" style="text-align:center;color:#999;padding:18px;">No members match this selection.</td></tr>')
      + '</tbody></table>'
      + '</div></div>';
    var wrap = document.createElement('div');
    wrap.innerHTML = html;
    document.body.appendChild(wrap.firstChild);
  }).catch(function(err) { showUserError('opening drill-down', err); });
}

// ============================================================================
// AK (Azad Kishori) Dashboard — coral/peach youth-program theme. Distinct
// data and analytics from FLP/MGJ. Reads from /api/ak-dashboard/*.
// ============================================================================

var _akDashFilterDropdownsLoaded = false;
var _akDashChartInstances = {};

function _akDashMakeChart(id, config) {
  var prev = _akDashChartInstances[id];
  if (prev) { try { prev.destroy(); } catch(e) {} }
  var el = document.getElementById(id);
  if (!el) return;
  _akDashChartInstances[id] = new Chart(el.getContext('2d'), config);
}

function _akDashCollectFilters() {
  var p = {};
  var st = (document.getElementById('akDashFilterState')    || {}).value;
  var di = (document.getElementById('akDashFilterDistrict') || {}).value;
  var ce = (document.getElementById('akDashFilterCentre')   || {}).value;
  var bt = (document.getElementById('akDashFilterBatch')    || {}).value;
  var df = (document.getElementById('akDashFilterFrom')     || {}).value;
  var dt = (document.getElementById('akDashFilterTo')       || {}).value;
  // 2026-06-01 (v8): Year filter on Education Current Level restored.
  // Sent as education_year so the backend's education_distribution
  // query scopes by cohort year. Education Progression uses its own
  // batch filter (handled in the render path, no backend round-trip).
  // 2026-06-04: Education Year is now a number input (was a select);
  // its value reaches us as a string and we forward it as before. The
  // helper trims and ignores empty / NaN entries so a partially-typed
  // year ("20", "202") doesn't get sent until the user lands on a valid
  // 4-digit year (handled below).
  var eyRaw = (document.getElementById('akDashEducationYear') || {}).value;
  var ey = '';
  if (eyRaw) {
    var t = String(eyRaw).trim();
    if (/^\d{4}$/.test(t)) ey = t;   // only forward fully-typed years
  }
  if (st) p.state_code      = st;
  if (di) p.district_code   = di;
  if (ce) p.centre_code     = ce;
  if (bt) p.batch_id        = bt;
  if (df) p.date_from       = df;
  if (dt) p.date_to         = dt;
  if (ey) p.education_year  = ey;
  return _applyRoleScopeFloor(p);
}

// 2026-06-04: Education Current Level year picker is now a free-form
// number input (per user spec — no dropdown). Year change triggers a
// full charts refresh because the filter applies server-side. The
// previous Increase / Decrease range filter has been removed.
function onAkDashEducationYearChange() { _refreshAkDashboard(); }

// =============================================================================
// 2026-06-04: NEW AK Dashboard sections — Adda Reach, Family Engagement,
// Assessment Reports. Each renderer is idempotent + degrades gracefully
// when the backend payload doesn't carry the relevant series (the
// dashboard JSON is additive — fields appear as they're built out).
// =============================================================================

function _akDashRenderAddaReach(d) {
  // Reuses the existing /charts.addas_by_state payload (state_name,
  // adda_count, members_reached). Renders a horizontal bar of
  // members_reached per state so the dashboard surfaces actual outreach
  // scale, not just adda count.
  var rows = (d && d.addas_by_state) || [];
  // Sort biggest first; cap to top 10 so the chart stays readable.
  var top = rows.slice().sort(function(a, b) {
    return (parseInt(b.members_reached, 10) || 0) - (parseInt(a.members_reached, 10) || 0);
  }).slice(0, 10);
  _akDashMakeChart('akDashAddaReachChart', {
    type: 'bar',
    data: {
      labels: top.map(function(r) { return r.state_name || '—'; }),
      datasets: [{
        label: 'Members Reached',
        data: top.map(function(r) { return parseInt(r.members_reached, 10) || 0; }),
        backgroundColor: '#1abc9c', borderRadius: 4, barThickness: 18,
      }],
    },
    options: {
      indexAxis: 'y', responsive: true, maintainAspectRatio: false,
      plugins: { legend: { display: false } },
      scales: {
        x: { beginAtZero: true, ticks: { precision: 0 } },
        y: { ticks: { font: { size: 11 } }, grid: { display: false } },
      },
    },
  });
}

// 2026-06-04: _akDashRenderAssessmentReports and _akDashRenderFamilyEngagement
// removed alongside their HTML blocks per user spec — no Baseline / Midline /
// Endline KPI cards, no comparison chart, no Family Engagement placeholders.

// 2026-06-01 (v7): Batch picker on Education Progression — re-renders
// only that chart from the cached batch list (client-side filter on
// the existing education_progression payload, no extra round-trip).
function onAkDashEduProgBatchChange() {
  if (window._akDashLastCharts) _akDashRenderEducationProgression(window._akDashLastCharts);
}

function _populateAkDashFilters() {
  if (_akDashFilterDropdownsLoaded) return;
  _akDashFilterDropdownsLoaded = true;
  // States from the AK-only master geography (independent of FLP/MGJ).
  if (typeof apiAkMStatesDropdown === 'function') {
    apiAkMStatesDropdown().then(function(rows) {
      var sel = document.getElementById('akDashFilterState');
      if (!sel) return;
      (rows || []).forEach(function(r) {
        var o = document.createElement('option');
        o.value = r.state_code; o.textContent = r.state_name;
        sel.appendChild(o);
      });
      // 2026-06-06: For State Lead, after States load, auto-pick their
      // state and trigger the District cascade so District/Centre are
      // pre-narrowed to their state. State select itself isn't disabled
      // here (Dashboard is read-only navigation) — backend role-scope
      // still floors the data — but the dropdowns visually match.
      // 2026-06-08: Extended to DL/PI too. They also get District auto-
      // picked (when district_code resolved) and Centre auto-picked
      // (when centre_code resolved) so the cards/graphs reflect their
      // narrowest scope on first paint without needing to manually
      // click through the cascade.
      var _r = (currentUser && currentUser.role) || '';
      if ((_r === 'state_lead' || _r === 'district_lead' || _r === 'pi') &&
          currentUser.state_code) {
        sel.value = currentUser.state_code;
        if (typeof onAkDashStateChange === 'function') onAkDashStateChange();
        if ((_r === 'district_lead' || _r === 'pi') && currentUser.district_code) {
          // Allow the district fetch from onAkDashStateChange to land
          // (~400ms typical) then pick the user's district and fire
          // the centre cascade.
          setTimeout(function() {
            var dSel = document.getElementById('akDashFilterDistrict');
            if (dSel) { dSel.value = currentUser.district_code; }
            if (typeof onAkDashDistrictChange === 'function') onAkDashDistrictChange();
            if (_r === 'pi' && currentUser.centre_code) {
              setTimeout(function() {
                var cSel = document.getElementById('akDashFilterCentre');
                if (cSel) cSel.value = currentUser.centre_code;
                if (typeof onAkDashCentreChange === 'function') onAkDashCentreChange();
              }, 600);
            }
          }, 600);
        }
      }
    }).catch(function() {});
  }
  // 2026-06-06: For non-SL roles, do the initial all-states Batch fetch
  // now. For SL we let the state-auto-pick above fire onAkDashStateChange
  // which calls _loadAkDashBatches with the floored state — avoids a
  // duplicate fetch race that double-populated the dropdown.
  // 2026-06-08: Same skip for DL/PI — they get fired through the
  // cascade chain above and a parallel _loadAkDashBatches('','')
  // would race + double-populate.
  var _r2 = (currentUser && currentUser.role) || '';
  if (!((_r2 === 'state_lead' || _r2 === 'district_lead' || _r2 === 'pi') &&
        currentUser && currentUser.state_code)) {
    _loadAkDashBatches('', '');
  }
}

// 2026-06-06: Repopulate the Dashboard Batch dropdown filtered by state
// and/or centre. Centre takes precedence (narrowest). When neither is
// set, all active batches load (unless the user is SL — handled above).
//
// Duplicate-prevention notes:
//   * A monotonically increasing request token lets a fast cascade
//     change (e.g. SL auto-fire + manual Centre pick within <300ms)
//     drop stale fetch responses on the floor instead of appending a
//     second copy of each batch.
//   * Defensive dedupe by batch.id at append time covers the (rare)
//     case where the backend itself returns duplicate rows due to a
//     JOIN expansion.
var _akDashBatchReqSeq = 0;
function _loadAkDashBatches(stateCode, centreCode) {
  var sel = document.getElementById('akDashFilterBatch');
  if (!sel) return;
  // Floor to SL's state when caller didn't pass one.
  if (!stateCode && currentUser && currentUser.role === 'state_lead' && currentUser.state_code) {
    stateCode = currentUser.state_code;
  }
  var qs = 'status=Active&limit=200';
  if (centreCode)      qs += '&centre_code=' + encodeURIComponent(centreCode);
  else if (stateCode)  qs += '&state_code='  + encodeURIComponent(stateCode);
  var mySeq = ++_akDashBatchReqSeq;
  sel.innerHTML = '<option value="">All Batches</option>';
  fetch(window.location.origin + '/api/ak-batches?' + qs, {
    headers: authToken ? { Authorization: 'Bearer ' + authToken } : {}
  }).then(function(r) { return r.json(); }).then(function(result) {
    // Drop stale responses — only the latest call may render.
    if (mySeq !== _akDashBatchReqSeq) return;
    var data = (result && result.data) || result || [];
    var seen = {};
    (data || []).forEach(function(b) {
      if (!b || b.id == null) return;
      if (seen[b.id]) return;          // dedupe defensively by id
      seen[b.id] = 1;
      var o = document.createElement('option');
      o.value = b.id;
      o.textContent = b.name + (b.year ? ' (' + b.year + ')' : '');
      sel.appendChild(o);
    });
  }).catch(function() {});
}

// 2026-06-04: cascade handlers strengthened per user spec —
//   - State change   → reset District + Centre + Batch
//   - District change → reset Centre + Batch
//   - Centre change   → reset Batch
//   Each cascade explicitly clears .value (not just innerHTML) so a
//   programmatic reset propagates correctly. Temporary console.log
//   statements show the selected geo IDs being forwarded to each API
//   call — easy to diff against the network panel.
function onAkDashStateChange() {
  var sc = (document.getElementById('akDashFilterState') || {}).value || '';
  var d = document.getElementById('akDashFilterDistrict');
  var c = document.getElementById('akDashFilterCentre');
  var b = document.getElementById('akDashFilterBatch');
  if (d) { d.innerHTML = '<option value="">All Districts</option>'; d.value = ''; }
  if (c) { c.innerHTML = '<option value="">All Centres</option>';   c.value = ''; }
  if (b) b.value = '';
  // 2026-06-06: Batch dropdown now narrows by state too (Centre→Batch cascade).
  _loadAkDashBatches(sc, '');
  try { console.log('[AK-Dash] onStateChange — state_code=', sc || '(All)'); } catch (e) {}
  if (!sc) return;
  apiAkMDistrictsDropdown({ state_code: sc }).then(function(rows) {
    try { console.log('[AK-Dash] districts for state=', sc, '→ count=', (rows||[]).length); } catch (e) {}
    (rows || []).forEach(function(r) {
      var o = document.createElement('option');
      o.value = r.district_code; o.textContent = r.district_name;
      d.appendChild(o);
    });
  }).catch(function(err) { console.error('[AK-Dash] districts fetch failed:', err); });
}

function onAkDashDistrictChange() {
  var dc = (document.getElementById('akDashFilterDistrict') || {}).value || '';
  var sc = (document.getElementById('akDashFilterState')    || {}).value || '';
  var c = document.getElementById('akDashFilterCentre');
  var b = document.getElementById('akDashFilterBatch');
  if (c) { c.innerHTML = '<option value="">All Centres</option>'; c.value = ''; }
  if (b) b.value = '';
  // 2026-06-06: refresh batches narrowed to state (no specific centre yet).
  _loadAkDashBatches(sc, '');
  try { console.log('[AK-Dash] onDistrictChange — district_code=', dc || '(All)'); } catch (e) {}
  if (!dc) return;
  apiAkMCentresDropdown({ district_code: dc }).then(function(rows) {
    try {
      console.log('[AK-Dash] centres for district=', dc, '→ count=', (rows||[]).length,
                  '— names:', (rows||[]).map(function(r) { return r.centre_name; }).join(', '));
    } catch (e) {}
    (rows || []).forEach(function(r) {
      var o = document.createElement('option');
      o.value = r.centre_code; o.textContent = r.centre_name;
      c.appendChild(o);
    });
  }).catch(function(err) { console.error('[AK-Dash] centres fetch failed:', err); });
}

function onAkDashCentreChange() {
  var cc = (document.getElementById('akDashFilterCentre') || {}).value || '';
  var sc = (document.getElementById('akDashFilterState')  || {}).value || '';
  var b = document.getElementById('akDashFilterBatch');
  if (b) b.value = '';
  // 2026-06-06: Centre→Batch cascade per user spec. When a Centre is
  // picked, refetch batches narrowed to that centre. Clearing Centre
  // falls back to state-wide batches.
  _loadAkDashBatches(sc, cc);
  try { console.log('[AK-Dash] onCentreChange — centre_code=', cc || '(All)'); } catch (e) {}
}

function applyAkDashFilters() { _refreshAkDashboard(); }

function resetAkDashFilters() {
  ['akDashFilterState','akDashFilterDistrict','akDashFilterCentre',
   'akDashFilterBatch','akDashFilterFrom','akDashFilterTo'].forEach(function(id) {
    var el = document.getElementById(id); if (el) el.value = '';
  });
  document.getElementById('akDashFilterDistrict').innerHTML = '<option value="">All Districts</option>';
  document.getElementById('akDashFilterCentre').innerHTML   = '<option value="">All Centres</option>';
  // 2026-06-06: For State Lead, after Reset re-pin State to their state and
  // refire the cascade so District/Centre/Batch repopulate scoped to their
  // state — matches the post-login default and avoids leaking other states'
  // batches into the Batch dropdown.
  // 2026-06-08: DL / PI also re-apply via _lockAkFiltersForDlPi (soft
  // 2-option State + Centre) so the South Delhi DL keeps "All Centres
  // + South Delhi" after Reset.
  var role = currentUser && currentUser.role || '';
  if (role === 'state_lead' && currentUser.state_code) {
    var sEl = document.getElementById('akDashFilterState');
    if (sEl) sEl.value = currentUser.state_code;
    if (typeof onAkDashStateChange === 'function') onAkDashStateChange();
  } else if ((role === 'pi' || role === 'district_lead') && typeof _lockAkFiltersForDlPi === 'function') {
    _lockAkFiltersForDlPi('akDashFilterState', 'akDashFilterCentre', { stateMode: 'soft', centreMode: 'soft' });
    _loadAkDashBatches('', '');
  } else {
    _loadAkDashBatches('', '');
  }
  _refreshAkDashboard();
}

function loadAkDashboard() {
  _populateAkDashFilters();
  _refreshAkDashboard();
}

function _refreshAkDashboard() {
  var f = _akDashCollectFilters();
  var setText = function(id, v) { var el = document.getElementById(id); if (el) el.textContent = (v != null ? v : 0); };

  apiAkDashboardStats(f).then(function(d) {
    // 2026-06-01 (v7): Active + Dropout KPI tiles bound to
    // d.active_kishoris / d.dropout_kishoris. ALAP Stage KPI stays
    // unbound — backend still returns total_alaps for any other
    // consumer, just not surfaced as a tile.
    setText('akKpiTotalKishoris',   d.total_kishoris);
    setText('akKpiActiveKishoris',  d.active_kishoris);
    setText('akKpiDropoutKishoris', d.dropout_kishoris);
    setText('akKpiActiveAddas',     d.active_addas);
    setText('akKpiTrainings',       d.total_trainings);
    setText('akKpiAssessments',     d.total_assessments);
    setText('akKpiAlumni',          d.total_alumni);
  }).catch(function(err) { showUserError('loading AK KPIs', err); });

  apiAkDashboardCharts(f).then(function(d) { _akDashRender(d || {}); })
    .catch(function(err) { showUserError('loading AK charts', err); });
}

// 2026-06-01 (v9): Education Current Level —
//   - Year   (server-side filter via education_year in the next /charts
//             round-trip)
//   - Increase (client-side min-count: hide rows with count < this)
//   - Decrease (client-side max-count: hide rows with count > this)
// Increase + Decrease together act as a numeric range over the
// education_distribution row counts. Either side may be blank — blank
// = "no bound", so leaving both blank shows the full distribution.
function _akDashRenderEducationCurrent(d) {
  // 2026-06-04: simplified — year selector is now a free-form number
  // input handled server-side via _akDashCollectFilters.education_year,
  // and the Increase / Decrease range filter has been removed. We just
  // plot whatever distribution the backend returns for the requested
  // year (or all years when blank).
  var eduRows = (d && d.education_distribution) || [];
  var visible = eduRows;

  _akDashMakeChart('akDashEducationChart', {
    type: 'bar',
    data: {
      labels: visible.map(function(r) { return r.education; }),
      datasets: [{ label:'Kishori Leaders',
                   data: visible.map(function(r) { return parseInt(r.c, 10) || 0; }),
                   backgroundColor:'#732269', borderRadius:4,
                   barThickness: 18 }],
    },
    options: {
      indexAxis:'y', responsive:true, maintainAspectRatio:false,
      layout: { padding: { left: 4, right: 12, top: 4, bottom: 4 } },
      plugins:{ legend:{ display:false },
                tooltip:{ callbacks:{ label: function(ctx) { return ctx.parsed.x + ' leaders'; } } } },
      scales:{
        x:{ beginAtZero:true, ticks:{ precision:0 }, grid:{ color:'#eee' } },
        y:{ ticks:{ font:{ size:11 } }, grid:{ display:false } }
      }
    }
  });
}

// 2026-06-01 (v9): Education Progression — year-labeled X-axis.
//
// "All Batches" mode:
//   - X-axis labels = batch.year strings (e.g. "2020-24", "2021-25")
//   - One data point per batch per metric (Enrolled / Passed (Class 12)
//     / Continued / Drop-off). Each metric draws one line across all
//     batches so the user can compare cohorts at a glance.
//
// Specific batch mode:
//   - Parse batch.year ("2020-24", "2020-2024", or "2020") into the
//     actual calendar years spanned. The AK programme is 4 years
//     long, so a "2020-24" batch yields 5 year labels (2020-2024
//     inclusive); a "2020" batch (no end year) is treated as the
//     start of a 4-year window → [2020, 2021, 2022, 2023, 2024].
//   - 4 progression metrics overlay:
//       • Total Enrolled (flat orange dashed line)
//       • Passed         (descending purple staircase across the
//                        first 4 year-points; the 5th label has no
//                        passed-staircase data point so the line
//                        terminates at year 4)
//       • Continued (Active)  flat green dashed
//       • Drop-off            flat red dashed
function _akDashRenderEducationProgression(d) {
  var prog = (d && d.education_progression) || [];

  // Populate the Batch dropdown the first time we see this payload.
  // The option text is the batch.year string when present (e.g.
  // "2020-24"), falling back to the raw batch name; that matches the
  // x-axis labels in the All-Batches view.
  var sel = document.getElementById('akDashEduProgBatch');
  if (sel && sel.options.length <= 1 && prog.length) {
    var keep = sel.value;
    var html = '<option value="">All Batches</option>';
    prog.forEach(function(r) {
      if (r.batch_id == null) return;
      var labelTxt = r.batch_year || r.batch_name || ('Batch ' + r.batch_id);
      html += '<option value="' + r.batch_id + '">' + escHtml(labelTxt) + '</option>';
    });
    sel.innerHTML = html;
    if (keep) sel.value = keep;
  }
  var pickedId = sel ? sel.value : '';

  var datasets = [];
  var labels   = [];

  if (!pickedId) {
    // All-Batches view: x-axis = each batch's year label; 4 series
    // (Enrolled / Passed (Class 12 gate) / Continued / Drop-off) draw
    // one line each, crossing every batch.
    labels = prog.map(function(r) {
      return r.batch_year || r.batch_name || ('Batch ' + r.batch_id);
    });
    datasets = [
      { label: 'Total Enrolled',
        data: prog.map(function(r) { return parseInt(r.enrolled, 10) || 0; }),
        borderColor: '#f39c12', backgroundColor: 'rgba(243,156,18,0.18)',
        fill: false, tension: 0.2, pointRadius: 4, pointBackgroundColor: '#f39c12' },
      { label: 'Passed (Class 12)',
        data: prog.map(function(r) { return parseInt(r.passed_class_12, 10) || 0; }),
        borderColor: '#732269', backgroundColor: 'rgba(115,34,105,0.18)',
        fill: false, tension: 0.2, pointRadius: 4, pointBackgroundColor: '#732269' },
      { label: 'Continued (Active)',
        data: prog.map(function(r) { return parseInt(r.still_active, 10) || 0; }),
        borderColor: '#27ae60', backgroundColor: 'rgba(39,174,96,0.18)',
        fill: false, tension: 0.2, pointRadius: 4, pointBackgroundColor: '#27ae60' },
      { label: 'Drop-off',
        data: prog.map(function(r) { return parseInt(r.dropped_off, 10) || 0; }),
        borderColor: '#e74c3c', backgroundColor: 'rgba(231,76,60,0.18)',
        fill: false, tension: 0.2, pointRadius: 4, pointBackgroundColor: '#e74c3c' }
    ];
  } else {
    // Focused batch — derive actual year labels from batch.year.
    var picked = null;
    for (var i = 0; i < prog.length; i++) {
      if (String(prog[i].batch_id) === String(pickedId)) { picked = prog[i]; break; }
    }
    if (picked) {
      labels = _akDashParseBatchYears(picked.batch_year);
      var enrolled    = parseInt(picked.enrolled,    10) || 0;
      var stillActive = parseInt(picked.still_active, 10) || 0;
      var droppedOff  = parseInt(picked.dropped_off,  10) || 0;
      // The "Passed" staircase has 4 data points; pad with nulls so the
      // line stops at year 4 when the x-axis has 5 labels (5-year span).
      var passed = [
        enrolled,
        parseInt(picked.passed_class_8,  10) || 0,
        parseInt(picked.passed_class_10, 10) || 0,
        parseInt(picked.passed_class_12, 10) || 0,
      ];
      while (passed.length < labels.length) passed.push(null);
      var flatEnr  = labels.map(function() { return enrolled; });
      var flatCont = labels.map(function() { return stillActive; });
      var flatDrop = labels.map(function() { return droppedOff; });
      datasets = [
        { label: 'Total Enrolled', data: flatEnr,
          borderColor: '#f39c12', backgroundColor: 'rgba(243,156,18,0.12)',
          fill: false, tension: 0, pointRadius: 3, borderDash: [4, 4] },
        { label: 'Passed', data: passed, spanGaps: false,
          borderColor: '#732269', backgroundColor: 'rgba(115,34,105,0.18)',
          fill: false, tension: 0, pointRadius: 5, pointBackgroundColor: '#732269' },
        { label: 'Continued (Active)', data: flatCont,
          borderColor: '#27ae60', backgroundColor: 'rgba(39,174,96,0.10)',
          fill: false, tension: 0, pointRadius: 3, borderDash: [2, 4] },
        { label: 'Drop-off', data: flatDrop,
          borderColor: '#e74c3c', backgroundColor: 'rgba(231,76,60,0.10)',
          fill: false, tension: 0, pointRadius: 3, borderDash: [2, 4] },
      ];
    }
  }

  if (!labels.length) {
    labels   = ['—'];
    datasets = [{ label: 'No data', data: [0], borderColor:'#bdc3c7', pointRadius:3 }];
  }

  _akDashMakeChart('akDashEduProgressionChart', {
    type: 'line',
    data: { labels: labels, datasets: datasets },
    options: {
      responsive: true, maintainAspectRatio: false,
      layout: { padding: { left: 4, right: 12, top: 4, bottom: 4 } },
      plugins: {
        legend: { position: 'bottom', labels: { padding: 10, usePointStyle: true, font: { size: 11 } } },
        tooltip: { callbacks: { label: function(ctx) {
          return ctx.dataset.label + ' · ' + ctx.label + ': ' +
                 (ctx.parsed.y == null ? '—' : ctx.parsed.y + ' leaders');
        } } }
      },
      scales: {
        x: { grid: { color: '#eee' }, ticks: { font: { size: 11 } },
             title: { display: true,
                      text: pickedId ? 'Batch Year Journey' : 'Batch',
                      font: { size: 11 }, padding: { top: 6 } } },
        y: { beginAtZero: true, ticks: { precision: 0 }, grid: { color: '#eee' },
             title: { display: true, text: 'Leaders', font: { size: 11 } } }
      }
    }
  });
}

// 2026-06-01 (v9): Parse a batch.year string into the actual list of
// calendar years it spans. Handles three common shapes the AK team
// uses today:
//   "2020-24"   → [2020, 2021, 2022, 2023, 2024]
//   "2020-2024" → [2020, 2021, 2022, 2023, 2024]
//   "2020"      → [2020, 2021, 2022, 2023, 2024]  (treat as 4-year cohort)
//   ""/garbage  → ['Year 1', 'Year 2', 'Year 3', 'Year 4', 'Year 5']
function _akDashParseBatchYears(raw) {
  if (typeof raw !== 'string' || !raw) {
    return ['Year 1', 'Year 2', 'Year 3', 'Year 4', 'Year 5'];
  }
  var m = raw.match(/(\d{4})\s*[-–—]\s*(\d{2,4})/);
  var start = null, end = null;
  if (m) {
    start = parseInt(m[1], 10);
    var rawEnd = parseInt(m[2], 10);
    // Two-digit end ("2020-24") expands using the start year's century.
    if (m[2].length === 2) {
      end = Math.floor(start / 100) * 100 + rawEnd;
      // If that pushes us backward (start=2098, end=02), bump to next century.
      if (end < start) end += 100;
    } else {
      end = rawEnd;
    }
  } else {
    var solo = raw.match(/(\d{4})/);
    if (solo) {
      start = parseInt(solo[1], 10);
      end   = start + 4;   // canonical AK programme length
    }
  }
  if (start == null || end == null || end < start) {
    return ['Year 1', 'Year 2', 'Year 3', 'Year 4', 'Year 5'];
  }
  // Cap the span so a malformed value (e.g. "2020-2099") doesn't paint
  // 80 x-axis ticks.
  if (end - start > 8) end = start + 8;
  var out = [];
  for (var y = start; y <= end; y++) out.push(String(y));
  return out;
}

function _akDashRender(d) {
  // 2026-06-01 (v7): Cache the latest charts payload so the new
  // client-side filters (Min-Count on Education Current Level, Batch
  // picker on Education Progression) can re-paint just their chart
  // without a backend round-trip.
  window._akDashLastCharts = d;

  // FLP palette so charts visually harmonise with the rest of the MIS.
  var FLP_PURPLES = ['#732269','#9b3d8e','#c06bb3','#e0a3d4','#f0d1ea'];
  // SOCIO_PALETTE re-used by the new Socio-economic Profile mini-charts
  // (Income bands, Category, Religion).
  var SOCIO_PALETTE = ['#732269','#9b3d8e','#c06bb3','#e0a3d4','#f0d1ea','#27ae60','#f39c12','#3498db'];

  // Render Education Current Level + Progression via dedicated helpers
  // so the new Min-Count / Batch handlers can call them on their own
  // without re-running every other chart on the dashboard.
  _akDashRenderEducationCurrent(d);
  _akDashRenderEducationProgression(d);

  // 2026-06-04: Adda outreach bar. (Family Engagement Trends and the
  // Assessment Reports KPIs / Comparison renderer were removed
  // 2026-06-04 per user spec — their HTML blocks are gone too.)
  _akDashRenderAddaReach(d);

  // Age bands — 2026-06-01: dropped the 10-12 bucket per user spec.
  // The backend still returns it for compatibility; the renderer just
  // doesn't include it in the bands array.
  var ab = d.age_buckets || {};
  var bands = [
    { name: '13–15',  v: parseInt(ab.bucket_13_15,   10) || 0 },
    { name: '16–18',  v: parseInt(ab.bucket_16_18,   10) || 0 },
    { name: '19+',    v: parseInt(ab.bucket_19_plus, 10) || 0 },
  ];
  var maxBand = Math.max.apply(null, bands.map(function(b) { return b.v; }).concat([1]));
  var agEl = document.getElementById('akDashAgeBands');
  if (agEl) {
    agEl.innerHTML = bands.map(function(b) {
      var pct = maxBand ? Math.round(b.v * 100 / maxBand) : 0;
      return '<div class="ak-age-row">'
        + '<span class="ak-age-name">' + escHtml(b.name) + '</span>'
        + '<span class="ak-age-bar"><i style="width:' + pct + '%;"></i></span>'
        + '<b>' + b.v + '</b>'
      + '</div>';
    }).join('');
  }

  // Kishoris by State — donut (FLP purple gradient)
  var stRows = d.kishoris_by_state || [];
  _akDashMakeChart('akDashStateChart', {
    type: 'doughnut',
    data: {
      labels: stRows.map(function(r) { return r.state_name; }),
      datasets: [{
        data: stRows.map(function(r) { return parseInt(r.count, 10) || 0; }),
        backgroundColor: FLP_PURPLES,
        borderWidth: 0,
      }],
    },
    options: { responsive:true, maintainAspectRatio:false, cutout:'58%',
               plugins:{ legend:{ position:'bottom', labels:{ padding:12, usePointStyle:true } } } }
  });

  // 2026-06-01 (v4): "Leaders by State (Counts)" swapped for
  // "Addas by State" per user request. Reuses the existing
  // addas_by_state payload (the same source feeding the Adda
  // Details table below) so the two cards always agree numerically
  // and respond identically to the dashboard's geo/date filters.
  // Same horizontal-bar styling as the previous chart keeps the
  // visual rhythm of the row intact.
  var addaStateRows = d.addas_by_state || [];
  _akDashMakeChart('akDashAddaStateBarChart', {
    type: 'bar',
    data: {
      labels: addaStateRows.map(function(r) { return r.state_name; }),
      datasets: [{ label:'Addas',
                   data: addaStateRows.map(function(r) { return parseInt(r.adda_count, 10) || 0; }),
                   backgroundColor:'#1abc9c', borderRadius:4, barThickness: 18 }],
    },
    options: {
      indexAxis:'y', responsive:true, maintainAspectRatio:false,
      layout: { padding: { left: 4, right: 12, top: 4, bottom: 4 } },
      plugins:{ legend:{ display:false },
                tooltip:{ callbacks:{ label: function(ctx) {
                  var n = ctx.parsed.x;
                  return n + (n === 1 ? ' adda' : ' addas');
                } } } },
      scales:{
        x:{ beginAtZero:true, ticks:{ precision:0 }, grid:{ color:'#eee' } },
        y:{ ticks:{ font:{ size:11 } }, grid:{ display:false } }
      }
    }
  });

  // 2026-06-01: Monthly Enrolment Trend chart removed per user
  // request. The backend still returns monthly_enrolment for any
  // external consumer; we simply don't paint a canvas for it.

  // ────────────────────────────────────────────────────────────────
  // Socio-economic Profile — 2 small doughnut charts driven by
  // ak_leaders socio columns: category, religion.
  // 2026-06-01: "Family Monthly Income" chart removed per user
  // request. d.socio_income_bands is still returned by the backend
  // but the frontend ignores it now.
  // ────────────────────────────────────────────────────────────────
  var catRows = d.socio_category || [];
  _akDashMakeChart('akDashCategoryChart', {
    type: 'doughnut',
    data: {
      labels: catRows.map(function(r) { return r.category || '—'; }),
      datasets: [{ data: catRows.map(function(r) { return parseInt(r.c, 10) || 0; }),
                   backgroundColor: SOCIO_PALETTE, borderWidth:0 }],
    },
    options: { responsive:true, maintainAspectRatio:false, cutout:'58%',
               plugins:{ legend:{ position:'bottom', labels:{ padding:10, usePointStyle:true } } } }
  });
  var relRows = d.socio_religion || [];
  _akDashMakeChart('akDashReligionChart', {
    type: 'doughnut',
    data: {
      labels: relRows.map(function(r) { return r.religion || '—'; }),
      datasets: [{ data: relRows.map(function(r) { return parseInt(r.c, 10) || 0; }),
                   backgroundColor: SOCIO_PALETTE, borderWidth:0 }],
    },
    options: { responsive:true, maintainAspectRatio:false, cutout:'58%',
               plugins:{ legend:{ position:'bottom', labels:{ padding:10, usePointStyle:true } } } }
  });

  // ────────────────────────────────────────────────────────────────
  // Trainings — Sessions vs Attendance (2026-06-01 v3).
  // Per the user spec, the stat tiles and Top Topics list were
  // removed; the chart now renders a grouped-bar comparison of
  // session count vs marked-present attendance per category, so the
  // user gets both training-conducted insight and participation
  // insight in one card. Payload: training_by_category_with_attendance
  // = [{ category, sessions, present }].
  // ────────────────────────────────────────────────────────────────
  var trcA = d.training_by_category_with_attendance || [];
  _akDashMakeChart('akDashTrainingChart', {
    type: 'bar',
    data: {
      labels: trcA.map(function(r) { return r.category || '—'; }),
      datasets: [
        { label:'Trainings',  data: trcA.map(function(r) { return parseInt(r.sessions, 10) || 0; }),
          backgroundColor:'#732269', borderRadius:4, barPercentage: .85 },
        { label:'Attendance', data: trcA.map(function(r) { return parseInt(r.present,  10) || 0; }),
          backgroundColor:'#9b3d8e', borderRadius:4, barPercentage: .85 }
      ],
    },
    options: {
      responsive:true, maintainAspectRatio:false,
      plugins:{ legend:{ position:'bottom', labels:{ padding:10, usePointStyle:true, font:{ size:11 } } } },
      scales:{
        x:{ grid:{ display:false } },
        y:{ beginAtZero:true, ticks:{ precision:0 }, grid:{ color:'#eee' } }
      }
    }
  });

  // 2026-06-01 (v7): Share column dropped per user request. Table is
  // now State / Addas / Members — the proportional read the Share
  // bar provided is already covered by the Addas-by-State chart at
  // the top of the dashboard.
  var aBody = document.getElementById('akDashAddasBody');
  var addas = d.addas_by_state || [];
  if (aBody) {
    if (!addas.length) {
      aBody.innerHTML = '<tr><td colspan="3" style="text-align:center;color:#999;padding:18px;">No adda data yet.</td></tr>';
    } else {
      aBody.innerHTML = addas.map(function(r) {
        var m = parseInt(r.members_reached, 10) || 0;
        return '<tr>'
          + '<td>' + escHtml(r.state_name || '—') + '</td>'
          + '<td>' + (r.adda_count || 0) + '</td>'
          + '<td>' + m + '</td>'
        + '</tr>';
      }).join('');
    }
  }

  // Assessments split — bar (FLP supporting palette)
  var asp = d.assessments_split || [];
  _akDashMakeChart('akDashAssessChart', {
    type: 'bar',
    data: {
      labels: asp.map(function(r) { return r.type; }),
      datasets: [{ label:'Assessments',
                   data: asp.map(function(r) { return parseInt(r.c, 10) || 0; }),
                   backgroundColor:'#c06bb3', borderRadius:4 }],
    },
    options: { responsive:true, maintainAspectRatio:false,
               plugins:{ legend:{ display:false } },
               scales:{ y:{ beginAtZero:true, ticks:{ precision:0 } } } }
  });

  // Alumni engagement stats — 4 simple stat tiles (FLP neutral cards)
  var ae = d.alumni_engagement || {};
  var aeEl = document.getElementById('akDashAlumniStats');
  if (aeEl) {
    aeEl.innerHTML =
      '<div class="ak-alumni-stat"><span class="ak-alumni-label">Total Alumni</span><span class="ak-alumni-value">' + (ae.total || 0) + '</span></div>'
    + '<div class="ak-alumni-stat"><span class="ak-alumni-label">Working</span><span class="ak-alumni-value">' + (ae.working || 0) + '</span></div>'
    + '<div class="ak-alumni-stat"><span class="ak-alumni-label">Studying</span><span class="ak-alumni-value">' + (ae.studying || 0) + '</span></div>'
    + '<div class="ak-alumni-stat"><span class="ak-alumni-label">Working &amp; Studying</span><span class="ak-alumni-value">' + (ae.both || 0) + '</span></div>';
  }

  // ────────────────────────────────────────────────────────────────
  // 2026-06-01 (v5): Family Engagement section trimmed —
  // Family Size Distribution card removed per user request; only
  // Per-Capita Income Bands stays.
  // ────────────────────────────────────────────────────────────────
  var pcap = d.per_capita_income_bands || [];
  _akDashMakeChart('akDashPerCapitaChart', {
    type: 'bar',
    data: {
      labels: pcap.map(function(r) { return r.band; }),
      datasets: [{ label:'Leaders',
                   data: pcap.map(function(r) { return parseInt(r.c, 10) || 0; }),
                   backgroundColor:'#9b3d8e', borderRadius:4 }],
    },
    options: { responsive:true, maintainAspectRatio:false,
               plugins:{ legend:{ display:false } },
               scales:{ x:{ grid:{ display:false } },
                        y:{ beginAtZero:true, ticks:{ precision:0 }, grid:{ color:'#eee' } } } }
  });

  // 2026-06-01 (v5): JP + Delhi side-by-side state-compare cards
  // removed per user request. The backend still returns
  // d.state_compare for any other consumer; we simply stop painting
  // anything on the frontend.
}

// ============================================================================
// ALAP PERFORMANCE — single unified view, FLP-style.
// Filter strip → KPI cards → one performance table with an FLP-style
// expandable detail row that shows every activity category and its
// submitted fields for the selected ALAP × month.
// Backed by GET /api/ak/alap-performance (see backend/routes/ak_alap_performance.py).
// ============================================================================

// Cache the last loaded payload so the export uses what the user actually
// sees (and so the expand toggle can pull bundle data without a second API
// call). Keyed by `alap_id::iso-month` so each row has a stable lookup.
var _alapPerfState = {
  loaded:    false,
  summary:   {},
  columns:   [],
  categories: [],
  rows:      [],
  byRowKey:  {},
};
var _alapPerfStatesLoaded = false;

function _alapPerfRowKey(r) { return String(r.alap_id) + '::' + String(r.month || ''); }

function _alapPerfPopulateStates() {
  if (_alapPerfStatesLoaded) return;
  _alapPerfStatesLoaded = true;
  var sel = document.getElementById('alapPerfFilterState');
  if (!sel || typeof apiAkMStatesDropdown !== 'function') return;
  apiAkMStatesDropdown().then(function(rows) {
    (rows || []).forEach(function(r) {
      var o = document.createElement('option');
      o.value = r.state_code; o.textContent = r.state_name;
      sel.appendChild(o);
    });
  }).catch(function() {});
}

function _alapPerfCascadeCentres() {
  var sc = (document.getElementById('alapPerfFilterState') || {}).value || '';
  var cSel = document.getElementById('alapPerfFilterCentre');
  if (!cSel) return;
  cSel.innerHTML = '<option value="">All Centres</option>';
  if (!sc) return;
  apiAkMCentresDropdown({ state_code: sc }).then(function(rows) {
    (rows || []).forEach(function(r) {
      var o = document.createElement('option');
      o.value = r.centre_code; o.textContent = r.centre_name;
      cSel.appendChild(o);
    });
  }).catch(function() {});
}
function onAlapPerfStateChange() { _alapPerfCascadeCentres(); }

function _initAlapPerfPage() {
  _alapPerfPopulateStates();
}

// Collect current filters (and apply role-scope floor for SL/DL/PI).
function _alapPerfCollectFilters() {
  var p = {};
  var st = (document.getElementById('alapPerfFilterState')  || {}).value;
  var ce = (document.getElementById('alapPerfFilterCentre') || {}).value;
  var mo = (document.getElementById('alapPerfFilterMonth')  || {}).value;
  if (st) p.state_code  = st;
  if (ce) p.centre_code = ce;
  if (mo) p.month       = mo;
  return _applyRoleScopeFloor(p);
}

function loadAlapPerformanceData() {
  var p = _alapPerfCollectFilters();
  apiAlapPerformance(p).then(function(d) {
    _alapPerfState.loaded     = true;
    _alapPerfState.summary    = d.summary || {};
    _alapPerfState.columns    = d.columns || [];
    _alapPerfState.categories = d.categories || [];
    _alapPerfState.rows       = d.rows || [];
    _alapPerfState.byRowKey   = {};
    _alapPerfState.rows.forEach(function(r) { _alapPerfState.byRowKey[_alapPerfRowKey(r)] = r; });
    _renderAlapPerfKpis(_alapPerfState.summary);
    _renderAlapPerfTable(_alapPerfState);
  }).catch(function(err) { showUserError('loading ALAP performance', err); });
}

function _renderAlapPerfKpis(s) {
  var setText = function(id, v) { var el = document.getElementById(id); if (el) el.textContent = v; };
  setText('alapPerfKpiTotalAlaps', s.total_alaps || 0);
  setText('alapPerfKpiReports',    s.total_reports || 0);
  var pct = (s.total_alaps || 0) > 0
    ? Math.round(((s.alaps_reporting || 0) * 100) / s.total_alaps)
    : 0;
  setText('alapPerfKpiReportingPct', pct + '%');
}

function _renderAlapPerfTable(state) {
  var body = document.getElementById('alapPerfTableBody');
  if (!body) return;
  var rows = state.rows || [];
  if (!rows.length) {
    body.innerHTML = '<tr><td colspan="10" style="text-align:center;color:#999;padding:30px;">No Activity Mapping entries match these filters.</td></tr>';
    return;
  }
  var html = '';
  rows.forEach(function(r, i) {
    var sno = i + 1;
    var s = r.summary || {};
    var rowKey = _alapPerfRowKey(r);
    var safeKey = rowKey.replace(/[^a-zA-Z0-9_]/g, '_');
    // Each summary cell: numeric for "count" kind, ✓/— for "event" kind.
    var summaryCells = (state.columns || []).map(function(c) {
      var v = s[c.key];
      if (c.kind === 'count') {
        var n = parseInt(v, 10) || 0;
        return '<td style="text-align:center;font-variant-numeric:tabular-nums;">'
          + (n > 0 ? '<b style="color:var(--primary);">' + n + '</b>' : '<span style="color:#bbb;">—</span>')
          + '</td>';
      }
      // event-typed
      if (parseInt(v, 10) === 1) return '<td style="text-align:center;color:#27ae60;font-size:15px;"><i class="fas fa-check-circle"></i></td>';
      return '<td style="text-align:center;color:#bbb;">—</td>';
    }).join('');

    var nameCell = '<b>' + escHtml(r.alap_name || '-') + '</b>'
      + (r.centre_name ? '<br><span style="color:#888;font-size:11px;">' + escHtml(r.centre_name) + (r.state_name ? ', ' + escHtml(r.state_name) : '') + '</span>' : '');
    var monthBadge = r.month ? '<br><span style="color:#888;font-size:11px;">' + _formatMonthMmmYy(r.month) + '</span>' : '';

    html += '<tr class="alap-perf-row" data-row-key="' + escHtml(rowKey) + '">'
      + '<td>' + sno + '</td>'
      + '<td>' + nameCell + monthBadge + '</td>'
      + '<td>' + escHtml(r.enrollment_number || '-') + '</td>'
      + summaryCells
      + '<td style="text-align:center;">'
        + '<button class="btn-icon" title="Show activity details" '
        + 'onclick="toggleAlapPerfDetail(\'' + safeKey + '\', this)" '
        + 'data-row-key="' + escHtml(rowKey) + '">'
        + '<i class="fas fa-chevron-down"></i></button>'
      + '</td>'
    + '</tr>';
    html += '<tr class="alap-perf-detail-row" id="alapPerfDetail_' + safeKey + '" style="display:none;background:#faf5f9;">'
      + '<td colspan="10" style="padding:0;">'
      + '<div class="alap-perf-detail-content" id="alapPerfDetailContent_' + safeKey + '">'
      + _renderAlapPerfDetail(r, state.categories)
      + '</div>'
      + '</td></tr>';
  });
  body.innerHTML = html;
}

// Render the expanded detail panel — one card per activity category.
// Categories with no data show a muted "No data recorded" tag so users
// quickly see what's missing.
function _renderAlapPerfDetail(row, categories) {
  var data = row.data || {};
  var blocks = (categories || []).map(function(c) {
    var bundle = data[String(c.idx)] || {};
    var hasAny = false;
    var fieldHtml = (c.fields || []).map(function(f) {
      var v = bundle[f.key];
      var disp;
      if (v == null || v === '' || (Array.isArray(v) && !v.length)) {
        disp = '<span style="color:#bbb;">—</span>';
      } else {
        hasAny = true;
        if (Array.isArray(v)) disp = escHtml(v.join(', '));
        else if (typeof v === 'string' && /^\d{4}-\d{2}-\d{2}/.test(v)) disp = escHtml(formatDateNice(v));
        else if (typeof v === 'string' && /^\d{4}-\d{2}$/.test(v))      disp = escHtml(_formatMonthMmmYy(v));
        else                                                            disp = escHtml(String(v));
      }
      return '<div class="alap-perf-field">'
        + '<span class="alap-perf-label">' + escHtml(f.label) + '</span>'
        + '<span class="alap-perf-value">' + disp + '</span>'
        + '</div>';
    }).join('');
    var statusPill = hasAny
      ? '<span class="alap-perf-pill alap-perf-pill-on"><i class="fas fa-check"></i> Reported</span>'
      : '<span class="alap-perf-pill alap-perf-pill-off">No data recorded</span>';
    return '<div class="alap-perf-cat-card' + (hasAny ? '' : ' alap-perf-cat-empty') + '">'
      + '<div class="alap-perf-cat-head">'
        + '<span class="alap-perf-cat-name">' + escHtml(c.name) + '</span>'
        + statusPill
      + '</div>'
      + '<div class="alap-perf-fields">' + fieldHtml + '</div>'
      + '</div>';
  }).join('');
  return '<div class="alap-perf-cat-grid">' + blocks + '</div>';
}

// Toggle the expanded detail row for an ALAP × month. Flips the chevron
// direction and the row's display.
function toggleAlapPerfDetail(safeKey, btn) {
  var row = document.getElementById('alapPerfDetail_' + safeKey);
  if (!row) return;
  var isOpen = row.style.display !== 'none';
  row.style.display = isOpen ? 'none' : '';
  if (btn) {
    var icon = btn.querySelector('i');
    if (icon) {
      icon.classList.toggle('fa-chevron-down', isOpen);
      icon.classList.toggle('fa-chevron-up',  !isOpen);
    }
    btn.title = isOpen ? 'Show activity details' : 'Hide activity details';
  }
}

function resetAlapPerfFilters() {
  ['alapPerfFilterState','alapPerfFilterCentre','alapPerfFilterMonth'].forEach(function(id) {
    var el = document.getElementById(id); if (el) el.value = '';
  });
  var c = document.getElementById('alapPerfFilterCentre');
  if (c) c.innerHTML = '<option value="">All Centres</option>';
  // 2026-06-08 (round 3): re-apply SL/DL/PI lock after value-wipe so
  // Centre dropdown keeps "All Centres + <user centre>" after Reset.
  var _r = currentUser && currentUser.role || '';
  if ((_r === 'pi' || _r === 'district_lead' || _r === 'state_lead') &&
      typeof _lockAkFiltersForDlPi === 'function') {
    _lockAkFiltersForDlPi('alapPerfFilterState', 'alapPerfFilterCentre', { stateMode: 'soft', centreMode: 'soft' });
  }
  // Clear KPIs and table back to the empty state.
  _alapPerfState = { loaded:false, summary:{}, columns:[], categories:[], rows:[], byRowKey:{} };
  ['alapPerfKpiTotalAlaps','alapPerfKpiReports'].forEach(function(id) {
    var el = document.getElementById(id); if (el) el.textContent = '0';
  });
  var pctEl = document.getElementById('alapPerfKpiReportingPct');
  if (pctEl) pctEl.textContent = '0%';
  var body = document.getElementById('alapPerfTableBody');
  if (body) body.innerHTML = '<tr><td colspan="10" style="text-align:center;color:#999;padding:30px;">Pick a Month then click Apply.</td></tr>';
}

// Export to .xls (HTML-shape) so Excel opens it natively with formatting,
// matching the FLP Performance export pattern. Two sheets-worth of content
// in one file: a summary table on top and the full per-row expanded
// activity details underneath.
function exportAlapPerformanceToExcel() {
  if (!_alapPerfState.loaded || !_alapPerfState.rows.length) {
    alert('Nothing to export. Click Apply first.');
    return;
  }
  var cols = _alapPerfState.columns || [];
  var cats = _alapPerfState.categories || [];
  var rows = _alapPerfState.rows || [];

  // ── Filter / context block ────────────────────────────────────────────
  var stateEl  = document.getElementById('alapPerfFilterState');
  var centreEl = document.getElementById('alapPerfFilterCentre');
  var monthEl  = document.getElementById('alapPerfFilterMonth');
  var stateLbl  = stateEl  && stateEl.value  ? stateEl.options[stateEl.selectedIndex].text   : 'All States';
  var centreLbl = centreEl && centreEl.value ? centreEl.options[centreEl.selectedIndex].text : 'All Centres';
  var monthLbl  = monthEl  && monthEl.value  ? _formatMonthMmmYy(monthEl.value)              : 'All Months';

  var html = ''
    + '<html><head><meta charset="utf-8"><style>'
    + 'table { border-collapse:collapse; font-family:Arial,sans-serif; font-size:12px; }'
    + 'th, td { border:1px solid #999; padding:6px 10px; }'
    + 'th { background:#732269; color:#fff; }'
    + '.section { background:#f0e3ed; color:#732269; font-weight:bold; }'
    + '.kv { background:#fafafa; }'
    + '.ok { color:#27ae60; font-weight:bold; }'
    + '.no { color:#bbb; }'
    + '</style></head><body>';

  // Header / context
  html += '<table><tr><td class="section" colspan="2">ALAP Performance Report</td></tr>'
    + '<tr><td class="kv">Generated</td><td>' + escHtml(new Date().toLocaleString()) + '</td></tr>'
    + '<tr><td class="kv">State</td><td>'    + escHtml(stateLbl)  + '</td></tr>'
    + '<tr><td class="kv">Centre</td><td>'   + escHtml(centreLbl) + '</td></tr>'
    + '<tr><td class="kv">Month</td><td>'    + escHtml(monthLbl)  + '</td></tr>'
    + '<tr><td class="kv">Total ALAPs</td><td>'         + (_alapPerfState.summary.total_alaps || 0)     + '</td></tr>'
    + '<tr><td class="kv">Activities Reported</td><td>' + (_alapPerfState.summary.total_reports || 0)   + '</td></tr>'
    + '<tr><td class="kv">ALAPs Reporting</td><td>'     + (_alapPerfState.summary.alaps_reporting || 0) + '</td></tr>'
    + '</table><br>';

  // ── Summary table ─────────────────────────────────────────────────────
  html += '<table><tr><th>S.No</th><th>ALAP Member</th><th>Enrollment No.</th><th>Centre</th><th>State</th><th>Month</th>';
  cols.forEach(function(c) { html += '<th>' + escHtml(c.label) + '</th>'; });
  html += '<th>Active Categories</th></tr>';
  rows.forEach(function(r, i) {
    var s = r.summary || {};
    html += '<tr>'
      + '<td>' + (i + 1) + '</td>'
      + '<td>' + escHtml(r.alap_name || '') + '</td>'
      + '<td>' + escHtml(r.enrollment_number || '') + '</td>'
      + '<td>' + escHtml(r.centre_name || '') + '</td>'
      + '<td>' + escHtml(r.state_name || '') + '</td>'
      + '<td>' + (r.month ? escHtml(_formatMonthMmmYy(r.month)) : '') + '</td>';
    cols.forEach(function(c) {
      var v = s[c.key];
      if (c.kind === 'count') {
        html += '<td>' + (parseInt(v, 10) || 0) + '</td>';
      } else {
        html += '<td>' + (parseInt(v, 10) === 1 ? '<span class="ok">✓</span>' : '<span class="no">—</span>') + '</td>';
      }
    });
    html += '<td>' + (r.active_categories || 0) + ' / ' + cats.length + '</td>';
    html += '</tr>';
  });
  html += '</table><br><br>';

  // ── Expanded activity details ─────────────────────────────────────────
  // One sub-table per ALAP × month, mirroring the on-screen expand block.
  html += '<table><tr><td class="section" colspan="3">Activity Details — Per ALAP × Month</td></tr></table>';
  rows.forEach(function(r) {
    var data = r.data || {};
    html += '<br><table>'
      + '<tr><td class="section" colspan="3">'
        + escHtml(r.alap_name || '') + ' &nbsp;·&nbsp; ' + escHtml(r.enrollment_number || '')
        + ' &nbsp;·&nbsp; ' + (r.month ? escHtml(_formatMonthMmmYy(r.month)) : '')
        + ' &nbsp;·&nbsp; ' + escHtml(r.centre_name || '') + (r.state_name ? ', ' + escHtml(r.state_name) : '')
      + '</td></tr>'
      + '<tr><th>Activity Category</th><th>Field</th><th>Value</th></tr>';
    (cats || []).forEach(function(c) {
      var bundle = data[String(c.idx)] || {};
      var anyRow = false;
      (c.fields || []).forEach(function(f) {
        var v = bundle[f.key];
        if (v == null || v === '' || (Array.isArray(v) && !v.length)) return;
        anyRow = true;
        var disp;
        if (Array.isArray(v)) disp = v.join(', ');
        else if (typeof v === 'string' && /^\d{4}-\d{2}-\d{2}/.test(v)) disp = formatDateNice(v);
        else if (typeof v === 'string' && /^\d{4}-\d{2}$/.test(v))      disp = _formatMonthMmmYy(v);
        else                                                            disp = String(v);
        html += '<tr><td>' + escHtml(c.name) + '</td><td>' + escHtml(f.label) + '</td><td>' + escHtml(disp) + '</td></tr>';
      });
      if (!anyRow) {
        html += '<tr><td>' + escHtml(c.name) + '</td><td colspan="2" class="no">No data recorded</td></tr>';
      }
    });
    html += '</table>';
  });

  html += '</body></html>';

  // Trigger the download as .xls; Excel reads HTML tables natively.
  var blob = new Blob([html], { type: 'application/vnd.ms-excel' });
  var a = document.createElement('a');
  a.href = URL.createObjectURL(blob);
  var ds = new Date().toISOString().slice(0, 10);
  a.download = 'ALAP_Performance_' + ds + '.xls';
  document.body.appendChild(a); a.click(); document.body.removeChild(a);
  setTimeout(function() { URL.revokeObjectURL(a.href); }, 1000);
}

// ============================================================================
// AK BASELINE REPORT — 2026-06-01
//
// KPI dashboard for submitted AK baseline assessments. One call to
// /api/ak-assessments/baseline-report returns every aggregate the page
// needs: total cohort size, average age, family income, phone ownership,
// per-section response distributions, and a family-table roll-up. The
// charts and Key Findings narrative are derived from that one payload.
//
// Layout mirrors FLP's #page-baselineReport: filter row (State / District
// / Centre / Batch) → 6 KPI cards → Key Findings panel (colored cards) →
// 5 targeted charts (Education, Income, Gender-Norms Likert, Career,
// Mobility + Cyber, GBV). Source-of-truth for the KPI selection is the
// Azad Foundation field team's "AK Jaipur Batch 5 Baseline" report PDF.
// ============================================================================

var _akBrCharts = {};  // canvasId → Chart instance (so we can destroy on re-render)
var _akBrLastPayload = null;

function loadAkBaselineReport() {
  // First-time setup: populate state dropdown + immediately fetch the
  // unfiltered aggregate. The state dropdown reuses the AK list helper so
  // the same roster of active states appears here as elsewhere.
  _populateAkStatesInto('akBrFilterState');
  applyAkBaselineReportFilters();
}

function onAkBrStateChange() {
  // State changed → reload districts (depend on state), clear lower
  // levels, and refresh the aggregate.
  var s = (document.getElementById('akBrFilterState') || {}).value;
  _akBrLoadDistrictsForState(s);
  _akBrClearSelect('akBrFilterCentre', 'All Centres');
  _akBrClearSelect('akBrFilterBatch',  'All Batches');
  // 2026-06-08 (round 5): For DL/PI, re-apply the soft 2-option Centre
  // lock after the placeholder-only clear above so the user still sees
  // "All Centres + <user centre>" instead of just "All Centres".
  var _role = (currentUser && currentUser.role) || '';
  if ((_role === 'district_lead' || _role === 'pi') &&
      currentUser && currentUser.centre_code &&
      typeof _lockAkFiltersForDlPi === 'function') {
    _lockAkFiltersForDlPi(null, 'akBrFilterCentre', { centreMode: 'soft' });
  }
}

function onAkBrDistrictChange() {
  var d = (document.getElementById('akBrFilterDistrict') || {}).value;
  _akBrLoadCentresForDistrict(d);
  _akBrClearSelect('akBrFilterBatch', 'All Batches');
  // 2026-06-08 (round 5): re-apply DL/PI Centre lock — same reason as
  // above. _akBrLoadCentresForDistrict short-circuits itself for DL/PI
  // but only when district_code is set; cover the explicit clear too.
  var _role = (currentUser && currentUser.role) || '';
  if ((_role === 'district_lead' || _role === 'pi') &&
      currentUser && currentUser.centre_code &&
      typeof _lockAkFiltersForDlPi === 'function') {
    _lockAkFiltersForDlPi(null, 'akBrFilterCentre', { centreMode: 'soft' });
  }
}

function onAkBrCentreChange() {
  var c = (document.getElementById('akBrFilterCentre') || {}).value;
  _akBrLoadBatchesForCentre(c);
}

function _akBrClearSelect(id, defaultLabel) {
  var el = document.getElementById(id);
  if (el) el.innerHTML = '<option value="">' + defaultLabel + '</option>';
}

function _akBrLoadDistrictsForState(stateCode) {
  var sel = document.getElementById('akBrFilterDistrict');
  if (!sel) return;
  // 2026-06-08 (round 5): For DL/PI with a resolved district, keep the
  // soft 2-option lock ("All Districts + <user district>") instead of
  // listing every district in the state. Otherwise picking "Delhi" as
  // State surfaces East/South/North Delhi and the DL can leak across
  // districts.
  var _role = (currentUser && currentUser.role) || '';
  if ((_role === 'district_lead' || _role === 'pi') &&
      currentUser && currentUser.district_code &&
      typeof _lockAkBrDistrictForDlPi === 'function') {
    _lockAkBrDistrictForDlPi();
    return;
  }
  sel.innerHTML = '<option value="">All Districts</option>';
  if (!stateCode) return;
  // Reuse the AK Master dropdown endpoint — same shape as the existing
  // cascading filters elsewhere in the AK module.
  apiGet('/ak-master/dropdown/districts?state_code=' + encodeURIComponent(stateCode)).then(function(rows) {
    (rows || []).forEach(function(r) {
      var o = document.createElement('option');
      o.value = r.district_code;
      o.textContent = r.district_name;
      sel.appendChild(o);
    });
  }).catch(function() {});
}

function _akBrLoadCentresForDistrict(districtCode) {
  var sel = document.getElementById('akBrFilterCentre');
  if (!sel) return;
  // 2026-06-08 (round 5): same DL/PI short-circuit for Centre.
  var _role = (currentUser && currentUser.role) || '';
  if ((_role === 'district_lead' || _role === 'pi') &&
      currentUser && currentUser.centre_code &&
      typeof _lockAkFiltersForDlPi === 'function') {
    _lockAkFiltersForDlPi(null, 'akBrFilterCentre', { centreMode: 'soft' });
    return;
  }
  sel.innerHTML = '<option value="">All Centres</option>';
  if (!districtCode) return;
  apiGet('/ak-master/dropdown/centres?district_code=' + encodeURIComponent(districtCode)).then(function(rows) {
    (rows || []).forEach(function(r) {
      var o = document.createElement('option');
      o.value = r.centre_code;
      o.textContent = r.centre_name;
      sel.appendChild(o);
    });
  }).catch(function() {});
}

function _akBrLoadBatchesForCentre(centreCode) {
  var sel = document.getElementById('akBrFilterBatch');
  if (!sel) return;
  sel.innerHTML = '<option value="">All Batches</option>';
  if (!centreCode) return;
  // ak_batches endpoint accepts centre_code filter to scope the dropdown
  // to in-scope batches only.
  apiGet('/ak-batches?centre_code=' + encodeURIComponent(centreCode)).then(function(resp) {
    var rows = (resp && resp.data) || resp || [];
    rows.forEach(function(r) {
      var o = document.createElement('option');
      o.value = r.id;
      o.textContent = r.name;
      sel.appendChild(o);
    });
  }).catch(function() {});
}

function applyAkBaselineReportFilters() {
  // 2026-06-05: Build params object first so the role-scope floor can
  // be applied, then serialise to qs. Without the floor, a Sangini's
  // empty filters would return the unscoped global aggregate.
  var params = {};
  var s = (document.getElementById('akBrFilterState')    || {}).value;
  var d = (document.getElementById('akBrFilterDistrict') || {}).value;
  var c = (document.getElementById('akBrFilterCentre')   || {}).value;
  var b = (document.getElementById('akBrFilterBatch')    || {}).value;
  if (s) params.state_code    = s;
  if (d) params.district_code = d;
  if (c) params.centre_code   = c;
  if (b) params.batch_id      = b;
  params = _applyRoleScopeFloor(params);
  var qs = Object.keys(params).map(function(k) {
    return encodeURIComponent(k) + '=' + encodeURIComponent(params[k]);
  });
  var url = '/ak-assessments/baseline-report' + (qs.length ? '?' + qs.join('&') : '');
  apiGet(url).then(function(d) {
    _akBrLastPayload = d || {};
    _akBrRender(_akBrLastPayload);
  }).catch(function(err) { showUserError('loading AK Baseline Report', err); });
}

function resetAkBaselineReportFilters() {
  // 2026-06-05: For Mobiliser / Sangini, Reset clears only the
  // optional Batch filter. The locked State + District + Centre are
  // re-asserted via the helper so the user's geography stays pinned.
  // 2026-06-06: State Lead behaves like Mobiliser/Sangini for State —
  // their state stays locked. District/Centre clear back to "All".
  var role = (currentUser && currentUser.role) || '';
  var lockedAll = (role === 'mobiliser' || role === 'sangini');
  var lockedState = (role === 'state_lead');
  if (lockedAll) {
    var bEl = document.getElementById('akBrFilterBatch');
    if (bEl) bEl.value = '';
    _akBrClearSelect('akBrFilterBatch', 'All Batches');
    if (typeof _lockGeoFiltersForRestrictedRole === 'function') {
      _lockGeoFiltersForRestrictedRole('akBrFilterState', 'akBrFilterDistrict', 'akBrFilterCentre');
    }
    if (typeof _loadBatchesForRestrictedRole === 'function') {
      _loadBatchesForRestrictedRole('akBaselineReport');
    }
  } else {
    // 2026-06-06: Previously this cleared District/Centre/Batch dropdown
    // *contents* down to a single placeholder option, which made the
    // dropdowns look empty after Reset because no cascade refire was
    // queued. Now we just clear the *value* on State/District (and re-
    // assert the SL state lock if applicable) and recascade so the lists
    // repopulate as the user expects.
    ['akBrFilterDistrict','akBrFilterCentre','akBrFilterBatch'].forEach(function(id) {
      var el = document.getElementById(id); if (el) el.value = '';
    });
    _akBrClearSelect('akBrFilterDistrict', 'All Districts');
    _akBrClearSelect('akBrFilterCentre',   'All Centres');
    _akBrClearSelect('akBrFilterBatch',    'All Batches');
    if (lockedState && typeof _lockGeoFiltersForRestrictedRole === 'function') {
      // SL: re-pin State to their state + re-trigger the cascade so
      // District/Centre/Batch repopulate with that state's records.
      _lockGeoFiltersForRestrictedRole('akBrFilterState', 'akBrFilterDistrict', 'akBrFilterCentre');
    } else if ((role === 'district_lead' || role === 'pi') &&
               typeof _lockAkFiltersForDlPi === 'function') {
      // 2026-06-08 (round 4): DL/PI BR — re-apply soft 2-option locks
      // on State + District + Centre after Reset wipes them.
      _lockAkFiltersForDlPi('akBrFilterState', 'akBrFilterCentre', { stateMode: 'soft', centreMode: 'soft' });
      if (typeof _lockAkBrDistrictForDlPi === 'function') _lockAkBrDistrictForDlPi();
      // Also reload Batch scoped to user's centre.
      if (typeof _loadBatchesForRestrictedRole === 'function') {
        _loadBatchesForRestrictedRole('akBaselineReport');
      }
    } else {
      // Admin / super-admin: clear State value too.
      var sEl = document.getElementById('akBrFilterState'); if (sEl) sEl.value = '';
    }
  }
  applyAkBaselineReportFilters();
}

// ---- Render ---------------------------------------------------------------

function _akBrRender(d) {
  var total = d.total_baselines || 0;
  // KPI cards
  function setKpi(id, val) { var el = document.getElementById(id); if (el) el.textContent = (val == null || val === '' || val === '—') ? '—' : val; }
  var fmtINR = function(n) { return n == null ? '—' : ('₹' + Number(n).toLocaleString('en-IN')); };
  setKpi('akBrKpiTotal',     total);
  setKpi('akBrKpiAvgAge',    d.avg_age != null ? d.avg_age + ' yrs' : '—');
  setKpi('akBrKpiAvgIncome', fmtINR(d.avg_income));

  // Phone ownership % (q103 = Yes)
  var phoneYes = _akBrPctYes(((d.cyber || {}).q103_dist) || [], 'Yes');
  setKpi('akBrKpiPhone', phoneYes != null ? phoneYes + '%' : '—');

  // Discussion with parents (q43 multi — count leaders with at least 1 selection)
  var q43 = ((d.career || {}).q43_multi) || [];
  var q43Mentioning = q43.length ? Math.round((q43.reduce(function(s, r) { return s + r.c; }, 0) / Math.max(1, total))) : 0;
  // That's avg topics; instead use highest-topic % as a "Talk to Parents" proxy
  var topTopic = q43.length ? q43[0].c : 0;
  setKpi('akBrKpiTalkParents', total ? Math.round(topTopic * 100 / total) + '%' : '—');

  // Self-efficacy: q99 "Strongly Agree" + "Somewhat Agree" of total responding
  var q99 = ((d.efficacy || {}).q99_dist) || [];
  var seGood = 0, seTotal = 0;
  q99.forEach(function(r) { seTotal += r.c; if (r.opt === 'Strongly Agree' || r.opt === 'Somewhat Agree') seGood += r.c; });
  setKpi('akBrKpiSelfEfficacy', seTotal ? Math.round(seGood * 100 / seTotal) + '%' : '—');

  // Key Findings — slim 8-card high-level summary (v2 per user feedback)
  _akBrRenderKeyFindings(d, total);

  // Charts — Section A: Demographics
  _akBrRenderEducationChart(d);
  _akBrRenderIncomeChart(d);
  // Section B: Gender Norms
  _akBrRenderGenderLikertChart(d);
  // Section C: Career & Aspirations (3 charts)
  _akBrRenderQ48Chart(d);
  _akBrRenderCareerAspirationsChart(d);   // Q44 vs Q45 grouped bar
  _akBrRenderCareerNTLChart(d);           // Q50 pie
  // Section D: Mobility (4 charts) — separated from Cyber per user feedback
  _akBrRenderMobilityChart(d);
  _akBrRenderMobilityQ91Chart(d);
  _akBrRenderMobilityQ92Chart(d);
  _akBrRenderMobilityQ96Chart(d);
  // Section E: Cyber Safety (3 charts) — its own section now
  _akBrRenderCyberQ103Chart(d);
  _akBrRenderCyberQ107Chart(d);
  _akBrRenderCyberChart(d);               // Yes/No: Q110/Q111/Q113/Q115
  // Section F: Agency & Leadership (3 charts)
  _akBrRenderAgencyQ56Chart(d);
  _akBrRenderAgencyQ57Chart(d);
  _akBrRenderEfficacyChart(d);
  // Section G: GBV (3 charts)
  _akBrRenderGbvChart(d);                 // Q65 pie
  _akBrRenderGbvQ70Chart(d);
  _akBrRenderGbvQ68Chart(d);
  // Section H: SRH (4 charts)
  _akBrRenderSrhQ72Chart(d);
  _akBrRenderSrhQ74Chart(d);
  _akBrRenderSrhQ78Chart(d);
  _akBrRenderSrhQ73Chart(d);
}

// Helper: % of cohort that picked a single-choice answer.
function _akBrPctYes(dist, label) {
  var total = dist.reduce(function(s, r) { return s + r.c; }, 0);
  if (!total) return null;
  var hit = dist.filter(function(r) { return r.k === label; })[0];
  return Math.round(((hit && hit.c) || 0) * 100 / total);
}

// Build / re-build a chart, destroying any previous instance first so the
// canvas can be reused across filter changes.
function _akBrMakeChart(canvasId, config) {
  if (_akBrCharts[canvasId]) { try { _akBrCharts[canvasId].destroy(); } catch (e) {} }
  var ctx = document.getElementById(canvasId);
  if (!ctx) return;

  var t = (config && config.type) || '';
  var isScrollableType = (t === 'bar' || t === 'line');
  var isHorizontalBar = t === 'bar' &&
    config.options && config.options.indexAxis === 'y';

  // 2026-06-06 v10: On desktop / web view, if a PREVIOUS render
  // already wrapped the canvas in .chart-canvas-outer >
  // .chart-canvas-inner (which can happen because the page is an
  // SPA and the user may have visited at <=768px viewport before,
  // OR because earlier code versions wrapped on all viewports),
  // strip those wraps now so Chart.js can measure the chart-card
  // directly. Without this, display:contents on the wraps makes
  // Chart.js read 0x0 for the canvas parent and the bar chart
  // renders invisible.
  var _wm = window.matchMedia;
  if (!(_wm && _wm('(max-width: 768px)').matches) &&
      ctx.parentElement &&
      ctx.parentElement.classList.contains('chart-canvas-inner')) {
    var _inner = ctx.parentElement;
    var _outer = _inner.parentElement;
    if (_outer && _outer.parentElement) {
      _outer.parentElement.insertBefore(ctx, _outer);
      _outer.parentElement.removeChild(_outer);
    }
  }

  // 2026-06-06 v9: MOBILE-ONLY chart wrap + tag + dimension fix.
  // User explicitly said earlier attempts also changed the WEB
  // (desktop) view — they only want the Mobiliser / Sangini mobile
  // browser experience improved. So everything below is now hard-
  // gated behind a (max-width: 768px) match. On desktop NONE of
  // this runs and Chart.js sees the exact same DOM + cascade it
  // saw before any of these helpers were patched.
  var isMobile = window.matchMedia &&
                 window.matchMedia('(max-width: 768px)').matches;

  var innerEl = null;
  if (isMobile && isScrollableType && ctx.parentElement &&
      !ctx.parentElement.classList.contains('chart-canvas-inner')) {
    var outer = document.createElement('div');
    outer.className = 'chart-canvas-outer';
    var inner = document.createElement('div');
    inner.className = 'chart-canvas-inner';
    ctx.parentNode.insertBefore(outer, ctx);
    outer.appendChild(inner);
    inner.appendChild(ctx);
    innerEl = inner;
    // 2026-06-06 v14: Fit-to-screen list trimmed. Q91, Q56, Q73
    // are MOVED BACK to the 800px horizontal-scroll group per
    // user request — they also get their labels wrapped via
    // _akBrWrapLabel() at the chart-config level so the y-axis
    // text is clean even when scrolled. Remaining fit-screen
    // charts: Q6, Family Income, Q44 vs Q45, Q74, Q68.
    var _fitScreen = (canvasId === 'akBrEducationChart' ||
                      canvasId === 'akBrIncomeChart' ||
                      canvasId === 'akBrCareerAspirationsChart' ||  // Q44 vs Q45
                      canvasId === 'akBrSrhQ74Chart' ||              // Q74
                      canvasId === 'akBrGbvQ68Chart');               // Q68
    outer.style.cssText = 'display:block;width:100%;' +
      (_fitScreen ? 'overflow-x:hidden;' : 'overflow-x:auto;') +
      'overflow-y:hidden;-webkit-overflow-scrolling:touch;';
    if (_fitScreen) {
      // Q6 / Income / Q44vs45 / Q74: vertical bars — compact 240px
      // Q91 / Q56 / Q73 / Q68: horizontal bars — 340px so all
      //                                          category rows fit
      var _h = (isHorizontalBar ? '340px' : '240px');
      inner.style.cssText = 'display:block;width:100%;height:' + _h + ';position:relative;';
    } else {
      inner.style.cssText = 'display:block;width:' +
        (isHorizontalBar ? '800px;height:460px' : '800px;height:340px') +
        ';position:relative;';
    }
  } else if (isMobile && isScrollableType && ctx.parentElement &&
             ctx.parentElement.classList.contains('chart-canvas-inner')) {
    innerEl = ctx.parentElement;
  }

  // Tag the parent .chart-card ONLY on mobile so the mobile CSS
  // can target chart-bar / chart-doughnut etc. Desktop never gets
  // these classes and behaves exactly as it did pre-fix.
  var card = ctx.closest && ctx.closest('.chart-card');
  if (isMobile && card) {
    card.classList.remove('chart-bar', 'chart-line', 'chart-pie',
                          'chart-doughnut', 'chart-radar', 'chart-polarArea');
    if (t) card.classList.add('chart-' + t);
    card.classList.toggle('chart-horizontal-bar', !!isHorizontalBar);
  }

  // Sync layout flush — also mobile-only since it's only useful
  // when the wrap was just inserted.
  if (isMobile && innerEl) { void innerEl.offsetHeight; }

  _akBrCharts[canvasId] = new Chart(ctx.getContext('2d'), config);
}

// ---- Key Findings narrative ----------------------------------------------

function _akBrRenderKeyFindings(d, totalN) {
  // 2026-06-01 (v2): Slimmed to a single grid of 8 high-level cards
  // (one headline per section). The detailed findings that used to live
  // here are now visualised in dedicated graph sections below — Career,
  // Mobility, Cyber Safety, Agency, GBV, SRH each have 2–4 charts of
  // their own.
  var host = document.getElementById('akBrKeyFindings');
  if (!host) return;
  if (!totalN) {
    host.innerHTML = '<div class="br-kf-empty">No submitted baseline assessments in the current filter scope.</div>';
    return;
  }
  var esc = (typeof escHtml === 'function') ? escHtml : function(s) { return String(s == null ? '' : s); };
  var pct = function(num, denom) { return denom ? Math.round(num * 100 / denom) : 0; };
  function statusForProgress(p) { return p >= 60 ? 'positive' : (p >= 40 ? 'mixed' : 'concern'); }
  function tagForProgress(p)    { return p >= 60 ? 'Progressive' : (p >= 40 ? 'Mixed' : 'Concern'); }
  function card(opts) {
    var cls = 'br-kf-card' + (opts.status ? ' ' + opts.status : '');
    var tag = opts.tag ? '<span class="br-kf-tag">' + esc(opts.tag) + '</span>' : '';
    return '<div class="' + cls + '">'
         + '<div class="br-kf-label">' + esc(opts.label) + '</div>'
         + '<div class="br-kf-metric">' + opts.metric + '</div>'
         + (opts.desc ? '<div class="br-kf-desc">' + opts.desc + '</div>' : '')
         + tag
         + '</div>';
  }
  // For Likert questions we treat 'Disagree' as progressive on
  // patriarchal-claim statements (Q87/Q88/Q89).
  function progScalePct(distArr, progressiveOpts) {
    var total = 0, prog = 0;
    (distArr || []).forEach(function(r) { total += r.c; if (progressiveOpts.indexOf(r.opt) >= 0) prog += r.c; });
    return total ? Math.round(prog * 100 / total) : 0;
  }

  var cards = [];

  // 1. Demographics — top education level
  var ed = (d.education_dist || [])[0];
  if (ed) {
    cards.push(card({ status: 'positive', label: 'Top Education Level', metric: esc(ed.k),
      desc: '<b>' + ed.c + '</b> of <b>' + totalN + '</b> (' + pct(ed.c, totalN) + '%) at this level.' }));
  }
  // 2. Gender Norms — average rejection of Q87/Q88/Q89 patriarchal claims
  var gn = d.gender_norms || {};
  var gnPcts = ['q87_dist','q88_dist','q89_dist'].map(function(k) {
    return progScalePct(gn[k] || [], ['Somewhat Disagree','Strongly Disagree']);
  });
  var gnAvg = Math.round(gnPcts.reduce(function(a,b) { return a + b; }, 0) / gnPcts.length);
  cards.push(card({ status: statusForProgress(gnAvg), label: 'Gender Norms — Progressive %',
    metric: gnAvg + '%', desc: 'average rejection of patriarchal claims (Q87 permission · Q88 male leadership · Q89 dowry).',
    tag: tagForProgress(gnAvg) }));

  // 3. Mobility — travel to school alone (Q90)
  var alone90 = _akBrPctYes((d.mobility || {}).q90_dist || [], 'Alone');
  if (alone90 != null) {
    cards.push(card({ status: statusForProgress(alone90), label: 'Mobility — Travel to School Alone',
      metric: alone90 + '%', desc: 'travel to school independently (Q90).', tag: tagForProgress(alone90) }));
  }
  // 4. Cyber Safety — phone ownership (Q103)
  var phone = _akBrPctYes((d.cyber || {}).q103_dist || [], 'Yes');
  if (phone != null) {
    cards.push(card({ status: statusForProgress(phone), label: 'Cyber Safety — Own a Phone',
      metric: phone + '%', desc: 'have their own mobile phone (Q103).', tag: tagForProgress(phone) }));
  }
  // 5. Career — open to non-traditional jobs (Q50)
  var ntl = _akBrPctYes((d.career || {}).q50_dist || [], 'Yes');
  if (ntl != null) {
    cards.push(card({ status: statusForProgress(ntl), label: 'Career — Open to Non-Traditional Jobs',
      metric: ntl + '%', desc: 'would consider electrician / driver / mechanic / painter careers (Q50).',
      tag: tagForProgress(ntl) }));
  }
  // 6. Agency — combined self-efficacy across Q99-Q102
  var seSum = 0, seTotalSum = 0;
  ['q99_dist','q100_dist','q101_dist','q102_dist'].forEach(function(k) {
    ((d.efficacy || {})[k] || []).forEach(function(r) {
      seTotalSum += r.c;
      if (r.opt === 'Strongly Agree' || r.opt === 'Somewhat Agree') seSum += r.c;
    });
  });
  if (seTotalSum) {
    var pSe = Math.round(seSum * 100 / seTotalSum);
    cards.push(card({ status: statusForProgress(pSe), label: 'Agency — Self-Efficacy',
      metric: pSe + '%', desc: 'agree they can achieve goals and handle difficult tasks (Q99-Q102).',
      tag: tagForProgress(pSe) }));
  }
  // 7. GBV — reject hitting women (Q65)
  var d65 = (d.gbv || {}).q65_dist || [];
  var tot65 = d65.reduce(function(s, r) { return s + r.c; }, 0);
  var prog65 = d65.filter(function(r) { return /completely wrong|wrong for a man/i.test(r.k); }).reduce(function(s, r) { return s + r.c; }, 0);
  if (tot65) {
    var p65 = Math.round(prog65 * 100 / tot65);
    cards.push(card({ status: statusForProgress(p65), label: 'GBV — Reject Hitting Women',
      metric: p65 + '%', desc: 'reject the idea that hitting women is acceptable (Q65).',
      tag: tagForProgress(p65) }));
  }
  // 8. SRH — comfortable discussing menstruation at home (Q78)
  var d78 = (d.srh || {}).q78_dist || [];
  var tot78 = d78.reduce(function(s, r) { return s + r.c; }, 0);
  var ok78 = d78.filter(function(r) { return /comfortable/i.test(r.k) && !/Not at all/i.test(r.k); }).reduce(function(s, r) { return s + r.c; }, 0);
  if (tot78) {
    var p78 = Math.round(ok78 * 100 / tot78);
    cards.push(card({ status: statusForProgress(p78), label: 'SRH — Talk About SRH at Home',
      metric: p78 + '%', desc: 'are comfortable discussing menstruation / SRH at home (Q78).',
      tag: tagForProgress(p78) }));
  }

  host.innerHTML = cards.length
    ? '<div class="br-kf-grid">' + cards.join('') + '</div>'
    : '<div class="br-kf-empty">No findings to display for the current filter.</div>';
}

