function _akBrRenderGenderLikertChart(d) {
  // Stacked horizontal bar — one stack per Q80..Q89 with the 5-point split.
  var gn = d.gender_norms || {};
  var keys = ['q80_dist','q81_dist','q83_dist','q84_dist','q85_dist','q86_dist','q87_dist','q88_dist','q89_dist'];
  var titles = {
    q80_dist: 'Q80 — Gender ≠ Sex',
    q81_dist: 'Q81 — Early motherhood: disadvantages',
    q83_dist: 'Q83 — Girls weaker in maths',
    q84_dist: 'Q84 — Girls play outdoor sports',
    q85_dist: 'Q85 — Boys & girls play together',
    q86_dist: 'Q86 — Comfortable talking to boys',
    q87_dist: 'Q87 — Wife needs permission for market',
    q88_dist: 'Q88 — Leaders should be men',
    q89_dist: 'Q89 — Parents should give dowry'
  };
  var labels = keys.map(function(k) { return titles[k]; });
  var SCALE = ['Strongly Agree','Somewhat Agree','Neither Agree nor Disagree','Somewhat Disagree','Strongly Disagree'];
  var COLORS = ['#c0392b','#e67e22','#bdc3c7','#16a085','#27ae60'];
  var datasets = SCALE.map(function(opt, i) {
    return {
      label: opt,
      backgroundColor: COLORS[i],
      data: keys.map(function(k) {
        var r = (gn[k] || []).filter(function(x) { return x.opt === opt; })[0];
        return (r && r.c) || 0;
      }),
    };
  });
  _akBrMakeChart('akBrGenderLikertChart', {
    type: 'bar',
    data: { labels: labels, datasets: datasets },
    options: {
      responsive: true, maintainAspectRatio: false, indexAxis: 'y',
      plugins: { legend: { position: 'bottom' } },
      scales: { x: { stacked: true, ticks: { precision: 0 } }, y: { stacked: true } }
    }
  });
}

