function _akBrRenderCyberChart(d) {
  // Side-by-side bars: "Yes" vs "No" for q103 / q110 / q113 / q115.
  var cyb = d.cyber || {};
  var labels = ['Own Phone (Q103)','Privacy Awareness (Q110)','Cyber Laws (Q113)','Google for Education (Q115)'];
  function yesNo(distArr) {
    var yes = ((distArr || []).filter(function(r) { return r.k === 'Yes'; })[0] || {}).c || 0;
    var no  = ((distArr || []).filter(function(r) { return r.k === 'No';  })[0] || {}).c || 0;
    return { yes: yes, no: no };
  }
  var rows = [cyb.q103_dist, cyb.q110_dist, cyb.q113_dist, cyb.q115_dist].map(yesNo);
  _akBrMakeChart('akBrCyberChart', {
    type: 'bar',
    data: {
      labels: labels,
      datasets: [
        { label: 'Yes', data: rows.map(function(r) { return r.yes; }), backgroundColor: '#27ae60', borderRadius: 4 },
        { label: 'No',  data: rows.map(function(r) { return r.no;  }), backgroundColor: '#c0392b', borderRadius: 4 }
      ],
    },
    options: { responsive: true, maintainAspectRatio: false,
               plugins: { legend: { position: 'bottom' } },
               scales: { y: { beginAtZero: true, ticks: { precision: 0 } } } }
  });
}

