// Section C — Career & Aspirations

function _akBrRenderCareerAspirationsChart(d) {
  // Side-by-side bar: Q44 (parents want her to study till) vs Q45 (what
  // she wants to study). Same option set across both questions.
  var car = d.career || {};
  var q44 = car.q44_dist || [];
  var q45 = car.q45_dist || [];
  // Union the option keys, preserving Q44's order then appending any
  // new Q45-only keys.
  var labels = q44.map(function(r) { return r.k; });
  q45.forEach(function(r) { if (labels.indexOf(r.k) < 0) labels.push(r.k); });
  function pickC(arr, k) { var hit = arr.filter(function(r) { return r.k === k; })[0]; return (hit && hit.c) || 0; }
  _akBrMakeChart('akBrCareerAspirationsChart', {
    type: 'bar',
    data: {
      labels: labels,
      datasets: [
        { label: 'Parents want (Q44)', data: labels.map(function(k) { return pickC(q44, k); }), backgroundColor: '#732269', borderRadius: 4 },
        { label: 'Self wants (Q45)',   data: labels.map(function(k) { return pickC(q45, k); }), backgroundColor: '#3498db', borderRadius: 4 },
      ],
    },
    options: { responsive: true, maintainAspectRatio: false,
               plugins: { legend: { position: 'bottom' } },
               scales: { y: { beginAtZero: true, ticks: { precision: 0 } } } }
  });
}

