function _akBrRenderGbvQ68Chart(d) {
  // Q68 — multi-select "what is violence?"
  // 2026-06-06 v12: Long category labels (e.g. "Stopping someone
  // from seeing their family/friends") now wrap into multiple
  // lines via Chart.js's array-of-strings label format, so the
  // y-axis text doesn't crowd or get truncated.
  var rows = ((d.gbv || {}).q68_multi) || [];
  _akBrMakeChart('akBrGbvQ68Chart', {
    type: 'bar',
    data: {
      labels: rows.map(function(r) { return _akBrWrapLabel(r.k || '', 26); }),
      datasets: [{ label: 'Leaders', data: rows.map(function(r) { return r.c; }),
                   backgroundColor: '#c0392b', borderRadius: 4 }],
    },
    options: { responsive: true, maintainAspectRatio: false, indexAxis: 'y',
               plugins: { legend: { display: false } },
               scales: { x: { beginAtZero: true, ticks: { precision: 0 } },
                         y: { ticks: { autoSkip: false, font: { size: 11 } } } } }
  });
}

// Helper: split a long label into an array of lines (max chars
// per line). Chart.js renders array labels as multi-line text.
function _akBrWrapLabel(text, maxLen) {
  text = String(text || '');
  if (text.length <= maxLen) return text;
  var words = text.split(/\s+/);
  var lines = [], cur = '';
  for (var i = 0; i < words.length; i++) {
    var w = words[i];
    if (!cur) { cur = w; continue; }
    if ((cur + ' ' + w).length > maxLen) {
      lines.push(cur);
      cur = w;
    } else {
      cur += ' ' + w;
    }
  }
  if (cur) lines.push(cur);
  return lines;
}

