function _collectWwwGbv() {
  // GBV situations: pull checked + their data-violence category.
  var situations = [];
  document.querySelectorAll('#wwwAtSituations input[type="checkbox"]:checked').forEach(function(el) {
    situations.push({
      situation: el.value,
      violence_category: el.getAttribute('data-violence') || null
    });
  });
  return {
    gbv_situations: situations,
    violence_place: _wwwVal('wwwAtViolencePlace') || null,
    violence_by: _wwwVal('wwwAtViolenceBy') || null,
    violence_when: _wwwVal('wwwAtViolenceWhen') || null,
    want_support: _wwwRadio('wwwAtWantSupport'),
    gbv_support_kinds: _wwwCheckedAll('wwwAtSupportKind'),
    support_other: _wwwVal('wwwAtSupportOther') || null,
    housework_hours: _wwwVal('wwwAtHouseworkHrs') || null,
    encouraged_by: _wwwCheckedAll('wwwAtEncBy')
  };
}

function _collectWwwReference() {
  var refs = [];
  document.querySelectorAll('#wwwAtRefBody tr').forEach(function(tr) {
    var cells = tr.querySelectorAll('td');
    if (cells.length < 3) return;
    var name = ((cells[0].querySelector('input') || {}).value || '').trim();
    var rel  = (cells[1].querySelector('select') || {}).value || '';
    var mob  = ((cells[2].querySelector('input') || {}).value || '').trim();
    if (!name && !rel && !mob) return;
    refs.push({ ref_name: name || null, relation: rel || null, contact_no: mob || null });
  });
  // Documents: from the doc list table.  File binary upload is not yet
  // wired — Phase 3 stores only metadata that was added via addWwwDoc().
  var docs = [];
  document.querySelectorAll('#wwwAtDocList tr').forEach(function(tr) {
    if (tr.classList.contains('empty-row')) return;
    var cells = tr.querySelectorAll('td');
    if (cells.length < 4) return;
    var fn = (cells[0].textContent || '').trim();
    var dt = (cells[1].textContent || '').trim();
    if (!fn && !dt) return;
    docs.push({ file_name: fn || null, doc_type: dt || null });
  });
  return { references: refs, documents: docs };
}

function _collectWwwCommitment() {
  return {
    commit_aware: _wwwRadio('wwwAtCmtAware'),
    commit_ready: _wwwRadio('wwwAtCmtReady'),
    commit_amount: _wwwRadio('wwwAtCmtAmount'),
    commit_paid_status: _wwwVal('wwwAtCmtPaidStatus') || null,
    commit_paid_amount: _wwwVal('wwwAtCmtPaidAmount') || null,
    commit_partial_amt: _wwwVal('wwwAtCmtPartialAmt') || null
  };
}

// =============================================================================
// Master collector: builds the full TraineeIn payload
// =============================================================================
function _collectWwwTraineeAll(asDraft) {
  var basic = _collectWwwBasic();
  var payload = basic;
  Object.assign(payload, _collectWwwPrevEmp());
  Object.assign(payload, _collectWwwFinancial());
  Object.assign(payload, _collectWwwHousing());
  Object.assign(payload, _collectWwwDisability());
  Object.assign(payload, _collectWwwOrgAssoc());
  Object.assign(payload, _collectWwwGbv());
  Object.assign(payload, _collectWwwCommitment());
  payload.family_members = _collectWwwFamily();
  var ref = _collectWwwReference();
  payload.references = ref.references;
  payload.documents = ref.documents;
  payload.status = asDraft ? 'Draft' : 'Active';
  return payload;
}

// =============================================================================
// SAVE
// =============================================================================
function saveWwwTrainee(asDraft) {
  var payload = _collectWwwTraineeAll(asDraft);
  // Minimum required validation — matches backend.
  if (!payload.name || !payload.state_code || !payload.district_code || !payload.centre_code) {
    alert('Please fill Name, State, District and Centre before saving.');
    switchWwwAtTab('basic');
    return;
  }
  var isEdit = !!_wwwEditingId;
  var url = '/www-trainees' + (isEdit ? '/' + _wwwEditingId : '');
  var promise = isEdit
    ? apiPut(url, payload)
    : apiPost(url, payload);
  promise.then(function(resp) {
    var msg = asDraft ? 'Trainee saved as Draft.' : 'Trainee saved successfully.';
    if (resp && resp.enrollment_no) msg += '\nEnrollment No: ' + resp.enrollment_no;
    alert(msg);
    _wwwEditingId = null;
    navigateTo('wwwEnrollmentList');
  }).catch(function(err) {
    console.error('WWW save error:', err);
    alert('Save failed: ' + ((err && err.message) || err || 'unknown error'));
  });
}

// =============================================================================
// Per-tab hydrators (reverse of collectors)
// =============================================================================
function _hydrateWwwBasic(d) {
  _wwwSetVal('wwwAtEnrollNo', d.enrollment_no);
  _wwwSetVal('wwwAtFinYear', d.financial_year);
  _wwwSetVal('wwwAtState', d.state_code);
  // Trigger cascade so district/centre/area get populated before we set them.
  if (typeof onWwwAtStateChange === 'function' && d.state_code) onWwwAtStateChange();
  setTimeout(function() {
    _wwwSetVal('wwwAtDistrict', d.district_code);
    if (typeof onWwwAtDistrictChange === 'function' && d.district_code) onWwwAtDistrictChange();
    setTimeout(function() {
      _wwwSetVal('wwwAtCentre', d.centre_code);
      if (typeof onWwwAtCentreChange === 'function' && d.centre_code) onWwwAtCentreChange();
      setTimeout(function() {
        _wwwSetVal('wwwAtArea', d.area_code);
        _wwwSetVal('wwwAtBatch', d.batch_id);
      }, 300);
    }, 300);
  }, 300);
  _wwwSetVal('wwwAtBasti', d.basti);
  _wwwSetVal('wwwAtName', d.name);
  _wwwSetVal('wwwAtEnrollDate', d.enrollment_date);
  _wwwSetVal('wwwAtEnrollType', d.enrollment_type);
  _wwwSetVal('wwwAtDob', d.date_of_birth);
  _wwwSetVal('wwwAtAge', d.age_at_enrollment);
  _wwwSetVal('wwwAtBlood', d.blood_group);
  _wwwSetVal('wwwAtMobile', d.mobile);
  _wwwSetVal('wwwAtEmail', d.email);
  _wwwSetVal('wwwAtCurrAddr', d.current_address);
  _wwwSetVal('wwwAtPermAddr', d.permanent_address);
  _wwwSetVal('wwwAtCaste', d.caste_category);
  _wwwSetVal('wwwAtCasteOther', d.caste_other);
  _wwwSetVal('wwwAtReligion', d.religion);
  _wwwSetVal('wwwAtReligionOther', d.religion_other);
  _wwwSetVal('wwwAtGender', d.gender);
  _wwwSetVal('wwwAtGenderOther', d.gender_other);
  _wwwSetVal('wwwAtMarital', d.marital_status);
  _wwwSetVal('wwwAtAgeMarriage', d.age_at_marriage);
  _wwwSetVal('wwwAtLivingWith', d.living_with);
  _wwwSetVal('wwwAtLivingWithOther', d.living_with_other);
  _wwwSetVal('wwwAtEducation', d.education_qualification);
  _wwwSetVal('wwwAtEducationOther', d.education_other);
  _wwwSetVal('wwwAtStudying', d.still_studying === true ? 'Yes' : (d.still_studying === false ? 'No' : ''));
  _wwwSetVal('wwwAtClass', d.studying_class);
  _wwwSetVal('wwwAtEmgCount', d.num_emergency_contacts || (d.emergency_contacts || []).length);
  if (typeof onWwwAtEmgCountChange === 'function') onWwwAtEmgCountChange();
  setTimeout(function() {
    var emgInputs = document.querySelectorAll('#wwwAtEmgList input[type="tel"]');
    (d.emergency_contacts || []).forEach(function(num, i) {
      if (emgInputs[i]) emgInputs[i].value = num;
    });
  }, 100);
  _wwwSetRadio('wwwAtSocial', d.has_social_media === true ? 'Yes' : (d.has_social_media === false ? 'No' : null));
  _wwwSetCheckedAll('wwwAtSocialPlatform', d.social_platforms || []);
  _wwwSetVal('wwwAtSource', d.how_known_azad);
  _wwwSetVal('wwwAtMobActivity', d.mobilization_activity);
  // 2026-06-11: LL / PL block hydrate.
  _wwwSetRadio('wwwAtLicType', d.came_with_lic_type);
  _wwwSetVal('wwwAtLlDate', d.ll_date);
  _wwwSetVal('wwwAtLlNumber', d.ll_number);
  _wwwSetVal('wwwAtLlAttempts', d.ll_attempts);
  _wwwSetVal('wwwAtPlDate', d.pl_date);
  _wwwSetVal('wwwAtPlNumber', d.pl_number);
  _wwwSetVal('wwwAtPlAttempts', d.pl_attempts);
  // Re-run all the conditional-field handlers so toggled wraps reflect data.
  // (Includes the 3 new ones added 2026-06-11: Age at Marriage,
  // Studying-Class, and Social Platforms.)
  ['onWwwAtCasteChange', 'onWwwAtReligionChange', 'onWwwAtGenderChange',
   'onWwwAtLivingWithChange', 'onWwwAtEducationChange', 'onWwwAtSourceChange',
   'onWwwAtMobActivityChange', 'onWwwAtMaritalChange', 'onWwwAtStudyingChange',
   'onWwwAtSocialChange', 'onWwwAtLicTypeChange', 'onWwwAtDobChange',
   'onWwwAtWorkedChange', 'onWwwAtWorkTypeChange',
   // 2026-06-11: Financial Status conditional reveals.
   'onWwwAtBankChange', 'onWwwAtSavingsChange', 'onWwwAtDebtChange',
   // 2026-06-11: Savings "Some Other Place" -> Specify input reveal.
   'onWwwAtSavingsWhereChange',
   // 2026-06-11: Disability Info gate + relation Any-Other.
   'onWwwAtDisHouseChange', 'onWwwAtDisRelationChange',
   // 2026-06-11: Housing & Asset Info conditional reveals.
   'onWwwAtOwnershipChange', 'onWwwAtPropNameChange', 'onWwwAtPropKeeperChange',
   'onWwwAtMobOwnChange', 'onWwwAtSmartPhoneChange', 'onWwwAtPhoneUsageChange',
   // 2026-06-11: Organization Association gate + Any-Other reveals.
   'onWwwAtRelativeWorksChange', 'onWwwAtRelativeRelationChange', 'onWwwAtRelativeDesignationChange',
   // 2026-06-11: GBV conditionals (violence place / want support / two Other-Specify).
   'onWwwAtViolencePlaceChange', 'onWwwAtWantSupportChange',
   'onWwwAtSupportAnyOtherChange', 'onWwwAtEncOtherChange',
   // 2026-06-11: Commitment Fund cascade (Full/Partial).
   'onWwwAtCmtPaidStatusChange'
  ].forEach(function(fn) {
    if (typeof window[fn] === 'function') { try { window[fn](); } catch(_e) {} }
  });
}

function _hydrateWwwFamily(d) {
  var tbody = document.getElementById('wwwAtFamilyBody');
  if (!tbody) return;
  tbody.innerHTML = '';
  var rows = d.family_members || [];
  if (!rows.length) { addWwwFamilyRow(); return; }
  // 2026-06-11: standard options for relation + occupation.  If saved
  // value isn't in the list, treat it as "Other" with the saved text in
  // the Specify input.
  var STD_RELATIONS  = ['Father','Mother','Husband','Brother','Sister','Son','Daughter','Other'];
  var STD_OCCUPATIONS = ['Unemployed','Student','Self-employed','Employed','Daily Wage','Other'];
  rows.forEach(function(fm) {
    addWwwFamilyRow();
    var tr = tbody.lastElementChild;
    var cells = tr.querySelectorAll('td');
    if (cells[0].querySelector('input')) cells[0].querySelector('input').value = fm.member_name || '';

    // Relation
    var relSel   = cells[1].querySelector('select');
    var relOther = cells[1].querySelector('.fam-relation-other');
    var rel = fm.relation || '';
    if (rel && STD_RELATIONS.indexOf(rel) < 0) {
      if (relSel)   relSel.value = 'Other';
      if (relOther) { relOther.value = rel; relOther.style.display = ''; }
    } else if (relSel) {
      relSel.value = rel;
    }

    if (cells[2].querySelector('input')) cells[2].querySelector('input').value = fm.mobile_no || '';
    if (cells[3].querySelector('input')) cells[3].querySelector('input').value = fm.age == null ? '' : fm.age;
    if (cells[4].querySelector('select')) cells[4].querySelector('select').value = fm.education || '';

    // Occupation
    var occSel   = cells[5].querySelector('select');
    var occOther = cells[5].querySelector('.fam-occupation-other');
    var occ = fm.occupation || '';
    if (occ && STD_OCCUPATIONS.indexOf(occ) < 0) {
      if (occSel)   occSel.value = 'Other';
      if (occOther) { occOther.value = occ; occOther.style.display = ''; }
    } else if (occSel) {
      occSel.value = occ;
    }

    if (cells[6].querySelector('input')) cells[6].querySelector('input').value = fm.monthly_income == null ? '' : fm.monthly_income;
    if (cells[7].querySelector('input')) cells[7].querySelector('input').value = fm.monthly_contribution == null ? '' : fm.monthly_contribution;
  });
  if (typeof recalcWwwFamilyTotals === 'function') recalcWwwFamilyTotals();
}

