// 2026-06-11: helper to show/hide the "Specify, If other" input below
// the Relation / Occupation selects in a family-table row.
function _wwwFamilyToggleOther(sel, kind) {
  var td = sel.closest('td');
  if (!td) return;
  // 2026-06-11: add 'edu' kind for the Family Education dropdown.
  var specClass;
  if (kind === 'rel')      specClass = '.fam-relation-other';
  else if (kind === 'edu') specClass = '.fam-education-other';
  else                     specClass = '.fam-occupation-other';
  var inp = td.querySelector(specClass);
  if (!inp) return;
  // 2026-06-11: also match "Any Other" / "Any other" wording used in the
  // Occupation / Education dropdowns (Relation still uses plain "Other").
  var v = (sel.value || '').toLowerCase();
  if (v === 'other' || v === 'any other') {
    inp.style.display = '';
  } else {
    inp.style.display = 'none';
    inp.value = '';
  }
}

