function removeWwwFamilyRow(btn) {
  var tr = btn.closest('tr');
  if (tr) tr.remove();
  recalcWwwFamilyTotals();
}

function recalcWwwFamilyTotals() {
  var rows = document.querySelectorAll('#wwwAtFamilyBody tr');
  var members = rows.length;
  var total = 0;
  rows.forEach(function(r) {
    var inp = r.querySelector('.fam-income');
    var v = parseFloat((inp && inp.value) || '0');
    if (!isNaN(v)) total += v;
  });
  var perCapita = members > 0 ? Math.round(total / members) : 0;
  var pcEl = document.getElementById('wwwAtPerCapita');
  var mtEl = document.getElementById('wwwAtMonthlyTotal');
  if (pcEl) pcEl.textContent = members > 0 ? '₹ ' + perCapita.toLocaleString() : '—';
  if (mtEl) mtEl.textContent = total > 0 ? '₹ ' + total.toLocaleString() : '—';
}

// ---- GBV tab: auto-fill Type of Violence from situations checked ----
// Each situation checkbox carries a data-violence="<bucket>" attribute
// (mobility / physical / decision / verbal / sexual / financial).
// Every <span class="www-violence-tag" data-violence="..."> in the
// auto-fill row lights up when at least one situation in its bucket
// is ticked.  Pure UI feedback — no validation, no backend.
function _wwwRefreshViolenceTags() {
  var checked = document.querySelectorAll('#wwwAtSituations input[type="checkbox"]:checked');
  var activeBuckets = {};
  checked.forEach(function(cb) {
    var b = cb.getAttribute('data-violence');
    if (b && b !== 'none') activeBuckets[b] = true;
  });
  var tags = document.querySelectorAll('#wwwAtViolenceTypes .www-violence-tag');
  tags.forEach(function(t) {
    var b = t.getAttribute('data-violence');
    t.classList.toggle('is-active', !!activeBuckets[b]);
  });
}

