// Number of Emergency Contacts — generate N phone inputs, 10-digit
// number-only.  Capped at 10 to keep the UI sane (matches the input's
// max attribute).
// 2026-06-11: Emergency Contact 1, 2, ... now render as SIBLINGS of
// the Number field inside #wwwAtEmgWrap (same .www-form-grid.g4), so
// they sit on the SAME row to the right of the count.  We mark them
// with data-emg="1" so we can selectively remove and rebuild without
// touching the count field.
function onWwwAtEmgCountChange() {
  var countEl = document.getElementById('wwwAtEmgCount');
  var wrap = document.getElementById('wwwAtEmgWrap');
  if (!countEl || !wrap) return;
  var n = parseInt(countEl.value || '0', 10);
  if (isNaN(n) || n < 0) n = 0;
  if (n > 10) { n = 10; countEl.value = '10'; }
  // Preserve any values the user already typed.
  var prev = {};
  wrap.querySelectorAll('input[type="tel"]').forEach(function(inp, i) {
    prev[i + 1] = inp.value || '';
  });
  // Remove only the emergency-contact siblings (data-emg="1"); keep
  // the Number field intact.
  wrap.querySelectorAll('.www-field[data-emg]').forEach(function(el) { el.remove(); });
  for (var i = 1; i <= n; i++) {
    var val = (prev[i] || '').replace(/"/g, '&quot;');
    var div = document.createElement('div');
    div.className = 'www-field';
    div.setAttribute('data-emg', '1');
    div.innerHTML =
      '<label>Emergency Contact - ' + i + '</label>' +
      '<input type="tel" id="wwwAtEmg' + i + '" placeholder="10-digit number" ' +
             'maxlength="10" inputmode="numeric" pattern="[0-9]{10}" value="' + val + '" ' +
             'oninput="this.value=this.value.replace(/[^0-9]/g,\'\').slice(0,10)">';
    wrap.appendChild(div);
  }
}

