// Reset every conditional widget to its default visibility/enabled
// state.  Called from initWwwAddTrainee on every form open.
function _wwwResetBasicConditionals() {
  // 2026-06-11: include 3 new conditional wraps (Age at Marriage,
  // Class, Social Platforms) — all hidden by default.
  ['wwwAtCasteOtherWrap', 'wwwAtReligionOtherWrap', 'wwwAtGenderOtherWrap',
   'wwwAtLivingWithOtherWrap', 'wwwAtEducationOtherWrap',
   'wwwAtSourceOtherWrap', 'wwwAtMobActivityWrap', 'wwwAtMobActivityOtherWrap',
   'wwwAtAgeMarriageWrap', 'wwwAtClassWrap', 'wwwAtPlatWrap',
   // 2026-06-11: LL + PL groups (3 wraps each).
   'wwwAtLlDateWrap', 'wwwAtLlNumberWrap', 'wwwAtLlAttemptsWrap',
   'wwwAtPlDateWrap', 'wwwAtPlNumberWrap', 'wwwAtPlAttemptsWrap',
   // 2026-06-11: Previous Employment extras (one row, 2 hideable cells).
   'wwwAtWorkTypeWrap', 'wwwAtPrevIncomeWrap',
   // 2026-06-11: Commitment Fund cascade (Full vs Partial).
   'wwwAtCmtPaidAmountWrap', 'wwwAtCmtPartialAmtWrap',
   // 2026-06-11: Financial Status conditional reveals.
   'wwwAtBankTypeWrap', 'wwwAtBankNameWrap', 'wwwAtBankAcctWrap',
   'wwwAtSavingsWhereWrap',
   'wwwAtDebtAmtWrap', 'wwwAtLoanSourceWrap', 'wwwAtLoanRepayWrap',
   // 2026-06-11: Disability Info conditional reveals.
   'wwwAtDisRelationWrap', 'wwwAtDisTypeWrap', 'wwwAtDisCertWrap',
   // 2026-06-11: Housing & Asset Info conditional wraps.
   'wwwAtOwnDetailWrap',
   'wwwAtSmartPhoneWrap', 'wwwAtPhoneUserWrap',
   'wwwAtNetUseWrap',
   // 2026-06-11: Organization Association conditional wraps.
   'wwwAtRelativeNameWrap', 'wwwAtRelativeRelationWrap', 'wwwAtRelativeOrgWrap',
   'wwwAtRelativeDesignationWrap', 'wwwAtRelativeYearsWrap',
   // 2026-06-11: GBV conditional wraps.
   'wwwAtViolenceByWrap', 'wwwAtSupportKindWrap'
  ].forEach(function(id) {
    var el = document.getElementById(id);
    if (el) el.style.display = 'none';
  });
  ['wwwAtCasteOther','wwwAtReligionOther','wwwAtGenderOther',
   'wwwAtLivingWithOther','wwwAtEducationOther','wwwAtSourceOther',
   'wwwAtMobActivityOther'].forEach(function(id) {
    var el = document.getElementById(id);
    if (el) el.value = '';
  });
  var age = document.getElementById('wwwAtAgeMarriage');
  if (age) age.value = '';
  var cls = document.getElementById('wwwAtClass');
  if (cls) cls.value = '';
  // Clear platform checkboxes too.
  document.querySelectorAll('input[name="wwwAtPlat"]:checked').forEach(function(el) { el.checked = false; });
  // 2026-06-11: hide the inline "Specify, If other" input under Type of work.
  var workOther = document.getElementById('wwwAtWorkOther');
  if (workOther) { workOther.value = ''; workOther.style.display = 'none'; }
  // Seed emergency contacts (default 2 inputs).
  onWwwAtEmgCountChange();
  // 2026-06-10 v2: 4 new field validations.
  // (a) DOB max = today, clear age.
  var dob = document.getElementById('wwwAtDob');
  if (dob) {
    var t = new Date();
    var yyyy = t.getFullYear();
    var mm = String(t.getMonth() + 1).padStart(2, '0');
    var dd = String(t.getDate()).padStart(2, '0');
    dob.max = yyyy + '-' + mm + '-' + dd;
    dob.value = '';
  }
  var ageAt = document.getElementById('wwwAtAge');
  if (ageAt) ageAt.value = '';
  // (b) Reset perm-same checkbox + unlock perm address.
  var permChk = document.getElementById('wwwAtPermSame');
  if (permChk) permChk.checked = false;
  var permAddr = document.getElementById('wwwAtPermAddr');
  if (permAddr) { permAddr.readOnly = false; permAddr.style.backgroundColor = ''; }
}

// 2026-06-10 v2: WWW Basic Profile field validations.
// (1) Date of Birth: prevent future date + auto-calc Age at Enrollment.
function onWwwAtDobChange() {
  var dob = document.getElementById('wwwAtDob');
  var ageAt = document.getElementById('wwwAtAge');
  if (!dob) return;
  var v = dob.value;
  if (!v) { if (ageAt) ageAt.value = ''; return; }
  // Clamp future dates: if user typed/picked future, snap to today.
  var picked = new Date(v + 'T00:00:00');
  var now = new Date();
  if (picked > now) {
    var yyyy = now.getFullYear();
    var mm = String(now.getMonth() + 1).padStart(2, '0');
    var dd = String(now.getDate()).padStart(2, '0');
    dob.value = yyyy + '-' + mm + '-' + dd;
    picked = new Date(dob.value + 'T00:00:00');
    if (typeof alert === 'function') {
      // Soft notice only on change/blur, not oninput (avoids alert spam while typing year).
    }
  }
  if (!ageAt) return;
  // Compute integer age in completed years.
  var age = now.getFullYear() - picked.getFullYear();
  var m   = now.getMonth() - picked.getMonth();
  if (m < 0 || (m === 0 && now.getDate() < picked.getDate())) age--;
  if (age < 0) age = 0;
  ageAt.value = age;
}

// (2) Mobile: validate exactly 10 digits on blur (digits-only is enforced via oninput).
function _wwwValidateMobile(inp) {
  if (!inp) return;
  var v = (inp.value || '').replace(/[^0-9]/g, '');
  inp.value = v;
  if (v.length === 0) { inp.style.borderColor = ''; return; }
  if (v.length !== 10) {
    inp.style.borderColor = '#e74c3c';
    inp.title = 'Mobile number must be exactly 10 digits';
  } else {
    inp.style.borderColor = '';
    inp.title = '';
  }
}

// (3) Permanent Address "Same as Current Address" checkbox handler.
// When checked -> copy Current into Permanent + make Permanent readonly.
// When unchecked -> clear Permanent + unlock it.
function onWwwAtPermSameChange() {
  var chk = document.getElementById('wwwAtPermSame');
  var curr = document.getElementById('wwwAtCurrAddr');
  var perm = document.getElementById('wwwAtPermAddr');
  if (!chk || !perm) return;
  if (chk.checked) {
    perm.value = (curr && curr.value) ? curr.value : '';
    perm.readOnly = true;
    perm.style.backgroundColor = '#f5f5f5';
  } else {
    perm.readOnly = false;
    perm.style.backgroundColor = '';
  }
}

// (3b) Current Address change -> if Same-as-Current is ticked, mirror in real time.
function onWwwAtCurrAddrChange() {
  var chk = document.getElementById('wwwAtPermSame');
  if (chk && chk.checked) {
    var curr = document.getElementById('wwwAtCurrAddr');
    var perm = document.getElementById('wwwAtPermAddr');
    if (curr && perm) perm.value = curr.value || '';
  }
}

