// auto-classify, kick off the State dropdown fetch, ensure Basic tab
// is active.
function initWwwAddTrainee() {
  // 2026-06-11 Phase 3: reset edit-mode state by default — every fresh
  // form open is "Add New" until editWwwTrainee() sets the id again.
  _wwwEditingId = null;
  var upd = document.getElementById('btnWwwAtUpdateHeader');
  if (upd) upd.style.display = 'none';
  var banner = document.getElementById('wwwAtDraftBanner');
  if (banner) banner.style.display = 'none';
  var bc = document.getElementById('wwwAtBreadcrumb');
  if (bc && bc.lastChild) bc.lastChild.textContent = ' Add Enrollment';
  // 2026-06-11 hotfix v2: install event-delegated click handler on the
  // tab-nav so tab switching works even if the inline onclick attrs
  // ever get stripped or shadowed.  Idempotent.
  _wwwBindTabNavOnce();
  _wwwResetBasicConditionals();
  switchWwwAtTab('basic');
  // 2026-06-10: Cascading dropdowns — fetch States from the backend on
  // every open of the form.  District/Centre/Area/Batch all stay empty
  // until the user picks a parent, mirroring FLP / AK / MGJ behaviour.
  _wwwLoadStatesBasic();
  var fam = document.getElementById('wwwAtFamilyBody');
  if (fam && fam.children.length === 0) addWwwFamilyRow();
  var ref = document.getElementById('wwwAtRefBody');
  if (ref && ref.children.length === 0) addWwwReferenceRow();
  // Wire the GBV situations -> violence-tag auto-classifier.  Use
  // event delegation in case the panel is re-rendered.
  var sitWrap = document.getElementById('wwwAtSituations');
  if (sitWrap && !sitWrap._wwwBound) {
    sitWrap.addEventListener('change', _wwwRefreshViolenceTags);
    sitWrap._wwwBound = true;
  }
  _wwwRefreshViolenceTags();
}

// === WWW INDUCTION (Add + List) — 2026-06-15 ===
/**
 * WWW Add Induction page — State→Centre→Batch cascade, Go loads matching
 * trainees, pick one with the radio, fill Start/End dates, Save.
 * Backed by /api/www-inductions (GET list / POST create).
 */
var _WWW_IA_SELECTED_TRAINEE = null;

function loadWwwAddInduction() {
  _WWW_IA_SELECTED_TRAINEE = null;
  // Reset everything every time the page opens
  ['wwwIaCentre', 'wwwIaBatch'].forEach(function(id) {
    var sel = document.getElementById(id);
    if (!sel) return;
    var ph = id === 'wwwIaCentre' ? 'Select Centre' : 'Select Batch';
    sel.innerHTML = '<option value="">' + ph + '</option>';
    sel.disabled = true;
  });
  ['wwwIaStartDate', 'wwwIaEndDate'].forEach(function(id) {
    var el = document.getElementById(id); if (el) el.value = '';
  });
  var body = document.getElementById('wwwIaTraineesBody');
  if (body) body.innerHTML = '<tr><td colspan="6" class="ind-empty">No trainees yet — pick State/Centre/Batch and click Go.</td></tr>';
  var wrap = document.getElementById('wwwIaTrainees'); if (wrap) wrap.style.display = 'none';
  var hint = document.getElementById('wwwIaHint'); if (hint) hint.style.display = '';
  // Populate State dropdown
  apiGet('/www-master/dropdown/states')
    .then(function(rows) {
      var sel = document.getElementById('wwwIaState');
      if (!sel) return;
      sel.innerHTML = '<option value="">Select State</option>';
      (rows || []).forEach(function(r) {
        sel.innerHTML += '<option value="' + r.state_code + '">' + (r.state_name || r.state_code) + '</option>';
      });
    })
    .catch(function(err) { console.warn('WWW Ind/Add states load failed:', err); });
}

function onWwwIaStateChange() {
  var state = (document.getElementById('wwwIaState') || {}).value || '';
  var centreSel = document.getElementById('wwwIaCentre');
  var batchSel  = document.getElementById('wwwIaBatch');
  centreSel.innerHTML = '<option value="">Select Centre</option>';
  batchSel.innerHTML  = '<option value="">Select Batch</option>';
  centreSel.disabled = !state; batchSel.disabled = true;
  if (!state) return;
  apiGet('/www-master/dropdown/centres?state_code=' + encodeURIComponent(state))
    .then(function(rows) {
      (rows || []).forEach(function(r) {
        centreSel.innerHTML += '<option value="' + r.centre_code + '">' + (r.centre_name || r.centre_code) + '</option>';
      });
      centreSel.disabled = false;
    })
    .catch(function(err) { console.warn('WWW Ind/Add centres load failed:', err); });
}

function onWwwIaCentreChange() {
  var state  = (document.getElementById('wwwIaState')  || {}).value || '';
  var centre = (document.getElementById('wwwIaCentre') || {}).value || '';
  var batchSel = document.getElementById('wwwIaBatch');
  batchSel.innerHTML = '<option value="">Select Batch</option>';
  batchSel.disabled = !centre;
  if (!centre) return;
  apiGet('/www-master/dropdown/batches?state_code=' + encodeURIComponent(state) + '&centre_code=' + encodeURIComponent(centre))
    .then(function(rows) {
      (rows || []).forEach(function(r) {
        var label = (r.name || '') + (r.year ? ' (' + r.year + ')' : '');
        batchSel.innerHTML += '<option value="' + r.id + '">' + label + '</option>';
      });
      batchSel.disabled = false;
    })
    .catch(function(err) { console.warn('WWW Ind/Add batches load failed:', err); });
}

function goWwwIaSearch() {
  var state  = (document.getElementById('wwwIaState')  || {}).value || '';
  var centre = (document.getElementById('wwwIaCentre') || {}).value || '';
  var batch  = (document.getElementById('wwwIaBatch')  || {}).value || '';
  if (!state || !centre || !batch) { alert('Please select State, Centre and Batch first.'); return; }
  _WWW_IA_SELECTED_TRAINEE = null;
  var body = document.getElementById('wwwIaTraineesBody');
  var wrap = document.getElementById('wwwIaTrainees');
  var hint = document.getElementById('wwwIaHint');
  hint.style.display = 'none'; wrap.style.display = '';
  body.innerHTML = '<tr><td colspan="6" class="ind-empty">Loading trainees…</td></tr>';
  apiGet('/www-trainees?state_code=' + encodeURIComponent(state) +
         '&centre_code=' + encodeURIComponent(centre) +
         '&batch_id=' + encodeURIComponent(batch) + '&limit=200')
    .then(function(resp) {
      var rows = (resp && resp.data) || [];
      if (!rows.length) {
        body.innerHTML = '<tr><td colspan="6" class="ind-empty">No trainees found for that State / Centre / Batch.</td></tr>';
        return;
      }
      body.innerHTML = rows.map(function(r) {
        return '<tr>' +
          '<td><input type="radio" name="wwwIaPick" value="' + r.id + '" onchange="selectWwwIaTrainee(' + r.id + ')"></td>' +
          '<td>' + escHtml(r.enrollment_no || '') + '</td>' +
          '<td>' + escHtml(r.name || '') + '</td>' +
          '<td>' + escHtml(r.batch_name || (r.batch_id ? '#' + r.batch_id : '—')) + '</td>' +
          '<td>' + escHtml(r.mobile || '') + '</td>' +
          '<td>' + escHtml(r.enrollment_type || '') + '</td>' +
        '</tr>';
      }).join('');
    })
    .catch(function(err) {
      console.warn('WWW Ind/Add trainees load failed:', err);
      body.innerHTML = '<tr><td colspan="6" class="ind-empty">Failed to load trainees.</td></tr>';
    });
}

function selectWwwIaTrainee(id) { _WWW_IA_SELECTED_TRAINEE = id; }

function cancelWwwAddInduction() { navigateTo('wwwInductionList'); }

function saveWwwInduction() {
  var sd = (document.getElementById('wwwIaStartDate') || {}).value || '';
  var ed = (document.getElementById('wwwIaEndDate')   || {}).value || '';
  if (!_WWW_IA_SELECTED_TRAINEE) { alert('Please pick a trainee from the table.'); return; }
  if (!sd || !ed) { alert('Please enter Induction Start and End dates.'); return; }
  if (ed < sd)   { alert('End date must be on or after Start date.'); return; }
  apiPost('/www-inductions', { trainee_id: _WWW_IA_SELECTED_TRAINEE, start_date: sd, end_date: ed })
    .then(function(resp) {
      alert('Induction saved.');
      navigateTo('wwwInductionList');
    })
    .catch(function(err) { alert('Save failed: ' + (err && err.detail ? err.detail : err)); });
}

/* ---------- Induction LIST wiring ---------- */

function _wwwInFmtDate(d) {
  if (!d) return '';
  // Backend returns ISO YYYY-MM-DD; show DD-MM-YYYY
  var s = String(d);
  if (s.length >= 10 && s.charAt(4) === '-') {
    return s.substring(8,10) + '-' + s.substring(5,7) + '-' + s.substring(0,4);
  }
  return s;
}

function loadWwwInductionList() {
  // populate batch filter (no cascade — show all active batches)
  var batchSel = document.getElementById('wwwInFilterBatch');
  if (batchSel) {
    apiGet('/www-master/dropdown/batches').then(function(rows) {
      batchSel.innerHTML = '<option value="">All Batches</option>';
      (rows || []).forEach(function(r) {
        batchSel.innerHTML += '<option value="' + r.id + '">' + (r.name || '#' + r.id) + '</option>';
      });
    }).catch(function() {});
  }
  applyWwwInFilters();
}

function applyWwwInFilters() {
  var get = function(id) { var el = document.getElementById(id); return el ? el.value : ''; };
  var qs = [];
  if (get('wwwInFilterBatch'))    qs.push('batch_id=' + encodeURIComponent(get('wwwInFilterBatch')));
  if (get('wwwInFilterType'))     qs.push('enrollment_type=' + encodeURIComponent(get('wwwInFilterType')));
  if (get('wwwInFilterName'))     qs.push('name=' + encodeURIComponent(get('wwwInFilterName')));
  if (get('wwwInFilterDateFrom')) qs.push('date_from=' + get('wwwInFilterDateFrom'));
  if (get('wwwInFilterDateTo'))   qs.push('date_to='   + get('wwwInFilterDateTo'));
  var limit = parseInt(get('wwwInItemsPerPage') || '10', 10);
  qs.push('limit=' + limit);
  apiGet('/www-inductions' + (qs.length ? '?' + qs.join('&') : ''))
    .then(function(resp) {
      var rows = (resp && resp.data) || [];
      var tbody = document.getElementById('wwwInTableBody');
      var pag   = document.getElementById('wwwInPagination');
      if (!tbody) return;
      if (!rows.length) {
        tbody.innerHTML = '<tr><td colspan="8" style="text-align:center;color:#999;padding:30px;">No induction records yet. Click <b>Add Induction</b> to add one.</td></tr>';
        if (pag) pag.textContent = 'Showing 0 of 0';
        return;
      }
      tbody.innerHTML = rows.map(function(r) {
        return '<tr>' +
          '<td>' + escHtml(r.enrollment_no || '') + '</td>' +
          '<td>' + escHtml(r.name || '') + '</td>' +
          '<td>' + escHtml(r.batch_name || (r.batch_id ? '#' + r.batch_id : '—')) + '</td>' +
          '<td>' + escHtml(r.enrollment_type || '') + '</td>' +
          '<td>' + escHtml(r.mobile || '') + '</td>' +
          '<td>' + _wwwInFmtDate(r.start_date) + '</td>' +
          '<td>' + _wwwInFmtDate(r.end_date)   + '</td>' +
          '<td>' +
            '<button class="btn-icon" title="View"   onclick="viewWwwInduction('   + r.id + ')"><i class="far fa-eye"></i></button> ' +
            '<button class="btn-icon" title="Edit"   onclick="editWwwInduction('   + r.id + ')"><i class="fas fa-edit"></i></button> ' +
            '<button class="btn-icon" title="Delete" onclick="deleteWwwInduction(' + r.id + ')"><i class="fas fa-trash-alt"></i></button>' +
          '</td>' +
        '</tr>';
      }).join('');
      if (pag) pag.textContent = 'Showing ' + rows.length + ' of ' + rows.length;
    })
    .catch(function(err) {
      console.warn('WWW Induction list load failed:', err);
      var tbody = document.getElementById('wwwInTableBody');
      if (tbody) tbody.innerHTML = '<tr><td colspan="8" style="text-align:center;color:#c0392b;padding:30px;">Failed to load induction records.</td></tr>';
    });
}

function resetWwwInFilters() {
  ['wwwInFilterBatch','wwwInFilterType','wwwInFilterName','wwwInFilterDateFrom','wwwInFilterDateTo'].forEach(function(id) {
    var el = document.getElementById(id); if (el) el.value = '';
  });
  loadWwwInductionList();
}

function exportWwwInList() {
  // simple frontend CSV export of currently-visible rows
  var tbody = document.getElementById('wwwInTableBody');
  if (!tbody) return;
  var rows = tbody.querySelectorAll('tr');
  if (!rows.length) { alert('Nothing to export.'); return; }
  var lines = ['Enrollment No.,Name,Batch,Type of Enrollment,Mobile No.,Induction Start Date,Induction End Date'];
  rows.forEach(function(tr) {
    var cells = tr.querySelectorAll('td');
    if (cells.length < 7) return;
    var vals = [];
    for (var i = 0; i < 7; i++) { vals.push('"' + (cells[i].textContent || '').replace(/"/g, '""').trim() + '"'); }
    lines.push(vals.join(','));
  });
  var blob = new Blob([lines.join('\n')], { type: 'text/csv;charset=utf-8;' });
  var url = URL.createObjectURL(blob);
  var a = document.createElement('a');
  a.href = url; a.download = 'www_inductions.csv'; document.body.appendChild(a); a.click();
  setTimeout(function() { document.body.removeChild(a); URL.revokeObjectURL(url); }, 100);
}


function deleteWwwInduction(id) {
  if (!confirm('Delete this induction record?')) return;
  apiDelete('/www-inductions/' + id)
    .then(function() { loadWwwInductionList(); })
    .catch(function(err) { alert('Delete failed: ' + (err && err.detail ? err.detail : err)); });
}

// === WWW MASTER (State/District/Centre/Area/Batch) — 2026-06-15 ===
/**
 * WWW Master pages — read-only lists backed by /api/www-master/dropdown/*.
 * Each loadXxx function is also wired into the navigateTo hook so the
 * page populates whenever the user opens it.
 */
function _wwwMRow(cols) { return '<tr>' + cols.map(function(c){return '<td>'+c+'</td>';}).join('') + '</tr>'; }
function _wwwMBadge(status) {
  var s = (status || 'Active');
  var cls = (s === 'Active') ? 'badge-active' : 'badge-inactive';
  return '<span class="badge ' + cls + '">' + escHtml(s) + '</span>';
}
function _wwwMActions(label) {
  return '<button class="btn-icon" title="View"   onclick="wwwComingSoon(\'View ' + label + '\')"><i class="far fa-eye"></i></button> ' +
         '<button class="btn-icon" title="Edit"   onclick="wwwComingSoon(\'Edit ' + label + '\')"><i class="fas fa-edit"></i></button>';
}
function _wwwMFillStateSelect(elId, keepValue, includeAll) {
  return apiGet('/www-master/dropdown/states?include_inactive=1').then(function(rows) {
    var sel = document.getElementById(elId); if (!sel) return;
    var keep = keepValue || sel.value || '';
    sel.innerHTML = (includeAll === false ? '' : '<option value="">All States</option>');
    (rows || []).forEach(function(r) {
      sel.innerHTML += '<option value="' + r.state_code + '">' + escHtml(r.state_name || r.state_code) + '</option>';
    });
    if (keep) sel.value = keep;
  });
}

/* ---------- State Management ---------- */
function loadWwwStateManagement() {
  apiGet('/www-master/dropdown/states?include_inactive=1').then(function(rows) {
    var q = ((document.getElementById('wwwMStateSearch') || {}).value || '').toLowerCase().trim();
    var data = (rows || []).filter(function(r) { return !q || (r.state_name || '').toLowerCase().indexOf(q) >= 0; });
    var tbody = document.getElementById('wwwStateTableBody');
    var pag   = document.getElementById('wwwStatePagination');
    if (!data.length) { tbody.innerHTML = '<tr><td colspan="5" style="text-align:center;color:#999;padding:30px;">No states found.</td></tr>'; if (pag) pag.textContent = 'Showing 0 of 0'; return; }
    tbody.innerHTML = data.map(function(r, i) {
      return _wwwMRow([ i+1, escHtml(r.state_code), escHtml(r.state_name || ''), _wwwMBadge(r.status), _wwwMActions('State') ]);
    }).join('');
    if (pag) pag.textContent = 'Showing ' + data.length + ' of ' + data.length;
  }).catch(function() {});
}

/* ---------- District Management ---------- */
function loadWwwDistrictManagement() {
  _wwwMFillStateSelect('wwwMDistFilterState').then(function() {
    var st = (document.getElementById('wwwMDistFilterState') || {}).value || '';
    var url = '/www-master/dropdown/districts?include_inactive=1' + (st ? '&state_code=' + encodeURIComponent(st) : '');
    return apiGet(url);
  }).then(function(rows) {
    return _wwwMFillStateSelect('wwwMDistFilterState', null).then(function(){ return rows; });
  }).then(function(rows) {
    return apiGet('/www-master/dropdown/states?include_inactive=1').then(function(states) {
      var stMap = {}; (states || []).forEach(function(s) { stMap[s.state_code] = s.state_name; });
      var q = ((document.getElementById('wwwMDistSearch') || {}).value || '').toLowerCase().trim();
      var data = (rows || []).filter(function(r) { return !q || (r.district_name || '').toLowerCase().indexOf(q) >= 0; });
      var tbody = document.getElementById('wwwDistrictTableBody');
      var pag   = document.getElementById('wwwDistrictPagination');
      if (!data.length) { tbody.innerHTML = '<tr><td colspan="6" style="text-align:center;color:#999;padding:30px;">No districts found.</td></tr>'; if (pag) pag.textContent = 'Showing 0 of 0'; return; }
      tbody.innerHTML = data.map(function(r, i) {
        return _wwwMRow([ i+1, escHtml(r.district_code), escHtml(r.district_name || ''), escHtml(stMap[r.state_code] || r.state_code || ''), _wwwMBadge(r.status), _wwwMActions('District') ]);
      }).join('');
      if (pag) pag.textContent = 'Showing ' + data.length + ' of ' + data.length;
    });
  }).catch(function() {});
}

/* ---------- Centre Management ---------- */
function onWwwMCentreStateChange() {
  var st = (document.getElementById('wwwMCentreFilterState') || {}).value || '';
  var distSel = document.getElementById('wwwMCentreFilterDistrict');
  if (distSel) distSel.innerHTML = '<option value="">All Districts</option>';
  if (st) {
    apiGet('/www-master/dropdown/districts?include_inactive=1&state_code=' + encodeURIComponent(st)).then(function(rows) {
      (rows || []).forEach(function(r) { distSel.innerHTML += '<option value="' + r.district_code + '">' + escHtml(r.district_name || '') + '</option>'; });
    });
  }
  loadWwwCentreManagement();
}
function loadWwwCentreManagement() {
  _wwwMFillStateSelect('wwwMCentreFilterState');
  var st = (document.getElementById('wwwMCentreFilterState') || {}).value || '';
  var dt = (document.getElementById('wwwMCentreFilterDistrict') || {}).value || '';
  var qs = [];
  if (st) qs.push('state_code=' + encodeURIComponent(st));
  if (dt) qs.push('district_code=' + encodeURIComponent(dt));
  qs.push('include_inactive=1');
  apiGet('/www-master/dropdown/centres?' + qs.join('&')).then(function(rows) {
    return Promise.all([
      apiGet('/www-master/dropdown/states?include_inactive=1'),
      apiGet('/www-master/dropdown/districts?include_inactive=1')
    ]).then(function(refs) {
      var stMap = {}, dtMap = {};
      (refs[0] || []).forEach(function(s) { stMap[s.state_code] = s.state_name; });
      (refs[1] || []).forEach(function(d) { dtMap[d.district_code] = d.district_name; });
      var q = ((document.getElementById('wwwMCentreSearch') || {}).value || '').toLowerCase().trim();
      var data = (rows || []).filter(function(r) { return !q || (r.centre_name || '').toLowerCase().indexOf(q) >= 0; });
      var tbody = document.getElementById('wwwCentreTableBody');
      var pag   = document.getElementById('wwwCentrePagination');
      if (!data.length) { tbody.innerHTML = '<tr><td colspan="7" style="text-align:center;color:#999;padding:30px;">No centres found.</td></tr>'; if (pag) pag.textContent = 'Showing 0 of 0'; return; }
      tbody.innerHTML = data.map(function(r, i) {
        return _wwwMRow([ i+1, escHtml(r.centre_code), escHtml(r.centre_name || ''), escHtml(dtMap[r.district_code] || r.district_code || ''), escHtml(stMap[r.state_code] || r.state_code || ''), _wwwMBadge(r.status), _wwwMActions('Centre') ]);
      }).join('');
      if (pag) pag.textContent = 'Showing ' + data.length + ' of ' + data.length;
    });
  }).catch(function() {});
}

