function loadWwwBatchManagement() {
  _wwwMFillStateSelect('wwwMBatchFilterState');
  var st = (document.getElementById('wwwMBatchFilterState') || {}).value || '';
  var cc = (document.getElementById('wwwMBatchFilterCentre') || {}).value || '';
  var qs = ['include_inactive=1'];
  if (st) qs.push('state_code=' + encodeURIComponent(st));
  if (cc) qs.push('centre_code=' + encodeURIComponent(cc));
  apiGet('/www-master/dropdown/batches?' + qs.join('&')).then(function(rows) {
    return Promise.all([
      apiGet('/www-master/dropdown/states?include_inactive=1'),
      apiGet('/www-master/dropdown/centres?include_inactive=1')
    ]).then(function(refs) {
      var stMap = {}, ccMap = {};
      (refs[0] || []).forEach(function(s) { stMap[s.state_code] = s.state_name; });
      (refs[1] || []).forEach(function(c) { ccMap[c.centre_code] = c.centre_name; });
      var q = ((document.getElementById('wwwMBatchSearch') || {}).value || '').toLowerCase().trim();
      var data = (rows || []).filter(function(r) { return !q || (r.name || '').toLowerCase().indexOf(q) >= 0; });
      var tbody = document.getElementById('wwwBatchTableBody');
      var pag   = document.getElementById('wwwBatchPagination');
      if (!data.length) { tbody.innerHTML = '<tr><td colspan="7" style="text-align:center;color:#999;padding:30px;">No batches found.</td></tr>'; if (pag) pag.textContent = 'Showing 0 of 0'; return; }
      tbody.innerHTML = data.map(function(r, i) {
        return _wwwMRow([ i+1, escHtml(r.name || ''), escHtml(r.year || ''), escHtml(ccMap[r.centre_code] || r.centre_code || ''), escHtml(stMap[r.state_code] || r.state_code || ''), _wwwMBadge(r.status), _wwwMActions('Batch') ]);
      }).join('');
      if (pag) pag.textContent = 'Showing ' + data.length + ' of ' + data.length;
    });
  }).catch(function() {});
}

// === WWW INDUCTION view + edit — 2026-06-15 ===
var _WWW_IA_EDIT_ID = null;          // truthy means we're editing this id
var _WWW_VIEW_INDUCTION_ID = null;   // payload for the View page

function viewWwwInduction(id) {
  _WWW_VIEW_INDUCTION_ID = id;
  navigateTo('wwwViewInduction');
}

function editWwwInduction(id) {
  _WWW_IA_EDIT_ID = id;
  navigateTo('wwwAddInduction');
}

function editWwwInductionFromView() {
  if (_WWW_VIEW_INDUCTION_ID) editWwwInduction(_WWW_VIEW_INDUCTION_ID);
}

function loadWwwViewInduction() {
  var id = _WWW_VIEW_INDUCTION_ID;
  if (!id) { navigateTo('wwwInductionList'); return; }
  ['vWInEnrollmentNo','vWInName','vWInMobile','vWInBatch','vWInType','vWInLocation',
   'vWInStart','vWInEnd','vWInDuration','vWInCreated','vWInId'].forEach(function(eid) {
    var el = document.getElementById(eid); if (el) el.textContent = '…';
  });
  apiGet('/www-inductions/' + id)
    .then(function(r) {
      function set(eid, v) { var el = document.getElementById(eid); if (el) el.textContent = (v === null || v === undefined || v === '') ? '—' : v; }
      set('vWInEnrollmentNo', r.enrollment_no);
      set('vWInName',         r.name);
      set('vWInMobile',       r.mobile);
      set('vWInBatch',        r.batch_name || (r.batch_id ? '#' + r.batch_id : null));
      set('vWInType',         r.enrollment_type);
      var loc = '';
      if (r.centre_code) loc = r.centre_code;
      if (r.state_code)  loc = loc ? (loc + ', ' + r.state_code) : r.state_code;
      set('vWInLocation', loc || null);
      set('vWInStart',   _wwwInFmtDate(r.start_date));
      set('vWInEnd',     _wwwInFmtDate(r.end_date));
      // Duration (inclusive day count)
      try {
        if (r.start_date && r.end_date) {
          var s = new Date(r.start_date), e = new Date(r.end_date);
          var days = Math.round((e - s) / 86400000) + 1;
          set('vWInDuration', days + ' day' + (days === 1 ? '' : 's'));
        }
      } catch(e) {}
      set('vWInCreated', r.created_at ? String(r.created_at).substring(0, 19).replace('T', ' ') : null);
      set('vWInId', r.id);
    })
    .catch(function(err) {
      alert('Failed to load induction: ' + (err && err.detail ? err.detail : err));
      navigateTo('wwwInductionList');
    });
}

/**
 * loadWwwAddInduction is already defined earlier — but we override its
 * tail to detect edit mode (_WWW_IA_EDIT_ID set) and preload the
 * record.  We use a wrapper rather than editing the original function.
 */
var _origLoadWwwAddInduction = loadWwwAddInduction;
loadWwwAddInduction = function() {
  _origLoadWwwAddInduction();   // resets the form, populates State dropdown

  var banner   = document.getElementById('wwwIaEditBanner');
  var titleEl  = document.getElementById('wwwIaFormTitleText');
  var row      = document.querySelector('#page-wwwAddInduction .ind-row');
  var trWrap   = document.getElementById('wwwIaTrainees');
  var hint     = document.getElementById('wwwIaHint');
  var saveBtns = document.querySelectorAll('#page-wwwAddInduction .form-actions .btn-primary');

  if (_WWW_IA_EDIT_ID) {
    // Edit mode — hide cascade row + trainee table + hint; show banner.
    if (banner) banner.style.display = '';
    if (titleEl) titleEl.textContent = 'Edit Induction Details';
    if (row)    row.style.display    = 'none';
    if (trWrap) trWrap.style.display = 'none';
    if (hint)   hint.style.display   = 'none';
    if (saveBtns && saveBtns.length) {
      saveBtns[saveBtns.length - 1].innerHTML = '<i class="fas fa-save"></i> Update';
    }
    apiGet('/www-inductions/' + _WWW_IA_EDIT_ID)
      .then(function(r) {
        var nm  = document.getElementById('wwwIaEditTraineeName');  if (nm)  nm.textContent  = r.name || '—';
        var en  = document.getElementById('wwwIaEditEnrollment');   if (en)  en.textContent  = r.enrollment_no || '—';
        var sd  = document.getElementById('wwwIaStartDate');        if (sd)  sd.value = r.start_date || '';
        var ed  = document.getElementById('wwwIaEndDate');          if (ed)  ed.value = r.end_date   || '';
      })
      .catch(function(err) {
        alert('Failed to load induction for edit: ' + (err && err.detail ? err.detail : err));
        navigateTo('wwwInductionList');
      });
  } else {
    // Add mode — make sure UI is in pristine add state
    if (banner) banner.style.display = 'none';
    if (titleEl) titleEl.textContent = 'Add Induction Details';
    if (row)    row.style.display    = '';
    if (hint)   hint.style.display   = '';
    if (saveBtns && saveBtns.length) {
      saveBtns[saveBtns.length - 1].innerHTML = '<i class="fas fa-save"></i> Save';
    }
  }
};

// Wrap saveWwwInduction so it does PUT in edit mode + POST in add mode.
var _origSaveWwwInduction = saveWwwInduction;
saveWwwInduction = function() {
  if (!_WWW_IA_EDIT_ID) return _origSaveWwwInduction();
  var sd = (document.getElementById('wwwIaStartDate') || {}).value || '';
  var ed = (document.getElementById('wwwIaEndDate')   || {}).value || '';
  if (!sd || !ed) { alert('Please enter Induction Start and End dates.'); return; }
  if (ed < sd)    { alert('End date must be on or after Start date.'); return; }
  apiPut('/www-inductions/' + _WWW_IA_EDIT_ID, { start_date: sd, end_date: ed })
    .then(function() {
      alert('Induction updated.');
      _WWW_IA_EDIT_ID = null;
      navigateTo('wwwInductionList');
    })
    .catch(function(err) { alert('Update failed: ' + (err && err.detail ? err.detail : err)); });
};

// Cancel from Add Induction should also clear edit state.
var _origCancelWwwAddInduction = cancelWwwAddInduction;
cancelWwwAddInduction = function() {
  _WWW_IA_EDIT_ID = null;
  _origCancelWwwAddInduction();
};

// === WWW LEARNING LICENSE (List + Add) — 2026-06-15 ===
var _WWW_LLA_SELECTED_TRAINEE = null;
var _WWW_LLA_EDIT_ID          = null;
var _WWW_LLA_TRAINEES_RAW     = [];

/* ---------- LIST ---------- */
function loadWwwLLList() {
  // populate State dropdown
  apiGet('/www-master/dropdown/states').then(function(rows) {
    var sel = document.getElementById('wwwLLFilterState');
    if (!sel) return;
    sel.innerHTML = '<option value="">All States</option>';
    (rows || []).forEach(function(r) {
      sel.innerHTML += '<option value="' + r.state_code + '">' + escHtml(r.state_name || r.state_code) + '</option>';
    });
  }).catch(function() {});
  // populate Batch dropdown (all active batches)
  apiGet('/www-master/dropdown/batches').then(function(rows) {
    var sel = document.getElementById('wwwLLFilterBatch');
    if (!sel) return;
    sel.innerHTML = '<option value="">All Batches</option>';
    (rows || []).forEach(function(r) {
      sel.innerHTML += '<option value="' + r.id + '">' + escHtml(r.name || '#' + r.id) + '</option>';
    });
  }).catch(function() {});
  applyWwwLLFilters();
}

function onWwwLLListStateChange() {
  var st = (document.getElementById('wwwLLFilterState') || {}).value || '';
  var sel = document.getElementById('wwwLLFilterCentre');
  if (sel) sel.innerHTML = '<option value="">All Centres</option>';
  if (!st || !sel) return;
  apiGet('/www-master/dropdown/centres?state_code=' + encodeURIComponent(st)).then(function(rows) {
    (rows || []).forEach(function(r) {
      sel.innerHTML += '<option value="' + r.centre_code + '">' + escHtml(r.centre_name || r.centre_code) + '</option>';
    });
  }).catch(function() {});
}

function _wwwLLFmtDate(d) {
  if (!d) return '';
  var s = String(d);
  if (s.length >= 10 && s.charAt(4) === '-') {
    return s.substring(8,10) + '-' + s.substring(5,7) + '-' + s.substring(0,4);
  }
  return s;
}

function applyWwwLLFilters() {
  var get = function(id) { var el = document.getElementById(id); return el ? el.value : ''; };
  var qs = [];
  if (get('wwwLLFilterState'))    qs.push('state_code='      + encodeURIComponent(get('wwwLLFilterState')));
  if (get('wwwLLFilterCentre'))   qs.push('centre_code='     + encodeURIComponent(get('wwwLLFilterCentre')));
  if (get('wwwLLFilterBatch'))    qs.push('batch_id='        + encodeURIComponent(get('wwwLLFilterBatch')));
  if (get('wwwLLFilterType'))     qs.push('enrollment_type=' + encodeURIComponent(get('wwwLLFilterType')));
  if (get('wwwLLFilterDateFrom')) qs.push('date_from='       + get('wwwLLFilterDateFrom'));
  if (get('wwwLLFilterDateTo'))   qs.push('date_to='         + get('wwwLLFilterDateTo'));
  var limit = parseInt(get('wwwLLItemsPerPage') || '10', 10);
  qs.push('limit=' + limit);
  apiGet('/www-learning-licenses' + (qs.length ? '?' + qs.join('&') : ''))
    .then(function(resp) {
      var rows = (resp && resp.data) || [];
      var tbody = document.getElementById('wwwLLTableBody');
      var pag = document.getElementById('wwwLLPagination');
      if (!tbody) return;
      if (!rows.length) {
        tbody.innerHTML = '<tr><td colspan="9" style="text-align:center;color:#999;padding:30px;">No learning licenses yet. Click <b>Add LL</b> to add one.</td></tr>';
        if (pag) pag.textContent = 'Showing 0 of 0';
        return;
      }
      tbody.innerHTML = rows.map(function(r) {
        var loc = (r.centre_code || '') + (r.state_code ? ', ' + r.state_code : '');
        return '<tr>' +
          '<td>' + escHtml(r.enrollment_no || '') + '</td>' +
          '<td>' + escHtml(r.name || '') + '</td>' +
          '<td>' + escHtml(r.mobile || '') + '</td>' +
          '<td>' + escHtml(r.batch_name || (r.batch_id ? '#' + r.batch_id : '—')) + '</td>' +
          '<td>' + escHtml(loc) + '</td>' +
          '<td>' + escHtml(r.enrollment_type || '') + '</td>' +
          '<td>' + _wwwLLFmtDate(r.date_of_ll) + '</td>' +
          '<td><span class="badge badge-active">Active</span></td>' +
          '<td>' +
            '<button class="btn-icon" title="View" onclick="viewWwwLearningLicense(' + r.id + ')"><i class="far fa-eye"></i></button> ' +
            '<button class="btn-icon" title="Edit" onclick="editWwwLearningLicense(' + r.id + ')"><i class="fas fa-edit"></i></button> ' +
            '<button class="btn-icon" title="Add LL Renewed Details" onclick="openWwwLLRenewModal(' + r.id + ', \'' + escHtml(r.name || '') + '\', ' + (r.attempts_taken || 1) + ')"><i class="fas fa-plus-circle"></i></button>' +
          '</td>' +
        '</tr>';
      }).join('');
      if (pag) pag.textContent = 'Showing ' + rows.length + ' of ' + rows.length;
    })
    .catch(function(err) {
      console.warn('WWW LL list load failed:', err);
      var tbody = document.getElementById('wwwLLTableBody');
      if (tbody) tbody.innerHTML = '<tr><td colspan="9" style="text-align:center;color:#c0392b;padding:30px;">Failed to load learning licenses.</td></tr>';
    });
}

function resetWwwLLFilters() {
  ['wwwLLFilterState','wwwLLFilterCentre','wwwLLFilterBatch','wwwLLFilterType','wwwLLFilterDateFrom','wwwLLFilterDateTo'].forEach(function(id) {
    var el = document.getElementById(id); if (el) el.value = '';
  });
  var c = document.getElementById('wwwLLFilterCentre'); if (c) c.innerHTML = '<option value="">All Centres</option>';
  loadWwwLLList();
}

function exportWwwLLList() {
  var tbody = document.getElementById('wwwLLTableBody');
  if (!tbody) return;
  var rows = tbody.querySelectorAll('tr');
  if (!rows.length) { alert('Nothing to export.'); return; }
  var lines = ['Enrollment No.,Name,Mobile,Batch,Location,Type,Date Of LL,Status'];
  rows.forEach(function(tr) {
    var cells = tr.querySelectorAll('td');
    if (cells.length < 8) return;
    var vals = [];
    for (var i = 0; i < 8; i++) { vals.push('"' + (cells[i].textContent || '').replace(/"/g,'""').trim() + '"'); }
    lines.push(vals.join(','));
  });
  var blob = new Blob([lines.join('\n')], { type:'text/csv;charset=utf-8;' });
  var url = URL.createObjectURL(blob);
  var a = document.createElement('a');
  a.href = url; a.download = 'www_learning_licenses.csv'; document.body.appendChild(a); a.click();
  setTimeout(function(){ document.body.removeChild(a); URL.revokeObjectURL(url); }, 100);
}

function viewWwwLearningLicense(id) { _WWW_LL_VIEW_ID = id; navigateTo('wwwViewLL'); }
function editWwwLearningLicense(id) {
  _WWW_LL_EDIT_ID = id;
  navigateTo('wwwEditLL');
}
function deleteWwwLearningLicense(id) {
  if (!confirm('Delete this Learning License?')) return;
  apiDelete('/www-learning-licenses/' + id)
    .then(function() { loadWwwLLList(); })
    .catch(function(err) { alert('Delete failed: ' + (err && err.detail ? err.detail : err)); });
}

/* ---------- ADD ---------- */
function loadWwwAddLL() {
  _WWW_LLA_SELECTED_TRAINEE = null;
  _WWW_LLA_TRAINEES_RAW = [];
  ['wwwLLAState','wwwLLACentre','wwwLLATraineeFilter','wwwLLADate','wwwLLANumber',
   'wwwLLADuration','wwwLLAAttempts','wwwLLAStartDate','wwwLLAEndDate'].forEach(function(id) {
    var el = document.getElementById(id); if (el) el.value = '';
  });
  document.querySelectorAll('input[name="wwwLLAModuleDone"]').forEach(function(r) { r.checked = false; });
  var ce = document.getElementById('wwwLLACentre');     if (ce) { ce.innerHTML = '<option value="">Select Centre</option>'; ce.disabled = true; }
  var tb = document.getElementById('wwwLLATraineesBody'); if (tb) tb.innerHTML = '<tr><td colspan="7" class="ll-empty">No trainees yet — pick State and Centre above.</td></tr>';
  var tw = document.getElementById('wwwLLATrainees');   if (tw) tw.style.display = 'none';
  var hn = document.getElementById('wwwLLAHint');       if (hn) hn.style.display = '';

  // Edit-mode chrome
  var banner = document.getElementById('wwwLLAEditBanner');
  var title  = document.getElementById('wwwLLAFormTitleText');
  var stRow  = document.getElementById('wwwLLAStateCentreRow');
  var trFilt = document.getElementById('wwwLLATraineeFilterWrap');
  var saveTx = document.getElementById('wwwLLASaveText');

  if (_WWW_LLA_EDIT_ID) {
    if (banner) banner.style.display = '';
    if (title)  title.textContent = 'Edit Learning License';
    if (stRow)  stRow.style.display = 'none';
    if (trFilt) trFilt.style.display = 'none';
    if (tw)     tw.style.display = 'none';
    if (hn)     hn.style.display = 'none';
    if (saveTx) saveTx.textContent = 'Update';
    apiGet('/www-learning-licenses/' + _WWW_LLA_EDIT_ID).then(function(r) {
      _WWW_LLA_SELECTED_TRAINEE = r.trainee_id;
      var nm = document.getElementById('wwwLLAEditTraineeName'); if (nm) nm.textContent = r.name || '—';
      var en = document.getElementById('wwwLLAEditEnrollment');  if (en) en.textContent = r.enrollment_no || '—';
      document.getElementById('wwwLLADate').value      = r.date_of_ll        || '';
      document.getElementById('wwwLLANumber').value    = r.ll_number         || '';
      document.getElementById('wwwLLADuration').value  = (r.duration_days != null) ? r.duration_days : '';
      document.getElementById('wwwLLAAttempts').value  = (r.attempts_taken != null) ? r.attempts_taken : '';
      document.getElementById('wwwLLAStartDate').value = r.module_start_date || '';
      document.getElementById('wwwLLAEndDate').value   = r.module_end_date   || '';
      var radio = document.querySelector('input[name="wwwLLAModuleDone"][value="' + (r.module_done ? 'yes' : 'no') + '"]');
      if (radio) radio.checked = true;
    }).catch(function(err) {
      alert('Failed to load LL: ' + (err && err.detail ? err.detail : err));
      navigateTo('wwwLLList');
    });
    return;
  }

  // Add mode chrome
  if (banner) banner.style.display = 'none';
  if (title)  title.textContent = 'Add Learning License';
  if (stRow)  stRow.style.display = '';
  if (trFilt) trFilt.style.display = '';
  if (saveTx) saveTx.textContent = 'Save';
  apiGet('/www-master/dropdown/states').then(function(rows) {
    var sel = document.getElementById('wwwLLAState');
    if (!sel) return;
    sel.innerHTML = '<option value="">Select State</option>';
    (rows || []).forEach(function(r) {
      sel.innerHTML += '<option value="' + r.state_code + '">' + escHtml(r.state_name || r.state_code) + '</option>';
    });
  }).catch(function() {});
}

function onWwwLLAStateChange() {
  var st = (document.getElementById('wwwLLAState') || {}).value || '';
  var ce = document.getElementById('wwwLLACentre');
  if (ce) { ce.innerHTML = '<option value="">Select Centre</option>'; ce.disabled = !st; }
  _wwwLLAResetTrainees();
  if (!st) return;
  apiGet('/www-master/dropdown/centres?state_code=' + encodeURIComponent(st)).then(function(rows) {
    (rows || []).forEach(function(r) {
      ce.innerHTML += '<option value="' + r.centre_code + '">' + escHtml(r.centre_name || r.centre_code) + '</option>';
    });
    ce.disabled = false;
  }).catch(function() {});
}

function onWwwLLACentreChange() {
  _wwwLLAResetTrainees();
  var st = (document.getElementById('wwwLLAState')  || {}).value || '';
  var ce = (document.getElementById('wwwLLACentre') || {}).value || '';
  if (!st || !ce) return;
  var body = document.getElementById('wwwLLATraineesBody');
  var wrap = document.getElementById('wwwLLATrainees');
  var hint = document.getElementById('wwwLLAHint');
  if (hint) hint.style.display = 'none';
  if (wrap) wrap.style.display = '';
  if (body) body.innerHTML = '<tr><td colspan="7" class="ll-empty">Loading trainees...</td></tr>';
  apiGet('/www-trainees?state_code=' + encodeURIComponent(st) +
         '&centre_code=' + encodeURIComponent(ce) + '&limit=500')
    .then(function(resp) {
      _WWW_LLA_TRAINEES_RAW = (resp && resp.data) || [];
      _renderWwwLLATrainees();
    })
    .catch(function() { if (body) body.innerHTML = '<tr><td colspan="7" class="ll-empty">Failed to load trainees.</td></tr>'; });
}

function _wwwLLAResetTrainees() {
  _WWW_LLA_SELECTED_TRAINEE = null;
  _WWW_LLA_TRAINEES_RAW = [];
  var body = document.getElementById('wwwLLATraineesBody');
  var wrap = document.getElementById('wwwLLATrainees');
  var hint = document.getElementById('wwwLLAHint');
  if (body) body.innerHTML = '<tr><td colspan="7" class="ll-empty">No trainees yet — pick State and Centre above.</td></tr>';
  if (wrap) wrap.style.display = 'none';
  if (hint) hint.style.display = '';
}

function filterWwwLLATrainees() { _renderWwwLLATrainees(); }

function _renderWwwLLATrainees() {
  var body = document.getElementById('wwwLLATraineesBody');
  if (!body) return;
  var q = ((document.getElementById('wwwLLATraineeFilter') || {}).value || '').toLowerCase().trim();
  var rows = _WWW_LLA_TRAINEES_RAW.filter(function(r) { return !q || (r.name || '').toLowerCase().indexOf(q) >= 0; });
  if (!rows.length) {
    body.innerHTML = '<tr><td colspan="7" class="ll-empty">No trainees match.</td></tr>';
    return;
  }
  body.innerHTML = rows.map(function(r) {
    var loc = (r.centre_code || '') + (r.state_code ? ', ' + r.state_code : '');
    return '<tr>' +
      '<td><input type="radio" name="wwwLLAPick" value="' + r.id + '" onchange="selectWwwLLATrainee(' + r.id + ')"' + (_WWW_LLA_SELECTED_TRAINEE === r.id ? ' checked' : '') + '></td>' +
      '<td>' + escHtml(r.enrollment_no || '') + '</td>' +
      '<td>' + escHtml(r.name || '') + '</td>' +
      '<td>' + escHtml(r.batch_name || (r.batch_id ? '#' + r.batch_id : '—')) + '</td>' +
      '<td>' + escHtml(r.mobile || '') + '</td>' +
      '<td>' + escHtml(loc) + '</td>' +
      '<td><span class="badge badge-active">Active</span></td>' +
    '</tr>';
  }).join('');
}

function selectWwwLLATrainee(id) { _WWW_LLA_SELECTED_TRAINEE = id; }

function _wwwLLAAutoCalcDuration() {
  var s = (document.getElementById('wwwLLAStartDate') || {}).value || '';
  var e = (document.getElementById('wwwLLAEndDate')   || {}).value || '';
  var out = document.getElementById('wwwLLADuration');
  if (!out) return;
  if (s && e && e >= s) {
    var sd = new Date(s), ed = new Date(e);
    var days = Math.round((ed - sd) / 86400000) + 1;
    out.value = days;
  } else {
    out.value = '';
  }
}

function saveWwwLearningLicense() {
  var date_of_ll = (document.getElementById('wwwLLADate')     || {}).value || '';
  var ll_number  = (document.getElementById('wwwLLANumber')   || {}).value.trim();
  var attempts   = (document.getElementById('wwwLLAAttempts') || {}).value || '';
  var sd         = (document.getElementById('wwwLLAStartDate')|| {}).value || '';
  var ed         = (document.getElementById('wwwLLAEndDate')  || {}).value || '';
  var duration   = (document.getElementById('wwwLLADuration') || {}).value || '';
  var mdone_el   = document.querySelector('input[name="wwwLLAModuleDone"]:checked');
  var module_done = mdone_el ? (mdone_el.value === 'yes') : null;

  if (!_WWW_LLA_EDIT_ID && !_WWW_LLA_SELECTED_TRAINEE) { alert('Please pick a trainee from the table.'); return; }
  if (!date_of_ll) { alert('Please enter Date of LL.'); return; }
  if (!ll_number)  { alert('Please enter LL Number.'); return; }
  if (attempts === '' || isNaN(parseInt(attempts, 10)) || parseInt(attempts, 10) < 1) { alert('Please enter Attempts taken to clear LL.'); return; }
  if (module_done === null) { alert('Please answer "Is the Learners Module done?".'); return; }
  if (!sd || !ed) { alert('Please enter Learner\'s Module Start and End dates.'); return; }
  if (ed < sd) { alert('Module End Date must be on or after Start Date.'); return; }

  var payload = {
    date_of_ll: date_of_ll,
    ll_number: ll_number,
    duration_days: parseInt(duration || '0', 10) || null,
    attempts_taken: parseInt(attempts, 10),
    module_done: module_done,
    module_start_date: sd,
    module_end_date: ed
  };
  if (_WWW_LLA_EDIT_ID) {
    apiPut('/www-learning-licenses/' + _WWW_LLA_EDIT_ID, payload)
      .then(function() { alert('Learning License updated.'); _WWW_LLA_EDIT_ID = null; navigateTo('wwwLLList'); })
      .catch(function(err) { alert('Update failed: ' + (err && err.detail ? err.detail : err)); });
  } else {
    payload.trainee_id = _WWW_LLA_SELECTED_TRAINEE;
    apiPost('/www-learning-licenses', payload)
      .then(function() { alert('Learning License saved.'); navigateTo('wwwLLList'); })
      .catch(function(err) { alert('Save failed: ' + (err && err.detail ? err.detail : err)); });
  }
}

// === WWW LL View + Edit + Renewal — 2026-06-15 ===
var _WWW_LL_VIEW_ID  = null;
var _WWW_LL_EDIT_ID  = null;
var _WWW_LL_RENEW_ID = null;
var _WWW_LL_RENEW_ATTEMPTS_DEFAULT = 1;

/* ---------- VIEW page ---------- */
function loadWwwViewLL() {
  var id = _WWW_LL_VIEW_ID;
  if (!id) { navigateTo('wwwLLList'); return; }
  // Reset all spans to placeholders.
  ['vWLLBreadcrumbName','vWLLProfileName','vWLLProfileEnrollment',
   'vWLLName','vWLLMobile','vWLLBatch','vWLLState','vWLLCentre','vWLLType',
   'vWLLDate','vWLLNumber','vWLLDuration','vWLLAttempts',
   'vWLLModuleDone','vWLLModuleEnd','vWLLModuleStart'].forEach(function(eid) {
    var el = document.getElementById(eid); if (el) el.textContent = '…';
  });
  document.getElementById('vWLLRenewalsWrap').innerHTML = '<div class="vll-renewal-empty">Loading renewals…</div>';

  function set(eid, v) { var el = document.getElementById(eid); if (el) el.textContent = (v === null || v === undefined || v === '') ? '—' : v; }

  apiGet('/www-learning-licenses/' + id).then(function(r) {
    set('vWLLBreadcrumbName', r.name);
    set('vWLLProfileName',    r.name);
    set('vWLLProfileEnrollment', r.enrollment_no);
    set('vWLLName',           r.name);
    set('vWLLMobile',         r.mobile);
    set('vWLLBatch',          r.batch_name || (r.batch_id ? '#' + r.batch_id : null));
    // For State and Centre we resolve names from the masters if available;
    // fall back to codes.
    set('vWLLState',          r.state_code);
    set('vWLLCentre',         r.centre_code);
    set('vWLLType',           r.enrollment_type);
    set('vWLLDate',           _wwwLLFmtDate(r.date_of_ll));
    set('vWLLNumber',         r.ll_number);
    set('vWLLDuration',       r.duration_days);
    set('vWLLAttempts',       r.attempts_taken);
    set('vWLLModuleDone',     r.module_done ? 'Yes' : 'No');
    set('vWLLModuleEnd',      _wwwLLFmtDate(r.module_end_date));
    set('vWLLModuleStart',    _wwwLLFmtDate(r.module_start_date));

    // Resolve State/Centre names asynchronously (best-effort).
    if (r.state_code) {
      apiGet('/www-master/dropdown/states').then(function(rows) {
        var row = (rows || []).filter(function(x) { return x.state_code === r.state_code; })[0];
        if (row && row.state_name) set('vWLLState', row.state_name);
      }).catch(function() {});
    }
    if (r.centre_code) {
      apiGet('/www-master/dropdown/centres?state_code=' + encodeURIComponent(r.state_code || '')).then(function(rows) {
        var row = (rows || []).filter(function(x) { return x.centre_code === r.centre_code; })[0];
        if (row && row.centre_name) set('vWLLCentre', row.centre_name);
      }).catch(function() {});
    }
  }).catch(function(err) {
    alert('Failed to load LL: ' + (err && err.detail ? err.detail : err));
    navigateTo('wwwLLList');
  });

  apiGet('/www-learning-licenses/' + id + '/renewals').then(function(resp) {
    var rows = (resp && resp.data) || [];
    var wrap = document.getElementById('vWLLRenewalsWrap');
    if (!rows.length) {
      wrap.innerHTML = '<div class="vll-renewal-empty">No renewals yet. Use the <b>+</b> icon in the list to add one.</div>';
      return;
    }
    // Render in chronological order (oldest first)
    rows = rows.slice().reverse();
    wrap.innerHTML = rows.map(function(r, i) {
      return (rows.length > 1 ? ('<div class="vll-renewal-num">Renewal #' + (i+1) + '</div>') : '') +
        '<div class="vll-renewal-block">' +
          '<div class="vll-grid g3">' +
            '<div class="vll-item"><label>Date of Renewed of LL</label><span>' + _wwwLLFmtDate(r.renewal_date) + '</span></div>' +
            '<div class="vll-item"><label>New LL Number</label><span>' + escHtml(r.new_ll_number || '') + '</span></div>' +
            '<div class="vll-item"><label>Attempts taken to clear LL</label><span>' + (r.attempts_taken != null ? r.attempts_taken : '—') + '</span></div>' +
          '</div>' +
        '</div>';
    }).join('');
  }).catch(function() {
    document.getElementById('vWLLRenewalsWrap').innerHTML = '<div class="vll-renewal-empty" style="color:#c0392b;">Failed to load renewals.</div>';
  });
}

function printWwwViewLL() { window.print(); }

function editWwwLearningLicenseFromView() {
  if (_WWW_LL_VIEW_ID) editWwwLearningLicense(_WWW_LL_VIEW_ID);
}

/* ---------- EDIT page (dedicated) ---------- */
function loadWwwEditLL() {
  var id = _WWW_LL_EDIT_ID;
  if (!id) { navigateTo('wwwLLList'); return; }
  ['wwwLLEDate','wwwLLENumber','wwwLLEDuration','wwwLLEAttempts','wwwLLEStartDate','wwwLLEEndDate'].forEach(function(eid) {
    var el = document.getElementById(eid); if (el) el.value = '';
  });
  document.querySelectorAll('input[name="wwwLLEModuleDone"]').forEach(function(r) { r.checked = false; });
  apiGet('/www-learning-licenses/' + id).then(function(r) {
    document.getElementById('wwwLLEName').textContent       = r.name || '—';
    document.getElementById('wwwLLEEnrollment').textContent = r.enrollment_no || '—';
    document.getElementById('wwwLLEDate').value      = r.date_of_ll        || '';
    document.getElementById('wwwLLENumber').value    = r.ll_number         || '';
    document.getElementById('wwwLLEDuration').value  = (r.duration_days != null) ? r.duration_days : '';
    document.getElementById('wwwLLEAttempts').value  = (r.attempts_taken != null) ? r.attempts_taken : '';
    document.getElementById('wwwLLEStartDate').value = r.module_start_date || '';
    document.getElementById('wwwLLEEndDate').value   = r.module_end_date   || '';
    var radio = document.querySelector('input[name="wwwLLEModuleDone"][value="' + (r.module_done ? 'yes' : 'no') + '"]');
    if (radio) radio.checked = true;
  }).catch(function(err) {
    alert('Failed to load LL for edit: ' + (err && err.detail ? err.detail : err));
    navigateTo('wwwLLList');
  });
}

function _wwwLLEAutoCalcDuration() {
  var s = (document.getElementById('wwwLLEStartDate') || {}).value || '';
  var e = (document.getElementById('wwwLLEEndDate')   || {}).value || '';
  var out = document.getElementById('wwwLLEDuration');
  if (!out) return;
  if (s && e && e >= s) {
    var sd = new Date(s), ed = new Date(e);
    out.value = Math.round((ed - sd) / 86400000) + 1;
  } else {
    out.value = '';
  }
}

function saveEditWwwLearningLicense() {
  var id = _WWW_LL_EDIT_ID;
  if (!id) { navigateTo('wwwLLList'); return; }
  var date_of_ll = (document.getElementById('wwwLLEDate')      || {}).value || '';
  var ll_number  = (document.getElementById('wwwLLENumber')    || {}).value.trim();
  var duration   = (document.getElementById('wwwLLEDuration')  || {}).value || '';
  var attempts   = (document.getElementById('wwwLLEAttempts')  || {}).value || '';
  var sd         = (document.getElementById('wwwLLEStartDate') || {}).value || '';
  var ed         = (document.getElementById('wwwLLEEndDate')   || {}).value || '';
  var mdone_el   = document.querySelector('input[name="wwwLLEModuleDone"]:checked');
  var module_done = mdone_el ? (mdone_el.value === 'yes') : null;
  if (!date_of_ll) { alert('Please enter Date of LL.'); return; }
  if (!ll_number)  { alert('Please enter LL Number.'); return; }
  if (attempts === '' || isNaN(parseInt(attempts, 10)) || parseInt(attempts, 10) < 1) { alert('Please enter Attempts taken.'); return; }
  if (module_done === null) { alert('Please answer "Is the Learners Module done?".'); return; }
  if (!sd || !ed) { alert('Please enter Module Start and End dates.'); return; }
  if (ed < sd) { alert('Module End Date must be on or after Start Date.'); return; }
  apiPut('/www-learning-licenses/' + id, {
    date_of_ll: date_of_ll, ll_number: ll_number,
    duration_days: parseInt(duration || '0', 10) || null,
    attempts_taken: parseInt(attempts, 10),
    module_done: module_done,
    module_start_date: sd, module_end_date: ed
  })
  .then(function() { alert('Learning License updated.'); _WWW_LL_EDIT_ID = null; navigateTo('wwwLLList'); })
  .catch(function(err) { alert('Update failed: ' + (err && err.detail ? err.detail : err)); });
}

/* ---------- RENEWAL MODAL ---------- */
function openWwwLLRenewModal(llId, traineeName, priorAttempts) {
  _WWW_LL_RENEW_ID = llId;
  _WWW_LL_RENEW_ATTEMPTS_DEFAULT = parseInt(priorAttempts || 1, 10) || 1;
  document.getElementById('wwwLLRenewForId').textContent   = llId;
  document.getElementById('wwwLLRenewForName').textContent = traineeName || '—';
  document.getElementById('wwwLLRenewDate').value     = '';
  document.getElementById('wwwLLRenewNumber').value   = '';
  document.getElementById('wwwLLRenewAttempts').value = _WWW_LL_RENEW_ATTEMPTS_DEFAULT;
  var m = document.getElementById('wwwLLRenewModal');
  if (m) m.style.display = 'flex';
}

function closeWwwLLRenewModal() {
  var m = document.getElementById('wwwLLRenewModal');
  if (m) m.style.display = 'none';
  _WWW_LL_RENEW_ID = null;
}

function saveWwwLLRenewal() {
  if (!_WWW_LL_RENEW_ID) return;
  var date = (document.getElementById('wwwLLRenewDate')     || {}).value || '';
  var num  = (document.getElementById('wwwLLRenewNumber')   || {}).value.trim();
  var att  = (document.getElementById('wwwLLRenewAttempts') || {}).value || '';
  if (!date) { alert('Please enter Date of Renewal Of LL.'); return; }
  if (!num)  { alert('Please enter New LL Number.'); return; }
  if (att === '' || isNaN(parseInt(att, 10)) || parseInt(att, 10) < 1) { alert('Please enter Number of attempts.'); return; }
  apiPost('/www-learning-licenses/' + _WWW_LL_RENEW_ID + '/renewals',
          { renewal_date: date, new_ll_number: num, attempts_taken: parseInt(att, 10) })
    .then(function() {
      alert('Renewal saved.');
      closeWwwLLRenewModal();
      if (typeof loadWwwLLList === 'function') loadWwwLLList();
    })
    .catch(function(err) { alert('Save failed: ' + (err && err.detail ? err.detail : err)); });
}

// === WWW DRIVING PRACTICE (List + Add) — 2026-06-15 ===
var _WWW_DPA_SELECTED_TRAINEE = null;
var _WWW_DPA_EDIT_ID = null;

function _wwwDPFmtDate(d) {
  if (!d) return '';
  var s = String(d);
  if (s.length >= 10 && s.charAt(4) === '-') {
    return s.substring(8,10) + '-' + s.substring(5,7) + '-' + s.substring(2,4);
  }
  return s;
}
function _wwwDPFmtRange(s, e) {
  if (!s && !e) return '—';
  return _wwwDPFmtDate(s) + ' -- ' + _wwwDPFmtDate(e);
}

/* ---------- LIST ---------- */
function loadWwwDPList() {
  apiGet('/www-master/dropdown/batches').then(function(rows) {
    var sel = document.getElementById('wwwDPFilterBatch'); if (!sel) return;
    sel.innerHTML = '<option value="">All Batches</option>';
    (rows || []).forEach(function(r) {
      sel.innerHTML += '<option value="' + r.id + '">' + escHtml(r.name || '#' + r.id) + '</option>';
    });
  }).catch(function() {});
  applyWwwDPFilters();
}

function applyWwwDPFilters() {
  var get = function(id) { var el = document.getElementById(id); return el ? el.value : ''; };
  var qs = [];
  if (get('wwwDPFilterBatch'))    qs.push('batch_id=' + encodeURIComponent(get('wwwDPFilterBatch')));
  if (get('wwwDPFilterName'))     qs.push('name='     + encodeURIComponent(get('wwwDPFilterName')));
  if (get('wwwDPFilterDateFrom')) qs.push('date_from=' + get('wwwDPFilterDateFrom'));
  if (get('wwwDPFilterDateTo'))   qs.push('date_to='   + get('wwwDPFilterDateTo'));
  qs.push('limit=' + parseInt(get('wwwDPItemsPerPage') || '10', 10));
  apiGet('/www-driving-practices' + (qs.length ? '?' + qs.join('&') : ''))
    .then(function(resp) {
      var rows = (resp && resp.data) || [];
      var tbody = document.getElementById('wwwDPTableBody');
      var pag = document.getElementById('wwwDPPagination');
      if (!tbody) return;
      if (!rows.length) {
        tbody.innerHTML = '<tr><td colspan="7" style="text-align:center;color:#999;padding:30px;">No practice records yet. Click <b>ADD Practice Details</b> to add one.</td></tr>';
        if (pag) pag.textContent = 'Showing 0 of 0';
        return;
      }
      tbody.innerHTML = rows.map(function(r) {
        return '<tr>' +
          '<td>' + escHtml(r.enrollment_no || '') + '</td>' +
          '<td>' + escHtml(r.name || '') + '</td>' +
          '<td>' + escHtml(r.batch_name || (r.batch_id ? '#' + r.batch_id : '—')) + '</td>' +
          '<td>' + escHtml(r.mobile || '') + '</td>' +
          '<td>' + _wwwDPFmtRange(r.ds_start_date, r.ds_end_date) + '</td>' +
          '<td>' + _wwwDPFmtRange(r.onground_start_date, r.onground_end_date) + '</td>' +
          '<td>' +
            '<button class="btn-icon" title="View"   onclick="viewWwwDrivingPractice('   + r.id + ')"><i class="far fa-eye"></i></button> ' +
            '<button class="btn-icon" title="Edit"   onclick="editWwwDrivingPractice('   + r.id + ')"><i class="fas fa-edit"></i></button> ' +
            '<button class="btn-icon" title="Delete" onclick="deleteWwwDrivingPractice(' + r.id + ')"><i class="fas fa-trash-alt"></i></button>' +
          '</td>' +
        '</tr>';
      }).join('');
      if (pag) pag.textContent = 'Showing ' + rows.length + ' of ' + rows.length;
    })
    .catch(function() {
      var tbody = document.getElementById('wwwDPTableBody');
      if (tbody) tbody.innerHTML = '<tr><td colspan="7" style="text-align:center;color:#c0392b;padding:30px;">Failed to load practice records.</td></tr>';
    });
}

function resetWwwDPFilters() {
  ['wwwDPFilterBatch','wwwDPFilterName','wwwDPFilterDateFrom','wwwDPFilterDateTo'].forEach(function(id) {
    var el = document.getElementById(id); if (el) el.value = '';
  });
  loadWwwDPList();
}

function exportWwwDPList() {
  var tbody = document.getElementById('wwwDPTableBody');
  if (!tbody) return;
  var rows = tbody.querySelectorAll('tr');
  if (!rows.length) { alert('Nothing to export.'); return; }
  var lines = ['Enrollment No.,Name,Batch,Mobile No.,Driving School Date,Onground Practice Date'];
  rows.forEach(function(tr) {
    var cells = tr.querySelectorAll('td');
    if (cells.length < 6) return;
    var vals = [];
    for (var i = 0; i < 6; i++) { vals.push('"' + (cells[i].textContent || '').replace(/"/g,'""').trim() + '"'); }
    lines.push(vals.join(','));
  });
  var blob = new Blob([lines.join('\n')], { type:'text/csv;charset=utf-8;' });
  var url = URL.createObjectURL(blob);
  var a = document.createElement('a');
  a.href = url; a.download = 'www_driving_practices.csv';
  document.body.appendChild(a); a.click();
  setTimeout(function(){ document.body.removeChild(a); URL.revokeObjectURL(url); }, 100);
}

function viewWwwDrivingPractice(id) { _WWW_DP_VIEW_ID = id; navigateTo('wwwViewDP'); }
function editWwwDrivingPractice(id) {
  _WWW_DP_EDIT_ID = id;
  navigateTo('wwwEditDP');
}
function deleteWwwDrivingPractice(id) {
  if (!confirm('Delete this practice record?')) return;
  apiDelete('/www-driving-practices/' + id)
    .then(function() { loadWwwDPList(); })
    .catch(function(err) { alert('Delete failed: ' + (err && err.detail ? err.detail : err)); });
}

