  // Edit-mode chrome
  var banner = document.getElementById('wwwDPAEditBanner');
  var title  = document.getElementById('wwwDPAFormTitleText');
  var stRow  = document.getElementById('wwwDPAStateCentreRow');
  var saveTx = document.getElementById('wwwDPASaveText');

  if (_WWW_DPA_EDIT_ID) {
    if (banner) banner.style.display = '';
    if (title)  title.textContent = 'Edit Practice Details';
    if (stRow)  stRow.style.display = 'none';
    if (wrap)   wrap.style.display = 'none';
    if (hint)   hint.style.display = 'none';
    if (saveTx) saveTx.textContent = 'Update';
    apiGet('/www-driving-practices/' + _WWW_DPA_EDIT_ID).then(function(r) {
      _WWW_DPA_SELECTED_TRAINEE = r.trainee_id;
      document.getElementById('wwwDPAEditName').textContent       = r.name || '—';
      document.getElementById('wwwDPAEditEnrollment').textContent = r.enrollment_no || '—';
      document.getElementById('wwwDPADsStart').value = r.ds_start_date       || '';
      document.getElementById('wwwDPADsEnd').value   = r.ds_end_date         || '';
      document.getElementById('wwwDPAOgStart').value = r.onground_start_date || '';
      document.getElementById('wwwDPAOgEnd').value   = r.onground_end_date   || '';
    }).catch(function(err) {
      alert('Failed to load practice: ' + (err && err.detail ? err.detail : err));
      navigateTo('wwwDPList');
    });
    return;
  }

  if (banner) banner.style.display = 'none';
  if (title)  title.textContent = 'Add Practice Details';
  if (stRow)  stRow.style.display = '';
  if (hint)   hint.style.display = '';
  if (saveTx) saveTx.textContent = 'Save';
  apiGet('/www-master/dropdown/states').then(function(rows) {
    var sel = document.getElementById('wwwDPAState'); if (!sel) return;
    sel.innerHTML = '<option value="">Select State</option>';
    (rows || []).forEach(function(r) {
      sel.innerHTML += '<option value="' + r.state_code + '">' + escHtml(r.state_name || r.state_code) + '</option>';
    });
  }).catch(function() {});
