// === WWW DP View — 2026-06-15 ===
var _WWW_DP_VIEW_ID = null;

function _wwwDPFmtDateLong(d) {
  if (!d) return '';
  var s = String(d);
  if (s.length >= 10 && s.charAt(4) === '-') {
    return s.substring(8,10) + '-' + s.substring(5,7) + '-' + s.substring(0,4);
  }
  return s;
}
function _wwwDPDurationDays(s, e) {
  if (!s || !e) return '';
  try {
    var sd = new Date(s), ed = new Date(e);
    if (isNaN(sd) || isNaN(ed) || ed < sd) return '';
    var days = Math.round((ed - sd) / 86400000) + 1;
    return days + ' day' + (days === 1 ? '' : 's');
  } catch (err) { return ''; }
}

function loadWwwViewDP() {
  var id = _WWW_DP_VIEW_ID;
  if (!id) { navigateTo('wwwDPList'); return; }
  ['vWDPBreadcrumbName','vWDPProfileName','vWDPProfileEnrollment',
   'vWDPName','vWDPMobile','vWDPBatch','vWDPState','vWDPCentre','vWDPType',
   'vWDPDsStart','vWDPDsEnd','vWDPDsDuration',
   'vWDPOgStart','vWDPOgEnd','vWDPOgDuration',
   'vWDPCreated','vWDPId'].forEach(function(eid) {
    var el = document.getElementById(eid); if (el) el.textContent = '…';
  });
  function set(eid, v) { var el = document.getElementById(eid); if (el) el.textContent = (v === null || v === undefined || v === '') ? '—' : v; }

  apiGet('/www-driving-practices/' + id).then(function(r) {
    set('vWDPBreadcrumbName',    r.name);
    set('vWDPProfileName',       r.name);
    set('vWDPProfileEnrollment', r.enrollment_no);
    set('vWDPName',              r.name);
    set('vWDPMobile',            r.mobile);
    set('vWDPBatch',             r.batch_name || (r.batch_id ? '#' + r.batch_id : null));
    set('vWDPState',             r.state_code);
    set('vWDPCentre',            r.centre_code);
    set('vWDPType',              r.enrollment_type);
    set('vWDPDsStart',           _wwwDPFmtDateLong(r.ds_start_date));
    set('vWDPDsEnd',             _wwwDPFmtDateLong(r.ds_end_date));
    set('vWDPDsDuration',        _wwwDPDurationDays(r.ds_start_date, r.ds_end_date));
    set('vWDPOgStart',           _wwwDPFmtDateLong(r.onground_start_date));
    set('vWDPOgEnd',             _wwwDPFmtDateLong(r.onground_end_date));
    set('vWDPOgDuration',        _wwwDPDurationDays(r.onground_start_date, r.onground_end_date));
    set('vWDPCreated',           r.created_at ? String(r.created_at).substring(0,19).replace('T', ' ') : null);
    set('vWDPId',                r.id);

    // Resolve State/Centre names best-effort.
    if (r.state_code) {
      apiGet('/www-master/dropdown/states').then(function(rows) {
        var row = (rows || []).filter(function(x) { return x.state_code === r.state_code; })[0];
        if (row && row.state_name) set('vWDPState', row.state_name);
      }).catch(function() {});
    }
    if (r.centre_code) {
      apiGet('/www-master/dropdown/centres?state_code=' + encodeURIComponent(r.state_code || '')).then(function(rows) {
        var row = (rows || []).filter(function(x) { return x.centre_code === r.centre_code; })[0];
        if (row && row.centre_name) set('vWDPCentre', row.centre_name);
      }).catch(function() {});
    }
  }).catch(function(err) {
    alert('Failed to load practice: ' + (err && err.detail ? err.detail : err));
    navigateTo('wwwDPList');
  });
}

