/* =====================  NON-TECHNICAL TRAINING  ===================== */
var _WWW_NT_EDIT_ID  = null;
var _WWW_NT_ATT_TRAINING = null;
var _WWW_NT_ATT_ROSTER   = [];   // {trainee_id, name, enrollment_no, mobile, batch_name, status}

function _wwwNTFmtDate(d) {
  if (!d) return '';
  var s = String(d);
  if (s.length >= 10 && s.charAt(4) === '-') {
    return s.substring(8,10) + '-' + s.substring(5,7) + '-' + s.substring(0,4);
  }
  return s;
}
function _wwwNTStatusBadge(s) {
  var cls = 'badge-planned';
  if (s === 'Conducted') cls = 'badge-conducted';
  else if (s === 'Not Conducted') cls = 'badge-not-conducted';
  return '<span class="' + cls + '">' + escHtml(s || 'Planned') + '</span>';
}

function loadWwwNTList() {
  apiGet('/www-master/dropdown/centres').then(function(rows) {
    var sel = document.getElementById('wwwNTFilterCentre'); if (!sel) return;
    sel.innerHTML = '<option value="">All Centres</option>';
    (rows || []).forEach(function(r) {
      sel.innerHTML += '<option value="' + r.centre_code + '">' + escHtml(r.centre_name || r.centre_code) + '</option>';
    });
  }).catch(function() {});
  applyWwwNTFilters();
}

function applyWwwNTFilters() {
  var g = function(id) { var el = document.getElementById(id); return el ? el.value : ''; };
  var qs = [];
  if (g('wwwNTFilterQuarter'))     qs.push('quarter=' + encodeURIComponent(g('wwwNTFilterQuarter')));
  if (g('wwwNTFilterType'))        qs.push('training_type=' + encodeURIComponent(g('wwwNTFilterType')));
  if (g('wwwNTFilterCentre'))      qs.push('centre_code=' + encodeURIComponent(g('wwwNTFilterCentre')));
  if (g('wwwNTFilterFacilitator')) qs.push('facilitator_name=' + encodeURIComponent(g('wwwNTFilterFacilitator')));
  if (g('wwwNTFilterStatus'))      qs.push('status=' + encodeURIComponent(g('wwwNTFilterStatus')));
  if (g('wwwNTFilterDateFrom'))    qs.push('date_from=' + g('wwwNTFilterDateFrom'));
  if (g('wwwNTFilterDateTo'))      qs.push('date_to=' + g('wwwNTFilterDateTo'));
  qs.push('limit=' + parseInt(g('wwwNTItemsPerPage') || '10', 10));
  apiGet('/www-nt-trainings' + (qs.length ? '?' + qs.join('&') : ''))
    .then(function(resp) {
      var rows = (resp && resp.data) || [];
      var tbody = document.getElementById('wwwNTTableBody');
      var pag = document.getElementById('wwwNTPagination');
      if (!rows.length) {
        tbody.innerHTML = '<tr><td colspan="10" style="text-align:center;color:#999;padding:30px;">No trainings yet. Click <b>ADD Training</b> to add one.</td></tr>';
        if (pag) pag.textContent = 'Showing 0 of 0';
        return;
      }
      tbody.innerHTML = rows.map(function(r, i) {
        var att = (r.present_count != null && r.attendance_target ? r.present_count : '--') + ' / ' + (r.attendance_target || '--');
        return '<tr>' +
          '<td>' + (i+1) + '</td>' +
          '<td>' + escHtml(r.quarter || '') + '</td>' +
          '<td>' + escHtml(r.training_type || '') + '</td>' +
          '<td>' + escHtml(r.centre_name || r.centre_code || '') + '</td>' +
          '<td>' + _wwwNTFmtDate(r.start_date) + '</td>' +
          '<td>' + _wwwNTFmtDate(r.end_date) + '</td>' +
          '<td>' + escHtml(r.facilitator_name || '') + '</td>' +
          '<td>' + att + '</td>' +
          '<td>' + _wwwNTStatusBadge(r.status) + '</td>' +
          '<td>' +
            '<button class="btn-icon" title="Attendance" onclick="openWwwNTAttendance(' + r.id + ')"><i class="fas fa-clipboard-check"></i></button> ' +
            '<button class="btn-icon" title="View" onclick="viewWwwNTTraining(' + r.id + ')"><i class="far fa-eye"></i></button> ' +
            '<button class="btn-icon" title="Edit" onclick="editWwwNTTraining(' + r.id + ')"><i class="fas fa-edit"></i></button>' +
          '</td>' +
        '</tr>';
      }).join('');
      if (pag) pag.textContent = 'Showing ' + rows.length + ' of ' + rows.length;
    })
    .catch(function() {
      var tbody = document.getElementById('wwwNTTableBody');
      if (tbody) tbody.innerHTML = '<tr><td colspan="10" style="text-align:center;color:#c0392b;padding:30px;">Failed to load trainings.</td></tr>';
    });
}

function resetWwwNTFilters() {
  ['wwwNTFilterQuarter','wwwNTFilterType','wwwNTFilterCentre','wwwNTFilterFacilitator','wwwNTFilterStatus','wwwNTFilterDateFrom','wwwNTFilterDateTo'].forEach(function(id) {
    var el = document.getElementById(id); if (el) el.value = '';
  });
  loadWwwNTList();
}

function exportWwwNTList() {
  var tbody = document.getElementById('wwwNTTableBody');
  var rows = tbody.querySelectorAll('tr');
  if (!rows.length) { alert('Nothing to export.'); return; }
  var lines = ['S.No.,Quarter,Training Type,Centre,Start Date,End Date,Facilitator,Attendance,Status'];
  rows.forEach(function(tr) {
    var cells = tr.querySelectorAll('td');
    if (cells.length < 9) return;
    var vals = [];
    for (var i = 0; i < 9; i++) vals.push('"' + (cells[i].textContent || '').replace(/"/g,'""').trim() + '"');
    lines.push(vals.join(','));
  });
  var blob = new Blob([lines.join('\n')], { type:'text/csv;charset=utf-8;' });
  var url = URL.createObjectURL(blob);
  var a = document.createElement('a'); a.href=url; a.download='www_nt_trainings.csv';
  document.body.appendChild(a); a.click();
  setTimeout(function(){ document.body.removeChild(a); URL.revokeObjectURL(url); }, 100);
}

function viewWwwNTTraining(id) { _WWW_NT_VIEW_ID = id; navigateTo('wwwViewNT'); }

function editWwwNTTraining(id) {
  _WWW_NT_EDIT_ID = id;
  navigateTo('wwwAddNT');
}

function loadWwwAddNT() {
  ['wwwNTAQuarter','wwwNTAType','wwwNTACentre','wwwNTAFacilitator','wwwNTAStart','wwwNTAEnd','wwwNTATarget'].forEach(function(id) {
    var el = document.getElementById(id); if (el) el.value = '';
  });
  var st = document.getElementById('wwwNTAStatus'); if (st) st.value = 'Planned';
  apiGet('/www-master/dropdown/centres').then(function(rows) {
    var sel = document.getElementById('wwwNTACentre'); if (!sel) return;
    sel.innerHTML = '<option value="">Select Centre</option>';
    (rows || []).forEach(function(r) {
      sel.innerHTML += '<option value="' + r.centre_code + '">' + escHtml(r.centre_name || r.centre_code) + '</option>';
    });
  }).catch(function() {});
  var title = document.getElementById('wwwNTAFormTitle');
  var save  = document.getElementById('wwwNTASaveText');
  if (_WWW_NT_EDIT_ID) {
    if (title) title.textContent = 'Edit Training';
    if (save)  save.textContent  = 'Update';
    apiGet('/www-nt-trainings/' + _WWW_NT_EDIT_ID).then(function(r) {
      document.getElementById('wwwNTAQuarter').value     = r.quarter || '';
      document.getElementById('wwwNTAType').value        = r.training_type || '';
      document.getElementById('wwwNTACentre').value      = r.centre_code || '';
      document.getElementById('wwwNTAFacilitator').value = r.facilitator_name || '';
      document.getElementById('wwwNTAStart').value       = r.start_date || '';
      document.getElementById('wwwNTAEnd').value         = r.end_date || '';
      document.getElementById('wwwNTAStatus').value      = r.status || 'Planned';
      document.getElementById('wwwNTATarget').value      = (r.attendance_target != null) ? r.attendance_target : '';
    }).catch(function(err) {
      alert('Failed to load training: ' + (err && err.detail ? err.detail : err));
      navigateTo('wwwNTList');
    });
  } else {
    if (title) title.textContent = 'Add New Training';
    if (save)  save.textContent  = 'Save Training';
  }
}

function saveWwwNTTraining() {
  var g = function(id) { var el = document.getElementById(id); return el ? el.value : ''; };
  if (!g('wwwNTAQuarter')) { alert('Please select Quarter.'); return; }
  if (!g('wwwNTAType'))    { alert('Please select Training Type.'); return; }
  if (!g('wwwNTACentre'))  { alert('Please select Centre.'); return; }
  if (!g('wwwNTAStart'))   { alert('Please enter Start Date.'); return; }
  if (!g('wwwNTAEnd'))     { alert('Please enter End Date.'); return; }
  if (g('wwwNTAEnd') < g('wwwNTAStart')) { alert('End Date must be on or after Start Date.'); return; }
  var payload = {
    quarter: g('wwwNTAQuarter'), training_type: g('wwwNTAType'),
    centre_code: g('wwwNTACentre'), facilitator_name: g('wwwNTAFacilitator') || null,
    start_date: g('wwwNTAStart'), end_date: g('wwwNTAEnd'),
    status: g('wwwNTAStatus') || 'Planned',
    attendance_target: g('wwwNTATarget') ? parseInt(g('wwwNTATarget'), 10) : null
  };
  if (_WWW_NT_EDIT_ID) {
    apiPut('/www-nt-trainings/' + _WWW_NT_EDIT_ID, payload)
      .then(function() { alert('Training updated.'); _WWW_NT_EDIT_ID = null; navigateTo('wwwNTList'); })
      .catch(function(err) { alert('Update failed: ' + (err && err.detail ? err.detail : err)); });
  } else {
    apiPost('/www-nt-trainings', payload)
      .then(function() { alert('Training saved.'); navigateTo('wwwNTList'); })
      .catch(function(err) { alert('Save failed: ' + (err && err.detail ? err.detail : err)); });
  }
}

