function openWwwNTAttendance(id) { _WWW_NT_ATT_TRAINING = id; navigateTo('wwwNTAttendance'); }

function loadWwwNTAttendance() {
  var id = _WWW_NT_ATT_TRAINING;
  if (!id) { navigateTo('wwwNTList'); return; }
  ['wwwNTAttQuarter','wwwNTAttType','wwwNTAttCentre','wwwNTAttDuration'].forEach(function(eid) {
    var el = document.getElementById(eid); if (el) el.textContent = '…';
  });
  apiGet('/www-nt-trainings/' + id).then(function(r) {
    document.getElementById('wwwNTAttQuarter').textContent  = r.quarter || '—';
    document.getElementById('wwwNTAttType').textContent     = r.training_type || '—';
    document.getElementById('wwwNTAttCentre').textContent   = r.centre_name || r.centre_code || '—';
    document.getElementById('wwwNTAttDuration').textContent = _wwwNTFmtDate(r.start_date) + ' - ' + _wwwNTFmtDate(r.end_date);
  }).catch(function() {});
  apiGet('/www-nt-trainings/' + id + '/attendance').then(function(resp) {
    _WWW_NT_ATT_ROSTER = ((resp && resp.data) || []).map(function(r) {
      return { trainee_id: r.trainee_id, name: r.name, enrollment_no: r.enrollment_no,
               mobile: r.mobile, batch_name: r.batch_name, status: r.attendance_status || null };
    });
    _renderWwwNTAttendanceRows();
  }).catch(function() {
    document.getElementById('wwwNTAttBody').innerHTML = '<tr><td colspan="6" style="text-align:center;color:#c0392b;padding:30px;">Failed to load roster.</td></tr>';
  });
}

function _renderWwwNTAttendanceRows() {
  var tbody = document.getElementById('wwwNTAttBody');
  var present=0, absent=0, unmarked=0;
  _WWW_NT_ATT_ROSTER.forEach(function(r) {
    if (r.status === 'present') present++;
    else if (r.status === 'absent') absent++;
    else unmarked++;
  });
  document.getElementById('wwwNTAttPresent').textContent  = present;
  document.getElementById('wwwNTAttAbsent').textContent   = absent;
  document.getElementById('wwwNTAttUnmarked').textContent = unmarked;
  document.getElementById('wwwNTAttTotal').textContent    = _WWW_NT_ATT_ROSTER.length;
  if (!_WWW_NT_ATT_ROSTER.length) {
    var cnEl = document.getElementById('wwwNTAttCentre');
    var cn = cnEl ? cnEl.textContent : '';
    tbody.innerHTML = '<tr><td colspan="6" style="text-align:center;color:#a02020;padding:30px;"><i class="fas fa-info-circle" style="margin-right:6px;"></i>No trainees enrolled at <b>' + (cn || 'this centre') + '</b>. Add trainees from <b>Enrollment &rsaquo; Add Trainee</b> for this centre first.</td></tr>';
    return;
  }
  tbody.innerHTML = _WWW_NT_ATT_ROSTER.map(function(r, i) {
    var pCls = r.status === 'present' ? ' is-present' : '';
    var aCls = r.status === 'absent'  ? ' is-absent'  : '';
    return '<tr>' +
      '<td>' + (i+1) + '</td>' +
      '<td>' + escHtml(r.name || '') + '</td>' +
      '<td>' + escHtml(r.enrollment_no || '') + '</td>' +
      '<td>' + escHtml(r.mobile || '') + '</td>' +
      '<td>' + escHtml(r.batch_name || '—') + '</td>' +
      '<td><div class="att-buttons">' +
        '<button class="att-btn' + pCls + '" onclick="wwwNTAttMark(' + i + ',\'present\')">Present</button>' +
        '<button class="att-btn' + aCls + '" onclick="wwwNTAttMark(' + i + ',\'absent\')">Absent</button>' +
      '</div></td>' +
    '</tr>';
  }).join('');
}

function wwwNTAttMark(idx, status) {
  if (!_WWW_NT_ATT_ROSTER[idx]) return;
  _WWW_NT_ATT_ROSTER[idx].status = (_WWW_NT_ATT_ROSTER[idx].status === status) ? null : status;
  _renderWwwNTAttendanceRows();
}
function wwwNTAttMarkAll(status) {
  _WWW_NT_ATT_ROSTER.forEach(function(r) { r.status = status; });
  _renderWwwNTAttendanceRows();
}
function saveWwwNTAttendance() {
  if (!_WWW_NT_ATT_TRAINING) return;
  var items = _WWW_NT_ATT_ROSTER.map(function(r) { return { trainee_id: r.trainee_id, status: r.status }; });
  apiPut('/www-nt-trainings/' + _WWW_NT_ATT_TRAINING + '/attendance', { items: items })
    .then(function() { alert('Attendance saved.'); })
    .catch(function(err) { alert('Save failed: ' + (err && err.detail ? err.detail : err)); });
}
function exportWwwNTAttendance() {
  if (!_WWW_NT_ATT_ROSTER.length) { alert('Nothing to export.'); return; }
  var lines = ['S.No.,Trainee Name,Enrollment No.,Mobile No.,Batch,Attendance'];
  _WWW_NT_ATT_ROSTER.forEach(function(r, i) {
    var vals = [i+1, r.name, r.enrollment_no, r.mobile, r.batch_name || '', r.status || 'Unmarked']
      .map(function(v) { return '"' + String(v == null ? '' : v).replace(/"/g,'""') + '"'; });
    lines.push(vals.join(','));
  });
  var blob = new Blob([lines.join('\n')], { type:'text/csv;charset=utf-8;' });
  var url = URL.createObjectURL(blob);
  var a = document.createElement('a'); a.href=url; a.download='www_nt_attendance.csv';
  document.body.appendChild(a); a.click();
  setTimeout(function(){ document.body.removeChild(a); URL.revokeObjectURL(url); }, 100);
}

