function applyWwwGBVFilters() {
  var g = function(id) { var el = document.getElementById(id); return el ? el.value : ''; };
  var qs = [];
  if (g('wwwGBVFilterIncident')) qs.push('facing_during_training=' + encodeURIComponent(g('wwwGBVFilterIncident')));
  if (g('wwwGBVFilterForm'))     qs.push('form_of_violence=' + encodeURIComponent(g('wwwGBVFilterForm')));
  if (g('wwwGBVFilterSupport'))  qs.push('support_kind=' + encodeURIComponent(g('wwwGBVFilterSupport')));
  if (g('wwwGBVFilterBatch'))    qs.push('batch_id=' + encodeURIComponent(g('wwwGBVFilterBatch')));
  if (g('wwwGBVFilterName'))     qs.push('name=' + encodeURIComponent(g('wwwGBVFilterName')));
  apiGet('/www-gbv' + (qs.length ? '?' + qs.join('&') : ''))
    .then(function(resp) {
      var rows = (resp && resp.data) || [];
      var tbody = document.getElementById('wwwGBVTableBody');
      var pag = document.getElementById('wwwGBVPagination');
      if (!rows.length) {
        tbody.innerHTML = '<tr><td colspan="7" style="text-align:center;color:#999;padding:30px;">No GBV records yet.</td></tr>';
        if (pag) pag.textContent = 'Showing 0 of 0'; return;
      }
      tbody.innerHTML = rows.map(function(r) {
        return '<tr>' +
          '<td>' + escHtml(r.enrollment_no || '') + '</td>' +
          '<td>' + escHtml(r.name || '') + '</td>' +
          '<td>' + escHtml(r.batch_name || (r.batch_id ? '#' + r.batch_id : '—')) + '</td>' +
          '<td>' + escHtml(r.facing_during_training || '—') + '</td>' +
          '<td>' + escHtml((r.form_of_violence || []).join(', ') || '—') + '</td>' +
          '<td>' + escHtml((r.support_kinds || []).join(', ') || '—') + '</td>' +
          '<td>' +
            '<button class="btn-icon" title="View" onclick="viewWwwGBV(' + r.id + ')"><i class="far fa-eye"></i></button> ' +
            '<button class="btn-icon" title="Edit" onclick="editWwwGBV(' + r.id + ')"><i class="fas fa-edit"></i></button> ' +
            '<button class="btn-icon" title="Delete" onclick="deleteWwwGBV(' + r.id + ')"><i class="fas fa-trash-alt"></i></button>' +
          '</td>' +
        '</tr>';
      }).join('');
      if (pag) pag.textContent = 'Showing ' + rows.length + ' of ' + rows.length;
    }).catch(function() {
      var tbody = document.getElementById('wwwGBVTableBody');
      if (tbody) tbody.innerHTML = '<tr><td colspan="7" style="text-align:center;color:#c0392b;padding:30px;">Failed to load.</td></tr>';
    });
}

function resetWwwGBVFilters() {
  ['wwwGBVFilterIncident','wwwGBVFilterForm','wwwGBVFilterSupport','wwwGBVFilterBatch','wwwGBVFilterName'].forEach(function(id) {
    var el = document.getElementById(id); if (el) el.value = '';
  });
  loadWwwGBVList();
}

function exportWwwGBVList() {
  var tbody = document.getElementById('wwwGBVTableBody');
  var rows = tbody.querySelectorAll('tr');
  if (!rows.length) { alert('Nothing to export.'); return; }
  var lines = ['Enrollment No.,Name,Batch,Time of Incident,Form of Violence,Support'];
  rows.forEach(function(tr) {
    var cells = tr.querySelectorAll('td');
    if (cells.length < 6) return;
    var vals = [];
    for (var i = 0; i < 6; i++) vals.push('"' + (cells[i].textContent || '').replace(/"/g,'""').trim() + '"');
    lines.push(vals.join(','));
  });
  var blob = new Blob([lines.join('\n')], { type:'text/csv;charset=utf-8;' });
  var url = URL.createObjectURL(blob);
  var a = document.createElement('a'); a.href=url; a.download='www_gbv.csv';
  document.body.appendChild(a); a.click();
  setTimeout(function(){ document.body.removeChild(a); URL.revokeObjectURL(url); }, 100);
}

