function saveWwwGBV(isDraft) {
  var tid = parseInt(document.getElementById('wwwGBVATrainee').value || '0', 10);
  if (!tid && !_WWW_GBV_EDIT_ID) { alert('Please select a Trainee.'); return; }
  function bool(n) { var el = document.querySelector('input[name="' + n + '"]:checked'); return el ? (el.value === 'yes') : null; }
  function arr(n) { return Array.from(document.querySelectorAll('input[name="' + n + '"]:checked')).map(function(c) { return c.value; }); }
  var payload = {
    is_survivor: bool('wwwGBVASurvivor'),
    mentioned_in_enrollment: bool('wwwGBVAMentioned'),
    facing_during_training: document.getElementById('wwwGBVAFacing').value || null,
    violence_location: document.getElementById('wwwGBVALocation').value || null,
    inside_known_unknown: document.getElementById('wwwGBVAInside').value || null,
    known_relation: document.getElementById('wwwGBVAKnownRelation').value || null,
    outside_by_whom: document.getElementById('wwwGBVAOutsideBy').value || null,
    form_of_violence: arr('wwwGBVAForm'),
    do_you_want_support: bool('wwwGBVASupport'),
    support_kinds: arr('wwwGBVASupportKind'),
    any_other_what: document.getElementById('wwwGBVAOther').value || null,
    is_draft: !!isDraft
  };
  if (_WWW_GBV_EDIT_ID) {
    apiPut('/www-gbv/' + _WWW_GBV_EDIT_ID, payload)
      .then(function() { alert(isDraft ? 'Draft saved.' : 'GBV record updated.'); _WWW_GBV_EDIT_ID = null; navigateTo('wwwGBVList'); })
      .catch(function(err) { alert('Save failed: ' + (err && err.detail ? err.detail : err)); });
  } else {
    payload.trainee_id = tid;
    apiPost('/www-gbv', payload)
      .then(function() { alert(isDraft ? 'Draft saved.' : 'GBV record submitted.'); navigateTo('wwwGBVList'); })
      .catch(function(err) { alert('Save failed: ' + (err && err.detail ? err.detail : err)); });
  }
}

