// === WWW T&S View screens — 2026-06-15 ===
var _WWW_NT_VIEW_ID  = null;
var _WWW_GBV_VIEW_ID = null;
var _WWW_FAT_VIEW_ID = null;

function _wwwVSet(eid, v) { var el = document.getElementById(eid); if (el) el.textContent = (v === null || v === undefined || v === '') ? '—' : v; }
function _wwwVDate(d) {
  if (!d) return '';
  var s = String(d);
  if (s.length >= 10 && s.charAt(4) === '-') return s.substring(8,10) + '-' + s.substring(5,7) + '-' + s.substring(0,4);
  return s;
}
function _wwwVCreated(t) { return t ? String(t).substring(0,19).replace('T', ' ') : null; }

/* ---------- View NT ---------- */
function loadWwwViewNT() {
  var id = _WWW_NT_VIEW_ID;
  if (!id) { navigateTo('wwwNTList'); return; }
  apiGet('/www-nt-trainings/' + id).then(function(r) {
    var label = (r.training_type || '') + ' / ' + (r.centre_name || r.centre_code || '');
    _wwwVSet('vWNTBcName', label);
    _wwwVSet('vWNTQuarter', r.quarter);
    _wwwVSet('vWNTType', r.training_type);
    _wwwVSet('vWNTCentre', r.centre_name || r.centre_code);
    _wwwVSet('vWNTFacilitator', r.facilitator_name);
    _wwwVSet('vWNTStart', _wwwVDate(r.start_date));
    _wwwVSet('vWNTEnd', _wwwVDate(r.end_date));
    _wwwVSet('vWNTStatus', r.status);
    _wwwVSet('vWNTTarget', r.attendance_target);
    _wwwVSet('vWNTPresent', r.present_count);
    _wwwVSet('vWNTAbsent', r.absent_count);
    _wwwVSet('vWNTMarked', r.marked_count);
    _wwwVSet('vWNTCreated', _wwwVCreated(r.created_at));
    _wwwVSet('vWNTId', r.id);
  }).catch(function(err) {
    alert('Failed to load: ' + (err && err.detail ? err.detail : err));
    navigateTo('wwwNTList');
  });
}

/* ---------- View GBV ---------- */
function loadWwwViewGBV() {
  var id = _WWW_GBV_VIEW_ID;
  if (!id) { navigateTo('wwwGBVList'); return; }
  function tags(arr, into, fallback) {
    var box = document.getElementById(into);
    if (!box) return;
    if (!arr || !arr.length) { box.innerHTML = '<span style="color:#999;">' + (fallback || '—') + '</span>'; return; }
    box.innerHTML = arr.map(function(t) { return '<span class="v-tag">' + escHtml(t) + '</span>'; }).join('');
  }
  apiGet('/www-gbv/' + id).then(function(r) {
    _wwwVSet('vWGBVBcName',  r.name);
    _wwwVSet('vWGBVProfileName', r.name);
    _wwwVSet('vWGBVProfileEnrollment', r.enrollment_no);
    _wwwVSet('vWGBVName',  r.name);
    _wwwVSet('vWGBVMobile', r.mobile);
    _wwwVSet('vWGBVBatch', r.batch_name || (r.batch_id ? '#' + r.batch_id : null));
    _wwwVSet('vWGBVState', r.state_code);
    _wwwVSet('vWGBVDistrict', r.district_code);
    _wwwVSet('vWGBVCentre', r.centre_code);
    _wwwVSet('vWGBVJoining', _wwwVDate(r.date_of_joining));
    _wwwVSet('vWGBVSurvivor',  r.is_survivor === true ? 'Yes' : (r.is_survivor === false ? 'No' : null));
    _wwwVSet('vWGBVMentioned', r.mentioned_in_enrollment === true ? 'Yes' : (r.mentioned_in_enrollment === false ? 'No' : null));
    _wwwVSet('vWGBVFacing',    r.facing_during_training);
    _wwwVSet('vWGBVLocation',  r.violence_location);
    _wwwVSet('vWGBVInside',    r.inside_known_unknown);
    _wwwVSet('vWGBVRelation',  r.known_relation);
    _wwwVSet('vWGBVOutside',   r.outside_by_whom);
    tags(r.form_of_violence, 'vWGBVFormTags', 'No form recorded');
    _wwwVSet('vWGBVSupport', r.do_you_want_support === true ? 'Yes' : (r.do_you_want_support === false ? 'No' : null));
    _wwwVSet('vWGBVOther', r.any_other_what);
    _wwwVSet('vWGBVCreated', _wwwVCreated(r.created_at));
    tags(r.support_kinds, 'vWGBVKindTags', 'No support recorded');

    // Resolve State / District / Centre names best-effort
    if (r.state_code) {
      apiGet('/www-master/dropdown/states').then(function(rows) {
        var row = (rows || []).filter(function(x) { return x.state_code === r.state_code; })[0];
        if (row) _wwwVSet('vWGBVState', row.state_name);
      }).catch(function() {});
    }
    if (r.centre_code) {
      apiGet('/www-master/dropdown/centres?state_code=' + encodeURIComponent(r.state_code || '')).then(function(rows) {
        var row = (rows || []).filter(function(x) { return x.centre_code === r.centre_code; })[0];
        if (row) _wwwVSet('vWGBVCentre', row.centre_name);
      }).catch(function() {});
    }
    if (r.district_code) {
      apiGet('/www-master/dropdown/districts?state_code=' + encodeURIComponent(r.state_code || '')).then(function(rows) {
        var row = (rows || []).filter(function(x) { return x.district_code === r.district_code; })[0];
        if (row) _wwwVSet('vWGBVDistrict', row.district_name);
      }).catch(function() {});
    }
  }).catch(function(err) {
    alert('Failed to load: ' + (err && err.detail ? err.detail : err));
    navigateTo('wwwGBVList');
  });
}

