// === WWW BKS + PL Stories — 2026-06-15 ===
var _WWW_BKS_TRAINEES = [];
var _WWW_BKS_EDIT_ID = null;
var _WWW_PL_TRAINEES = [];
var _WWW_PL_EDIT_ID = null;
var _WWW_PL_IMAGE_COUNT = 0;
var BKS_INDICATORS = ['against_violence','increased_mobility','claiming_identity','gaining_control','joining_community','engaging_government','treating_equally','putting_thoughts','started_studying'];
var BKS_INDICATOR_LABELS = {
  against_violence: 'Against Violence',
  increased_mobility: 'Increased Mobility',
  claiming_identity: 'Claiming Identity',
  gaining_control: 'Gaining Control',
  joining_community: 'Joining Community',
  engaging_government: 'Engaging Government',
  treating_equally: 'Treating Equally',
  putting_thoughts: 'Putting Thoughts',
  started_studying: 'Started Studying'
};

function _wwwBPFmtDate(d) {
  if (!d) return '';
  var s = String(d);
  if (s.length >= 10 && s.charAt(4) === '-') return s.substring(8,10) + '-' + s.substring(5,7) + '-' + s.substring(0,4);
  return s;
}

/* ====================== BKS LIST ====================== */
function loadWwwBKSList() {
  apiGet('/www-master/dropdown/states').then(function(rows) {
    var sel = document.getElementById('wwwBKSFilterState'); if (!sel) return;
    sel.innerHTML = '<option value="">All States</option>';
    (rows || []).forEach(function(r) { sel.innerHTML += '<option value="' + r.state_code + '">' + escHtml(r.state_name || r.state_code) + '</option>'; });
  });
  applyWwwBKSFilters();
}
function onWwwBKSFilterStateChange() {
  var st = (document.getElementById('wwwBKSFilterState') || {}).value || '';
  var ce = document.getElementById('wwwBKSFilterCentre');
  ce.innerHTML = '<option value="">All Centres</option>';
  if (!st) return;
  apiGet('/www-master/dropdown/centres?state_code=' + encodeURIComponent(st)).then(function(rows) {
    (rows || []).forEach(function(r) { ce.innerHTML += '<option value="' + r.centre_code + '">' + escHtml(r.centre_name || r.centre_code) + '</option>'; });
  });
}
function applyWwwBKSFilters() {
  var g = function(id) { var el = document.getElementById(id); return el ? el.value : ''; };
  var qs = [];
  if (g('wwwBKSFilterState'))    qs.push('state_code=' + encodeURIComponent(g('wwwBKSFilterState')));
  if (g('wwwBKSFilterCentre'))   qs.push('centre_code=' + encodeURIComponent(g('wwwBKSFilterCentre')));
  if (g('wwwBKSFilterIndicator')) qs.push('indicator=' + encodeURIComponent(g('wwwBKSFilterIndicator')));
  if (g('wwwBKSFilterDateFrom')) qs.push('date_from=' + g('wwwBKSFilterDateFrom'));
  if (g('wwwBKSFilterDateTo'))   qs.push('date_to=' + g('wwwBKSFilterDateTo'));
  apiGet('/www-bks' + (qs.length ? '?' + qs.join('&') : '')).then(function(resp) {
    var rows = (resp && resp.data) || [];
    var tbody = document.getElementById('wwwBKSTableBody');
    var pag = document.getElementById('wwwBKSPagination');
    if (!rows.length) {
      tbody.innerHTML = '<tr><td colspan="7" style="text-align:center;color:#999;padding:30px;">No BKS records yet.</td></tr>';
      if (pag) pag.textContent = 'Showing 0 of 0'; return;
    }
    tbody.innerHTML = rows.map(function(r) {
      var loc = (r.centre_code || '') + (r.state_code ? ', ' + r.state_code : '');
      var ind = [];
      BKS_INDICATORS.forEach(function(k) { if (r['spoke_' + k]) ind.push(BKS_INDICATOR_LABELS[k]); });
      return '<tr>' +
        '<td>' + escHtml(r.enrollment_no || '') + '</td>' +
        '<td>' + escHtml(r.name || '') + '</td>' +
        '<td>' + escHtml(loc) + '</td>' +
        '<td>' + _wwwBPFmtDate(r.date_of_bks) + '</td>' +
        '<td>' + escHtml(ind.join(', ') || '—') + '</td>' +
        '<td><span class="badge badge-active">Active</span></td>' +
        '<td>' +
          '<button class="btn-icon" title="View" onclick="viewWwwBKS(' + r.id + ')"><i class="far fa-eye"></i></button> ' +
          '<button class="btn-icon" title="Edit" onclick="editWwwBKS(' + r.id + ')"><i class="fas fa-edit"></i></button>' +
        '</td>' +
      '</tr>';
    }).join('');
    if (pag) pag.textContent = 'Showing ' + rows.length + ' of ' + rows.length;
  });
}
function resetWwwBKSFilters() {
  ['wwwBKSFilterState','wwwBKSFilterCentre','wwwBKSFilterIndicator','wwwBKSFilterDateFrom','wwwBKSFilterDateTo'].forEach(function(id) {
    var el = document.getElementById(id); if (el) el.value = '';
  });
  loadWwwBKSList();
}
function exportWwwBKSList() { alert('Export coming soon.'); }
function editWwwBKS(id) { _WWW_BKS_EDIT_ID = id; navigateTo('wwwAddBKS'); }

/* ====================== ADD BKS ====================== */
function loadWwwAddBKS() {
  ['wwwBKSAState','wwwBKSADistrict','wwwBKSACentre','wwwBKSAType','wwwBKSATrainee',
   'wwwBKSAEnrollment','wwwBKSAJoining','wwwBKSAMonth','wwwBKSADate','wwwBKSAOther'].forEach(function(id) {
    var el = document.getElementById(id); if (el) el.value = '';
  });
  BKS_INDICATORS.forEach(function(k) {
    document.querySelectorAll('input[name="wwwBKSA_' + k + '"]').forEach(function(r) { r.checked = false; });
    var s = document.getElementById('wwwBKSA_story_' + k); if (s) s.value = '';
  });
  apiGet('/www-master/dropdown/states').then(function(rows) {
    var sel = document.getElementById('wwwBKSAState');
    sel.innerHTML = '<option value="">All States</option>';
    (rows || []).forEach(function(r) { sel.innerHTML += '<option value="' + r.state_code + '">' + escHtml(r.state_name || r.state_code) + '</option>'; });
  });
  if (_WWW_BKS_EDIT_ID) {
    apiGet('/www-bks/' + _WWW_BKS_EDIT_ID).then(function(r) {
      document.getElementById('wwwBKSAEnrollment').value = r.enrollment_no || '';
      document.getElementById('wwwBKSAJoining').value = _wwwBPFmtDate(r.date_of_joining);
      document.getElementById('wwwBKSAMonth').value = r.month_of_bks || '';
      document.getElementById('wwwBKSADate').value = r.date_of_bks || '';
      document.getElementById('wwwBKSAOther').value = r.other_indicator || '';
      BKS_INDICATORS.forEach(function(k) {
        var v = r['spoke_' + k];
        if (v !== null && v !== undefined) {
          var el = document.querySelector('input[name="wwwBKSA_' + k + '"][value="' + (v ? 'yes' : 'no') + '"]');
          if (el) el.checked = true;
        }
        var st = document.getElementById('wwwBKSA_story_' + k); if (st) st.value = r['story_' + k] || '';
      });
    });
  }
}
function onWwwBKSAStateChange() {
  var st = document.getElementById('wwwBKSAState').value || '';
  var dt = document.getElementById('wwwBKSADistrict');
  var ce = document.getElementById('wwwBKSACentre');
  var tr = document.getElementById('wwwBKSATrainee');
  dt.innerHTML = '<option value="">All Districts</option>';
  ce.innerHTML = '<option value="">All Centres</option>';
  tr.innerHTML = '<option value="">Select</option>';
  if (!st) return;
  apiGet('/www-master/dropdown/districts?state_code=' + encodeURIComponent(st)).then(function(rows) {
    (rows || []).forEach(function(r) { dt.innerHTML += '<option value="' + r.district_code + '">' + escHtml(r.district_name || r.district_code) + '</option>'; });
  });
}
function onWwwBKSADistrictChange() {
  var st = document.getElementById('wwwBKSAState').value || '';
  var dt = document.getElementById('wwwBKSADistrict').value || '';
  var ce = document.getElementById('wwwBKSACentre');
  ce.innerHTML = '<option value="">All Centres</option>';
  if (!dt) return;
  apiGet('/www-master/dropdown/centres?state_code=' + encodeURIComponent(st) + '&district_code=' + encodeURIComponent(dt)).then(function(rows) {
    (rows || []).forEach(function(r) { ce.innerHTML += '<option value="' + r.centre_code + '">' + escHtml(r.centre_name || r.centre_code) + '</option>'; });
  });
}
function onWwwBKSACentreChange() {
  var st = document.getElementById('wwwBKSAState').value || '';
  var ce = document.getElementById('wwwBKSACentre').value || '';
  var tr = document.getElementById('wwwBKSATrainee');
  tr.innerHTML = '<option value="">Select</option>';
  _WWW_BKS_TRAINEES = [];
  if (!ce) return;
  apiGet('/www-trainees?state_code=' + encodeURIComponent(st) + '&centre_code=' + encodeURIComponent(ce) + '&limit=500').then(function(resp) {
    _WWW_BKS_TRAINEES = (resp && resp.data) || [];
    _WWW_BKS_TRAINEES.forEach(function(t) { tr.innerHTML += '<option value="' + t.id + '">' + escHtml(t.name || '') + '</option>'; });
  });
}
function onWwwBKSATraineeChange() {
  var id = parseInt(document.getElementById('wwwBKSATrainee').value || '0', 10);
  var t = _WWW_BKS_TRAINEES.filter(function(x) { return x.id === id; })[0];
  document.getElementById('wwwBKSAEnrollment').value = t ? (t.enrollment_no || '') : '';
  document.getElementById('wwwBKSAJoining').value    = t && t.enrollment_date ? _wwwBPFmtDate(t.enrollment_date) : '';
}
function saveWwwBKS(isDraft) {
  var tid = parseInt(document.getElementById('wwwBKSATrainee').value || '0', 10);
  if (!tid && !_WWW_BKS_EDIT_ID) { alert('Please select a Trainee.'); return; }
  function bool(name) { var el = document.querySelector('input[name="' + name + '"]:checked'); return el ? (el.value === 'yes') : null; }
  var payload = {
    month_of_bks: document.getElementById('wwwBKSAMonth').value || null,
    date_of_bks: document.getElementById('wwwBKSADate').value || null,
    other_indicator: document.getElementById('wwwBKSAOther').value || null,
    is_draft: !!isDraft
  };
  BKS_INDICATORS.forEach(function(k) {
    payload['spoke_' + k] = bool('wwwBKSA_' + k);
    payload['story_' + k] = (document.getElementById('wwwBKSA_story_' + k) || {}).value || null;
  });
  if (_WWW_BKS_EDIT_ID) {
    apiPut('/www-bks/' + _WWW_BKS_EDIT_ID, payload)
      .then(function() { alert(isDraft ? 'Draft saved.' : 'BKS updated.'); _WWW_BKS_EDIT_ID = null; navigateTo('wwwBKSList'); })
      .catch(function(err) { alert('Save failed: ' + (err && err.detail ? err.detail : err)); });
  } else {
    payload.trainee_id = tid;
    apiPost('/www-bks', payload)
      .then(function() { alert(isDraft ? 'Draft saved.' : 'BKS submitted.'); navigateTo('wwwBKSList'); })
      .catch(function(err) { alert('Save failed: ' + (err && err.detail ? err.detail : err)); });
  }
}

