var _WWW_BKS_VIEW_ID = null;
var _WWW_PL_VIEW_ID  = null;

function _wwwBPSet(eid, v) { var el = document.getElementById(eid); if (el) el.textContent = (v === null || v === undefined || v === '') ? '—' : v; }
function _wwwBPCreated(t) { return t ? String(t).substring(0,19).replace('T', ' ') : null; }

function viewWwwBKS(id) { _WWW_BKS_VIEW_ID = id; navigateTo('wwwViewBKS'); }
function viewWwwPL(id)  { _WWW_PL_VIEW_ID  = id; navigateTo('wwwViewPL');  }

/* ---------- View BKS ---------- */
function loadWwwViewBKS() {
  var id = _WWW_BKS_VIEW_ID;
  if (!id) { navigateTo('wwwBKSList'); return; }
  apiGet('/www-bks/' + id).then(function(r) {
    _wwwBPSet('vWBKSBcName',  r.name);
    _wwwBPSet('vWBKSProfileName', r.name);
    _wwwBPSet('vWBKSProfileEnrollment', r.enrollment_no);
    _wwwBPSet('vWBKSName',  r.name);
    _wwwBPSet('vWBKSMobile', r.mobile);
    _wwwBPSet('vWBKSBatch',  r.batch_name || (r.batch_id ? '#' + r.batch_id : null));
    _wwwBPSet('vWBKSState',    r.state_code);
    _wwwBPSet('vWBKSDistrict', r.district_code);
    _wwwBPSet('vWBKSCentre',   r.centre_code);
    _wwwBPSet('vWBKSJoining',  _wwwBPFmtDate(r.date_of_joining));
    _wwwBPSet('vWBKSMonth',    r.month_of_bks);
    _wwwBPSet('vWBKSDate',     _wwwBPFmtDate(r.date_of_bks));
    _wwwBPSet('vWBKSCreated',  _wwwBPCreated(r.created_at));
    _wwwBPSet('vWBKSOther',    r.other_indicator);
    _wwwBPSet('vWBKSId',       r.id);

    var LABELS = [
      ['against_violence',     'Spoke Out Against Violence'],
      ['increased_mobility',   'Spoke about increased Mobility'],
      ['claiming_identity',    'Spoke about claiming identity with dignity'],
      ['gaining_control',      'Spoke about gaining more control over my own life'],
      ['joining_community',    'Spoke about Joining larger community through campaign'],
      ['engaging_government',  'Spoke about engaging with government and got my work done'],
      ['treating_equally',     'Spoke about treating people from a different religion, caste, sexuality and abilities with equality, respect and understanding'],
      ['putting_thoughts',     'Spoke about putting forward my own thoughts and decisions in front of my family and others in my community'],
      ['started_studying',     'Spoke about started studying again']
    ];
    var html = LABELS.map(function(pair) {
      var k = pair[0], label = pair[1];
      var v = r['spoke_' + k];
      var story = r['story_' + k] || '';
      var badge = (v === true)  ? '<span class="v-ind-badge yes">Yes</span>'
                : (v === false) ? '<span class="v-ind-badge no">No</span>'
                :                 '<span class="v-ind-badge na">Not answered</span>';
      var storyHtml = story.trim() ? ('<div class="v-ind-story">' + escHtml(story) + '</div>') : '';
      return '<div class="v-ind-block">' +
               '<div class="v-ind-head"><div class="v-ind-title">' + escHtml(label) + '</div>' + badge + '</div>' +
               storyHtml +
             '</div>';
    }).join('');
    document.getElementById('vWBKSIndicatorsBox').innerHTML = html;

    // Resolve State / District / Centre names best-effort
    if (r.state_code) apiGet('/www-master/dropdown/states').then(function(rows) {
      var row = (rows || []).filter(function(x) { return x.state_code === r.state_code; })[0];
      if (row) _wwwBPSet('vWBKSState', row.state_name);
    });
    if (r.district_code) apiGet('/www-master/dropdown/districts?state_code=' + encodeURIComponent(r.state_code || '')).then(function(rows) {
      var row = (rows || []).filter(function(x) { return x.district_code === r.district_code; })[0];
      if (row) _wwwBPSet('vWBKSDistrict', row.district_name);
    });
    if (r.centre_code) apiGet('/www-master/dropdown/centres?state_code=' + encodeURIComponent(r.state_code || '')).then(function(rows) {
      var row = (rows || []).filter(function(x) { return x.centre_code === r.centre_code; })[0];
      if (row) _wwwBPSet('vWBKSCentre', row.centre_name);
    });
  }).catch(function(err) {
    alert('Failed to load BKS: ' + (err && err.detail ? err.detail : err));
    navigateTo('wwwBKSList');
  });
}

