function _wwwAPLicResetTrainees() {
  _WWW_APLIC_TRAINEES_RAW = []; _WWW_APLIC_SELECTED = null;
  document.getElementById('wwwAPLicTraineesBody').innerHTML = '';
  document.getElementById('wwwAPLicTraineesWrap').style.display = 'none';
  document.getElementById('wwwAPLicHint').style.display = '';
}
function filterWwwAPLicTrainees() { _renderWwwAPLicTrainees(); }
function _renderWwwAPLicTrainees() {
  var q = (document.getElementById('wwwAPLicNameFilter').value || '').toLowerCase().trim();
  var rows = _WWW_APLIC_TRAINEES_RAW.filter(function(r) { return !q || (r.name || '').toLowerCase().indexOf(q) >= 0; });
  var body = document.getElementById('wwwAPLicTraineesBody');
  if (!rows.length) {
    body.innerHTML = '<tr><td colspan="6" class="plic-empty">No trainees match.</td></tr>';
    return;
  }
  body.innerHTML = rows.map(function(r) {
    var loc = (r.centre_code || '') + (r.state_code ? ', ' + r.state_code : '');
    return '<tr>' +
      '<td><input type="radio" name="wwwAPLicPick" value="' + r.id + '" onchange="selectWwwAPLicTrainee(' + r.id + ')"' + (_WWW_APLIC_SELECTED === r.id ? ' checked' : '') + '></td>' +
      '<td>' + escHtml(r.enrollment_no || '') + '</td>' +
      '<td>' + escHtml(r.name || '') + '</td>' +
      '<td>' + escHtml(r.batch_name || (r.batch_id ? '#' + r.batch_id : '—')) + '</td>' +
      '<td>' + escHtml(loc) + '</td>' +
      '<td><span class="badge badge-active">Active</span></td>' +
    '</tr>';
  }).join('');
}
function selectWwwAPLicTrainee(id) { _WWW_APLIC_SELECTED = id; }
function proceedToPLicForm() {
  if (!_WWW_APLIC_SELECTED) { alert('Please pick a trainee from the table.'); return; }
  var t = _WWW_APLIC_TRAINEES_RAW.filter(function(x) { return x.id === _WWW_APLIC_SELECTED; })[0];
  if (!t) { alert('Trainee not found.'); return; }
  _WWW_PLIC_FORM_TRAINEE = t;
  navigateTo('wwwPLicForm');
}

/* ====================== PL FORM ====================== */
function loadWwwPLicForm() {
  var t = _WWW_PLIC_FORM_TRAINEE;
  if (!t) {
    alert('Pick a trainee first: Add PL → State → Centre → select → Proceed to Form.');
    navigateTo('wwwAddPLic'); return;
  }
  _wwwPLicVSet('wwwPLicFName', t.name);
  _wwwPLicVSet('wwwPLicFEnroll', t.enrollment_no);
  _wwwPLicVSet('wwwPLicFType', t.enrollment_type);
  _wwwPLicVSet('wwwPLicFJoining', _wwwPLicFmtDate(t.date_of_joining));
  document.getElementById('wwwPLicFNameI').value  = t.name || '';
  document.getElementById('wwwPLicFMobile').value = t.mobile || '';
  document.getElementById('wwwPLicFBatch').value  = t.batch_name || (t.batch_id ? '#' + t.batch_id : '');

  // Reset PL fields then prefill if editing
  ['wwwPLicFLLDate','wwwPLicFLLNumber','wwwPLicFLLDuration','wwwPLicFLLAttempts',
   'wwwPLicFPLDate','wwwPLicFPLNumber','wwwPLicFPLDuration','wwwPLicFPLAttempts'].forEach(function(id) {
    var el = document.getElementById(id); if (el) el.value = '';
  });

  // Best-effort LL auto-fill
  apiGet('/www-learning-licenses?centre_code=' + encodeURIComponent(t.centre_code || '') + '&name=' + encodeURIComponent(t.name || '')).then(function(resp) {
    var matches = ((resp && resp.data) || []).filter(function(r) { return r.trainee_id === t.id; });
    if (matches.length) {
      var ll = matches[0];
      document.getElementById('wwwPLicFLLDate').value     = ll.date_of_ll || '';
      document.getElementById('wwwPLicFLLNumber').value   = ll.ll_number || '';
      document.getElementById('wwwPLicFLLDuration').value = (ll.duration_days != null) ? ll.duration_days : '';
      document.getElementById('wwwPLicFLLAttempts').value = (ll.attempts_taken != null) ? ll.attempts_taken : '';
    }
  }).catch(function() {});

  if (t._existing) {
    var e = t._existing;
    document.getElementById('wwwPLicFPLDate').value     = e.date_of_pl || '';
    document.getElementById('wwwPLicFPLNumber').value   = e.pl_number || '';
    document.getElementById('wwwPLicFPLDuration').value = (e.duration_days != null) ? e.duration_days : '';
    document.getElementById('wwwPLicFPLAttempts').value = (e.attempts_taken != null) ? e.attempts_taken : '';
  }
}
function saveWwwPLicForm() {
  var t = _WWW_PLIC_FORM_TRAINEE;
  if (!t) { alert('Trainee context missing.'); navigateTo('wwwAddPLic'); return; }
  var date = document.getElementById('wwwPLicFPLDate').value || '';
  var num  = document.getElementById('wwwPLicFPLNumber').value.trim();
  var dur  = document.getElementById('wwwPLicFPLDuration').value || '';
  var att  = document.getElementById('wwwPLicFPLAttempts').value || '';
  if (!date) { alert('Please enter Date of PL.'); return; }
  if (!num)  { alert('Please enter PL Number.'); return; }
  if (att === '' || isNaN(parseInt(att, 10)) || parseInt(att, 10) < 1) { alert('Please enter Attempts taken to clear PL.'); return; }
  var payload = {
    date_of_pl: date, pl_number: num,
    duration_days: dur ? parseInt(dur, 10) : null,
    attempts_taken: parseInt(att, 10)
  };
  if (t._editing_pl_id) {
    apiPut('/www-permanent-licenses/' + t._editing_pl_id, payload)
      .then(function() { alert('Permanent License updated.'); _WWW_PLIC_FORM_TRAINEE = null; navigateTo('wwwPLicList'); })
      .catch(function(err) { alert('Save failed: ' + (err && err.detail ? err.detail : err)); });
  } else {
    payload.trainee_id = t.id;
    apiPost('/www-permanent-licenses', payload)
      .then(function() { alert('Permanent License submitted.'); _WWW_PLIC_FORM_TRAINEE = null; navigateTo('wwwPLicList'); })
      .catch(function(err) { alert('Save failed: ' + (err && err.detail ? err.detail : err)); });
  }
}

/* ====================== Renewal modal ====================== */
function openWwwPLicRenewModal(plId, traineeName, priorAttempts) {
  _WWW_PLIC_RENEW_ID = plId;
  _WWW_PLIC_RENEW_ATTEMPTS_DEFAULT = parseInt(priorAttempts || 1, 10) || 1;
  document.getElementById('wwwPLicRenewForId').textContent = plId;
  document.getElementById('wwwPLicRenewForName').textContent = traineeName || '—';
  document.getElementById('wwwPLicRenewDate').value = '';
  document.getElementById('wwwPLicRenewNumber').value = '';
  document.getElementById('wwwPLicRenewAttempts').value = _WWW_PLIC_RENEW_ATTEMPTS_DEFAULT;
  document.getElementById('wwwPLicRenewModal').style.display = 'flex';
}
function closeWwwPLicRenewModal() {
  document.getElementById('wwwPLicRenewModal').style.display = 'none';
  _WWW_PLIC_RENEW_ID = null;
}
function saveWwwPLicRenewal() {
  if (!_WWW_PLIC_RENEW_ID) return;
  var date = document.getElementById('wwwPLicRenewDate').value || '';
  var num  = document.getElementById('wwwPLicRenewNumber').value.trim();
  var att  = document.getElementById('wwwPLicRenewAttempts').value || '';
  if (!date) { alert('Please enter Date of Renewal Of PL.'); return; }
  if (!num)  { alert('Please enter New PL Number.'); return; }
  if (att === '' || isNaN(parseInt(att, 10)) || parseInt(att, 10) < 1) { alert('Please enter Number of attempts.'); return; }
  apiPost('/www-permanent-licenses/' + _WWW_PLIC_RENEW_ID + '/renewals',
          { renewal_date: date, new_pl_number: num, attempts_taken: parseInt(att, 10) })
    .then(function() { alert('Renewal saved.'); closeWwwPLicRenewModal(); if (typeof loadWwwPLicList === 'function') loadWwwPLicList(); })
    .catch(function(err) { alert('Save failed: ' + (err && err.detail ? err.detail : err)); });
}

/* ====================== View PL ====================== */
function loadWwwViewPLic() {
  var id = _WWW_PLIC_VIEW_ID;
  if (!id) { navigateTo('wwwPLicList'); return; }
  apiGet('/www-permanent-licenses/' + id).then(function(r) {
    _wwwPLicVSet('vWPLicBcName', r.name);
    _wwwPLicVSet('vWPLicProfileName', r.name);
    _wwwPLicVSet('vWPLicProfileEnrollment', r.enrollment_no);
    _wwwPLicVSet('vWPLicName',  r.name);
    _wwwPLicVSet('vWPLicMobile', r.mobile);
    _wwwPLicVSet('vWPLicBatch',  r.batch_name || (r.batch_id ? '#' + r.batch_id : null));
    _wwwPLicVSet('vWPLicState', r.state_code);
    _wwwPLicVSet('vWPLicCentre', r.centre_code);
    _wwwPLicVSet('vWPLicType',   r.enrollment_type);
    _wwwPLicVSet('vWPLicDate',   _wwwPLicFmtDate(r.date_of_pl));
    _wwwPLicVSet('vWPLicNumber', r.pl_number);
    _wwwPLicVSet('vWPLicDuration', r.duration_days);
    _wwwPLicVSet('vWPLicAttempts', r.attempts_taken);
    if (r.state_code) apiGet('/www-master/dropdown/states').then(function(rows) {
      var row = (rows || []).filter(function(x) { return x.state_code === r.state_code; })[0];
      if (row) _wwwPLicVSet('vWPLicState', row.state_name);
    });
    if (r.centre_code) apiGet('/www-master/dropdown/centres?state_code=' + encodeURIComponent(r.state_code || '')).then(function(rows) {
      var row = (rows || []).filter(function(x) { return x.centre_code === r.centre_code; })[0];
      if (row) _wwwPLicVSet('vWPLicCentre', row.centre_name);
    });
  });
  apiGet('/www-permanent-licenses/' + id + '/renewals').then(function(resp) {
    var rows = ((resp && resp.data) || []).slice().reverse();
    var wrap = document.getElementById('vWPLicRenewalsWrap');
    if (!rows.length) {
      wrap.innerHTML = '<div class="v-renewal-empty">No renewals yet. Use the <b>+</b> icon in the list to add one.</div>';
      return;
    }
    wrap.innerHTML = rows.map(function(r, i) {
      return (rows.length > 1 ? ('<div class="v-renewal-num">Renewal #' + (i+1) + '</div>') : '') +
        '<div class="v-renewal-block">' +
          '<div class="v-grid g3">' +
            '<div class="v-item"><label>Date of Renewed of PL</label><span>' + _wwwPLicFmtDate(r.renewal_date) + '</span></div>' +
            '<div class="v-item"><label>New PL Number</label><span>' + escHtml(r.new_pl_number || '') + '</span></div>' +
            '<div class="v-item"><label>Attempts taken to clear PL</label><span>' + (r.attempts_taken != null ? r.attempts_taken : '—') + '</span></div>' +
          '</div>' +
        '</div>';
    }).join('');
  });
}

// === WWW Sakha (Internal + External) — 2026-06-15 ===
var _WWW_IS_TRAINEES = [], _WWW_IS_EDIT_ID = null;
var _WWW_ES_TRAINEES = [], _WWW_ES_EDIT_ID = null;

function _wwwSkFmtDate(d) {
  if (!d) return '';
  var s = String(d);
  if (s.length >= 10 && s.charAt(4) === '-') return s.substring(8,10) + '-' + s.substring(5,7) + '-' + s.substring(0,4);
  return s;
}

/* ====================== Shared helpers for cascade + auto-fill ====================== */
function _wwwSkLoadCentres(cb) {
  apiGet('/www-master/dropdown/states').then(function(rows) { cb(rows || []); });
}

function _wwwSkAutoFillLLPL(trainee, prefix) {
  // Best-effort: fetch LL + PL records by trainee match.
  if (!trainee) return;
  apiGet('/www-learning-licenses?centre_code=' + encodeURIComponent(trainee.centre_code || '') + '&name=' + encodeURIComponent(trainee.name || '')).then(function(resp) {
    var ll = ((resp && resp.data) || []).filter(function(r) { return r.trainee_id === trainee.id; })[0];
    if (ll) {
      document.getElementById(prefix + 'LLDate').value     = _wwwSkFmtDate(ll.date_of_ll);
      document.getElementById(prefix + 'LLNumber').value   = ll.ll_number || '';
      document.getElementById(prefix + 'LLAttempts').value = (ll.attempts_taken != null) ? ll.attempts_taken : '';
    }
  }).catch(function() {});
  apiGet('/www-permanent-licenses?centre_code=' + encodeURIComponent(trainee.centre_code || '') + '&name=' + encodeURIComponent(trainee.name || '')).then(function(resp) {
    var pl = ((resp && resp.data) || []).filter(function(r) { return r.trainee_id === trainee.id; })[0];
    if (pl) {
      document.getElementById(prefix + 'PLDate').value     = _wwwSkFmtDate(pl.date_of_pl);
      document.getElementById(prefix + 'PLNumber').value   = pl.pl_number || '';
      document.getElementById(prefix + 'PLAttempts').value = (pl.attempts_taken != null) ? pl.attempts_taken : '';
    }
  }).catch(function() {});
}

/* ====================== INTERNAL SAKHA LIST ====================== */
function loadWwwISList() {
  apiGet('/www-master/dropdown/batches').then(function(rows) {
    var sel = document.getElementById('wwwISFilterBatch');
    sel.innerHTML = '<option value="">All Batches</option>';
    (rows || []).forEach(function(r) { sel.innerHTML += '<option value="' + r.id + '">' + escHtml(r.name || '#' + r.id) + '</option>'; });
  });
  applyWwwISFilters();
}
function applyWwwISFilters() {
  var g = function(id) { var el = document.getElementById(id); return el ? el.value : ''; };
  var qs = [];
  if (g('wwwISFilterPassed'))   qs.push('passed=' + encodeURIComponent(g('wwwISFilterPassed')));
  if (g('wwwISFilterName'))     qs.push('name=' + encodeURIComponent(g('wwwISFilterName')));
  if (g('wwwISFilterBatch'))    qs.push('batch_id=' + encodeURIComponent(g('wwwISFilterBatch')));
  if (g('wwwISFilterDateFrom')) qs.push('date_from=' + g('wwwISFilterDateFrom'));
  if (g('wwwISFilterDateTo'))   qs.push('date_to=' + g('wwwISFilterDateTo'));
  apiGet('/www-internal-sakha' + (qs.length ? '?' + qs.join('&') : '')).then(function(resp) {
    var rows = (resp && resp.data) || [];
    var tbody = document.getElementById('wwwISTableBody');
    var pag = document.getElementById('wwwISPagination');
    if (!rows.length) {
      tbody.innerHTML = '<tr><td colspan="8" style="text-align:center;color:#999;padding:30px;">No records yet. Click <b>ADD Internal Sakha</b> to add one.</td></tr>';
      if (pag) pag.textContent = 'Showing 0 of 0'; return;
    }
    tbody.innerHTML = rows.map(function(r) {
      var passed = r.passed_internal === true ? 'Yes' : (r.passed_internal === false ? 'No' : '—');
      return '<tr>' +
        '<td>' + escHtml(r.enrollment_no || '') + '</td>' +
        '<td>' + escHtml(r.name || '') + '</td>' +
        '<td>' + escHtml(r.batch_name || (r.batch_id ? '#' + r.batch_id : '—')) + '</td>' +
        '<td>' + passed + '</td>' +
        '<td>' + _wwwSkFmtDate(r.internal_pass_date) + '</td>' +
        '<td>' + (r.internal_attempts != null ? r.internal_attempts : '—') + '</td>' +
        '<td>' + (r.duration_days != null ? r.duration_days : '—') + '</td>' +
        '<td>' +
          '<button class="btn-icon" title="View" onclick="viewWwwIS(' + r.id + ')"><i class="far fa-eye"></i></button> ' +
          '<button class="btn-icon" title="Edit" onclick="editWwwIS(' + r.id + ')"><i class="fas fa-edit"></i></button>' +
        '</td>' +
      '</tr>';
    }).join('');
    if (pag) pag.textContent = 'Showing ' + rows.length + ' of ' + rows.length;
  });
}
function resetWwwISFilters() {
  ['wwwISFilterPassed','wwwISFilterName','wwwISFilterBatch','wwwISFilterDateFrom','wwwISFilterDateTo'].forEach(function(id) {
    var el = document.getElementById(id); if (el) el.value = '';
  });
  loadWwwISList();
}
function exportWwwISList() { alert('Export coming soon.'); }
function editWwwIS(id) { _WWW_IS_EDIT_ID = id; navigateTo('wwwEditIS'); }

/* ====================== ADD INTERNAL SAKHA ====================== */
function loadWwwAddIS() {
  ['wwwISAState','wwwISADistrict','wwwISACentre','wwwISATrainee','wwwISAEnrollment',
   'wwwISAJoining','wwwISABatch','wwwISALLDate','wwwISALLNumber','wwwISALLAttempts',
   'wwwISAPLDate','wwwISAPLNumber','wwwISAPLAttempts','wwwISAEnrollType',
   'wwwISAOnRoadStart','wwwISAOnRoadEnd','wwwISASelfDriveStart','wwwISASelfDriveEnd',
   'wwwISAPassDate','wwwISAAttempts','wwwISAReason','wwwISAReasonOther','wwwISADurationMonths'].forEach(function(id) {
    var el = document.getElementById(id); if (el) el.value = '';
  });
  document.querySelectorAll('input[name="wwwISAPassed"]').forEach(function(r) { r.checked = false; });
  apiGet('/www-master/dropdown/states').then(function(rows) {
    var sel = document.getElementById('wwwISAState');
    sel.innerHTML = '<option value="">All States</option>';
    (rows || []).forEach(function(r) { sel.innerHTML += '<option value="' + r.state_code + '">' + escHtml(r.state_name || r.state_code) + '</option>'; });
  });
  if (_WWW_IS_EDIT_ID) {
    apiGet('/www-internal-sakha/' + _WWW_IS_EDIT_ID).then(function(r) {
      // best-effort prefill — fields are hydrated where available
      _wwwSkAutoFillLLPL({ id: r.trainee_id, name: r.name, centre_code: r.centre_code }, 'wwwISA');
      document.getElementById('wwwISAJoining').value     = _wwwSkFmtDate(r.date_of_joining);
      document.getElementById('wwwISABatch').value       = r.batch_name || '';
      document.getElementById('wwwISAEnrollType').value  = r.enrollment_type || '';
      document.getElementById('wwwISAOnRoadStart').value = r.on_road_start_date    || '';
      document.getElementById('wwwISAOnRoadEnd').value   = r.on_road_end_date      || '';
      document.getElementById('wwwISASelfDriveStart').value = r.self_drive_start_date || '';
      document.getElementById('wwwISASelfDriveEnd').value   = r.self_drive_end_date   || '';
      var radio = document.querySelector('input[name="wwwISAPassed"][value="' + (r.passed_internal ? 'yes' : 'no') + '"]');
      if (radio) { radio.checked = true; onWwwISAPassedChange(); }
      document.getElementById('wwwISAPassDate').value = r.internal_pass_date || '';
      document.getElementById('wwwISAAttempts').value = (r.internal_attempts != null) ? r.internal_attempts : '';
      document.getElementById('wwwISAReason').value   = r.fail_reason || '';
      document.getElementById('wwwISAReasonOther').value = r.fail_reason_other || '';
      document.getElementById('wwwISADurationMonths').value = (r.duration_months != null) ? r.duration_months : '';
    });
  }
}
function onWwwISAStateChange() {
  var st = document.getElementById('wwwISAState').value || '';
  document.getElementById('wwwISADistrict').innerHTML = '<option value="">All Districts</option>';
  document.getElementById('wwwISACentre').innerHTML = '<option value="">All Centres</option>';
  document.getElementById('wwwISATrainee').innerHTML = '<option value="">Select</option>';
  document.getElementById('wwwISAEnrollment').innerHTML = '<option value="">Select</option>';
  if (!st) return;
  apiGet('/www-master/dropdown/districts?state_code=' + encodeURIComponent(st)).then(function(rows) {
    var dt = document.getElementById('wwwISADistrict');
    (rows || []).forEach(function(r) { dt.innerHTML += '<option value="' + r.district_code + '">' + escHtml(r.district_name || r.district_code) + '</option>'; });
  });
}
function onWwwISADistrictChange() {
  var st = document.getElementById('wwwISAState').value || '';
  var dt = document.getElementById('wwwISADistrict').value || '';
  var ce = document.getElementById('wwwISACentre');
  ce.innerHTML = '<option value="">All Centres</option>';
  if (!dt) return;
  apiGet('/www-master/dropdown/centres?state_code=' + encodeURIComponent(st) + '&district_code=' + encodeURIComponent(dt)).then(function(rows) {
    (rows || []).forEach(function(r) { ce.innerHTML += '<option value="' + r.centre_code + '">' + escHtml(r.centre_name || r.centre_code) + '</option>'; });
  });
}
function onWwwISACentreChange() {
  var st = document.getElementById('wwwISAState').value || '';
  var ce = document.getElementById('wwwISACentre').value || '';
  var tr = document.getElementById('wwwISATrainee');
  var en = document.getElementById('wwwISAEnrollment');
  tr.innerHTML = '<option value="">Select</option>';
  en.innerHTML = '<option value="">Select</option>';
  _WWW_IS_TRAINEES = [];
  if (!ce) return;
  apiGet('/www-trainees?state_code=' + encodeURIComponent(st) + '&centre_code=' + encodeURIComponent(ce) + '&limit=500').then(function(resp) {
    _WWW_IS_TRAINEES = (resp && resp.data) || [];
    _WWW_IS_TRAINEES.forEach(function(t) {
      tr.innerHTML += '<option value="' + t.id + '">' + escHtml(t.name || '') + '</option>';
      en.innerHTML += '<option value="' + t.id + '">' + escHtml(t.enrollment_no || '') + '</option>';
    });
  });
}
function onWwwISATraineeChange(fromEnrollment) {
  var srcId = fromEnrollment ? 'wwwISAEnrollment' : 'wwwISATrainee';
  var otherId = fromEnrollment ? 'wwwISATrainee' : 'wwwISAEnrollment';
  var id = parseInt(document.getElementById(srcId).value || '0', 10);
  document.getElementById(otherId).value = id || '';
  var t = _WWW_IS_TRAINEES.filter(function(x) { return x.id === id; })[0];
  if (!t) return;
  document.getElementById('wwwISAJoining').value     = t.enrollment_date ? _wwwSkFmtDate(t.enrollment_date) : '';
  document.getElementById('wwwISABatch').value       = t.batch_name || (t.batch_id ? '#' + t.batch_id : '');
  document.getElementById('wwwISAEnrollType').value  = t.enrollment_type || '';
  _wwwSkAutoFillLLPL(t, 'wwwISA');
}
function onWwwISAPassedChange() {
  var v = (document.querySelector('input[name="wwwISAPassed"]:checked') || {}).value;
  document.getElementById('wwwISAYesDateWrap').style.display   = v === 'yes' ? '' : 'none';
  document.getElementById('wwwISAYesAttWrap').style.display    = v === 'yes' ? '' : 'none';
  document.getElementById('wwwISANoReasonWrap').style.display  = v === 'no'  ? '' : 'none';
}
function saveWwwIS(isDraft) {
  var tid = parseInt(document.getElementById('wwwISATrainee').value || '0', 10);
  if (!tid && !_WWW_IS_EDIT_ID) { alert('Please select a Trainee.'); return; }
  var passed = (document.querySelector('input[name="wwwISAPassed"]:checked') || {}).value;
  var payload = {
    on_road_start_date: document.getElementById('wwwISAOnRoadStart').value || null,
    on_road_end_date:   document.getElementById('wwwISAOnRoadEnd').value || null,
    self_drive_start_date: document.getElementById('wwwISASelfDriveStart').value || null,
    self_drive_end_date:   document.getElementById('wwwISASelfDriveEnd').value || null,
    passed_internal: passed === 'yes' ? true : (passed === 'no' ? false : null),
    internal_pass_date: document.getElementById('wwwISAPassDate').value || null,
    internal_attempts: document.getElementById('wwwISAAttempts').value ? parseInt(document.getElementById('wwwISAAttempts').value, 10) : null,
    fail_reason: document.getElementById('wwwISAReason').value || null,
    fail_reason_other: document.getElementById('wwwISAReasonOther').value || null,
    duration_months: document.getElementById('wwwISADurationMonths').value ? parseInt(document.getElementById('wwwISADurationMonths').value, 10) : null,
    is_draft: !!isDraft
  };
  if (_WWW_IS_EDIT_ID) {
    apiPut('/www-internal-sakha/' + _WWW_IS_EDIT_ID, payload)
      .then(function() { alert(isDraft ? 'Draft saved.' : 'Internal Sakha updated.'); _WWW_IS_EDIT_ID = null; navigateTo('wwwISList'); })
      .catch(function(err) { alert('Save failed: ' + (err && err.detail ? err.detail : err)); });
  } else {
    payload.trainee_id = tid;
    apiPost('/www-internal-sakha', payload)
      .then(function() { alert(isDraft ? 'Draft saved.' : 'Internal Sakha submitted.'); navigateTo('wwwISList'); })
      .catch(function(err) { alert('Save failed: ' + (err && err.detail ? err.detail : err)); });
  }
}

