/* ====================== ADD EXTERNAL SAKHA ====================== */
function loadWwwAddES() {
  ['wwwESAState','wwwESADistrict','wwwESACentre','wwwESATrainee','wwwESAEnrollment',
   'wwwESAJoining','wwwESABatch','wwwESALLDate','wwwESALLNumber','wwwESALLAttempts',
   'wwwESAPLDate','wwwESAPLNumber','wwwESAPLAttempts','wwwESAEnrollType',
   'wwwESAIntDate','wwwESAIntAttempts',
   'wwwESAPassDate','wwwESAAttempts','wwwESAReason','wwwESAReasonOther','wwwESADurationMonths','wwwESATransferDate'].forEach(function(id) {
    var el = document.getElementById(id); if (el) el.value = '';
  });
  document.querySelectorAll('input[name="wwwESAPassed"]').forEach(function(r) { r.checked = false; });
  apiGet('/www-master/dropdown/states').then(function(rows) {
    var sel = document.getElementById('wwwESAState');
    sel.innerHTML = '<option value="">All States</option>';
    (rows || []).forEach(function(r) { sel.innerHTML += '<option value="' + r.state_code + '">' + escHtml(r.state_name || r.state_code) + '</option>'; });
  });
  if (_WWW_ES_EDIT_ID) {
    apiGet('/www-external-sakha/' + _WWW_ES_EDIT_ID).then(function(r) {
      _wwwSkAutoFillLLPL({ id: r.trainee_id, name: r.name, centre_code: r.centre_code }, 'wwwESA');
      document.getElementById('wwwESAJoining').value     = _wwwSkFmtDate(r.date_of_joining);
      document.getElementById('wwwESABatch').value       = r.batch_name || '';
      document.getElementById('wwwESAEnrollType').value  = r.enrollment_type || '';
      apiGet('/www-internal-sakha/trainee/' + r.trainee_id).then(function(intRec) {
        if (intRec) {
          document.getElementById('wwwESAIntDate').value     = _wwwSkFmtDate(intRec.internal_pass_date);
          document.getElementById('wwwESAIntAttempts').value = (intRec.internal_attempts != null) ? intRec.internal_attempts : '';
        }
      });
      var radio = document.querySelector('input[name="wwwESAPassed"][value="' + (r.passed_external ? 'yes' : 'no') + '"]');
      if (radio) { radio.checked = true; onWwwESAPassedChange(); }
      document.getElementById('wwwESAPassDate').value = r.external_pass_date || '';
      document.getElementById('wwwESAAttempts').value = (r.external_attempts != null) ? r.external_attempts : '';
      document.getElementById('wwwESAReason').value   = r.fail_reason || '';
      document.getElementById('wwwESAReasonOther').value = r.fail_reason_other || '';
      document.getElementById('wwwESADurationMonths').value = (r.duration_months != null) ? r.duration_months : '';
      document.getElementById('wwwESATransferDate').value   = r.date_of_transfer_to_sakha || '';
    });
  }
}
function onWwwESAStateChange() {
  var st = document.getElementById('wwwESAState').value || '';
  document.getElementById('wwwESADistrict').innerHTML = '<option value="">All Districts</option>';
  document.getElementById('wwwESACentre').innerHTML = '<option value="">All Centres</option>';
  document.getElementById('wwwESATrainee').innerHTML = '<option value="">Select</option>';
  document.getElementById('wwwESAEnrollment').innerHTML = '<option value="">Select</option>';
  if (!st) return;
  apiGet('/www-master/dropdown/districts?state_code=' + encodeURIComponent(st)).then(function(rows) {
    var dt = document.getElementById('wwwESADistrict');
    (rows || []).forEach(function(r) { dt.innerHTML += '<option value="' + r.district_code + '">' + escHtml(r.district_name || r.district_code) + '</option>'; });
  });
}
function onWwwESADistrictChange() {
  var st = document.getElementById('wwwESAState').value || '';
  var dt = document.getElementById('wwwESADistrict').value || '';
  var ce = document.getElementById('wwwESACentre');
  ce.innerHTML = '<option value="">All Centres</option>';
  if (!dt) return;
  apiGet('/www-master/dropdown/centres?state_code=' + encodeURIComponent(st) + '&district_code=' + encodeURIComponent(dt)).then(function(rows) {
    (rows || []).forEach(function(r) { ce.innerHTML += '<option value="' + r.centre_code + '">' + escHtml(r.centre_name || r.centre_code) + '</option>'; });
  });
}
function onWwwESACentreChange() {
  var st = document.getElementById('wwwESAState').value || '';
  var ce = document.getElementById('wwwESACentre').value || '';
  var tr = document.getElementById('wwwESATrainee');
  var en = document.getElementById('wwwESAEnrollment');
  tr.innerHTML = '<option value="">Select</option>';
  en.innerHTML = '<option value="">Select</option>';
  _WWW_ES_TRAINEES = [];
  if (!ce) return;
  apiGet('/www-trainees?state_code=' + encodeURIComponent(st) + '&centre_code=' + encodeURIComponent(ce) + '&limit=500').then(function(resp) {
    _WWW_ES_TRAINEES = (resp && resp.data) || [];
    _WWW_ES_TRAINEES.forEach(function(t) {
      tr.innerHTML += '<option value="' + t.id + '">' + escHtml(t.name || '') + '</option>';
      en.innerHTML += '<option value="' + t.id + '">' + escHtml(t.enrollment_no || '') + '</option>';
    });
  });
}
function onWwwESATraineeChange(fromEnrollment) {
  var srcId = fromEnrollment ? 'wwwESAEnrollment' : 'wwwESATrainee';
  var otherId = fromEnrollment ? 'wwwESATrainee' : 'wwwESAEnrollment';
  var id = parseInt(document.getElementById(srcId).value || '0', 10);
  document.getElementById(otherId).value = id || '';
  var t = _WWW_ES_TRAINEES.filter(function(x) { return x.id === id; })[0];
  if (!t) return;
  document.getElementById('wwwESAJoining').value     = t.enrollment_date ? _wwwSkFmtDate(t.enrollment_date) : '';
  document.getElementById('wwwESABatch').value       = t.batch_name || (t.batch_id ? '#' + t.batch_id : '');
  document.getElementById('wwwESAEnrollType').value  = t.enrollment_type || '';
  _wwwSkAutoFillLLPL(t, 'wwwESA');
  // also pull internal sakha summary
  apiGet('/www-internal-sakha/trainee/' + id).then(function(intRec) {
    if (intRec) {
      document.getElementById('wwwESAIntDate').value     = _wwwSkFmtDate(intRec.internal_pass_date);
      document.getElementById('wwwESAIntAttempts').value = (intRec.internal_attempts != null) ? intRec.internal_attempts : '';
    } else {
      document.getElementById('wwwESAIntDate').value = '';
      document.getElementById('wwwESAIntAttempts').value = '';
    }
  });
}
function onWwwESAPassedChange() {
  var v = (document.querySelector('input[name="wwwESAPassed"]:checked') || {}).value;
  document.getElementById('wwwESAYesDateWrap').style.display   = v === 'yes' ? '' : 'none';
  document.getElementById('wwwESAYesAttWrap').style.display    = v === 'yes' ? '' : 'none';
  document.getElementById('wwwESANoReasonWrap').style.display  = v === 'no'  ? '' : 'none';
}
function saveWwwES(isDraft) {
  var tid = parseInt(document.getElementById('wwwESATrainee').value || '0', 10);
  if (!tid && !_WWW_ES_EDIT_ID) { alert('Please select a Trainee.'); return; }
  var passed = (document.querySelector('input[name="wwwESAPassed"]:checked') || {}).value;
  var payload = {
    passed_external: passed === 'yes' ? true : (passed === 'no' ? false : null),
    external_pass_date: document.getElementById('wwwESAPassDate').value || null,
    external_attempts: document.getElementById('wwwESAAttempts').value ? parseInt(document.getElementById('wwwESAAttempts').value, 10) : null,
    fail_reason: document.getElementById('wwwESAReason').value || null,
    fail_reason_other: document.getElementById('wwwESAReasonOther').value || null,
    duration_months: document.getElementById('wwwESADurationMonths').value ? parseInt(document.getElementById('wwwESADurationMonths').value, 10) : null,
    date_of_transfer_to_sakha: document.getElementById('wwwESATransferDate').value || null,
    is_draft: !!isDraft
  };
  if (_WWW_ES_EDIT_ID) {
    apiPut('/www-external-sakha/' + _WWW_ES_EDIT_ID, payload)
      .then(function() { alert(isDraft ? 'Draft saved.' : 'External Sakha updated.'); _WWW_ES_EDIT_ID = null; navigateTo('wwwESList'); })
      .catch(function(err) { alert('Save failed: ' + (err && err.detail ? err.detail : err)); });
  } else {
    payload.trainee_id = tid;
    apiPost('/www-external-sakha', payload)
      .then(function() { alert(isDraft ? 'Draft saved.' : 'External Sakha submitted.'); navigateTo('wwwESList'); })
      .catch(function(err) { alert('Save failed: ' + (err && err.detail ? err.detail : err)); });
  }
}

