function _wwwSkVSet(eid, v) { var el = document.getElementById(eid); if (el) el.textContent = (v === null || v === undefined || v === '') ? '—' : v; }
function _wwwSkVCreated(t) { return t ? String(t).substring(0,19).replace('T', ' ') : null; }

function _wwwSkPassedPill(elId, v) {
  var el = document.getElementById(elId); if (!el) return;
  if (v === true)  el.innerHTML = '<span class="v-pill yes">Yes</span>';
  else if (v === false) el.innerHTML = '<span class="v-pill no">No</span>';
  else el.textContent = '—';
}

function loadWwwViewIS() {
  var id = _WWW_IS_VIEW_ID;
  if (!id) { navigateTo('wwwISList'); return; }
  apiGet('/www-internal-sakha/' + id).then(function(r) {
    _wwwSkVSet('vWISBcName',  r.name);
    _wwwSkVSet('vWISProfileName', r.name);
    _wwwSkVSet('vWISProfileEnrollment', r.enrollment_no);
    _wwwSkVSet('vWISName',   r.name);
    _wwwSkVSet('vWISMobile', r.mobile);
    _wwwSkVSet('vWISBatch',  r.batch_name || (r.batch_id ? '#' + r.batch_id : null));
    _wwwSkVSet('vWISState',  r.state_code);
    _wwwSkVSet('vWISCentre', r.centre_code);
    _wwwSkVSet('vWISType',   r.enrollment_type);
    _wwwSkVSet('vWISJoining', _wwwSkFmtDate(r.date_of_joining));
    _wwwSkVSet('vWISOnRoadStart', _wwwSkFmtDate(r.on_road_start_date));
    _wwwSkVSet('vWISOnRoadEnd',   _wwwSkFmtDate(r.on_road_end_date));
    _wwwSkVSet('vWISSelfStart',   _wwwSkFmtDate(r.self_drive_start_date));
    _wwwSkVSet('vWISSelfEnd',     _wwwSkFmtDate(r.self_drive_end_date));
    _wwwSkPassedPill('vWISPassed', r.passed_internal);
    _wwwSkVSet('vWISPassDate',     _wwwSkFmtDate(r.internal_pass_date));
    _wwwSkVSet('vWISAttempts',     r.internal_attempts);
    _wwwSkVSet('vWISDurationDays', r.duration_days);
    _wwwSkVSet('vWISReason',       r.fail_reason);
    _wwwSkVSet('vWISReasonOther',  r.fail_reason_other);
    _wwwSkVSet('vWISDurationMonths', r.duration_months);
    _wwwSkVSet('vWISCreated', _wwwSkVCreated(r.created_at));
    _wwwSkVSet('vWISId',      r.id);
    if (r.state_code) apiGet('/www-master/dropdown/states').then(function(rows) {
      var row = (rows || []).filter(function(x) { return x.state_code === r.state_code; })[0];
      if (row) _wwwSkVSet('vWISState', row.state_name);
    });
    if (r.centre_code) apiGet('/www-master/dropdown/centres?state_code=' + encodeURIComponent(r.state_code || '')).then(function(rows) {
      var row = (rows || []).filter(function(x) { return x.centre_code === r.centre_code; })[0];
      if (row) _wwwSkVSet('vWISCentre', row.centre_name);
    });
  }).catch(function(err) {
    alert('Failed to load: ' + (err && err.detail ? err.detail : err));
    navigateTo('wwwISList');
  });
}

