// === AAG picker cascade + hard-refresh hook — 2026-06-16 ===
// (1) Unscoped batch loader for the AAG picker. The original
//     _loadAkAlumniBatchesInto hard-filters to status=Inactive ("Alumni
//     Batches") which empties the dropdown on any Centre that has no
//     Inactive batches yet. The AAG picker only uses Batch as a filter
//     on top of the eligible-alumni table, so dropping the status scope
//     just lets the user actually see the centre's batches.
function _loadAagPickerBatchesInto(stateCode, centreCode) {
  var sel = document.getElementById('aagPickerBatch');
  if (!sel) return;
  var prev = sel.value;
  var p = { limit: 200 };
  if (stateCode)  p.state_code  = stateCode;
  if (centreCode) p.centre_code = centreCode;
  apiAkBatchList(p).then(function(result) {
    var list = (result && result.data) || result || [];
    var seen = {};
    var html = '<option value="">-- All Batches --</option>';
    list.forEach(function(b) {
      var label = b.name || b.batch_name || ('Batch ' + b.id);
      if (seen[label]) return; seen[label] = 1;
      var esc  = (typeof escHtml === 'function') ? escHtml(label) : label;
      var stat = (b.status && b.status !== 'Active') ? (' (' + b.status + ')') : '';
      html += '<option value="' + esc + '">' + esc + stat + '</option>';
    });
    sel.innerHTML = html;
    if (prev) sel.value = prev;
  }).catch(function() {
    sel.innerHTML = '<option value="">-- All Batches --</option>';
  });
}

// (2) Page-init for #page-akAddAag — fires on every navigateTo to the
//     page, including hard-refresh landings, not just the
//     openAddAagPicker click. Idempotent: _populateAkStatesInto guards
//     against duplicate XHRs once states are loaded.
function _initAagPickerPage() {
  var sEl = document.getElementById('aagPickerState');
  var cEl = document.getElementById('aagPickerCentre');
  var role = (currentUser && currentUser.role) || '';
  if ((role === 'district_lead' || role === 'pi') &&
      currentUser && currentUser.state_code && currentUser.centre_code) {
    if (typeof _lockAkFiltersForDlPi === 'function') {
      _lockAkFiltersForDlPi('aagPickerState', 'aagPickerCentre');
    }
    _loadAagPickerBatchesInto(currentUser.state_code, currentUser.centre_code);
    if (typeof loadAagEligibleAlumni === 'function') {
      [200, 600, 1500].forEach(function(d) {
        setTimeout(function() { loadAagEligibleAlumni(1); }, d);
      });
    }
    return;
  }
  if (role === 'state_lead' && currentUser && currentUser.state_code) {
    if (cEl) cEl.innerHTML = '<option value="">-- All Centres --</option>';
    if (typeof _lockAkFiltersForDlPi === 'function') {
      _lockAkFiltersForDlPi('aagPickerState', 'aagPickerCentre');
    }
    setTimeout(function() {
      if (sEl) try { sEl.dispatchEvent(new Event('change', { bubbles: true })); } catch (e) {}
    }, 1400);
    return;
  }
  // Default (admin / no scoped role): populate State, leave Centre empty
  if (typeof _populateAkStatesInto === 'function') {
    _populateAkStatesInto('aagPickerState', '-- Select State --');
  }
  _loadAagPickerBatchesInto('', '');
  if (cEl) cEl.innerHTML = '<option value="">-- All Centres --</option>';
  if (typeof _aagPickerEmptyState === 'function') _aagPickerEmptyState();
}

// === WWW Employment — list + picker + modal + view + edit (2026-06-16) ===
var _WWW_EMP_SELECTED_TRAINEE = null;
var _WWW_EMP_PENDING_DOCS = [];
var _WWW_EMP_VIEW_ID = null;
var _WWW_EMP_EDIT_ID = null;
var _WWW_EMP_FILTER_DEBOUNCE = null;
var _wwwEmpCurrentPage = 1;

function _wwwEmpFmtDate(s) {
  if (!s) return '';
  try {
    var d = new Date(s);
    if (isNaN(d.getTime())) return s;
    var dd = String(d.getDate()).padStart(2,'0');
    var mm = String(d.getMonth()+1).padStart(2,'0');
    return dd + '-' + mm + '-' + d.getFullYear();
  } catch(e) { return s; }
}

function _wwwEmpFillStates(selId, defaultLabel) {
  var sel = document.getElementById(selId); if (!sel) return;
  apiGet('/www-master/dropdown/states').then(function(states) {
    var html = '<option value="">' + (defaultLabel || '-- Select State --') + '</option>';
    (states || []).forEach(function(s) {
      html += '<option value="' + escHtml(s.state_code) + '">' + escHtml(s.state_name) + '</option>';
    });
    sel.innerHTML = html;
  }).catch(function() {
    sel.innerHTML = '<option value="">' + (defaultLabel || '-- Select State --') + '</option>';
  });
}

function _wwwEmpFillCentres(selId, stateCode, defaultLabel) {
  var sel = document.getElementById(selId); if (!sel) return;
  sel.innerHTML = '<option value="">' + (defaultLabel || '-- Select Centre --') + '</option>';
  if (!stateCode) return;
  apiGet('/www-master/dropdown/centres?state_code=' + encodeURIComponent(stateCode)).then(function(rows) {
    var html = '<option value="">' + (defaultLabel || '-- Select Centre --') + '</option>';
    (rows || []).forEach(function(r) {
      html += '<option value="' + escHtml(r.centre_code) + '">' + escHtml(r.centre_name) + '</option>';
    });
    sel.innerHTML = html;
  }).catch(function() {});
}

function _wwwEmpFillBatches(selId, stateCode, centreCode, defaultLabel) {
  var sel = document.getElementById(selId); if (!sel) return;
  var url = '/www-master/dropdown/batches';
  var qs = [];
  if (stateCode)  qs.push('state_code='  + encodeURIComponent(stateCode));
  if (centreCode) qs.push('centre_code=' + encodeURIComponent(centreCode));
  if (qs.length) url += '?' + qs.join('&');
  apiGet(url).then(function(rows) {
    var html = '<option value="">' + (defaultLabel || 'All Batches') + '</option>';
    (rows || []).forEach(function(r) {
      html += '<option value="' + r.id + '">' + escHtml(r.batch_name || r.name || ('Batch ' + r.id)) + '</option>';
    });
    sel.innerHTML = html;
  }).catch(function() {});
}

// ============== EMPLOYMENT LIST ==============
function _initWwwEmploymentListPage() {
  _wwwEmpFillBatches('wwwEmpFilterBatch', '', '', 'All Batches');
  loadWwwEmploymentList(1);
}
function _debounceWwwEmpFilter() {
  clearTimeout(_WWW_EMP_FILTER_DEBOUNCE);
  _WWW_EMP_FILTER_DEBOUNCE = setTimeout(function() { loadWwwEmploymentList(1); }, 350);
}
function resetWwwEmpFilters() {
  ['wwwEmpFilterBatch','wwwEmpFilterTypeOfJob','wwwEmpFilterMinSalary','wwwEmpFilterName','wwwEmpFilterEnrollmentType'].forEach(function(id) {
    var el = document.getElementById(id); if (el) el.value = '';
  });
  loadWwwEmploymentList(1);
}
function loadWwwEmploymentList(page) {
  if (typeof page === 'number') _wwwEmpCurrentPage = page;
  var p = { page: _wwwEmpCurrentPage, limit: parseInt((document.getElementById('wwwEmpLimit') || {}).value || '10', 10) };
  var b = document.getElementById('wwwEmpFilterBatch'); if (b && b.value) p.batch_id = b.value;
  var tj = document.getElementById('wwwEmpFilterTypeOfJob'); if (tj && tj.value) p.type_of_job = tj.value;
  var ms = document.getElementById('wwwEmpFilterMinSalary'); if (ms && ms.value) p.min_salary = ms.value;
  var n = document.getElementById('wwwEmpFilterName'); if (n && n.value) p.name = n.value;
  var et = document.getElementById('wwwEmpFilterEnrollmentType'); if (et && et.value) p.type_of_enrollment = et.value;
  var qs = Object.keys(p).map(function(k) { return k + '=' + encodeURIComponent(p[k]); }).join('&');
  apiGet('/www-employment?' + qs).then(function(res) {
    var tb = document.getElementById('wwwEmpTBody'); if (!tb) return;
    var rows = (res && res.data) || [];
    if (!rows.length) {
      tb.innerHTML = '<tr><td colspan="9" style="text-align:center;color:#999;padding:30px;">No employment records found.</td></tr>';
    } else {
      tb.innerHTML = rows.map(function(r) {
        var status = (r.is_active === false) ? '<span style="color:#a94442;">Inactive</span>' : '<span style="color:#1e7e34;">Active</span>';
        return '<tr>' +
          '<td>' + escHtml(r.enrollment_no || '') + '</td>' +
          '<td>' + escHtml(r.name || '') + '</td>' +
          '<td>' + escHtml(r.batch_name || '') + '</td>' +
          '<td>' + escHtml(r.trainee_enrollment_type || r.type_of_enrollment || '') + '</td>' +
          '<td>' + escHtml(r.type_of_job || '') + '</td>' +
          '<td>' + _wwwEmpFmtDate(r.date_of_job) + '</td>' +
          '<td>' + (r.salary != null ? Number(r.salary).toLocaleString() : '') + '</td>' +
          '<td>' + status + '</td>' +
          '<td style="white-space:nowrap;">' +
            '<i class="fas fa-eye" style="cursor:pointer;color:#732269;margin-right:10px;" onclick="viewWwwEmployment(' + r.id + ')" title="View"></i>' +
            '<i class="fas fa-edit" style="cursor:pointer;color:#732269;margin-right:10px;" onclick="editWwwEmployment(' + r.id + ')" title="Edit"></i>' +
            '<i class="fas fa-trash" style="cursor:pointer;color:#c0392b;" onclick="deleteWwwEmployment(' + r.id + ')" title="Delete"></i>' +
          '</td></tr>';
      }).join('');
    }
    // Pagination
    var pag = document.getElementById('wwwEmpPagination');
    if (pag) {
      var total = (res && res.total) || 0; var lim = p.limit; var pages = Math.max(1, Math.ceil(total / lim));
      var s = Math.max(1, _wwwEmpCurrentPage - 2), e = Math.min(pages, s + 4);
      var html = 'Showing ' + ((_wwwEmpCurrentPage - 1) * lim + 1) + '-' + Math.min(total, _wwwEmpCurrentPage * lim) + ' of ' + total + ' &nbsp; ';
      html += '<button onclick="loadWwwEmploymentList(' + Math.max(1, _wwwEmpCurrentPage - 1) + ')">&lsaquo;</button>';
      for (var i = s; i <= e; i++) {
        html += '<button onclick="loadWwwEmploymentList(' + i + ')"' + (i === _wwwEmpCurrentPage ? ' style="background:#732269;color:#fff;border-color:#732269;"' : '') + '>' + i + '</button>';
      }
      html += '<button onclick="loadWwwEmploymentList(' + Math.min(pages, _wwwEmpCurrentPage + 1) + ')">&rsaquo;</button>';
      pag.innerHTML = html;
    }
  }).catch(function() {
    var tb = document.getElementById('wwwEmpTBody');
    if (tb) tb.innerHTML = '<tr><td colspan="9" style="text-align:center;color:#a94442;padding:30px;">Failed to load.</td></tr>';
  });
}
function exportWwwEmploymentCsv() {
  var tb = document.getElementById('wwwEmpTBody');
  if (!tb) return;
  var rows = tb.querySelectorAll('tr');
  var hdr = ['Enrollment No','Name','Batch','Type of Enrollment','Type of Job','Date of Job','Salary','Status'];
  var csv = hdr.join(',') + '\n';
  rows.forEach(function(tr) {
    var cells = tr.querySelectorAll('td');
    if (cells.length < 8) return;
    var vals = [];
    for (var i=0; i<8; i++) vals.push('"' + (cells[i].innerText || '').replace(/"/g,'""') + '"');
    csv += vals.join(',') + '\n';
  });
  var blob = new Blob([csv], { type: 'text/csv;charset=utf-8;' });
  var a = document.createElement('a');
  a.href = URL.createObjectURL(blob); a.download = 'employment_list.csv'; a.click();
}

// ============== ADD EMPLOYMENT — trainee picker ==============
function _initWwwEmpAddPage() {
  _WWW_EMP_SELECTED_TRAINEE = null;
  _WWW_EMP_PENDING_DOCS = [];
  ['wwwEmpAddCentre','wwwEmpAddFY','wwwEmpAddType','wwwEmpAddSearch'].forEach(function(id) {
    var el = document.getElementById(id); if (el) el.value = '';
  });
  var c = document.getElementById('wwwEmpAddCentre'); if (c) c.innerHTML = '<option value="">Select Centre</option>';
  _wwwEmpFillStates('wwwEmpAddState', 'Select State');
  var pb = document.getElementById('wwwEmpProceedBtn'); if (pb) pb.disabled = true;
  var wrap = document.getElementById('wwwEmpAddTraineesWrap'); if (wrap) wrap.style.display = 'none';
  var hint = document.getElementById('wwwEmpAddHint');
  if (hint) { hint.style.display = ''; hint.innerHTML = 'Pick <b>State</b> and <b>Centre</b> above to load trainees.'; }
  var tb = document.getElementById('wwwEmpAddBody'); if (tb) tb.innerHTML = '';
}
function onWwwEmpAddStateChange() {
  var sc = (document.getElementById('wwwEmpAddState') || {}).value;
  _wwwEmpFillCentres('wwwEmpAddCentre', sc, 'Select Centre');
  loadWwwEmpEligibleTrainees();
}
function onWwwEmpAddCentreChange() {
  loadWwwEmpEligibleTrainees();
}
function loadWwwEmpEligibleTrainees() {
  _WWW_EMP_SELECTED_TRAINEE = null;
  var pb = document.getElementById('wwwEmpProceedBtn'); if (pb) pb.disabled = true;
  var sc = (document.getElementById('wwwEmpAddState') || {}).value;
  var cc = (document.getElementById('wwwEmpAddCentre') || {}).value;
  var fy = (document.getElementById('wwwEmpAddFY') || {}).value;
  var tp = (document.getElementById('wwwEmpAddType') || {}).value;
  var nm = (document.getElementById('wwwEmpAddSearch') || {}).value;
  var wrap = document.getElementById('wwwEmpAddTraineesWrap');
  var hint = document.getElementById('wwwEmpAddHint');
  var tb = document.getElementById('wwwEmpAddBody');
  if (!sc || !cc) {
    if (wrap) wrap.style.display = 'none';
    if (hint) { hint.style.display = ''; hint.innerHTML = 'Pick <b>State</b> and <b>Centre</b> above to load trainees.'; }
    if (tb) tb.innerHTML = '';
    return;
  }
  var qs = ['state_code=' + encodeURIComponent(sc), 'centre_code=' + encodeURIComponent(cc)];
  if (fy) qs.push('financial_year=' + encodeURIComponent(fy));
  if (tp) qs.push('type_of_enrollment=' + encodeURIComponent(tp));
  if (nm) qs.push('name=' + encodeURIComponent(nm));
  apiGet('/www-employment/eligible-trainees?' + qs.join('&')).then(function(rows) {
    if (!rows || !rows.length) {
      if (wrap) wrap.style.display = 'none';
      if (hint) { hint.style.display = ''; hint.innerHTML = 'No eligible trainees found for the selected State + Centre.'; }
      if (tb) tb.innerHTML = '';
      return;
    }
    if (hint) hint.style.display = 'none';
    if (wrap) wrap.style.display = '';
    tb.innerHTML = rows.map(function(r) {
      var loc = (r.centre_name || '') + (r.centre_name && r.state_name ? ', ' : '') + (r.state_name || '');
      var nameSafe = (r.name || '').replace(/"/g, '&quot;');
      return '<tr>' +
        '<td style="text-align:center;"><input type="radio" name="wwwEmpPickerRadio" onclick="_wwwEmpPickTrainee(' + r.id + ', \'' + nameSafe + '\', \'' + escHtml(r.enrollment_no || '') + '\', \'' + escHtml(r.batch_name || '') + '\', \'' + escHtml(r.enrollment_type || '') + '\')"></td>' +
        '<td>' + escHtml(r.enrollment_no || '') + '</td>' +
        '<td>' + escHtml(r.financial_year || '') + '</td>' +
        '<td>' + escHtml(r.enrollment_type || '') + '</td>' +
        '<td>' + escHtml(r.name || '') + '</td>' +
        '<td>' + escHtml(loc) + '</td>' +
        '<td>' + escHtml(r.batch_name || '') + '</td>' +
        '<td>' + escHtml(r.status || '') + '</td>' +
      '</tr>';
    }).join('');
  }).catch(function() {
    if (wrap) wrap.style.display = 'none';
    if (hint) { hint.style.display = ''; hint.innerHTML = '<span style="color:#a94442;">Failed to load trainees.</span>'; }
    if (tb) tb.innerHTML = '';
  });
}

function _wwwEmpPickTrainee(id, name, enrollNo, batchName, enrollType) {
  _WWW_EMP_SELECTED_TRAINEE = { id: id, name: name, enrollment_no: enrollNo, batch_name: batchName, enrollment_type: enrollType };
  document.getElementById('wwwEmpProceedBtn').disabled = false;
}

// ============== ADD EMPLOYMENT DETAILS MODAL ==============
function openWwwEmpDetailsModal() {
  if (!_WWW_EMP_SELECTED_TRAINEE) { alert('Please select a trainee first.'); return; }
  var t = _WWW_EMP_SELECTED_TRAINEE;
  document.getElementById('wwwEmpModalTName').textContent = t.name || '—';
  document.getElementById('wwwEmpModalTEnroll').textContent = t.enrollment_no || '—';
  document.getElementById('wwwEmpModalTMeta').textContent = [t.batch_name, t.enrollment_type].filter(Boolean).join(' / ');
  ['wwwEmpModalStatus','wwwEmpModalStatusOther','wwwEmpModalTypeOfJob','wwwEmpModalWhere','wwwEmpModalOutside','wwwEmpModalDate','wwwEmpModalSalary','wwwEmpModalDocType','wwwEmpModalDocFile'].forEach(function(id) {
    var el = document.getElementById(id); if (el) el.value = '';
  });
  _WWW_EMP_PENDING_DOCS = [];
  _wwwEmpRenderPendingDocs();
  document.getElementById('wwwEmpDetailsModal').style.display = 'flex';
}
function closeWwwEmpDetailsModal() {
  document.getElementById('wwwEmpDetailsModal').style.display = 'none';
}
function onWwwEmpModalStatusChange() {
  var v = (document.getElementById('wwwEmpModalStatus') || {}).value;
  var other = document.getElementById('wwwEmpModalStatusOther');
  if (other) other.parentElement.style.opacity = (v === 'Other' || v === 'On Job test') ? '1' : '0.5';
}
function addWwwEmpDoc() {
  var dt = (document.getElementById('wwwEmpModalDocType') || {}).value;
  var fn = (document.getElementById('wwwEmpModalDocFile') || {}).value;
  if (!dt || !fn) { alert('Pick a document type and file name.'); return; }
  _WWW_EMP_PENDING_DOCS.push({ document_type: dt, file_name: fn });
  document.getElementById('wwwEmpModalDocType').value = '';
  document.getElementById('wwwEmpModalDocFile').value = '';
  _wwwEmpRenderPendingDocs();
}
function _wwwEmpRemoveDoc(idx) {
  _WWW_EMP_PENDING_DOCS.splice(idx, 1);
  _wwwEmpRenderPendingDocs();
}
function _wwwEmpRenderPendingDocs() {
  var tb = document.getElementById('wwwEmpModalDocsBody');
  if (!_WWW_EMP_PENDING_DOCS.length) {
    tb.innerHTML = '<tr><td colspan="4" style="text-align:center;color:#999;padding:14px;">No documents added.</td></tr>';
    return;
  }
  tb.innerHTML = _WWW_EMP_PENDING_DOCS.map(function(d, i) {
    return '<tr><td>' + (i+1) + '</td><td>' + escHtml(d.document_type) + '</td><td>' + escHtml(d.file_name) + '</td>' +
           '<td><i class="fas fa-trash" style="cursor:pointer;color:#c0392b;" onclick="_wwwEmpRemoveDoc(' + i + ')"></i></td></tr>';
  }).join('');
}
function saveWwwEmploymentDetails() {
  if (!_WWW_EMP_SELECTED_TRAINEE) { alert('No trainee selected.'); return; }
  var payload = {
    trainee_id: _WWW_EMP_SELECTED_TRAINEE.id,
    financial_year: (document.getElementById('wwwEmpAddFY') || {}).value || null,
    type_of_enrollment: (document.getElementById('wwwEmpAddType') || {}).value || _WWW_EMP_SELECTED_TRAINEE.enrollment_type || null,
    current_status: (document.getElementById('wwwEmpModalStatus') || {}).value || null,
    current_status_other: (document.getElementById('wwwEmpModalStatusOther') || {}).value || null,
    type_of_job: (document.getElementById('wwwEmpModalTypeOfJob') || {}).value || null,
    where_location: (document.getElementById('wwwEmpModalWhere') || {}).value || null,
    outside_location: (document.getElementById('wwwEmpModalOutside') || {}).value || null,
    date_of_job: (document.getElementById('wwwEmpModalDate') || {}).value || null,
    salary: (document.getElementById('wwwEmpModalSalary') || {}).value ? parseFloat((document.getElementById('wwwEmpModalSalary') || {}).value) : null,
    is_active: true
  };
  if (!payload.current_status || !payload.type_of_job || !payload.date_of_job || !payload.salary) {
    alert('Please fill the required fields (Status, Type of Job, Date of Job, Salary).'); return;
  }
  apiPost('/www-employment', payload).then(function(res) {
    var newId = res.id;
    var docPromises = _WWW_EMP_PENDING_DOCS.map(function(d) { return apiPost('/www-employment/' + newId + '/documents', d); });
    Promise.all(docPromises).then(function() {
      alert('Employment record added.');
      closeWwwEmpDetailsModal();
      navigateTo('wwwEmploymentList');
    }).catch(function() { alert('Saved record but some documents failed.'); navigateTo('wwwEmploymentList'); });
  }).catch(function(err) {
    alert('Failed to save: ' + (err && err.detail ? err.detail : err));
  });
}

// ============== VIEW + EDIT + DELETE ==============
function viewWwwEmployment(id) { _WWW_EMP_VIEW_ID = id; navigateTo('wwwViewEmployment'); }
function editWwwEmployment(id) { _WWW_EMP_EDIT_ID = id; navigateTo('wwwEditEmployment'); }
function deleteWwwEmployment(id) {
  if (!confirm('Delete this employment record?')) return;
  apiDelete('/www-employment/' + id).then(function() { loadWwwEmploymentList(_wwwEmpCurrentPage); }).catch(function(err) { alert('Delete failed: ' + (err && err.detail ? err.detail : err)); });
}
function loadWwwViewEmployment() {
  var id = _WWW_EMP_VIEW_ID; if (!id) { navigateTo('wwwEmploymentList'); return; }
  apiGet('/www-employment/' + id).then(function(r) {
    var name = r.name || '—';
    document.getElementById('wwwViewEmpName').textContent  = name;
    document.getElementById('wwwViewEmpName2').textContent = name.toLowerCase();
    document.getElementById('wwwViewEmpEnroll').textContent = r.enrollment_no || '—';
    document.getElementById('wwwViewEmpState').textContent  = r.state_name || '';
    document.getElementById('wwwViewEmpBatch').textContent  = r.batch_name || '';
    var stEl = document.getElementById('wwwViewEmpStatus');
    if (stEl) { stEl.className = 'v-badge' + (r.is_active === false ? ' red' : ''); stEl.textContent = r.is_active === false ? 'Inactive' : 'Active'; }
    document.getElementById('wwwViewEmpTopName').textContent   = name;
    document.getElementById('wwwViewEmpTopEnroll').textContent = r.enrollment_no || '—';
    document.getElementById('wwwViewEmpTopType').textContent   = ' ' + (r.trainee_enrollment_type || r.type_of_enrollment || '—');
    document.getElementById('wwwViewEmpTopDoj').textContent    = _wwwEmpFmtDate(r.date_of_joining);
    // Demographic
    document.getElementById('wvDemName').textContent     = name;
    document.getElementById('wvDemState').textContent    = r.state_name || '—';
    document.getElementById('wvDemDistrict').textContent = r.district_name || '—';
    document.getElementById('wvDemCentre').textContent   = r.centre_name || '—';
    document.getElementById('wvDemFY').textContent       = r.financial_year || '—';
    document.getElementById('wvDemType').textContent     = r.trainee_enrollment_type || r.type_of_enrollment || '—';
    document.getElementById('wvDemDoj').textContent      = _wwwEmpFmtDate(r.date_of_joining);
    // LL Details
    document.getElementById('wvLLBatch').textContent    = r.batch_name || '—';
    document.getElementById('wvLLDate').textContent     = _wwwEmpFmtDate(r.ll_date);
    document.getElementById('wvLLNumber').textContent   = r.ll_number || '—';
    document.getElementById('wvLLAttempts').textContent = (r.ll_attempts != null) ? r.ll_attempts : '—';
    // PL Details
    document.getElementById('wvPLDate').textContent     = _wwwEmpFmtDate(r.pl_date);
    document.getElementById('wvPLNumber').textContent   = r.pl_number || '—';
    document.getElementById('wvPLAttempts').textContent = (r.pl_attempts != null) ? r.pl_attempts : '—';
    // Sakha Details
    document.getElementById('wvISDate').textContent     = _wwwEmpFmtDate(r.internal_pass_date);
    document.getElementById('wvISAttempts').textContent = (r.internal_attempts != null) ? r.internal_attempts : '—';
    document.getElementById('wvESDate').textContent     = _wwwEmpFmtDate(r.external_pass_date);
    document.getElementById('wvESAttempts').textContent = (r.external_attempts != null) ? r.external_attempts : '—';
    // Employment Details
    document.getElementById('wvEmpStatus').textContent      = r.current_status || '—';
    document.getElementById('wvEmpStatusOther').textContent = r.current_status_other || '—';
    document.getElementById('wvEmpType').textContent        = r.type_of_job || '—';
    document.getElementById('wvEmpWhere').textContent       = r.where_location || '—';
    document.getElementById('wvEmpOutside').textContent     = r.outside_location || '—';
    document.getElementById('wvEmpDoj').textContent         = _wwwEmpFmtDate(r.date_of_job);
    document.getElementById('wvEmpSalary').textContent      = r.salary != null ? Number(r.salary).toLocaleString() : '—';
    // Documents
    var docs = r.documents || [];
    var tb = document.getElementById('wwwViewEmpDocsBody');
    if (!docs.length) {
      tb.innerHTML = '<tr><td colspan="5" style="text-align:center;color:#999;padding:14px;">No documents.</td></tr>';
    } else {
      tb.innerHTML = docs.map(function(d, i) {
        return '<tr><td>' + (i+1) + '</td><td>' + escHtml(d.document_type || '') + '</td>' +
               '<td><a style="color:#732269;text-decoration:underline;">' + escHtml(d.file_name || '') + '</a></td>' +
               '<td>' + _wwwEmpFmtDate(d.uploaded_at) + '</td>' +
               '<td><i class="fas fa-eye" style="cursor:pointer;color:#732269;"></i></td></tr>';
      }).join('');
    }
  }).catch(function(err) {
    alert('Failed to load: ' + (err && err.detail ? err.detail : err));
    navigateTo('wwwEmploymentList');
  });
}


