// === WWW Walkout — list + picker + walkout/walkin modals + view + edit (2026-06-16) ===
var _WWW_WO_SELECTED_TRAINEE = null;
var _WWW_WO_VIEW_ID = null;
var _WWW_WO_EDIT_ID = null;
var _WWW_WO_WALKIN_ID = null;
var _WWW_WO_FILTER_DEBOUNCE = null;
var _wwwWoCurrentPage = 1;

function _wwwWoFmtDate(s) {
  if (!s) return '-';
  try {
    var d = new Date(s); if (isNaN(d.getTime())) return s;
    var dd = String(d.getDate()).padStart(2,'0');
    var mm = String(d.getMonth()+1).padStart(2,'0');
    return dd + '-' + mm + '-' + d.getFullYear();
  } catch(e) { return s; }
}

function _wwwWoFillStates(selId) {
  var sel = document.getElementById(selId); if (!sel) return;
  apiGet('/www-master/dropdown/states').then(function(states) {
    var html = '<option value="">Select State</option>';
    (states || []).forEach(function(s) {
      html += '<option value="' + escHtml(s.state_code) + '">' + escHtml(s.state_name) + '</option>';
    });
    sel.innerHTML = html;
  }).catch(function() {});
}

function _wwwWoFillCentres(selId, stateCode) {
  var sel = document.getElementById(selId); if (!sel) return;
  sel.innerHTML = '<option value="">Select Centre</option>';
  if (!stateCode) return;
  apiGet('/www-master/dropdown/centres?state_code=' + encodeURIComponent(stateCode)).then(function(rows) {
    var html = '<option value="">Select Centre</option>';
    (rows || []).forEach(function(r) {
      html += '<option value="' + escHtml(r.centre_code) + '">' + escHtml(r.centre_name) + '</option>';
    });
    sel.innerHTML = html;
  }).catch(function() {});
}

function _wwwWoFillBatches(selId, stateCode, centreCode, defaultLabel) {
  var sel = document.getElementById(selId); if (!sel) return;
  var url = '/www-master/dropdown/batches';
  var qs = [];
  if (stateCode)  qs.push('state_code='  + encodeURIComponent(stateCode));
  if (centreCode) qs.push('centre_code=' + encodeURIComponent(centreCode));
  if (qs.length) url += '?' + qs.join('&');
  apiGet(url).then(function(rows) {
    var html = '<option value="">' + (defaultLabel || 'Select Batch') + '</option>';
    (rows || []).forEach(function(r) {
      html += '<option value="' + r.id + '">' + escHtml(r.batch_name || r.name || ('Batch ' + r.id)) + '</option>';
    });
    sel.innerHTML = html;
  }).catch(function() {});
}

// ============== WALKOUT LIST ==============
function _initWwwWalkoutListPage() {
  _wwwWoFillBatches('wwwWoFilterBatch', '', '', 'All Batches');
  loadWwwWalkoutList(1);
}
function _debounceWwwWoFilter() {
  clearTimeout(_WWW_WO_FILTER_DEBOUNCE);
  _WWW_WO_FILTER_DEBOUNCE = setTimeout(function() { loadWwwWalkoutList(1); }, 350);
}
function resetWwwWoFilters() {
  ['wwwWoFilterBatch','wwwWoFilterStage','wwwWoFilterName','wwwWoFilterStatus','wwwWoFilterFrom','wwwWoFilterTo'].forEach(function(id) {
    var el = document.getElementById(id); if (el) el.value = '';
  });
  loadWwwWalkoutList(1);
}
function loadWwwWalkoutList(page) {
  if (typeof page === 'number') _wwwWoCurrentPage = page;
  var p = { page: _wwwWoCurrentPage, limit: parseInt((document.getElementById('wwwWoLimit') || {}).value || '10', 10) };
  var b = document.getElementById('wwwWoFilterBatch'); if (b && b.value) p.batch_id = b.value;
  var st = document.getElementById('wwwWoFilterStage'); if (st && st.value) p.walkout_stage = st.value;
  var n = document.getElementById('wwwWoFilterName'); if (n && n.value) p.name = n.value;
  var s = document.getElementById('wwwWoFilterStatus'); if (s && s.value) p.status = s.value;
  var f = document.getElementById('wwwWoFilterFrom'); if (f && f.value) p.from_date = f.value;
  var t = document.getElementById('wwwWoFilterTo'); if (t && t.value) p.to_date = t.value;
  var qs = Object.keys(p).map(function(k) { return k + '=' + encodeURIComponent(p[k]); }).join('&');
  apiGet('/www-walkout?' + qs).then(function(res) {
    var tb = document.getElementById('wwwWoTBody'); if (!tb) return;
    var rows = (res && res.data) || [];
    if (!rows.length) {
      tb.innerHTML = '<tr><td colspan="9" style="text-align:center;color:#999;padding:30px;">No walkout records found.</td></tr>';
    } else {
      tb.innerHTML = rows.map(function(r) {
        var statusBadge = r.status === 'Walkin'
          ? '<span style="background:#d5f4d8;color:#1e7a2f;padding:2px 10px;border-radius:12px;font-size:12px;font-weight:600;">Walkin</span>'
          : '<span style="background:#f8d7da;color:#a94442;padding:2px 10px;border-radius:12px;font-size:12px;font-weight:600;">Walkout</span>';
        return '<tr>' +
          '<td>' + escHtml(r.enrollment_no || '') + '</td>' +
          '<td>' + escHtml(r.name || '') + '</td>' +
          '<td>' + escHtml(r.batch_name || '') + '</td>' +
          '<td>' + escHtml(r.trainee_mobile || '') + '</td>' +
          '<td>' + escHtml(r.walkout_stage || '') + '</td>' +
          '<td>' + _wwwWoFmtDate(r.walkout_date) + '</td>' +
          '<td>' + (r.walkin_date ? _wwwWoFmtDate(r.walkin_date) : '-') + '</td>' +
          '<td>' + statusBadge + '</td>' +
          '<td style="white-space:nowrap;">' +
            '<i class="fas fa-eye" style="cursor:pointer;color:#732269;margin-right:10px;" onclick="viewWwwWalkout(' + r.id + ')" title="View"></i>' +
            '<i class="fas fa-edit" style="cursor:pointer;color:#732269;margin-right:10px;" onclick="editWwwWalkout(' + r.id + ')" title="Edit"></i>' +
            '<i class="fas fa-trash" style="cursor:pointer;color:#c0392b;" onclick="deleteWwwWalkout(' + r.id + ')" title="Delete"></i>' +
          '</td></tr>';
      }).join('');
    }
    var pag = document.getElementById('wwwWoPagination');
    if (pag) {
      var total = (res && res.total) || 0; var lim = p.limit; var pages = Math.max(1, Math.ceil(total / lim));
      var s = Math.max(1, _wwwWoCurrentPage - 2), e = Math.min(pages, s + 4);
      var html = 'Showing ' + (total ? ((_wwwWoCurrentPage - 1) * lim + 1) : 0) + '-' + Math.min(total, _wwwWoCurrentPage * lim) + ' of ' + total + ' &nbsp; ';
      html += '<button onclick="loadWwwWalkoutList(' + Math.max(1, _wwwWoCurrentPage - 1) + ')">&lsaquo;</button>';
      for (var i = s; i <= e; i++) {
        html += '<button onclick="loadWwwWalkoutList(' + i + ')"' + (i === _wwwWoCurrentPage ? ' style="background:#732269;color:#fff;border-color:#732269;"' : '') + '>' + i + '</button>';
      }
      html += '<button onclick="loadWwwWalkoutList(' + Math.min(pages, _wwwWoCurrentPage + 1) + ')">&rsaquo;</button>';
      pag.innerHTML = html;
    }
  }).catch(function() {
    var tb = document.getElementById('wwwWoTBody');
    if (tb) tb.innerHTML = '<tr><td colspan="9" style="text-align:center;color:#a94442;padding:30px;">Failed to load.</td></tr>';
  });
}
function exportWwwWalkoutCsv() {
  var tb = document.getElementById('wwwWoTBody'); if (!tb) return;
  var rows = tb.querySelectorAll('tr');
  var hdr = ['Enrollment No','Name','Batch','Mobile No','Stage of Walkout','Date of Walk-out','Date of Walk-In','Status'];
  var csv = hdr.join(',') + '\n';
  rows.forEach(function(tr) {
    var cells = tr.querySelectorAll('td');
    if (cells.length < 8) return;
    var vals = [];
    for (var i=0; i<8; i++) vals.push('"' + (cells[i].innerText || '').replace(/"/g,'""') + '"');
    csv += vals.join(',') + '\n';
  });
  var blob = new Blob([csv], { type: 'text/csv;charset=utf-8;' });
  var a = document.createElement('a');
  a.href = URL.createObjectURL(blob); a.download = 'walkout_list.csv'; a.click();
}

// ============== ADD WALKOUT — trainee picker ==============
function _initWwwAddWalkoutPage() {
  _WWW_WO_SELECTED_TRAINEE = null;
  ['wwwWoAddCentre','wwwWoAddBatch','wwwWoAddSearch'].forEach(function(id) {
    var el = document.getElementById(id); if (el) el.value = '';
  });
  var cEl = document.getElementById('wwwWoAddCentre'); if (cEl) cEl.innerHTML = '<option value="">Select Centre</option>';
  var bEl = document.getElementById('wwwWoAddBatch'); if (bEl) bEl.innerHTML = '<option value="">Select Batch</option>';
  _wwwWoFillStates('wwwWoAddState');
  var pb = document.getElementById('wwwWoProceedBtn'); if (pb) pb.disabled = true;
  var wrap = document.getElementById('wwwWoAddTraineesWrap'); if (wrap) wrap.style.display = 'none';
  var hint = document.getElementById('wwwWoAddHint');
  if (hint) { hint.style.display = ''; hint.innerHTML = 'Pick <b>State</b> and <b>Centre</b> above to load trainees.'; }
  var tb = document.getElementById('wwwWoAddBody'); if (tb) tb.innerHTML = '';
}
function onWwwWoAddStateChange() {
  var sc = (document.getElementById('wwwWoAddState') || {}).value;
  _wwwWoFillCentres('wwwWoAddCentre', sc);
  _wwwWoFillBatches('wwwWoAddBatch', sc, '', 'Select Batch');
  loadWwwWoEligibleTrainees();
}
function onWwwWoAddCentreChange() {
  var sc = (document.getElementById('wwwWoAddState') || {}).value;
  var cc = (document.getElementById('wwwWoAddCentre') || {}).value;
  _wwwWoFillBatches('wwwWoAddBatch', sc, cc, 'Select Batch');
  loadWwwWoEligibleTrainees();
}
function loadWwwWoEligibleTrainees() {
  _WWW_WO_SELECTED_TRAINEE = null;
  var pb = document.getElementById('wwwWoProceedBtn'); if (pb) pb.disabled = true;
  var sc = (document.getElementById('wwwWoAddState') || {}).value;
  var cc = (document.getElementById('wwwWoAddCentre') || {}).value;
  var bid = (document.getElementById('wwwWoAddBatch') || {}).value;
  var nm = (document.getElementById('wwwWoAddSearch') || {}).value;
  var wrap = document.getElementById('wwwWoAddTraineesWrap');
  var hint = document.getElementById('wwwWoAddHint');
  var tb = document.getElementById('wwwWoAddBody');
  if (!sc || !cc) {
    if (wrap) wrap.style.display = 'none';
    if (hint) { hint.style.display = ''; hint.innerHTML = 'Pick <b>State</b> and <b>Centre</b> above to load trainees.'; }
    if (tb) tb.innerHTML = '';
    return;
  }
  var qs = ['state_code=' + encodeURIComponent(sc), 'centre_code=' + encodeURIComponent(cc)];
  if (bid) qs.push('batch_id=' + encodeURIComponent(bid));
  if (nm)  qs.push('name=' + encodeURIComponent(nm));
  apiGet('/www-walkout/eligible-trainees?' + qs.join('&')).then(function(rows) {
    if (!rows || !rows.length) {
      if (wrap) wrap.style.display = 'none';
      if (hint) { hint.style.display = ''; hint.innerHTML = 'No eligible trainees found for the selected scope.'; }
      if (tb) tb.innerHTML = '';
      return;
    }
    if (hint) hint.style.display = 'none';
    if (wrap) wrap.style.display = '';
    tb.innerHTML = rows.map(function(r) {
      var nameSafe = (r.name || '').replace(/"/g, '&quot;');
      return '<tr>' +
        '<td style="text-align:center;"><input type="radio" name="wwwWoPickerRadio" onclick="_wwwWoPickTrainee(' + r.id + ', \'' + nameSafe + '\', \'' + escHtml(r.enrollment_no || '') + '\', \'' + escHtml(r.batch_name || '') + '\', \'' + escHtml(r.mobile || '') + '\')"></td>' +
        '<td>' + escHtml(r.enrollment_no || '') + '</td>' +
        '<td>' + escHtml(r.name || '') + '</td>' +
        '<td>' + escHtml(r.batch_name || '') + '</td>' +
        '<td>' + escHtml(r.mobile || '') + '</td>' +
      '</tr>';
    }).join('');
  }).catch(function() {
    if (wrap) wrap.style.display = 'none';
    if (hint) { hint.style.display = ''; hint.innerHTML = '<span style="color:#a94442;">Failed to load trainees.</span>'; }
    if (tb) tb.innerHTML = '';
  });
}
function _wwwWoPickTrainee(id, name, enrollNo, batchName, mobile) {
  _WWW_WO_SELECTED_TRAINEE = { id: id, name: name, enrollment_no: enrollNo, batch_name: batchName, mobile: mobile };
  var pb = document.getElementById('wwwWoProceedBtn'); if (pb) pb.disabled = false;
}

