  document.getElementById('wwwWoModalTEnroll').textContent = t.enrollment_no || '—';
  document.getElementById('wwwWoModalTMeta').textContent   = [t.batch_name, t.mobile].filter(Boolean).join(' / ');
  ['wwwWoModalDate','wwwWoModalStage','wwwWoModalReason','wwwWoModalReasonOther'].forEach(function(id) {
    var el = document.getElementById(id); if (el) el.value = '';
  });
  document.getElementById('wwwWoReasonOtherWrap').style.display = 'none';
