function saveWwwWalkoutDetails() {
  if (!_WWW_WO_SELECTED_TRAINEE) { alert('No trainee selected.'); return; }
  var payload = {
    trainee_id: _WWW_WO_SELECTED_TRAINEE.id,
    walkout_date: (document.getElementById('wwwWoModalDate') || {}).value || null,
    walkout_stage: (document.getElementById('wwwWoModalStage') || {}).value || null,
    walkout_reason: (document.getElementById('wwwWoModalReason') || {}).value || null,
    walkout_reason_other: (document.getElementById('wwwWoModalReasonOther') || {}).value || null,
    status: 'Walkout', is_active: true
  };
  if (!payload.walkout_date || !payload.walkout_stage) {
    alert('Please fill Date of Walkout and Stage of Walkout.'); return;
  }
  apiPost('/www-walkout', payload).then(function() {
    alert('Walkout recorded.');
    closeWwwWalkoutDetailsModal();
    navigateTo('wwwWalkoutList');
  }).catch(function(err) { alert('Failed: ' + (err && err.detail ? err.detail : err)); });
}

